// ── G1c: LayoutBoundary (.Boundary) + relayout-escape counter + UseMeasuredBounds/Width probes ──────────────────────

// A deep-nested subtree with a re-rendering leaf, wrapped in a container that is EITHER a `.Boundary()` (layout firewall)
// or a plain flex box. Flipping the leaf signal marks the deep node LayoutDirty; the boundary decides whether the scoped
// relayout stops at the container (escapes = 0) or walks all the way to the scene root (escapes >= 1).
sealed class BoundaryEscapeProbe : Component
{
    public static bool UseBoundary;
    public readonly FluentGpu.Signals.Signal<int> Deep = new(0);

    public override Element Render()
    {
        var inner = new BoxEl { Grow = 1f, Direction = 1, Children = [ Embed.Comp(() => new BoundaryDeepLeaf { Sig = Deep }) ] };
        var container = new BoxEl { Grow = 1f, Direction = 1, Children = [ inner ] };
        if (UseBoundary) container = container.Boundary();
        return new BoxEl { Grow = 1f, Direction = 1, Children = [ container ] };
    }
}

sealed class BoundaryDeepLeaf : Component
{
    public FluentGpu.Signals.Signal<int> Sig = null!;
    public override Element Render()
    {
        int v = Sig.Value;   // subscribe → re-render (and change size, marking LayoutDirty) on flip
        return new BoxEl { Width = 100f, Height = 20f + v };
    }
}

// Hosts a nested component so the measured component's HostNode is its OWN rendered box (NOT the scene root, which is what
// the top-level component's HostNode is forced to). The child's box width is a bound FloatSignal (a compositor/layout
// bind — no re-render), driven per frame to reproduce a resize.
sealed class MeasureHost : Component
{
    readonly Component _child;
    public MeasureHost(Component child) => _child = child;
    public override Element Render() => new BoxEl { Grow = 1f, Direction = 0, Children = [ Embed.Comp(() => _child) ] };
}

sealed class MeasuredWidthProbe : Component
{
    public readonly FluentGpu.Signals.FloatSignal DriveWidth = new(100f);
    public float Quantum;
    public int RenderCount;
    public float LastSeen = -1f;

    public override Element Render()
    {
        RenderCount++;
        var w = UseMeasuredWidth(Quantum);
        LastSeen = w.Value;   // subscribe → re-render when the (quantized) measured width changes
        return new BoxEl { Grow = 0f, Shrink = 0f, Height = 50f, Width = Prop.Of(() => DriveWidth.Value) };
    }
}

sealed class ComposeBoundsProbe : Component
{
    public readonly FluentGpu.Signals.FloatSignal DriveWidth = new(100f);
    public int AuthorFires;
    public int RenderCount;
    public float LastSeenW = -1f;

    public override Element Render()
    {
        RenderCount++;
        var bounds = UseMeasuredBounds();
        LastSeenW = bounds.Value.W;   // subscribe
        return new BoxEl
        {
            Grow = 0f, Shrink = 0f, Height = 50f,
            Width = Prop.Of(() => DriveWidth.Value),
            OnBoundsChanged = _ => AuthorFires++,   // the element author's own handler — must still fire alongside the hook
        };
    }
}

static class Slice
{
    static int s_failures;
    static int s_total;
    public static readonly Context<int> NumCtx = new(0);

    // Phase-3 (GestureArena, §7A/§7B) headline-gate evidence echoed into the final summary line so the orchestrator can
    // read arena health straight off the slice tail (the FixLoop contract): the five load-bearing arena gates write a
    // CONDENSED form of their own computed detail here, at the point each one is asserted, so the summary never
    // recomputes or drifts. Null until the corresponding gate runs (the arena suite is unconditional, so all five are
    // populated on a normal run). Startup-only assignments — not a hot path, so plain strings are fine.
    static string? s_arenaDeterminism, s_arenaIntegratorSweep, s_arenaFastpath, s_arenaAllocZero, s_arenaDispatchAllocZero;

    static void Check(string name, bool ok, string? detail = null)
    {
        Console.WriteLine($"  [{(ok ? "PASS" : "FAIL")}] {name}{(detail is null ? "" : $"  ({detail})")}");
        s_total++;
        if (!ok) s_failures++;
    }

    static void GeolocationChecks()
    {
        var provider = new HeadlessGeolocationProvider();
        var expectedPosition = new GeolocationPosition(
            52.3676,
            4.9041,
            18.5,
            new DateTimeOffset(2026, 7, 13, 12, 0, 0, TimeSpan.Zero));
        var request = new GeolocationRequest(
            TimeSpan.FromSeconds(3),
            TimeSpan.FromMinutes(2),
            GeolocationAccuracy.High);

        provider.Enqueue(GeolocationResult.Success(expectedPosition));
        GeolocationResult success = provider.RequestAsync(request).AsTask().GetAwaiter().GetResult();
        Check("geo.contract success carries a valid provider-neutral fix",
            success.IsSuccess && success.Position == expectedPosition &&
            provider.RequestCount == 1 && provider.LastRequest == request,
            $"status={success.Status} lat={success.Position.Latitude:0.####} requests={provider.RequestCount}");

        provider.Enqueue(GeolocationResult.PermissionDenied);
        GeolocationResult denied = provider.RequestAsync(request).AsTask().GetAwaiter().GetResult();
        Check("geo.contract permission denial is distinct", denied.Status == GeolocationStatus.PermissionDenied,
            $"status={denied.Status}");

        provider.Enqueue(GeolocationResult.Unavailable);
        GeolocationResult unavailable = provider.RequestAsync(request).AsTask().GetAwaiter().GetResult();
        Check("geo.contract unavailable is distinct", unavailable.Status == GeolocationStatus.Unavailable,
            $"status={unavailable.Status}");

        provider.Enqueue(GeolocationResult.Failed);
        GeolocationResult failed = provider.RequestAsync(request).AsTask().GetAwaiter().GetResult();
        Check("geo.contract platform failure is distinct", failed.Status == GeolocationStatus.Failed,
            $"status={failed.Status}");

        HeadlessGeolocationCompletion lateCompletion = provider.EnqueuePending();
        GeolocationResult timedOut = provider.RequestAsync(new GeolocationRequest(TimeSpan.Zero))
            .AsTask().GetAwaiter().GetResult();
        bool lateWasAcceptedByPlatform = lateCompletion.Complete(GeolocationResult.Success(expectedPosition));
        Check("geo.headless timeout wins and a late platform completion cannot replace it",
            timedOut.Status == GeolocationStatus.TimedOut && lateWasAcceptedByPlatform,
            $"status={timedOut.Status} lateAccepted={lateWasAcceptedByPlatform}");

        provider.EnqueuePending();
        using var cancellation = new CancellationTokenSource();
        Task<GeolocationResult> canceledTask = provider.RequestAsync(request, cancellation.Token).AsTask();
        cancellation.Cancel();
        GeolocationResult canceled = canceledTask.GetAwaiter().GetResult();
        Check("geo.headless caller cancellation is distinct", canceled.Status == GeolocationStatus.Canceled,
            $"status={canceled.Status}");

        var unscripted = new HeadlessGeolocationProvider();
        GeolocationResult fallback = unscripted.RequestAsync(request).AsTask().GetAwaiter().GetResult();
        Check("geo.headless unscripted requests deterministically report unavailable",
            fallback.Status == GeolocationStatus.Unavailable,
            $"status={fallback.Status}");
    }

    static NodeHandle Child(SceneStore s, NodeHandle parent, int index)
    {
        var c = s.FirstChild(parent);
        for (int i = 0; i < index && !c.IsNull; i++) c = s.NextSibling(c);
        return c;
    }

    static bool HasGlyph(HeadlessGpuDevice dev, StringTable strings, string text)
    {
        foreach (var g in dev.LastGlyphs)
            if (strings.Resolve(g.Text) == text) return true;
        return false;
    }

    enum DeviceLossProbeFailure { Submit, Present, PresentNonDevice }

    sealed class DeviceLossProbeDevice : IGpuDevice
    {
        readonly DeviceLossProbeFailure _failure;
        bool _armed = true;
        bool _lost;

        public DeviceLossProbeDevice(DeviceLossProbeFailure failure) => _failure = failure;
        public HeadlessGpuDevice Inner { get; } = new();
        public string BackendName => "DeviceLossProbe";
        public bool SupportsSecondarySwapchains => true;
        public int RecoverCount { get; private set; }
        public int DumpCount { get; private set; }
        public int NoteCount { get; private set; }

        public ISwapchain CreateSwapchain(in SwapchainDesc desc) => new DeviceLossProbeSwapchain(this, Inner.CreateSwapchain(desc));

        public void SubmitDrawList(ReadOnlySpan<byte> drawList, ReadOnlySpan<ulong> sortKeys, in FrameInfo ctx)
        {
            if (_failure == DeviceLossProbeFailure.Submit) ThrowOnce();
            Inner.SubmitDrawList(drawList, sortKeys, in ctx);
        }

        public void SubmitDrawList(ReadOnlySpan<byte> drawList, ReadOnlySpan<ulong> sortKeys, in FrameInfo ctx, ISwapchain target)
            => SubmitDrawList(drawList, sortKeys, in ctx);

        public void UploadImage(int imageId, ReadOnlySpan<byte> pbgra8, int w, int h) => Inner.UploadImage(imageId, pbgra8, w, h);
        public void EvictImage(int imageId) => Inner.EvictImage(imageId);
        public bool NoteIfDeviceLost() { NoteCount++; return _lost; }
        public int PollDeviceLost() => _lost ? unchecked((int)0x887A0006u) : 0;
        public void RecoverDevice() { RecoverCount++; _lost = false; }
        public void DumpDeviceLostDiagnostics(Action<string> write) { DumpCount++; write("[probe] device-lost diagnostics"); }
        public void Dispose() { }

        internal void Present(ISwapchain inner)
        {
            if (_failure is DeviceLossProbeFailure.Present or DeviceLossProbeFailure.PresentNonDevice) ThrowOnce();
            inner.Present();
        }

        void ThrowOnce()
        {
            if (!_armed) return;
            _armed = false;
            if (_failure != DeviceLossProbeFailure.PresentNonDevice) _lost = true;
            throw new InvalidOperationException(_lost ? "synthetic device lost" : "synthetic render bug");
        }
    }

    sealed class DeviceLossProbeSwapchain(DeviceLossProbeDevice owner, ISwapchain inner) : ISwapchain
    {
        public Size2 SizePx => inner.SizePx;
        public void Resize(Size2 px) => inner.Resize(px);
        public void Present() => owner.Present(inner);
        public void ConfigurePopupChrome(in PopupChromeMetrics m) => inner.ConfigurePopupChrome(in m);
        public void AnimatePopupOpen() => inner.AnimatePopupOpen();
        public void AnimatePopupClose() => inner.AnimatePopupClose();
        public bool PopupAnimating => inner.PopupAnimating;
        public void Dispose() => inner.Dispose();
    }

    static AppHost DeviceLostHost(StringTable strings, DeviceLossProbeDevice device, out HeadlessPlatformApp app, out HeadlessWindow window)
    {
        app = new HeadlessPlatformApp();
        window = new HeadlessWindow(new WindowDesc("device loss", new Size2(320, 220), 1f));
        window.Show();
        return new AppHost(app, window, device, new HeadlessFontSystem(strings), strings, new Counter());
    }

    static void DeviceLostRecoveryChecks(StringTable strings)
    {
        var oldSink = Diag.Sink;
        var lines = new List<string>();
        Diag.Sink = lines.Add;
        try
        {
            var presentDevice = new DeviceLossProbeDevice(DeviceLossProbeFailure.Present);
            var presentHost = DeviceLostHost(strings, presentDevice, out var presentApp, out var presentWindow);
            using (presentApp)
            using (presentHost)
            {
                var lost = presentHost.RunFrame();
                var recovered = presentHost.RunFrame();
                Check("DL1. foreground Present device-loss is recovered; failed frame is dropped",
                    !lost.Rendered && !lost.Presented && recovered.Presented && presentDevice.RecoverCount == 1 && presentDevice.DumpCount == 1 && presentHost.DeviceLostRecoveryCountForTest == 1,
                    $"lostRendered={lost.Rendered} recoveredPresented={recovered.Presented} recover={presentDevice.RecoverCount} dump={presentDevice.DumpCount}");
            }

            Check("DL2. device-loss log includes frame breadcrumbs and opcode stats",
                lines.Exists(l => l.Contains("[device-lost]")) && lines.Exists(l => l.Contains("ops=")) && lines.Exists(l => l.Contains("[probe]")),
                $"lines={lines.Count}");

            var submitDevice = new DeviceLossProbeDevice(DeviceLossProbeFailure.Submit);
            var submitHost = DeviceLostHost(strings, submitDevice, out var submitApp, out var submitWindow);
            using (submitApp)
            using (submitHost)
            {
                var lost = submitHost.RunFrame();
                var recovered = submitHost.RunFrame();
                Check("DL3. foreground Submit device-loss is recovered; next frame submits cleanly",
                    !lost.Rendered && recovered.Presented && submitDevice.Inner.FrameCount == 1 && submitDevice.RecoverCount == 1,
                    $"frames={submitDevice.Inner.FrameCount} recover={submitDevice.RecoverCount}");
            }

            var bugDevice = new DeviceLossProbeDevice(DeviceLossProbeFailure.PresentNonDevice);
            var bugHost = DeviceLostHost(strings, bugDevice, out var bugApp, out var bugWindow);
            using (bugApp)
            using (bugHost)
            {
                bool threw = false;
                try { bugHost.RunFrame(); }
                catch (InvalidOperationException ex) when (ex.Message.Contains("synthetic render bug")) { threw = true; }
                Check("DL4. non-device-loss render exception still propagates",
                    threw && bugDevice.RecoverCount == 0 && bugHost.DeviceLostRecoveryCountForTest == 0 && bugDevice.NoteCount == 1,
                    $"threw={threw} recover={bugDevice.RecoverCount} notes={bugDevice.NoteCount}");
            }
        }
        finally
        {
            Diag.Sink = oldSink;
        }
    }

    static ColorF GlyphColor(HeadlessGpuDevice dev, StringTable strings, string text)
    {
        foreach (var g in dev.LastGlyphs)
            if (strings.Resolve(g.Text) == text) return g.Color;
        return default;
    }

    static int CountGlyph(HeadlessGpuDevice dev, StringTable strings, string text)
    {
        int n = 0;
        foreach (var g in dev.LastGlyphs)
            if (strings.Resolve(g.Text) == text) n++;
        return n;
    }

    static ColorF FirstGradientC0(HeadlessGpuDevice dev) => dev.LastGradients.Count > 0 ? dev.LastGradients[0].C0 : default;

    // Full-ARGB color comparison (WinUI foreground state changes are often ALPHA-only, so RGB-only checks are too weak).
    static bool ColorClose(ColorF a, ColorF b, float tol)
        => MathF.Abs(a.R - b.R) < tol && MathF.Abs(a.G - b.G) < tol && MathF.Abs(a.B - b.B) < tol && MathF.Abs(a.A - b.A) < tol;

    static bool Near(float a, float b) => MathF.Abs(a - b) < 0.5f;
    static bool Near(float a, float b, float tol) => MathF.Abs(a - b) < tol;

    // Depth-first search for the first node carrying a given automation role (for locating controls in tests).
    static NodeHandle FindRole(SceneStore s, NodeHandle n, AutomationRole role)
    {
        if (n.IsNull) return NodeHandle.Null;
        if (s.Interaction(n).Role == role) return n;
        for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
        {
            var r = FindRole(s, c, role);
            if (!r.IsNull) return r;
        }
        return NodeHandle.Null;
    }

    // Depth-first search for the first Text visual under a node (the rendered glyph run; the role node may differ from
    // the text-visual node). Top-level twin of the local TextVisual helpers — reachable from the arena determinism script.
    static NodeHandle TextVisualNode(SceneStore s, NodeHandle n)
    {
        if (n.IsNull) return NodeHandle.Null;
        if (s.Paint(n).VisualKind == VisualKind.Text) return n;
        for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
        {
            var r = TextVisualNode(s, c);
            if (!r.IsNull) return r;
        }
        return NodeHandle.Null;
    }

    static Point2 CenterOf(SceneStore s, NodeHandle n)
    {
        var r = s.AbsoluteRect(n);
        return new Point2(r.X + r.W / 2f, r.Y + r.H / 2f);
    }

    // The largest |TranslateX| anim-track value over a subtree — the SwipeControl pans its content on that channel, so a
    // non-zero result means the swipe revealed (the content slid sideways); ~0 means it stayed closed. Channel-true (it
    // reads the live track), so it works mid-glide and at rest.
    static float MaxAbsTrackX(AppHost host, NodeHandle n)
    {
        float best = 0f;
        if (n.IsNull) return best;
        if (host.Animation.TryGetTrackValue(n, AnimChannel.TranslateX, out float v)) best = MathF.Abs(v);
        for (var c = host.Scene.FirstChild(n); !c.IsNull; c = host.Scene.NextSibling(c))
        {
            float child = MaxAbsTrackX(host, c);
            if (child > best) best = child;
        }
        return best;
    }

    // Depth-first search for the first scrollable viewport (for locating a ScrollView in tests).
    static NodeHandle FindScrollable(SceneStore s, NodeHandle n)
    {
        if (n.IsNull) return NodeHandle.Null;
        if ((s.Flags(n) & NodeFlags.Scrollable) != 0) return n;
        for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
        {
            var r = FindScrollable(s, c);
            if (!r.IsNull) return r;
        }
        return NodeHandle.Null;
    }

    // Depth-first search for a uniquely-coloured paint node. Useful when the interactive card is wrapped in internal
    // component/cell nodes and its exact depth is intentionally not part of the control contract.
    static NodeHandle FindFillNode(SceneStore s, NodeHandle n, ColorF fill, float tol = 0.006f)
    {
        if (n.IsNull) return NodeHandle.Null;
        if (ColorClose(s.Paint(n).Fill, fill, tol)) return n;
        for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
        {
            var r = FindFillNode(s, c, fill, tol);
            if (!r.IsNull) return r;
        }
        return NodeHandle.Null;
    }

    // The node currently carrying the keyboard-focus flag (the dispatcher sets NodeFlags.Focused on it).
    static NodeHandle FocusedNode(SceneStore s, NodeHandle n)
    {
        if (n.IsNull) return NodeHandle.Null;
        if ((s.Flags(n) & NodeFlags.Focused) != 0) return n;
        for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
        {
            var r = FocusedNode(s, c);
            if (!r.IsNull) return r;
        }
        return NodeHandle.Null;
    }

    static void CollectRole(SceneStore s, NodeHandle n, AutomationRole role, List<NodeHandle> outList)
    {
        if (n.IsNull) return;
        if (s.Interaction(n).Role == role) outList.Add(n);
        for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c)) CollectRole(s, c, role, outList);
    }

    static List<NodeHandle> Roles(SceneStore s, AutomationRole role)
    {
        var list = new List<NodeHandle>();
        CollectRole(s, s.Root, role, list);
        return list;
    }

    static NodeHandle FindTextNode(SceneStore s, StringTable strings, NodeHandle n, string text)
    {
        if (n.IsNull) return NodeHandle.Null;
        ref var p = ref s.Paint(n);
        if (p.VisualKind == VisualKind.Text && strings.Resolve(p.Text) == text) return n;
        for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
        {
            var r = FindTextNode(s, strings, c, text);
            if (!r.IsNull) return r;
        }
        return NodeHandle.Null;
    }

    // D67 menu chrome: constrained menus carry acrylic on the stretch PLATE; OS-backed windowed menus clear that
    // acrylic and keep the same childless 1px presenter plate over the DWM transient backdrop.
    static bool ChildHasAcrylic(SceneStore s, NodeHandle n)
    {
        for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
        {
            if (s.TryGetAcrylic(c, out _)) return true;
            if (s.FirstChild(c).IsNull && s.Paint(c).BorderWidth > 0.5f) return true;
        }
        return false;
    }

    static NodeHandle FindPolylineStrokeNode(SceneStore s, NodeHandle n)
    {
        if (n.IsNull) return NodeHandle.Null;
        if (s.Paint(n).VisualKind == VisualKind.PolylineStroke) return n;
        for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
        {
            var r = FindPolylineStrokeNode(s, c);
            if (!r.IsNull) return r;
        }
        return NodeHandle.Null;
    }

    static int DrawPayloadSize(DrawOp op) => op switch
    {
        DrawOp.FillRoundRect => Unsafe.SizeOf<FillRoundRectCmd>(),
        DrawOp.DrawGlyphRun => Unsafe.SizeOf<DrawGlyphRunCmd>(),
        DrawOp.PushClip => Unsafe.SizeOf<ClipCmd>(),
        DrawOp.PopClip => 0,
        DrawOp.DrawImage => Unsafe.SizeOf<DrawImageCmd>(),
        DrawOp.DrawRoundRectStroke => Unsafe.SizeOf<DrawRoundRectStrokeCmd>(),
        DrawOp.DrawShadow => Unsafe.SizeOf<DrawShadowCmd>(),
        DrawOp.DrawGradientRect => Unsafe.SizeOf<DrawGradientRectCmd>(),
        DrawOp.PushLayer => Unsafe.SizeOf<PushLayerCmd>(),
        DrawOp.PopLayer => Unsafe.SizeOf<PopLayerCmd>(),
        DrawOp.DrawGradientStroke => Unsafe.SizeOf<DrawGradientStrokeCmd>(),
        DrawOp.DrawArc => Unsafe.SizeOf<DrawArcCmd>(),
        DrawOp.DrawPolylineStroke => Unsafe.SizeOf<DrawPolylineStrokeCmd>(),
        DrawOp.DrawTabShape => Unsafe.SizeOf<DrawTabShapeCmd>(),
        _ => 0,
    };

    // Locate a uniquely-coloured rectangle in command-stream order and report the active clip depth at its draw.
    // Used by the exit-orphan containment gate: the old global pass emitted the outgoing rect last at depth 0.
    static (int Order, int ClipDepth) FindFillCommand(DrawList dl, ColorF fill)
    {
        ReadOnlySpan<byte> bytes = dl.Bytes;
        int pos = 0, order = 0, clipDepth = 0;
        while (pos + sizeof(int) <= bytes.Length)
        {
            var op = (DrawOp)MemoryMarshal.Read<int>(bytes.Slice(pos, sizeof(int)));
            pos += sizeof(int);
            if (op == DrawOp.FillRoundRect)
            {
                var cmd = MemoryMarshal.Read<FillRoundRectCmd>(bytes.Slice(pos, Unsafe.SizeOf<FillRoundRectCmd>()));
                if (cmd.Fill.Equals(fill)) return (order, clipDepth);
            }
            if (op == DrawOp.PushClip) clipDepth++;
            else if (op == DrawOp.PopClip) clipDepth--;
            pos += DrawPayloadSize(op);
            order++;
        }
        return (-1, -1);
    }

    // Tolerant sibling of FindFillCommand for HOVER-driven fills: ResolveSurface routes an interactive (or
    // progress-inheriting) fill through LerpLinear, whose sRGB→linear→sRGB float roundtrip is not bit-exact even at
    // identity (HoverFill == Fill) — match within ~1.5/255 instead.
    static (int Order, int ClipDepth) FindFillCommandNear(DrawList dl, ColorF fill, float tol = 0.006f)
    {
        ReadOnlySpan<byte> bytes = dl.Bytes;
        int pos = 0, order = 0, clipDepth = 0;
        while (pos + sizeof(int) <= bytes.Length)
        {
            var op = (DrawOp)MemoryMarshal.Read<int>(bytes.Slice(pos, sizeof(int)));
            pos += sizeof(int);
            if (op == DrawOp.FillRoundRect)
            {
                var cmd = MemoryMarshal.Read<FillRoundRectCmd>(bytes.Slice(pos, Unsafe.SizeOf<FillRoundRectCmd>()));
                if (MathF.Abs(cmd.Fill.R - fill.R) <= tol && MathF.Abs(cmd.Fill.G - fill.G) <= tol
                    && MathF.Abs(cmd.Fill.B - fill.B) <= tol && MathF.Abs(cmd.Fill.A - fill.A) <= tol)
                    return (order, clipDepth);
            }
            if (op == DrawOp.PushClip) clipDepth++;
            else if (op == DrawOp.PopClip) clipDepth--;
            pos += DrawPayloadSize(op);
            order++;
        }
        return (-1, -1);
    }

    static void ClickNode(AppHost host, HeadlessWindow window, NodeHandle n)
    {
        var c = CenterOf(host.Scene, n);
        window.QueueInput(new InputEvent(InputKind.PointerDown, c, 0, 0));
        window.QueueInput(new InputEvent(InputKind.PointerUp, c, 0, 0));
        host.RunFrame();
    }

    // ── synthetic touch gestures ──────────────────────────────────────────────────────────────────────
    // Touch events carry PointerKind.Touch, a per-contact PointerId, and a MONOTONICALLY-INCREASING TimestampMs (never 0
    // — the VelocitySampler's EMA snaps to zero velocity on a 0/duplicate stamp, so a 0-stamp flick is a vacuous pass).
    // The event TimestampMs (the velocity clock) is SEPARATE from the animation clock (FixedFrameTimeSource, 16ms/frame):
    // each gesture step interleaves one RunFrame so the ring's per-id move-coalescing keeps every move (one move/frame)
    // instead of collapsing the whole drag into a single move. The base stamp is global so back-to-back gestures in one
    // test never reuse a timestamp (which would zero the next sampler delta).
    static uint s_touchClockMs = 1000;

    static InputEvent Touch(InputKind kind, Point2 p, uint timestampMs, uint pointerId)
        => new(kind, p, 0, 0, 0f, KeyModifiers.None, PointerKind.Touch, false, timestampMs, pointerId, 1f);

    static Point2 Lerp(Point2 a, Point2 b, float t) => new(a.X + (b.X - a.X) * t, a.Y + (b.Y - a.Y) * t);

    /// <summary>Drive ONE contact's touch gesture: PointerDown at <paramref name="from"/>, <paramref name="steps"/>
    /// PointerMoves easing to <paramref name="to"/> (one RunFrame per move so the ring does not coalesce them away), then
    /// PointerUp — every event tagged Touch + <paramref name="pointerId"/> with a monotonic stamp (+<paramref name="msPerStep"/>
    /// each). Returns the worst <see cref="FrameStats.HotPhaseAllocBytes"/> seen across the move+up frames (0 = clean).</summary>
    static long TouchGesture(HeadlessWindow window, AppHost host, Point2 from, Point2 to, int steps, uint pointerId, float msPerStep)
    {
        long worst = 0;
        float acc = s_touchClockMs;
        window.QueueInput(Touch(InputKind.PointerDown, from, (uint)acc, pointerId));
        host.RunFrame();   // deliver the down on its own frame (records the pan anchor + seeds the sampler)
        for (int i = 1; i <= steps; i++)
        {
            acc += msPerStep;
            var p = Lerp(from, to, (float)i / steps);
            window.QueueInput(Touch(InputKind.PointerMove, p, (uint)acc, pointerId));
            var f = host.RunFrame();
            if (f.HotPhaseAllocBytes > worst) worst = f.HotPhaseAllocBytes;
        }
        acc += msPerStep;
        window.QueueInput(Touch(InputKind.PointerUp, to, (uint)acc, pointerId));
        var fu = host.RunFrame();
        if (fu.HotPhaseAllocBytes > worst) worst = fu.HotPhaseAllocBytes;
        s_touchClockMs = (uint)acc + 1000;   // advance the shared clock so the next gesture never reuses a stamp
        return worst;
    }

    /// <summary>A full touch FLICK over a scroller: <see cref="TouchGesture"/> (down → N moves → up) then
    /// <paramref name="decayFrames"/> fixed-clock frames so phase 7 integrates the seeded fling decay. Returns the worst
    /// <see cref="FrameStats.HotPhaseAllocBytes"/> across the gesture AND the decay frames (the 0-alloc-fling gate).</summary>
    static long TouchFlick(HeadlessWindow window, AppHost host, Point2 from, Point2 to, int steps, uint pointerId, float msPerStep, int decayFrames)
    {
        long worst = TouchGesture(window, host, from, to, steps, pointerId, msPerStep);
        for (int i = 0; i < decayFrames; i++)
        {
            var f = host.RunFrame();
            if (f.HotPhaseAllocBytes > worst) worst = f.HotPhaseAllocBytes;
        }
        return worst;
    }

    /// <summary>Drive a two-contact PINCH (Phase-4): contact <paramref name="idA"/> down at <paramref name="a0"/> and
    /// <paramref name="idB"/> down at <paramref name="b0"/> (the second down opens the pinch), then <paramref name="steps"/>
    /// move-pairs easing each finger from its start toward <paramref name="aEnd"/>/<paramref name="bEnd"/> (one RunFrame per
    /// pair so the ring keeps every move). The two contacts move SYMMETRICALLY about their shared midpoint to spread/pinch.
    /// Leaves both fingers DOWN (the caller lifts to commit / continue). Returns the worst hot-phase alloc across the moves.</summary>
    static long PinchGesture(HeadlessWindow window, AppHost host, Point2 a0, Point2 b0, Point2 aEnd, Point2 bEnd,
                             int steps, uint idA, uint idB, float msPerStep)
    {
        long worst = 0;
        float acc = s_touchClockMs;
        window.QueueInput(Touch(InputKind.PointerDown, a0, (uint)acc, idA));   // first contact: a pan candidate over the zoom viewport
        host.RunFrame();
        acc += msPerStep;
        window.QueueInput(Touch(InputKind.PointerDown, b0, (uint)acc, idB));   // second contact over the SAME viewport → opens the pinch
        host.RunFrame();
        for (int i = 1; i <= steps; i++)
        {
            acc += msPerStep;
            var pa = Lerp(a0, aEnd, (float)i / steps);
            var pb = Lerp(b0, bEnd, (float)i / steps);
            window.QueueInput(Touch(InputKind.PointerMove, pa, (uint)acc, idA));
            window.QueueInput(Touch(InputKind.PointerMove, pb, (uint)acc, idB));
            var f = host.RunFrame();
            if (f.HotPhaseAllocBytes > worst) worst = f.HotPhaseAllocBytes;
        }
        s_touchClockMs = (uint)acc + 1000;
        return worst;
    }

    // Any node in the subtree carrying NodeFlags.Hovered (a touch sequence must leave none behind — no resting touch hover).
    static NodeHandle AnyHovered(SceneStore s, NodeHandle n)
    {
        if (n.IsNull) return NodeHandle.Null;
        if ((s.Flags(n) & NodeFlags.Hovered) != 0) return n;
        for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
        {
            var r = AnyHovered(s, c);
            if (!r.IsNull) return r;
        }
        return NodeHandle.Null;
    }

    // Any node in the subtree carrying NodeFlags.Pressed (a touch down sets it; up/cancel/pan-claim must clear it).
    static NodeHandle AnyPressed(SceneStore s, NodeHandle n)
    {
        if (n.IsNull) return NodeHandle.Null;
        if ((s.Flags(n) & NodeFlags.Pressed) != 0) return n;
        for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
        {
            var r = AnyPressed(s, c);
            if (!r.IsNull) return r;
        }
        return NodeHandle.Null;
    }

    // Depth-first find the scrollable viewport whose ScrollState.ItemCount matches (two-sibling-scroller location).
    static NodeHandle ViewportWithItemCount(SceneStore s, NodeHandle n, int itemCount)
    {
        if (n.IsNull) return NodeHandle.Null;
        if (s.TryGetScroll(n, out var sc) && sc.ItemCount == itemCount) return n;
        for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
        {
            var r = ViewportWithItemCount(s, c, itemCount);
            if (!r.IsNull) return r;
        }
        return NodeHandle.Null;
    }

    static SceneStore LayoutTree(StringTable strings, Element tree)
    {
        var scene = new SceneStore();
        new TreeReconciler(scene, strings).ReconcileRoot(tree, null);
        new FlexLayout(scene, new HeadlessFontSystem(strings)).Run(scene.Root);
        return scene;
    }

    // Golden flexbox checks (deterministic, no text): justify-content, flex-grow, align-items.
    static void FlexChecks(StringTable strings)
    {
        // justify space-between: row 300 wide, two 40-wide boxes → x = 0 and 260
        var sb = LayoutTree(strings, new BoxEl
        {
            Direction = 0, Width = 300, Height = 50, Justify = FlexJustify.SpaceBetween,
            Children = [new BoxEl { Width = 40, Height = 20 }, new BoxEl { Width = 40, Height = 20 }],
        });
        var a = sb.AbsoluteRect(Child(sb, sb.Root, 0));
        var b = sb.AbsoluteRect(Child(sb, sb.Root, 1));
        Check("10. justify space-between", Near(a.X, 0) && Near(b.X, 260) && Near(b.W, 40), $"x0={a.X:0.#} x1={b.X:0.#}");

        // flex-grow: row 300 wide, two grow:1 children → each 150 wide at x = 0 and 150
        var gr = LayoutTree(strings, new BoxEl
        {
            Direction = 0, Width = 300, Height = 40,
            Children = [new BoxEl { Grow = 1, Height = 20 }, new BoxEl { Grow = 1, Height = 20 }],
        });
        var g0 = gr.AbsoluteRect(Child(gr, gr.Root, 0));
        var g1 = gr.AbsoluteRect(Child(gr, gr.Root, 1));
        Check("11. flex-grow splits free space", Near(g0.W, 150) && Near(g1.W, 150) && Near(g1.X, 150), $"w0={g0.W:0.#} x1={g1.X:0.#}");

        // A finite row's grow/Basis=0 child suppresses intrinsic width. This is the toolbar/AutoSuggestBox shape:
        // the field contains a fixed-width editor behind a clipped Basis=0 wrapper, while a fixed account cluster follows.
        // The field must take only the row's remaining 200px; its old 720px editor width must not become the flex base.
        var toolbar = LayoutTree(strings, new BoxEl
        {
            Direction = 0, Width = 400, Height = 48,
            Children =
            [
                new BoxEl
                {
                    Grow = 1, Basis = 0, Shrink = 1, Direction = 0, ClipToBounds = true,
                    Children =
                    [
                        new BoxEl
                        {
                            Grow = 1, Shrink = 1, Direction = 0, MaxWidth = 720,
                            Children =
                            [
                                new BoxEl
                                {
                                    Grow = 1, Basis = 0, Shrink = 1, ClipToBounds = true,
                                    Children = [new BoxEl { Width = 720, Height = 32 }],
                                },
                                new BoxEl { Width = 38, Height = 32 },
                            ],
                        },
                    ],
                },
                new BoxEl { Width = 200, Height = 32 },
            ],
        });
        var searchSlot = toolbar.AbsoluteRect(Child(toolbar, toolbar.Root, 0));
        var account = toolbar.AbsoluteRect(Child(toolbar, toolbar.Root, 1));
        var field = toolbar.AbsoluteRect(Child(toolbar, Child(toolbar, toolbar.Root, 0), 0));
        Check("11a. finite-row Basis=0 suppresses intrinsic width (toolbar children do not overlap)",
            Near(searchSlot.W, 200) && Near(field.W, 200) && Near(account.X, 200) && field.Right <= account.X + 0.01f,
            $"slot={searchSlot.X:0.#}+{searchSlot.W:0.#} field={field.X:0.#}+{field.W:0.#} accountX={account.X:0.#}");

        // align-items center on the cross axis: row 100 tall, child 20 tall → y = 40
        var al = LayoutTree(strings, new BoxEl
        {
            Direction = 0, Width = 200, Height = 100, AlignItems = FlexAlign.Center,
            Children = [new BoxEl { Width = 40, Height = 20 }],
        });
        var ac = al.AbsoluteRect(Child(al, al.Root, 0));
        Check("12. align-items center", Near(ac.Y, 40), $"y={ac.Y:0.#}");

        // padding + gap: column, padding 10, gap 8, two 20-tall children → y = 10 and 38
        var pg = LayoutTree(strings, new BoxEl
        {
            Direction = 1, Width = 100, Height = 200, Padding = Edges4.All(10), Gap = 8,
            Children = [new BoxEl { Width = 40, Height = 20 }, new BoxEl { Width = 40, Height = 20 }],
        });
        var p0 = pg.AbsoluteRect(Child(pg, pg.Root, 0));
        var p1 = pg.AbsoluteRect(Child(pg, pg.Root, 1));
        Check("13. padding + gap stacking", Near(p0.Y, 10) && Near(p1.Y, 38) && Near(p0.X, 10), $"y0={p0.Y:0.#} y1={p1.Y:0.#}");
    }

    // ── Shell chrome/fill/dock column (regression guard for the WaveeShell dock + sidebar-scroll bug) ──
    //
    // Mirrors WaveeShell.cs: OverlayHost wraps the shell column in a root ZStack sized to the live window
    // (OverlayHost.cs:885 — Ui.ZStack(...) with { Width=vp.Width, Height=vp.Height }). The column is a flex COLUMN
    // (Direction=1, Grow=1) with [ titlebar(H=40) , toolbar(H=48) , middle ZStack(Grow=1) , playerbar(H=56) ]. The
    // middle ZStack holds a ROW [ sidebar-pane(Width=240, ScrollView(tall) Grow=1) , content(Grow=1) ]. AlignItems
    // defaults to Stretch (Element.cs:292) so the sidebar pane height == the middle region height; a plain (non-virtual)
    // ScrollView measures to height 0 when unconstrained (FlexLayout MeasureViewport, lines ~359-369) and relies on its
    // parent assigning a definite bounded height.
    //
    // The bug: BoxEl.Shrink defaults to 0 (Element.cs:288). FlexLayout only redistributes OVERFLOW through children with
    // FlexShrink>0 (FlexLayout.cs:263; finalMain floors at 0 via MathF.Max, line 264). With the middle as Grow=1 only and
    // no shrinkable child, when the column overflows a short window NOTHING yields: the player bar spills below the window
    // (not docked), and the over-tall middle hands the sidebar's ScrollView a viewport TALLER than its content (so it
    // never reports overflow → never scrolls). The fix: make the middle the BOUNDED fill (Grow=1 + Shrink=1); chrome rows
    // and the player-bar host stay Shrink=0 (default) so ONLY the middle yields and the bar stays a fixed 56px dock.

    const float ShellTitleH = 40f, ShellToolbarH = 48f, ShellPlayerH = 56f;
    const int ShellSidebarRows = 30;
    const float ShellRowH = 44f, ShellSidebarW = 240f;

    // Build the shell chrome/fill/dock column inside an OverlayHost-style root ZStack sized to (W,H).
    // withShrink=false reproduces the suspected-buggy form (middle Grow=1 only); true is the fix form (Grow=1, Shrink=1).
    // tallMiddle injects an INTRINSIC tall layer into the middle ZStack (modeling real content-card / sidebar content that
    // is NOT zeroed by a viewport): a ZStack measures to its tallest child (MeasureZStack, FlexLayout.cs:591), so this
    // drives the middle's base main size ABOVE the window's free space — the overflow case the dock/scroll bug needs.
    static Element ShellColumnTree(float w, float h, bool withShrink, bool tallMiddle = false)
    {
        var rows = new Element[ShellSidebarRows];
        for (int i = 0; i < rows.Length; i++)
            rows[i] = new BoxEl { Height = ShellRowH, Fill = ColorF.FromRgba(40, 40, 40) };
        var tallContent = new BoxEl { Direction = 1, Children = rows };   // ~30 rows × 44px = 1320px, taller than any viewport here

        var sidebarPane = new BoxEl
        {
            Direction = 1, Shrink = 0f, Width = ShellSidebarW,
            Children = [ Ui.ScrollView(tallContent) with { Grow = 1f } ],   // ScrollView factory already sets Grow=1f
        };
        var contentCard = new BoxEl { Direction = 1, Grow = 1f };
        var mainRow = new BoxEl { Direction = 0, Grow = 1f, Children = [sidebarPane, contentCard] };

        // The middle ZStack's layers: the main row, plus (optionally) a tall intrinsic-height layer. A ZStack sizes to
        // its tallest child, so the tall layer makes the middle's MEASURED (base) height ~1320px — far above the window's
        // free space — without going through a viewport that would zero it.
        Element middle = tallMiddle
            ? Ui.ZStack(mainRow, new BoxEl { Height = ShellSidebarRows * ShellRowH }) with { Grow = 1f }
            : Ui.ZStack(mainRow) with { Grow = 1f };
        if (withShrink) middle = ((BoxEl)middle) with { Shrink = 1f };

        var column = new BoxEl
        {
            Direction = 1, Grow = 1f,
            Children =
            [
                new BoxEl { Height = ShellTitleH },        // titlebar
                new BoxEl { Height = ShellToolbarH },      // toolbar
                middle,                                    // fill
                new BoxEl { Height = ShellPlayerH },       // playerbar
            ],
        };
        return Ui.ZStack(column) with { Grow = 1f, Width = w, Height = h };
    }

    // Locate the lone non-virtual scroll viewport (the sidebar ScrollView) anywhere in the subtree.
    static NodeHandle PlainViewport(SceneStore s, NodeHandle n)
    {
        if (n.IsNull) return NodeHandle.Null;
        if (s.TryGetScroll(n, out var sc) && sc.ItemCount == 0) return n;
        for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
        {
            var r = PlainViewport(s, c);
            if (!r.IsNull) return r;
        }
        return NodeHandle.Null;
    }

    // Resolve the key nodes + their absolute rects for one (W,H,withShrink) cell of the matrix.
    static (RectF col, RectF mid, RectF row, RectF side, RectF bar, ScrollState sc, NodeHandle vp)
        ShellLayout(StringTable strings, float w, float h, bool withShrink, bool tallMiddle = false)
    {
        var s = LayoutTree(strings, ShellColumnTree(w, h, withShrink, tallMiddle));
        var column = Child(s, s.Root, 0);
        var middle = Child(s, column, 2);
        var bar = Child(s, column, 3);
        var mainRow = Child(s, middle, 0);
        var side = Child(s, mainRow, 0);
        var vp = PlainViewport(s, s.Root);
        s.TryGetScroll(vp, out var sc);
        return (s.AbsoluteRect(column), s.AbsoluteRect(middle), s.AbsoluteRect(mainRow),
                s.AbsoluteRect(side), s.AbsoluteRect(bar), sc, vp);
    }

    // Permanent regression guard for the WaveeShell dock + sidebar-scroll bug. Builds the FIX form (middle Grow=1+Shrink=1)
    // over a TALL-MEASURING middle (a ZStack layer whose intrinsic height ~1320px exceeds the window's free space — the
    // overflow case the bug needs) at a SHORT window height, and asserts the real invariants: the player bar is pinned to
    // the window bottom at its fixed height, the middle is bounded to (H − chrome), and the sidebar ScrollView gets a
    // viewport == the bounded middle with content taller than the viewport (so it is genuinely scrollable). These are RED
    // on the no-shrink form (the middle stays 1320, the bar spills to bottom=1464, the viewport == content so it can't
    // scroll — verified in the diagnostic matrix) and GREEN on the fix form. tallMiddle is REQUIRED: with an empty middle
    // the column never overflows, so the guard would pass even without the fix (a tautology).
    static void ShellDockChecks(StringTable strings)
    {
        const float W = 1180f, H = 420f;   // short: free < 0 (40+48+56 + a 1320px-content middle overflows H)
        var (col, mid, row, side, bar, sc, vp) = ShellLayout(strings, W, H, withShrink: true, tallMiddle: true);

        float expectMid = H - ShellTitleH - ShellToolbarH - ShellPlayerH;   // 420 − 144 = 276

        bool barDocked = Near(bar.Y + bar.H, H) && Near(bar.H, ShellPlayerH);
        bool midBounded = Near(mid.H, expectMid) && Near(mid.Y, ShellTitleH + ShellToolbarH);
        Check("S1. shell dock: player bar pinned to window bottom",
            barDocked && midBounded,
            $"bar.Y+H={bar.Y + bar.H:0.#} (want {H:0}) bar.H={bar.H:0.#} mid.H={mid.H:0.#} (want {expectMid:0})");

        bool vpFound = !vp.IsNull;
        bool vpBounded = Near(sc.ViewportH, expectMid, 1f) && Near(side.H, expectMid, 1f);
        bool scrollable = sc.ContentH > sc.ViewportH + 1f;   // content (1320px) overflows the bounded viewport ⇒ scrolls
        Check("S2. shell sidebar: ScrollView bounded + scrollable",
            vpFound && vpBounded && scrollable,
            $"vpH={sc.ViewportH:0.#} (want {expectMid:0}) contentH={sc.ContentH:0.#} side.H={side.H:0.#}");

    }

    // S3 — the WaveeShell RESIZE bug. S1/S2 are STATIC (a fresh, explicit-sized root ZStack, no Embed chain, no resize),
    // so they pass while the real app is broken. The real fault only appears on a live resize: OverlayHost pins its root
    // ZStack to Viewport.Size, but a frozen outer shell (WaveeShell builds the frame once) never re-renders, so the new
    // size is never mirrored up to the scene root and Run(root, window) lays out at the STALE pre-resize size. This drives
    // the actual AppHost resize path (EnsureSize → PublishViewport → Flush → Run) through a HeadlessWindow whose
    // ClientSizePx we shrink between frames, and asserts the player bar re-docks to the NEW window bottom.
    static void ShellResizeChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("resizeshell", new Size2(1180, 900), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var probe = new ResizeShellProbe();
        using var host = new AppHost(app, window, device, fonts, strings, probe);

        host.RunFrame();                                            // first full layout at 1180×900
        RectF barBig = host.Scene.AbsoluteRect(probe.Bar);
        bool dockedBig = Near(barBig.Y + barBig.H, 900f, 1f) && Near(barBig.H, 56f);

        window.ClientSizePx = new Size2(1180, 440);                 // resize DOWN (the reported repro: shrink from big)
        // The real app resizes via WM_SIZE → PaintRequested → Paint (which runs EnsureSize); RunFrame would idle-skip
        // (HasActiveWork is false — a bare ClientSizePx write fires no wake), so drive Paint directly to model the resize.
        host.Paint(0, keepAlive: true);                             // resize tick: EnsureSize → PublishViewport → Flush → Run
        host.Paint(0, keepAlive: true);                             // one settle frame

        RectF rootR = host.Scene.AbsoluteRect(host.Scene.Root);
        RectF barR = host.Scene.AbsoluteRect(probe.Bar);
        bool rootTracks = Near(rootR.H, 440f, 1f);
        bool dockedSmall = Near(barR.Y + barR.H, 440f, 1f) && Near(barR.H, 56f);

        Check("S3. shell resize-down: root tracks the window + player bar re-docks",
            dockedBig && rootTracks && dockedSmall,
            $"big:bar.bottom={barBig.Y + barBig.H:0.#}(want 900) | small:root.H={rootR.H:0.#}(want 440) bar.bottom={barR.Y + barR.H:0.#}(want 440)");

    }

    // Responsive band resize: a Responsive.Of two-column band that flips to a single column (taller) when narrowed must
    // reflow its sibling DOWN — repro for the artist-page "resize small → content overlaps" bug (measure-driven re-render).
    static void ResponsiveResizeChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("respresize", new Size2(1180, 760), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var probe = new RespResizeProbe();
        using var host = new AppHost(app, window, device, fonts, strings, probe);

        // Settle at WIDE — Responsive needs a couple frames (first build at fallback → OnBoundsChanged → rebuild at real w).
        for (int i = 0; i < 8; i++) host.RunFrame();
        RectF bandWide = host.Scene.AbsoluteRect(probe.Band);
        RectF belowWide = host.Scene.AbsoluteRect(probe.Below);
        bool wideNoOverlap = belowWide.Y >= bandWide.Y + bandWide.H - 1f;

        // Resize NARROW (band flips row→column → ~2x taller). Model the real WM_SIZE → Paint path + settle the rebuild.
        window.ClientSizePx = new Size2(560, 760);
        for (int i = 0; i < 10; i++) host.Paint(0, keepAlive: true);
        RectF bandNarrow = host.Scene.AbsoluteRect(probe.Band);
        RectF belowNarrow = host.Scene.AbsoluteRect(probe.Below);
        bool bandGrew = bandNarrow.H > bandWide.H + 50f;                              // column band is taller than the row band
        bool narrowNoOverlap = belowNarrow.Y >= bandNarrow.Y + bandNarrow.H - 1f;     // sibling reflowed below the taller band

        Check("RZ-RESP. responsive band reflows its sibling on resize (no overlap)",
            wideNoOverlap && bandGrew && narrowNoOverlap,
            $"wide band.H={bandWide.H:0} below.Y={belowWide.Y:0}(bottom={bandWide.Y + bandWide.H:0}) | narrow band.H={bandNarrow.H:0} below.Y={belowNarrow.Y:0}(bottom={bandNarrow.Y + bandNarrow.H:0})");
    }

    // RZ — sidebar GRIP-resize speed (the "resizing is still shit / doesn't match the mouse" report). Drives the pane
    // Width signal exactly as the grip's OnMove does (cursor delta → width) over 20 frames and measures, PER FRAME, the
    // ACTUAL pane width vs the EXPECTED target — the empirical "resize delta vs mouse delta" comparison — plus the
    // per-frame relayout/record cost. A 1:1 resize tracks the target exactly every frame with bounded per-frame cost.
    static void CollapsedHeroRebakeChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("collapse-rebake", new Size2(360, 240), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var probe = new CollapsedHeroRebakeProbe();
        using var host = new AppHost(app, window, device, fonts, strings, probe);

        host.RunFrame();
        var s = host.Scene;
        var vp = PlainViewport(s, s.Root);
        var content = s.ScrollRef(vp).ContentNode;
        ref ScrollState st = ref s.ScrollRef(vp);
        st.OffsetY = 260f;
        st.TargetY = 260f;
        s.Paint(content).LocalTransform = Affine2D.Translation(0f, -260f);
        s.Mark(content, NodeFlags.TransformDirty | NodeFlags.PaintDirty);
        ScrollBindEval.ApplyContinuous(s, vp, ref st);
        float collapsedBefore = s.Paint(probe.Hero).PresentedH;

        float mediaBefore = s.Paint(probe.Media).Opacity;

        probe.HeroHeight.Value = 240f;
        host.Reconciler.Runtime.Flush();
        float afterRebake = s.Paint(probe.Hero).PresentedH;

        host.Paint(0, keepAlive: true);
        float afterFrame = s.Paint(probe.Hero).PresentedH;
        float afterFrameShift = s.Paint(probe.Hero).ChildShiftY;
        float mediaAfter = s.Paint(probe.Media).Opacity;

        Check("RZ-HERO. collapsed PresentedHTrailing hero stays collapsed across bind re-bake",
            Near(collapsedBefore, 0f, 0.5f)
            && !float.IsNaN(afterRebake) && Near(afterRebake, 0f, 0.5f)
            && Near(afterFrame, 0f, 0.5f) && Near(afterFrameShift, -240f, 0.5f),
            $"before={collapsedBefore:0.#} rebake={afterRebake:0.#} frame={afterFrame:0.#}/{afterFrameShift:0.#}");

        // The photo proxy's scroll-bound dissolve must survive the re-bake: the re-render just RESET paint.Opacity to
        // the element literal (1), and the fresh bind row's FIRST eval must write the corrective 0 — a LastWritten
        // seeded 0 change-gates it away (the hero photo popping back over the collapsed band on a re-theme/focus regain).
        Check("RZ-HERO. scroll-bound media opacity re-writes 0 across a bind re-bake (first-write not change-gated)",
            Near(mediaBefore, 0f, 0.01f) && Near(mediaAfter, 0f, 0.01f),
            $"before={mediaBefore:0.##} after={mediaAfter:0.##}");
    }

    // Mica focus toggle (WindowBlur/WindowFocus) bumps Tok.Epoch and re-themes in place. The steady frame after regain
    // must keep a collapsed hero clipped — span reuse cannot replay a subtree recorded at full PresentedH.
    static void CollapsedHeroFocusChecks(StringTable strings)
    {
        var priorBg = Theme.WindowBackground;
        Theme.WindowBackground = ColorF.Transparent;
        try
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("collapse-focus", new Size2(360, 240), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var probe = new CollapsedHeroRebakeProbe();
            using var host = new AppHost(app, window, device, fonts, strings, probe);

            host.RunFrame();
            var s = host.Scene;
            var vp = PlainViewport(s, s.Root);
            var content = s.ScrollRef(vp).ContentNode;
            ref ScrollState st = ref s.ScrollRef(vp);
            st.OffsetY = 260f;
            st.TargetY = 260f;
            s.Paint(content).LocalTransform = Affine2D.Translation(0f, -260f);
            s.Mark(content, NodeFlags.TransformDirty | NodeFlags.PaintDirty);
            ScrollBindEval.ApplyContinuous(s, vp, ref st);
            host.Paint(0, keepAlive: true);
            float collapsed = s.Paint(probe.Hero).PresentedH;
            float mediaCollapsed = s.Paint(probe.Media).Opacity;

            window.IsActive = false;
            var blurStats = host.Paint(0, keepAlive: true);
            float afterBlur = s.Paint(probe.Hero).PresentedH;
            float mediaBlur = s.Paint(probe.Media).Opacity;

            window.IsActive = true;
            var focusStats = host.Paint(0, keepAlive: true);
            float afterFocus = s.Paint(probe.Hero).PresentedH;
            float mediaFocus = s.Paint(probe.Media).Opacity;

            var steadyStats = host.Paint(0, keepAlive: true);
            float afterSteady = s.Paint(probe.Hero).PresentedH;
            float afterSteadyShift = s.Paint(probe.Hero).ChildShiftY;
            float mediaSteady = s.Paint(probe.Media).Opacity;

            Check("RZ-HERO. collapsed hero survives window blur/focus (Mica re-theme) with PresentedHTrailing intact",
                Near(collapsed, 0f, 0.5f)
                && Near(afterBlur, 0f, 0.5f)
                && Near(afterFocus, 0f, 0.5f)
                && Near(afterSteady, 0f, 0.5f) && Near(afterSteadyShift, -200f, 0.5f),
                $"collapsed={collapsed:0.#} blur={afterBlur:0.#} focus={afterFocus:0.#} steady={afterSteady:0.#}/{afterSteadyShift:0.#} "
                + $"blurReuse={blurStats.SpansReused} focusReuse={focusStats.SpansReused} steadyReuse={steadyStats.SpansReused}");

            // The hero PHOTO's scroll-bound dissolve (Opacity → 0) must ALSO survive the re-theme re-bake: a fresh bind
            // row change-gating its first write away leaves the reconciled literal (1) — the photo band popping back
            // over the collapsed hero on focus regain (the user-visible regression this guards).
            Check("RZ-HERO. scroll-bound media opacity stays 0 across window blur/focus (re-bake first-write)",
                Near(mediaCollapsed, 0f, 0.01f)
                && Near(mediaBlur, 0f, 0.01f)
                && Near(mediaFocus, 0f, 0.01f)
                && Near(mediaSteady, 0f, 0.01f),
                $"collapsed={mediaCollapsed:0.##} blur={mediaBlur:0.##} focus={mediaFocus:0.##} steady={mediaSteady:0.##}");
        }
        finally { Theme.WindowBackground = priorBg; }
    }

    // Sidebar collapse-toggle FLIP (the projected-motion migration). Repro for two defects that shared ONE root cause:
    //  Bug A — the toggle SNAPPED: the content sheet jumped to its final X in one frame while only the (occluded) pane
    //          reveal eased behind it, because the content card's Position FLIP was measured PARENT-relative and its
    //          parent (the content region) absorbs the whole reserved-width shift ⇒ zero FLIP delta ⇒ no slide.
    //  Bug B — a stale dark band was left where the pane USED to be, because a static (snapped) card never re-damages the
    //          backdrop it covers, so the region-aware acrylic cache reused the pane's old pixels behind the translucent
    //          card. Fixing A (card FLIPs relative to the stable ROW frame, not its moving parent) makes the card TRANSLATE
    //          each frame, so its device bounds are damaged and — since the card's left edge tracks the pane's revealing
    //          right edge EXACTLY — the swept region is damaged contiguously ⇒ no stale band. One fix, both bugs.
    static void SidebarCollapseFlipChecks(StringTable strings)
    {
        // Mode 0 = the pre-fix wiring (FLIP on the card, parent-relative) — must SNAP (regression guard for the bug).
        // Mode 2 = the fix (FLIP on the card, RelativeTo the row) — must SLIDE with pane↔card edge coherence.
        (float toggleEdge, float minEdge, float maxAbsCoherence, float regionX) Run(int mode)
        {
            FluentGpu.Dsl.Motion.ReducedMotion = false;
            CollapseToggleProbe.Mode = mode;
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("collapse", new Size2(1180, 760), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var probe = new CollapseToggleProbe();
            using var host = new AppHost(app, window, device, fonts, strings, probe);
            for (int i = 0; i < 4; i++) host.RunFrame();
            var s = host.Scene;
            float CardEdge() => s.AbsoluteRect(probe.Card).X;
            float PaneRight() { var b = s.Bounds(probe.Pane); float pw = s.Paint(probe.Pane).PresentedW; return b.X + (float.IsNaN(pw) ? b.W : pw); }
            probe.CompactSig.Value = true;   // collapse 360 -> 56
            host.RunFrame();
            float toggleEdge = CardEdge();
            float minEdge = toggleEdge, maxCoh = 0f;
            for (int k = 0; k < 24; k++)
            {
                host.RunFrame();
                minEdge = MathF.Min(minEdge, CardEdge());
                maxCoh = MathF.Max(maxCoh, MathF.Abs(CardEdge() - PaneRight()));   // 0 ⇒ contiguous swept-band damage (Bug B)
            }
            return (toggleEdge, minEdge, maxCoh, s.Bounds(probe.Content).X);
        }

        var bug = Run(0);
        var fix = Run(2);
        FluentGpu.Dsl.Motion.ReducedMotion = false;
        // Regression guard: the pre-fix (parent-relative card FLIP) SNAPS — the sheet jumps to 56 on the toggle frame.
        Check("SBF0. pre-fix wiring SNAPS the content sheet (parent-relative card FLIP ⇒ zero delta) — the bug",
            bug.toggleEdge < 100f, $"toggleEdge={bug.toggleEdge:0.#} (want ~56 snapped)");
        // Bug A fixed: the sheet does NOT snap on the toggle frame (stays near its old 360 edge) and eases down to ~56.
        Check("SBF1. fix: content sheet does not snap on the toggle frame (Bug A) — eases from ~360",
            fix.toggleEdge > 300f && fix.minEdge < 60f, $"toggleEdge={fix.toggleEdge:0.#} (want >300) minEdge={fix.minEdge:0.#} (want <60)");
        // Bug B fixed: the card's left edge tracks the pane's revealing right edge EXACTLY every frame ⇒ the swept region
        // is damaged contiguously (no stale-backdrop band), and the static underlays stay put (regionX == final 56).
        Check("SBF2. fix: pane↔card edge coherence every frame (contiguous swept damage, no ghost band — Bug B) + static underlays",
            fix.maxAbsCoherence < 1.0f && System.MathF.Abs(fix.regionX - 56f) < 1f,
            $"maxEdgeGap={fix.maxAbsCoherence:0.##}px (want <1) regionX={fix.regionX:0.#} (want 56 static)");
    }

    static void SidebarResizeSimChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("resizesim", new Size2(1180, 760), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var probe = new ResizeSidebarProbe();
        using var host = new AppHost(app, window, device, fonts, strings, probe);
        host.RunFrame();   // mount + first layout at width 400

        long maxHotAlloc = 0; int maxNodes = 0; int maxCmds = 0;
        var trace = new System.Text.StringBuilder();
        // One full grip-drag cycle: down (Dragging=true → reduced-motion ON, snap) → N moves (one frame each) → up
        // (Dragging=false → restored) → settle frames. Returns the WORST per-frame |actualPaneWidth − target|: 0 means
        // the (animated) pane width tracks the cursor exactly; > 0 means the reflow spring is easing instead of snapping.
        float DragCycle(int idx, float fromW, float toW, int steps, bool record)
        {
            probe.BeginDrag();
            bool rm = FluentGpu.Dsl.Motion.ReducedMotion;   // DIAGNOSTIC: is the reduced-motion gate already ON before frame #1?
            float worst = 0f;
            for (int s = 1; s <= steps; s++)
            {
                float target = fromW + (toW - fromW) * s / steps;
                probe.WidthSig.Value = target;
                var fs = host.RunFrame();
                if (s == 1) rm = FluentGpu.Dsl.Motion.ReducedMotion;
                float actual = host.Scene.AbsoluteRect(probe.Pane).W;
                worst = MathF.Max(worst, MathF.Abs(actual - target));
                if (record && s > 1) { if (fs.HotPhaseAllocBytes > maxHotAlloc) maxHotAlloc = fs.HotPhaseAllocBytes; if (fs.NodesVisited > maxNodes) maxNodes = fs.NodesVisited; if (fs.DrawCommandCount > maxCmds) maxCmds = fs.DrawCommandCount; }
              }
              probe.EndDrag();
            for (int k = 0; k < 6; k++) host.RunFrame();   // release-settle frames
            trace.Append($" drag{idx}={worst:0.#}(rm={rm})");
            return worst;
        }

        float err1 = DragCycle(1, 400f, 280f, 12, record: true);    // FIRST resize ("ok")
        float err2 = DragCycle(2, 280f, 380f, 12, record: false);   // SECOND resize (reported "dogshit")
        float err3 = DragCycle(3, 380f, 240f, 12, record: false);   // THIRD
        FluentGpu.Dsl.Motion.ReducedMotion = false;                  // defensive: never leak the gate to later checks
        Console.WriteLine($"  [resize-sim]{trace}  maxNodes={maxNodes} maxCmds={maxCmds} maxHotAlloc={maxHotAlloc}B");
        Check("RZ1. FIRST sidebar resize tracks the cursor 1:1 (pane width == target, reflow spring snaps)",
            err1 < 1f, $"drag1 worstErr={err1:0.##}");
        Check("RZ3. SUBSEQUENT sidebar resizes track 1:1 too — no degradation after drag #1 (the reported bug)",
            err2 < 1f && err3 < 1f, $"drag2={err2:0.##} drag3={err3:0.##} (drag1={err1:0.##})");
        Check("RZ2. sidebar resize re-flow is bounded per frame (no per-frame growth in alloc / nodes / draw commands)",
            maxHotAlloc < 256 && maxNodes < 200 && maxCmds < 60, $"maxHotAlloc={maxHotAlloc}B nodes={maxNodes} cmds={maxCmds}");
    }

    // S4 — the navview scrollbar. At a short (overflow) window, a wheel over the sidebar must scroll it AND reveal the
    // auto-hiding (conscious) scrollbar (FadeT>0). Guards "the sidebar scrolls + shows a scrollbar when it overflows".
    static void ShellSidebarScrollChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("navscroll", new Size2(1180, 440), 1f));   // short ⇒ sidebar overflows
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var probe = new ResizeShellProbe();
        using var host = new AppHost(app, window, device, fonts, strings, probe);
        host.RunFrame();

        var vpn = PlainViewport(host.Scene, host.Scene.Root);
        window.QueueInput(new InputEvent(InputKind.Wheel, new Point2(120f, 250f), 0, 0, 240f));
        for (int i = 0; i < 8; i++) host.RunFrame();
        host.Scene.TryGetScroll(vpn, out var ssc);

        bool overflow = ssc.ContentH > ssc.ViewportH + 1f;
        bool scrolled = ssc.OffsetY > 1f;
        bool barRevealed = ssc.FadeT > 0.01f;
        Check("S4. navview: overflowing sidebar scrolls on wheel + reveals the auto-hiding scrollbar",
            !vpn.IsNull && overflow && scrolled && barRevealed,
            $"offY={ssc.OffsetY:0.#} contentH={ssc.ContentH:0.#} vpH={ssc.ViewportH:0.#} fadeT={ssc.FadeT:0.00}");
    }

    // UseReducer / UseMemo / UseRef exercised through a real Component across renders.
    static void HookChecks()
    {
        var p = new HookProbe();

        p.RenderWithHooks();   // frame 1 (mount)
        var r1 = p.RefBox;
        bool ok1 = p.State == 0 && p.Memo == 10 && p.MemoRuns == 1 && r1!.Value == 7;

        p.Dispatch!(5); p.Dispatch!(3);   // fold: 0+5=5, +3=8 (a reducer dispatch applies to the signal immediately)
        r1!.Value = 42;

        p.RenderWithHooks();   // frame 2 (same dep)
        bool ok2 = p.State == 8 && p.Memo == 10 && p.MemoRuns == 1 && ReferenceEquals(p.RefBox, r1) && p.RefBox!.Value == 42;

        p.Dep = 2;
        p.RenderWithHooks();   // frame 3 (changed dep)
        bool ok3 = p.Memo == 20 && p.MemoRuns == 2;

        Check("14. UseReducer folds dispatches", ok1 && p.State == 8, "0 →(+5,+3)→ 8");
        Check("15. UseMemo recomputes only on dep change", ok2 && ok3, $"memoRuns={p.MemoRuns}");
        Check("16. UseRef persists & is stable", p.RefBox!.Value == 42 && ReferenceEquals(p.RefBox, r1));
    }

    // Drain a component's passive-effect queue the way the host does after paint (phase 12) — snapshot-per-pass so an
    // effect that re-enqueues during the drain is handled, but the auto-effect body itself enqueues nothing.
    static void PumpEffects(RenderContext c)
    {
        var q = c.PendingEffects;
        while (q.Count > 0) { var batch = q.ToArray(); q.Clear(); foreach (var a in batch) a(); }
    }

    // G1a — the new hook surface: auto-tracked effects (default), DepKey deps (opt-in), cleanup, Signal equality, Prop.Bind.
    static void HookSurfaceChecks()
    {
        // gate.hooks.autotrack-timing — the auto-tracked body executes in the passive drain, NEVER inline during Flush.
        {
            var rt = new ReactiveRuntime();
            var pr = new AutoEffectProbe(); pr.Context.Runtime = rt;
            pr.RenderWithHooks();
            bool deferredAtMount = pr.Runs == 0;          // not run during render/mount
            PumpEffects(pr.Context);
            bool ranInDrain = pr.Runs == 1;
            pr.A.Value = 1;
            bool notOnWrite = pr.Runs == 1;
            rt.Flush();
            bool notInFlush = pr.Runs == 1;              // Flush schedules + stages, but does NOT run the body inline
            PumpEffects(pr.Context);
            bool ranInPassive = pr.Runs == 2;
            Check("gate.hooks.autotrack-timing", deferredAtMount && ranInDrain && notOnWrite && notInFlush && ranInPassive,
                $"mount-deferred={deferredAtMount} drain={ranInDrain} not-in-flush={notInFlush} passive={ranInPassive}");
        }

        // gate.hooks.autotrack-rearm — reads sigA run 1, sigB run 2 (branch flip); re-fires on sigB, NOT sigA.
        {
            var rt = new ReactiveRuntime();
            var pr = new AutoEffectProbe(); pr.Context.Runtime = rt;
            pr.UseB = false; pr.RenderWithHooks(); PumpEffects(pr.Context);   // run1 reads A
            pr.UseB = true; pr.RenderWithHooks();                            // re-render installs closure2 (reads B)
            pr.A.Value = 1; rt.Flush(); PumpEffects(pr.Context);             // run2 (via still-subscribed A) → now tracks B
            pr.B.Value = 1; rt.Flush(); PumpEffects(pr.Context);             // re-fires on B
            int afterB = pr.Runs;
            pr.A.Value = 2; rt.Flush(); PumpEffects(pr.Context);             // A no longer tracked → no re-fire
            Check("gate.hooks.autotrack-rearm", pr.Runs == 3 && afterB == 3,
                $"runs={pr.Runs} (want 3; A-after-flip must not re-fire)");
        }

        // gate.hooks.effect-cleanup-runs — cleanup before re-run on dep change AND once at unmount.
        {
            var rt = new ReactiveRuntime();
            var cp = new CleanupProbe(); cp.Context.Runtime = rt;
            cp.Dep = 1; cp.RenderWithHooks(); PumpEffects(cp.Context);   // Setup=1, Cleanup=0
            cp.Dep = 2; cp.RenderWithHooks(); PumpEffects(cp.Context);   // cleanup fires, then re-run: Cleanup=1, Setup=2
            bool beforeRerun = cp.Setup == 2 && cp.Cleanup == 1;
            cp.Unmount();
            bool atUnmount = cp.Cleanup == 2;
            Check("gate.hooks.effect-cleanup-runs", beforeRerun && atUnmount, $"setup={cp.Setup} cleanup={cp.Cleanup}");
        }

        // gate.hooks.effect-cleanup-order — multi-effect cleanups run in cell order at unmount.
        {
            var rt = new ReactiveRuntime();
            var mp = new MultiCleanupProbe(); mp.Context.Runtime = rt;
            mp.RenderWithHooks(); PumpEffects(mp.Context);
            mp.Unmount();
            Check("gate.hooks.effect-cleanup-order", mp.Order.Count == 2 && mp.Order[0] == 1 && mp.Order[1] == 2,
                $"order=[{string.Join(",", mp.Order)}]");
        }

        // gate.hooks.deps-empty-mount-once — UseEffect(fn, DepKey.Empty) runs exactly once across N re-renders.
        {
            var rt = new ReactiveRuntime();
            var mo = new MountOnceProbe(); mo.Context.Runtime = rt;
            mo.RenderWithHooks(); PumpEffects(mo.Context);
            for (int i = 0; i < 5; i++) { mo.RenderWithHooks(); PumpEffects(mo.Context); }
            Check("gate.hooks.deps-empty-mount-once", mo.Runs == 1, $"runs={mo.Runs} over 6 renders");
        }

        // gate.hooks.depkey-string-tuple-parity — (string,int) deps re-fire on either changing, not on equal re-supply.
        {
            var rt = new ReactiveRuntime();
            var sp = new StringTupleProbe(); sp.Context.Runtime = rt;
            sp.S = "a"; sp.I = 1; sp.RenderWithHooks(); PumpEffects(sp.Context);   // Runs=1
            sp.RenderWithHooks(); PumpEffects(sp.Context);                         // equal → Runs=1
            sp.S = "b"; sp.RenderWithHooks(); PumpEffects(sp.Context);             // string changed → Runs=2
            sp.I = 2; sp.RenderWithHooks(); PumpEffects(sp.Context);               // int changed → Runs=3
            sp.RenderWithHooks(); PumpEffects(sp.Context);                         // equal → Runs=3
            Check("gate.hooks.depkey-string-tuple-parity", sp.Runs == 3, $"runs={sp.Runs} (want 3)");
        }

        // gate.hooks.depkey-fromref-identity — FromRef re-fires on instance swap, not on an unchanged instance.
        {
            var rt = new ReactiveRuntime();
            var fp = new FromRefProbe(); fp.Context.Runtime = rt;
            fp.RenderWithHooks(); PumpEffects(fp.Context);   // Runs=1
            fp.RenderWithHooks(); PumpEffects(fp.Context);   // same instance → Runs=1
            fp.RenderWithHooks(); PumpEffects(fp.Context);   // still same instance → Runs=1
            bool stable = fp.Runs == 1;
            fp.Obj = new object(); fp.RenderWithHooks(); PumpEffects(fp.Context);   // swapped → Runs=2
            Check("gate.hooks.depkey-fromref-identity", stable && fp.Runs == 2, $"runs={fp.Runs} (want 2 after swap)");
        }

        // gate.signal.setifchanged — false+no-notify on equal, true+notify on change; always-notify notifies on equal set.
        {
            var rt = new ReactiveRuntime();
            var s = new Signal<int>(0);
            int notifs = 0;
            _ = new Effect(rt, () => { _ = s.Value; notifs++; });   // subscribes; runs now (notifs=1)
            bool eqFalse = !s.SetIfChanged(0); rt.Flush(); bool noNotify = notifs == 1;
            bool changeTrue = s.SetIfChanged(5); rt.Flush(); bool didNotify = notifs == 2;
            var an = Signal.AlwaysNotify(0);
            int anNotifs = 0;
            _ = new Effect(rt, () => { _ = an.Value; anNotifs++; });   // notifs -> 1
            bool anTrue = an.SetIfChanged(0); rt.Flush(); bool alwaysNotified = anNotifs == 2;   // equal set still notifies
            Check("gate.signal.setifchanged", eqFalse && noNotify && changeTrue && didNotify && anTrue && alwaysNotified,
                $"eqFalse={eqFalse} noNotify={noNotify} changeTrue={changeTrue} didNotify={didNotify} alwaysNotify={alwaysNotified}");
        }

        // gate.prop.bind-named-ctor — Prop.Bind over a Memo-typed-as-IReadSignal wires a live binding that re-fires on write.
        {
            var rt = new ReactiveRuntime();
            var src = new Signal<int>(3);
            var memo = new Memo<int>(rt, () => src.Value * 2);
            IReadSignal<int> asInterface = memo;
            var prop = Prop.Bind(asInterface);
            bool bound = prop.IsBound && ReferenceEquals(prop.Signal, memo);
            int v1 = prop.Signal!.Peek();       // 6
            src.Value = 10; rt.Flush();
            int v2 = prop.Signal!.Peek();       // 20 — the bound source tracks writes
            Check("gate.prop.bind-named-ctor", bound && v1 == 6 && v2 == 20, $"bound={bound} {v1}->{v2}");
        }
    }

    // G4a — the call-site-keyed hook substrate DECISION gates: conditional hooks, looped hooks, zero-alloc lookup,
    // plus UseRequiredContext, the BindContract flip tripwire, and the backwards-write tripwire.
    static void HookSubstrateChecks(StringTable strings)
    {
        // gate.hooks.substrate-conditional — a hook inside `if` gains/loses its cell WITHOUT corrupting its neighbours;
        // the skipped hook's state survives for when the branch is re-entered (the thing positional cursor cells cannot do).
        {
            var rt = new ReactiveRuntime();
            var p = new ConditionalHookProbe(); p.Context.Runtime = rt;
            p.IncludeMiddle = true; p.RenderWithHooks();            // mount: Top=10 Middle=20 Bottom=30
            p.Top.Set(11); p.Middle.Set(21); p.Bottom.Set(31);
            p.RenderWithHooks();
            bool r1 = p.Top.Value == 11 && p.Middle.Value == 21 && p.Bottom.Value == 31;
            p.IncludeMiddle = false; p.RenderWithHooks();          // Middle skipped — Bottom must stay 31 (NOT inherit Middle's cell)
            bool r2 = p.Top.Value == 11 && p.Bottom.Value == 31;
            p.Bottom.Set(32); p.RenderWithHooks();
            bool r3 = p.Top.Value == 11 && p.Bottom.Value == 32;
            p.IncludeMiddle = true; p.RenderWithHooks();           // Middle re-enters — its state (21) is preserved
            bool r4 = p.Middle.Value == 21 && p.Top.Value == 11 && p.Bottom.Value == 32;
            Check("gate.hooks.substrate-conditional a conditional hook gains/loses its cell without shifting neighbours; skipped state survives",
                r1 && r2 && r3 && r4, $"r1={r1} r2={r2} r3={r3} r4={r4} (Top={p.Top.Value} Middle={p.Middle.Value} Bottom={p.Bottom.Value})");
        }

        // gate.hooks.substrate-loop — hooks in a loop keyed per ordinal keep per-iteration state across a count change.
        {
            var rt = new ReactiveRuntime();
            var p = new LoopHookProbe(); p.Context.Runtime = rt;
            p.Count = 3; p.RenderWithHooks();
            p.Sigs[0].Value = 1; p.Sigs[1].Value = 101; p.Sigs[2].Value = 201;
            p.RenderWithHooks();
            bool keep = p.Sigs[0].Peek() == 1 && p.Sigs[1].Peek() == 101 && p.Sigs[2].Peek() == 201;
            p.Count = 4; p.RenderWithHooks();                      // append at end → first 3 keep state, 4th mounts fresh (300)
            bool grow = p.Sigs.Count == 4 && p.Sigs[0].Peek() == 1 && p.Sigs[1].Peek() == 101 && p.Sigs[2].Peek() == 201 && p.Sigs[3].Peek() == 300;
            p.Count = 2; p.RenderWithHooks();                      // remove at end → first 2 keep state
            bool shrink = p.Sigs.Count == 2 && p.Sigs[0].Peek() == 1 && p.Sigs[1].Peek() == 101;
            Check("gate.hooks.substrate-loop looped hooks keyed per ordinal keep per-iteration state across grow/shrink",
                keep && grow && shrink, $"keep={keep} grow={grow} shrink={shrink}");
        }

        // gate.hooks.substrate-alloc — the keyed lookup on a steady re-render allocates 0 bytes in the hot window.
        {
            var rt = new ReactiveRuntime();
            var p = new SteadyHookProbe(); p.Context.Runtime = rt;
            p.RenderWithHooks(); p.RenderWithHooks(); p.RenderWithHooks();   // warm (JIT + mount + dict capacity)
            long before = GC.GetAllocatedBytesForCurrentThread();
            for (int i = 0; i < 200; i++) p.RenderWithHooks();
            long delta = GC.GetAllocatedBytesForCurrentThread() - before;
            Check("gate.hooks.substrate-alloc keyed cell lookup is 0-alloc on a steady re-render", delta == 0, $"delta={delta}B/200 renders");
        }

        // gate.ctx.required — UseRequiredContext throws (naming the type) when unprovided; returns the value when
        // provided; survives a parked re-render (resolves via the parked _ctxResolveCache fallback).
        {
            var channel = new Context<string>("dflt");
            var ctx = new RenderContext();
            bool unprovidedThrows = false; string? msg = null;
            try { ctx.UseRequiredContext(channel); } catch (InvalidOperationException ex) { unprovidedThrows = true; msg = ex.Message; }
            bool named = msg is not null && msg.Contains("String");

            var provided = new Signal<object?>("hello");
            ctx.ResolveContextSignal = (a, c) => ReferenceEquals(c, channel) ? provided : null;
            string got = ctx.UseRequiredContext(channel);                    // resolves + caches
            ctx.ResolveContextSignal = (a, c) => null;                       // simulate a PARKED (detached) re-render
            string parked = ctx.UseRequiredContext(channel);                 // reuses the cached provider signal

            var ctx2 = new RenderContext();
            var nullSig = new Signal<object?>(null);
            ctx2.ResolveContextSignal = (a, c) => nullSig;                   // provider carrying null → must also throw
            bool nullThrows = false;
            try { ctx2.UseRequiredContext(channel); } catch (InvalidOperationException) { nullThrows = true; }

            Check("gate.ctx.required throws (named) when unprovided/null; returns the value; survives a parked re-render",
                unprovidedThrows && named && got == "hello" && parked == "hello" && nullThrows,
                $"threw={unprovidedThrows} named={named} got={got} parked={parked} nullThrows={nullThrows}");
        }

        // gate.bind.contract-flip — a bound↔static flip on a REUSED node trips BindContract; a fresh-thunk re-render does NOT.
        {
            bool prevEnabled = BindContract.Enabled, prevThrow = BindContract.ThrowOnViolation;
            BindContract.Enabled = true; BindContract.ThrowOnViolation = false;
            try
            {
                var sig = new Signal<FluentGpu.Foundation.ColorF>(FluentGpu.Foundation.ColorF.Transparent);

                BindContract.Reset();
                var s1 = new SceneStore(); var r1 = new TreeReconciler(s1, strings);
                var e1 = new BoxEl { Width = 10, Height = 10, Fill = FluentGpu.Foundation.ColorF.Transparent };   // static
                var e2 = new BoxEl { Width = 10, Height = 10, Fill = sig };                                       // bound
                r1.ReconcileRoot(e1, null); r1.ReconcileRoot(e2, e1);
                bool staticToBound = BindContract.Violations == 1 && BindContract.LastViolation!.Contains("Fill");

                BindContract.Reset();
                var s2 = new SceneStore(); var r2 = new TreeReconciler(s2, strings);
                var f1 = new BoxEl { Width = 10, Height = 10, Fill = sig };                                       // bound
                var f2 = new BoxEl { Width = 10, Height = 10, Fill = FluentGpu.Foundation.ColorF.Transparent };   // static
                r2.ReconcileRoot(f1, null); r2.ReconcileRoot(f2, f1);
                bool boundToStatic = BindContract.Violations == 1;

                BindContract.Reset();
                var s3 = new SceneStore(); var r3 = new TreeReconciler(s3, strings);
                var g1 = new BoxEl { Width = 10, Height = 10, Fill = Prop.Of(() => FluentGpu.Foundation.ColorF.Transparent) };   // bound (thunk)
                var g2 = new BoxEl { Width = 10, Height = 10, Fill = Prop.Of(() => FluentGpu.Foundation.ColorF.Transparent) };   // FRESH thunk, same shape → NOT a flip
                r3.ReconcileRoot(g1, null); r3.ReconcileRoot(g2, g1);
                bool thunkQuiet = BindContract.Violations == 0;

                Check("gate.bind.contract-flip bound↔static flip on a reused node trips; a fresh-thunk re-render does not",
                    staticToBound && boundToStatic && thunkQuiet,
                    $"staticToBound={staticToBound} boundToStatic={boundToStatic} thunkQuiet={thunkQuiet}");
            }
            finally { BindContract.Enabled = prevEnabled; BindContract.ThrowOnViolation = prevThrow; }
        }

        // gate.signal.backwards-write-tripwire — an effect that reads+writes the same signal trips once; a normal effect does not.
        {
            bool prevEnabled = BackwardsWriteGuard.Enabled, prevThrow = BackwardsWriteGuard.ThrowOnViolation;
            BackwardsWriteGuard.Enabled = true; BackwardsWriteGuard.ThrowOnViolation = false;
            try
            {
                var rt = new ReactiveRuntime();
                BackwardsWriteGuard.Reset();
                var sig = new Signal<int>(5);
                _ = new Effect(rt, () => { int v = sig.Value; sig.Value = v; });   // read (subscribe) then write the SAME signal
                bool tripped = BackwardsWriteGuard.Violations >= 1 && BackwardsWriteGuard.LastViolation!.Contains("Signal");

                BackwardsWriteGuard.Reset();
                var a = new Signal<int>(1); var b = new Signal<int>(2);
                _ = new Effect(rt, () => { int v = a.Value; b.Value = v; });       // reads A, writes B → no convergence risk
                bool clean = BackwardsWriteGuard.Violations == 0;

                Check("gate.signal.backwards-write-tripwire an effect reading+writing the same signal trips once; a normal effect does not",
                    tripped && clean, $"tripped={tripped} clean={clean}");
            }
            finally { BackwardsWriteGuard.Enabled = prevEnabled; BackwardsWriteGuard.ThrowOnViolation = prevThrow; }
        }
    }

    // G4b — Component/ReactiveComponent unification (one tracked model; run-once inferred; RethemeAll re-runs in place)
    // + per-component ReactiveScope ownership (render-effect + hook cleanups owned by one scope disposed at unmount;
    // KeepAlive parking never disposes it). Bindings stay NODE-owned (they outlive a render but die with their node).
    static void UnifyChecks(StringTable strings)
    {
        // gate.unify.signal-free-render-once — a render that reads no signals runs exactly once, even while an unrelated
        // sibling re-renders across many flushes (run-once is a consequence of subscribing to nothing, not a mode).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("unify-once", new Size2(200, 200), 1f));
            window.Show();
            var root = new SignalFreeRoot();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), new HeadlessFontSystem(strings), strings, root);
            host.RunFrame();
            bool mountedOnce = root.Probe.Renders == 1 && root.RootRenders == 1;
            for (int i = 0; i < 5; i++) { root.Unrelated!.Value = i + 1; host.RunFrame(); }
            bool rootReran = root.RootRenders >= 6;          // the root really re-rendered on each unrelated flush…
            bool childStillOnce = root.Probe.Renders == 1;   // …but the signal-free child never did
            Check("gate.unify.signal-free-render-once a signal-free render runs exactly once across unrelated flushes",
                mountedOnce && rootReran && childStillOnce,
                $"childRenders={root.Probe.Renders} rootRenders={root.RootRenders}");
        }

        // gate.unify.retheme-in-place — RethemeAll re-runs a run-once component's render IN PLACE: token color updates,
        // hook state + node identity preserved (no remount). Replaces the deleted ReactiveComponent.InvalidateTree path.
        {
            ThemeKind saved = Tok.Theme;
            try
            {
                Tok.Use(ThemeKind.Dark);
                using var app = new HeadlessPlatformApp();
                var window = new HeadlessWindow(new WindowDesc("unify-retheme", new Size2(240, 120), 1f));
                window.Show();
                var probe = new RethemeInPlaceProbe();
                using var host = new AppHost(app, window, new HeadlessGpuDevice(), new HeadlessFontSystem(strings), strings, probe);
                host.RunFrame();
                bool once = probe.Renders == 1;
                probe.SetState!(42); host.RunFrame();
                bool stateWrite = probe.SeenState == 42 && probe.Renders == 2;
                var textNode = FindTextNode(host.Scene, strings, host.Scene.Root, "g4b-themed");
                ColorF darkColor = host.Scene.Paint(textNode).TextColor;

                Tok.Use(ThemeKind.Light);
                host.Reconciler.RethemeAll();
                host.RunFrame();
                var textAfter = FindTextNode(host.Scene, strings, host.Scene.Root, "g4b-themed");
                bool sameNode = !textAfter.IsNull && textAfter == textNode;
                bool colorUpdated = darkColor != Tok.TextPrimary && host.Scene.Paint(textAfter).TextColor == Tok.TextPrimary;
                bool statePreserved = probe.SeenState == 42 && probe.Renders == 3;   // re-rendered in place; state survived
                Check("gate.unify.retheme-in-place RethemeAll re-runs a run-once render in place (color updates; state + node identity preserved)",
                    once && stateWrite && sameNode && colorUpdated && statePreserved,
                    $"once={once} stateWrite={stateWrite} sameNode={sameNode} colorUpdated={colorUpdated} statePreserved={statePreserved} renders={probe.Renders}");
            }
            finally { Tok.Use(saved); }
        }

        // gate.unify.scope-owns-lifetime — unmount == Scope.Dispose(): it disposes the render-effect (the signal it read
        // has zero subscribers afterward) AND runs the hook cleanups exactly once, both via the ONE per-component scope.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("unify-scope", new Size2(200, 200), 1f));
            window.Show();
            var root = new ScopeLifetimeRoot();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), new HeadlessFontSystem(strings), strings, root);
            host.RunFrame();
            var c = root.C;
            bool mounted = c.Renders == 1 && c.Cleanups == 0 && c.Dep.SubscriberCount == 1;
            c.Dep.Value = 1; host.RunFrame();
            bool reran = c.Renders == 2 && c.Cleanups == 0;
            c.Show.Value = false; host.RunFrame();               // unmount the child
            bool cleanedOnce = c.Cleanups == 1;
            bool effectDisposed = c.Dep.SubscriberCount == 0;    // render-effect unsubscribed ⇒ disposed via the scope
            c.Dep.Value = 2; host.RunFrame();                    // a post-unmount write must not re-run or re-clean
            bool inert = c.Renders == 2 && c.Cleanups == 1;
            Check("gate.unify.scope-owns-lifetime unmount disposes the render-effect + runs hook cleanups exactly once, via the scope",
                mounted && reran && cleanedOnce && effectDisposed && inert,
                $"renders={c.Renders} cleanups={c.Cleanups} subs={c.Dep.SubscriberCount}");
        }

        // gate.unify.scope-keepalive-parks — parking does NOT dispose the scope: the page instance + hook state survive,
        // a parked page defers renders (no re-render even when a signal it read changes), and reactivation replays once.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("unify-park", new Size2(200, 200), 1f));
            window.Show();
            var probe = new ScopeParkProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), new HeadlessFontSystem(strings), strings, probe);
            host.RunFrame();
            bool mountA = probe.Renders["a"] == 1 && probe.Constructions["a"] == 1;
            probe.Ping.Value = 1; host.RunFrame();
            bool activeReran = probe.Renders["a"] == 2;                        // active + subscribed → re-renders
            probe.Route!.Value = "b"; host.RunFrame();                         // park "a", mount "b"
            bool parkedMountB = probe.Renders.GetValueOrDefault("b") == 1 && probe.Renders["a"] == 2;
            probe.Ping.Value = 2; host.RunFrame();                             // write a signal "a" read while it is parked
            bool parkedDeferred = probe.Renders["a"] == 2;                     // parked ⇒ deferred, NOT re-rendered
            probe.Route.Value = "a"; host.RunFrame();                          // reactivate "a"
            bool reactivateReplayOnce = probe.Renders["a"] == 3 && probe.Constructions["a"] == 1;   // replayed once; never reconstructed ⇒ scope preserved
            Check("gate.unify.scope-keepalive-parks parking keeps the scope (state survives, parked defers renders, reactivation replays once)",
                mountA && activeReran && parkedMountB && parkedDeferred && reactivateReplayOnce,
                $"rendersA={probe.Renders.GetValueOrDefault("a")} rendersB={probe.Renders.GetValueOrDefault("b")} ctorA={probe.Constructions.GetValueOrDefault("a")}");
        }
    }

    // Native form validation (form-validation.md): the signals-native core — gated error memo, cross-field via sibling
    // reads, submit gating, server-error merge, zero-alloc rule evaluation, and form deregistration on unmount.
    static void ValidationChecks()
    {
        // V1. a rule delegate evaluates allocation-free (the per-keystroke hot path resolves no string, allocates nothing).
        var req = Rules.Required("err.req");
        _ = req("warm");
        long before = GC.GetAllocatedBytesForCurrentThread();
        MsgId last = MsgId.None;
        for (int i = 0; i < 1000; i++) last = req(i % 2 == 0 ? "ok" : "");
        long delta = GC.GetAllocatedBytesForCurrentThread() - before;
        Check("V1. rule evaluation is zero-alloc", delta == 0 && !last.IsEmpty, $"delta={delta}B/1000");

        // V2. cross-field: an error memo that reads a sibling signal (Rules.Equals) re-validates when the sibling moves.
        var rt = new ReactiveRuntime();
        var pwd = new Signal<string>("secret");
        var confirm = new Signal<string>("secret");
        var eq = Rules.Equals(pwd, "err.match");
        var crossErr = new Memo<FieldError>(rt, () => { var m = eq(confirm.Value); return new FieldError(m, (byte)(m.IsEmpty ? 0 : 1)); });
        bool matchValid = crossErr.Value.IsValid;
        pwd.Value = "changed";                 // a sibling edit must re-validate confirm with no extra wiring
        rt.Flush();
        bool mismatchInvalid = !crossErr.Peek().IsValid;
        Check("V2. cross-field re-validates on sibling change", matchValid && mismatchInvalid);

        // V3. touched-gating: a pristine field hides its error while its UNGATED validity still reports the failure;
        //     a blur (MarkTouched) reveals it.
        var probe = new ValidationProbe { WithForm = true };
        var prt = new ReactiveRuntime();
        probe.Context.Runtime = prt;
        probe.RenderWithHooks();
        prt.Flush();
        bool pristineHidden = probe.EmailField!.Error.Peek().IsValid;   // Required fails but untouched → displayed-valid
        bool ungatedFalse = !probe.EmailField.IsValid.Peek();          // true validity reflects the failure
        probe.EmailField.MarkTouched();
        bool revealed = !probe.EmailField.Error.Peek().IsValid;
        Check("V3. touched-gating hides error until blur (ungated validity unaffected)", pristineHidden && ungatedFalse && revealed);

        // V4. submit gating: an invalid form blocks and reveals every field's error; fixing the value passes.
        bool formInvalid = !probe.Form!.IsValid.Peek();
        bool validateFalse = !probe.Form.Validate();
        prt.Flush();
        bool emailRevealed = !probe.EmailField.Error.Peek().IsValid;
        probe.Email.Value = "filled";
        prt.Flush();
        bool formValid = probe.Form.IsValid.Peek();
        bool validateTrue = probe.Form.Validate();
        Check("V4. submit gating: invalid blocks+reveals, fixed passes", formInvalid && validateFalse && emailRevealed && formValid && validateTrue);

        // V5. a server error (the async-result merge path) displays even on an untouched field, then clears — the
        //     equality-gated signal means an out-of-order async completion can only ever leave the last-written result.
        var p2 = new ValidationProbe { WithForm = false };
        var p2rt = new ReactiveRuntime();
        p2.Context.Runtime = p2rt;
        p2.Email.Value = "ok";                 // sync-valid + untouched
        p2.RenderWithHooks();
        p2rt.Flush();
        bool cleanFirst = p2.EmailField!.Error.Peek().IsValid;
        p2.EmailField.SetServerError(Msg.Key("err.taken"));
        bool serverShows = !p2.EmailField.Error.Peek().IsValid;        // bypasses the touched/submit gate
        p2.EmailField.SetServerError(MsgId.None);
        bool serverClears = p2.EmailField.Error.Peek().IsValid;
        Check("V5. server error bypasses the gate (async merge) and clears", cleanFirst && serverShows && serverClears);

        // V6. fields deregister from the form on unmount (no FormScope leak).
        bool registered = probe.Form.FieldCount == 2;
        probe.Unmount();
        bool deregistered = probe.Form.FieldCount == 0;
        Check("V6. fields deregister from the form on unmount", registered && deregistered, $"{(registered ? 2 : -1)}→{probe.Form.FieldCount}");

        // V7. the [Validatable] SOURCE GENERATOR emits working Validator<T>[] arrays that lower to the same Rules.* path.
        static bool AllPass<T>(Validator<T>[] rules, T value)
        {
            foreach (var r in rules) if (!r(value).IsEmpty) return false;
            return true;
        }
        bool emailGen = !AllPass(SignupRules.Validators.Email, "")        // Required fails
                        && !AllPass(SignupRules.Validators.Email, "bad")  // RegexMatch fails
                        && AllPass(SignupRules.Validators.Email, "a@b.co");
        bool pwdGen = !AllPass(SignupRules.Validators.Password, "1234567") && AllPass(SignupRules.Validators.Password, "12345678");
        bool ageGen = !AllPass(SignupRules.Validators.Age, 5.0) && AllPass(SignupRules.Validators.Age, 30.0);
        Check("V7. [Validatable] generator emits working Validator<T>[] (Required/MinLength/Range/RegexMatch)", emailGen && pwdGen && ageGen);
    }

    // Keyed reconcile: reorder preserves node identity (state), removal frees only the dropped key.
    static void KeyedChecks(StringTable strings)
    {
        var scene = new SceneStore();
        var recon = new TreeReconciler(scene, strings);

        static Element Row(params string[] keys)
        {
            var ch = new Element[keys.Length];
            for (int i = 0; i < keys.Length; i++) ch[i] = new BoxEl { Key = keys[i], Width = 10, Height = 10 };
            return new BoxEl { Direction = 0, Children = ch };
        }

        var t1 = Row("a", "b", "c");
        recon.ReconcileRoot(t1, null);
        var hA = Child(scene, scene.Root, 0);
        var hB = Child(scene, scene.Root, 1);
        var hC = Child(scene, scene.Root, 2);

        var t2 = Row("c", "a", "b");
        recon.ReconcileRoot(t2, t1);
        bool reordered = Child(scene, scene.Root, 0) == hC && Child(scene, scene.Root, 1) == hA && Child(scene, scene.Root, 2) == hB;
        Check("17. keyed reconcile reorders, preserving identity", reordered, "[a,b,c] → [c,a,b]");

        var t3 = Row("a", "b");
        recon.ReconcileRoot(t3, t2);
        int count = 0;
        for (var c = scene.FirstChild(scene.Root); !c.IsNull; c = scene.NextSibling(c)) count++;
        bool removed = count == 2 && Child(scene, scene.Root, 0) == hA && Child(scene, scene.Root, 1) == hB;
        Check("18. keyed reconcile removes only the dropped key", removed, "[c,a,b] → [a,b]");
    }

    // Frozen-props tripwire (ReuseGuard): the reconciler reuse early-return hands the live component the would-be
    // replacement; a control comparing its frozen scalar catches the "changed value silently dropped" bug class.
    static void ReuseGuardChecks(StringTable strings)
    {
        bool prevEnabled = ReuseGuard.Enabled;
        bool prevThrow = ReuseGuard.ThrowOnViolation;
        ReuseGuard.Enabled = true;             // gate turns the tripwire on regardless of the FG_REUSE_GUARD env
        ReuseGuard.ThrowOnViolation = false;   // count, don't throw (until the strict-mode sub-check)
        try
        {
            static Element Probe(int n) => new BoxEl { Children = [Embed.Comp(() => new FrozenPropProbe { Count = n })] };
            static Element ProbeKeyed(int n) => new BoxEl { Children = [Embed.Comp(() => new FrozenPropProbe { Count = n }) with { Key = "probe:" + n }] };

            // (1) Fires when a frozen scalar changed on a REUSED component (unkeyed positional child, same type).
            ReuseGuard.Reset();
            var scene1 = new SceneStore();
            var recon1 = new TreeReconciler(scene1, strings);
            var a1 = Probe(1); recon1.ReconcileRoot(a1, null);
            var a2 = Probe(5); recon1.ReconcileRoot(a2, a1);
            Check("gate.reuse.frozen-prop-tripwire fires when a reused component's frozen field carries a changed value",
                ReuseGuard.Violations == 1, $"violations={ReuseGuard.Violations} last={ReuseGuard.LastViolation}");

            // (2) Quiet when the value is unchanged, AND quiet when a changed Key REMOUNTS the child (the re-key fix idiom).
            ReuseGuard.Reset();
            var scene2 = new SceneStore();
            var recon2 = new TreeReconciler(scene2, strings);
            var b1 = Probe(3); recon2.ReconcileRoot(b1, null);
            var b2 = Probe(3); recon2.ReconcileRoot(b2, b1);
            bool quietOnSame = ReuseGuard.Violations == 0;
            var c1 = ProbeKeyed(1); recon2.ReconcileRoot(c1, b2);
            var c2 = ProbeKeyed(5); recon2.ReconcileRoot(c2, c1);
            bool quietOnRekey = ReuseGuard.Violations == 0;
            Check("gate.reuse.rekey-and-unchanged do NOT trip the tripwire (remount on Key change; equal value re-render)",
                quietOnSame && quietOnRekey, $"sameQuiet={quietOnSame} rekeyQuiet={quietOnRekey} violations={ReuseGuard.Violations}");

            // (3) Strict mode throws FrozenPropException so a hard-fail path exists for CI/dev.
            ReuseGuard.Reset();
            ReuseGuard.ThrowOnViolation = true;
            bool threw = false;
            var scene3 = new SceneStore();
            var recon3 = new TreeReconciler(scene3, strings);
            var d1 = Probe(1); recon3.ReconcileRoot(d1, null);
            try { var d2 = Probe(9); recon3.ReconcileRoot(d2, d1); }
            catch (FrozenPropException) { threw = true; }
            Check("gate.reuse.strict-throws raises FrozenPropException when ThrowOnViolation is set", threw);

            // (4) Const-gated identically to RenderBudget so the whole facility erases in release.
            Check("gate.reuse.guard-erased ReuseGuard.CompiledIn tracks the DEBUG/FLUENTGPU_DIAG erasure switch (== RenderBudget.CompiledIn)",
                ReuseGuard.CompiledIn == FluentGpu.Hosting.RenderBudget.CompiledIn,
                $"reuse={ReuseGuard.CompiledIn} renderBudget={FluentGpu.Hosting.RenderBudget.CompiledIn}");
        }
        finally
        {
            ReuseGuard.Enabled = prevEnabled;
            ReuseGuard.ThrowOnViolation = prevThrow;
            ReuseGuard.Reset();
        }
    }

    // G4c — RE-PUSHED live props for embedded components (Embed.Comp(props, factory) → UseProps<T>()). Delivery is at the
    // reconciler reuse seam into a per-instance PropsSig (equality-gated), the same physics as a context-provider signal.
    static void PropsChannelChecks(StringTable strings)
    {
        // gate.props.repush-reaches-instance — a CHANGED props record reaches the SAME instance (no remount, node
        // identity preserved), re-rendering it exactly once with the new value.
        {
            var scene = new SceneStore();
            var recon = new TreeReconciler(scene, strings);
            var child = new PropsChild();
            int ctor = 0;
            Element Tree(int n) => new BoxEl { Children = [Embed.Comp(new PropsPayload(n), () => { ctor++; return child; })] };
            var t1 = Tree(1); recon.ReconcileRoot(t1, null); recon.Runtime.Flush();
            var nodeBefore = scene.FirstChild(scene.Root);
            bool mount = child.Renders == 1 && child.LastN == 1 && ctor == 1;
            var t2 = Tree(2); recon.ReconcileRoot(t2, t1); recon.Runtime.Flush();
            var nodeAfter = scene.FirstChild(scene.Root);
            bool reached = ctor == 1 && nodeBefore == nodeAfter && child.Renders == 2 && child.LastN == 2;
            Check("gate.props.repush-reaches-instance changed props re-render the SAME reused instance once (no remount)",
                mount && reached, $"mount={mount} ctor={ctor} sameNode={nodeBefore == nodeAfter} renders={child.Renders} lastN={child.LastN}");
        }

        // gate.props.equality-gated — a fresh-but-EQUAL-VALUE record (different instance, equal fields) → no re-render.
        {
            var scene = new SceneStore();
            var recon = new TreeReconciler(scene, strings);
            var child = new PropsChild();
            Element Tree(PropsPayload p) => new BoxEl { Children = [Embed.Comp(p, () => child)] };
            var t1 = Tree(new PropsPayload(7)); recon.ReconcileRoot(t1, null); recon.Runtime.Flush();
            int afterMount = child.Renders;
            var t2 = Tree(new PropsPayload(7)); recon.ReconcileRoot(t2, t1); recon.Runtime.Flush();   // fresh, equal
            Check("gate.props.equality-gated a fresh-but-equal props record does not re-render the child",
                afterMount == 1 && child.Renders == 1 && child.LastN == 7, $"afterMount={afterMount} renders={child.Renders}");
        }

        // gate.props.ref-shortcircuit — the SAME reference re-supplied → the record Equals is NEVER walked and the child
        // is not re-rendered (the reuse seam short-circuits on ReferenceEquals BEFORE the equality-gated write).
        {
            CountingProps.EqualsCalls = 0;
            var scene = new SceneStore();
            var recon = new TreeReconciler(scene, strings);
            var child = new CountingPropsChild();
            var shared = new CountingProps(3);
            Element Tree() => new BoxEl { Children = [Embed.Comp(shared, () => child)] };
            var t1 = Tree(); recon.ReconcileRoot(t1, null); recon.Runtime.Flush();
            int equalsAfterMount = CountingProps.EqualsCalls;   // seeding the signal never compares
            int rendersAfterMount = child.Renders;
            var t2 = Tree(); recon.ReconcileRoot(t2, t1); recon.Runtime.Flush();   // SAME shared reference re-pushed
            bool noEqualsWalk = CountingProps.EqualsCalls == equalsAfterMount;
            bool noRerender = child.Renders == rendersAfterMount;
            Check("gate.props.ref-shortcircuit same reference re-supplied → no record-Equals walk, no re-render",
                equalsAfterMount == 0 && noEqualsWalk && noRerender, $"equals={CountingProps.EqualsCalls} renders={child.Renders}");
        }

        // gate.props.element-slot-repush — an Element-typed prop (slot) re-pushed → the child subtree reconciles IN PLACE
        // (slot node identity preserved), and a sibling component's UseState in the child survives.
        {
            var scene = new SceneStore();
            var recon = new TreeReconciler(scene, strings);
            var child = new PropsChild { HostKeeper = true };
            Element Tree(Element slot) => new BoxEl { Children = [Embed.Comp(new PropsPayload(0, slot), () => child)] };
            var slotA = new TextEl("A") { Size = 12f };
            var t1 = Tree(slotA); recon.ReconcileRoot(t1, null); recon.Runtime.Flush();
            // root box → PropsChild anchor → child's rendered box → slot (TextEl) node.
            NodeHandle SlotNode() => scene.FirstChild(scene.FirstChild(scene.FirstChild(scene.Root)));
            var slotNodeBefore = SlotNode();
            child.Keeper.Bump!(); recon.Runtime.Flush();                            // sibling state 0 → 1
            bool keeperTicked = child.Keeper.Ticks == 1;
            var slotB = new TextEl("B") { Size = 12f };
            var t2 = Tree(slotB); recon.ReconcileRoot(t2, t1); recon.Runtime.Flush();   // re-push a DIFFERENT slot
            var slotNodeAfter = SlotNode();
            bool inPlace = slotNodeBefore == slotNodeAfter;                         // same TextEl node reconciled in place
            bool siblingSurvived = child.Keeper.Ticks == 1;                         // UseState survived the slot re-push
            Check("gate.props.element-slot-repush slot re-push reconciles in place; sibling UseState survives",
                child.Renders == 2 && keeperTicked && inPlace && siblingSurvived,
                $"renders={child.Renders} inPlace={inPlace} keeper={child.Keeper.Ticks}");
        }

        // gate.props.key-remount — same type + equal props but a CHANGED Key → fresh instance (state reset), one level
        // above the reuse seam (the keyed child diff).
        {
            var scene = new SceneStore();
            var recon = new TreeReconciler(scene, strings);
            int ctor = 0;
            Element Tree(int key, int n) => new BoxEl { Children = [Embed.Comp(new PropsPayload(n), () => { ctor++; return new PropsChild(); }) with { Key = "k" + key }] };
            var t1 = Tree(1, 5); recon.ReconcileRoot(t1, null); recon.Runtime.Flush();
            bool mount = ctor == 1;
            var t2 = Tree(2, 5); recon.ReconcileRoot(t2, t1); recon.Runtime.Flush();   // equal props, changed Key
            Check("gate.props.key-remount a changed Key remounts a fresh instance despite equal props",
                mount && ctor == 2, $"ctor={ctor}");
        }

        // gate.props.parked-defers-replays-latest — a props write while parked defers (zero renders), and reactivation
        // replays exactly ONCE reading the LATEST value.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("props-park", new Size2(200, 200), 1f));
            window.Show();
            var probe = new PropsParkProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), new HeadlessFontSystem(strings), strings, probe);
            host.RunFrame();
            var childA = probe.Children["a"];
            bool mountA = childA.Renders == 1 && childA.LastN == 0;
            probe.Route!.Value = "b"; host.RunFrame();                                                   // park "a", mount "b"
            probe.ChildN.Value = 1; childA.Context.PropsSig!.Value = new PropsPayload(1); host.RunFrame();   // push reaches the PARKED entry
            bool deferred1 = childA.Renders == 1;
            probe.ChildN.Value = 2; childA.Context.PropsSig!.Value = new PropsPayload(2); host.RunFrame();   // latest push, still parked
            bool deferred2 = childA.Renders == 1;
            probe.Route.Value = "a"; host.RunFrame();                                                    // reactivate "a" (re-push carries the latest)
            bool replayOnceLatest = childA.Renders == 2 && childA.LastN == 2;
            Check("gate.props.parked-defers-replays-latest parked defers props renders; reactivation replays once with the latest",
                mountA && deferred1 && deferred2 && replayOnceLatest,
                $"renders={childA.Renders} lastN={childA.LastN} deferred={deferred1 && deferred2}");
        }

        // gate.props.single-flush-coalesce — a parent write + props delivery + child re-render all settle within ONE
        // flush (no torn intermediate, nothing owed to the next frame).
        {
            var scene = new SceneStore();
            var rt = new ReactiveRuntime();
            var recon = new TreeReconciler(scene, strings, rt);
            var driver = new Signal<int>(0);
            var parent = new PropsFlushParent(driver);
            recon.MountRoot(parent);                                 // mount: parent+child render once, child sees 0
            bool mount = parent.Renders == 1 && parent.Child.Renders == 1 && parent.Child.LastN == 0;
            driver.Value = 1;                                        // schedule the parent re-render
            rt.Flush();                                              // ONE flush drains parent → delivers → child
            bool coalesced = parent.Renders == 2 && parent.Child.Renders == 2 && parent.Child.LastN == 1 && !rt.HasPending;
            Check("gate.props.single-flush-coalesce parent write + delivery + child re-render settle in one flush",
                mount && coalesced, $"parent={parent.Renders} child={parent.Child.Renders} lastN={parent.Child.LastN} pending={rt.HasPending}");
        }

        // gate.props.zero-hot-alloc — steady-state ref-equal re-pushes add NO subscriber (the render-effect is the sole
        // PropsSig subscriber) and never re-render; the flush hot-window stays 0-alloc.
        {
            var scene = new SceneStore();
            var recon = new TreeReconciler(scene, strings);
            var child = new PropsChild();
            var shared = new PropsPayload(4);
            var t1 = new BoxEl { Children = [Embed.Comp(shared, () => child)] };
            var t2 = new BoxEl { Children = [Embed.Comp(shared, () => child)] };
            recon.ReconcileRoot(t1, null); recon.Runtime.Flush();
            bool oneSubscriber = child.Context.PropsSig!.SubscriberCount == 1;
            for (int w = 0; w < 6; w++) { recon.ReconcileRoot(w % 2 == 0 ? t2 : t1, w % 2 == 0 ? t1 : t2); recon.Runtime.Flush(); }
            bool stillOne = child.Context.PropsSig!.SubscriberCount == 1;
            bool neverRerendered = child.Renders == 1;
            recon.ReconcileRoot(t2, t1); recon.Runtime.Flush();   // warm a ref-equal delivery (short-circuited)
            long before = GC.GetAllocatedBytesForCurrentThread();
            for (int i = 0; i < 500; i++) recon.Runtime.Flush();
            long delta = GC.GetAllocatedBytesForCurrentThread() - before;
            Check("gate.props.zero-hot-alloc ref-equal re-push adds no subscriber, never re-renders; hot-window flush is 0-alloc",
                oneSubscriber && stillOne && neverRerendered && delta == 0,
                $"subs={child.Context.PropsSig!.SubscriberCount} renders={child.Renders} flushDelta={delta}B");
        }

        // gate.props.useprops-throws-propless — UseProps<T> on a propless mount THROWS naming the component + props type;
        // UsePropsOrDefault returns null propless, the value when present.
        {
            var scene = new SceneStore();
            var recon = new TreeReconciler(scene, strings);
            var thrower = new PropsChild();
            bool threw = false; string msg = "";
            try { recon.ReconcileRoot(new BoxEl { Children = [Embed.Comp(() => thrower)] }, null); recon.Runtime.Flush(); }
            catch (InvalidOperationException ex) { threw = true; msg = ex.Message; }
            bool named = msg.Contains("PropsPayload") && msg.Contains(nameof(PropsChild));

            var scene2 = new SceneStore(); var recon2 = new TreeReconciler(scene2, strings);
            var opt = new OptionalPropsChild();
            recon2.ReconcileRoot(new BoxEl { Children = [Embed.Comp(() => opt)] }, null); recon2.Runtime.Flush();
            bool nullPropless = opt.SawNull;

            var scene3 = new SceneStore(); var recon3 = new TreeReconciler(scene3, strings);
            var opt2 = new OptionalPropsChild();
            recon3.ReconcileRoot(new BoxEl { Children = [Embed.Comp(new PropsPayload(9), () => opt2)] }, null); recon3.Runtime.Flush();
            bool valuePresent = !opt2.SawNull;

            Check("gate.props.useprops-throws-propless UseProps throws (naming component+props) propless; UsePropsOrDefault null propless, value when present",
                threw && named && nullPropless && valuePresent, $"threw={threw} named={named} nullPropless={nullPropless} valuePresent={valuePresent}");
        }
    }

    // G4e — the [Props] source generator (master plan §WS1 P5). A [Props] partial component gets per-field signal-backed
    // storage, subscribing getters, XxxProp bind accessors, a PropsData transport, and IPropsHost.ApplyProps — so a
    // signal-backed field re-renders the core on change, a delegate field is a stable latest-write forwarder that never
    // re-renders, and a bound XxxProp accessor updates compositor-only.
    static void PropsGenChecks(StringTable strings)
    {
        // gate.props.gen.field-level — changing ONE generated (signal-backed) prop re-renders the core once; supplying a
        // FRESH delegate (new lambda, all signal-backed fields unchanged) does NOT re-render; the wired handler (the
        // captured stable forwarder) invokes the NEWEST delegate.
        {
            var scene = new SceneStore();
            var recon = new TreeReconciler(scene, strings);
            var probe = new PropsGenProbe();
            int pings = 0;
            Element Tree(int count, string label, float alpha, Action? onPing)
                => new BoxEl { Children = [Embed.Comp(new PropsGenProbe.PropsData(count, label, alpha, onPing), () => probe)] };
            var t1 = Tree(1, "a", 0.5f, () => pings++); recon.ReconcileRoot(t1, null); recon.Runtime.Flush();
            bool mount = probe.Renders == 1 && probe.LastCount == 1;
            var t2 = Tree(2, "a", 0.5f, () => pings++); recon.ReconcileRoot(t2, t1); recon.Runtime.Flush();   // one signal field changed
            bool changedReRenders = probe.Renders == 2 && probe.LastCount == 2;
            Action fresh = () => pings += 10;
            var t3 = Tree(2, "a", 0.5f, fresh); recon.ReconcileRoot(t3, t2); recon.Runtime.Flush();           // only a fresh delegate
            bool freshNoRerender = probe.Renders == 2;
            probe.Wired!.Invoke();                                                                            // stable forwarder → newest
            bool invokesNewest = pings == 10;
            Check("gate.props.gen.field-level a changed signal-prop re-renders; a fresh delegate does not; the forwarder invokes the newest",
                mount && changedReRenders && freshNoRerender && invokesNewest,
                $"mount={mount} changed={changedReRenders} freshNoRerender={freshNoRerender} pings={pings}");
        }

        // gate.props.gen.batch-coalesce — ApplyProps writing TWO changed fields (wrapped in Runtime.Batch at the reuse
        // seam) re-renders the core EXACTLY ONCE, both values landed (no torn intermediate, no double render).
        {
            var scene = new SceneStore();
            var recon = new TreeReconciler(scene, strings);
            var probe = new PropsGenProbe();
            Element Tree(int c, string l) => new BoxEl { Children = [Embed.Comp(new PropsGenProbe.PropsData(c, l, 0.5f, null), () => probe)] };
            var t1 = Tree(1, "a"); recon.ReconcileRoot(t1, null); recon.Runtime.Flush();
            bool mount = probe.Renders == 1;
            var t2 = Tree(2, "b"); recon.ReconcileRoot(t2, t1); recon.Runtime.Flush();   // two signal fields change at once
            bool once = probe.Renders == 2 && probe.LastCount == 2 && probe.LastLabel == "b";
            Check("gate.props.gen.batch-coalesce ApplyProps writing two changed fields re-renders the core exactly once (Batch wrap)",
                mount && once, $"renders={probe.Renders} count={probe.LastCount} label={probe.LastLabel}");
        }

        // gate.props.gen.bind-direct — a NameProp accessor (AlphaProp) bound to a node channel (Opacity) updates
        // compositor-only when the field changes: FrameStats.Rendered == false, no component re-render.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("props-gen-bind", new Size2(120, 120), 1f)); window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var probe = new PropsGenProbe();
            using var host = new AppHost(app, window, device, fonts, strings, new W0fStaticProbe
            {
                Build = () => new BoxEl { Children = [Embed.Comp(new PropsGenProbe.PropsData(1, "a", 0.5f, null), () => probe)] },
            });
            host.RunFrame();
            int rendersAfterMount = probe.Renders;
            float op0 = host.Scene.Paint(probe.Box).Opacity;
            ((IPropsHost)probe).ApplyProps(new PropsGenProbe.PropsData(1, "a", 0.9f, null));   // change ONLY the bound field
            var f = host.RunFrame();
            float op1 = host.Scene.Paint(probe.Box).Opacity;
            bool changed = Near(op1, 0.9f, 0.01f) && !Near(op0, op1, 0.01f);
            bool compositorOnly = !f.Rendered && probe.Renders == rendersAfterMount;
            Check("gate.props.gen.bind-direct AlphaProp bound to Opacity updates compositor-only (Rendered==false, no re-render)",
                changed && compositorOnly, $"op {op0:0.00}->{op1:0.00} rendered={f.Rendered} renders+{probe.Renders - rendersAfterMount}");
        }

        // gate.props.gen.partial-notify — each of three fields notifies ONLY its own subscribers: Count/Label (read in
        // render) re-fire the render-effect while the Alpha bind holds; Alpha (bound only) fires the bind effect while
        // the render-effect is untouched (Rendered==false, no re-render).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("props-gen-partial", new Size2(120, 120), 1f)); window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var probe = new PropsGenProbe();
            using var host = new AppHost(app, window, device, fonts, strings, new W0fStaticProbe
            {
                Build = () => new BoxEl { Children = [Embed.Comp(new PropsGenProbe.PropsData(1, "a", 0.5f, null), () => probe)] },
            });
            host.RunFrame();
            int r0 = probe.Renders;
            float opMount = host.Scene.Paint(probe.Box).Opacity;
            ((IPropsHost)probe).ApplyProps(new PropsGenProbe.PropsData(2, "a", 0.5f, null));   // only Count
            var fCount = host.RunFrame();
            bool countIsolated = probe.Renders == r0 + 1 && probe.LastCount == 2
                && Near(host.Scene.Paint(probe.Box).Opacity, opMount, 0.01f) && fCount.Rendered;
            ((IPropsHost)probe).ApplyProps(new PropsGenProbe.PropsData(2, "a", 0.8f, null));   // only Alpha (bound)
            var fAlpha = host.RunFrame();
            bool alphaIsolated = probe.Renders == r0 + 1 && !fAlpha.Rendered
                && Near(host.Scene.Paint(probe.Box).Opacity, 0.8f, 0.01f);
            ((IPropsHost)probe).ApplyProps(new PropsGenProbe.PropsData(2, "b", 0.8f, null));   // only Label
            host.RunFrame();
            bool labelIsolated = probe.Renders == r0 + 2 && probe.LastLabel == "b"
                && Near(host.Scene.Paint(probe.Box).Opacity, 0.8f, 0.01f);
            Check("gate.props.gen.partial-notify each field notifies only its own subscribers (Count/Label->render, Alpha->bind; others untouched)",
                countIsolated && alphaIsolated && labelIsolated,
                $"countIso={countIsolated} alphaIso={alphaIsolated} labelIso={labelIsolated} renders={probe.Renders}");
        }
    }

    // Focus + keyboard routing: Tab cycles focus, Enter activates a clickable, keys bubble (Handled stops).
    static void KeyboardChecks(StringTable strings)
    {
        var scene = new SceneStore();
        var recon = new TreeReconciler(scene, strings);
        var dispatcher = new InputDispatcher(scene);

        bool clicked = false, innerSaw = false; int rootSaw = 0;
        var tree = new BoxEl
        {
            Direction = 0,
            OnKeyDown = a => rootSaw = a.KeyCode,                          // ancestor (bubble target)
            Children =
            [
                new BoxEl { Key = "b1", Width = 20, Height = 20, OnClick = () => clicked = true },
                new BoxEl { Key = "b2", Width = 20, Height = 20, Focusable = true,
                    OnKeyDown = a => { innerSaw = true; if (a.KeyCode == Keys.Escape) a.Handled = true; } },
            ],
        };
        recon.ReconcileRoot(tree, null);
        new FlexLayout(scene, new HeadlessFontSystem(strings)).Run(scene.Root);
        var b1 = Child(scene, scene.Root, 0);
        var b2 = Child(scene, scene.Root, 1);

        dispatcher.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Tab) });
        var f1 = dispatcher.Focused;
        dispatcher.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Tab) });
        var f2 = dispatcher.Focused;
        Check("19. Tab cycles focus through focusables", f1 == b1 && f2 == b2, "→ b1 → b2");

        dispatcher.SetFocus(b1);
        dispatcher.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Enter) });
        dispatcher.Dispatch(new[] { new InputEvent(InputKind.KeyUp, default, 0, Keys.Enter) });   // WinUI: click on key-UP
        Check("20. Enter activates the focused clickable", clicked, "OnClick fired via keyboard");

        dispatcher.SetFocus(b2);
        dispatcher.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Down) });   // not handled → bubbles
        bool bubbled = innerSaw && rootSaw == Keys.Down;
        innerSaw = false; rootSaw = 0;
        dispatcher.SetFocus(b2);
        dispatcher.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Escape) });  // b2 marks Handled → stops
        bool stopped = innerSaw && rootSaw == 0;
        Check("21. keys bubble to ancestor; Handled stops propagation", bubbled && stopped);
    }

    // Animation timelines: eased opacity completes (PaintDirty, never LayoutDirty); translate marks TransformDirty.
    static void AnimChecks()
    {
        var scene = new SceneStore();
        var node = scene.CreateNode(1);
        scene.Root = node;
        var engine = new AnimEngine(scene);

        scene.Paint(node).Opacity = 0f;
        scene.Flags(node) &= ~(NodeFlags.PaintDirty | NodeFlags.LayoutDirty | NodeFlags.TransformDirty);
        engine.Animate(node, AnimChannel.Opacity, 0f, 1f, 100f, Easing.Linear);
        engine.Tick(0f);
        bool startOk = MathF.Abs(scene.Paint(node).Opacity) < 0.001f;
        engine.Tick(50f);
        float op = scene.Paint(node).Opacity;
        var fl = scene.Flags(node);
        bool midOk = MathF.Abs(op - 0.5f) < 0.02f && (fl & NodeFlags.PaintDirty) != 0 && (fl & NodeFlags.LayoutDirty) == 0;
        engine.Tick(60f);   // 110ms > 100ms → complete
        bool doneOk = MathF.Abs(scene.Paint(node).Opacity - 1f) < 0.001f && !engine.HasActive;
        Check("22. opacity timeline samples t0, eases & completes (no relayout)", startOk && midOk && doneOk, $"@50ms={op:0.00}");

        scene.Flags(node) &= ~(NodeFlags.TransformDirty | NodeFlags.LayoutDirty);
        engine.Animate(node, AnimChannel.TranslateX, 0f, 100f, 100f, Easing.Linear);
        engine.Tick(0f);
        engine.Tick(25f);
        float dx = scene.Paint(node).LocalTransform.Dx;
        var fl2 = scene.Flags(node);
        bool transOk = MathF.Abs(dx - 25f) < 0.5f && (fl2 & NodeFlags.TransformDirty) != 0 && (fl2 & NodeFlags.LayoutDirty) == 0;
        Check("23. translate timeline marks TransformDirty only", transOk, $"@25ms dx={dx:0.0}");

        var modal = scene.CreateNode(1);
        ref NodePaint mp = ref scene.Paint(modal);
        mp.Opacity = 1f;
        mp.LocalTransform = Affine2D.Identity;
        engine.Animate(modal, AnimChannel.ScaleX, 1f, 1.05f, 167f, Easing.FluentPopOpen);
        engine.Animate(modal, AnimChannel.ScaleY, 1f, 1.05f, 167f, Easing.FluentPopOpen);
        engine.Animate(modal, AnimChannel.Opacity, 1f, 0f, 83f, Easing.Linear);
        engine.Tick(0f);
        for (int i = 0; i < 6; i++) engine.Tick(16f);  // 96ms: opacity settled/removed, scale still active
        float faded = scene.Paint(modal).Opacity;
        bool scaleStillActive = engine.HasTracks(modal);
        engine.Tick(16f);                              // previous bug: remaining scale tracks reset Opacity to 1 here
        float held = scene.Paint(modal).Opacity;
        Check("23z. multi-channel animation preserves completed channels while longer tracks continue",
            faded < 0.01f && held < 0.01f && scaleStillActive,
            $"opacity {faded:0.00}->{held:0.00}, active={scaleStillActive}");
    }

    // Cross-frame self-blur pin-cache KEY (backdrop-effects-animation.md §FA-2a). BlurPinKey.TryCompute is portable
    // (TerraFX-free) so the position-independent content key can be gated headlessly here; the Windows D3D12 pool (G1/G2
    // LRU + budget + settle re-mint) is covered by the --screenshot golden. We emit the blur subtree the SAME way the
    // recorder does — layer DeviceRect = the ABSOLUTE device bounds, each child op's Bounds = node-local (0,0,w,h), each
    // child op's Transform = the world transform (position lives in Dx/Dy) — so these bytes exercise the exact rebasing
    // path. (Constructing the DrawList directly, rather than driving SceneRecorder + a scroll, isolates each delta.)
    static (ulong key, bool ok) BlurStripKey(StringTable strings, float ox, float oy, float sigma, float scaleX, float w, float h,
        StringId text, float childDx, float childDy, float split, StringId text2 = default, float child2Dx = 0f, float child2Dy = 0f)
    {
        var dl = new DrawList();
        var fam = strings.Intern("Segoe UI");
        var layerRect = new RectF(ox, oy, w * scaleX, h);
        dl.PushBlurLayer(layerRect, default, sigma, 1f);
        var local = new RectF(0f, 0f, w, h);
        var world = new Affine2D(scaleX, 0f, 0f, 1f, ox + childDx, oy + childDy);   // world = translate(layer origin) ∘ child offset
        if (split >= 0f)
            dl.DrawGlyphRunGradient(local, text, fam, 20f, 400, 0, 0, 1, 0f, 24f, 0, 0, world, 1f,
                new ColorF(1f, 1f, 1f, 1f), new ColorF(1f, 1f, 1f, 0.4f), split, 0.05f, 0f);
        else
            dl.DrawGlyphRun(local, new ColorF(1f, 1f, 1f, 1f), text, fam, 20f, 400, 0, 0, 1, 0f, 24f, 0, 0, world, 1f);
        if (!text2.IsEmpty)
        {
            var world2 = new Affine2D(scaleX, 0f, 0f, 1f, ox + child2Dx, oy + child2Dy);
            dl.DrawGlyphRun(new RectF(0f, 0f, w, h), new ColorF(1f, 1f, 1f, 1f), text2, fam, 20f, 400, 0, 0, 1, 0f, 24f, 0, 0, world2, 1f);
        }
        dl.PopLayer(layerRect);
        var bytes = dl.Bytes;
        var L = MemoryMarshal.Read<PushLayerCmd>(bytes.Slice(sizeof(int)));
        int start = sizeof(int) + Unsafe.SizeOf<PushLayerCmd>();
        bool ok = BlurPinKey.TryCompute(bytes, start, in L, out ulong key, out _);
        return (key, ok);
    }

    // As BlurStripKey but also returns the layer's PushLayerCmd (for SelfBlurRegion clamp/region checks).
    static (ulong key, PushLayerCmd L) BlurStripKeyL(StringTable strings, float ox, float oy, float sigma, float w, float h, StringId text)
    {
        var dl = new DrawList();
        var fam = strings.Intern("Segoe UI");
        var layerRect = new RectF(ox, oy, w, h);
        dl.PushBlurLayer(layerRect, default, sigma, 1f);
        var world = new Affine2D(1f, 0f, 0f, 1f, ox + 8f, oy + 6f);
        dl.DrawGlyphRun(new RectF(0f, 0f, w, h), new ColorF(1f, 1f, 1f, 1f), text, fam, 20f, 400, 0, 0, 1, 0f, 24f, 0, 0, world, 1f);
        dl.PopLayer(layerRect);
        var bytes = dl.Bytes;
        var L = MemoryMarshal.Read<PushLayerCmd>(bytes.Slice(sizeof(int)));
        int start = sizeof(int) + Unsafe.SizeOf<PushLayerCmd>();
        BlurPinKey.TryCompute(bytes, start, in L, out ulong key, out _);
        return (key, L);
    }

    static void BlurPinKeyChecks(StringTable strings)
    {
        // BP.1 — the core G3 invariant: a pure translation (scroll) at two DIFFERENT (and fractional) origins ⇒ SAME key.
        var t1 = strings.Intern("lyric line");
        var (k1, o1) = BlurStripKey(strings, 100f, 200f, 4f, 1f, 300f, 40f, t1, 8f, 6f, -1f);
        var (k2, o2) = BlurStripKey(strings, 100f - 13.7f, 200f - 37.4f, 4f, 1f, 300f, 40f, t1, 8f, 6f, -1f);
        Check("BP.1 translation-invariant key (scroll → HIT, not a re-blur)", o1 && o2 && k1 == k2 && k1 != 0, $"k1={k1:X16} k2={k2:X16}");

        // BP.2 — determinism: sweep the origin across 200 sub-pixel AND integer-crossing offsets; the key must not wobble
        // (a raw fl(P+X)-X rebase would leak a ≤1-ULP jitter — rounding to the integer grid kills it). Non-integer child
        // offsets (12.3, 5.7) make the P+X and P subtractions genuinely inexact, so this exercises the wobble path.
        ulong refk = 0; bool allSame = true, allOk = true;
        var t2 = strings.Intern("determinism");
        for (int i = 0; i < 200; i++)
        {
            float frac = i / 50f;   // 0.00 .. 3.98, crossing 0/1/2/3
            var (k, ok) = BlurStripKey(strings, 100f + frac, 200f + frac, 4f, 1f, 300f, 40f, t2, 12.3f, 5.7f, -1f);
            if (i == 0) refk = k;
            if (k != refk) allSame = false;
            if (!ok) allOk = false;
        }
        Check("BP.2 key constant across 200 sub-pixel + integer-crossing offsets (no float wobble)", allOk && allSame && refk != 0, $"ref={refk:X16}");

        // BP.3 — content sensitivity: a glyph text change and a wipe-Split change (DrawGlyphRunGradient) each flip the key.
        var ta = strings.Intern("verse one");
        var tb = strings.Intern("verse two");
        var (ka, _) = BlurStripKey(strings, 100f, 200f, 4f, 1f, 300f, 40f, ta, 8f, 6f, -1f);
        var (kb, _) = BlurStripKey(strings, 100f, 200f, 4f, 1f, 300f, 40f, tb, 8f, 6f, -1f);
        var (ks1, _) = BlurStripKey(strings, 100f, 200f, 4f, 1f, 300f, 40f, ta, 8f, 6f, 0.3f);
        var (ks2, _) = BlurStripKey(strings, 100f, 200f, 4f, 1f, 300f, 40f, ta, 8f, 6f, 0.7f);
        Check("BP.3 content-sensitive: text change and wipe-split change each flip the key", ka != kb && ks1 != ks2, $"text={ka != kb} split={ks1 != ks2}");

        // BP.4 — size/sigma sensitivity: a σ step and a ScaleX step (⇒ device W/H + world M11) each flip the key. This
        // proves SIZE stays a CONTENT miss (scale reuse is a non-goal; the app steps scale so the ease is position-only).
        var tz = strings.Intern("emphasis");
        var (kg1, _) = BlurStripKey(strings, 100f, 200f, 4f, 1f, 300f, 40f, tz, 8f, 6f, -1f);
        var (kg2, _) = BlurStripKey(strings, 100f, 200f, 5f, 1f, 300f, 40f, tz, 8f, 6f, -1f);
        var (kc1, _) = BlurStripKey(strings, 100f, 200f, 4f, 1.00f, 300f, 40f, tz, 8f, 6f, -1f);
        var (kc2, _) = BlurStripKey(strings, 100f, 200f, 4f, 1.10f, 300f, 40f, tz, 8f, 6f, -1f);
        Check("BP.4 size-sensitive: σ change and ScaleX change each flip the key (size stays a content miss)", kg1 != kg2 && kc1 != kc2, $"sigma={kg1 != kg2} scale={kc1 != kc2}");

        // BP.5 — relative-layout sensitivity: shift ONE child's local offset by ≥1 px (same size/content) ⇒ the key flips.
        // Proves the rebase catches a genuine relative move — it is NOT a blanket "ignore all Dx/Dy" (no false-share).
        var tr = strings.Intern("main");
        var tr2 = strings.Intern("child2");
        var (kr1, or1) = BlurStripKey(strings, 100f, 200f, 4f, 1f, 300f, 40f, tr, 8f, 6f, -1f, tr2, 40f, 6f);
        var (kr2, or2) = BlurStripKey(strings, 100f, 200f, 4f, 1f, 300f, 40f, tr, 8f, 6f, -1f, tr2, 44f, 6f);
        Check("BP.5 relative-layout-sensitive: a ≥1px child-local shift flips the key (no false-share)", or1 && or2 && kr1 != kr2 && kr1 != 0, $"k1={kr1:X16} k2={kr2:X16}");

        // BP.6 — alloc: 10000 TryCompute calls on a fixed byte buffer under the GC tripwire ⇒ delta == 0 (stackalloc only,
        // safe for the phase 6–13 record hot path).
        {
            var dl = new DrawList();
            var fam = strings.Intern("Segoe UI");
            var layerRect = new RectF(100f, 200f, 300f, 40f);
            dl.PushBlurLayer(layerRect, default, 4f, 1f);
            dl.DrawGlyphRun(new RectF(0f, 0f, 300f, 40f), new ColorF(1f, 1f, 1f, 1f), strings.Intern("alloc"), fam, 20f, 400, 0, 0, 1, 0f, 24f, 0, 0, new Affine2D(1f, 0f, 0f, 1f, 108f, 206f), 1f);
            dl.PopLayer(layerRect);
            var pl = MemoryMarshal.Read<PushLayerCmd>(dl.Bytes.Slice(sizeof(int)));
            int st = sizeof(int) + Unsafe.SizeOf<PushLayerCmd>();
            BlurPinKey.TryCompute(dl.Bytes, st, in pl, out _, out _);   // warm
            long before = GC.GetAllocatedBytesForCurrentThread();
            ulong last = 0;
            for (int i = 0; i < 10000; i++) { BlurPinKey.TryCompute(dl.Bytes, st, in pl, out ulong k, out _); last = k; }
            long delta = GC.GetAllocatedBytesForCurrentThread() - before;
            Check("BP.6 BlurPinKey.TryCompute is zero-alloc (10000 calls)", delta == 0 && last != 0, $"delta={delta}B/10000 last={last:X16}");
        }

        // gate.blur.edgeClampedPinCaches (FA-2a edge-clamp fix). A self-blur whose halo-inflated region is clamped by a
        // canvas edge is STILL cacheable: SelfBlurRegion clamps the region and the compositor's FindPin matches SIZE-
        // exactly, so a STATIONARY clamped row produces a byte-identical key AND a byte-identical clamped region box two
        // frames running ⇒ a pin HIT (no re-blur — the fix for an edge-clamped blur re-running its Gaussian every submit).
        // A ≥1-device-px move that shifts the clamp changes the region-box size ⇒ a size MISS (re-render the exact strip),
        // never a full pin squished into a shorter viewport. The size-exact match is why removing the old clamped-refusal
        // is sound. (The D3D12 pool/pin lease is a --screenshot golden; the portable predicate is gated here.)
        {
            int cw = 1920, ch = 1080;
            var te = strings.Intern("edge line");
            // Near the TOP edge: σ=8 ⇒ tap halo min(ceil(24),32)=24 px; DeviceRect.Y=10 ⇒ 10−24 = −14 < 0 ⇒ clamped.
            var (ke1, Le1) = BlurStripKeyL(strings, 100f, 10f, 8f, 300f, 40f, te);
            var (ke2, Le2) = BlurStripKeyL(strings, 100f, 10f, 8f, 300f, 40f, te);   // stationary: byte-identical next frame
            bool clamped = SelfBlurRegion.IsClamped(in Le1, 1f, cw, ch);
            SelfBlurRegion.RegionBox(in Le1, 1f, cw, ch, out int aX, out int aY, out int aXe, out int aYe);
            SelfBlurRegion.RegionBox(in Le2, 1f, cw, ch, out int bX, out int bY, out int bXe, out int bYe);
            bool stationaryHit = ke1 == ke2 && ke1 != 0 && aX == bX && aY == bY && aXe == bXe && aYe == bYe && aY == 0; // clamped at top ⇒ minY 0
            // Fully on-canvas ⇒ not clamped (mints/hits a full pin as before).
            var (_, Lon) = BlurStripKeyL(strings, 100f, 400f, 8f, 300f, 40f, te);
            bool onCanvasUnclamped = !SelfBlurRegion.IsClamped(in Lon, 1f, cw, ch);
            // A 1px move at the clamped edge changes the region SIZE ⇒ size-exact FindPin misses (re-blur, no squish).
            var (_, Lmv) = BlurStripKeyL(strings, 100f, 11f, 8f, 300f, 40f, te);
            SelfBlurRegion.RegionBox(in Lmv, 1f, cw, ch, out _, out int mY, out _, out int mYe);
            bool moveChangesSize = (mYe - mY) != (aYe - aY);
            Check("gate.blur.edgeClampedPinCaches: a stationary canvas-clamped self-blur keys + region-boxes identically (pin HIT); a 1px edge move changes the region size (size MISS, no squish)",
                clamped && stationaryHit && onCanvasUnclamped && moveChangesSize,
                $"clamped={clamped} hit={stationaryHit} onCanvas={onCanvasUnclamped} moveMiss={moveChangesSize}");
        }

        // gate.blur.selfBlurHaloCoversKernel. The self-blur RegionBox halo (SelfBlurRegion.TapRadius) MUST equal the
        // ACTUAL support of the downsample-then-separable-Gaussian schedule OpacityLayerCompositor.BlurInPlace runs —
        // KernelRadiusTexels(σ/down)·down phys px — so the region's scissor + the cross-frame pin capture keep every
        // non-zero tap (a HIT stays pixel-identical to a MISS). At σ ≤ 4 (down 1, the exact full-res path) it is the
        // un-capped ceil(3σ); at large σ it is the true ≈3σ reach, NOT the old 32 px cap (which truncated the Gaussian
        // to ~1.2σ at σ26). This ties the portable halo to AcrylicBackdropMath, the schedule owner.
        {
            bool haloOk = true;
            string detail = "";
            // Each σ: halo == kernel support, and (crucially) halo >= the down==1 full-res shader's discrete radius
            // min(ceil(3σ),32) at σ≤4 so the exact path's scissor never clips a tap.
            foreach (float s in new[] { 1f, 2f, 4f, 5f, 8f, 16f, 26f, 32f })
            {
                int down = AcrylicBackdropMath.DownsampleFactor(s, 1f);
                float texelSigma = AcrylicBackdropMath.EffectiveTexelSigma(s, 1f, down);
                int expected = AcrylicBackdropMath.KernelRadiusTexels(texelSigma) * down;
                int actual = SelfBlurRegion.TapRadius(s);
                bool covers = actual == expected && texelSigma <= AcrylicBackdropMath.MaxEffectiveTexelSigma + 1e-4f;
                if (s <= 4f) covers &= actual >= (int)MathF.Ceiling(s * 3f);   // exact path: halo covers the shader's radius
                if (!covers) { haloOk = false; detail += $" σ{s}:halo={actual}!=support{expected}(down{down},texelσ{texelSigma:0.00})"; }
            }
            // σ26 (the editorial-card case): down 8, texelσ 3.25, radius 10 texels ⇒ 80 px support — well past the old 32 cap.
            int r26 = SelfBlurRegion.TapRadius(26f);
            bool liftsCap = r26 == 80 && r26 > 32;
            Check("gate.blur.selfBlurHaloCoversKernel: the self-blur halo == the downsample schedule's KernelRadiusTexels(σ/down)·down support (σ26 ⇒ 80 px, lifting the old 32 px truncation)",
                haloOk && liftsCap, $"haloOk={haloOk} r26={r26}{detail}");
        }
    }

    // Expressive Motion Kit (transitions.dev adoption): the new named expressive curves, the per-node self-blur channel
    // (AnimChannel.BlurSigma → NodePaint.BlurSigma, PaintDirty only — never relayout), and the recorder's PushLayer{Blur}
    // emission. Blurred GPU pixels are a --shot manual check; here we prove the curve math, the channel, and the opcode.
    static void ExpressiveMotionChecks(StringTable strings)
    {
        // EM.a — the four expressive curves: endpoints 0→1; SmoothOut decelerates (past halfway by t=0.5); Overshoot &
        // Pop exceed 1.0 mid-flight (the spring-past-target look); OvershootStrong peaks highest of all.
        bool ends =
            Near(Easings.Ease(Easing.SmoothOut, 0f), 0f, 1e-3f) && Near(Easings.Ease(Easing.SmoothOut, 1f), 1f, 1e-3f) &&
            Near(Easings.Ease(Easing.Overshoot, 0f), 0f, 1e-3f) && Near(Easings.Ease(Easing.Overshoot, 1f), 1f, 1e-3f) &&
            Near(Easings.Ease(Easing.OvershootStrong, 0f), 0f, 1e-3f) && Near(Easings.Ease(Easing.OvershootStrong, 1f), 1f, 1e-3f) &&
            Near(Easings.Ease(Easing.Pop, 0f), 0f, 1e-3f) && Near(Easings.Ease(Easing.Pop, 1f), 1f, 1e-3f);
        bool smoothDecel = Easings.Ease(Easing.SmoothOut, 0.5f) > 0.6f;
        float ovPeak = 0f, ovStrongPeak = 0f, popPeak = 0f;
        for (int i = 1; i < 100; i++)
        {
            float t = i / 100f;
            ovPeak = MathF.Max(ovPeak, Easings.Ease(Easing.Overshoot, t));
            ovStrongPeak = MathF.Max(ovStrongPeak, Easings.Ease(Easing.OvershootStrong, t));
            popPeak = MathF.Max(popPeak, Easings.Ease(Easing.Pop, t));
        }
        bool overshoots = ovPeak > 1.0f && popPeak > 1.0f && ovStrongPeak > ovPeak;
        Check("EM.a expressive curves: 0→1 endpoints, SmoothOut decelerates, Overshoot/Pop exceed 1, OvershootStrong peaks highest",
            ends && smoothDecel && overshoots,
            $"smooth@.5={Easings.Ease(Easing.SmoothOut, 0.5f):0.00} ovPeak={ovPeak:0.00} popPeak={popPeak:0.00} strongPeak={ovStrongPeak:0.00}");

        // EM.b — AnimChannel.BlurSigma eases NodePaint.BlurSigma (8→0), marks PaintDirty (never LayoutDirty), settles at 0.
        {
            var scene = new SceneStore();
            var node = scene.CreateNode(1);
            scene.Root = node;
            var engine = new AnimEngine(scene);
            scene.Paint(node).BlurSigma = 8f;
            scene.Flags(node) &= ~(NodeFlags.PaintDirty | NodeFlags.LayoutDirty | NodeFlags.TransformDirty);
            engine.Animate(node, AnimChannel.BlurSigma, 8f, 0f, 100f, Easing.Linear);
            engine.Tick(0f);
            float b0 = scene.Paint(node).BlurSigma;
            engine.Tick(50f);
            float bMid = scene.Paint(node).BlurSigma;
            var fl = scene.Flags(node);
            bool midOk = Near(bMid, 4f, 0.2f) && (fl & NodeFlags.PaintDirty) != 0 && (fl & NodeFlags.LayoutDirty) == 0;
            engine.Tick(60f);   // > 100ms → complete
            float bEnd = scene.Paint(node).BlurSigma;
            bool doneOk = Near(bEnd, 0f, 1e-3f) && !engine.HasActive;
            Check("EM.b AnimChannel.BlurSigma eases BlurSigma 8→0 (PaintDirty only, settles at 0)",
                Near(b0, 8f, 0.1f) && midOk && doneOk, $"t0={b0:0.0} mid={bMid:0.0} end={bEnd:0.00}");
        }

        // EM.c — the recorder wraps a node with Blur>0 in a balanced PushLayer{Blur} carrying its σ; a 0-blur node does not.
        {
            var s = new SceneStore();
            var recon = new TreeReconciler(s, strings);
            recon.ReconcileRoot(new BoxEl
            {
                Width = 80, Height = 60, Fill = ColorF.FromRgba(0x20, 0x20, 0x20),
                Children = [new BoxEl { Width = 30, Height = 30, Blur = 6f, Fill = ColorF.FromRgba(0x60, 0xCD, 0xFF) }],
            }, null);
            new FlexLayout(s, new HeadlessFontSystem(strings)).Run(s.Root);
            var dl = new DrawList();
            SceneRecorder.Record(s, dl);
            var dev = new HeadlessGpuDevice();
            dev.SubmitDrawList(dl.Bytes, dl.SortKeys, new FrameInfo(new Size2(120, 80), 1f, ColorF.Transparent));
            bool blurLayer = false; float sigma = 0f;
            foreach (var l in dev.LastLayers) if (l.Kind == (int)LayerKind.Blur) { blurLayer = true; sigma = l.BlurSigma; }
            bool balanced = dev.LayerBalance == 0;

            var s0 = new SceneStore();
            var recon0 = new TreeReconciler(s0, strings);
            recon0.ReconcileRoot(new BoxEl
            {
                Width = 80, Height = 60, Fill = ColorF.FromRgba(0x20, 0x20, 0x20),
                Children = [new BoxEl { Width = 30, Height = 30, Fill = ColorF.FromRgba(0x60, 0xCD, 0xFF) }],
            }, null);
            new FlexLayout(s0, new HeadlessFontSystem(strings)).Run(s0.Root);
            var dl0 = new DrawList();
            SceneRecorder.Record(s0, dl0);
            var dev0 = new HeadlessGpuDevice();
            dev0.SubmitDrawList(dl0.Bytes, dl0.SortKeys, new FrameInfo(new Size2(120, 80), 1f, ColorF.Transparent));
            bool noBlurWhenZero = true;
            foreach (var l in dev0.LastLayers) if (l.Kind == (int)LayerKind.Blur) noBlurWhenZero = false;

            Check("EM.c recorder emits a balanced PushLayer{Blur} (σ carried) for Blur>0; none for Blur=0",
                blurLayer && Near(sigma, 6f, 0.01f) && balanced && noBlurWhenZero,
                $"blurLayer={blurLayer} sigma={sigma:0.0} balanced={balanced} noneWhenZero={noBlurWhenZero}");
        }

        // EM.d — the PopIn recipe (number pop-in) seeds Opacity 0→1 + TranslateY dist→0 + Blur small→0, and settles to
        // rest (the recipe library composes the new curves + blur channel, not just one track).
        {
            var scene = new SceneStore();
            var node = scene.CreateNode(1);
            scene.Root = node;
            var engine = new AnimEngine(scene);
            engine.PopIn(node, dirY: 1f, distance: 8f, blur: 2f, durationMs: 100f);
            engine.Tick(0f);
            ref NodePaint pp = ref scene.Paint(node);
            bool t0 = Near(pp.Opacity, 0f, 0.05f) && Near(pp.LocalTransform.Dy, 8f, 0.5f) && Near(pp.BlurSigma, 2f, 0.1f);
            engine.Tick(120f);   // > 100ms → all tracks complete
            bool settled = Near(pp.Opacity, 1f, 0.01f) && Near(pp.LocalTransform.Dy, 0f, 0.2f) && Near(pp.BlurSigma, 0f, 0.01f) && !engine.HasActive;
            Check("EM.d PopIn recipe seeds Opacity+TranslateY+Blur and settles to rest", t0 && settled,
                $"t0(op={pp.Opacity:0.00} dy=8 blur=2)={t0} settled={settled}");
        }

        // EM.e — the Shake recipe (error shake) is a single multi-segment TranslateX path that swings to +distance and
        // settles back to 0 (one Replace track, completes).
        {
            var scene = new SceneStore();
            var node = scene.CreateNode(1);
            scene.Root = node;
            var engine = new AnimEngine(scene);
            engine.Shake(node, distance: 6f, overshoot: 4f, durationMs: 280f);
            engine.Tick(0f);
            engine.Tick(80f);   // 80/280 = 28.57% → the +distance peak keyframe
            float dxPeak = scene.Paint(node).LocalTransform.Dx;
            for (int i = 0; i < 16 && engine.HasActive; i++) engine.Tick(16f);   // run to settle (≈256ms more)
            float dxEnd = scene.Paint(node).LocalTransform.Dx;
            Check("EM.e Shake recipe swings to +distance then settles to 0", dxPeak > 3f && Near(dxEnd, 0f, 0.2f) && !engine.HasActive,
                $"peak={dxPeak:0.0} end={dxEnd:0.00} active={engine.HasActive}");
        }

        // EM.f — transitions.dev state/page/refit terminals and the independent interactive-resize policy.
        {
            var text = MotionRecipes.TextSwap;
            var forward = MotionRecipes.PageSlideForward;
            var back = MotionRecipes.PageSlideBack;
            var height = MotionRecipes.CardResizeHeight;
            // Page slides are deliberately BLUR-FREE: a page-root BlurSigma makes the whole page a blur group
            // (canvas-sized offscreen RT + 2-pass Gaussian per transition frame — the measured ~13ms-vs-7ms GPU
            // regression). TextSwap keeps its blur (a tiny element, not a page).
            bool recipes = text.Enter.Dy == 4f && text.Exit.Dy == -4f && text.Enter.Blur == 2f
                && forward.Enter.Dx == 8f && forward.Exit.Dx == -8f && forward.Enter.Blur == 0f && forward.Exit.Blur == 0f
                && back.Enter.Dx == -8f && back.Exit.Dx == 8f && back.Enter.Blur == 0f && back.Exit.Blur == 0f
                && height.Axes == SizeAxes.Height && height.Size == SizeMode.Reflow;

            Motion.SetLayoutTransitionsSuppressed(MotionSuppressionSource.WindowResize, true);
            Motion.SetLayoutTransitionsSuppressed(MotionSuppressionSource.AppResize, true);
            Motion.SetLayoutTransitionsSuppressed(MotionSuppressionSource.WindowResize, false);
            bool independentlyOwned = Motion.LayoutTransitionsSuppressed;
            Motion.SetLayoutTransitionsSuppressed(MotionSuppressionSource.AppResize, false);
            bool cleared = !Motion.LayoutTransitionsSuppressed;
            Check("EM.f text/page/refit recipes carry the authored terminals; resize suppression is independently owned",
                recipes && independentlyOwned && cleared,
                $"recipes={recipes} independentlyOwned={independentlyOwned} cleared={cleared}");
        }

        // EM.g — suppression gates STARTS: SnapStructuralToLayout (the branch ApplyProjections takes while
        // Motion.LayoutTransitionsSuppressed) cancels an in-flight FLIP track and lands the node at its laid-out
        // geometry immediately — no projection keeps running, no residual transform offset.
        {
            var scene = new SceneStore();
            var n = scene.CreateNode(1); scene.Root = n;
            ref RectF nb = ref scene.Bounds(n); nb = new RectF(0, 200, 50, 20);
            var engine = new AnimEngine(scene);
            var spring = new LayoutTransition(TransitionChannels.Position, TransitionDynamics.Spring(1.0f, 1.0f));
            engine.AnimateBounds(n, new RectF(0, 100, 50, 20), new RectF(0, 200, 50, 20), spring);
            for (int i = 0; i < 4; i++) engine.Tick(16f);
            bool wasFlying = MathF.Abs(scene.Paint(n).LocalTransform.Dy) > 5f && engine.HasActive;
            engine.SnapStructuralToLayout(n);                        // the suppressed-branch action
            bool snapped = scene.Paint(n).LocalTransform.IsIdentity; // lands at final geometry (no residual offset)
            bool noTrack = !engine.HasActive;
            engine.Tick(16f);                                        // and none re-seeds next tick
            bool stays = scene.Paint(n).LocalTransform.IsIdentity && !engine.HasActive;
            Check("EM.g suppression snap cancels the in-flight projection and lands at final geometry (no residual offset)",
                wasFlying && snapped && noTrack && stays,
                $"wasFlying={wasFlying} snapped={snapped} noTrack={noTrack} stays={stays}");
        }

        // EM.h — a resize frame (CancelStructuralAll over the FLIP set) cancels an in-flight structural transition:
        // SizeMode.Relayout li.Width/Height restore to the DECLARED value (NaN = auto here), PresentedW resets, the
        // Relayouting flag clears, and the FLIP position offset is gone — bounds land clean, no poisoned layout input.
        {
            var scene = new SceneStore();
            var n = scene.CreateNode(1); scene.Root = n;
            ref LayoutInput li = ref scene.Layout(n); li.Width = float.NaN; li.Height = float.NaN;  // declared = auto
            ref RectF nb = ref scene.Bounds(n); nb = new RectF(0, 0, 100, 200);
            var engine = new AnimEngine(scene);
            var refit = new LayoutTransition(TransitionChannels.Position | TransitionChannels.Size,
                TransitionDynamics.Tween(300f, Easing.SmoothOut), Size: SizeMode.Relayout);
            engine.AnimateBounds(n, new RectF(0, 100, 200, 200), new RectF(0, 0, 100, 200), refit);  // moved (Y 100→0) + width 200→100
            for (int i = 0; i < 3; i++) engine.Tick(16f);
            bool inFlight = engine.HasActive && !float.IsNaN(scene.Paint(n).PresentedW)
                && (scene.Flags(n) & NodeFlags.Relayouting) != 0 && MathF.Abs(scene.Paint(n).LocalTransform.Dy) > 1f;
            engine.CancelStructuralAll(new List<NodeHandle> { n });   // the resize-frame action
            bool liRestored = float.IsNaN(scene.Layout(n).Width) && float.IsNaN(scene.Layout(n).Height);  // declared, not stale interp
            bool presentedReset = float.IsNaN(scene.Paint(n).PresentedW);
            bool relayoutCleared = (scene.Flags(n) & NodeFlags.Relayouting) == 0;
            bool noOffset = scene.Paint(n).LocalTransform.IsIdentity;
            bool noTrack = !engine.HasActive;
            Check("EM.h resize-frame cancel restores declared LayoutInput (NaN), resets presented size + transform, clears Relayouting",
                inFlight && liRestored && presentedReset && relayoutCleared && noOffset && noTrack,
                $"inFlight={inFlight} li={liRestored} pres={presentedReset} relayout={relayoutCleared} offset={noOffset} track={noTrack}");
        }
    }

    // Native skeleton-loading (the Skel.Region kit): ONE UI source → derived shimmer → blur-reveal swap, partial-known,
    // incremental per-field, failed, reduced-motion, and the wake-loop pulse-cancel. Drives the loadable across a flush.
    private sealed record SkTrack(int Number, string Title, string Dur);

    static Element SkRow(SkTrack? t) => new BoxEl
    {
        Direction = 0, Gap = 12f,
        Children =
        [
            new TextEl(t is null ? "" : t.Number.ToString()) { Size = 14f, Width = 24f },
            new TextEl(t?.Title ?? "") { Size = 14f, Grow = 1f },
            new TextEl(t?.Dur ?? "") { Size = 13f, Width = 48f },
        ],
    };

    static int CountText(SceneStore s, NodeHandle n)
    {
        int c = s.Paint(n).VisualKind == VisualKind.Text ? 1 : 0;
        for (var ch = s.FirstChild(n); !ch.IsNull; ch = s.NextSibling(ch)) c += CountText(s, ch);
        return c;
    }

    static int CountNodes(SceneStore s, NodeHandle n)
    {
        int c = 1;
        for (var ch = s.FirstChild(n); !ch.IsNull; ch = s.NextSibling(ch)) c += CountNodes(s, ch);
        return c;
    }

    static void SkeletonChecks(StringTable strings)
    {
        var fonts = new HeadlessFontSystem(strings);

        // SK.a derivation fidelity + SK.b swap + SK.c wake-loop.
        {
            var scene = new SceneStore();
            var engine = new AnimEngine(scene);
            var recon = new TreeReconciler(scene, strings) { Anim = engine };
            var tracks = Loadable<SkTrack[]>.Pending(Array.Empty<SkTrack>());
            recon.ReconcileRoot(
                Skel.Region(tracks, SkRow, count: 5,
                    content: ts => Flow.For<SkTrack>(() => ts, t => t.Number.ToString(), (t, i) => SkRow(t)),
                    reveal: SkelReveal.StaggerRows),
                null);
            new FlexLayout(scene, fonts).Run(scene.Root);

            var region = scene.Root;
            var shimmer = Child(scene, region, 0);
            int shimmerRows = 0; for (var c = scene.FirstChild(shimmer); !c.IsNull; c = scene.NextSibling(c)) shimmerRows++;
            var row0 = Child(scene, shimmer, 0);
            bool widths = Near(scene.Bounds(Child(scene, row0, 0)).W, 24f, 0.5f) && Near(scene.Bounds(Child(scene, row0, 2)).W, 48f, 0.5f);
            bool noTextPending = CountText(scene, region) == 0;
            bool pulsing = engine.LoopTrackCount >= 1;
            Check("SK.a skeleton derives N shimmer rows from the ONE row template (declared bar widths 24/48; no real text; pulsing)",
                shimmerRows == 5 && widths && noTextPending && pulsing,
                $"rows={shimmerRows} bar0={scene.Bounds(Child(scene, row0, 0)).W:0} bar2={scene.Bounds(Child(scene, row0, 2)).W:0} text={CountText(scene, region)} loops={engine.LoopTrackCount}");

            tracks.SetReady(new[] { new SkTrack(1, "One", "1:01"), new SkTrack(2, "Two", "2:02"), new SkTrack(3, "Three", "3:03") });
            recon.Runtime.Flush();
            new FlexLayout(scene, fonts).Run(scene.Root);
            bool realText = CountText(scene, region) > 0;
            engine.Tick(0f);
            var realRow0 = Child(scene, Child(scene, region, 0), 0);
            bool revealSeeded = engine.TryGetTrackValue(realRow0, AnimChannel.Opacity, out var op0) && op0 < 0.2f;
            Check("SK.b Pending→Ready swaps shimmer→real (text appears) and blur-reveals the rows",
                realText && revealSeeded, $"realText={realText} revealOp0={op0:0.00}");

            for (int i = 0; i < 80 && engine.HasActive; i++) engine.Tick(16f);
            Check("SK.c the looping skeleton pulse is cancelled on swap (no loop pins the orphan — wake-loop fix)",
                engine.LoopTrackCount == 0, $"loops={engine.LoopTrackCount} active={engine.HasActive}");
        }

        // SK.d partial-known: a pre-Ready region renders real immediately (no shimmer).
        {
            var scene = new SceneStore();
            var recon = new TreeReconciler(scene, strings);
            var ready = Loadable<SkTrack[]>.Ready(new[] { new SkTrack(1, "Known", "0:30") });
            recon.ReconcileRoot(
                Skel.Region(ready, SkRow, count: 3, content: ts => Flow.For<SkTrack>(() => ts, t => t.Number.ToString(), (t, i) => SkRow(t))),
                null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            Check("SK.d a pre-Ready region (partial-known data) renders REAL immediately — no shimmer",
                CountText(scene, scene.Root) > 0, $"text={CountText(scene, scene.Root)}");
        }

        // SK.e incremental per-field: .Pending(field) shimmers ONE leaf in place and reveals on the field flip.
        {
            var scene = new SceneStore();
            var engine = new AnimEngine(scene);
            var recon = new TreeReconciler(scene, strings) { Anim = engine };
            var dur = Loadable<string>.Pending("");
            Element leaf = new TextEl("") { Text = dur.Bind(), Size = 13f, Width = 48f }.Pending(dur);
            recon.ReconcileRoot(new BoxEl { Direction = 0, Children = [new TextEl("Title") { Size = 14f }, leaf] }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var leafRegion = Child(scene, scene.Root, 1);
            bool pendingBar = CountText(scene, leafRegion) == 0;
            dur.SetReady("3:14");
            recon.Runtime.Flush();
            new FlexLayout(scene, fonts).Run(scene.Root);
            bool nowReal = CountText(scene, leafRegion) > 0;
            Check("SK.e incremental field (.Pending) shimmers ONE leaf in place, reveals on the field flip (row identity kept)",
                pendingBar && nowReal, $"pendingBar={pendingBar} nowReal={nowReal}");
        }

        // SK.f failed: SetFailed mounts the onFailed branch.
        {
            var scene = new SceneStore();
            var recon = new TreeReconciler(scene, strings);
            var ld = Loadable<SkTrack[]>.Pending(Array.Empty<SkTrack>());
            recon.ReconcileRoot(
                Skel.Region(ld, SkRow, count: 3, content: ts => Flow.For<SkTrack>(() => ts, t => t.Number.ToString(), (t, i) => SkRow(t)),
                    onFailed: () => new TextEl("FAILED") { Size = 14f }),
                null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            ld.SetFailed(new Exception("nope"));
            recon.Runtime.Flush();
            new FlexLayout(scene, fonts).Run(scene.Root);
            Check("SK.f a failed load mounts the onFailed branch", CountText(scene, scene.Root) == 1, $"text={CountText(scene, scene.Root)}");
        }

        // SK.g reduced motion: structural swap occurs, but no pulse/reveal tracks are seeded (snap).
        {
            bool prev = Motion.ReducedMotion;
            Motion.ReducedMotion = true;
            try
            {
                var scene = new SceneStore();
                var engine = new AnimEngine(scene);
                var recon = new TreeReconciler(scene, strings) { Anim = engine };
                var tracks = Loadable<SkTrack[]>.Pending(Array.Empty<SkTrack>());
                recon.ReconcileRoot(
                    Skel.Region(tracks, SkRow, count: 3, content: ts => Flow.For<SkTrack>(() => ts, t => t.Number.ToString(), (t, i) => SkRow(t))),
                    null);
                new FlexLayout(scene, fonts).Run(scene.Root);
                bool noPulse = engine.LoopTrackCount == 0;
                tracks.SetReady(new[] { new SkTrack(1, "R", "0:01") });
                recon.Runtime.Flush();
                new FlexLayout(scene, fonts).Run(scene.Root);
                bool real = CountText(scene, scene.Root) > 0;
                bool noReveal = !engine.HasActive;
                Check("SK.g reduced motion: structural swap occurs but no pulse/reveal tracks are seeded (snap)",
                    noPulse && real && noReveal, $"noPulse={noPulse} real={real} noReveal={noReveal}");
            }
            finally { Motion.ReducedMotion = prev; }
        }

        // RM.a reduced-motion-as-value (engine seed, the rework): under reduced motion a SnapEnd token snaps EVERY channel
        // (incl Opacity) to its end-state immediately — no glide, settles in one frame; a KeepFade token still cross-fades
        // Opacity (a fade aids orientation, it is not "motion"). Proves the engine reads reduced-motion as DATA at the seed
        // (AnimScheduler.Structural.ReducedSnap), never an early-return — the [[motion-hooks-reducedmotion-conditional]] fix.
        {
            bool prev = Motion.ReducedMotion;
            Motion.ReducedMotion = true;
            try
            {
                var sceneA = new SceneStore();
                var engineA = new AnimEngine(sceneA);
                new TreeReconciler(sceneA, strings).ReconcileRoot(new BoxEl { Width = 40, Height = 40, Fill = ColorF.FromRgba(0, 0, 0) }, null);
                engineA.SeedEnter(sceneA.Root, new EnterExit(Opacity: 0f, Active: true), MotionTokenDef.Eased(300f, Easing.FluentDecelerate));   // bare Eased ⇒ SnapEnd
                engineA.Tick(16f); engineA.Tick(16f);
                bool snapEnd = sceneA.Paint(sceneA.Root).Opacity > 0.99f && !engineA.HasActive;

                var sceneB = new SceneStore();
                var engineB = new AnimEngine(sceneB);
                new TreeReconciler(sceneB, strings).ReconcileRoot(new BoxEl { Width = 40, Height = 40, Fill = ColorF.FromRgba(0, 0, 0) }, null);
                engineB.SeedEnter(sceneB.Root, new EnterExit(Opacity: 0f, Active: true), MotionTok.StandardEnter);   // KeepFade
                engineB.Tick(16f); engineB.Tick(16f);   // 2 ticks: the seed frame holds the initial value, the advance begins next frame
                float opB = sceneB.Paint(sceneB.Root).Opacity;
                bool keepFade = opB > 0.001f && opB < 0.99f && engineB.HasActive;

                Check("RM.a reduced-motion-as-value: SnapEnd token snaps Opacity to end (no glide); KeepFade still cross-fades",
                    snapEnd && keepFade, $"snapEnd={snapEnd} keepFadeOp={opB:0.00} keepFadeActive={engineB.HasActive}");
            }
            finally { Motion.ReducedMotion = prev; }
        }

        // ST.a Stagger (declarative): a parent's Stagger delays each child's Enter by (sibling index × stagger ms) — the
        // staggered list/shelf reveal. After a sub-stagger tick, child 0 is fading in but child 2 is still delayed (0 opacity).
        {
            var sceneS = new SceneStore();
            var engineS = new AnimEngine(sceneS);
            var reconS = new TreeReconciler(sceneS, strings) { Anim = engineS };
            EnterExit fadeS = new(Opacity: 0f, Active: true);
            reconS.ReconcileRoot(new BoxEl
            {
                Direction = 1, Stagger = 100f,
                Children =
                [
                    new BoxEl { Width = 20, Height = 20, Fill = ColorF.FromRgba(0, 0, 0), Enter = fadeS, Transition = MotionTok.ControlNormal },
                    new BoxEl { Width = 20, Height = 20, Fill = ColorF.FromRgba(0, 0, 0), Enter = fadeS, Transition = MotionTok.ControlNormal },
                    new BoxEl { Width = 20, Height = 20, Fill = ColorF.FromRgba(0, 0, 0), Enter = fadeS, Transition = MotionTok.ControlNormal },
                ],
            }, null);
            new FlexLayout(sceneS, fonts).Run(sceneS.Root);
            var cs0 = Child(sceneS, sceneS.Root, 0);
            var cs2 = Child(sceneS, sceneS.Root, 2);
            engineS.Tick(16f); engineS.Tick(16f); engineS.Tick(16f);   // ~48ms < the 100ms stagger to child 1 (200ms to child 2)
            float ops0 = sceneS.Paint(cs0).Opacity, ops2 = sceneS.Paint(cs2).Opacity;
            Check("ST.a Stagger: a parent staggers child Enters (child 0 revealing, child 2 still delayed)",
                ops0 > 0.01f && ops2 < 0.01f, $"op0={ops0:0.00} op2={ops2:0.00}");
        }

        // RT.a FLIP relativeTarget: a follower's RelativeTo resolves to the live node carrying that MorphId (the
        // shared-layout anchor the host's projection capture FLIPs against, so the follower rides the anchor coherently
        // instead of double-counting its motion). A plain node resolves to none (the default parent-relative FLIP).
        {
            var sceneR = new SceneStore();
            var reconR = new TreeReconciler(sceneR, strings);
            reconR.ReconcileRoot(new BoxEl
            {
                Children =
                [
                    new BoxEl { Width = 20, Height = 20, MorphId = "grp" },     // the anchor
                    new BoxEl { Width = 20, Height = 20, RelativeTo = "grp" },   // the follower
                    new BoxEl { Width = 20, Height = 20 },                       // a plain node (no relativeTarget)
                ],
            }, null);
            var anchorR = Child(sceneR, sceneR.Root, 0);
            var followerR = Child(sceneR, sceneR.Root, 1);
            var plainR = Child(sceneR, sceneR.Root, 2);
            bool resolves = reconR.ResolveRelativeTarget(followerR) == anchorR;
            bool plainNull = reconR.ResolveRelativeTarget(plainR).IsNull;
            Check("RT.a FLIP relativeTarget: a follower resolves to its keyed shared-layout anchor (plain node → none)",
                resolves && plainNull, $"resolves={resolves} plainNull={plainNull}");
        }

        // CF.a connected-fly rebuild (FG_DETACHED_FLY): SceneRecorder.RecordDetached draws a DetachedAnimSlab snapshot as
        // an image at its baked WORLD transform + opacity — the render path that replaces the live overlay node. Device-
        // verified directly (the per-frame ConnectedAnimation.SyncDetached mirror, which feeds these fields, uses the exact
        // recorder world formula, so a fly drawn this way is pixel-identical to the live-overlay path).
        {
            var slab = new DetachedAnimSlab();
            int g = slab.OpenGroup(default, PresenceMode.Sync);
            int s = slab.Detach(g);
            ref DetachedNode d = ref slab.At(s);
            d.Kind = (byte)VisualKind.Image;
            d.ImageId = 1;                                   // images=null ⇒ placeholder-fill path; we verify the rect/world/opacity emit
            d.Bounds = new RectF(0f, 0f, 40f, 40f);
            d.WorldTransform = Affine2D.Translation(100f, 50f);
            d.Opacity = 0.5f;
            d.Fill = ColorF.FromRgba(255, 255, 255);
            var dl = new DrawList();
            SceneRecorder.RecordDetached(new SceneStore(), dl, null, slab, RectF.Infinite);
            var dev = new HeadlessGpuDevice();
            dev.SubmitDrawList(dl.Bytes, dl.SortKeys, new FrameInfo(new Size2(200, 200), 1f, ColorF.Transparent));
            bool drew = false;
            foreach (var im in dev.LastImages)
                if (im.ImageId == 1 && Near(im.Rect.W, 40f, 0.5f) && Near(im.Opacity, 0.5f, 0.02f) && Near(im.Transform.Dx, 100f, 0.5f)) drew = true;
            bool retired = slab.Retire(s) == g && slab.Count == 0;   // completion-gate retirement frees the row + the group
            Check("CF.a connected-fly rebuild: RecordDetached draws a detached snapshot at its world transform + opacity; Retire frees the slot",
                drew && retired, $"images={dev.LastImages.Count} drew={drew} retired={retired}");
        }

        // SK.h smooth-resize: the region is BoundsAnimated + carries a SizeMode.Reflow transition, so a height-changing
        // swap eases the region's layout size (the host re-solves the parent each tick → surrounding content reflows,
        // not snaps). The reflow RUNTIME is the host-driven FLIP path (proven by ReflowChecks); here we prove the region
        // is enrolled AND that its spec produces a reflow track when the host applies the bounds diff.
        {
            var scene = new SceneStore();
            var engine = new AnimEngine(scene);
            var recon = new TreeReconciler(scene, strings) { Anim = engine };
            var ld = Loadable<SkTrack[]>.Pending(Array.Empty<SkTrack>());
            recon.ReconcileRoot(
                Skel.Region(ld, SkRow, count: 4, content: ts => Flow.For<SkTrack>(() => ts, t => t.Number.ToString(), (t, i) => SkRow(t))),
                null);
            var region = scene.Root;
            bool boundsAnim = (scene.Flags(region) & NodeFlags.BoundsAnimated) != 0;
            bool reflowSpec = engine.TryGetTransition(region, out var spec) && (spec.Channels & TransitionChannels.Size) != 0 && spec.Size == SizeMode.Reflow;
            // Mimic the host FLIP "apply" for a shrinking swap (4 shimmer rows → a short branch): a Reflow size track runs.
            new FlexLayout(scene, fonts).Run(scene.Root);
            engine.AnimateBounds(region, new RectF(0, 0, 320, 200), new RectF(0, 0, 320, 60), spec);
            bool reflowRuns = engine.HasActive;
            Check("SK.h smooth-resize: region is BoundsAnimated + SizeMode.Reflow → a height-changing swap reflows surrounding content (not snap)",
                boundsAnim && reflowSpec && reflowRuns, $"boundsAnim={boundsAnim} reflowSpec={reflowSpec} reflowRuns={reflowRuns}");
        }

        // SK.i composes with VIRTUALIZATION: a region whose content is a 10k-row Virtual.List swaps to a WINDOWED list
        // (only a viewport-worth of rows realized, not 10k materialized) — so skeleton-loading scales to huge lists (the
        // Wavee track list). Shimmer = a viewport-fill of placeholder rows (NOT 10k); real = the virtualized list.
        {
            var scene = new SceneStore();
            var engine = new AnimEngine(scene);
            var recon = new TreeReconciler(scene, strings) { Anim = engine };
            var count = Loadable<int>.Pending(0);
            var shimmerRows = new Element[8];
            for (int i = 0; i < shimmerRows.Length; i++) shimmerRows[i] = SkRow(null);
            recon.ReconcileRoot(new BoxEl
            {
                Width = 360f, Height = 400f, ClipToBounds = true,
                Children =
                [
                    Skel.Region(count,
                        shimmerSource: () => new BoxEl { Direction = 1, Gap = 8f, Children = shimmerRows },
                        content: n => Virtual.List(n, 44f, i => SkRow(new SkTrack(i + 1, "Track " + (i + 1), "0:00")), keyOf: i => i.ToString())),
                ],
            }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            int pendingNodes = CountNodes(scene, scene.Root);
            count.SetReady(10_000);
            recon.Runtime.Flush();
            new FlexLayout(scene, fonts).Run(scene.Root);
            int realNodes = CountNodes(scene, scene.Root);
            Check("SK.i composes with a 10k-row Virtual.List — swaps to a WINDOWED list (≪10k nodes realized, not 10k)",
                realNodes < 2000, $"pendingNodes={pendingNodes} realNodes={realNodes} (10k items)");
        }
    }

    // General layout-transition projection (continuous FLIP): the side-table plumbing, the spring that drives a moved
    // node's presented offset → 0, and the velocity-continuous reframe that keeps an interrupted move from jumping.
    static void ProjectionChecks(StringTable strings)
    {
        // 23a — BoxEl.Animate wires the BoundsAnimated flag + the per-node transition side-table (Phase 0 plumbing).
        {
            var scene = new SceneStore();
            var engine = new AnimEngine(scene);
            var recon = new TreeReconciler(scene, strings) { Anim = engine };
            recon.ReconcileRoot(new BoxEl { Animate = LayoutTransition.Slide, Width = 50, Height = 20 }, null);
            var root = scene.Root;
            bool flagSet = (scene.Flags(root) & NodeFlags.BoundsAnimated) != 0;
            bool roundTrip = engine.TryGetTransition(root, out var spec) && spec.Channels == TransitionChannels.Position;
            // dropping Animate clears both
            recon.ReconcileRoot(new BoxEl { Width = 50, Height = 20 }, new BoxEl { Animate = LayoutTransition.Slide, Width = 50, Height = 20 });
            bool cleared = (scene.Flags(root) & NodeFlags.BoundsAnimated) == 0 && !engine.TryGetTransition(root, out _);
            Check("23a. BoxEl.Animate ↔ BoundsAnimated + transition side-table (set/clear)", flagSet && roundTrip && cleared);
        }

        // 23b — a moved node FLIPs: the presented offset springs old→new monotonically and settles, never relaying out.
        {
            var scene = new SceneStore();
            var n = scene.CreateNode(1); scene.Root = n;
            ref RectF nb = ref scene.Bounds(n); nb = new RectF(0, 200, 50, 20);   // final laid-out position
            var engine = new AnimEngine(scene);
            scene.Flags(n) &= ~(NodeFlags.TransformDirty | NodeFlags.LayoutDirty);
            var crit = new LayoutTransition(TransitionChannels.Position, TransitionDynamics.Spring(0.18f, 1.0f));  // critically damped → no overshoot
            engine.AnimateBounds(n, new RectF(0, 100, 50, 20), new RectF(0, 200, 50, 20), crit);  // was at y=100, now laid out at y=200

            bool monotonic = true; float prev = -1e9f; int settledAt = -1;
            for (int i = 0; i < 80 && settledAt < 0; i++)
            {
                engine.Tick(16f);
                float dy = scene.Paint(n).LocalTransform.Dy;
                if (i > 0 && dy < prev - 0.6f) monotonic = false;   // offset climbs -100 → 0
                prev = dy;
                if (!engine.HasActive) settledAt = i;
            }
            var f = scene.Flags(n);
            bool noRelayout = (f & NodeFlags.LayoutDirty) == 0 && (f & NodeFlags.TransformDirty) != 0;
            bool settledZero = settledAt >= 0 && MathF.Abs(scene.Paint(n).LocalTransform.Dy) < 0.5f;
            Check("23b. projection FLIPs a moved node (offset springs → 0, settles, no relayout)",
                monotonic && settledZero && noRelayout, $"settled@{settledAt}");
        }

        // 23c — interruption is velocity-continuous: re-projecting mid-flight must NOT snap the presented position
        // (the old code overwrote the transform, losing the in-flight offset → the visible jump).
        {
            var scene = new SceneStore();
            var n = scene.CreateNode(1); scene.Root = n;
            ref RectF nb = ref scene.Bounds(n); nb = new RectF(0, 200, 50, 20);
            var engine = new AnimEngine(scene);
            // a slow spring keeps per-tick motion tiny (~3px), so the continuity test isolates the reframe (≈3px) from
            // the old overwrite bug (which loses the in-flight offset → a ~90px snap).
            var spring = new LayoutTransition(TransitionChannels.Position, TransitionDynamics.Spring(1.0f, 1.0f));
            engine.AnimateBounds(n, new RectF(0, 100, 50, 20), new RectF(0, 200, 50, 20), spring);
            for (int i = 0; i < 5; i++) engine.Tick(16f);
            float d = scene.Paint(n).LocalTransform.Dy;     // in-flight offset (large for a slow spring)
            float presentedBefore = nb.Y + d;               // its on-screen Y this instant
            // it moves again to y=300; layout snaps Bounds, the transform is unchanged → toAbs = 300 + d
            nb = new RectF(0, 300, 50, 20);
            engine.AnimateBounds(n, new RectF(0, presentedBefore, 50, 20), new RectF(0, 300f + d, 50, 20), spring);
            engine.Tick(16f);
            float presentedAfter = 300f + scene.Paint(n).LocalTransform.Dy;
            bool continuous = MathF.Abs(presentedAfter - presentedBefore) < 15f;
            Check("23c. projection reframes on interruption (velocity-continuous, no jump)",
                continuous, $"presented {presentedBefore:0.0}→{presentedAfter:0.0}");
        }

        // 23d — Reveal (size): the presented extent springs old→new with NO relayout (model Bounds stay final), and
        // resets to NaN on settle so the recorder falls back to the layout size. This replaces the deleted Width channel.
        {
            var scene = new SceneStore();
            var n = scene.CreateNode(1); scene.Root = n;
            ref RectF nb = ref scene.Bounds(n); nb = new RectF(0, 0, 48, 600);   // final (collapsed) model width
            scene.Flags(n) &= ~NodeFlags.LayoutDirty;
            var engine = new AnimEngine(scene);
            var reveal = LayoutTransition.BoundsT(SizeMode.Reveal) with { Dynamics = TransitionDynamics.Spring(0.18f, 1.0f) };
            engine.AnimateBounds(n, new RectF(0, 0, 320, 600), new RectF(0, 0, 48, 600), reveal);  // collapsing 320 → 48
            engine.Tick(16f);
            float firstW = scene.Paint(n).PresentedW;                    // presented starts near 320 (not snapped to 48)
            bool startedWide = firstW > 200f;
            bool noRelayout = (scene.Flags(n) & NodeFlags.LayoutDirty) == 0;
            bool modelFinal = Near(scene.Bounds(n).W, 48f);              // only the presented extent animates
            int settledAt = -1;
            for (int i = 0; i < 90 && settledAt < 0; i++) { engine.Tick(16f); if (!engine.HasActive) settledAt = i; }
            bool resetNaN = float.IsNaN(scene.Paint(n).PresentedW);      // on settle, falls back to the (final) layout size
            Check("23d. Reveal springs presented size (no relayout, model final, resets on settle)",
                startedWide && noRelayout && modelFinal && resetNaN && settledAt >= 0, $"firstW={firstW:0} settled@{settledAt}");
        }
    }

    // Enter/exit lifecycle: a removed node with Exit.Active is kept live (an orphan) and drawn while it fades, then
    // deferred-freed on settle; a mounted node with Enter.Active appears from its enter terminal.
    static void EnterExitChecks(StringTable strings)
    {
        // 23e — exit orphan: removing the child keeps it live + drawing until its fade settles, then reclaims (gen bump).
        {
            var scene = new SceneStore();
            var engine = new AnimEngine(scene);
            var recon = new TreeReconciler(scene, strings) { Anim = engine };
            var exit = new LayoutTransition(TransitionChannels.Opacity, TransitionDynamics.Spring(0.12f, 1f),
                Exit: new EnterExit(Opacity: 0f, Active: true));
            Element Tree(bool present) => new BoxEl
            {
                Width = 100, Height = 100,
                Children = present ? [new BoxEl { Key = "x", Width = 50, Height = 20, Animate = exit }] : [],
            };
            var old = Tree(true);
            recon.ReconcileRoot(old, null);
            new FlexLayout(scene, new HeadlessFontSystem(strings)).Run(scene.Root);
            var child = Child(scene, scene.Root, 0);
            bool mountedLive = scene.IsLive(child);

            recon.ReconcileRoot(Tree(false), old);                       // remove → orphan + seed exit
            bool orphaned = scene.IsOrphan(child) && scene.IsLive(child) && scene.OrphanCount == 1;

            int settledAt = -1;
            for (int i = 0; i < 90 && settledAt < 0; i++)
            {
                engine.Tick(16f);
                for (int k = scene.OrphanCount - 1; k >= 0; k--)        // host's ReclaimSettledOrphans
                { var o = scene.OrphanAt(k, out _, out _); if (!engine.HasTracks(o)) scene.ReclaimOrphan(o); }
                if (scene.OrphanCount == 0) settledAt = i;
            }
            bool reclaimed = settledAt >= 0 && !scene.IsLive(child);     // deferred free → handle dead
            Check("23e. exit orphan stays live while fading, then reclaims (deferred free)",
                mountedLive && orphaned && reclaimed, $"settled@{settledAt}");
        }

        // 23e2: an exit inside a rounded flyout + rectangular scroller must replay at its former parent, not in the
        // global un-clipped band. Outgoing paints first (behind the incoming row), under both active ancestor clips.
        // Hard-removing the containing surface then cascade-reclaims the still-running exit.
        {
            var scene = new SceneStore();
            var engine = new AnimEngine(scene);
            var recon = new TreeReconciler(scene, strings) { Anim = engine };
            var fonts = new HeadlessFontSystem(strings);
            var exit = new LayoutTransition(TransitionChannels.Opacity, TransitionDynamics.Tween(300f, Easing.Linear),
                Exit: new EnterExit(Dy: -4f, Opacity: 0f, Active: true));
            ColorF outgoingColor = ColorF.FromRgba(211, 47, 47);
            ColorF incomingColor = ColorF.FromRgba(33, 150, 243);

            Element Tree(bool incoming, bool surface = true) => new BoxEl
            {
                Width = 180, Height = 140,
                Children = surface
                    ?
                    [
                        new BoxEl
                        {
                            Width = 120, Height = 80, ClipToBounds = true, Corners = CornerRadius4.All(8f),
                            Children =
                            [
                                new BoxEl
                                {
                                    Width = 100, Height = 40, Margin = Edges4.All(10f), ClipToBounds = true,
                                    Children =
                                    [
                                        new BoxEl
                                        {
                                            Key = incoming ? "incoming" : "outgoing",
                                            Width = 100, Height = 80,
                                            Fill = incoming ? incomingColor : outgoingColor,
                                            Animate = exit,
                                        },
                                    ],
                                },
                            ],
                        },
                    ]
                    : [],
            };

            var old = Tree(incoming: false);
            recon.ReconcileRoot(old, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var outgoing = Child(scene, Child(scene, Child(scene, scene.Root, 0), 0), 0);

            var next = Tree(incoming: true);
            recon.ReconcileRoot(next, old);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var dl = new DrawList();
            SceneRecorder.Record(scene, dl);
            var outCmd = FindFillCommand(dl, outgoingColor);
            var inCmd = FindFillCommand(dl, incomingColor);
            bool contained = scene.IsOrphan(outgoing) && outCmd.Order >= 0 && inCmd.Order >= 0
                             && outCmd.Order < inCmd.Order && outCmd.ClipDepth == 2 && inCmd.ClipDepth == 2;

            var empty = Tree(incoming: true, surface: false);
            recon.ReconcileRoot(empty, next);
            engine.Tick(0f);   // freed-handle rows self-prune on the animation slab's next gen-check
            bool cascaded = scene.OrphanCount == 0 && !scene.IsLive(outgoing) && !engine.HasTracks(outgoing);
            Check("23e2. exits replay inside former parent clip/order and cascade-reclaim when that parent is removed",
                contained && cascaded,
                $"out={outCmd.Order}@clip{outCmd.ClipDepth} in={inCmd.Order}@clip{inCmd.ClipDepth} cascaded={cascaded}");
        }

        // 23f — enter: a mounted node with Enter.Active starts at the enter terminal (opacity 0) and springs to 1.
        {
            var scene = new SceneStore();
            var engine = new AnimEngine(scene);
            var recon = new TreeReconciler(scene, strings) { Anim = engine };
            var enter = new LayoutTransition(TransitionChannels.Opacity, TransitionDynamics.Spring(0.15f, 1f),
                Enter: new EnterExit(Opacity: 0f, Active: true));
            recon.ReconcileRoot(new BoxEl { Width = 100, Height = 100, Children = [new BoxEl { Width = 50, Height = 20, Animate = enter }] }, null);
            new FlexLayout(scene, new HeadlessFontSystem(strings)).Run(scene.Root);
            var child = Child(scene, scene.Root, 0);
            engine.Tick(16f);
            float a1 = scene.Paint(child).Opacity;                      // entering: near 0
            for (int i = 0; i < 90; i++) engine.Tick(16f);
            float a2 = scene.Paint(child).Opacity;                      // settled to 1
            Check("23f. enter animates a mounted node from the enter terminal (opacity 0 → 1)",
                a1 < 0.5f && Near(a2, 1f), $"opacity {a1:0.00}→{a2:0.00}");
        }

        // (The CheckBox checkmark draw-on is a component reveal hook → it needs the host's layout-effect drain, so it is
        //  exercised through the real AppHost in check 66b, not the bare reconciler here.)

        // 23h — WinUI RadioButton motion: CheckGlyph is 12px at rest, 14px on PointerOver, 10px on Pressed; unchecked
        // Pressed uses a separate PressedCheckGlyph that appears while held and grows from 4px toward 10px.
        {
            var scene = new SceneStore();
            var recon = new TreeReconciler(scene, strings);
            recon.ReconcileRoot(RadioButton.Create("x", true), null);   // root = row; ring = child0; dot = ring.child0
            new FlexLayout(scene, new HeadlessFontSystem(strings)).Run(scene.Root);
            var ring = Child(scene, scene.Root, 0);
            var dot = Child(scene, ring, 0);
            bool sized = Near(scene.Bounds(dot).W, 12f, 0.01f) && Near(scene.Bounds(dot).H, 12f, 0.01f);
            bool interactive = scene.TryGetInteract(dot, out var ia)
                && Near(ia.HoverScale, 14f / 12f, 0.001f)
                && Near(ia.PressScale, 10f / 12f, 0.001f)
                && Near(ia.HoverDurationMs, 250f, 0.01f)
                && Near(ia.PressDurationMs, 250f, 0.01f);
            bool instantChecked = scene.Paint(dot).LocalTransform.IsIdentity;
            Check("23h. RadioButton wires WinUI CheckGlyph size states (12 rest, 14 hover, 10 pressed)",
                sized && interactive && instantChecked,
                $"size={scene.Bounds(dot).W:0.#} hoverScale={ia.HoverScale:0.###} pressScale={ia.PressScale:0.###}");

            var unselected = new SceneStore();
            var unselectedRecon = new TreeReconciler(unselected, strings);
            unselectedRecon.ReconcileRoot(RadioButton.Create("x", false), null);
            new FlexLayout(unselected, new HeadlessFontSystem(strings)).Run(unselected.Root);
            var unselectedRing = Child(unselected, unselected.Root, 0);
            var pressedGlyph = Child(unselected, unselectedRing, 0);
            bool hiddenAtRest = Near(unselected.Bounds(pressedGlyph).W, 4f, 0.01f)
                && Near(unselected.Paint(pressedGlyph).Opacity, 0f, 0.001f)
                && Near(unselected.Paint(pressedGlyph).PressedOpacity, 1f, 0.001f);
            bool growsToPressedSize = unselected.TryGetInteract(pressedGlyph, out var pia)
                && Near(pia.PressScale, 10f / 4f, 0.001f)
                && Near(pia.PressDurationMs, 167f, 0.01f);

            var iax = new AnimEngine(unselected);   // hover/press now engine-driven (InteractionAnimator subsumed)
            iax.SetPress(unselected.Root, true);
            iax.Tick(16f);
            var dl = new DrawList();
            SceneRecorder.Record(unselected, dl);
            var dev = new HeadlessGpuDevice();
            dev.SubmitDrawList(dl.Bytes, dl.SortKeys, new FrameInfo(new Size2(120, 80), 1f, ColorF.Transparent));
            bool drewPressedGlyph = false;
            foreach (var rect in dev.LastRects)
                if (Near(rect.Rect.W, 4f, 0.01f) && rect.Opacity > 0.08f && rect.Transform.M11 > 1.08f)
                    drewPressedGlyph = true;
            Check("23h2. RadioButton unchecked press draws PressedCheckGlyph (4px hidden → visible/growing toward 10px)",
                hiddenAtRest && growsToPressedSize && drewPressedGlyph,
                $"rest={hiddenAtRest} scale={pia.PressScale:0.###} drew={drewPressedGlyph}");
        }

        // 23i — visual-state RAMP wiring (the StateBrush model, not a 12-state matrix): an unchecked CheckBox wires the
        // full interaction ladder into the box's scene columns. Crucially the PRESSED stroke DIMS to
        // ControlStrongStrokeColorDisabled (the exact WinUI press feedback) — provable here without pixels, the empirical
        // counterpart to a screenshot. The recorder eases BorderColor→PressedBorderColor on PressT (covered by check 58).
        {
            var scene = new SceneStore();
            var recon = new TreeReconciler(scene, strings);
            recon.ReconcileRoot(CheckBox.Create("x", new Signal<CheckState>(CheckState.Unchecked)), null);
            var cbRow = FindRole(scene, scene.Root, AutomationRole.CheckBox);   // CheckBox is a component now → find its row
            ref var p = ref scene.Paint(Child(scene, cbRow, 0));   // the 20px box (child 0 of the CheckBox row)
            bool restRing = MathF.Abs(p.BorderColor.A - Tok.StrokeControlStrongDefault.A) < 0.02f;
            bool pressDims = MathF.Abs(p.PressedBorderColor.A - Tok.StrokeControlStrongDisabled.A) < 0.02f && p.PressedBorderColor.A < p.BorderColor.A;
            bool hoverFill = MathF.Abs(p.HoverFill.A - Tok.FillControlAltTertiary.A) < 0.02f;
            bool pressFill = MathF.Abs(p.PressedFill.A - Tok.FillControlAltQuaternary.A) < 0.02f;
            Check("23i. CheckBox wires the interaction ramp (pressed stroke dims to StrongDisabled, no 12-state matrix)",
                restRing && pressDims && hoverFill && pressFill,
                $"ring.A={p.BorderColor.A:0.00}→press {p.PressedBorderColor.A:0.00}; fill hover.A={p.HoverFill.A:0.00} press.A={p.PressedFill.A:0.00}");
        }

    }

    // Smallest in-flight presented width anywhere in a subtree (a DrawnCheckmark/DrawnDash reveal), else NaN. The
    // checkmark "draws itself" by sweeping its clip box's presented width 0→full — this lets a check assert the draw-on
    // empirically (mid-reveal: 0 &lt; w &lt; full; settled: NaN, since AnimEngine resets a finished reveal to NaN).
    static float RevealingW(SceneStore s, NodeHandle n)
    {
        float best = float.NaN;
        float w = s.Paint(n).PresentedW;
        if (!float.IsNaN(w)) best = w;
        for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
        {
            float cw = RevealingW(s, c);
            if (!float.IsNaN(cw) && (float.IsNaN(best) || cw < best)) best = cw;
        }
        return best;
    }

    // The opt-in size modes: ScaleCorrect (GPU scale → 1, compositor-only) and Relayout (re-solve the subtree at the
    // interpolated size each tick → live text reflow), both via the same general AnimateBounds entry point.
    // Smallest active stroke-trim end in a subtree (DrawnCheckmark/DrawnDash), else NaN. A freshly seeded draw-on starts
    // at 0, advances between 0 and 1 while active, then AnimEngine resets the override to NaN when the track settles.
    static float ActiveStrokeTrimEnd(SceneStore s, NodeHandle n)
    {
        float best = float.NaN;
        float t = s.Paint(n).StrokeTrimEnd;
        if (!float.IsNaN(t)) best = t;
        for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
        {
            float ct = ActiveStrokeTrimEnd(s, c);
            if (!float.IsNaN(ct) && (float.IsNaN(best) || ct < best)) best = ct;
        }
        return best;
    }

    static void SizeModeChecks(StringTable strings)
    {
        // 23g — ScaleCorrect: a grown node starts scaled-down and springs its scale to 1, never relaying out.
        {
            var scene = new SceneStore();
            var n = scene.CreateNode(1); scene.Root = n;
            ref RectF nb = ref scene.Bounds(n); nb = new RectF(0, 0, 200, 100);
            scene.Flags(n) &= ~NodeFlags.LayoutDirty;
            var engine = new AnimEngine(scene);
            var sc = LayoutTransition.BoundsT(SizeMode.ScaleCorrect) with { Dynamics = TransitionDynamics.Spring(0.2f, 1f) };
            engine.AnimateBounds(n, new RectF(0, 0, 100, 100), new RectF(0, 0, 200, 100), sc);  // width 100→200 ⇒ scaleX 0.5→1
            engine.Tick(16f);
            float m11a = scene.Paint(n).LocalTransform.M11;
            bool noRelayout = (scene.Flags(n) & NodeFlags.LayoutDirty) == 0;
            int settledAt = -1;
            for (int i = 0; i < 90 && settledAt < 0; i++) { engine.Tick(16f); if (!engine.HasActive) settledAt = i; }
            float m11b = scene.Paint(n).LocalTransform.M11;
            Check("23g. ScaleCorrect springs the node scale → 1 (compositor-only, no relayout)",
                m11a > 0.3f && m11a < 0.7f && Near(m11b, 1f, 0.02f) && noRelayout && settledAt >= 0, $"M11 {m11a:0.00}→{m11b:0.00}");
        }

        // 23h — Relayout: the node's MODEL width interpolates via scoped RunSubtree (so its content re-solves live).
        {
            var scene = new SceneStore();
            var fonts = new HeadlessFontSystem(strings);
            var engine = new AnimEngine(scene);
            var layout = new FlexLayout(scene, fonts);
            var recon = new TreeReconciler(scene, strings) { Anim = engine };
            var rel = LayoutTransition.BoundsT(SizeMode.Relayout) with { Dynamics = TransitionDynamics.Spring(0.2f, 1f) };
            recon.ReconcileRoot(new BoxEl { Width = 100, Height = 200, Animate = rel,
                Children = [new TextEl("the quick brown fox jumps over the lazy dog") { Wrap = TextWrap.Wrap }] }, null);
            layout.Run(scene.Root, new Size2(400, 200));
            var panel = scene.Root;
            engine.AnimateBounds(panel, new RectF(0, 0, 300, 200), new RectF(0, 0, 100, 200), rel);   // 300 → 100
            bool relayouting = (scene.Flags(panel) & NodeFlags.Relayouting) != 0;
            float midW = -1f; int runs = 0;
            for (int i = 0; i < 8; i++)
            {
                engine.Tick(16f);
                runs += engine.IncrementalRoots.Count;                // exactly one root re-solves per tick (scoped, not full-tree)
                foreach (var r in engine.IncrementalRoots)
                {
                    ref LayoutInput li = ref scene.Layout(r);
                    ref NodePaint pp = ref scene.Paint(r);
                    if (!float.IsNaN(pp.PresentedW)) li.Width = pp.PresentedW;
                    layout.RunSubtree(r);
                }
                engine.IncrementalRoots.Clear();
                if (i == 1) midW = scene.Bounds(panel).W;
            }
            bool interpolated = midW > 105f && midW < 300f;          // model width genuinely moved through the range
            Check("23h. Relayout re-solves only the subtree at the interpolated size (live reflow)",
                relayouting && interpolated && runs >= 2, $"midW={midW:0} runs={runs}");
        }
    }

    // Animation regressions surfaced by the gallery AnimationPage: a component-effect spring must retarget mid-flight
    // without snapping (23s), and a settled SizeMode.Relayout animation must RESTORE the element-declared LayoutInput
    // instead of freezing the node at the last interpolated solve (23t — the auto-height axis is where it shows).
    static void AnimRegressionChecks(StringTable strings)
    {
        // 23s — spring retarget continuity through the live AppHost path (UseLayoutEffect → Context.Anim.Spring).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("springlab", new Size2(320, 120), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new SpringLabProbe();
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var toggle = Child(host.Scene, host.Scene.Root, 0);

            ClickNode(host, window, toggle);                       // 0 → 210
            for (int i = 0; i < 8; i++) host.RunFrame();           // mid-flight
            float before = host.Scene.Paint(root.Dot).LocalTransform.Dx;
            ClickNode(host, window, toggle);                       // retarget mid-flight → 0
            float atClick = host.Scene.Paint(root.Dot).LocalTransform.Dx;
            host.RunFrame();
            float after = host.Scene.Paint(root.Dot).LocalTransform.Dx;
            bool continuous = MathF.Abs(atClick - before) < 25f && MathF.Abs(after - atClick) < 25f;   // no snap to an endpoint
            bool carried = after > 5f;                             // velocity carry: still well away from 0 right after
            for (int i = 0; i < 90; i++) host.RunFrame();
            bool settled = MathF.Abs(host.Scene.Paint(root.Dot).LocalTransform.Dx) < 0.5f && !host.Animation.HasTracks(root.Dot);
            Check("23s. spring retarget mid-flight keeps position+velocity through the component-effect path (no snap)",
                before > 30f && continuous && carried && settled,
                $"before={before:0.0} atClick={atClick:0.0} after={after:0.0} settled={settled}");
        }

        // 23w — alpha-weighted (premultiplied) linear-light lerp: a translucent white-tinted card fill cross-fading
        // to an OPAQUE DARK solid must stay dark mid-flight. The straight per-channel lerp passed through bright
        // half-transparent grey (~0.74 sRGB) — the sticky-header "white flash". Same-alpha pairs are bit-identical
        // to the straight linear-light lerp (every pre-existing mid-color assertion stays valid).
        {
            static float S2L(float c) => c <= 0.04045f ? c / 12.92f : MathF.Pow((c + 0.055f) / 1.055f, 2.4f);
            static float L2S(float c) => c <= 0.0031308f ? c * 12.92f : 1.055f * MathF.Pow(MathF.Max(c, 0f), 1f / 2.4f) - 0.055f;
            var cardWhite5 = new ColorF(1f, 1f, 1f, 0.051f);     // CardBackgroundFillColorDefault (dark theme): white @ 5%
            var solidDark = ColorF.FromRgba(0x20, 0x20, 0x20);   // SolidBackgroundFillColorBase: opaque dark
            var mid = ColorF.LerpLinear(cardWhite5, solidDark, 0.5f);
            bool staysDark = mid.R < 0.35f && mid.G < 0.35f && mid.B < 0.35f && Near(mid.A, 0.5255f, 0.01f);
            var sa = new ColorF(0.2f, 0.4f, 0.6f, 0.8f);
            var sb = new ColorF(0.6f, 0.2f, 0.4f, 0.8f);
            var sm = ColorF.LerpLinear(sa, sb, 0.5f);
            bool sameAlphaIdentical =
                Near(sm.R, L2S((S2L(sa.R) + S2L(sb.R)) * 0.5f), 0.002f) &&
                Near(sm.G, L2S((S2L(sa.G) + S2L(sb.G)) * 0.5f), 0.002f) &&
                Near(sm.B, L2S((S2L(sa.B) + S2L(sb.B)) * 0.5f), 0.002f) && Near(sm.A, 0.8f, 0.002f);
            Check("23w. LerpLinear is alpha-weighted: translucent-white → opaque-dark stays dark mid-flight; same-alpha pairs unchanged",
                staysDark && sameAlphaIdentical,
                $"mid=({mid.R:0.00},{mid.G:0.00},{mid.B:0.00},{mid.A:0.00}) sameAlpha={sameAlphaIdentical}");
        }

        // 23u — CSS position:sticky (a ScrollBinds PinTop op): the header scrolls normally, PINS at the viewport top while
        // its parent card is in view (hit-test follows — AbsoluteRect includes the pin transform), CLAMPS at the
        // card's end (never escapes its containing block), releases on scroll-back, and fires OnFlag per transition.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("sticky", new Size2(320, 200), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            int pinEvents = 0; bool lastPin = false; NodeHandle headerN = NodeHandle.Null;
            var root = new W0fStaticProbe
            {
                Build = () => ScrollView(new BoxEl
                {
                    Direction = 1,
                    Children =
                    [
                        new BoxEl { Height = 100f },                              // lead-in
                        new BoxEl                                                  // the card (containing block)
                        {
                            Direction = 1,
                            Children =
                            [
                                new BoxEl { Height = 40f, ScrollBinds = [ new() { PinTop = 0f, OnFlag = p => { pinEvents++; lastPin = p; } } ], OnRealized = h => headerN = h },
                                new BoxEl { Height = 400f },                       // card content
                            ],
                        },
                        new BoxEl { Height = 600f },                               // after the card
                    ],
                }),
            };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var s = host.Scene;
            NodeHandle FindScrollable(NodeHandle n)
            {
                if (n.IsNull) return NodeHandle.Null;
                if (s.HasScroll(n)) return n;
                for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
                {
                    var r = FindScrollable(c);
                    if (!r.IsNull) return r;
                }
                return NodeHandle.Null;
            }
            var vp = FindScrollable(s.Root);                       // the ScrollView viewport
            var content = s.ScrollRef(vp).ContentNode;
            // headerN (the sticky node) is captured via OnRealized at mount (declared above).
            float vpTop = s.AbsoluteRect(vp).Y;
            float restY = s.AbsoluteRect(headerN).Y;

            void ScrollTo(float y)
            {
                ref ScrollState st = ref s.ScrollRef(vp);
                st.OffsetY = y; st.TargetY = y;
                s.Paint(content).LocalTransform = Affine2D.Translation(0f, -y);
                s.Mark(content, NodeFlags.TransformDirty | NodeFlags.PaintDirty);
                // Wake the frame loop like real input would (a wheel scroll sets frameNeeded via dispatch; a raw
                // ScrollRef write does not) — the sticky pass runs in the full frame pipeline.
                window.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(8f, 8f), 0, 0));
                host.RunFrame();
            }

            ScrollTo(250f);   // header's natural Y (100) is far above the viewport top → pinned at the top
            bool pinnedNow = (s.Flags(headerN) & NodeFlags.StickyPinned) != 0;
            float pinnedY = s.AbsoluteRect(headerN).Y;
            // Card spans content 100..540; the header (40h) can pin until content-y 500 (shift limit 400). At offset
            // 520 the clamp holds it at content-y 500 → viewport −20: the card's end pushes it out, CSS-exactly.
            ScrollTo(520f);
            float clampedY = s.AbsoluteRect(headerN).Y;
            bool stillPinned = (s.Flags(headerN) & NodeFlags.StickyPinned) != 0;
            ScrollTo(0f);     // released, back at its natural slot
            bool releasedFlag = (s.Flags(headerN) & NodeFlags.StickyPinned) == 0;
            float releasedY = s.AbsoluteRect(headerN).Y;
            Check("23u. position:sticky — pins at viewport top, clamps at the card's end, releases, OnPinned fires per transition",
                pinnedNow && Near(pinnedY, vpTop, 0.5f)
                && stillPinned && Near(clampedY, vpTop - 20f, 0.5f)
                && releasedFlag && Near(releasedY, restY, 0.5f)
                && pinEvents == 2 && !lastPin,
                $"restY={restY:0} pinnedY={pinnedY:0} (vpTop={vpTop:0}) clampedY={clampedY:0} releasedY={releasedY:0} pinEvents={pinEvents} lastPin={lastPin}");
        }

        // 23u3 — sticky clip-top (ScrollBindDsl.ClipTopAtViewport, the paint dual of the 23u pin): the body's
        // ClipRect.top rides the viewport-anchored line (viewport top + inset) 1:1 with the offset while engaged,
        // releases back to the Infinite sentinel when the line sits above the body, and OnFlag fires per edge —
        // the mechanism that keeps the page backdrop (not the cards) behind a pinned section header.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("sticky-clip", new Size2(320, 200), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            int clipEvents = 0; bool lastClip = false; NodeHandle bodyN = NodeHandle.Null;
            var root = new W0fStaticProbe
            {
                Build = () => ScrollView(new BoxEl
                {
                    Direction = 1,
                    Children =
                    [
                        new BoxEl { Height = 100f },                              // lead-in
                        new BoxEl                                                  // the section (containing block)
                        {
                            Direction = 1,
                            Children =
                            [
                                new BoxEl { Height = 40f, ScrollBinds = [ new() { PinTop = 0f } ] },   // the pinned header
                                new BoxEl                                                              // the section body
                                {
                                    Height = 400f,
                                    ScrollBinds = [ new() { ClipTopAtViewport = 40f, OnFlag = c => { clipEvents++; lastClip = c; } } ],
                                    OnRealized = h => bodyN = h,
                                },
                            ],
                        },
                        new BoxEl { Height = 600f },                               // after the section
                    ],
                }),
            };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var s = host.Scene;
            NodeHandle FindScrollable(NodeHandle n)
            {
                if (n.IsNull) return NodeHandle.Null;
                if (s.HasScroll(n)) return n;
                for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
                {
                    var r = FindScrollable(c);
                    if (!r.IsNull) return r;
                }
                return NodeHandle.Null;
            }
            var vp = FindScrollable(s.Root);
            var content = s.ScrollRef(vp).ContentNode;
            void ScrollTo(float y)
            {
                ref ScrollState st = ref s.ScrollRef(vp);
                st.OffsetY = y; st.TargetY = y;
                s.Paint(content).LocalTransform = Affine2D.Translation(0f, -y);
                s.Mark(content, NodeFlags.TransformDirty | NodeFlags.PaintDirty);
                window.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(8f, 8f), 0, 0));
                host.RunFrame();
            }

            bool restReleased = s.Paint(bodyN).ClipRect.IsInfinite;   // at rest: line far above the body → no clip
            // Body spans content 140..540. At offset 250 the line (viewport top + 40) sits at content-y 290 →
            // body-local clip top = 250 + 40 − 140 = 150; one more scroll px moves it exactly one px (1:1).
            ScrollTo(250f);
            float clipA = s.Paint(bodyN).ClipRect.Y;
            ScrollTo(251f);
            float clipB = s.Paint(bodyN).ClipRect.Y;
            ScrollTo(90f);    // line at content-y 130, above the body top (140) → released, not a stale 0-clip
            bool releasedMid = s.Paint(bodyN).ClipRect.IsInfinite;
            Check("23u3. sticky clip-top — body ClipRect.top rides the viewport line 1:1, releases above the body, OnFlag per edge",
                restReleased && Near(clipA, 150f, 0.5f) && Near(clipB - clipA, 1f, 0.1f)
                && releasedMid && clipEvents == 2 && !lastClip,
                $"rest={restReleased} clipA={clipA:0.#} clipB={clipB:0.#} releasedMid={releasedMid} clipEvents={clipEvents} lastClip={lastClip}");
        }

        // 23u2 — trailing-anchored presented height: a pinned hero collapses without relayout, its bottom-authored
        // child + edge stay attached to the live reveal edge, the following content meets that edge through normal
        // scrolling, and hit-testing follows the child-group shift.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("scroll-collapse-trailing", new Size2(320, 240), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            NodeHandle heroN = NodeHandle.Null, edgeN = NodeHandle.Null, bodyN = NodeHandle.Null;
            int edgeClicks = 0, bodyClicks = 0;
            var root = new W0fStaticProbe
            {
                Build = () => ScrollView(new BoxEl
                {
                    Direction = 1,
                    Children =
                    [
                        new BoxEl
                        {
                            Height = 200f, Direction = 1, Justify = FlexJustify.End, ClipToBounds = true,
                            ScrollBinds =
                            [
                                new() { PinTop = 0f },
                                new()
                                {
                                    From = ScrollChannel.Offset, To = BindSink.PresentedHTrailing,
                                    Range = ScrollRange.Px(0f, 200f), OutStart = 200f, OutEnd = 0f
                                },
                            ],
                            OnRealized = h => heroN = h,
                            Children =
                            [
                                new BoxEl { Height = 30f, OnClick = () => edgeClicks++, OnRealized = h => edgeN = h },
                            ],
                        },
                        new BoxEl { Height = 600f, OnClick = () => bodyClicks++, OnRealized = h => bodyN = h },
                    ],
                }),
            };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var s = host.Scene;
            NodeHandle FindScrollable(NodeHandle n)
            {
                if (n.IsNull) return NodeHandle.Null;
                if (s.HasScroll(n)) return n;
                for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
                {
                    var r = FindScrollable(c);
                    if (!r.IsNull) return r;
                }
                return NodeHandle.Null;
            }
            var vp = FindScrollable(s.Root);
            var content = s.ScrollRef(vp).ContentNode;
            ref ScrollState st = ref s.ScrollRef(vp);
            st.OffsetY = 80f; st.TargetY = 80f;
            s.Paint(content).LocalTransform = Affine2D.Translation(0f, -80f);
            s.Mark(content, NodeFlags.TransformDirty | NodeFlags.PaintDirty);
            ScrollBindEval.ApplyContinuous(s, vp, ref st);
            window.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(8f, 8f), 0, 0));
            host.RunFrame();

            float vpTop = s.AbsoluteRect(vp).Y;
            float ph = s.Paint(heroN).PresentedH;
            float shift = s.Paint(heroN).ChildShiftY;
            RectF edge = s.AbsoluteRect(edgeN);
            RectF body = s.AbsoluteRect(bodyN);
            var edgePoint = new Point2(edge.X + 5f, edge.Y + edge.H * 0.5f);
            window.QueueInput(new InputEvent(InputKind.PointerDown, edgePoint, 0, 0));
            window.QueueInput(new InputEvent(InputKind.PointerUp, edgePoint, 0, 0));
            host.RunFrame();
            var bodyPoint = new Point2(body.X + 5f, body.Y + 10f);
            window.QueueInput(new InputEvent(InputKind.PointerDown, bodyPoint, 0, 0));
            window.QueueInput(new InputEvent(InputKind.PointerUp, bodyPoint, 0, 0));
            host.RunFrame();

            bool geometry = Near(ph, 120f, 0.5f) && Near(shift, -80f, 0.5f)
                && Near(edge.Bottom, vpTop + ph, 0.75f) && Near(body.Y, vpTop + ph, 0.75f);
            Check("23u2. trailing PresentedH collapse keeps child/content on one live edge and hit-testing follows",
                geometry && edgeClicks == 1 && bodyClicks == 1,
                $"ph={ph:0.0} shift={shift:0.0} edgeBottom={edge.Bottom:0.0} bodyY={body.Y:0.0} vpTop={vpTop:0.0} edgeClicks={edgeClicks} bodyClicks={bodyClicks}");
        }

        // 23v/23w — scroll-position restoration (ScrollKey): a revisit seeds the saved offset BEFORE the first realize
        // (no scroll-to-top flash, even cold), a never-seen key starts at the top, and a reused viewport saves/restores
        // per content identity. The "1-2 frames at the top then a jump" antipattern is structurally impossible here.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("scrollrestore", new Size2(360, 260), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new ScrollRestoreProbe();
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var s = host.Scene;
            NodeHandle Find(NodeHandle n)
            {
                if (n.IsNull) return NodeHandle.Null;
                if (s.HasScroll(n)) return n;
                for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c)) { var r = Find(c); if (!r.IsNull) return r; }
                return NodeHandle.Null;
            }
            // Scroll "A" to row 20 (offset 400), then unmount → the offset is saved under its ScrollKey.
            { ref ScrollState st = ref s.ScrollRef(Find(s.Root)); st.OffsetY = 400f; st.TargetY = 400f; }
            host.RunFrame();
            root.Mounted.Value = false; host.RunFrame();          // unmount → SaveScroll caches "A"=400
            root.Mounted.Value = true;  host.RunFrame();          // cold remount → seed BEFORE the first realize
            ref ScrollState ra = ref s.ScrollRef(Find(s.Root));
            float restoredOffset = ra.OffsetY; int restoredFirst = ra.FirstRealized; bool noPending = !ra.RestorePending;
            Check("scroll-restore.cold-seed: a cold remount seeds the saved offset on the FIRST realized window (no scroll-to-top flash)",
                Near(restoredOffset, 400f, 1f) && restoredFirst > 0 && noPending,
                $"offset={restoredOffset:0} firstRealized={restoredFirst} pending={!noPending}");

            // Switch the ScrollKey on the reused viewport: new content starts at the top; the old content's offset is saved.
            root.Key.Value = "B"; host.RunFrame();
            float bTop = s.ScrollRef(Find(s.Root)).OffsetY;
            { ref ScrollState stb = ref s.ScrollRef(Find(s.Root)); stb.OffsetY = 600f; stb.TargetY = 600f; }
            host.RunFrame();
            root.Key.Value = "A"; host.RunFrame();                // back to A → restore 400
            float aBack = s.ScrollRef(Find(s.Root)).OffsetY;
            Check("scroll-restore.key-isolation: a different ScrollKey starts at the top; returning restores the prior content's offset",
                Near(bTop, 0f, 1f) && Near(aBack, 400f, 1f),
                $"newKeyTop={bTop:0} restoredPrev={aBack:0}");
        }

        // virtual-collection — the source-agnostic data-windowing primitive (paged remote list of known total): the total is
        // learned from page 0, pages fill on demand, repeat requests dedup, a seeded prefix refetches nothing, and the hot
        // path (indexing + an already-satisfied EnsureRange) allocates ZERO. The artist-discography virtualization rides this.
        {
            var data = new int[1000];
            for (int i = 0; i < data.Length; i++) data[i] = i * 10;
            int fetches = 0;
            var vc = new VirtualCollection<int>((off, cnt, ct) =>
            {
                fetches++;
                return new ValueTask<PageResult<int>>(new PageResult<int>(data.Length, data.AsMemory(off, Math.Min(cnt, data.Length - off))));
            }, pageSize: 50);

            bool before = vc.Count == -1 && !vc.IsLoaded(0);
            vc.EnsureRange(0, 30);                                   // page 0 → learns total + fills
            bool firstPage = vc.Count == 1000 && vc.IsLoaded(0) && vc[10] == 100 && !vc.IsLoaded(60) && fetches == 1;
            vc.EnsureRange(0, 30);                                   // same page → deduped, no new fetch
            bool deduped = fetches == 1;
            vc.EnsureRange(40, 120);                                 // pages 0(loaded)+1+2 → exactly 2 new fetches
            bool windowed = vc.IsLoaded(60) && vc[60] == 600 && vc.IsLoaded(120) && vc[120] == 1200 && fetches == 3;

            long a0 = GC.GetAllocatedBytesForCurrentThread();
            long sum = 0; for (int i = 0; i < 150; i++) sum += vc[i];   // index across loaded pages
            vc.EnsureRange(0, 140);                                  // window already present → no fetch, no alloc
            long hot = GC.GetAllocatedBytesForCurrentThread() - a0;

            int seedFetches = 0;
            var seeded = new VirtualCollection<int>((off, cnt, ct) =>
            {
                seedFetches++;
                return new ValueTask<PageResult<int>>(new PageResult<int>(500, data.AsMemory(off, Math.Min(cnt, 500 - off))));
            }, pageSize: 50);
            seeded.Seed(500, data.AsSpan(0, 50));                    // the overview's first window — free
            seeded.EnsureRange(0, 40);                               // covered by the seed → no fetch
            bool seedFree = seeded.Count == 500 && seeded.IsLoaded(0) && seeded[7] == 70 && seedFetches == 0;

            Check("virtual-collection: paged data-windowing — total from page 0, fill, dedup, seed, 0-alloc hot path",
                before && firstPage && deduped && windowed && hot == 0 && seedFree,
                $"count={vc.Count} fetches={fetches} hotAlloc={hot} seedFetches={seedFetches} sum={sum}");
        }

        // lazy-grid windowing math — the in-page virtualized grid: a scroll band → the visible row range + spacer heights
        // that reserve the WHOLE collection's extent (so the page scrollbar/sections-below never jump), with an inline
        // drawer's height reserved whether it's in or above the window. The extent invariant (topPad+block+drawer+bottom ==
        // contentH) must hold exactly so the realized window can move without any scroll drift.
        {
            const float rowH = 200f, vh = 400f; const int total = 100, over = 2;
            float Extent(in LazyGridMath.View v, float drawer) => v.TopPad + (v.LastRow - v.FirstRow + 1) * rowH + (v.DrawerVisible ? drawer : 0f) + v.BottomPad;

            var v0 = LazyGridMath.Compute(0f, vh, rowH, total, over, -1, 0f);              // at top
            bool atTop = v0.FirstRow == 0 && v0.LastRow == 4 && Near(v0.TopPad, 0f, 0.5f) && Near(Extent(v0, 0f), 20000f, 0.5f);
            var v1 = LazyGridMath.Compute(1000f, vh, rowH, total, over, -1, 0f);           // scrolled to row 5
            bool mid = v1.FirstRow == 3 && v1.LastRow == 9 && Near(v1.TopPad, 600f, 0.5f) && Near(Extent(v1, 0f), 20000f, 0.5f);
            var vAhead = LazyGridMath.Compute(1000f, vh, rowH, total, 4, -1, 0f);           // media grids prefetch farther ahead/behind
            bool largerOverscan = vAhead.FirstRow == 1 && vAhead.LastRow == 11 && Near(Extent(vAhead, 0f), 20000f, 0.5f);
            var v2 = LazyGridMath.Compute(1000f, vh, rowH, total, over, 5, 300f);          // drawer inside the window
            bool drawerIn = v2.DrawerVisible && Near(Extent(v2, 300f), 20300f, 0.5f);
            var v3 = LazyGridMath.Compute(4000f, vh, rowH, total, over, 5, 300f);          // drawer scrolled ABOVE the window
            bool drawerAbove = !v3.DrawerVisible && Near(v3.TopPad, 3900f, 0.5f) && Near(Extent(v3, 300f), 20300f, 0.5f);
            var vEnd = LazyGridMath.Compute(1e9f, vh, rowH, total, over, -1, 0f);          // clamped at the bottom
            bool atEnd = vEnd.LastRow == total - 1 && Near(Extent(vEnd, 0f), 20000f, 0.5f);
            float shortTarget = LazyGridMath.ExpandedTarget(700f, 5000f, 1100f, 220f);
            float tallTarget = LazyGridMath.ExpandedTarget(700f, 5380f, 1100f, 600f);   // same drawer-less extent
            bool bring = Near(shortTarget, 1072f, 0.5f) && Near(tallTarget, shortTarget, 0.01f);

            Check("lazy-grid: window covers the viewport and spacers reserve the exact extent (incl. inline drawer in/above window)",
                atTop && mid && largerOverscan && drawerIn && drawerAbove && atEnd && bring,
                $"top=({v0.FirstRow},{v0.LastRow},pad{v0.TopPad:0}) mid=({v1.FirstRow},{v1.LastRow}) ahead=({vAhead.FirstRow},{vAhead.LastRow}) drawerAboveTopPad={v3.TopPad:0} endLast={vEnd.LastRow} bring={shortTarget:0}/{tallTarget:0}");
        }

        // 23t — SizeMode.Relayout restores the DECLARED LayoutInput at settle (auto height stays auto).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("relayoutfix", new Size2(360, 240), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new RelayoutRestoreProbe();
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var toggle = Child(host.Scene, host.Scene.Root, 0);
            var card = Child(host.Scene, host.Scene.Root, 1);
            float narrowH = host.Scene.AbsoluteRect(card).H;       // tall: text wraps hard at 160

            ClickNode(host, window, toggle);                       // widen 160 → 300
            for (int i = 0; i < 90; i++) host.RunFrame();          // settle the spring fully
            bool wideAuto = float.IsNaN(host.Scene.Layout(card).Height);          // declared auto RESTORED
            bool wideDeclaredW = host.Scene.Layout(card).Width == 300f;           // declared width restored too
            float wideH = host.Scene.AbsoluteRect(card).H;                        // fewer lines → shorter

            ClickNode(host, window, toggle);                       // back to narrow
            for (int i = 0; i < 90; i++) host.RunFrame();
            bool narrowAuto = float.IsNaN(host.Scene.Layout(card).Height);
            float narrowH2 = host.Scene.AbsoluteRect(card).H;                     // re-wraps back to the tall layout
            Check("23t. Relayout settle restores declared LayoutInput (auto axis stays auto; round-trip re-wraps)",
                wideAuto && wideDeclaredW && narrowAuto && wideH < narrowH - 4f && Near(narrowH2, narrowH, 1.5f),
                $"narrowH={narrowH:0} wideH={wideH:0} narrowH2={narrowH2:0} wideAuto={wideAuto} narrowAuto={narrowAuto}");
        }
    }

    // SizeMode.Reflow — the layout-participating size transition (smooth reflow): the interpolated size runs through
    // REAL layout each tick (boundary-scoped re-solve), so siblings ease instead of snapping; the declared LayoutInput
    // is restored at settle; the Trailing anchor rides the content's end edge on the animated edge; and the parent-
    // relative FLIP projection keeps BoundsAnimated nodes below RIGID while everything reflows.
    static void ReflowChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("reflow", new Size2(360, 420), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var root = new ReflowProbe();
        using var host = new AppHost(app, window, device, fonts, strings, root);
        var s = host.Scene;

        host.RunFrame();   // mount collapsed (first frame never captures → no spurious enter reveal)
        var toggle = Child(s, s.Root, 0);
        var noise = Child(s, s.Root, 1);
        var shift = Child(s, s.Root, 2);
        var wrap = Child(s, s.Root, 3);
        var row = Child(s, s.Root, 4);
        var mover = Child(s, row, 1);
        float sibY0 = s.AbsoluteRect(row).Y;          // the row below IS the observable sibling
        float wrapH0 = s.AbsoluteRect(wrap).H;

        // 23r.a — expand: old size on the click frame (no jump), sibling eases MONOTONICALLY through the 333ms reveal,
        // Trailing child-shift == interp − contentExtent mid-flight, settle restores the declared NaN(auto) input.
        ClickNode(host, window, toggle);
        float wrapHClick = s.AbsoluteRect(wrap).H;
        float sibYClick = s.AbsoluteRect(row).Y;
        bool monotone = true;
        float prevY = sibYClick, midH = 0f, midShift = 0f;
        for (int i = 0; i < 30; i++)
        {
            host.RunFrame();
            float y = s.AbsoluteRect(row).Y;
            if (y < prevY - 0.25f) monotone = false;
            prevY = y;
            if (i == 2) { midH = s.AbsoluteRect(wrap).H; midShift = s.Paint(wrap).ChildShiftY; }
        }
        float wrapHOpen = s.AbsoluteRect(wrap).H;
        float sibYOpen = s.AbsoluteRect(row).Y;
        bool liRestoredOpen = float.IsNaN(s.Layout(wrap).Height);
        bool shiftRest = s.Paint(wrap).ChildShiftY == 0f;
        Check("23r.a Reflow expand: old-size click frame, sibling eases monotonically, trailing shift rides, settle restores declared input",
            wrapH0 < 0.5f && wrapHClick < 0.5f && Near(sibYClick, sibY0, 0.5f) && monotone
            && midH > 4f && midH < 56f && Near(midShift, midH - 60f, 1.5f)
            && Near(wrapHOpen, 60f, 0.5f) && Near(sibYOpen, sibY0 + 60f, 0.5f) && liRestoredOpen && shiftRest,
            $"wrapH {wrapHClick:0.0}→{midH:0.0}→{wrapHOpen:0.0} sibY {sibY0:0.0}→{sibYClick:0.0}→{sibYOpen:0.0} shift={midShift:0.0} liNaN={liRestoredOpen}");

        // 23r.b — collapse with a mid-flight UNRELATED re-commit: the commit snap-solves the wrapper at its declared
        // value inside the frame, but the target/echo guards keep the in-flight track (no restart) and phase 7
        // re-establishes the interp before record — so the collapse still settles ON SCHEDULE (167ms + pad).
        ClickNode(host, window, toggle);                 // collapse — ExitDynamics leg
        host.RunFrame(); host.RunFrame();                // ~32ms in
        float hA = s.AbsoluteRect(wrap).H;
        ClickNode(host, window, noise);                  // unrelated state commit mid-flight
        float hB = s.AbsoluteRect(wrap).H;
        bool stillFlying = host.Animation.HasTracks(wrap);
        for (int i = 0; i < 11; i++) host.RunFrame();    // total ≈ 224ms ≥ 167ms — would NOT settle if the tween restarted
        bool closedOnSchedule = Near(s.AbsoluteRect(wrap).H, 0f, 0.5f) && !host.Animation.HasTracks(wrap);
        bool liRestoredClosed = s.Layout(wrap).Height == 0f;
        bool sibHome = Near(s.AbsoluteRect(row).Y, sibY0, 0.5f);
        Check("23r.b Reflow collapse: mid-flight reconcile does not restart the track (guards), settles on schedule, declared 0 restored",
            hA < 59.5f && hA > 0.5f && hB <= hA + 0.25f && stillFlying && closedOnSchedule && liRestoredClosed && sibHome,
            $"hA={hA:0.0} hB={hB:0.0} flying={stillFlying} closed={closedOnSchedule} li0={liRestoredClosed}");

        // 23x — rigidity: a BoundsAnimated node below the reflowing wrapper rides the reveal RIGIDLY (parent-relative
        // projection skips it on commit frames — exercised by clicking noise EVERY ride frame), then a genuine LOCAL
        // move (the leading spacer) still FLIPs it.
        ClickNode(host, window, toggle);                 // expand again
        bool rigid = true;
        float prevMovY = s.AbsoluteRect(mover).Y, prevRowY = s.AbsoluteRect(row).Y;
        float rideStartY = prevMovY;
        for (int i = 0; i < 5; i++)
        {
            ClickNode(host, window, noise);              // every ride frame is a COMMIT frame (capture+apply run)
            float my = s.AbsoluteRect(mover).Y, ry = s.AbsoluteRect(row).Y;
            if (!Near(my - prevMovY, ry - prevRowY, 0.25f)) rigid = false;
            if (host.Animation.HasTracks(mover)) rigid = false;
            if (MathF.Abs(s.Paint(mover).LocalTransform.Dy) > 0.01f) rigid = false;
            prevMovY = my; prevRowY = ry;
        }
        bool rode = prevMovY > rideStartY + 4f;          // it genuinely moved with the reveal
        for (int i = 0; i < 30; i++) host.RunFrame();    // settle the reveal
        float movX0 = s.AbsoluteRect(mover).X;
        ClickNode(host, window, shift);                  // spacer 0→40: a LOCAL move within the row
        bool seeded = host.Animation.HasTracks(mover);
        float dx0 = s.Paint(mover).LocalTransform.Dx;    // JustSeeded samples u=0 → −40 on the commit frame
        bool held = Near(s.AbsoluteRect(mover).X, movX0, 1.5f);   // presented X holds (FLIP "Invert")
        for (int i = 0; i < 30; i++) host.RunFrame();
        bool landed = Near(s.AbsoluteRect(mover).X, movX0 + 40f, 0.5f) && !host.Animation.HasTracks(mover);
        Check("23x. parent-relative projection: ancestor reflow rides rigidly (no tracks, no transform); a local move still FLIPs",
            rigid && rode && seeded && dx0 < -30f && held && landed,
            $"rigid={rigid} rode={rode} seeded={seeded} dx0={dx0:0.0} held={held} landed={landed}");
    }

    // Nested stateful component: renders, owns its own UseState, and re-renders on its own setState.
    static void NestedChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("nest", new Size2(480, 320), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var root = new NestParent();
        using var host = new AppHost(app, window, device, fonts, strings, root);

        host.RunFrame();
        bool mounted = HasGlyph(device, strings, "child 0");

        // parent VStack → [Heading, componentHost]; host → [Button]
        var compHost = Child(host.Scene, host.Scene.Root, 1);
        var btn = Child(host.Scene, compHost, 0);
        var r = host.Scene.AbsoluteRect(btn);
        var center = new Point2(r.X + r.W / 2f, r.Y + r.H / 2f);
        window.QueueInput(new InputEvent(InputKind.PointerDown, center, 0, 0));
        window.QueueInput(new InputEvent(InputKind.PointerUp, center, 0, 0));
        var f2 = host.RunFrame();

        bool childUpdated = HasGlyph(device, strings, "child 1");
        Check("24. nested component renders & owns state", mounted && f2.ClicksHandled == 1 && childUpdated, "child 0 → click → child 1");
    }

    // UseContext: provider value reaches a nested consumer, and a change propagates on re-render.
    static void ContextChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("ctx", new Size2(480, 320), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var root = new CtxParent();
        using var host = new AppHost(app, window, device, fonts, strings, root);

        host.RunFrame();
        bool c0 = HasGlyph(device, strings, "ctx 7");

        var incBtn = Child(host.Scene, host.Scene.Root, 0);   // VStack child 0 = "inc" button
        var rr = host.Scene.AbsoluteRect(incBtn);
        var center = new Point2(rr.X + rr.W / 2f, rr.Y + rr.H / 2f);
        window.QueueInput(new InputEvent(InputKind.PointerDown, center, 0, 0));
        window.QueueInput(new InputEvent(InputKind.PointerUp, center, 0, 0));
        host.RunFrame();
        bool c1 = HasGlyph(device, strings, "ctx 8");

        Check("25. UseContext provides + propagates across components", c0 && c1, "ctx 7 → ctx 8");
    }

    // Hover/pressed visual states: the dispatcher tracks them as node flags following the pointer.
    static void HoverChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("hover", new Size2(480, 320), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var root = new HoverProbe();
        using var host = new AppHost(app, window, device, fonts, strings, root);

        host.RunFrame();
        var btn = host.Scene.Root;
        var r = host.Scene.AbsoluteRect(btn);
        var center = new Point2(r.X + r.W / 2f, r.Y + r.H / 2f);
        var outside = new Point2(r.Right + 50f, r.Bottom + 50f);

        window.QueueInput(new InputEvent(InputKind.PointerMove, center, 0, 0));
        host.RunFrame();
        bool hov = (host.Scene.Flags(btn) & NodeFlags.Hovered) != 0;

        window.QueueInput(new InputEvent(InputKind.PointerDown, center, 0, 0));
        host.RunFrame();
        bool prs = (host.Scene.Flags(btn) & NodeFlags.Pressed) != 0;

        window.QueueInput(new InputEvent(InputKind.PointerUp, center, 0, 0));
        host.RunFrame();
        bool released = (host.Scene.Flags(btn) & NodeFlags.Pressed) == 0;

        window.QueueInput(new InputEvent(InputKind.PointerMove, outside, 0, 0));
        host.RunFrame();
        bool unhov = (host.Scene.Flags(btn) & NodeFlags.Hovered) == 0;

        Check("26. hover/pressed states track the pointer", hov && prs && released && unhov, "enter→hover, down→pressed, up→release, leave→unhover");
    }

    // gate.input.hover-subtree-enter-exit: per-node OnHoverMove/OnPointerExit are SUBTREE-scoped (WinUI PointerEntered/
    // PointerExited parity) — a ToolTip.Wrap-shaped wrapper around an INTERACTIVE child (which wins the deepest-leaf hit)
    // still receives its enter when the pointer lands on the child, receives NO exit moving wrapper-padding→child, and
    // exactly one exit when the pointer leaves the subtree. Pre-fix, leaf-only delivery starved every such wrapper —
    // tooltips around buttons could never open.
    static void HoverSubtreeChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("hover-subtree", new Size2(320, 320), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var probe = new HoverSubtreeProbe();
        using var host = new AppHost(app, window, device, fonts, strings, probe);
        host.RunFrame();   // mount + layout

        // Geometry: root pad 50 → wrapper at (50,50) 100×100; wrapper pad 20 → child at (70,70) 60×60.
        var vp = host.Scene.AbsoluteRect(host.Scene.Root);
        var ptOut = new Point2(vp.X + 10f, vp.Y + 10f);       // outside the wrapper subtree (root has no handlers)
        var ptChild = new Point2(vp.X + 100f, vp.Y + 100f);   // inside the interactive child
        var ptChild2 = new Point2(vp.X + 110f, vp.Y + 105f);  // still inside the child
        var ptPad = new Point2(vp.X + 58f, vp.Y + 58f);       // the wrapper's own padding (the wrapper is the leaf here)

        void Move(Point2 p) { window.QueueInput(new InputEvent(InputKind.PointerMove, p, 0, 0)); host.RunFrame(); }

        Move(ptOut);
        probe.WrapperEnter = 0; probe.WrapperExit = 0;

        Move(ptChild);                                        // outside → child (the child is the deepest interactive leaf)
        bool enterOnChild = probe.WrapperEnter == 1 && probe.WrapperExit == 0;
        Move(ptChild2);                                       // move WITHIN the child — no re-enter, no exit
        bool noRefire = probe.WrapperEnter == 1 && probe.WrapperExit == 0;
        Move(ptOut);                                          // leave the subtree
        bool exitOnce = probe.WrapperExit == 1;

        probe.WrapperEnter = 0; probe.WrapperExit = 0;
        Move(ptPad);                                          // onto the wrapper's own padding (wrapper = hovered leaf)
        Move(ptChild);                                        // padding → child: still INSIDE the subtree → no exit
        bool noSelfExit = probe.WrapperExit == 0;
        Move(ptOut);
        bool exitAfter = probe.WrapperExit == 1;

        Check("gate.input.hover-subtree-enter-exit OnHoverMove/OnPointerExit are subtree-scoped for a wrapper around an interactive child (enter on child-hover, no re-fire within, no exit wrapper→child, one exit on leave)",
            enterOnChild && noRefire && exitOnce && noSelfExit && exitAfter,
            $"enterOnChild={enterOnChild} noRefire={noRefire} exitOnce={exitOnce} noSelfExit={noSelfExit} exitAfter={exitAfter} enter={probe.WrapperEnter} exit={probe.WrapperExit}");
    }

    // gate.scroll.hover-follows-content (input-a11y.md §5.4/§15 "stuck hover"): wheel-scrolling a list under a STATIONARY
    // mouse cursor re-resolves hover — the row that slides under the point becomes Hovered and the row that left it is
    // cleared — WITHOUT a PointerMove, and the synthesized re-eval frame allocates 0 managed bytes (phases 6–13).
    static void ScrollHoverChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("scroll-hover", new Size2(320, 320), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new ScrollHoverProbe());
        host.RunFrame();   // mount + layout (SmoothScroll defaults false ⇒ a wheel writes the offset synchronously)

        var vp = host.Scene.AbsoluteRect(host.Scene.Root);
        var pt = new Point2(vp.X + 60f, vp.Y + 20f);   // fixed point over ROW 0 (top 40px), inside the 180px-wide row

        // Warm the hover + scroll + re-eval path (JIT + seed both rows' hover anim-slab channels) OUTSIDE the measured
        // frame, so the zero-alloc assertion measures steady state (mirrors gate.scroll.alloc-zero's warm pass).
        window.QueueInput(new InputEvent(InputKind.PointerMove, pt, 0, 0)); host.RunFrame();
        for (int w = 0; w < 2; w++)
        {
            window.QueueInput(new InputEvent(InputKind.Wheel, pt, 0, 0, 40f)); host.RunFrame();    // row 0 → row 1
            window.QueueInput(new InputEvent(InputKind.Wheel, pt, 0, 0, -40f)); host.RunFrame();   // row 1 → row 0
        }
        for (int i = 0; i < 8; i++) host.RunFrame();   // settle bars/anim back to rest

        // Establish hover on ROW 0 at the fixed point.
        window.QueueInput(new InputEvent(InputKind.PointerMove, pt, 0, 0)); host.RunFrame();
        var a = host.Input.HitTest(pt);
        bool hovA = !a.IsNull && (host.Scene.Flags(a) & NodeFlags.Hovered) != 0;

        // MEASURED: wheel one row DOWN with the pointer NOT moving. Offset 0→40 ⇒ row 1 slides under the fixed point.
        window.QueueInput(new InputEvent(InputKind.Wheel, pt, 0, 0, 40f));
        var f = host.RunFrame();
        var b = host.Input.HitTest(pt);
        bool contentMoved = !b.IsNull && b != a;                                        // a DIFFERENT node is under the point
        bool hovB = !b.IsNull && (host.Scene.Flags(b) & NodeFlags.Hovered) != 0;         // the NEW node is Hovered
        bool oldCleared = a.IsNull || (host.Scene.Flags(a) & NodeFlags.Hovered) == 0;    // the OLD node is NOT Hovered
        bool zero = f.HotPhaseAllocBytes == 0;                                           // the synthesized re-eval is 0-alloc

        Check("gate.scroll.hover-follows-content a wheel-scroll under a stationary cursor moves NodeFlags.Hovered to the row that slid under the point (old row cleared), with no PointerMove and 0 managed alloc on the re-eval frame",
            hovA && contentMoved && hovB && oldCleared && zero,
            $"a={(a.IsNull ? "null" : a.Raw.Index.ToString())} b={(b.IsNull ? "null" : b.Raw.Index.ToString())} hovA={hovA} moved={contentMoved} hovB={hovB} oldCleared={oldCleared} alloc={f.HotPhaseAllocBytes}B");

        ScrollHoverVirtualCheck(strings);
    }

    // gate.scroll.hover-follows-content.recycled-slot: the VIRTUAL-LIST variant. A boundary-crossing scroll in a bound
    // recycler (Virtual.ListBound) keeps the SAME slot HANDLE under a fixed screen point but rebinds it to the next item;
    // the reconciler's rebind Unmark clears that handle's Hovered flag while _hovered still points at it. Since the handle
    // is unchanged, SetState early-outs — so RefreshHoverAfterScroll must re-assert the bit, else the recycled row shows no
    // hover tint until the next real PointerMove. (Unlike the non-virtual gate above, HitTest returns the SAME handle here,
    // which is exactly why that gate cannot reproduce this case. No alloc assertion: a boundary-crossing rebind legitimately
    // allocates — the zero-alloc guarantee of the refresh path itself is already covered by the non-virtual gate above.)
    static void ScrollHoverVirtualCheck(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("scroll-hover-virt", new Size2(320, 320), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new ScrollHoverVirtualProbe());
        host.RunFrame();   // mount + layout (SmoothScroll defaults false ⇒ a wheel writes the offset synchronously)

        var vp = host.Scene.Root;
        var pt = new Point2(60f, 20f);   // fixed point 20px down (top row of the 200px viewport), inside the 180px-wide row

        // Scroll PAST the overscan buffer so FirstRealized is off zero — then the ordinal under a fixed screen point is
        // pinned at `overscan` (first = floor(offset/extent) − overscan, so index_under_point − first == overscan for any
        // offset), i.e. the SAME child HANDLE stays under the point across every re-realize. Warm the rebind + re-eval path.
        for (int i = 0; i < 12; i++) { window.QueueInput(new InputEvent(InputKind.Wheel, pt, 0, 0, 40f)); host.RunFrame(); }
        for (int i = 0; i < 8; i++) host.RunFrame();   // settle bars/anim back to rest

        // Establish hover on the row currently under the fixed point.
        window.QueueInput(new InputEvent(InputKind.PointerMove, pt, 0, 0)); host.RunFrame();
        var a = host.Input.HitTest(pt);
        bool hovA = !a.IsNull && (host.Scene.Flags(a) & NodeFlags.Hovered) != 0;
        host.Scene.TryGetScroll(vp, out var scA);
        int firstA = scA.FirstRealized;

        // MEASURED: scroll DOWN several rows with the pointer NOT moving — enough to force a re-realize (NeedsRealize fires
        // in ~guard-sized jumps, not 1:1). FirstRealized advances ⇒ the slot at ordinal `overscan` (the SAME handle) is
        // rebound to a new item and the reconciler's Unmark clears its Hovered flag. RefreshHoverAfterScroll must re-assert
        // it: the handle is unchanged, so SetState early-outs and (pre-fix) leaves the row un-hovered.
        window.QueueInput(new InputEvent(InputKind.Wheel, pt, 0, 0, 200f));
        host.RunFrame();
        var b = host.Input.HitTest(pt);
        host.Scene.TryGetScroll(vp, out var scB);
        bool reRealized = scB.FirstRealized > firstA;                                   // the realize window shifted (rebind ran)
        bool sameHandle = !b.IsNull && b == a;                                          // the SAME slot handle stayed under the point
        bool hovB = !b.IsNull && (host.Scene.Flags(b) & NodeFlags.Hovered) != 0;         // the recycled slot is (re-)Hovered

        Check("gate.scroll.hover-follows-content.recycled-slot a boundary-crossing virtual scroll re-asserts NodeFlags.Hovered on the recycled slot handle that stays under a stationary cursor (the reconciler's rebind Unmark would otherwise leave it un-hovered)",
            hovA && reRealized && sameHandle && hovB,
            $"a={(a.IsNull ? "null" : a.Raw.Index.ToString())} b={(b.IsNull ? "null" : b.Raw.Index.ToString())} firstA={firstA} firstB={scB.FirstRealized} hovA={hovA} reRealized={reRealized} sameHandle={sameHandle} hovB={hovB}");
    }

    // Controls are barebone + a default Fluent style on top, overrideable per-instance (ButtonStyle) or via modifiers.
    static void StyleChecks()
    {
        var s = new Button.Style
        {
            Background = ColorF.FromRgba(10, 20, 30),
            Foreground = ColorF.FromRgba(40, 50, 60),
            HoverBackground = ColorF.FromRgba(70, 80, 90),
            CornerRadius = 8f,
        };
        var btn = Button.Accent("x", () => { }, s);
        bool styled = btn.Fill.Value == s.Background
            && btn.HoverFill == s.HoverBackground
            && Near(btn.Corners.Value.TopLeft, 8f)
            && btn.Children[0] is TextEl t && t.Color.Value == s.Foreground;

        var modded = Button.Accent("y", () => { }).Background(ColorF.FromRgba(1, 2, 3)).Rounded(12f);
        bool overridden = modded.Fill.Value == ColorF.FromRgba(1, 2, 3) && Near(modded.Corners.Value.TopLeft, 12f);

        // Wave-1 parity: WinUI Button storyboards swap brushes ONLY (Button_themeresources.xaml:176-229 — no scale),
        // so the default Button must have NO press scale; IconButton (engine media-transport control) keeps its
        // deliberate glyph pop, proving the scale CHANNEL still works for controls that opt in.
        var animatedButton = Button.Standard("z", () => { });
        var animatedIcon = IconButton.Create("i", () => { });
        bool animation = animatedButton.PressScale == 1f && animatedButton.HoverScale == 1f
            && animatedIcon.Children[0] is BoxEl iconGlyph
            && iconGlyph.HoverScale > 1f
            && iconGlyph.PressScale < 1f;

        Check("27. controls are user-styleable + animated (ButtonStyle, modifiers, AnimatedIcon)", styled && overridden && animation,
            "custom style + .Background().Rounded() + WinUI no-scale Button / opt-in icon scale");
    }

    // UseAnimatedValue eases toward a changed target across renders, then settles (React/framer-style transition).
    static void AnimValueChecks()
    {
        var p = new AnimProbe { Target = 0f };
        p.RenderWithHooks();                 // mount → value = 0
        p.Target = 1f;
        p.RenderWithHooks();                 // target changed → first eased step
        float v1 = p.Value;
        for (int i = 0; i < 20; i++) p.RenderWithHooks();   // advance past the 100ms duration
        float v2 = p.Value;
        Check("28. UseAnimatedValue eases then settles", v1 > 0f && v1 < 1f && Near(v2, 1f), $"step={v1:0.00} settled={v2:0.0}");
    }

    // flex-wrap: a 100-wide row of three 40-wide boxes flows to two lines ([0,1] then [2]).
    static void WrapChecks(StringTable strings)
    {
        var scene = LayoutTree(strings, new BoxEl
        {
            Direction = 0, Width = 100, Height = 100, Wrap = true,
            Children =
            [
                new BoxEl { Width = 40, Height = 20 },
                new BoxEl { Width = 40, Height = 20 },
                new BoxEl { Width = 40, Height = 20 },
            ],
        });
        var c0 = scene.AbsoluteRect(Child(scene, scene.Root, 0));
        var c1 = scene.AbsoluteRect(Child(scene, scene.Root, 1));
        var c2 = scene.AbsoluteRect(Child(scene, scene.Root, 2));
        Check("29. flex-wrap flows children to lines", Near(c0.X, 0) && Near(c1.X, 40) && Near(c2.X, 0) && Near(c2.Y, 20), $"c2=({c2.X:0.#},{c2.Y:0.#})");
    }

    // flex-wrap + flex-grow: each wrapped line distributes ITS leftover main to that line's grow children (CSS grow is
    // per-line, INCLUDING the last line) — so a wrapped row fills edge-to-edge instead of leaving a ragged gap.
    static void WrapGrowChecks(StringTable strings)
    {
        var scene = LayoutTree(strings, new BoxEl
        {
            Direction = 0, Width = 100, Height = 100, Wrap = true,   // gap 0
            Children =
            [
                new BoxEl { Width = 40, Height = 20, Grow = 1f },
                new BoxEl { Width = 40, Height = 20, Grow = 1f },
                new BoxEl { Width = 40, Height = 20, Grow = 1f },
            ],
        });
        var c0 = scene.AbsoluteRect(Child(scene, scene.Root, 0));
        var c1 = scene.AbsoluteRect(Child(scene, scene.Root, 1));
        var c2 = scene.AbsoluteRect(Child(scene, scene.Root, 2));
        // line 1 = [0,1]: 40+40 base, 20 free split → each 50 (c1 starts at 50). line 2 = [2]: lone grow fills → 100 wide.
        bool ok = Near(c0.X, 0) && Near(c0.W, 50) && Near(c1.X, 50) && Near(c1.W, 50)
                  && Near(c2.X, 0) && Near(c2.Y, 20) && Near(c2.W, 100);
        Check("29b. flex-wrap distributes grow per line (incl. the last) → lines fill", ok,
            $"c0.W={c0.W:0.#} c1.X={c1.X:0.#} c2.W={c2.W:0.#}");
    }

    // Regression for the gallery shell shape: a root overlay (ZStack) contains a fixed nav pane + grow content. The
    // content page has a wrapped caption followed by a grow virtual list. The overlay must pass the finite window width
    // into measure, and wrapping text must measure against the content frame width, not its full single-line width.
    static void ConstrainedWrapChecks(StringTable strings)
    {
        const string caption =
            "100,000 rows with real CDN thumbnails - only the visible window is realized and recycled over a slab free-list; " +
            "images decode off-thread, pack into the atlas, and evict off-screen, so memory stays flat. Wheel to scroll.";

        var tree = Ui.ZStack(new BoxEl
        {
            Direction = 0,
            Children =
            [
                new BoxEl { Width = 320f, Direction = 1 },
                new BoxEl
                {
                    Direction = 1,
                    Grow = 1f,
                    Gap = 16f,
                    Padding = Edges4.All(24f),
                    Children =
                    [
                        new TextEl("List virtualization") { Size = 28f, Bold = true },
                        new TextEl(caption) { Size = 14f, Wrap = TextWrap.Wrap },
                        Virtual.List(100000, 48f, _ => new BoxEl { Height = 48f }, keyOf: i => "r" + i) with { Grow = 1f },
                    ],
                },
            ],
        });

        var scene = new SceneStore();
        new TreeReconciler(scene, strings).ReconcileRoot(tree, null);
        new FlexLayout(scene, new HeadlessFontSystem(strings)).Run(scene.Root, new Size2(900f, 720f));

        NodeHandle captionNode = default, listNode = default;
        void Visit(NodeHandle n)
        {
            if (n.IsNull) return;
            ref var paint = ref scene.Paint(n);
            if (paint.VisualKind == VisualKind.Text && strings.Resolve(paint.Text) == caption) captionNode = n;
            if (scene.TryGetScroll(n, out var sc) && sc.ItemCount == 100000) listNode = n;
            for (var c = scene.FirstChild(n); !c.IsNull; c = scene.NextSibling(c)) Visit(c);
        }
        Visit(scene.Root);

        var cap = scene.AbsoluteRect(captionNode);
        var list = scene.AbsoluteRect(listNode);
        bool captionWrapped = cap.H > 30f;                 // > one 14px line in the headless font system
        bool listConstrained = Near(list.X, 344f) && Near(list.W, 532f) && list.Right <= 900f;

        Check("29a. wrapping text in fixed-pane + grow content is measured to the content frame",
            captionWrapped && listConstrained,
            $"caption={cap.W:0}x{cap.H:0} list=({list.X:0},{list.W:0},right={list.Right:0})");
    }

    // Compositor: the renderer applies a per-node world transform + cumulative opacity (CSS compositor model).
    static void CompositorChecks(StringTable strings)
    {
        var scene = new SceneStore();
        new TreeReconciler(scene, strings).ReconcileRoot(new BoxEl
        {
            Direction = 1, Width = 200, Height = 100, OffsetX = 20, OffsetY = 30, Opacity = 0.5f,
            Fill = ColorF.FromRgba(255, 0, 0),
            Children = [new BoxEl { Width = 40, Height = 20, Fill = ColorF.FromRgba(0, 255, 0), Opacity = 0.5f }],
        }, null);
        new FlexLayout(scene, new HeadlessFontSystem(strings)).Run(scene.Root);

        var dl = new DrawList();
        SceneRecorder.Record(scene, dl);
        var dev = new HeadlessGpuDevice();
        dev.SubmitDrawList(dl.Bytes, dl.SortKeys, new FrameInfo(new Size2(400, 300), 1f, ColorF.Transparent));

        var parent = dev.LastRects[0];   // root box
        var child = dev.LastRects[1];    // nested box
        bool parentOk = Near(parent.Transform.Dx, 20) && Near(parent.Transform.Dy, 30) && Near(parent.Opacity, 0.5f);
        bool childOk = Near(child.Opacity, 0.25f) && child.Transform.Dx >= 20f;   // opacity composes 0.5*0.5; inherits parent offset
        Check("30. compositor: transform + cumulative opacity", parentOk && childOk, $"pOffset=({parent.Transform.Dx:0.#},{parent.Transform.Dy:0.#}) childOpacity={child.Opacity:0.00}");

        var edgeScene = new SceneStore();
        new TreeReconciler(edgeScene, strings).ReconcileRoot(new BoxEl
        {
            Width = 200, Height = 80, ClipToBounds = true,
            Children =
            [
                new BoxEl
                {
                    Width = 200, Height = 160, Fill = ColorF.FromRgba(20, 20, 20),
                    EdgeFade = new EdgeFadeSpec(EdgeMask.Bottom, 32f),
                    Children = [new BoxEl { Width = 200, Height = 160, Fill = ColorF.FromRgba(255, 255, 255) }],
                },
            ],
        }, null);
        new FlexLayout(edgeScene, new HeadlessFontSystem(strings)).Run(edgeScene.Root);
        var edgeDl = new DrawList();
        SceneRecorder.Record(edgeScene, edgeDl);
        var edgeDev = new HeadlessGpuDevice();
        edgeDev.SubmitDrawList(edgeDl.Bytes, edgeDl.SortKeys, new FrameInfo(new Size2(400, 300), 1f, ColorF.Transparent));
        PushLayerCmd edgeLayer = default;
        foreach (var l in edgeDev.LastLayers) if (l.Kind == (int)LayerKind.EdgeFade) { edgeLayer = l; break; }
        bool edgeClipOk = edgeLayer.Kind == (int)LayerKind.EdgeFade
            && Near(edgeLayer.DeviceRect.H, 160f)
            && Near(edgeLayer.CompositeClip.H, 80f)
            && Near(edgeLayer.CompositeClip.W, 200f)
            && edgeLayer.LayerId != 0;
        Check("30a. edge-fade layer carries effective composite clip + stable source id",
            edgeClipOk, $"deviceH={edgeLayer.DeviceRect.H:0.#} clip=({edgeLayer.CompositeClip.W:0.#}x{edgeLayer.CompositeClip.H:0.#}) id={edgeLayer.LayerId}");

        var nestedScene = new SceneStore();
        new TreeReconciler(nestedScene, strings).ReconcileRoot(new BoxEl
        {
            Width = 240, Height = 120,
            EdgeFade = new EdgeFadeSpec(EdgeMask.Horizontal, 24f),
            Children =
            [
                new BoxEl
                {
                    Width = 180, Height = 80, Acrylic = AcrylicSpec.InAppDefault,
                    Children = [new BoxEl { Width = 180, Height = 80, Fill = ColorF.FromRgba(255, 255, 255) }],
                },
            ],
        }, null);
        new FlexLayout(nestedScene, new HeadlessFontSystem(strings)).Run(nestedScene.Root);
        var nestedDl = new DrawList();
        SceneRecorder.Record(nestedScene, nestedDl);
        var nestedDev = new HeadlessGpuDevice();
        nestedDev.SubmitDrawList(nestedDl.Bytes, nestedDl.SortKeys, new FrameInfo(new Size2(400, 300), 1f, ColorF.Transparent));
        bool nestedKinds = nestedDev.LastLayers.Count >= 2
            && nestedDev.LastLayers[0].Kind == (int)LayerKind.EdgeFade
            && nestedDev.LastLayers[1].Kind == (int)LayerKind.Acrylic
            && nestedDev.LastLayers[0].LayerId != 0
            && nestedDev.LastLayers[1].LayerId != 0
            && nestedDev.LayerBalance == 0;
        Check("30b. edge-fade -> acrylic records balanced nested layers with stable target identities",
            nestedKinds, $"layers={nestedDev.LastLayers.Count} balance={nestedDev.LayerBalance}");
    }

    // Phase 2 — the generic runtime: keyframes, composite (add), springs, and scroll-driven timelines.
    static void AnimEngineChecks(StringTable strings)
    {
        // eased multi-keyframe tween → composed into LocalTransform
        var s1 = Single(strings);
        var a1 = new AnimEngine(s1);
        a1.Animate(s1.Root, AnimChannel.TranslateX, 0f, 100f, 100f, Easing.Linear);
        a1.Tick(0f);
        a1.Tick(50f);
        float mid = s1.Paint(s1.Root).LocalTransform.Dx;
        a1.Tick(100f);
        float end = s1.Paint(s1.Root).LocalTransform.Dx;
        Check("31. eased keyframe tween + hold", Near(mid, 50f, 1f) && Near(end, 100f, 0.5f), $"mid={mid:0.#} end={end:0.#}");

        // composite Add: two tracks on one channel combine (animation-composition: add)
        var s2 = Single(strings);
        var a2 = new AnimEngine(s2);
        a2.Animate(s2.Root, AnimChannel.TranslateX, 0f, 30f, 100f, Easing.Linear, CompositeOp.Replace);
        a2.Animate(s2.Root, AnimChannel.TranslateX, 0f, 20f, 100f, Easing.Linear, CompositeOp.Add);
        a2.Tick(0f);
        a2.Tick(100f);
        float add = s2.Paint(s2.Root).LocalTransform.Dx;
        Check("32. composite add combines tracks", Near(add, 50f, 0.5f), $"dx={add:0.#}");

        // spring settles to its target (semi-implicit ODE)
        var s3 = Single(strings);
        var a3 = new AnimEngine(s3);
        a3.Spring(s3.Root, AnimChannel.ScaleX, 1.3f, SpringParams.FromResponse(0.2f, 1f), initial: 1.0f);
        for (int i = 0; i < 150; i++) a3.Tick(16f);
        float sx = s3.Paint(s3.Root).LocalTransform.M11;
        Check("33. spring settles to target", Near(sx, 1.3f, 0.02f), $"scaleX={sx:0.###}");

        // scroll-driven timeline: a value source maps to progress (animation-timeline: scroll())
        var s4 = Single(strings);
        var a4 = new AnimEngine(s4);
        float scroll = 0f;
        int clk = a4.Clocks.Register(() => scroll);
        a4.Drive(s4.Root, AnimChannel.Opacity, [new(0f, 0f, Easing.Linear), new(1f, 1f, Easing.Linear)], clk, 0f, 100f);
        scroll = 25f; a4.Tick(16f);
        float op25 = s4.Paint(s4.Root).Opacity;
        scroll = 100f; a4.Tick(16f);
        float op100 = s4.Paint(s4.Root).Opacity;
        Check("34. scroll-driven timeline", Near(op25, 0.25f, 0.02f) && Near(op100, 1f, 0.01f), $"op@25={op25:0.00} op@100={op100:0.00}");
    }

    // Phase 3 — declarative hooks: a component animates its own node via UseSpring (composited, no re-render per frame).
    static void AnimHookChecks(StringTable strings)
    {
        var scene = new SceneStore();
        var anim = new AnimEngine(scene);
        var recon = new TreeReconciler(scene, strings) { Anim = anim };
        recon.ReconcileRoot(Embed.Comp(() => new SpringProbe()), null);

        foreach (var c in recon.LiveComponents)   // phase 6.5: drain layout effects → seeds the spring on the host node
        {
            foreach (var e in c.Context.PendingLayoutEffects) e();
            c.Context.PendingLayoutEffects.Clear();
        }
        for (int i = 0; i < 150; i++) anim.Tick(16f);

        var host = scene.FirstChild(scene.Root);   // the SpringProbe's box node
        float sx = scene.Paint(host).LocalTransform.M11;
        Check("35. UseSpring hook seeds + drives the node", !host.IsNull && Near(sx, 1.2f, 0.03f), $"scaleX={sx:0.###}");
    }

    // ScrollView: layout publishes ContentSize, the viewport clips overflow, and a wheel scrolls via a transform
    // (layout-free) clamped to the content — no relayout, offscreen rows culled.
    static void ScrollChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("scroll", new Size2(480, 320), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new ScrollProbe());

        host.RunFrame();   // mount + layout → ContentSize published
        var vp = host.Scene.Root;
        host.Scene.TryGetScroll(vp, out var sc0);
        bool sized = Near(sc0.ContentH, 800) && Near(sc0.ViewportH, 200);

        // a 200px viewport over 40px rows shows ~5 of 20 — the rest are clip-culled; clip is balanced.
        int drawnAtTop = device.LastRects.Count;
        bool clipped = device.LastClips.Count >= 1 && device.ClipBalance == 0 && drawnAtTop is >= 5 and < 20;

        // wheel down 100 → offset 100, content transform −100, NO re-render (transform-only frame)
        var center = new Point2(100, 100);
        window.QueueInput(new InputEvent(InputKind.Wheel, center, 0, 0, 100f));
        var f = host.RunFrame();
        host.Scene.TryGetScroll(vp, out var sc1);
        bool scrolled = Near(sc1.OffsetY, 100)
            && Near(host.Scene.Paint(sc1.ContentNode).LocalTransform.Dy, -100)
            && !f.Rendered;

        // fling past the end → clamp to ContentH − ViewportH = 600
        window.QueueInput(new InputEvent(InputKind.Wheel, center, 0, 0, 10000f));
        host.RunFrame();
        host.Scene.TryGetScroll(vp, out var sc2);
        bool clamped = Near(sc2.OffsetY, 600);

        Check("36. ScrollView publishes ContentSize + clips overflow", sized && clipped, $"content={sc0.ContentH:0} drawn={drawnAtTop} clips={device.LastClips.Count}");
        Check("37. wheel scrolls via transform (layout-free) + clamps", scrolled && clamped, $"off→{sc1.OffsetY:0}, clamp={sc2.OffsetY:0}");
    }

    // Wheel-axis routing: the two wheel axes route INDEPENDENTLY to a scroller of their own orientation, so a horizontal
    // two-finger swipe over a nested horizontal box scrolls THAT box (not the page vertically), and a vertical wheel over
    // the same box climbs past it to scroll the PAGE.
    static void TwoAxisScrollChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("twoaxis", new Size2(220, 220), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new NestedScrollProbe());
        host.RunFrame();

        var outer = host.Scene.Root;                    // the vertical page scroller
        NodeHandle inner = NodeHandle.Null;             // the nested horizontal scroller
        void Visit(NodeHandle n)
        {
            if (n.IsNull) return;
            if (host.Scene.TryGetScroll(n, out var s) && s.Orientation == 1) inner = n;
            for (var c = host.Scene.FirstChild(n); !c.IsNull; c = host.Scene.NextSibling(c)) Visit(c);
        }
        Visit(outer);

        var pos = new Point2(90, 30);   // over the inner horizontal box (top strip; it stays there through both wheels)

        // Horizontal wheel over the inner box → the BOX scrolls on X; the page Y stays 0 (the swipe never leaks vertical).
        window.QueueInput(new InputEvent(InputKind.Wheel, pos, 0, 0, 0f, ScrollDeltaX: 60f));
        host.RunFrame();
        host.Scene.TryGetScroll(outer, out var o1);
        host.Scene.TryGetScroll(inner, out var i1);
        bool hWheelScrollsBox = Near(i1.OffsetX, 60) && Near(o1.OffsetY, 0);

        // Vertical wheel over the same box → the PAGE scrolls on Y (climbing past the horizontal box); the box X is unchanged.
        window.QueueInput(new InputEvent(InputKind.Wheel, pos, 0, 0, 80f));
        host.RunFrame();
        host.Scene.TryGetScroll(outer, out var o2);
        host.Scene.TryGetScroll(inner, out var i2);
        bool vWheelScrollsPage = Near(o2.OffsetY, 80) && Near(i2.OffsetX, 60);

        Check("37b. wheel-axis routing: horizontal wheel scrolls a nested horizontal box (not the page); vertical wheel scrolls the page past it",
            !inner.IsNull && hWheelScrollsBox && vWheelScrollsPage,
            $"box.X={i2.OffsetX:0} page.Y={o2.OffsetY:0} (after-h: box.X={i1.OffsetX:0} page.Y={o1.OffsetY:0})");
    }

    static void ScrollCrossAxisChecks(StringTable strings)
    {
        const string longLine =
            "This intentionally unwrapped caption is long enough to exceed the viewport width and must not widen the vertical scroll content or nested virtual grids.";

        var tree = Ui.ScrollView(new BoxEl
        {
            Direction = 1,
            Gap = 12f,
            Padding = Edges4.All(24f),
            Children =
            [
                new TextEl(longLine) { Size = 14f },
                new BoxEl
                {
                    Height = 260f,
                    Children =
                    [
                        Virtual.Grid(1000, columns: 4, itemHeight: 110f, gap: 12f,
                            renderItem: i => new BoxEl { Fill = ColorF.FromRgba(40, 40, 40) },
                            keyOf: i => "g" + i),
                    ],
                },
            ],
        });

        var scene = new SceneStore();
        new TreeReconciler(scene, strings).ReconcileRoot(tree, null);
        new FlexLayout(scene, new HeadlessFontSystem(strings)).Run(scene.Root, new Size2(480f, 320f));

        scene.TryGetScroll(scene.Root, out var outer);
        NodeHandle gridViewport = NodeHandle.Null;
        void Visit(NodeHandle n)
        {
            if (n.IsNull) return;
            if (scene.TryGetScroll(n, out var sc) && sc.ItemCount == 1000) gridViewport = n;
            for (var c = scene.FirstChild(n); !c.IsNull; c = scene.NextSibling(c)) Visit(c);
        }
        Visit(scene.Root);

        scene.TryGetScroll(gridViewport, out var gridScroll);
        var firstCard = scene.FirstChild(gridScroll.ContentNode);
        var grid = scene.AbsoluteRect(gridViewport);
        var card = scene.AbsoluteRect(firstCard);

        bool contentClamped = Near(outer.ContentW, outer.ViewportW) && Near(scene.Bounds(outer.ContentNode).W, outer.ViewportW);
        bool gridConstrained = !gridViewport.IsNull && Near(grid.W, 432f) && card.W <= 101f;

        Check("37a. vertical ScrollView clamps cross-axis content before nested virtual layout",
            contentClamped && gridConstrained,
            $"contentW={outer.ContentW:0} viewportW={outer.ViewportW:0} gridW={grid.W:0} cardW={card.W:0}");
    }

    // Virtualization: a 10k-row list realizes only the viewport window; scrolling recycles via the slab free-list
    // (bounded live nodes, no leak); a sub-extent scroll is a transform-only frame (no realize / no relayout).
    // Overlay scrollbar visual states: hover over the lane shows the full WinUI gutter; leaving collapses to a thin
    // indicator; after the idle timeout it auto-hides to no scrollbar draw.
    static void ScrollOverlayChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("scrollbar", new Size2(480, 320), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new ScrollProbe());

        static RectF DeviceRect(FillRoundRectCmd cmd) => cmd.Transform.TransformBounds(cmd.Rect);
        static bool LaneRect(FillRoundRectCmd cmd, out RectF r)
        {
            r = DeviceRect(cmd);
            return r.X >= 186f && r.X <= 200.5f && r.W <= 13.5f && r.H > 20f;
        }

        host.RunFrame();

        window.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(198f, 100f), 0, 0));
        for (int i = 0; i < 40; i++) host.RunFrame();

        bool expandedGutter = false, expandedThumb = false;
        foreach (var rect in device.LastRects)
        {
            if (!LaneRect(rect, out var r)) continue;
            expandedGutter |= r.W >= 10f && r.H >= 190f;
            expandedThumb |= r.W >= 5f && r.W < 10f && r.H >= 30f && r.H < 190f;
        }
        bool hoverSettledIdle = !host.HasActiveWork;

        window.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(260f, 260f), 0, 0));
        for (int i = 0; i < 30; i++) host.RunFrame();

        bool collapsedGutter = false, collapsedThumb = false;
        foreach (var rect in device.LastRects)
        {
            if (!LaneRect(rect, out var r)) continue;
            collapsedGutter |= r.W >= 10f && r.H >= 190f;
            collapsedThumb |= r.W <= 3f && r.H >= 30f;   // WinUI resting thumb = 2px visible (8 − 6 stroke)
        }

        for (int i = 0; i < 90; i++) host.RunFrame();

        bool anyScrollbar = false;
        foreach (var rect in device.LastRects)
        {
            anyScrollbar |= LaneRect(rect, out _);
        }

        Check("38a. overlay scrollbar expands, collapses to a visible thumb, then auto-hides",
            expandedGutter && expandedThumb && !collapsedGutter && collapsedThumb && !anyScrollbar,
            $"expanded=({expandedGutter},{expandedThumb}) collapsed=({collapsedGutter},{collapsedThumb}) hidden={!anyScrollbar}");
        Check("38b. hover-visible scrollbar settles without keeping frames active",
            hoverSettledIdle, $"active={host.HasActiveWork}");
    }

    // Frame-clock timing hooks (gate.timer.*): UseDebouncedValue / UseThrottledValue / UseTimeout / UseInterval over
    // the host's HostTimerQueue. All driven deterministically over the headless frame clock (each host.Paint(0) advances
    // one FixedFrameTimeSource step = 16 ms), so a 100 ms window fires ~7 frames in. Media playback keeps its own device
    // clock and never rides this queue (WS-Media non-goal) — no media gate here.
    static void TimerHookChecks(StringTable strings)
    {
        var fonts = new HeadlessFontSystem(strings);

        // ── gate.timer.debounce-trailing: 3 writes within the window ⇒ exactly one trailing commit to the last value ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("timer-debounce", new Size2(200, 120), 1f)); window.Show();
            var probe = new DebounceProbe(100f);
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.Paint(0);
            probe.Source.Value = "a"; host.Paint(0);   // arm
            probe.Source.Value = "b"; host.Paint(0);   // re-arm
            probe.Source.Value = "c"; host.Paint(0);   // re-arm — the last value wins
            bool pendingStillInitial = probe.Debounced.Peek() == "";
            string prev = probe.Debounced.Peek();
            int transitions = 0;
            for (int i = 0; i < 16; i++) { host.Paint(0); var v = probe.Debounced.Peek(); if (v != prev) { transitions++; prev = v; } }
            bool committedOnce = transitions == 1 && probe.Debounced.Peek() == "c";
            Check("gate.timer.debounce-trailing 3 writes in the window ⇒ exactly 1 trailing commit to the last value",
                pendingStillInitial && committedOnce, $"pendingInitial={pendingStillInitial} transitions={transitions} value='{probe.Debounced.Peek()}'");
        }

        // ── gate.timer.debounce-flush: Flush() commits immediately + cancels pending; Cancel() never commits ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("timer-flush", new Size2(200, 120), 1f)); window.Show();
            var probe = new DebounceProbe(100f);
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.Paint(0);
            probe.Source.Value = "x"; host.Paint(0);      // arm
            bool beforeFlush = probe.Debounced.Peek() == "";
            probe.Handle.Flush();                          // commit NOW + cancel pending
            bool afterFlush = probe.Debounced.Peek() == "x";
            string p = probe.Debounced.Peek(); int extra = 0;
            for (int i = 0; i < 16; i++) { host.Paint(0); if (probe.Debounced.Peek() != p) { extra++; p = probe.Debounced.Peek(); } }
            bool flushNoExtra = extra == 0;

            using var app2 = new HeadlessPlatformApp();
            var window2 = new HeadlessWindow(new WindowDesc("timer-cancel", new Size2(200, 120), 1f)); window2.Show();
            var probe2 = new DebounceProbe(100f);
            using var host2 = new AppHost(app2, window2, new HeadlessGpuDevice(), fonts, strings, probe2);
            host2.Paint(0);
            probe2.Source.Value = "y"; host2.Paint(0);     // arm
            probe2.Handle.Cancel();                         // drop the pending fire
            for (int i = 0; i < 16; i++) host2.Paint(0);
            bool cancelNoCommit = probe2.Debounced.Peek() == "";
            Check("gate.timer.debounce-flush Flush() commits immediately + cancels pending; Cancel() never commits",
                beforeFlush && afterFlush && flushNoExtra && cancelNoCommit,
                $"beforeFlush={beforeFlush} afterFlush={afterFlush} flushNoExtra={flushNoExtra} cancelNoCommit={cancelNoCommit}");
        }

        // ── gate.timer.throttle-leading-trailing: leading fires immediately; trailing samples the last value ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("timer-throttle", new Size2(200, 120), 1f)); window.Show();
            var probe = new ThrottleProbe(100f);
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.Paint(0);
            probe.Source.Value = 1; host.Paint(0);   // leading → emit immediately
            bool leading = probe.Throttled.Peek() == 1;
            probe.Source.Value = 2; host.Paint(0);   // suppressed (cooldown)
            probe.Source.Value = 3; host.Paint(0);   // suppressed, latest = 3
            bool stillLeading = probe.Throttled.Peek() == 1;
            for (int i = 0; i < 16; i++) host.Paint(0);   // window closes → trailing sample
            bool trailing = probe.Throttled.Peek() == 3;
            Check("gate.timer.throttle-leading-trailing leading emits immediately; trailing samples the last value",
                leading && stillLeading && trailing, $"leading={leading} stillLeading={stillLeading} trailing={trailing} value={probe.Throttled.Peek()}");
        }

        // ── gate.timer.interval-pauses-inactive: ticks while active, pauses while window-inactive, resumes on return ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("timer-interval", new Size2(200, 120), 1f)); window.Show();
            var probe = new IntervalProbe(48f);   // ~3 frames per tick
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.Paint(0);
            for (int i = 0; i < 20; i++) host.Paint(0);
            bool tickedWhileActive = probe.Ticks > 0;
            host.SetWindowActive(false); host.Paint(0);   // flush the activation change → interval pauses
            int atPause = probe.Ticks;
            for (int i = 0; i < 20; i++) host.Paint(0);
            bool pausedNoTicks = probe.Ticks == atPause;
            host.SetWindowActive(true); host.Paint(0);    // resume
            for (int i = 0; i < 20; i++) host.Paint(0);
            bool resumed = probe.Ticks > atPause;
            Check("gate.timer.interval-pauses-inactive interval ticks while active, pauses while window-inactive, resumes",
                tickedWhileActive && pausedNoTicks && resumed, $"active={probe.Ticks - (probe.Ticks - atPause)} atPause={atPause} final={probe.Ticks}");
        }

        // ── gate.timer.unmount-cancels: a due-after-unmount timeout never fires ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("timer-unmount", new Size2(200, 120), 1f)); window.Show();
            var parent = new TimeoutUnmountParent();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, parent);
            host.RunFrame();                        // mount: child arms a 200 ms timeout (due ≈ 200)
            bool notFiredYet = parent.Fires == 0;
            parent.Show.Value = false; host.Paint(0);   // unmount the child BEFORE the fire → RunAllCleanups cancels the timer
            for (int i = 0; i < 24; i++) host.Paint(0);  // advance well past 200 ms
            Check("gate.timer.unmount-cancels a due-after-unmount timeout never fires",
                notFiredYet && parent.Fires == 0, $"notFiredYet={notFiredYet} fires={parent.Fires}");
        }

        // ── gate.timer.quiesce-idle: one pending 5 s timeout — the host wait reflects the due time; no intermediate frame runs ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("timer-quiesce", new Size2(200, 120), 1f)); window.Show();
            var probe = new TimeoutProbe(5000f);
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            for (int i = 0; i < 6 && host.HasActiveWork; i++) host.RunFrame();   // settle the mount (leaves only the pending 5 s timer)
            int wait = host.RecommendedWaitMs();
            bool waitReflectsDue = wait >= 4000 && wait <= 5100;
            bool noTimerWake = (host.CurrentWakeReasons & WakeReasons.Timer) == 0;   // pending, not due
            bool wouldIdle = !host.HasActiveWork;                                     // the loop would fully block
            double clockBefore = host.FrameClockMsForTest;
            bool anyRendered = false;
            for (int i = 0; i < 8; i++) { var f = host.RunFrame(); if (f.Rendered) anyRendered = true; }
            bool noIntermediateFrames = !anyRendered && probe.Fires == 0 && host.FrameClockMsForTest == clockBefore;
            Check("gate.timer.quiesce-idle a pending 5s timeout: the wait reflects the due time and no intermediate frame runs",
                waitReflectsDue && noTimerWake && wouldIdle && noIntermediateFrames,
                $"wait={wait} noTimerWake={noTimerWake} wouldIdle={wouldIdle} rendered={anyRendered} fires={probe.Fires}");
        }

        // ── gate.timer.zero-steady-alloc: an armed timer adds 0 bytes to the hot phase on quiet frames ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("timer-alloc", new Size2(200, 120), 1f)); window.Show();
            var probe = new IntervalProbe(100000f);   // armed the whole time, never fires during the window
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            for (int i = 0; i < 4 && host.HasActiveWork; i++) host.RunFrame();
            for (int i = 0; i < 6; i++) host.Paint(0);   // warm the drain path (JIT) with the timer armed
            long worst = 0;
            for (int i = 0; i < 10; i++) { var f = host.Paint(0); if (f.HotPhaseAllocBytes > worst) worst = f.HotPhaseAllocBytes; }
            Check("gate.timer.zero-steady-alloc an armed timer adds 0 bytes to the hot phase on quiet frames",
                worst == 0, $"worst={worst} bytes (armed timers={host.TimersForTest.Count})");
        }

        // ── gate.timer.warm-cadence: frames continue for the hold window after a synthetic input, then quiesce ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("timer-warm", new Size2(200, 120), 1f)); window.Show();
            var probe = new InertBoxProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.WarmCadenceEnabledForTest = true;   // off headless by default (keeps existing idle gates green); the gate opts in
            for (int i = 0; i < 6 && host.HasActiveWork; i++) host.RunFrame();
            bool idleBefore = !host.HasActiveWork;
            window.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(10f, 10f), 0, 0));
            host.RunFrame();                          // dispatch → warm-cadence armed for ~1 s
            bool warmLit = (host.CurrentWakeReasons & WakeReasons.WarmCadence) != 0;
            int warmFrames = 0;
            for (int i = 0; i < 200; i++) { if ((host.CurrentWakeReasons & WakeReasons.WarmCadence) == 0) break; host.RunFrame(); warmFrames++; }
            bool held = warmFrames >= 50 && warmFrames <= 75;   // ~1000 ms / 16 ms ≈ 62 frames
            for (int i = 0; i < 8 && host.HasActiveWork; i++) host.RunFrame();
            bool quiescedAfter = !host.HasActiveWork;
            Check("gate.timer.warm-cadence frames continue for the ~1s hold after input, then quiesce",
                idleBefore && warmLit && held && quiescedAfter,
                $"idleBefore={idleBefore} warmLit={warmLit} warmFrames={warmFrames} quiescedAfter={quiescedAfter}");
        }
    }

    // Generic async-command primitive (UseAsyncCommand / UseAsyncCommands<TKey>): the in-progress state tracks the
    // Task, a re-fire while running is blocked, Cancel clears it, keyed runs are independent, and an idle frame is 0-alloc.
    static void AsyncCommandChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("async-cmd", new Size2(320, 240), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);

        // ── single command: lifecycle + re-entry guard ──
        var probe = new AsyncCommandProbe();
        using var host = new AppHost(app, window, device, fonts, strings, probe);
        host.RunFrame();

        var gate = new TaskCompletionSource<bool>();
        int starts = 0;
        probe.Cmd.Run(_ => { starts++; return gate.Task; });
        bool runningWhilePending = probe.Cmd.IsRunningNow;
        probe.Cmd.Run(_ => { starts++; return Task.CompletedTask; });   // BLOCKED — first is still in flight (op not invoked)
        bool blocked = starts == 1;
        gate.SetResult(true);
        for (int k = 0; k < 16 && probe.Cmd.IsRunningNow; k++) host.RunFrame();
        bool clearedAfter = !probe.Cmd.IsRunningNow;
        Check("AC-1/2. async command: IsRunning tracks the Task, and a re-fire while running is blocked",
            runningWhilePending && blocked && clearedAfter,
            $"runningWhilePending={runningWhilePending} opStarts={starts} clearedAfter={clearedAfter}");

        // ── cancellation: Cancel() clears IsRunning; a late completion of the underlying task does not revive it ──
        var gate2 = new TaskCompletionSource<bool>();
        probe.Cmd.Run(ct => gate2.Task.WaitAsync(ct));
        bool runningC = probe.Cmd.IsRunningNow;
        probe.Cmd.Cancel();
        for (int k = 0; k < 16 && probe.Cmd.IsRunningNow; k++) host.RunFrame();
        bool clearedAfterCancel = !probe.Cmd.IsRunningNow;
        gate2.TrySetResult(true);
        host.RunFrame();
        bool stayedCleared = !probe.Cmd.IsRunningNow;
        Check("AC-3. async command: Cancel() clears IsRunning; a late completion does not revive it",
            runningC && clearedAfterCancel && stayedCleared,
            $"runningC={runningC} clearedAfterCancel={clearedAfterCancel} stayedCleared={stayedCleared}");

        // ── 0-alloc when idle ──
        var fIdle = host.RunFrame();
        Check("AC-5. an idle async-command frame is 0-alloc on the hot phases",
            fIdle.HotPhaseAllocBytes == 0, $"{fIdle.HotPhaseAllocBytes} bytes");

        // ── keyed: per-key independence ──
        using var app2 = new HeadlessPlatformApp();
        var window2 = new HeadlessWindow(new WindowDesc("async-cmd-keyed", new Size2(320, 240), 1f));
        window2.Show();
        var kp = new AsyncCommandsProbe();
        using var host2 = new AppHost(app2, window2, new HeadlessGpuDevice(), fonts, strings, kp);
        host2.RunFrame();
        var g1 = new TaskCompletionSource<bool>();
        var g2 = new TaskCompletionSource<bool>();
        kp.Cmds.Run(1, _ => g1.Task);
        kp.Cmds.Run(2, _ => g2.Task);
        bool bothRunning = kp.Cmds.IsRunningNow(1) && kp.Cmds.IsRunningNow(2);
        g1.SetResult(true);
        for (int k = 0; k < 16 && kp.Cmds.IsRunningNow(1); k++) host2.RunFrame();
        bool oneDoneTwoRunning = !kp.Cmds.IsRunningNow(1) && kp.Cmds.IsRunningNow(2);
        g2.SetResult(true);
        for (int k = 0; k < 16 && kp.Cmds.IsRunningNow(2); k++) host2.RunFrame();
        bool allDone = !kp.Cmds.IsRunningNow(2);
        Check("AC-4. keyed async commands: each key's IsRunning is independent (key 1 finishing leaves key 2 running)",
            bothRunning && oneDoneTwoRunning && allDone,
            $"both={bothRunning} oneDoneTwoRunning={oneDoneTwoRunning} allDone={allDone}");
    }

    // The first node at or under <paramref name="n"/> that owns a scroll viewport (the VirtualListEl that ItemsView builds).
    static NodeHandle FindScrollNode(SceneStore s, NodeHandle n)
    {
        if (n.IsNull) return NodeHandle.Null;
        if (s.HasScroll(n)) return n;
        for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
        {
            var r = FindScrollNode(s, c);
            if (!r.IsNull) return r;
        }
        return NodeHandle.Null;
    }

    static int BoundSlotCount(SceneStore scene, NodeHandle root)
    {
        var vp = FindScrollNode(scene, root);
        if (vp.IsNull || !scene.TryGetScroll(vp, out var sc)) return 0;
        int n = 0;
        for (var c = scene.FirstChild(sc.ContentNode); !c.IsNull; c = scene.NextSibling(c)) n++;
        return n;
    }

    // Detail-shell resize flicker — engine + app contract gates (detail-resize-flicker-fix-proposal.md §Fix 3).
    static void DetailResizeFlickerChecks(StringTable strings)
    {
        // Fix 1 — tier remount without cold stagger fills the viewport window in the remount frame.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("tier-remount", new Size2(400, 320), 1f, Composited: true));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var probe = new ColdStaggerRemountProbe();
            using var host = new AppHost(app, window, device, fonts, strings, probe);

            host.RunFrame();
            var firstVp = FindScrollNode(host.Scene, host.Scene.Root);
            host.Scene.TryGetScroll(firstVp, out var firstSc);
            int staggeredFirst = BoundSlotCount(host.Scene, host.Scene.Root);
            int firstWindowRows = firstSc.LastRealized - firstSc.FirstRealized;
            for (int i = 0; i < 24 && host.Reconciler.HasWarmingVirtuals; i++) host.RunFrame();
            int staggeredSettled = BoundSlotCount(host.Scene, host.Scene.Root);
            bool wasWarming = host.Reconciler.HasWarmingVirtuals;
            probe.Tier.Value = 1;   // keyed remount — staggerColdRealize:false (list already realized once)
            host.RunFrame();
            var vp = FindScrollNode(host.Scene, host.Scene.Root);
            host.Scene.TryGetScroll(vp, out var sc);
            int remountSlots = BoundSlotCount(host.Scene, host.Scene.Root);
            int windowRows = sc.LastRealized - sc.FirstRealized;
            Check("RZ-TIER. cold stagger never presents a partial visible window; tier remount fills in one frame",
                staggeredFirst >= firstWindowRows && staggeredFirst >= 8 && firstWindowRows >= 8
                && !wasWarming && staggeredSettled >= staggeredFirst
                && remountSlots >= windowRows && remountSlots >= 8,
                $"first={staggeredFirst}/{firstWindowRows} settled={staggeredSettled} remount={remountSlots} window={windowRows} first={sc.FirstRealized} last={sc.LastRealized}");
        }

        // Fix 2 — modal-loop keep-alive must not swallow warming virtual refill when ambient animation is live.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("modal-warm", new Size2(400, 320), 1f, Composited: true));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var probe = new ModalWarmProbe();
            using var host = new AppHost(app, window, device, fonts, strings, probe);

            host.RunFrame();
            bool warming = host.Reconciler.HasWarmingVirtuals;
            int slots0 = BoundSlotCount(host.Scene, host.Scene.Root);
            var vp0 = FindScrollNode(host.Scene, host.Scene.Root);
            host.Scene.TryGetScroll(vp0, out var sc0);
            int windowRows0 = sc0.LastRealized - sc0.FirstRealized;
            host.Animation.Keyframes(host.Scene.Root, AnimChannel.Opacity,
                [new Keyframe(0f, 0.5f, Easing.Linear), new Keyframe(1f, 1f, Easing.Linear)], 1000f, loop: true);
            bool ambient = host.CurrentWakeReasons.HasFlag(WakeReasons.Anim);
            window.InModalLoop = true;
            window.SizedInModalLoop = false;   // titlebar move (not edge resize) — ambient ticks must still paint
            host.Paint(0, keepAlive: true);
            int slots1 = BoundSlotCount(host.Scene, host.Scene.Root);
            Check("RZ-MODAL. modal-loop keep-alive preserves/refills the visible virtual window under ambient-only animation wake",
                ambient && slots0 >= windowRows0 && slots0 >= 8 && (warming ? slots1 > slots0 : slots1 >= slots0),
                $"warming={warming} ambient={ambient} slots {slots0}→{slots1} window={windowRows0} wake={host.CurrentWakeReasons}");
        }
    }

    // Butter-smooth resize v2 — modal defer / live non-composited / throttle / move liveness (docs/plans/butter-smooth-resize-v2.md).
    static void ButterSmoothResizeChecks(StringTable strings)
    {
        // RZ-DEFER — composited edge-resize defer: HWND grows but layout/swapchain stay at last size until modal exit.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("rz-defer", new Size2(400, 320), 1f, Composited: true));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            using var host = new AppHost(app, window, device, fonts, strings, new ResizeBoxProbe());

            host.RunFrame();
            float rootHBefore = host.Scene.AbsoluteRect(host.Scene.Root).H;

            window.InModalLoop = true;
            window.SizedInModalLoop = true;
            window.ClientSizePx = new Size2(800, 640);
            host.Paint(0, keepAlive: true);
            float rootHDeferred = host.Scene.AbsoluteRect(host.Scene.Root).H;

            window.InModalLoop = false;
            window.SizedInModalLoop = false;
            host.Paint(0, keepAlive: true);
            float rootHSettled = host.Scene.AbsoluteRect(host.Scene.Root).H;

            Check("RZ-DEFER. composited modal grow keeps viewport until exit, then applies final size",
                Near(rootHBefore, 320f, 1f) && Near(rootHDeferred, rootHBefore, 1f) && Near(rootHSettled, 640f, 1f),
                $"rootH {rootHBefore:0.#}→{rootHDeferred:0.#}→{rootHSettled:0.#} (want 320,320,640)");
        }

        // RZ-LIVE — non-composited modal resize applies the new client size on each keep-alive tick.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("rz-live", new Size2(400, 320), 1f, Composited: false));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            using var host = new AppHost(app, window, device, fonts, strings, new ResizeBoxProbe());

            host.RunFrame();
            window.InModalLoop = true;
            window.SizedInModalLoop = true;
            window.ClientSizePx = new Size2(800, 640);
            host.Paint(0, keepAlive: true);
            float rootH = host.Scene.AbsoluteRect(host.Scene.Root).H;

            Check("RZ-LIVE. non-composited modal keep-alive applies the new client size",
                Near(rootH, 640f, 1f), $"rootH={rootH:0.#} (want 640)");
        }

        // RZ-SETTLE — settle frame presents, disables span reuse for resize, hints DWM sync.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("rz-settle", new Size2(400, 320), 1f, Composited: true));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            using var host = new AppHost(app, window, device, fonts, strings, new ResizeBoxProbe());

            host.RunFrame();
            window.InModalLoop = true;
            window.SizedInModalLoop = true;
            window.ClientSizePx = new Size2(800, 640);
            host.Paint(0, keepAlive: true);
            window.InModalLoop = false;
            window.SizedInModalLoop = false;
            var stats = host.Paint(0, keepAlive: true);

            Check("RZ-SETTLE. modal exit settle presents with span reuse disabled for resize + settle hint",
                stats.Presented
                && (stats.SpanReuseDisabledReasons & SpanReuseDisabledReason.Resize) != 0
                && device.HintSettlePresentCount == 1,
                $"presented={stats.Presented} spanDisable={stats.SpanReuseDisabledReasons} hint={device.HintSettlePresentCount}");
        }

        // RZ-THROTTLE — 30 Hz gate for non-composited modal edge-resize paints.
        {
            long last = 0;
            int paints = 0;
            for (int step = 0; step < 10; step++)
            {
                long now = step * 8;
                if (!ModalPaintThrottle.ShouldSkip(now, ref last, sized: true, minIntervalMs: 33))
                    paints++;
            }
            long gapLast = 0;
            bool gapPaint = !ModalPaintThrottle.ShouldSkip(40, ref gapLast, sized: true, minIntervalMs: 33);
            Check("RZ-THROTTLE. 10 steps @8ms yields ≤4 paints; 40ms gap allows paint",
                paints <= 4 && gapPaint, $"paints={paints} gapPaint={gapPaint} last={gapLast}");
        }

        // RZ-MOVE — composited titlebar move: ambient animation ticks still submit; span reuse stays enabled.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("rz-move", new Size2(400, 320), 1f, Composited: true));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            using var host = new AppHost(app, window, device, fonts, strings, new ResizeBoxProbe());

            host.RunFrame();
            host.Animation.Keyframes(host.Scene.Root, AnimChannel.Opacity,
                [new Keyframe(0f, 0.5f, Easing.Linear), new Keyframe(1f, 1f, Easing.Linear)], 1000f, loop: true);
            int framesBefore = device.FrameCount;
            window.InModalLoop = true;
            window.SizedInModalLoop = false;
            var stats = host.Paint(0, keepAlive: true);

            Check("RZ-MOVE. composited move keeps ambient modal ticks + span reuse",
                device.FrameCount > framesBefore && stats.Presented
                && (stats.SpanReuseDisabledReasons & SpanReuseDisabledReason.ModalPaint) == 0,
                $"frames {framesBefore}→{device.FrameCount} presented={stats.Presented} spanDisable={stats.SpanReuseDisabledReasons}");
        }

        // RZ-MOVE2 — composited edge resize: ambient-only ticks bail; span reuse disabled for modal paint.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("rz-move2", new Size2(400, 320), 1f, Composited: true));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            using var host = new AppHost(app, window, device, fonts, strings, new ResizeBoxProbe());

            host.RunFrame();
            host.Animation.Keyframes(host.Scene.Root, AnimChannel.Opacity,
                [new Keyframe(0f, 0.5f, Easing.Linear), new Keyframe(1f, 1f, Easing.Linear)], 1000f, loop: true);
            int framesBefore = device.FrameCount;
            window.InModalLoop = true;
            window.SizedInModalLoop = true;
            var stats = host.Paint(0, keepAlive: true);

            Check("RZ-MOVE2. composited edge resize bails ambient-only ticks + disables span reuse",
                device.FrameCount == framesBefore,
                $"frames {framesBefore}→{device.FrameCount} (idle-skip expected)");
        }
    }

    sealed class ResizeBoxProbe : Component
    {
        public override Element Render() => Embed.Comp(() => new OverlayHost
        {
            Child = new BoxEl { Grow = 1f, Fill = ColorF.FromRgba(20, 20, 20) },
        });
    }

    // ItemsView BOUND row path (CreateBound): selection / now-playing re-skin the persistent slots IN PLACE via binds —
    // no row-template re-run (no rebuild/remount/Enter replay = no flash), 0-alloc on the paint phases, one roving tab stop.
    static void BoundItemsViewChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("bound-iv", new Size2(640, 480), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var probe = new BoundItemsViewProbe();
        using var host = new AppHost(app, window, device, fonts, strings, probe);

        host.RunFrame();
        var scene = host.Scene;
        var vp = FindScrollNode(scene, scene.Root);
        scene.TryGetScroll(vp, out var sc);
        var content = sc.ContentNode;

        // slot root (the AccentPill BoxEl) → [ lv-content → [text] , lv-pill ].
        var slot0 = scene.FirstChild(content);
        var lane0 = scene.FirstChild(slot0);
        var text0 = scene.FirstChild(lane0);
        var pill0 = scene.NextSibling(lane0);

        float pillRest = scene.Paint(pill0).Opacity;
        int callsBase = probe.TemplateCalls;

        // 1. Selecting a visible row flips its bound pill opacity 0→1 with NO row-template re-run (no rebuild = no flash).
        probe.Selection.Select(0);
        host.RunFrame();
        float pillSel = scene.Paint(pill0).Opacity;
        int callsSel = probe.TemplateCalls;
        Check("IV-bound 1. select flips the bound pill in place (no template re-run = no flash)",
            pillRest < 0.01f && pillSel > 0.99f && callsSel == callsBase,
            $"pill {pillRest:0.00}→{pillSel:0.00} templateCalls {callsBase}→{callsSel}");

        // 2. The selection re-skin frame allocates 0 managed bytes on the hot (paint) phases — it is a bound opacity write,
        //    not a rebuild.
        probe.Selection.Deselect(0);
        var fDe = host.RunFrame();
        Check("IV-bound 2. selection re-skin is 0-alloc on the hot phases",
            fDe.HotPhaseAllocBytes == 0, $"{fDe.HotPhaseAllocBytes} bytes");

        // 3. Now-playing recolours the bound title in place, again with NO row-template re-run.
        var colorRest = scene.Paint(text0).TextColor;
        int callsNowBase = probe.TemplateCalls;
        probe.NowPlaying.Value = 0;
        host.RunFrame();
        var colorNow = scene.Paint(text0).TextColor;
        Check("IV-bound 3. now-playing recolours the title in place (no template re-run)",
            !colorRest.Equals(colorNow) && probe.TemplateCalls == callsNowBase,
            $"colorChanged={!colorRest.Equals(colorNow)} templateCalls {callsNowBase}→{probe.TemplateCalls}");

        // 4. Exactly ONE realized slot carries the roving tab stop (NodeFlags.Focusable) — slot 0 via the no-current
        //    fallback (the others are Focusable=false, so the list has a single tab stop, moved without a re-render).
        int focusable = 0; NodeHandle theStop = NodeHandle.Null;
        for (var c = scene.FirstChild(content); !c.IsNull; c = scene.NextSibling(c))
            if ((scene.Flags(c) & NodeFlags.Focusable) != 0) { focusable++; theStop = c; }
        Check("IV-bound 4. exactly one realized slot holds the roving tab stop (no-current fallback = slot 0)",
            focusable == 1 && theStop == slot0, $"focusable={focusable} isSlot0={theStop == slot0}");

        // Same-count replacement: title is not special. Title, artist, album and duration are four separate mounted
        // binds, and all four must update on the same persistent row without re-running the template or replacing nodes.
        using var atomicApp = new HeadlessPlatformApp();
        var atomicWindow = new HeadlessWindow(new WindowDesc("bound-atomic", new Size2(640, 480), 1f));
        atomicWindow.Show();
        var atomicProbe = new BoundAtomicItemsProbe();
        using var atomicHost = new AppHost(atomicApp, atomicWindow, new HeadlessGpuDevice(), fonts, strings, atomicProbe);
        atomicHost.RunFrame();
        int atomicCalls = atomicProbe.TemplateCalls;
        var oldTitle = FindTextNode(atomicHost.Scene, strings, atomicHost.Scene.Root, "old-title");
        var oldArtist = FindTextNode(atomicHost.Scene, strings, atomicHost.Scene.Root, "old-artist");
        var oldAlbum = FindTextNode(atomicHost.Scene, strings, atomicHost.Scene.Root, "old-album");
        var oldDuration = FindTextNode(atomicHost.Scene, strings, atomicHost.Scene.Root, "101");
        atomicProbe.Items.Value = new BoundAtomicItem[]
        {
            new("new-title", "new-artist", "new-album", 303),
            new("other-new-title", "other-new-artist", "other-new-album", 404),
        };
        atomicHost.RunFrame();
        var newTitle = FindTextNode(atomicHost.Scene, strings, atomicHost.Scene.Root, "new-title");
        var newArtist = FindTextNode(atomicHost.Scene, strings, atomicHost.Scene.Root, "new-artist");
        var newAlbum = FindTextNode(atomicHost.Scene, strings, atomicHost.Scene.Root, "new-album");
        var newDuration = FindTextNode(atomicHost.Scene, strings, atomicHost.Scene.Root, "303");
        bool currentActionItem = atomicProbe.Source.TryPeek(0, out var current) && current.Title == "new-title";
        Check("IV-bound 4a. same-count source replacement atomically updates every cell on persistent row nodes",
            !oldTitle.IsNull && newTitle == oldTitle && newArtist == oldArtist && newAlbum == oldAlbum && newDuration == oldDuration
            && atomicProbe.TemplateCalls == atomicCalls && currentActionItem,
            $"sameNodes={newTitle == oldTitle && newArtist == oldArtist && newAlbum == oldAlbum && newDuration == oldDuration} " +
            $"templateCalls={atomicCalls}->{atomicProbe.TemplateCalls} currentItem={current.Title}");

        // 5/6. A clickable child + an inline link inside a COMPONENT-wrapped bound row must receive the click — not have
        //      it fall through to the row's tap/double-tap. Mirrors the exact Wavee row shape (skin → lane → component → grid).
        using var app2 = new HeadlessPlatformApp();
        var window2 = new HeadlessWindow(new WindowDesc("bound-iv-hit", new Size2(640, 480), 1f));
        window2.Show();
        var hitProbe = new RowButtonHitProbe();
        using var host2 = new AppHost(app2, window2, new HeadlessGpuDevice(), fonts, strings, hitProbe);
        host2.RunFrame();
        var s2 = host2.Scene;
        var skin2 = s2.FirstChild(s2.Root);
        var lane2 = s2.FirstChild(skin2);
        var comp2 = s2.FirstChild(lane2);
        var grid2 = s2.FirstChild(comp2);
        var heartCell = s2.NextSibling(s2.FirstChild(grid2));    // grid child 1 (after the # cell)
        var heart = s2.FirstChild(heartCell);                    // the clickable heart BoxEl
        var hr = s2.AbsoluteRect(heart);
        var heartCenter = new Point2(hr.X + hr.W / 2f, hr.Y + hr.H / 2f);
        var hitNode = host2.Input.HitTest(heartCenter);
        window2.QueueInput(new InputEvent(InputKind.PointerDown, heartCenter, 0, 0));
        window2.QueueInput(new InputEvent(InputKind.PointerUp, heartCenter, 0, 0));
        host2.RunFrame();
        Check("IV-bound 5. a clickable child in a component-wrapped bound row gets the click (not the row's tap)",
            hitProbe.HeartClick == 1 && hitProbe.RowPress == 0 && hitNode == heart,
            $"heartClick={hitProbe.HeartClick} rowPress={hitProbe.RowPress} hitIsHeart={hitNode == heart}");

        var linkCell = s2.NextSibling(s2.NextSibling(heartCell)); // grid child 3 (#, heart, title, album)
        var span = s2.FirstChild(linkCell);                       // the SpanTextEl link node
        var lr = s2.AbsoluteRect(span);
        var linkPt = new Point2(lr.X + 4f, lr.Y + lr.H / 2f);     // over the link glyphs (left edge)
        window2.QueueInput(new InputEvent(InputKind.PointerDown, linkPt, 0, 0));
        window2.QueueInput(new InputEvent(InputKind.PointerUp, linkPt, 0, 0));
        host2.RunFrame();
        Check("IV-bound 6. an inline link in a component-wrapped bound row navigates (not the row's tap)",
            hitProbe.LinkClick == 1 && hitProbe.RowPress == 0,
            $"linkClick={hitProbe.LinkClick} rowPress={hitProbe.RowPress}");

        // 7. The VIRTUALIZED bound path: a clickable child on a realized CreateBound SLOT row must get the tap (not the row).
        using var app3 = new HeadlessPlatformApp();
        var window3 = new HeadlessWindow(new WindowDesc("bound-iv-vhit", new Size2(640, 480), 1f));
        window3.Show();
        var vProbe = new BoundListHitProbe();
        using var host3 = new AppHost(app3, window3, new HeadlessGpuDevice(), fonts, strings, vProbe);
        host3.RunFrame();
        vProbe.Now.Value = 0;     // trigger a row-content re-render first (rebuilds the child + its handler) — the Wavee path
        host3.RunFrame();
        var s3 = host3.Scene;
        var vp3 = FindScrollNode(s3, s3.Root);
        s3.TryGetScroll(vp3, out var sc3);
        var slotR = s3.FirstChild(sc3.ContentNode);          // slot 0 root (the row skin)
        var laneR = s3.FirstChild(slotR);                    // content lane
        var compR = s3.FirstChild(laneR);                    // the row-content component anchor
        var cellR = s3.FirstChild(compR);                    // the # cell (ZStack: reveal layer + click-catcher)
        var catcher = s3.NextSibling(s3.FirstChild(cellR));  // the Grow=1f click-catcher (2nd child)
        var cr = s3.AbsoluteRect(cellR);
        var cellCenter = new Point2(cr.X + cr.W / 2f, cr.Y + cr.H / 2f);
        var vHit = host3.Input.HitTest(cellCenter);
        window3.QueueInput(new InputEvent(InputKind.PointerDown, cellCenter, 0, 0));
        window3.QueueInput(new InputEvent(InputKind.PointerUp, cellCenter, 0, 0));
        host3.RunFrame();
        // …and again near the cell EDGE — proving the Grow=1f catcher FILLS the cell (not just a centered point).
        var cellEdge = new Point2(cr.X + 3f, cr.Y + cr.H - 3f);
        window3.QueueInput(new InputEvent(InputKind.PointerDown, cellEdge, 0, 0));
        window3.QueueInput(new InputEvent(InputKind.PointerUp, cellEdge, 0, 0));
        host3.RunFrame();
        Check("IV-bound 7. the # cell play-catcher (Grow=1f over a HoverOpacity reveal) takes the click across the cell, not the row",
            vProbe.ChildClick == 2 && vProbe.RowPress == 0 && vHit == catcher,
            $"childClick={vProbe.ChildClick} rowPress={vProbe.RowPress} hitIsCatcher={vHit == catcher} cellRect=({cr.X:0},{cr.Y:0},{cr.W:0},{cr.H:0})");

        // 8. THE REPORTED BUG: hovering an interactive CHILD (the # cell catcher) must KEEP the row's HoverWithin set, so
        //    the # cell's HoverOpacity reveal stays revealed (the play glyph must not snap back to the number when you
        //    move the pointer onto it to click). Hover the empty row body first, then move onto the catcher.
        var skinR = s3.FirstChild(sc3.ContentNode);
        var skinRect = s3.AbsoluteRect(skinR);
        window3.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(skinRect.X + 200f, skinRect.Y + skinRect.H / 2f), 0, 0));
        host3.RunFrame();
        bool bodyHover = (s3.Flags(skinR) & NodeFlags.Hovered) != 0;
        var catcherRect = s3.AbsoluteRect(catcher);
        window3.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(catcherRect.X + catcherRect.W / 2f, catcherRect.Y + catcherRect.H / 2f), 0, 0));
        host3.RunFrame();
        bool withinSet = (s3.Flags(skinR) & NodeFlags.HoverWithin) != 0;
        Check("IV-bound 8. hovering the # cell catcher keeps the row HoverWithin (so the play glyph stays revealed)",
            bodyHover && withinSet, $"bodyHover={bodyHover} rowHoverWithin={withinSet}");

        // 9. THE FIX (engine): with the pointer ON the catcher (from gate 8), the # cell's HoverOpacity reveal layer must
        //    stay DRIVEN (hover target 1 — it does not collapse to the number); it decays only when the pointer leaves
        //    the row entirely. Verifies the InteractionAnimator honors the container's HoverWithin.
        var revealLayer = s3.FirstChild(cellR);   // the HoverOpacity reveal layer (sibling of the catcher)
        bool revealOnCatcher = s3.TryGetInteract(revealLayer, out var raOn) && raOn.HoverTarget > 0.99f;
        window3.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(skinRect.X + skinRect.W + 80f, skinRect.Y + skinRect.H + 80f), 0, 0));
        host3.RunFrame();
        bool revealOffOutside = s3.TryGetInteract(revealLayer, out var raOff) && raOff.HoverTarget < 0.01f;
        Check("IV-bound 9. the # cell reveal stays driven while the pointer is on the play button, decays only off the row",
            revealOnCatcher && revealOffOutside, $"onCatcher={revealOnCatcher} offRow={revealOffOutside}");

        using var app4 = new HeadlessPlatformApp();
        var window4 = new HeadlessWindow(new WindowDesc("bound-iv-count-signal", new Size2(640, 480), 1f));
        window4.Show();
        var countProbe = new BoundCountSignalProbe();
        using var host4 = new AppHost(app4, window4, new HeadlessGpuDevice(), fonts, strings, countProbe);
        host4.RunFrame();
        var s4 = host4.Scene;
        var vp4 = FindScrollNode(s4, s4.Root);
        s4.TryGetScroll(vp4, out var sc4a);
        int slotsA = s4.ChildCount(sc4a.ContentNode);
        countProbe.Count.Value = 6;
        host4.RunFrame();
        s4.TryGetScroll(vp4, out var sc4b);
        int slotsB = s4.ChildCount(sc4b.ContentNode);
        countProbe.Count.Value = 3;
        host4.RunFrame();
        s4.TryGetScroll(vp4, out var sc4c);
        int slotsC = s4.ChildCount(sc4c.ContentNode);
        Check("IV-bound 10. bound ItemCount can change through a signal without remounting the list wrapper",
            sc4a.ItemCount == 4 && sc4b.ItemCount == 6 && sc4c.ItemCount == 3 && slotsA == 4 && slotsB == 6 && slotsC == 3,
            $"counts {sc4a.ItemCount}->{sc4b.ItemCount}->{sc4c.ItemCount} slots {slotsA}->{slotsB}->{slotsC}");
    }

    static void VirtualChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("virt", new Size2(640, 480), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new VirtualProbe());

        host.RunFrame();
        var vp = host.Scene.Root;
        host.Scene.TryGetScroll(vp, out var sc0);
        var content = sc0.ContentNode;
        int realized = host.Scene.ChildCount(content);
        bool windowed = realized >= 10 && realized < 40;
        bool contentSize = Near(sc0.ContentH, VirtualProbe.N * 40f);
        Check("38. virtualizes 10k rows to a small window", windowed && contentSize, $"realized={realized}/{VirtualProbe.N} content={sc0.ContentH:0}");

        // in-window (sub-extent) scroll = transform-only frame: no re-render, window unchanged, content shifted.
        int firstA = sc0.FirstRealized;
        var ptr = new Point2(150, 200);
        window.QueueInput(new InputEvent(InputKind.Wheel, ptr, 0, 0, 10f));
        var f1 = host.RunFrame();
        host.Scene.TryGetScroll(vp, out var sc1);
        bool transformOnly = !f1.Rendered && sc1.FirstRealized == firstA
            && Near(host.Scene.Paint(content).LocalTransform.Dy, -10f);
        Check("39. in-window scroll is transform-only (no realize/relayout)", transformOnly, $"rendered={f1.Rendered} first={sc1.FirstRealized}");

        // boundary-crossing fling to the end: window re-realizes directly; recycle keeps live nodes bounded (no leak).
        long live0 = host.Scene.LiveCount;
        for (int s = 0; s < 60; s++) { window.QueueInput(new InputEvent(InputKind.Wheel, ptr, 0, 0, 7000f)); host.RunFrame(); }
        host.Scene.TryGetScroll(vp, out var sc2);
        long liveEnd = host.Scene.LiveCount;
        bool reachedEnd = sc2.FirstRealized > 9000;
        bool bounded = liveEnd < 90 && Math.Abs(liveEnd - live0) < 40;
        Check("40. fling recycles via free-list (bounded live nodes, no leak)", reachedEnd && bounded, $"first={sc2.FirstRealized} live {live0}→{liveEnd}");

        var counted = new CountingVirtualProbe();
        using var app2 = new HeadlessPlatformApp();
        var window2 = new HeadlessWindow(new WindowDesc("virt-overlap", new Size2(640, 480), 1f));
        window2.Show();
        using var host2 = new AppHost(app2, window2, new HeadlessGpuDevice(), fonts, strings, counted);
        host2.RunFrame();
        int calls0 = counted.RenderItemCalls;
        window2.QueueInput(new InputEvent(InputKind.Wheel, new Point2(150, 100), 0, 0, 80f));
        var guardFrame = host2.RunFrame();
        int guardCalls = counted.RenderItemCalls - calls0;
        host2.Scene.TryGetScroll(host2.Scene.Root, out var guardScroll);
        bool guardHeld = !guardFrame.Rendered && guardScroll.FirstRealized == 0 && guardCalls == 0;

        window2.QueueInput(new InputEvent(InputKind.Wheel, new Point2(150, 100), 0, 0, 120f));
        host2.RunFrame();
        int calls1 = counted.RenderItemCalls - calls0 - guardCalls;
        host2.Scene.TryGetScroll(host2.Scene.Root, out var countedScroll);
        bool reusedOverlap = guardHeld && countedScroll.FirstRealized > 0 && calls1 <= 5;
        Check("40a. virtual scroll keeps overscan guard and reuses overlapping item elements",
            reusedOverlap, $"guardCalls={guardCalls} first={countedScroll.FirstRealized} newTemplateCalls={calls1}");

        // Far jump (zero overlap — the scrollbar thumb-drag storm): the window's scene NODES are recycled in place
        // (columns rebound to the new items), not mounted/removed — the drag path becomes a column rewrite.
        var beforeNodes = new List<NodeHandle>();
        for (var c = host.Scene.FirstChild(content); !c.IsNull; c = host.Scene.NextSibling(c)) beforeNodes.Add(c);
        long liveBeforeJump = host.Scene.LiveCount;
        window.QueueInput(new InputEvent(InputKind.Wheel, ptr, 0, 0, -400_000f));   // end → top: no overlap with the old window
        host.RunFrame();
        var afterNodes = new HashSet<NodeHandle>();
        for (var c = host.Scene.FirstChild(content); !c.IsNull; c = host.Scene.NextSibling(c)) afterNodes.Add(c);
        host.Scene.TryGetScroll(vp, out var scTop);
        int recycledCount = 0;
        foreach (var n in beforeNodes) if (afterNodes.Contains(n)) recycledCount++;
        var firstRowText = host.Scene.FirstChild(host.Scene.FirstChild(content));
        string rebound = strings.Resolve(host.Scene.Paint(firstRowText).Text);
        bool recycledOk = scTop.FirstRealized == 0 && afterNodes.Count == beforeNodes.Count
            && recycledCount == beforeNodes.Count && host.Scene.LiveCount == liveBeforeJump && rebound == "row 0";
        Check("40b. far-jump realize recycles the window's scene nodes (rebind, no mount/remove)",
            recycledOk, $"first={scTop.FirstRealized} recycled={recycledCount}/{beforeNodes.Count} live {liveBeforeJump}→{host.Scene.LiveCount} text='{rebound}'");

        // 40b2 — theme correctness ON a recycled node: the default text color is a mount-time singleton-brush binding
        // that PERSISTS across recycle (Update rewrites columns, never bindings — recyclability of the bound default
        // rides that identity). A retheme AFTER the far-jump recycle must repaint the reused node via the re-fired
        // binding — the recycled row follows the live theme, not the color it was mounted under.
        {
            ColorF darkPrimary = Tok.TextPrimary;
            bool darkOk = host.Scene.Paint(firstRowText).TextColor == darkPrimary;
            Tok.Use(ThemeKind.Light);
            host.RunFrame();
            ColorF lightPrimary = Tok.TextPrimary;
            var t2 = host.Scene.FirstChild(host.Scene.FirstChild(content));
            bool lightOk = lightPrimary != darkPrimary && host.Scene.Paint(t2).TextColor == lightPrimary;
            Tok.Use(ThemeKind.Dark);
            host.RunFrame();
            Check("40b2. a recycled default-colored row follows a retheme (the persisted singleton-brush binding re-fires on the reused node)",
                darkOk && lightOk, $"dark={darkOk} light={lightOk}");
        }

        // Streaming thousands of unique row strings must NOT accrete in the interner: scrolled-out text releases its
        // ref, the map entry drops immediately, and the slot clears behind the reader quarantine (StringTable.Tick).
        int mapBase = strings.MapCount;
        for (int s = 0; s < 40; s++) { window.QueueInput(new InputEvent(InputKind.Wheel, ptr, 0, 0, 5_000f)); host.RunFrame(); }
        for (int s = 0; s < 25; s++) { window.QueueInput(new InputEvent(InputKind.Wheel, ptr, 0, 0, s % 2 == 0 ? 1f : -1f)); host.RunFrame(); }   // settle past the quarantine (painted frames tick the table)
        int mapAfter = strings.MapCount;
        host.Scene.TryGetScroll(vp, out var scStream);
        bool streamed = scStream.FirstRealized > 3000;
        bool reclaimed = mapAfter - mapBase < 200 && strings.PendingReclaim < 200;
        Check("40c. scrolled-out row text is reclaimed by the interner (no per-row string accretion)",
            streamed && reclaimed, $"first={scStream.FirstRealized} map {mapBase}→{mapAfter} pending={strings.PendingReclaim}");

        // BOUND list (Virtual.ListBound): the template runs once per visible slot; a far jump rebinds index SIGNALS
        // only — same nodes, same elements, zero template re-runs, text/fill rebound in the same frame.
        var bound = new BoundVirtualProbe();
        using var app3 = new HeadlessPlatformApp();
        var window3 = new HeadlessWindow(new WindowDesc("virt-bound", new Size2(640, 480), 1f));
        window3.Show();
        using var host3 = new AppHost(app3, window3, new HeadlessGpuDevice(), fonts, strings, bound);
        host3.RunFrame();
        var vp3 = host3.Scene.Root;
        host3.Scene.TryGetScroll(vp3, out var bsc0);
        var content3 = bsc0.ContentNode;

        // First jump to mid-list (the window stabilizes at full size: overscan extends both directions), THEN measure.
        window3.QueueInput(new InputEvent(InputKind.Wheel, new Point2(150, 200), 0, 0, 100_000f));
        host3.RunFrame();
        int slots0 = host3.Scene.ChildCount(content3);
        int templateCalls0 = bound.TemplateCalls;
        var slotNodes = new HashSet<NodeHandle>();
        for (var c = host3.Scene.FirstChild(content3); !c.IsNull; c = host3.Scene.NextSibling(c)) slotNodes.Add(c);

        window3.QueueInput(new InputEvent(InputKind.Wheel, new Point2(150, 200), 0, 0, 100_000f));   // far jump: zero overlap
        host3.RunFrame();
        host3.Scene.TryGetScroll(vp3, out var bsc1);
        int slots1 = host3.Scene.ChildCount(content3);
        bool sameNodes = true;
        for (var c = host3.Scene.FirstChild(content3); !c.IsNull; c = host3.Scene.NextSibling(c)) sameNodes &= slotNodes.Contains(c);
        var boundFirstText = strings.Resolve(host3.Scene.Paint(host3.Scene.FirstChild(host3.Scene.FirstChild(content3))).Text);
        bool boundOk = bsc1.FirstRealized > 4000 && bound.TemplateCalls == templateCalls0 && slots1 == slots0
            && sameNodes && boundFirstText == $"row {bsc1.FirstRealized}";
        Check("40d. bound list rebinds via index signals on a far jump (no template re-run, no node churn)",
            boundOk, $"first={bsc1.FirstRealized} template {templateCalls0}→{bound.TemplateCalls} slots {slots0}→{slots1} sameNodes={sameNodes} text='{boundFirstText}'");

        // Scrollbar THUMB DRAG on a bound list (the 100k storm path): grab the thumb, drag in small steps — the
        // offset must track the thumb the whole way (the drag must never silently disengage mid-travel).
        window3.QueueInput(new InputEvent(InputKind.Wheel, new Point2(150, 200), 0, 0, -10_000_000f));   // back to the top
        host3.RunFrame();
        float laneX = 294f;
        window3.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(laneX, 10f), 0, 0));
        host3.RunFrame();
        window3.QueueInput(new InputEvent(InputKind.PointerDown, new Point2(laneX, 10f), 0, 0));
        host3.RunFrame();
        float lastOff = 0f;
        int advanceSteps = 0;
        const int dragSteps = 120;
        for (int s = 1; s <= dragSteps; s++)
        {
            window3.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(laneX, 10f + s * 2.5f), 0, 0));
            host3.RunFrame();
            host3.Scene.TryGetScroll(vp3, out var dsc);
            if (dsc.OffsetY > lastOff) advanceSteps++;
            lastOff = dsc.OffsetY;
        }
        window3.QueueInput(new InputEvent(InputKind.PointerUp, new Point2(laneX, 10f + dragSteps * 2.5f), 0, 0));
        host3.RunFrame();
        host3.Scene.TryGetScroll(vp3, out var dragEnd);
        bool dragOk = advanceSteps >= dragSteps - 5 && dragEnd.OffsetY > 100_000f && dragEnd.FirstRealized > 2000;
        Check("40e. scrollbar thumb drag tracks the full travel on a bound list (never disengages)",
            dragOk, $"advanced {advanceSteps}/{dragSteps} off={dragEnd.OffsetY:0} first={dragEnd.FirstRealized}");
    }

    // The Fenwick extent table: O(log n) prefix-sum (OffsetOf) + binary-lift (IndexAt) + O(log n) correction.
    static void ExtentTableChecks()
    {
        var t = new ExtentTable(5, 10f);   // 5 items × 10 = 50
        bool init = Near((float)t.Total, 50) && Near(t.OffsetOf(0), 0) && Near(t.OffsetOf(2), 20) && Near(t.OffsetOf(5), 50);
        bool indexAt = t.IndexAt(0) == 0 && t.IndexAt(15) == 1 && t.IndexAt(25) == 2 && t.IndexAt(49) == 4;
        t.SetExtent(2, 30f);   // correct item 2: 10 → 30 (total 50 → 70)
        bool corrected = Near((float)t.Total, 70) && Near(t.OffsetOf(3), 50) && t.IndexAt(45) == 2 && t.IndexAt(55) == 3;
        Check("41. extent table: O(log n) offset↔index + correction", init && indexAt && corrected, $"total={t.Total:0}");
    }

    // Variable-height virtualization: rows are positioned by their measured extents (the corrected Fenwick table),
    // and a scroll anchors on the visible item (the offset stays inside the anchor item's band; clamped to content).
    static void VariableChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("var", new Size2(640, 480), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new VarProbe());

        host.RunFrame();
        var vp = host.Scene.Root;
        host.Scene.TryGetScroll(vp, out var sc);
        var content = sc.ContentNode;

        // rows positioned by cumulative measured heights (OffsetOf), and the extent table corrected for the window
        var r0 = Child(host.Scene, content, 0);
        var r1 = Child(host.Scene, content, 1);
        var r2 = Child(host.Scene, content, 2);
        var r3 = Child(host.Scene, content, 3);
        bool positions = Near(host.Scene.Bounds(r0).Y, 0)
            && Near(host.Scene.Bounds(r1).Y, VarProbe.H(0))
            && Near(host.Scene.Bounds(r2).Y, VarProbe.H(0) + VarProbe.H(1))
            && Near(host.Scene.Bounds(r3).Y, VarProbe.H(0) + VarProbe.H(1) + VarProbe.H(2));
        host.Scene.TryGetExtents(vp, out var table);
        bool measured = table is not null && Near(table.ExtentAt(0), VarProbe.H(0)) && Near(table.ExtentAt(2), VarProbe.H(2));
        Check("42. variable rows positioned by measured extents", positions && measured, $"y0..3={host.Scene.Bounds(r0).Y:0},{host.Scene.Bounds(r1).Y:0},{host.Scene.Bounds(r2).Y:0},{host.Scene.Bounds(r3).Y:0}");

        // scroll into the middle → anchor tracks the visible item; offset stays in its band and clamped to content
        for (int s = 0; s < 6; s++) { window.QueueInput(new InputEvent(InputKind.Wheel, new Point2(150, 150), 0, 0, 350f)); host.RunFrame(); }
        host.Scene.TryGetScroll(vp, out var sc2);
        host.Scene.TryGetExtents(vp, out var t2);
        int anchor = t2!.IndexAt(sc2.OffsetY);
        float band0 = t2.OffsetOf(anchor), band1 = t2.OffsetOf(anchor + 1);
        bool anchored = sc2.AnchorIndex == anchor
            && sc2.OffsetY >= band0 - 0.5f && sc2.OffsetY < band1 + 0.5f
            && sc2.OffsetY <= sc2.ContentH - sc2.ViewportH + 1f && sc2.FirstRealized > 0;
        Check("43. variable scroll anchors on the visible item (in-band, clamped)", anchored, $"anchor={anchor} off={sc2.OffsetY:0} content={sc2.ContentH:0} first={sc2.FirstRealized}");
    }

    static void CollectScrollNodes(SceneStore s, NodeHandle n, List<NodeHandle> into)
    {
        if (n.IsNull) return;
        if (s.HasScroll(n)) into.Add(n);
        for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c)) CollectScrollNodes(s, c, into);
    }

    // Wave 4 (scroll-perf remediation) — E5 velocity overscan, E4 steady-scroll realize budget + nested-rail mount
    // deferral, E6 scene-owned virtual-dirty queue. The load-bearing safety invariant: the VISIBLE range (+1 guard
    // row/side) is realized on EVERY recorded frame, budget-exempt — the budget clips only the overscan halo, so it can
    // never reintroduce the scroll-flicker blank-row bug phase 7.6 exists to prevent.
    static void VirtualBudgetChecks(StringTable strings)
    {
        // A bound slot can lag the already-published ScrollState range (for example when two realize paths converge in
        // one frame). ReRealizeVirtuals must report the SIGNAL rebind as progress even though First/LastRealized stay
        // unchanged, otherwise AppHost skips its post-realize reactive flush and presents a mixed row: index-bound title
        // from item N over component-snapshot artist/art/duration from item N-1.
        {
            var scene = new SceneStore();
            var runtime = new ReactiveRuntime();
            var rows = new List<StableRangeBoundRow>();
            var recon = new TreeReconciler(scene, strings, runtime);
            var tree = Virtual.ListBound(100, 40f, index =>
            {
                var row = new StableRangeBoundRow(index);
                rows.Add(row);
                return Embed.Comp(() => row);
            }) with { Width = 300f, Height = 400f };

            recon.ReconcileRoot(tree, null);
            while (recon.ReRealizeVirtuals()) runtime.Flush();
            runtime.Flush();

            // Put only the slot signals one index ahead while leaving ScrollState's published range untouched, then
            // flush that setup so every component truthfully snapshots the lagging index.
            for (int i = 0; i < rows.Count; i++)
                ((Signal<int>)rows[i].Index).Value++;
            runtime.Flush();

            scene.Mark(scene.Root, NodeFlags.VirtualRangeDirty);
            bool reboundProgress = recon.ReRealizeVirtuals();
            if (reboundProgress && runtime.HasPending) runtime.Flush();   // the exact AppHost contract
            int mismatches = 0;
            for (int i = 0; i < rows.Count; i++)
                if (rows[i].LastRendered != rows[i].Index.Peek()) mismatches++;

            Check("gate.virt.stableRangeBoundRebindFlush a bound-slot signal rebind reports realize progress even when the published range is unchanged, so component snapshots flush in the same frame",
                reboundProgress && !runtime.HasPending && mismatches == 0,
                $"progress={reboundProgress} pending={runtime.HasPending} mismatches={mismatches}/{rows.Count}");
        }

        // A stateful/custom layout can briefly return its cached OLD upper window bound after the collection shrinks.
        // These are the exact old-to-new count pairs recorded in the two Wavee crash dumps.
        {
            (int Before, int After)[] transitions = [(60, 43), (521, 208)];
            int bounded = 0;
            string failure = "none";
            foreach (var (before, after) in transitions)
            {
                var probe = new VirtualCountShrinkProbe(before);
                try
                {
                    using var app = new HeadlessPlatformApp();
                    var window = new HeadlessWindow(new WindowDesc("virt-count-shrink", new Size2(640, 480), 1f)); window.Show();
                    using var host = new AppHost(app, window, new HeadlessGpuDevice(), new HeadlessFontSystem(strings), strings, probe);
                    host.RunFrame();
                    probe.Count.Value = after;
                    host.RunFrame();
                    host.Scene.TryGetScroll(host.Scene.Root, out var sc);
                    if (sc.ItemCount == after && sc.FirstRealized >= 0 && sc.LastRealized <= after
                        && sc.LastRealized >= sc.FirstRealized && probe.MaxRenderedIndex < after)
                        bounded++;
                    else
                        failure = $"{before}->{after}: count={sc.ItemCount} realized=[{sc.FirstRealized},{sc.LastRealized}) maxRendered={probe.MaxRenderedIndex}";
                }
                catch (Exception ex)
                {
                    failure = $"{before}->{after}: {ex.GetType().Name}: {ex.Message}";
                }
            }
            Check("gate.virt.countShrinkClampsStaleLayout stale layout windows are clamped to the current ItemCount before budget clipping for the crash transitions 60->43 and 521->208",
                bounded == transitions.Length, $"bounded={bounded}/{transitions.Length} failure={failure}");
        }
        // ── gate.virt.velocityOverscanDirectional — the halo skews ahead of the scroll direction; NeedsRealize fires
        // before the visible edge exits the realized window at speed (it would not at rest). ────────────────────────────
        {
            VirtualWindowing.DirectionalOverscan(4, +3000f, 40f, out int loF, out int hiF);   // forward ⇒ ahead = high edge (7), behind (1)
            VirtualWindowing.DirectionalOverscan(4, -3000f, 40f, out int loB, out int hiB);   // backward ⇒ ahead = low edge
            VirtualWindowing.DirectionalOverscan(4, 0.4f, 40f, out int loR, out int hiR);      // below threshold ⇒ symmetric
            bool skewFwd = hiF > loF && hiF > 4 && (loF + hiF) == 8;   // ahead buffered, behind trimmed, SUM constant (0-alloc invariant)
            bool skewBack = loB > hiB && loB > 4 && (loB + hiB) == 8;  // mirror in the other direction, same fixed sum
            bool symAtRest = loR == 4 && hiR == 4;                     // no fling ⇒ pre-E5 symmetric window (existing gates unchanged)

            var sc = ScrollState.Default;
            sc.ItemCount = 1000; sc.Overscan = 4; sc.Orientation = 0; sc.ContentH = 40000f;   // avgExtent = 40
            sc.FirstRealized = 100; sc.LastRealized = 120;                                     // visible band [104,118] — 2 rows inside the leading edge
            sc.FlingVelocity = 0f;
            bool restNoRealize = !VirtualWindowing.NeedsRealize(in sc, 104, 118);              // rest guard 2 ⇒ distance 2 does NOT fire
            sc.FlingVelocity = 3000f;                                                          // ahead skewed to 7 ⇒ guard 3 ⇒ 118 > 120−3 ⇒ fires early
            bool flingRealize = VirtualWindowing.NeedsRealize(in sc, 104, 118);

            Check("gate.virt.velocityOverscanDirectional the realize halo skews ahead of the fling (fixed-sum: ahead grows, behind shrinks, total constant), collapses to symmetric at rest, and NeedsRealize fires earlier on the scroll-direction edge at speed",
                skewFwd && skewBack && symAtRest && restNoRealize && flingRealize,
                $"fwd(lo={loF},hi={hiF}) back(lo={loB},hi={hiB}) rest(lo={loR},hi={hiR}) restNoRealize={restNoRealize} flingRealize={flingRealize}");
        }

        // ── gate.virt.budgetNeverBlanksVisible — a fast fling advancing several windows/frame with a TINY budget still
        // realizes the full visible band [visibleFirst,visibleLast] on EVERY frame (the anti-flicker invariant). ────────
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("virt-budget-blank", new Size2(640, 480), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), new HeadlessFontSystem(strings), strings, new VirtualProbe());
            host.SmoothScroll = true;
            host.Reconciler.SteadyRealizeBudgetForTest = 2;   // 2 rows/frame ≪ the per-frame fling travel
            host.RunFrame();
            var vp = host.Scene.Root; host.Scene.TryGetScroll(vp, out var sc0); var content = sc0.ContentNode;
            var ptr = new Point2(150, 200);
            int blanks = 0, frames = 0;
            for (int sflk = 0; sflk < 80; sflk++)
            {
                window.QueueInput(new InputEvent(InputKind.Wheel, ptr, 0, 0, 6000f));
                host.RunFrame();
                host.Scene.TryGetScroll(vp, out var sc);
                float drawn = -host.Scene.Paint(content).LocalTransform.Dy;
                int vFirst = (int)MathF.Floor(drawn / 40f);
                int vLast = Math.Min(VirtualProbe.N, (int)MathF.Ceiling((drawn + sc.ViewportH) / 40f));
                if (!(sc.FirstRealized <= vFirst && sc.LastRealized >= vLast)) blanks++;
                frames++;
            }
            Check("gate.virt.budgetNeverBlanksVisible a fling with a 2-row budget realizes the visible band (FirstRealized ≤ visibleFirst ∧ LastRealized ≥ visibleLast) on every recorded frame — the budget never blanks a visible row",
                blanks == 0, $"blanks={blanks}/{frames}");
        }

        // ── gate.virt.budgetSpreadsOverscan — steady scroll with budget < overscan: the overscan halo completes across
        // ≥2 subsequent frames, VirtualRangeDirty persists then clears, and the host stays awake until caught up. ────────
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("virt-budget-spread", new Size2(640, 480), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), new HeadlessFontSystem(strings), strings, new VirtualProbe());
            host.RunFrame();
            for (int i = 0; i < 6 && host.HasActiveWork; i++) host.RunFrame();   // settle the mount-deferred overscan at full budget
            var vp = host.Scene.Root;
            host.Reconciler.SteadyRealizeBudgetForTest = 1;                       // throttle: 1 overscan row/frame
            var ptr = new Point2(150, 200);
            window.QueueInput(new InputEvent(InputKind.Wheel, ptr, 0, 0, 400f));  // cross a 10-row boundary

            int dirtyFrames = 0, growthFrames = 0, prevWidth = -1, finalWidth = 0;
            bool everAwakeWhileDirty = false, invariantHeld = true;
            for (int f = 0; f < 25; f++)
            {
                host.RunFrame();
                host.Scene.TryGetScroll(vp, out var sc);
                bool dirty = (host.Scene.Flags(vp) & NodeFlags.VirtualRangeDirty) != 0;
                int width = sc.LastRealized - sc.FirstRealized;
                int vFirst = (int)MathF.Floor(sc.OffsetY / 40f);
                if (!(sc.FirstRealized <= vFirst)) invariantHeld = false;
                if (dirty) { dirtyFrames++; if (host.Reconciler.HasBudgetDeferredVirtuals && host.HasActiveWork) everAwakeWhileDirty = true; }
                if (prevWidth >= 0 && width > prevWidth) growthFrames++;
                prevWidth = width; finalWidth = width;
            }
            bool finalClean = (host.Scene.Flags(vp) & NodeFlags.VirtualRangeDirty) == 0;
            bool spread = dirtyFrames >= 2 && growthFrames >= 2 && everAwakeWhileDirty && finalClean && finalWidth >= 16 && invariantHeld;
            Check("gate.virt.budgetSpreadsOverscan a budget<overscan steady scroll fills the overscan halo across ≥2 frames (VirtualRangeDirty persists, host awake via HasBudgetDeferredVirtuals) then clears; the visible band stays covered throughout",
                spread, $"dirtyFrames={dirtyFrames} growthFrames={growthFrames} awake={everAwakeWhileDirty} finalClean={finalClean} finalWidth={finalWidth} invariant={invariantHeld}");
        }

        // ── gate.virt.nestedRailDefersInner — mounting a virtual rail realizes the visible cards only; the overscan
        // halo fills over subsequent frames (the nested-rail-into-view spike flattener). ─────────────────────────────────
        {
            var probe = new NestedRailProbe();
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("virt-nested-rail", new Size2(400, 200), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), new HeadlessFontSystem(strings), strings, probe);
            host.Reconciler.SteadyRealizeBudgetForTest = 2;   // throttle so the mount deferral is observable
            host.RunFrame();
            probe.Show.Value = true;
            host.RunFrame();   // mount frame
            var rail = FindScrollNode(host.Scene, host.Scene.Root);
            host.Scene.TryGetScroll(rail, out var scMount);
            int mountWidth = scMount.LastRealized - scMount.FirstRealized;

            int settleFrames = 0;
            for (; settleFrames < 30 && host.HasActiveWork; settleFrames++) host.RunFrame();
            host.Scene.TryGetScroll(rail, out var scFull);
            int fullWidth = scFull.LastRealized - scFull.FirstRealized;
            // Visible = 300/60 = 5 cards; at offset 0 the behind overscan clamps, so the settled window is visible + the
            // ahead overscan (≈ 11). The mount frame realizes only ≈ visible+guard+one budget slice — strictly narrower.
            bool defers = !rail.IsNull && mountWidth < fullWidth && (fullWidth - mountWidth) >= 2 && mountWidth <= 10 && settleFrames >= 1;
            Check("gate.virt.nestedRailDefersInner a freshly-mounted virtual rail realizes the visible cards only (overscan 0 at mount), then fills its overscan window over a few frames via the row budget",
                defers, $"mountWidth={mountWidth} fullWidth={fullWidth} settleFrames={settleFrames} rail={(rail.IsNull ? "null" : "ok")}");
        }

        // ── gate.virt.dirtyQueueMatchesScan — marking 2 of 5 virtual lists dirty realizes exactly those two; the steady
        // path iterates the scene-owned queue (scan == dirty count), never the _virtuals dictionary (which has 5). ───────
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("virt-dirty-queue", new Size2(360, 680), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), new HeadlessFontSystem(strings), strings, new MultiVirtualProbe());
            host.RunFrame();
            // Drain the mount-deferred overscan on all five until a frame does NO realize work (queue empty) — so the marks
            // below are the only dirty entries and the flags aren't already set.
            int drained = 0;
            for (int i = 0; i < 25; i++) { host.RunFrame(); if (host.Reconciler.LastReRealizeScan == 0) { drained = i; break; } }
            var vps = new List<NodeHandle>();
            CollectScrollNodes(host.Scene, host.Scene.Root, vps);
            bool five = vps.Count == MultiVirtualProbe.Lists;

            int scan = -1, realized = -1;
            bool firstRealizedUnchanged = true;
            if (five)
            {
                // Capture the untouched lists' realized windows, then mark exactly two dirty and run the reconciler's
                // realize pass directly (bump FrameEpoch for a clean per-frame accumulator read). Only the two marked
                // viewports are queued ⇒ scan == 2 (the scene-owned queue), never the 5-entry _virtuals dictionary.
                var before = new int[5];
                for (int k = 0; k < 5; k++) { host.Scene.TryGetScroll(vps[k], out var s); before[k] = s.FirstRealized * 1000 + s.LastRealized; }
                host.Scene.Mark(vps[1], NodeFlags.VirtualRangeDirty);
                host.Scene.Mark(vps[3], NodeFlags.VirtualRangeDirty);
                host.Reconciler.FrameEpoch++;                 // reset the scan accumulator for this direct pass
                host.Reconciler.ReRealizeVirtuals();
                scan = host.Reconciler.LastReRealizeScan;
                realized = host.Reconciler.LastReRealizeRealized;
                // The three UNMARKED lists must be untouched (proves the realize was scoped to the dirty queue, not a
                // dictionary-wide re-realize). The two marked lists legitimately re-realize.
                for (int k = 0; k < 5; k++) { if (k == 1 || k == 3) continue; host.Scene.TryGetScroll(vps[k], out var s); if (before[k] != s.FirstRealized * 1000 + s.LastRealized) firstRealizedUnchanged = false; }
            }
            bool onlyTwo = scan == 2 && realized == 2;
            Check("gate.virt.dirtyQueueMatchesScan marking 2 of 5 virtual lists VirtualRangeDirty realizes exactly those two; ReRealizeVirtuals iterates the scene-owned dirty queue (== 2), never the 5-entry _virtuals dictionary",
                five && onlyTwo && firstRealizedUnchanged, $"lists={vps.Count} scan={scan} realized={realized} windowsStable={firstRealizedUnchanged} drainedAt={drained}");
        }
    }

    // The central virtualization claim: an in-window (sub-extent) scroll is a transform-only frame with ZERO managed
    // allocation on the paint half (no realize, no reconcile, no relayout — just re-record the shifted window).
    static void ZeroAllocScrollChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("zalloc", new Size2(640, 480), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new VirtualProbe());

        host.RunFrame();   // mount
        var ptr = new Point2(150, 200);
        // warm: several sub-extent (5px) scrolls — all stay within item 0 (5×5 = 25 < 40px row) → transform-only
        for (int i = 0; i < 5; i++) { window.QueueInput(new InputEvent(InputKind.Wheel, ptr, 0, 0, 2f)); host.RunFrame(); }
        window.QueueInput(new InputEvent(InputKind.Wheel, ptr, 0, 0, 2f));
        var fz = host.RunFrame();
        bool zero = !fz.Rendered && fz.HotPhaseAllocBytes == 0;
        Check("44. in-window scroll: 0 managed alloc on the paint half", zero, $"{fz.HotPhaseAllocBytes} bytes, rendered={fz.Rendered}");
    }

    // ── Touch substrate exit-criteria (Phase 1): flick-scroll inertia, the coalescing slab, tap-vs-pan, per-id capture,
    // per-id cancel, and no resting touch hover — all over the headless touch harness (monotonic event stamps + fixed
    // animation clock). The single-recognizer pan/tap + fling integrator are exercised end-to-end through AppHost.
    static void TouchGestureChecks(StringTable strings)
    {
        var fonts = new HeadlessFontSystem(strings);

        // gate.touch.flick-decay-settle: a touch flick UP over a bound virtual list seeds a friction-decay fling that
        // moves the offset monotonically for many frames, re-realizes the virtual window (FirstRealized advances), then
        // settles at a BOUNDED natural rest — coast ≈ v0/k under WinUI-like friction (FlingDecayPerS=0.05,
        // k≈3.0/s), so it stops SHORT of the far 2800px content-end clamp (NOT a floaty drift to the end),
        // and within a bounded number of frames.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("touch-fling", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
            host.RunFrame();
            var vp = host.Scene.Root;

            // Flick the finger up the viewport (offset increases as the content follows the finger upward). Start inside
            // the 400px-tall viewport (y < 400) so the touch-down lands ON the scroller, not on its bottom edge.
            TouchGesture(window, host, new Point2(150, 384), new Point2(150, 44), 16, pointerId: 7, msPerStep: 16f);
            host.Scene.TryGetScroll(vp, out var afterUp);
            float prevOff = afterUp.OffsetY;
            int firstAfterUp = afterUp.FirstRealized;

            int monotonicRun = 0, maxRun = 0, settledAt = -1;
            int firstRealizedSettled = firstAfterUp;
            bool decayRendered = false;
            for (int i = 0; i < 600 && settledAt < 0; i++)
            {
                var f = host.RunFrame();
                host.Scene.TryGetScroll(vp, out var sc);
                if (sc.OffsetY > prevOff + 0.01f) { monotonicRun++; if (monotonicRun > maxRun) maxRun = monotonicRun; if (f.Rendered) decayRendered = true; }
                else if (sc.Phase == 0) { settledAt = i; firstRealizedSettled = sc.FirstRealized; }
                else monotonicRun = 0;   // a non-advancing frame mid-fling (should not happen) breaks the run
                prevOff = sc.OffsetY;
            }
            host.Scene.TryGetScroll(vp, out var settled);
            float maxOff = MathF.Max(0f, settled.ContentH - settled.ViewportH);
            bool reRealized = settled.FirstRealized != firstAfterUp && decayRendered;
            // Windows-like friction: the fling coasts a BOUNDED distance forward and settles SHORT of the far clamp.
            bool coastedForward = settled.OffsetY > afterUp.OffsetY + 20f;
            bool boundedShortOfClamp = settled.OffsetY < maxOff - 100f;
            bool settledFast = settledAt >= 0 && settledAt < 160;   // comfortably below 2.7s at the fixed 60Hz clock
            Check("gate.touch.flick-decay-settle a touch flick decays monotonically (≥10 frames), re-realizes the window, then settles at a BOUNDED rest SHORT of the far clamp (WinUI-like friction, not a near-frictionless coast to the end)",
                maxRun >= 10 && settledFast && reRealized && coastedForward && boundedShortOfClamp,
                $"maxRun={maxRun} settledAt={settledAt} offset={afterUp.OffsetY:0}->{settled.OffsetY:0} (clamp={maxOff:0}) reRealized={reRealized}");
        }

        // gate.scroll.impulse-velocity (scroll-feel rework Phase 1, design §2): the IMPULSE (work-energy) release
        // estimator. (a) CONSTANT-velocity drag → the seeded fling speed equals the hand speed exactly (W = ½v² →
        // √(2W) = v). (b) An ACCELERATING drag queued TWO moves per frame — the ring coalesces each pair and deposits
        // the overwritten move into the velocity side ring — must match an independent in-gate replica of the IMPULSE
        // math over the full scripted sample stream: proves per-packet (pre-coalesce) fidelity survives frame
        // coalescing. (c) A drag that PAUSES ≥ AssumeStoppedMs before the lift seeds NO fling (Android
        // ASSUME_POINTER_STOPPED_TIME): the finger stopped before lifting.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("impulse-vel", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
            host.RunFrame();
            var vp = host.Scene.Root;

            // (a) constant velocity: 10 moves × 32 px @ 16 ms = 2000 px/s finger speed, up 16 ms after the last move.
            TouchGesture(window, host, new Point2(150, 384), new Point2(150, 64), 10, pointerId: 11, msPerStep: 16f);
            host.Scene.TryGetScroll(vp, out var scA);
            // The up frame's phase-7 tick already decayed the fresh seed once (16 ms of FlingDecayPerS) — fold that
            // into the expectation so the gate asserts the ESTIMATOR exactly, not the estimator minus one tick.
            float decay1 = MathF.Exp(MathF.Log(ScrollIntegrator.FlingDecayPerS) * 16f / 1000f);
            float vConst = MathF.Abs(scA.FlingVelocity);
            bool constExact = MathF.Abs(vConst - 2000f * decay1) <= 2000f * decay1 * 0.02f && scA.Phase == ScrollIntegrator.Fling;   // ±2%
            for (int i = 0; i < 400; i++) { host.RunFrame(); host.Scene.TryGetScroll(vp, out var s); if (s.Phase == 0) break; }

            // (b) accelerating, two moves per frame (8 ms stamps): quadratic profile y(t) sampled every 8 ms. The gate
            // replicates the estimator (cap-8 ring, 66 ms horizon, newest-pre-window baseline, ½ first term, √(2W)).
            uint t0 = s_touchClockMs; float y0 = 384f;
            Span<(uint T, float Y)> samples = stackalloc (uint, float)[17];
            samples[0] = (t0, y0);                                       // the down seeds the ring
            for (int i = 1; i <= 16; i++)
            {
                float tt = i / 16f;                                       // quadratic: slow start, fast finish
                samples[i] = ((uint)(t0 + i * 8), y0 - 320f * tt * tt);
            }
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(150, samples[0].Y), samples[0].T, 12));
            host.RunFrame();
            for (int i = 1; i <= 16; i += 2)
            {
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(150, samples[i].Y), samples[i].T, 12));
                if (i + 1 <= 16) window.QueueInput(Touch(InputKind.PointerMove, new Point2(150, samples[i + 1].Y), samples[i + 1].T, 12));
                host.RunFrame();                                          // the pair coalesces; the first feeds the side ring
            }
            uint tUp = (uint)(t0 + 16 * 8 + 8);
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(150, samples[16].Y), tUp, 12));
            host.RunFrame();
            s_touchClockMs = tUp + 1000;
            host.Scene.TryGetScroll(vp, out var scB);
            float vAccel = MathF.Abs(scB.FlingVelocity);

            // Independent replica of the estimator over the scripted stream (cap-8 ring → keep the NEWEST 8 samples).
            int keep = Math.Min(8, samples.Length);
            int start = samples.Length - keep;
            double w = 0.0, vprev = 0.0; bool firstSeg = true; int basei = -1;
            for (int i = start; i < samples.Length; i++)
            {
                if ((tUp - samples[i].T) > 40) { basei = i; continue; }   // pre-window → baseline (v2 §4.3: single 40ms IMPULSE window)
                if (basei < 0) { basei = i; continue; }                    // first in-window sample baselines
                double dt = (samples[i].T - samples[basei].T) / 1000.0;
                if (dt <= 0) { basei = i; continue; }
                double v = (samples[i].Y - samples[basei].Y) / dt;
                if (firstSeg) { w += 0.5 * v * Math.Abs(v); firstSeg = false; }
                else w += (v - vprev) * Math.Abs(v);
                vprev = v; basei = i;
            }
            float vExpected = (float)Math.Abs(Math.Sign(w) * Math.Sqrt(2.0 * Math.Abs(w))) * decay1;   // − one up-frame tick
            bool conforms = vExpected > 100f && MathF.Abs(vAccel - vExpected) <= MathF.Max(1f, vExpected * 0.02f);
            for (int i = 0; i < 400; i++) { host.RunFrame(); host.Scene.TryGetScroll(vp, out var s); if (s.Phase == 0) break; }

            // (c) pause-before-lift: a real drag, then the finger rests 60 ms (> AssumeStoppedMs=40), then lifts → no fling.
            uint t2 = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(150, 384), t2, 13)); host.RunFrame();
            for (int i = 1; i <= 8; i++)
            {
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(150, 384 - i * 24), t2 + (uint)(i * 16), 13));
                host.RunFrame();
            }
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(150, 384 - 8 * 24), t2 + 8 * 16 + 60, 13));   // 60 ms rest
            host.RunFrame();
            s_touchClockMs = t2 + 8 * 16 + 60 + 1000;
            host.Scene.TryGetScroll(vp, out var scC);
            bool stoppedNoFling = scC.Phase != ScrollIntegrator.Fling || MathF.Abs(scC.FlingVelocity) < 1f;

            Check("gate.scroll.impulse-velocity the IMPULSE release estimator: constant-velocity drag reads the exact hand speed; an accelerating TWO-MOVES-PER-FRAME stream (ring-coalesced, side-ring fed) matches the independent work-energy replica; a ≥40ms pause before lift seeds NO fling",
                constExact && conforms && stoppedNoFling,
                $"const={vConst:0} (expect 2000±2%) accel={vAccel:0} vs replica={vExpected:0} pauseFling={(scC.Phase == ScrollIntegrator.Fling ? scC.FlingVelocity : 0f):0.0}");
        }

        // gate.scroll.mouse-wheel-eases-discrete: a synthetic PointerKind.Mouse stream remains on ONE eased TargetChase
        // path regardless of delta magnitude. Precision touchpad selection is device-tag based (never magnitude based)
        // and is covered separately by ScrollParityChecks. A mixed mouse stream must advance monotonically toward the
        // summed target, never enter Fling mode, and converge without a post-target coast.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("wheel-eases", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
            host.RunFrame();
            var vp = host.Scene.Root;

            // Mixed synthetic mouse deltas straddling the old magnitude threshold: device type keeps all on one path.
            float[] mixed = { 20f, 60f, 30f, 90f, 15f, 70f, 40f, 25f, 50f, 35f };   // sum = 435
            uint t = 1000; bool everFlung = false; float prev = 0f; bool monotonic = true;
            foreach (float d in mixed)
            {
                window.QueueInput(new InputEvent(InputKind.Wheel, new Point2(150, 200), 0, 0, ScrollDelta: d, TimestampMs: t));
                host.RunFrame();
                host.Scene.TryGetScroll(vp, out var s);
                if (s.Phase == ScrollIntegrator.Fling) everFlung = true;
                if (s.OffsetY + 0.01f < prev) monotonic = false;   // never jumps backward (no eased-vs-1:1 desync)
                prev = s.OffsetY; t += 16;
            }
            for (int i = 0; i < 60; i++) host.RunFrame();   // let the ease converge to the accumulated target
            host.Scene.TryGetScroll(vp, out var settled);
            float offSettled = settled.OffsetY;
            bool converged = offSettled >= 433f && offSettled <= 437f && settled.Phase == 0;
            // After the stream stops, no momentum/coast past the target.
            float coastMax = offSettled;
            for (int i = 0; i < 30; i++) { host.RunFrame(); host.Scene.TryGetScroll(vp, out var s); coastMax = MathF.Max(coastMax, s.OffsetY); }
            bool noMomentum = coastMax <= offSettled + 1f;
            Check("gate.scroll.mouse-wheel-eases-discrete a MIXED-magnitude PointerKind.Mouse stream eases monotonically via ONE TargetChase path to the summed target — no magnitude split, no post-target momentum",
                monotonic && !everFlung && converged && noMomentum,
                $"settled={offSettled:0} (expect 435) monotonic={monotonic} flung={everFlung} coastTo={coastMax:0} mode={settled.Phase}");
        }

        // gate.scroll.flick-into-edge-bounce: a genuine TOUCH flick whose fling REACHES a clamp converts the residual
        // velocity into a rubber-band bounce (WinUI/iOS) instead of stopping dead — the real trace showed a finger flick
        // hit off=0 and stopped flat ("no rubber band"). Reproduces it: scroll down a bit, then a short HARD finger flick
        // toward the top so the fling coasts into off=0 with residual speed → overscroll excursion (>1px) → springs to ~0.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("flick-bounce", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
            host.RunFrame();
            var vp = host.Scene.Root;
            // Move down to ~offset 384 via wheel, then let it settle (room above for the flick's fling to coast into off=0).
            uint t = 1000;
            for (int i = 0; i < 8; i++) { window.QueueInput(new InputEvent(InputKind.Wheel, new Point2(150, 200), 0, 0, ScrollDelta: 48f, TimestampMs: t)); host.RunFrame(); t += 16; }
            for (int i = 0; i < 60; i++) host.RunFrame();
            host.Scene.TryGetScroll(vp, out var atStart);
            float startOff = atStart.OffsetY;
            // Short HARD finger flick DOWN (finger y increases → content scrolls toward the TOP, offset → 0). 80px move
            // stays in-range (no overpan during the drag); fast (5ms/step) → high release velocity → the fling overshoots 0.
            TouchGesture(window, host, new Point2(150, 150), new Point2(150, 230), 4, pointerId: 11, msPerStep: 5f);
            float maxBand = 0f; int settledAt = -1; bool flung = false;
            for (int i = 0; i < 200 && settledAt < 0; i++)
            {
                host.RunFrame();
                host.Scene.TryGetScroll(vp, out var s);
                if (s.Phase == ScrollIntegrator.Fling) flung = true;
                maxBand = MathF.Max(maxBand, MathF.Abs(s.OverscrollPx));
                if (i > 4 && MathF.Abs(s.OverscrollPx) < 0.1f && s.OffsetY <= 0.5f) settledAt = i;
            }
            Check("gate.scroll.flick-into-edge-bounce a touch flick whose fling reaches the clamp bounces (overscroll excursion > 1px) then springs back to ~0 (not a dead stop)",
                flung && maxBand > 1f && settledAt >= 0, $"startOff={startOff:0} flung={flung} maxBand={maxBand:0.0} settledAt={settledAt}");

            // A low residual speed is still live inertia, so crossing the clamp must hand it to the elastic spring too.
            // This catches the old 50 px/s bounce gate, which made a 25 px/s edge arrival stop perfectly flat.
            window.QueueInput(new InputEvent(InputKind.Wheel, new Point2(150, 200), 0, 0, ScrollDelta: 2f, TimestampMs: t));
            for (int i = 0; i < 60; i++) host.RunFrame();
            ref var slow = ref host.Scene.ScrollRef(vp);
            // Put the viewport within one 60 Hz coast step of the leading clamp. The preceding wheel is only a
            // convenient way to leave the completed bounce path in a valid scroll state; its device-scale mapping is
            // deliberately not part of this physics gate.
            slow.OffsetY = 0.1f;
            slow.FlingVelocity = -25f;
            slow.Phase = ScrollIntegrator.Fling;
            slow.PhaseFlags = 0;
            slow.FlingRetargeted = false;
            slow.FlingSnapTarget = float.NaN;
            slow.FlingFromOffset = slow.OffsetY;
            host.ScrollIntegratorForTest.Arm(vp);
            float slowBand = 0f;
            for (int i = 0; i < 60; i++)
            {
                host.RunFrame();
                host.Scene.TryGetScroll(vp, out var s);
                slowBand = MathF.Max(slowBand, MathF.Abs(s.OverscrollPx));
            }
            Check("gate.scroll.slow-fling-into-edge-elastic a still-live 25 px/s fling crossing the clamp produces a subtle elastic handoff instead of stopping dead",
                slowBand > 0.01f, $"maxBand={slowBand:0.000}px bounceGate={ScrollIntegrator.FlingBounceMinPxPerS:0}px/s");
        }

        // gate.scroll.touch-overpan-bounce: the surviving rubber band lives on the genuine TOUCH path. A finger pan that
        // drags PAST the top edge (at offset 0) builds a damped overscroll EXCURSION (>1px) and, on release, the
        // critically-damped spring carries it back to ~0 (WinUI/iOS). The trackpad/wheel path has no band (a wheel message
        // carries no manipulation to rubber-band — it hard-clamps).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("overpan-bounce", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
            host.RunFrame();
            var vp = host.Scene.Root;
            // Drag the finger DOWN inside the viewport while already at the top (offset 0) → pulls past the top edge.
            TouchGesture(window, host, new Point2(150, 120), new Point2(150, 340), 12, pointerId: 9, msPerStep: 16f);
            host.Scene.TryGetScroll(vp, out var afterDrag);
            float maxBand = MathF.Abs(afterDrag.OverscrollPx);
            int settledAt = -1;
            for (int i = 0; i < 200 && settledAt < 0; i++)   // release → spring the band back to 0
            {
                host.RunFrame();
                host.Scene.TryGetScroll(vp, out var s);
                maxBand = MathF.Max(maxBand, MathF.Abs(s.OverscrollPx));
                if (i > 4 && MathF.Abs(s.OverscrollPx) < 0.1f) settledAt = i;
            }
            Check("gate.scroll.touch-overpan-bounce a touch pan past the edge builds a rubber-band excursion (>1px) then springs back to ~0",
                maxBand > 1f && settledAt >= 0, $"maxBand={maxBand:0.0} settledAt={settledAt}");
        }

        // gate.touch.fling-alloc-steady-zero: a 30-frame fling allocates 0 managed bytes on the hot half. A large list
        // keeps the fling in steady decay across the whole window (never clamps), so all 30 frames run the integrator +
        // re-realize path. The gate list binds ONLY a struct channel (Fill) per row — the fling integrator, the phase-7
        // SetScrollOffset write, the virtual re-realize, and the slot-rebind flush must contribute 0 managed bytes. (A list
        // whose rows ALSO bind unique `$"row {idx}"` text streams a never-before-seen string into StringTable.Intern on each
        // cross-boundary recycle — the corpus's bounded-Gen0 reconcile edge, shared identically by wheel; that residual is
        // gated separately below as the SAME value under wheel, not attributed to the touch path.) Warm one full flick first
        // (JIT the gesture/integrator/realize path) outside the measured window.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("touch-fling-alloc", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new BoundVirtualFillOnlyProbe());
            host.RunFrame();

            TouchFlick(window, host, new Point2(150, 384), new Point2(150, 44), 12, pointerId: 1, msPerStep: 16f, decayFrames: 12);   // warm
            for (int i = 0; i < 30; i++) host.RunFrame();   // drain any residual fling so the measured flick starts clean

            long worstDuringGesture = TouchGesture(window, host, new Point2(150, 384), new Point2(150, 44), 12, pointerId: 1, msPerStep: 16f);
            long worstDecay = 0;
            int flingFrames = 0;
            for (int i = 0; i < 30; i++)
            {
                var f = host.RunFrame();
                if (f.HotPhaseAllocBytes > worstDecay) worstDecay = f.HotPhaseAllocBytes;
                if ((host.CurrentWakeReasons & WakeReasons.ScrollAnim) != 0) flingFrames++;
            }
            Check("gate.touch.fling-alloc-steady-zero a 30-frame touch fling over a struct-only bound list allocates 0 managed bytes on the hot half (the integrator + virtual re-realize + slot-rebind stayed armed and clean the whole window)",
                worstDecay == 0 && flingFrames >= 25, $"worstDecayHotAlloc={worstDecay}B flingFrames={flingFrames}/30 worstGesture={worstDuringGesture}B");
        }

        // gate.touch.fling-realize-edge-is-wheel: a bound list whose rows ALSO bind unique per-row text (`$"row {idx}"`)
        // streams a fresh string into the interner on every cross-boundary recycle — a non-zero hot-half cost. This check
        // proves that residual is the PRE-EXISTING reconcile edge, NOT introduced by touch: a touch fling's worst decay-frame
        // alloc equals a NON-touch wheel scroll's worst alloc across the SAME 40px-row boundaries on the SAME list. (CLAUDE.md:
        // near-zero — bounded Gen0 at the render/reconcile edge.) The fling integrator itself adds nothing on top of the wheel.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("touch-fling-edge", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new BoundVirtualProbe());
            host.RunFrame();

            TouchFlick(window, host, new Point2(150, 384), new Point2(150, 44), 12, pointerId: 1, msPerStep: 16f, decayFrames: 12);   // warm
            for (int i = 0; i < 30; i++) host.RunFrame();   // drain any residual fling so the measured flick starts clean

            // The wheel baseline: a non-touch scroll across the same row boundaries on this text-binding list.
            long wheelCrossAlloc = 0;
            {
                var wptr = new Point2(150, 200);
                for (int i = 0; i < 6; i++) { window.QueueInput(new InputEvent(InputKind.Wheel, wptr, 0, 0, 400f)); host.RunFrame(); }   // warm
                for (int i = 0; i < 20; i++) { window.QueueInput(new InputEvent(InputKind.Wheel, wptr, 0, 0, 400f)); var wf = host.RunFrame(); if (wf.HotPhaseAllocBytes > wheelCrossAlloc) wheelCrossAlloc = wf.HotPhaseAllocBytes; }
                window.QueueInput(new InputEvent(InputKind.Wheel, wptr, 0, 0, -10_000_000f)); host.RunFrame();   // back to top
                for (int i = 0; i < 6; i++) host.RunFrame();
            }

            long worstDuringGesture = TouchGesture(window, host, new Point2(150, 384), new Point2(150, 44), 12, pointerId: 1, msPerStep: 16f);
            long worstDecay = 0;
            int flingFrames = 0;
            for (int i = 0; i < 30; i++)
            {
                var f = host.RunFrame();
                if (f.HotPhaseAllocBytes > worstDecay) worstDecay = f.HotPhaseAllocBytes;
                if ((host.CurrentWakeReasons & WakeReasons.ScrollAnim) != 0) flingFrames++;
            }
            // The fling's per-frame edge cost must not EXCEED the wheel's (touch adds nothing); both are the shared recycle
            // string churn. wheelCrossAlloc>0 confirms the edge is genuinely exercised (else the comparison would be vacuous).
            Check("gate.touch.fling-realize-edge-is-wheel a touch fling's per-frame realize-edge alloc over a unique-text bound list is the SAME pre-existing reconcile-edge churn a non-touch wheel scroll incurs across the same row boundaries (touch adds nothing)",
                wheelCrossAlloc > 0 && worstDecay <= wheelCrossAlloc && flingFrames >= 25,
                $"worstDecayHotAlloc={worstDecay}B wheel-cross-boundary baseline={wheelCrossAlloc}B (touch≤wheel ⇒ the residual is the shared bound-row RE-REALIZE string churn, not the fling integrator) flingFrames={flingFrames}/30 worstGesture={worstDuringGesture}B");
        }

        // gate.touch.coalesce-flood: 500 moves for ONE contact queued WITHOUT interleaving a frame must coalesce to
        // exactly one surviving move for that id (Down/Up never coalesce). Tested two ways: (A) the ring contract
        // directly (drain a Down + 500 Moves + Up → exactly 1 PointerMove survives), and (B) end-to-end — a 500-move
        // flood pumped in one frame allocates 0 managed bytes on the hot half and lands the pan at the FINAL move only.
        {
            // (A) ring contract: one surviving move per id, Down/Up preserved, slab never grew.
            var ring = new InputEventRing();
            ring.Clear();
            ring.Write(Touch(InputKind.PointerDown, new Point2(10, 400), 1000, 3));
            for (int i = 0; i < 500; i++) ring.Write(Touch(InputKind.PointerMove, new Point2(10, 400 - i), (uint)(1001 + i), 3));
            ring.Write(Touch(InputKind.PointerUp, new Point2(10, 0), 1502, 3));
            var span = ring.Drain();
            int moves = 0, downs = 0, ups = 0;
            Point2 lastMovePos = default;
            foreach (ref readonly var e in span)
            {
                if (e.Kind == InputKind.PointerMove) { moves++; lastMovePos = e.PositionPx; }
                else if (e.Kind == InputKind.PointerDown) downs++;
                else if (e.Kind == InputKind.PointerUp) ups++;
            }
            bool ringOk = moves == 1 && downs == 1 && ups == 1 && Near(lastMovePos.Y, 400 - 499);   // the surviving move is the LAST queued
            Check("gate.touch.coalesce-flood.ring 500 unconsumed moves for one contact coalesce to exactly 1 surviving move (Down/Up preserved, the survivor is the latest)",
                ringOk, $"moves={moves} downs={downs} ups={ups} survivorY={lastMovePos.Y:0} drained={span.Length}");

            // (B) end-to-end: pump a 500-move flood in ONE frame → the ring keeps 1 move → the pump/coalesce/dispatch path
            // allocates 0 managed bytes on the hot half and the pan lands at the FINAL move only. Kept SUB-BOUNDARY (30px,
            // from offset 0) so the flood frame stays transform-only — isolating the coalescing 0-alloc from the separate
            // cross-boundary re-realize cost (which gate.touch.fling-alloc-steady-zero surfaces).
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("touch-flood", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new BoundVirtualProbe());
            host.RunFrame();
            var vp = host.Scene.Root;
            // Warm the sub-boundary pan path with a few small in-window drags (claim + transform-only scroll), then settle
            // back to the top so the measured flood starts at offset 0 and its 30px stays within the realized window.
            for (int w = 0; w < 4; w++)
            {
                uint tw = s_touchClockMs;
                window.QueueInput(Touch(InputKind.PointerDown, new Point2(150, 200), tw, 5)); host.RunFrame();
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(150, 188), tw + 16, 5)); host.RunFrame();   // 12px: claims, sub-boundary
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(150, 200), tw + 32, 5)); host.RunFrame();   // back
                window.QueueInput(Touch(InputKind.PointerUp, new Point2(150, 200), tw + 48, 5)); host.RunFrame();
                s_touchClockMs = tw + 1000;
            }
            window.QueueInput(new InputEvent(InputKind.Wheel, new Point2(150, 200), 0, 0, -1_000_000f)); host.RunFrame();   // pin to the top
            for (int i = 0; i < 6; i++) host.RunFrame();
            host.Scene.TryGetScroll(vp, out var beforeFlood);
            float floodBaseOff = beforeFlood.OffsetY;

            uint t0 = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(150, 200), t0, 9));
            host.RunFrame();   // anchor the contact (the claim + scroll happens on the flood frame's single surviving move)
            for (int i = 0; i < 500; i++)   // 500 moves, NO interleaved frame → the ring coalesces to one before dispatch
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(150, 200 - (i + 1) * 0.06f), t0 + 1 + (uint)i, 9));   // total 30px (sub-boundary)
            var floodFrame = host.RunFrame();   // pumps all 500 → ring keeps 1 → dispatch sees Down(prev)+1 Move
            host.Scene.TryGetScroll(vp, out var afterFlood);
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(150, 200 - 500 * 0.06f), t0 + 502, 9));
            host.RunFrame();
            s_touchClockMs = t0 + 1000;

            // The pan landed at the FINAL move's delta only (one effective move): finger from y=200 to y=170 ⇒ +30px offset.
            float expectFloodOff = floodBaseOff + 30f;
            bool floodLanded = Near(afterFlood.OffsetY, expectFloodOff, 1.5f);
            Check("gate.touch.coalesce-flood.frame a 500-move single-frame flood allocates 0 managed bytes on the hot half and lands the pan at the final move only (one effective move)",
                floodFrame.HotPhaseAllocBytes == 0 && floodLanded,
                $"floodHotAlloc={floodFrame.HotPhaseAllocBytes}B off={afterFlood.OffsetY:0} expect={expectFloodOff:0}");
        }

        // gate.touch.tap-vs-pan: a below-slop touch down→up over a clickable row TAPS it (OnClick fires); a touch drag
        // over the same list claims the pan and NEVER clicks (the pressed candidate is cancelled — WinUI Pressed→Canceled,
        // never Released). Same probe, same row 0 — only the gesture differs.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("touch-tap", new Size2(360, 460), 1f)); window.Show();
            var probe = new TouchTapPanProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            var vp = host.Scene.Root;
            host.Scene.TryGetScroll(vp, out var tapSc0);
            var row0 = host.Scene.FirstChild(tapSc0.ContentNode);   // first realized row
            var rowCenter = CenterOf(host.Scene, row0);

            // TAP: down + up at the same point (no slop crossing) over row 0.
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, rowCenter, t, 2));
            host.RunFrame();
            bool listPressInitiallyDelayed = (host.Scene.Flags(row0) & NodeFlags.Pressed) == 0;
            for (int i = 0; i < 7; i++) host.RunFrame();
            bool listPressAppearedAfterDelay = (host.Scene.Flags(row0) & NodeFlags.Pressed) != 0;
            window.QueueInput(Touch(InputKind.PointerUp, rowCenter, t + 128, 2));
            host.RunFrame();
            s_touchClockMs = t + 1000;
            int clicksAfterTap = probe.Row0Clicked;
            int pressedAfterTap = probe.Row0Pressed;
            host.Scene.TryGetScroll(vp, out var afterTap);
            bool tapDidNotScroll = Near(afterTap.OffsetY, 0f);

            // TAP-TO-STOP: a contact landing while the viewport is coasting belongs to the viewport. It arrests the
            // inertia but must not enter the row's press/click pipeline when lifted without moving.
            ref var stopping = ref host.Scene.ScrollRef(vp);
            stopping.Phase = ScrollIntegrator.Fling;
            stopping.FlingVelocity = 900f;
            window.QueueInput(Touch(InputKind.PointerDown, rowCenter, t + 160, 2)); host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerUp, rowCenter, t + 176, 2)); host.RunFrame();
            bool stopTapSwallowed = probe.Row0Clicked == clicksAfterTap && probe.Row0Pressed == pressedAfterTap
                                    && host.Scene.ScrollRef(vp).Phase != ScrollIntegrator.Fling;

            window.QueueInput(Touch(InputKind.PointerDown, rowCenter, t + 240, 3)); host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerMove, new Point2(rowCenter.X, rowCenter.Y - 20f), t + 256, 3)); host.RunFrame();
            bool panBeforeDelayNeverPressed = (host.Scene.Flags(row0) & NodeFlags.Pressed) == 0;
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(rowCenter.X, rowCenter.Y - 20f), t + 272, 3)); host.RunFrame();

            // PAN: a drag starting on row 0 that crosses slop. The press is delivered on down then cancelled at the claim.
            TouchGesture(window, host, new Point2(rowCenter.X, rowCenter.Y), new Point2(rowCenter.X, rowCenter.Y - 180f), 12, pointerId: 2, msPerStep: 16f);
            int clicksAfterPan = probe.Row0Clicked;
            int pressedAfterPan = probe.Row0Pressed;
            host.Scene.TryGetScroll(vp, out var afterPan);
            bool panScrolled = afterPan.OffsetY > 100f;

            bool tapOk = clicksAfterTap == 1 && tapDidNotScroll;
            bool panOk = clicksAfterPan == clicksAfterTap && panScrolled;   // NO additional click from the pan
            Check("gate.touch.tap-vs-pan a below-slop touch tap fires OnClick; a touch pan over the same row scrolls and never clicks",
                tapOk && listPressInitiallyDelayed && listPressAppearedAfterDelay && panBeforeDelayNeverPressed && stopTapSwallowed && panOk,
                $"tapClicks={clicksAfterTap} delayed={listPressInitiallyDelayed}->{listPressAppearedAfterDelay} panNoFlash={panBeforeDelayNeverPressed} stopSwallowed={stopTapSwallowed} panClicks={clicksAfterPan} (scroll={afterPan.OffsetY:0}) pressedDelivered={pressedAfterPan}");

            // gate.touch.pan-cancels-press: the down chain SAW the press (OnPointerPressed fired on down) but the pan claim
            // delivered the cancel — so no click ever fired through the pan. (Pressed delivered ≥ 1, click count unchanged
            // by the pan: the press was Canceled, not Released.)
            bool pressDeliveredThenCancelled = pressedAfterPan >= 1 && clicksAfterPan == clicksAfterTap;
            Check("gate.touch.pan-cancels-press a claimed pan cancels the press it delivered to the down chain (press seen, no Released/click)",
                pressDeliveredThenCancelled, $"row0Pressed={pressedAfterPan} row0Clicked={clicksAfterPan} (tap baseline {clicksAfterTap})");

            // gate.touch.no-stuck-hover: after the tap AND the pan sequences, no node retains NodeFlags.Hovered (touch has
            // no resting hover — up/cancel clears the transient touch hover).
            var stuck = AnyHovered(host.Scene, host.Scene.Root);
            Check("gate.touch.no-stuck-hover no node retains hover after a touch tap + pan sequence (no resting touch hover)",
                stuck.IsNull, stuck.IsNull ? "none" : $"node {stuck.Raw.Index} still Hovered");
        }

        // gate.touch.two-contacts-independent: two concurrent touch contacts pan two sibling scrollers independently (the
        // per-PointerId capture map). Each frame advances BOTH ids over their own list; each viewport's offset tracks only
        // its own contact (a pan on the left never moves the right).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("touch-two", new Size2(440, 360), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TwoListProbe());
            host.RunFrame();
            var left = ViewportWithItemCount(host.Scene, host.Scene.Root, TwoListProbe.LeftN);
            var right = ViewportWithItemCount(host.Scene, host.Scene.Root, TwoListProbe.RightN);
            var lrect = host.Scene.AbsoluteRect(left);
            var rrect = host.Scene.AbsoluteRect(right);
            float lx = lrect.X + lrect.W / 2f, rx = rrect.X + rrect.W / 2f;
            float startY = lrect.Y + lrect.H - 20f;

            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(lx, startY), t, 11));   // id 11 → left
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(rx, startY), t, 22));   // id 22 → right
            host.RunFrame();
            // Drag both up, interleaving one frame per step. Left moves at twice the right's rate so their offsets diverge.
            for (int s = 1; s <= 16; s++)
            {
                uint ts = t + (uint)(s * 16);
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(lx, startY - s * 12f), ts, 11));
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(rx, startY - s * 6f), ts, 22));
                host.RunFrame();
            }
            host.Scene.TryGetScroll(left, out var lsc);
            host.Scene.TryGetScroll(right, out var rsc);
            // Left dragged ~192px, right ~96px (clamped to the slop-claim). Both > 0 and the left out-scrolled the right.
            bool independent = lsc.OffsetY > 120f && rsc.OffsetY > 50f && lsc.OffsetY > rsc.OffsetY + 40f;
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(lx, startY - 16 * 12f), t + 300, 11));
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(rx, startY - 16 * 6f), t + 300, 22));
            host.RunFrame();
            s_touchClockMs = t + 1000;
            Check("gate.touch.two-contacts-independent two concurrent touch ids pan two sibling scrollers independently (per-PointerId capture)",
                independent, $"leftOff={lsc.OffsetY:0} rightOff={rsc.OffsetY:0}");
        }

        // gate.touch.per-id-cancel: with two contacts panning, a PointerCancel for ONE id ends only that contact (its pan
        // freezes, no fling); the OTHER id keeps panning. The cancelled list's offset stops advancing while the live one
        // continues.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("touch-cancel", new Size2(440, 360), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TwoListProbe());
            host.RunFrame();
            var left = ViewportWithItemCount(host.Scene, host.Scene.Root, TwoListProbe.LeftN);
            var right = ViewportWithItemCount(host.Scene, host.Scene.Root, TwoListProbe.RightN);
            var lrect = host.Scene.AbsoluteRect(left);
            var rrect = host.Scene.AbsoluteRect(right);
            float lx = lrect.X + lrect.W / 2f, rx = rrect.X + rrect.W / 2f;
            float startY = lrect.Y + lrect.H - 20f;

            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(lx, startY), t, 11));
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(rx, startY), t, 22));
            host.RunFrame();
            // Both pans claim and advance for a few steps.
            for (int s = 1; s <= 6; s++)
            {
                uint ts = t + (uint)(s * 16);
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(lx, startY - s * 12f), ts, 11));
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(rx, startY - s * 12f), ts, 22));
                host.RunFrame();
            }
            host.Scene.TryGetScroll(left, out var lMid);
            float leftFrozenAt = lMid.OffsetY;

            // Cancel ONLY id 11 (the left). Its pan dies with no fling; id 22 keeps going.
            window.QueueInput(Touch(InputKind.PointerCancel, new Point2(lx, startY - 6 * 12f), t + 7 * 16, 11));
            host.RunFrame();
            for (int s = 7; s <= 16; s++)
            {
                uint ts = t + (uint)(s * 16);
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(lx, startY - s * 12f), ts, 11));   // stray moves for the cancelled id (ignored)
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(rx, startY - s * 12f), ts, 22));
                host.RunFrame();
            }
            host.Scene.TryGetScroll(left, out var lEnd);
            host.Scene.TryGetScroll(right, out var rEnd);
            bool leftFrozen = Near(lEnd.OffsetY, leftFrozenAt, 1f);   // the cancelled contact stopped moving its list
            bool rightContinued = rEnd.OffsetY > leftFrozenAt + 40f;  // the live contact kept panning past where the left froze
            // A capture-loss is not a flick: the cancelled list must NOT be flinging.
            host.RunFrame();
            host.Scene.TryGetScroll(left, out var lAfter);
            bool leftNoFling = Near(lAfter.OffsetY, lEnd.OffsetY, 0.6f) && lAfter.Phase == 0;
            Check("gate.touch.per-id-cancel a per-id PointerCancel ends only that contact (its pan freezes, no fling) while the other id keeps panning",
                leftFrozen && rightContinued && leftNoFling,
                $"leftFrozenAt={leftFrozenAt:0} leftEnd={lEnd.OffsetY:0} rightEnd={rEnd.OffsetY:0} leftMode={lAfter.Phase}");
        }

        // gate.touch.pressed-no-hover: a touch PointerDown drives the Pressed visual exactly like a mouse press (the node
        // gets NodeFlags.Pressed AND the InteractionAnimator arms PressT via OnPressChanged) but NEVER sets hover (touch has
        // no cursor); on PointerUp the node returns to Normal — Pressed clears and NO hover is left (NOT PointerOver, which
        // is where a mouse would rest). The probe is a lone Accent button at Scene.Root (clickable, non-scrollable ⇒ a pure
        // tap, no pan-claim).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("touch-press", new Size2(240, 120), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new HoverProbe());
            host.RunFrame();
            var r = host.Scene.AbsoluteRect(host.Scene.Root);
            var center = new Point2(r.X + r.W / 2f, r.Y + r.H / 2f);

            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, center, t, 4));
            host.RunFrame();
            bool pressedOnDown = !AnyPressed(host.Scene, host.Scene.Root).IsNull;   // Pressed visual set
            bool noHoverOnDown = AnyHovered(host.Scene, host.Scene.Root).IsNull;    // never a touch hover
            bool animArmed = host.HasActiveWork;                                    // PressT easing (OnPressChanged → SetPress)

            window.QueueInput(Touch(InputKind.PointerUp, center, t + 16, 4));
            host.RunFrame();
            bool releasedToNormal = AnyPressed(host.Scene, host.Scene.Root).IsNull   // back to Normal: no Pressed…
                                    && AnyHovered(host.Scene, host.Scene.Root).IsNull;   // …and NOT PointerOver (no cursor)
            s_touchClockMs = t + 1000;

            Check("gate.touch.pressed-no-hover a touch down drives Pressed (+ the interaction animator) with no hover; up returns to Normal, never PointerOver",
                pressedOnDown && noHoverOnDown && animArmed && releasedToNormal,
                $"pressedDown={pressedOnDown} hoverDown={!noHoverOnDown} animArmed={animArmed} normalAfterUp={releasedToNormal}");
        }

        // gate.touch.thumb-drag: a touch press landing on the conscious overlay-scrollbar thumb drives the per-PointerId
        // _scrollDragNode thumb-drag (track-fraction → SetScrollOffset) — NOT a content pan — and reveals/expands the bar
        // for the contact's duration; releasing lets the bar fade. A plain (non-virtualized) 800px-over-200px scroller so
        // the drag machinery itself is isolated 0-alloc on the hot half (no realize-edge churn to confound it — that churn
        // is the shared bound-row reconcile edge gate.touch.fling-realize-edge-is-wheel already accounts for).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("touch-thumb", new Size2(260, 260), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new ScrollProbe());
            host.RunFrame();
            var vp = host.Scene.Root;
            // Warm the scroll content node's first dirty-Mark (a one-time per-node lazy init in the scene's dirty tracking):
            // v2 §2.1 moves the offset write to phase 7 (the integrator tick), so this init now lands inside the measured
            // hot half — prime it here (a throwaway wheel down then back to the top marks + resets the content), exactly as
            // the fling gates warm the tick-write path via pre-fling contact tracking. The measured drag asserts steady state.
            // NB: does NOT advance the shared s_touchClockMs (only the per-host frame clock) — a later gate's absolute
            // timestamps must stay put (gate.touch.flick-seed-gap-invariant sits knife-edge on AssumeStoppedMs=40).
            window.QueueInput(new InputEvent(InputKind.Wheel, new Point2(130, 100), 0, 0, ScrollDelta: 48f, TimestampMs: s_touchClockMs));
            host.RunFrame();
            window.QueueInput(new InputEvent(InputKind.Wheel, new Point2(130, 100), 0, 0, ScrollDelta: -1_000_000f, TimestampMs: s_touchClockMs + 16));
            host.RunFrame();
            host.Scene.TryGetScroll(vp, out var sc0);
            float maxOff = MathF.Max(0f, sc0.ContentH - sc0.ViewportH);   // 800 − 200 = 600
            float laneX = 194f;   // the 200-wide viewport's lane sits at x∈[188,200]; the thumb is at the top at offset 0

            // Touch-grab the thumb at the top of the lane, then drag DOWN the lane in small steps — the offset must track
            // the thumb the whole way (the scrollbar owns the contact; it never page-jumps a content pan).
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(laneX, 12f), t, 8));
            host.RunFrame();
            host.Scene.TryGetScroll(vp, out var grabbed);
            bool revealedOnGrab = grabbed.PointerOverScrollbar && grabbed.FadeT > 0f;   // the lane press revealed+expanded the bar

            float lastOff = grabbed.OffsetY;
            int advanceSteps = 0, regressions = 0;
            long worstHot = 0;
            const int dragSteps = 60;
            for (int s = 1; s <= dragSteps; s++)
            {
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(laneX, 12f + s * 4f), t + (uint)s, 8));
                var f = host.RunFrame();
                if (f.HotPhaseAllocBytes > worstHot) worstHot = f.HotPhaseAllocBytes;
                host.Scene.TryGetScroll(vp, out var dsc);
                if (dsc.OffsetY > lastOff + 0.5f) advanceSteps++;          // tracked the thumb down a step
                else if (dsc.OffsetY < lastOff - 0.5f) regressions++;       // a mid-drag regression = silent disengage
                lastOff = dsc.OffsetY;
            }
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(laneX, 12f + dragSteps * 4f), t + dragSteps + 1, 8));
            host.RunFrame();
            host.Scene.TryGetScroll(vp, out var afterUp);
            // A thumb-drag maps track-fraction → offset, so ~240px of finger travel sweeps the thumb its full track travel
            // and the offset to the content-end clamp (max=600); a 4px-axis CONTENT pan would have moved the offset by only
            // ~240px and never clamped. Reaching the clamp — monotonically, no regressions, then holding once clamped — is
            // the proof the contact drove the thumb (not a pan) and never silently disengaged mid-travel.
            bool draggedToEnd = Near(afterUp.OffsetY, maxOff, 1f);
            bool trackedMonotonic = advanceSteps >= 25 && regressions == 0;
            // After release the contact-duration reveal ends (PointerOverScrollbar dropped) so the bar can fade on the idle timer.
            bool fadesAfterRelease = !afterUp.PointerOverScrollbar;
            s_touchClockMs = t + 1000;

            Check("gate.touch.thumb-drag a touch press on the overlay scrollbar thumb drives the per-id thumb-drag (offset tracks the thumb to the content end, not a content pan), reveals the bar for the contact, releases it to fade, and stays 0-alloc on the hot half",
                revealedOnGrab && trackedMonotonic && draggedToEnd && fadesAfterRelease && worstHot == 0,
                $"revealed={revealedOnGrab} advanced={advanceSteps}/{dragSteps} regress={regressions} off={afterUp.OffsetY:0}/max={maxOff:0} fades={fadesAfterRelease} worstHot={worstHot}B");
        }

        // gate.touch.lane-page-step: a touch tap on the lane BELOW the thumb pages the scroll like a mouse lane-click, but
        // (unlike a resting mouse cursor) must NOT leave the bar's PointerOverScrollbar latched — touch has no hover to
        // clear it, so the reveal would otherwise stick forever. The bar flashes from the page scroll then fades on idle.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("touch-lane", new Size2(260, 260), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new ScrollProbe());
            host.RunFrame();
            var vp = host.Scene.Root;
            float laneX = 194f;

            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(laneX, 188f), t, 3));   // lane, below the top-anchored thumb
            host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(laneX, 188f), t + 16, 3));
            host.RunFrame();
            host.Scene.TryGetScroll(vp, out var afterTap);
            bool paged = afterTap.OffsetY > 1f;                       // the lane tap paged the content down
            bool notLatched = !afterTap.PointerOverScrollbar;         // the lane reveal was NOT left stuck on
            s_touchClockMs = t + 1000;

            Check("gate.touch.lane-page-step a touch tap on the scrollbar lane pages the scroll and never latches the bar reveal (touch has no hover to clear it)",
                paged && notLatched,
                $"pagedTo={afterTap.OffsetY:0} pointerOverScrollbar={afterTap.PointerOverScrollbar}");
        }

        // gate.touch.rating-focal-scale: the PointerKind.Touch tag reaches RatingControl's PressInfo end-to-end (the
        // previously-dead RatingControl.cs:243 branch) — a TOUCH down sets c_touchOverScale = 1.0 so the focal star grows
        // to 2×1.0 = 2.0, vs the mouse 2×0.8 = 1.6 that w1controls.11 verifies. Same probe/geometry, touch instead of mouse.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("touch-rating", new Size2(320, 120), 1f)); window.Show();
            var root = new RatingProbe { Initial = RatingControl.NoValueSet };
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, root);
            host.RunFrame();

            var rating = FindRole(host.Scene, host.Scene.Root, AutomationRole.Rating);
            var rr = host.Scene.AbsoluteRect(rating);
            var cell0 = Child(host.Scene, Child(host.Scene, rating, 0), 0);
            var star0 = new Point2(rr.X + 8f, rr.Y + rr.H / 2f);   // star 1 centre (StarCenter(0) = 8)

            // A touch down on star 0 fires OnPointerDown (Sweep → focal at the finger) AND OnPointerPressed (PressInfo →
            // the touch device scalar). The focal cell then scales to the TOUCH peak 2.0, proving e.Kind == Touch arrived.
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, star0, t, 6));
            host.RunFrame(); host.RunFrame();
            float touchFocal = host.Scene.Paint(cell0).LocalTransform.M11;
            window.QueueInput(Touch(InputKind.PointerUp, star0, t + 16, 6));
            host.RunFrame();
            s_touchClockMs = t + 1000;

            Check("gate.touch.rating-focal-scale a touch down reaches RatingControl PressInfo (kind=Touch end-to-end) → focal star scales to the 2.0 touch peak (vs 1.6 mouse)",
                Near(touchFocal, 2.0f, 0.05f),
                $"touchFocal={touchFocal:0.00} (expect 2.00, mouse peak 1.60)");
        }

        // gate.touch.light-dismiss: a TOUCH tap outside an open light-dismiss flyout dismisses it with the SAME semantics
        // as the mouse light-dismiss (test 64) — the press lands on the full-bleed scrim (it is the topmost hit-test
        // target while a popup is open), so the existing tap path fires the scrim's OnClick = CloseTop(LightDismiss),
        // and the tap is CONSUMED by the scrim: the behind-content the scrim covers never sees the press (no click-through —
        // WinUI CPopupRoot::OnPointerPressed sets Handled=didCloseAPopup, popup.cpp:5206). Then a touch contact landing on
        // the scrim that is lost mid-gesture (PointerCancel — the per-id WM_POINTERCAPTURECHANGED path) closes nothing and
        // leaks nothing (capture loss is not a tap), and WindowBlur still light-dismisses the overlay (e4popup.1 covers the
        // blur trigger itself; here it must hold with a live touch contact resting over the scrim).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("touch-dismiss", new Size2(480, 360), 1f)); window.Show();
            var probe = new TouchDismissProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            var svc = probe.Service!;
            Func<Element> menu = () => new BoxEl
            {
                Width = 140, Direction = 1,
                Children = [new BoxEl { Height = 32, Role = AutomationRole.MenuItem, OnClick = () => svc.CloseTop(), Children = [Ui.Text("Item A")] }],
            };
            void Settle() { for (int i = 0; i < 16; i++) host.RunFrame(); }
            bool MenuOpen() => !FindRole(host.Scene, host.Scene.Root, AutomationRole.MenuItem).IsNull;
            var outside = new Point2(460, 350);   // far from the BottomLeft popup over the (20,20) anchor — over the behind-content

            // (1) Open → touch tap on the scrim outside the popup dismisses it (down+up over the same scrim point, monotonic stamps).
            svc.Open(() => probe.Anchor, menu, FlyoutPlacement.BottomLeft);
            host.RunFrame();
            bool openedT = MenuOpen();
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, outside, t, 3));
            window.QueueInput(Touch(InputKind.PointerUp, outside, t + 16, 3));
            host.RunFrame();
            Settle();
            s_touchClockMs = t + 1000;
            bool touchDismissed = !MenuOpen();
            bool noClickThrough = probe.BehindClicks == 0;   // the scrim ate the tap — behind-content never clicked

            // (2) Per-id PointerCancel mid-gesture: a touch resting on the scrim that loses capture closes nothing, leaks nothing.
            svc.Open(() => probe.Anchor, menu, FlyoutPlacement.BottomLeft);
            host.RunFrame();
            uint t2 = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, outside, t2, 4));
            host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerCancel, outside, t2 + 16, 4));
            host.RunFrame();
            s_touchClockMs = t2 + 1000;
            bool cancelKeptOpen = MenuOpen() && probe.BehindClicks == 0;   // cancel is not a tap: no dismiss, no click-through

            // (3) WindowBlur still light-dismisses with a touch contact live over the scrim (modal would stay; this is light-dismiss).
            window.QueueInput(new InputEvent(InputKind.WindowBlur, default, 0, 0));
            host.RunFrame();
            Settle();
            bool blurDismissed = !MenuOpen();

            Check("gate.touch.light-dismiss a touch tap outside an open light-dismiss flyout dismisses it (mouse semantics) and is consumed by the scrim (no click-through); a per-id PointerCancel over the scrim dismisses nothing; WindowBlur still closes it with a live touch contact",
                openedT && touchDismissed && noClickThrough && cancelKeptOpen && blurDismissed,
                $"opened={openedT} touchDismiss={touchDismissed} noClickThrough={noClickThrough} (behindClicks={probe.BehindClicks}) cancelKeptOpen={cancelKeptOpen} blurDismiss={blurDismissed}");
        }
    }

    // ── Touch Phase-4: pinch-zoom (gate.touch4.*). A SECOND touch contact over a Zoomable ScrollEl viewport opens a pinch
    // (the §7B Pinch member EagerAccept-wins, sweeping the Pan); the two contacts' separation scales the content about the
    // gesture midpoint as a TRANSFORM-only term composed with the -offset translation (clamp 0.1..10.0, NEVER LayoutDirty),
    // and the committed factor scales the extent the offset clamps against. Reuses the touch harness (PinchGesture + the
    // two-clock fixed-animation model). The viewport is the PinchZoomProbe's NON-virtual ScrollEl root, so a pinch move is
    // a pure transform frame (FrameStats.Rendered == false ⇒ no relayout — the asserted no-LayoutDirty proof).
    static void PinchZoomChecks(StringTable strings)
    {
        var fonts = new HeadlessFontSystem(strings);

        // gate.touch4.pinch-out-doubles: spreading the two contacts to 2× their start separation about a fixed midpoint
        // doubles ZoomFactor (1 → 2), applies it as the content node's LocalTransform scale (M11 == M22 == ZoomFactor),
        // keeps the content point under the midpoint fixed (the focal-point offset), and marks NO relayout (every pinch
        // move frame renders transform-only — Rendered == false; the content's model Bounds stay 800px).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("pinch-out", new Size2(200, 200), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new PinchZoomProbe());
            host.RunFrame();
            var vp = host.Scene.Root;
            host.Scene.TryGetScroll(vp, out var sc0);
            var content = sc0.ContentNode;
            float contentHBefore = host.Scene.Bounds(content).H;

            // Midpoint (100,100); A=(100,70) B=(100,130) ⇒ sep 60. Spread to A=(100,40) B=(100,160) ⇒ sep 120 = 2×.
            // Drive the move frames manually so each frame's Rendered flag is observable (no virtual re-realize on a plain
            // ScrollEl ⇒ a pure transform frame returns Rendered == false: the LayoutDirty-never-marked proof).
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(100, 70), t, 1)); host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(100, 130), t + 16, 2)); host.RunFrame();   // 2nd contact opens the pinch
            bool anyRelayout = false;
            for (int i = 1; i <= 10; i++)
            {
                float fa = 70f - (70f - 40f) * i / 10f;     // A: 70 → 40
                float fb = 130f + (160f - 130f) * i / 10f;   // B: 130 → 160
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(100, fa), t + 16 + (uint)i * 16, 1));
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(100, fb), t + 16 + (uint)i * 16, 2));
                var f = host.RunFrame();
                if (f.Rendered) anyRelayout = true;   // a relayout/reconcile would flip Rendered true
            }
            s_touchClockMs = t + 1000;
            host.Scene.TryGetScroll(vp, out var scZ);
            var lt = host.Scene.Paint(content).LocalTransform;
            float contentHAfter = host.Scene.Bounds(content).H;

            bool zoomDoubled = Near(scZ.ZoomFactor, 2.0f, 0.06f);
            bool transformScaled = Near(lt.M11, scZ.ZoomFactor, 0.01f) && Near(lt.M22, scZ.ZoomFactor, 0.01f);
            // Focal point under the midpoint (y=100, viewport-local 100) stays put: newOff = z·100 − 100 = 100 at z=2.
            bool focalFixed = Near(scZ.OffsetY, 100f, 8f);
            bool noRelayout = !anyRelayout && Near(contentHAfter, contentHBefore);
            Check("gate.touch4.pinch-out-doubles a 2× spread doubles ZoomFactor (1→2) applied as the content LocalTransform scale about the gesture midpoint (focal point fixed), with NO relayout (every move frame transform-only; model bounds unchanged)",
                zoomDoubled && transformScaled && focalFixed && noRelayout,
                $"zoom={scZ.ZoomFactor:0.00} M11={lt.M11:0.00} M22={lt.M22:0.00} offY={scZ.OffsetY:0} (focal~100) anyRelayout={anyRelayout} contentH {contentHBefore:0}->{contentHAfter:0}");
        }

        // gate.touch4.clamp: pinch FAR out clamps at MaxZoom (10.0); pinch FAR in clamps at MinZoom (0.1). The ScrollEl
        // defaults (Min 0.1 / Max 10.0 — ScrollPresenter.h:63-64) bound the factor; the transform never exceeds them.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("pinch-clamp", new Size2(200, 200), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new PinchZoomProbe());
            host.RunFrame();
            var vp = host.Scene.Root;

            // Spread WAY out: A 70→ -300, B 130→ 500 (sep 60 → 800 ≈ 13× ⇒ clamps at 10).
            PinchGesture(window, host, new Point2(100, 70), new Point2(100, 130), new Point2(100, -300), new Point2(100, 500), 12, 1, 2, 16f);
            host.Scene.TryGetScroll(vp, out var scMax);
            float maxZoom = scMax.ZoomFactor;
            float maxM11 = host.Scene.Paint(scMax.ContentNode).LocalTransform.M11;
            // Lift both to end the session (commit), reset to a fresh host for the pinch-in leg.
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(100, -300), s_touchClockMs, 1)); host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(100, 500), s_touchClockMs + 16, 2)); host.RunFrame();
            s_touchClockMs += 1000;

            using var app2 = new HeadlessPlatformApp();
            var window2 = new HeadlessWindow(new WindowDesc("pinch-clamp2", new Size2(200, 200), 1f)); window2.Show();
            using var host2 = new AppHost(app2, window2, new HeadlessGpuDevice(), fonts, strings, new PinchZoomProbe());
            host2.RunFrame();
            var vp2 = host2.Scene.Root;
            // Pinch WAY in: A 40→98, B 160→102 (sep 120 → 4 ≈ 0.033× ⇒ clamps at 0.1).
            PinchGesture(window2, host2, new Point2(100, 40), new Point2(100, 160), new Point2(100, 98), new Point2(100, 102), 12, 3, 4, 16f);
            host2.Scene.TryGetScroll(vp2, out var scMin);
            float minZoom = scMin.ZoomFactor;

            bool maxOk = Near(maxZoom, 10f, 0.01f) && Near(maxM11, 10f, 0.01f);
            bool minOk = Near(minZoom, 0.1f, 0.01f);
            Check("gate.touch4.clamp pinch-out clamps ZoomFactor at MaxZoom (10.0) and pinch-in clamps at MinZoom (0.1) — the WinUI ScrollPresenter defaults",
                maxOk && minOk, $"maxZoom={maxZoom:0.00} (M11={maxM11:0.00}) minZoom={minZoom:0.000}");
        }

        // gate.touch4.sweeps-pan: a pinch sweeps the single-finger Pan — during a pinch the content does NOT scroll as a
        // pan (the offset follows the ZOOM focal math, not a finger-drag delta). A pure-spread pinch about a FIXED midpoint
        // reaches z≈2 and offset≈100 (the focal value), which a finger-pan (offset ≈ anchor − fingerDelta ≈ 30) could
        // never produce — so the Pan was swept, not co-driven. (No scroll-from-pan during the pinch.)
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("pinch-sweep", new Size2(200, 200), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new PinchZoomProbe());
            host.RunFrame();
            var vp = host.Scene.Root;
            PinchGesture(window, host, new Point2(100, 70), new Point2(100, 130), new Point2(100, 40), new Point2(100, 160), 10, 1, 2, 16f);
            host.Scene.TryGetScroll(vp, out var sc);
            // The focal offset (≈100) is unreachable by a single-finger pan of the ≤30px finger travel (which would yield
            // ≈30) — so a non-zero, zoom-consistent offset with z≈2 proves the Pan was swept and the zoom drove the offset.
            bool zoomed = Near(sc.ZoomFactor, 2.0f, 0.06f);
            bool offsetIsZoomFocal = sc.OffsetY > 60f;   // » the ~30px a finger-pan would have produced
            Check("gate.touch4.sweeps-pan a pinch sweeps the single-finger Pan (the content scrolls by the zoom focal math, not a pan delta) — no scroll-from-pan during the pinch",
                zoomed && offsetIsZoomFocal, $"zoom={sc.ZoomFactor:0.00} offY={sc.OffsetY:0} (focal~100, a finger-pan would be ~30)");
        }

        // gate.touch4.per-id-cancel: a PointerCancel for ONE finger mid-pinch ends the session GRACEFULLY — the committed
        // ZoomFactor is kept (a partial pinch keeps its magnification), and the cancelled finger's stray moves + the
        // surviving finger no longer drive any zoom (the session is closed). No crash, deterministic.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("pinch-cancel", new Size2(200, 200), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new PinchZoomProbe());
            host.RunFrame();
            var vp = host.Scene.Root;
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(100, 70), t, 1)); host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(100, 130), t + 16, 2)); host.RunFrame();
            // Spread partway (sep 60 → 90 ⇒ z ≈ 1.5).
            for (int i = 1; i <= 6; i++)
            {
                float fa = 70f - 15f * i / 6f, fb = 130f + 15f * i / 6f;
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(100, fa), t + 16 + (uint)i * 16, 1));
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(100, fb), t + 16 + (uint)i * 16, 2));
                host.RunFrame();
            }
            host.Scene.TryGetScroll(vp, out var scMid);
            float zoomAtCancel = scMid.ZoomFactor;
            // Cancel finger 1 mid-pinch.
            window.QueueInput(Touch(InputKind.PointerCancel, new Point2(100, 55), t + 200, 1)); host.RunFrame();
            host.Scene.TryGetScroll(vp, out var scAfterCancel);
            // Stray moves for BOTH ids after the cancel must not change the zoom (session closed).
            window.QueueInput(Touch(InputKind.PointerMove, new Point2(100, 200), t + 220, 2)); host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerMove, new Point2(100, 10), t + 236, 1)); host.RunFrame();
            host.Scene.TryGetScroll(vp, out var scStray);
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(100, 200), t + 260, 2)); host.RunFrame();
            s_touchClockMs = t + 1000;

            bool committed = zoomAtCancel > 1.2f && Near(scAfterCancel.ZoomFactor, zoomAtCancel, 0.02f);
            bool noPostCancelZoom = Near(scStray.ZoomFactor, scAfterCancel.ZoomFactor, 0.02f);
            Check("gate.touch4.per-id-cancel a per-id PointerCancel mid-pinch ends the session gracefully — the committed ZoomFactor is kept and post-cancel stray moves drive no further zoom",
                committed && noPostCancelZoom, $"zoomAtCancel={zoomAtCancel:0.00} afterCancel={scAfterCancel.ZoomFactor:0.00} afterStray={scStray.ZoomFactor:0.00}");
        }

        // gate.touch4.pan-continuation: when the FIRST finger lifts, the pinch commits and the SURVIVING finger continues
        // as a pan over the (now zoomed) content (WinUI continues the manipulation with the remaining contact). After a
        // pinch-out, lift one finger, then drag the survivor — the content scrolls (the offset moves).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("pinch-cont", new Size2(200, 200), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new PinchZoomProbe());
            host.RunFrame();
            var vp = host.Scene.Root;
            // Pinch out to z≈2 (both fingers DOWN at the end).
            PinchGesture(window, host, new Point2(100, 70), new Point2(100, 130), new Point2(100, 40), new Point2(100, 160), 10, 1, 2, 16f);
            host.Scene.TryGetScroll(vp, out var scZoomed);
            float offBeforeContinue = scZoomed.OffsetY;
            float zoomCommitted = scZoomed.ZoomFactor;
            // Lift finger 1 (B survives at y=160). The survivor re-anchors as an already-claimed pan from (100,160).
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(100, 40), t, 1)); host.RunFrame();
            // Drag the survivor UP by 60px → content scrolls down (offset increases).
            for (int i = 1; i <= 6; i++)
            {
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(100, 160 - 10f * i), t + (uint)i * 16, 2));
                host.RunFrame();
            }
            host.Scene.TryGetScroll(vp, out var scPan);
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(100, 100), t + 200, 2)); host.RunFrame();
            s_touchClockMs = t + 1000;

            bool zoomKept = Near(scPan.ZoomFactor, zoomCommitted, 0.02f);   // the pan continuation never changes the factor
            bool survivorPanned = scPan.OffsetY > offBeforeContinue + 30f;  // dragging the survivor up scrolled the content
            Check("gate.touch4.pan-continuation lifting one pinch finger commits the zoom and the surviving finger continues as a pan over the zoomed content (WinUI manipulation continuation)",
                zoomKept && survivorPanned, $"zoomKept={scPan.ZoomFactor:0.00} (was {zoomCommitted:0.00}) off {offBeforeContinue:0}->{scPan.OffsetY:0}");
        }

        // gate.touch4.alloc-zero: a 20-frame pinch allocates 0 managed bytes on the hot half (the dispatch + transform +
        // re-realize machinery is fixed-storage; no LINQ/closures/boxing on the per-event path). Reuses the two-clock harness.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("pinch-alloc", new Size2(200, 200), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new PinchZoomProbe());
            host.RunFrame();
            // Warm the slab/arena once (first pinch primes any lazily-grown harness buffers), then measure the 2nd.
            PinchGesture(window, host, new Point2(100, 70), new Point2(100, 130), new Point2(100, 45), new Point2(100, 155), 8, 1, 2, 16f);
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(100, 45), s_touchClockMs, 1)); host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(100, 155), s_touchClockMs + 16, 2)); host.RunFrame();
            s_touchClockMs += 1000;

            long worst = PinchGesture(window, host, new Point2(100, 70), new Point2(100, 130), new Point2(100, 30), new Point2(100, 170), 20, 5, 6, 16f);
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(100, 30), s_touchClockMs, 5)); var fu = host.RunFrame();
            if (fu.HotPhaseAllocBytes > worst) worst = fu.HotPhaseAllocBytes;
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(100, 170), s_touchClockMs + 16, 6)); host.RunFrame();
            s_touchClockMs += 1000;
            Check("gate.touch4.alloc-zero a 20-frame pinch (down→spread→up) allocates 0 managed bytes on the hot half (fixed-storage dispatch + zoom transform + re-realize)",
                worst == 0, $"worstHotAlloc={worst}B");
        }

        // gate.touch4.dispatch-alloc-zero: the COMPANION instrument (the gate.arena.dispatch-alloc-zero pattern) — a
        // GetAllocatedBytesForCurrentThread delta wrapped DIRECTLY around host.Input.Dispatch over a full pinch, so the
        // measured window is the per-event PINCH path itself: the second-contact TryOpenPinch (OnSecondContact + the arena
        // sweep), UpdatePinch (the scale + the SetScrollOffset content-transform write) on every coalesced move pair, and the
        // pinch-end commit + pan continuation. A stray new[]/closure on any of those is caught here. Dispatch via a reused
        // 1-element buffer so the span itself never allocates; a warm pinch JITs the path, the second is the measured window.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("pinch-dispatch-alloc", new Size2(200, 200), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new PinchZoomProbe());
            host.RunFrame();
            var one = new InputEvent[1];

            // Drive one full pinch (down A, down B opens it, 20 spread move-pairs, lift both) through the real dispatcher.
            void DrivePinch(uint t0, uint idA, uint idB)
            {
                one[0] = Touch(InputKind.PointerDown, new Point2(100, 70), t0, idA); host.Input.Dispatch(one);
                one[0] = Touch(InputKind.PointerDown, new Point2(100, 130), t0 + 16, idB); host.Input.Dispatch(one);
                for (int i = 1; i <= 20; i++)
                {
                    float fa = 70f - 40f * i / 20f, fb = 130f + 40f * i / 20f;
                    one[0] = Touch(InputKind.PointerMove, new Point2(100, fa), t0 + 16 + (uint)i * 16, idA); host.Input.Dispatch(one);
                    one[0] = Touch(InputKind.PointerMove, new Point2(100, fb), t0 + 16 + (uint)i * 16, idB); host.Input.Dispatch(one);
                }
                one[0] = Touch(InputKind.PointerUp, new Point2(100, 30), t0 + 400, idA); host.Input.Dispatch(one);
                one[0] = Touch(InputKind.PointerUp, new Point2(100, 170), t0 + 416, idB); host.Input.Dispatch(one);
            }

            DrivePinch(s_touchClockMs, 1, 2);   // warm (JIT the pinch path; not measured)
            s_touchClockMs += 2000;
            uint t = s_touchClockMs;
            long before = GC.GetAllocatedBytesForCurrentThread();
            DrivePinch(t, 3, 4);                 // measured: the per-event pinch path only
            long delta = GC.GetAllocatedBytesForCurrentThread() - before;
            s_touchClockMs = t + 2000;
            Check("gate.touch4.dispatch-alloc-zero the per-event pinch path itself — TryOpenPinch (OnSecondContact + arena sweep) + UpdatePinch (scale + SetScrollOffset transform) per coalesced move + the pinch-end commit/continuation, measured by a delta wrapped DIRECTLY around host.Input.Dispatch — allocates 0 managed bytes across a full pinch",
                delta == 0, $"dispatchDelta={delta}B (direct phase-2 dispatch delta over a 40-move pinch)");
        }
    }

    // ── Scroll-perf remediation gates (plan W2: ambient-cap post-scroll hold + scroll FLIP suppression; W6: the anim
    //    slab's active-node chain). Headless, deterministic (the hold/grace are pinned via the internal test seams
    //    rather than wall-clock sleeps; the chain fuzz is seeded).
    static void ScrollPerfWaveChecks(StringTable strings)
    {
        var fonts = new HeadlessFontSystem(strings);

        // gate.wake.scrollHoldSuppressesAmbientCap (W2-P2.1): the RecommendedWaitMs ambient-FPS cap must defer through
        // the 0.45s post-scroll hold, not just the display-rate grace — otherwise slow wheel-notch scrolling over an
        // ambient loop (skeleton shimmer) oscillates 30Hz↔display-rate per notch (the step-up Resync cadence lurch).
        // AmbientAnimationFps=1 makes the branches unambiguous: ambient wait ≈ 1000ms, display-rate pacing is 0/7ms.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("scrollhold-cap", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
            host.AmbientAnimationFps = 1;
            host.RunFrame();
            var vp = host.Scene.Root;
            host.Animation.Keyframes(vp, AnimChannel.Opacity,
                new[] { new Keyframe(0f, 0.4f, Easing.Linear), new Keyframe(1f, 1f, Easing.Linear) }, 800f, loop: true);
            host.RunFrame();
            int wIdle = host.RecommendedWaitMs();                 // loop-only motion, no scroll ever → the ambient cap paces
            bool ambientBaseline = wIdle > 300;

            long now = System.Diagnostics.Stopwatch.GetTimestamp();
            host.MainScrollHoldUntilForTest = now + System.Diagnostics.Stopwatch.Frequency;   // hold LIVE (~1s)
            host.SetScrollGraceForTest(0);                                                    // grace EXPIRED — isolates the hold term
            int wHold = host.RecommendedWaitMs();
            bool holdSuppresses = wHold <= 7;                     // display-rate pacing (0 sync / 7 pace floor), NOT AmbientFrameWaitMs

            host.MainScrollHoldUntilForTest = 0;                  // hold EXPIRED
            host.SetScrollGraceForTest(0);
            int wAfter = host.RecommendedWaitMs();
            bool capReturns = wAfter > 300;

            // And the production arming path: a REAL wheel notch through the dispatcher re-arms the hold at the
            // phase-7 scroll tick (the sync wheel write pulses ScrollMoved → UserScrollActive on the next ticked frame).
            window.QueueInput(new InputEvent(InputKind.Wheel, new Point2(150, 200), 0, 0, WheelNotch: 1f));
            host.RunFrame(); host.RunFrame(); host.RunFrame();
            bool holdArmed = host.MainScrollHoldUntilForTest > System.Diagnostics.Stopwatch.GetTimestamp();
            Check("gate.wake.scrollHoldSuppressesAmbientCap the ambient FPS cap defers through the post-scroll hold: loop-only motion paces at the cap; hold live (grace expired) ⇒ display-rate pacing, NOT AmbientFrameWaitMs; hold expired ⇒ the cap returns; a real wheel notch arms the hold",
                ambientBaseline && holdSuppresses && capReturns && holdArmed,
                $"wIdle={wIdle} (want >300) wHold={wHold} (want <=7) wAfter={wAfter} (want >300) holdArmed={holdArmed}");
        }

        // gate.motion.scrollSuppressionSnapsFlip (W2-P2.2): a reconcile landing on the frame right after a scroll
        // offset actually wrote SNAPS the moved BoundsAnimated node (no structural FLIP track seeded — cards must not
        // fly through a scrolling viewport); the same move on a still frame FLIPs — both before any scroll AND after
        // one while the 0.45s hold is still live but no offset moved (a click-triggered expand right after scrolling).
        {
            FluentGpu.Dsl.Motion.ReducedMotion = false;
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("scrollflip", new Size2(500, 400), 1f)); window.Show();
            var probe = new ScrollFlipProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            for (int i = 0; i < 4; i++) host.RunFrame();

            // Control: a reconcile move on a STILL frame (no scroll motion ever) seeds the structural FLIP track.
            probe.Moved.Value = true;                             // spacer 20→150 ⇒ box slot moves down 130px
            host.RunFrame();
            float dyFlip = host.Scene.Paint(probe.Box).LocalTransform.Dy;
            bool flipSeeds = host.Animation.HasTracks(probe.Box) && dyFlip < -50f;   // departs from the OLD slot
            host.Animation.SnapStructuralToLayout(probe.Box);     // settle instantly (bounded, deterministic)
            host.RunFrame();

            // Scroll-coincident: a wheel notch writes the offset THIS frame (sync path) → the latch arms for the NEXT
            // frame, where the reconcile lands → ApplyProjections must take its suppressed-snap branch.
            window.QueueInput(new InputEvent(InputKind.Wheel, new Point2(100, 150), 0, 0, WheelNotch: 1f));
            host.RunFrame();
            bool offsetWrote = host.ScrollIntegratorForTest.AnyOffsetWroteThisFrame;   // proof the scroll really moved
            probe.Moved.Value = false;                            // move back 150→20 on the post-write frame
            host.RunFrame();
            float dySnap = host.Scene.Paint(probe.Box).LocalTransform.Dy;
            bool snapped = !host.Animation.HasTracks(probe.Box) && MathF.Abs(dySnap) < 0.01f;

            // Hold still LIVE but no offset motion since ⇒ the very next click-triggered move must STILL FLIP
            // (the suppression gates on actual motion last frame, never on the bare hold window).
            host.RunFrame(); host.RunFrame();                     // idle frames: the offset-wrote latch clears
            bool holdLive = host.MainScrollHoldUntilForTest > System.Diagnostics.Stopwatch.GetTimestamp();
            bool latchClear = !host.ScrollIntegratorForTest.AnyOffsetWroteThisFrame;
            probe.Moved.Value = true;
            host.RunFrame();
            float dyAfter = host.Scene.Paint(probe.Box).LocalTransform.Dy;
            bool flipsAgain = host.Animation.HasTracks(probe.Box) && dyAfter < -50f;
            FluentGpu.Dsl.Motion.SetLayoutTransitionsSuppressed(FluentGpu.Dsl.MotionSuppressionSource.Scroll, false);   // never leak the static bit to later gates
            Check("gate.motion.scrollSuppressionSnapsFlip a reconcile landing right after a scroll-offset write SNAPS the moved node (no FLIP track); the same move with no scroll motion FLIPs — both before any scroll and (hold still live, latch clear) right after one",
                flipSeeds && offsetWrote && snapped && holdLive && latchClear && flipsAgain,
                $"flipSeeds={flipSeeds}(dy={dyFlip:0.#}) offsetWrote={offsetWrote} snapped={snapped}(dy={dySnap:0.##}) holdLive={holdLive} latchClear={latchClear} flipsAgain={flipsAgain}(dy={dyAfter:0.#})");
        }

        // gate.anim.activeChainMatchesDictionary (W6/E12): the slab's intrusive active-node chain (what PASS1/PASS2 and
        // the census scans iterate) stays set-equal to the node→head Dictionary (the lookup) through a seeded randomized
        // add / free-one-row / clear-node sequence — at EVERY step, with no duplicate and no cycle — and mutations bump
        // the census-memo Version.
        {
            var scene = new SceneStore();
            var nodes = new NodeHandle[24];
            for (int i = 0; i < nodes.Length; i++) nodes[i] = scene.CreateNode(1);
            var slab = new AnimValueSlab();
            var rng = new Random(0xF6E12);
            var slots = new System.Collections.Generic.List<int>[nodes.Length];
            for (int i = 0; i < slots.Length; i++) slots[i] = new System.Collections.Generic.List<int>();
            var chainSet = new System.Collections.Generic.HashSet<int>();
            var dictSet = new System.Collections.Generic.HashSet<int>();
            bool ok = true; string detail = "";
            int startVersion = slab.Version;
            for (int step = 0; step < 800 && ok; step++)
            {
                int pick = rng.Next(nodes.Length);
                int nodeIndex = (int)nodes[pick].Raw.Index;
                int op = rng.Next(10);
                if (op < 5)
                    slots[pick].Add(slab.Add(nodeIndex, new AnimValue { Node = nodes[pick], Channel = AnimChannel.Opacity }));
                else if (op < 8)
                {
                    if (slots[pick].Count > 0) { int k = rng.Next(slots[pick].Count); slab.Free(slots[pick][k]); slots[pick].RemoveAt(k); }
                }
                else { slab.ClearNode(nodeIndex); slots[pick].Clear(); }

                chainSet.Clear(); dictSet.Clear();
                foreach (int n in slab.NodeIndices) dictSet.Add(n);
                int guard = 0; bool dupOrCycle = false;
                for (int n = slab.FirstActiveNode; n >= 0; n = slab.NextActiveNode(n))
                {
                    if (!chainSet.Add(n) || ++guard > 1000) { dupOrCycle = true; break; }
                }
                if (dupOrCycle || !chainSet.SetEquals(dictSet))
                {
                    ok = false;
                    detail = $"step={step} dupOrCycle={dupOrCycle} chain={chainSet.Count} dict={dictSet.Count}";
                }
            }
            bool versioned = slab.Version > startVersion;
            Check("gate.anim.activeChainMatchesDictionary 800 seeded randomized add/free/clear steps keep the slab's active-node chain set-equal to the node→head dictionary at every step (no dup, no cycle), and mutations bump the census-memo Version",
                ok && versioned, ok ? $"800 steps, final live rows={slab.Count}, version={slab.Version}" : detail);
        }
    }

    // ── WinUI-parity scroll exit criteria: content-relative wheel distance (max(48,10%·viewport) per notch, not a flat
    //    60), the windowed-regression velocity sampler (true flick speed, no stationary up-sample bias), and the
    //    engine-owned integrator driving scrolling (the single, portable scroll source — no OS scroll source seam).
    static void ScrollParityChecks(StringTable strings)
    {
        var fonts = new HeadlessFontSystem(strings);

        // gate.scroll.wheel-distance-viewport-relative: ONE device wheel notch (InputEvent.WheelNotch) scrolls
        // max(48 DIP, 10%·viewport) — a bounded content-relative mouse-wheel line height — NOT the old flat 60 DIP. A TALL
        // viewport steps by the 10% term (>48); a SHORT viewport floors at 48. The two distinct steps prove it is
        // viewport-relative. (A synthetic DIP ScrollDelta — every other wheel gate — bypasses this scale, so they are
        // unchanged.)
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("wheel-dist", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
            host.RunFrame();
            var vp = host.Scene.Root;
            // ScrollBy reads ViewportH at dispatch (phase 2) — BEFORE layout re-publishes it at phase 6 — so forcing it
            // probes the per-notch distance for any viewport. TALL: max(48, 0.10·800) = 80. SHORT: max(48, 0.10·200) = 48.
            host.Scene.ScrollRef(vp).ViewportH = 800f; host.Scene.ScrollRef(vp).OffsetY = 0f; host.Scene.ScrollRef(vp).TargetY = 0f;
            window.QueueInput(new InputEvent(InputKind.Wheel, new Point2(150, 200), 0, 0, WheelNotch: 1f));
            host.RunFrame();
            host.Scene.TryGetScroll(vp, out var scTall);
            float stepTall = scTall.TargetY;

            host.Scene.ScrollRef(vp).ViewportH = 200f; host.Scene.ScrollRef(vp).OffsetY = 0f; host.Scene.ScrollRef(vp).TargetY = 0f;
            window.QueueInput(new InputEvent(InputKind.Wheel, new Point2(150, 200), 0, 0, WheelNotch: 1f));
            host.RunFrame();
            host.Scene.TryGetScroll(vp, out var scShort);
            float stepShort = scShort.TargetY;

            bool tallOk = Near(stepTall, 80f, 0.6f);     // 10%·800
            bool shortOk = Near(stepShort, 48f, 0.6f);   // floored (0.10·200 = 20 < 48)
            Check("gate.scroll.wheel-distance-viewport-relative one wheel notch scrolls max(48 DIP, 10%·viewport) — bounded content-relative motion, not a flat 60: viewport 800 ⇒ step 80, viewport 200 ⇒ step 48 (floor); distinct ⇒ genuinely viewport-relative",
                tallOk && shortOk && !Near(stepTall, stepShort, 1f),
                $"vp800 step={stepTall:0.#} (expect 80) vp200 step={stepShort:0.#} (expect 48)");
        }

        // gate.touch.flick-velocity-windowed: the windowed least-squares velocity sampler reads a fast constant-velocity
        // flick's TRUE terminal speed (the 50ms EMA under-read it — gain dt/(dt+50) lags before convergence), AND a finger
        // that moves fast then HOLDS STILL before lift decays to ~0 (the old EMA's stationary up-sample bias kept stale
        // momentum). Drives the dispatcher directly and reads PointerVelocity.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("flick-vel", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
            host.RunFrame();
            uint t = s_touchClockMs;
            var ev = new InputEvent[1];
            ev[0] = Touch(InputKind.PointerDown, new Point2(150, 384), t, 21); host.Input.Dispatch(ev); host.RunFrame();
            float y = 384f;
            for (int i = 0; i < 10; i++) { t += 8; y -= 16f; ev[0] = Touch(InputKind.PointerMove, new Point2(150, y), t, 21); host.Input.Dispatch(ev); host.RunFrame(); }
            float vFast = host.Input.PointerVelocity.Y;   // ≈ -2000 px/s (16px / 8ms, upward ⇒ negative)
            bool accurate = vFast <= -1700f;              // near the true -2000 (the EMA lagged to ~-1500); regression reads true
            // Now HOLD the finger still for several samples → the in-window slope goes to 0 (no stale momentum carried).
            for (int i = 0; i < 8; i++) { t += 8; ev[0] = Touch(InputKind.PointerMove, new Point2(150, y), t, 21); host.Input.Dispatch(ev); host.RunFrame(); }
            float vRest = host.Input.PointerVelocity.Y;
            bool restZero = MathF.Abs(vRest) < 60f;
            ev[0] = Touch(InputKind.PointerUp, new Point2(150, y), t + 8, 21); host.Input.Dispatch(ev); host.RunFrame();
            s_touchClockMs = t + 1000;
            Check("gate.touch.flick-velocity-windowed the windowed-regression velocity sampler reads a fast flick's TRUE terminal speed (no EMA under-read) and decays a paused-then-held finger to ~0 (the stationary up-sample bias is gone)",
                accurate && restZero, $"fastV={vFast:0} (true≈-2000, want ≤-1700) heldStillV={vRest:0} (want ~0)");
        }

        // gate.touch.flick-seed-gap-invariant: a constant-velocity flick seeds the SAME fling velocity regardless of the OS
        // move→up timing gap. The release velocity is RE-WINDOWED at lift WITHOUT folding the up point into the regression
        // (TouchVelocity.ComputeReleaseVelocity): the up event repeats the last-move position at a later stamp — a near-zero
        // sample that, folded in, dragged the seed toward 0 as the gap grew (the OLD path read ~−1786/−1429/−981/−554 px/s at
        // 8/16/24/32 ms — the felt "same fast flick, different result" / "scrolls only a bit"). Now every realistic lift gap
        // seeds the true ~2000 px/s. (A gap BEYOND the 50 ms regression window is a genuine pre-lift PAUSE and correctly seeds
        // no fling — not asserted here; this gate covers the lift-timing-jitter range a real flick lands in.)
        {
            float SeedForGap(uint gap)   // non-static: captures fonts/strings; fresh host per gap so each starts at offset 0
            {
                using var app = new HeadlessPlatformApp();
                var window = new HeadlessWindow(new WindowDesc("flick-gap", new Size2(360, 460), 1f)); window.Show();
                using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
                host.RunFrame();
                var vp = host.Scene.Root;
                uint t = s_touchClockMs;
                var ev = new InputEvent[1];
                ev[0] = Touch(InputKind.PointerDown, new Point2(150, 384), t, 21); host.Input.Dispatch(ev); host.RunFrame();
                float y = 384f;   // constant 16 px / 8 ms = 2000 px/s flick up (8 moves, 128 px — past slop, claims a pan)
                for (int i = 0; i < 8; i++) { t += 8; y -= 16f; ev[0] = Touch(InputKind.PointerMove, new Point2(150, y), t, 21); host.Input.Dispatch(ev); host.RunFrame(); }
                // Lift at the SAME position as the last move (the up REPEATS it — the corrupting case), GAP ms after it.
                ev[0] = Touch(InputKind.PointerUp, new Point2(150, y), t + gap, 21); host.Input.Dispatch(ev);   // SeedScrollFling runs synchronously
                host.Scene.TryGetScroll(vp, out var sc);
                s_touchClockMs = t + gap + 1000;
                return MathF.Abs(sc.FlingVelocity);   // offset-space seed (≈ 2000); 0 ⇒ no fling
            }
            uint[] gaps = { 8, 16, 24, 32, 40 };
            float min = float.MaxValue, max = 0f;
            foreach (var g in gaps) { float s = SeedForGap(g); if (s < min) min = s; if (s > max) max = s; }
            bool allReal = min >= 1700f;                                       // every gap seeds the true ~2000 (no gap drops to a low/zero seed)
            bool consistent = max <= 0f || (max - min) / max < 0.10f;          // within 10% across gaps — "same flick, same momentum"
            Check("gate.touch.flick-seed-gap-invariant a constant-velocity flick seeds the SAME ~2000 px/s fling across OS lift gaps {8..40}ms (release velocity re-windowed at lift, not folded with the stale up point) — the 'same fast flick, different result' inconsistency is gone",
                allReal && consistent, $"seed min={min:0} max={max:0} spread={(max > 0f ? (max - min) / max * 100f : 0f):0.#}% (want min≥1700, spread<10%)");
        }

        // gate.scroll.engine-owned-integrator: scroll is fully engine-owned — the deterministic ScrollIntegrator is the
        // single, portable scroll source on every platform (there is no OS scroll-source seam; DirectManipulation is
        // gone). A wheel notch drives the integrator's target-chase to a NON-ZERO offset in plain TargetChase mode,
        // proving the engine integrator alone moves the viewport.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("engine-scroll", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
            host.RunFrame();
            var vp = host.Scene.Root;
            window.QueueInput(new InputEvent(InputKind.Wheel, new Point2(150, 200), 0, 0, 200f));   // DIP ScrollDelta (integrator path)
            for (int i = 0; i < 40; i++) host.RunFrame();
            host.Scene.TryGetScroll(vp, out var s);
            bool integratorRan = s.OffsetY > 0f && s.Phase == ScrollIntegrator.Idle;
            Check("gate.scroll.engine-owned-integrator scroll is fully engine-owned — the deterministic ScrollIntegrator alone drives the viewport (no OS scroll source); a DIP wheel delta advances it to a non-zero offset and settles back to Idle",
                integratorRan, $"integratorRan={integratorRan} off={s.OffsetY:0} phase={s.Phase}");
        }

        // gate.scroll.overscroll-physics (v2): the canonical iOS asymptotic rubber-band + its EXACT inverse + the ω=12.5
        // snap-back (scroll-feel-rework-v2 §4.4/§4.5). d = BandAsymptoteFraction·vp = 60 is the asymptote the band
        // approaches but NEVER reaches (no wall, marginal give > 0 everywhere) — bandPos at excess=120 lands BELOW d,
        // not clamped at the old 10% cap. f(x) = x·d·c/(d + c·|x|), c = 0.55.
        {
            float vp = 400f;
            float d = OverscrollPhysics.BandAsymptoteFraction * vp;       // 60
            float bandNeg = OverscrollPhysics.BandFromExcess(-30f, vp);   // -30·60·0.55/(60+0.55·30) = -12.941
            float bandPos = OverscrollPhysics.BandFromExcess(120f, vp);   // 120·60·0.55/(60+0.55·120) = 31.429 (< d — no wall)
            float inv = OverscrollPhysics.ExcessFromBand(bandNeg, vp);    // exact inverse ⇒ -30
            float p = bandNeg, v = 0f;
            for (int i = 0; i < 120; i++) OverscrollPhysics.StepSpring(ref p, ref v, 16f);   // ω=SnapBackOmega=12.5 ⇒ settles well within 1920ms
            bool ok = Near(bandNeg, -12.941f, 0.05f) && bandNeg > -d && bandNeg < 0f
                   && Near(bandPos, 31.429f, 0.05f) && bandPos < d
                   && Near(inv, -30f, 0.5f)
                   && Near(p, 0f, 0.1f) && Near(v, 0f, 1f);
            Check("gate.scroll.overscroll-physics v2 iOS rubber-band f(x)=x·d·c/(d+c|x|) (c=0.55, d=0.15·vp) approaches but never reaches the asymptote, ExcessFromBand is its exact inverse, and the ω=12.5 snap-back springs to 0 (translation-only)",
                ok, $"bandNeg={bandNeg:0.000} bandPos={bandPos:0.000} d={d:0} inv={inv:0.0} final=({p:0.00},{v:0.0})");
        }
    }

    // ── scroll-feel-rework-v2 §8 validation: the twelve headless gates driven by the HeadlessScrollProducer (six input
    // kinds, synthetic ms/QPC stamps, deterministic frame clock) against the real Rhi.Headless/Pal.Headless pipeline. Each
    // pins one of the confirmed root causes (R1–R6) with the spec's exact formulas. All run headless, 0-alloc phases 6–13.
    static void ScrollV2ValidationChecks(StringTable strings)
    {
        var fonts = new HeadlessFontSystem(strings);
        float k = -MathF.Log(ScrollIntegrator.FlingDecayPerS);   // exact coast decay rate (1/s)
        var center = new Point2(150, 200);

        // gate.scroll.single-writer (§8.1, pins R1): a full contact-track + fling + top-overpan + snap-back + wheel-chase
        // cycle records offset writes from the PHASE-7 INTEGRATOR ONLY (writer == Integrator) and AT MOST ONE offset write
        // per active node per frame. The 0-alloc audit counts every real SetScrollOffset move and its ScrollWriter tag; a
        // foreign writer (a synchronous phase-2 write — the R1 two-owners defect) or a second write in one frame fails it.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("v2-single-writer", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
            host.Input.SmoothScroll = true;   // a wheel notch drives WheelAnimating (integrator), never a synchronous jump
            host.RunFrame();
            var vp = host.Scene.Root;
            var prod = new HeadlessScrollProducer(window, host, center);
            ScrollTrace.AuditBegin();
            prod.ContactBegin(0f); prod.Step(16);
            for (int i = 0; i < 6; i++) { prod.ContactUpdate(24f); prod.Step(16); }   // latch + track down ~144 DIP
            prod.ContactEnd(); prod.Step(16);                                          // fallback lift → seeds Fling
            for (int i = 0; i < 80; i++) { prod.Step(16); host.Scene.TryGetScroll(vp, out var s); if (s.Phase == ScrollIntegrator.Idle) break; }
            prod.ContactBegin(0f); prod.Step(16);
            for (int i = 0; i < 8; i++) { prod.ContactUpdate(-60f); prod.Step(16); }   // drag PAST the top edge → Overscroll band
            prod.ContactEnd(); prod.Step(16);                                          // release → SnapBack
            for (int i = 0; i < 80; i++) { prod.Step(16); host.Scene.TryGetScroll(vp, out var s); if (MathF.Abs(s.OverscrollPx) < 0.1f && s.Phase == ScrollIntegrator.Idle) break; }
            prod.WheelNotch(2f); prod.Step(16);                                        // discrete notch → WheelAnimating chase
            for (int i = 0; i < 80; i++) { prod.Step(16); host.Scene.TryGetScroll(vp, out var s); if (s.Phase == ScrollIntegrator.Idle) break; }
            bool foreign = ScrollTrace.AuditForeignWriter;
            int maxWrites = ScrollTrace.AuditMaxWritesPerFrame;
            ScrollTrace.AuditStop();
            Check("gate.scroll.single-writer a full contact+fling+overpan+snapback+wheel cycle records offset writes from the phase-7 integrator ONLY (no foreign writer) and AT MOST one offset write per active node per frame — the §2.1 single-writer invariant (pins R1)",
                !foreign && maxWrites == 1, $"foreignWriter={foreign} maxWritesPerFrame={maxWrites} (expect no-foreign, ≤1/frame)");
        }

        // gate.scroll.dt-invariance (§8.2, pins R2/R3/R5 frame-independence): the same scripted motion at dt∈{8,16,33}ms
        // yields the same trajectory within 1 DIP — contact (the §4.1 resampler tracks the same continuous position line
        // regardless of frame cadence), fling coast (the closed-form CoastStep telescopes to v0/k), wheel chase (closed-form
        // crit-damped, lands on the target), and snap-back (closed-form spring → 0).
        {
            const float vel = 0.4f;   // DIP/ms
            // Contact: run the 1-packet-per-frame-at-frame-time script at dt and return max deviation from vel·(t−5ms−t0).
            float ContactDev(float dt)
            {
                using var app = new HeadlessPlatformApp();
                var w = new HeadlessWindow(new WindowDesc("v2-dtinv", new Size2(360, 460), 1f)); w.Show();
                using var h = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe(), frameTime: new FixedFrameTimeSource(dt));
                h.RunFrame();
                var v2 = h.Scene.Root;
                var pr = new HeadlessScrollProducer(w, h, center) { Device = (byte)ScrollDeviceClass.Touchpad };
                double t0 = pr.FrameMs;
                pr.ContactBegin(0f); pr.Frame(dt);
                float maxDev = 0f;
                for (int kf = 0; kf < 40; kf++)
                {
                    pr.Ms = (uint)pr.FrameMs;                       // deliver one packet AT the present time
                    pr.ContactUpdate(vel * dt);
                    double present = pr.FrameMs;
                    pr.Frame(dt);
                    h.Scene.TryGetScroll(v2, out var s);
                    if (kf < 3 || s.Phase != ScrollIntegrator.TouchpadTracking) continue;
                    float expected = (float)(vel * (present - ScrollTuning.ResampleLatencyMs - t0));
                    if (s.OffsetY > 1f && s.OffsetY < 2600f) maxDev = MathF.Max(maxDev, MathF.Abs(s.OffsetY - expected));
                }
                return maxDev;
            }
            float FlingCoast(float dt) { float v = 1000f, c = 0f; for (int i = 0; i < 5000 && MathF.Abs(v) >= 0.5f; i++) c += OverscrollPhysics.CoastStep(ref v, dt, ScrollIntegrator.FlingDecayPerS); return c; }
            float WheelChase(float dt)
            {
                float off = 0f, vel2 = 0f; const float pending = 200f;
                float y = 1.3862944f / (ScrollTuning.WheelChaseHalflifeMs * 0.001f);
                for (int i = 0; i < 4000; i++)
                {
                    float dtS = dt * 0.001f, j0 = off - pending, j1 = vel2 + j0 * y, e = MathF.Exp(-y * dtS);
                    off = e * (j0 + j1 * dtS) + pending; vel2 = e * (vel2 - j1 * y * dtS);
                    if (MathF.Abs(off - pending) < 0.5f && MathF.Abs(vel2) < ScrollIntegrator.WheelSettleVelPxPerS) break;
                }
                return off;
            }
            float SnapEnd(float dt) { float p = 60f, v = 0f; for (int i = 0; i < 6000; i++) if (OverscrollPhysics.StepSpring(ref p, ref v, dt, OverscrollPhysics.SnapBackOmega)) break; return p; }
            float cd8 = ContactDev(8f), cd16 = ContactDev(16f), cd33 = ContactDev(33f);
            float f8 = FlingCoast(8f), f16 = FlingCoast(16f), f33 = FlingCoast(33f);
            float wh8 = WheelChase(8f), wh16 = WheelChase(16f), wh33 = WheelChase(33f);
            float sn8 = SnapEnd(8f), sn16 = SnapEnd(16f), sn33 = SnapEnd(33f);
            bool contactOk = cd8 <= 0.5f && cd16 <= 0.5f && cd33 <= 0.5f;              // each on the same line ⇒ pairwise ≤1
            bool flingOk = MathF.Abs(f8 - f16) <= 1f && MathF.Abs(f16 - f33) <= 1f && MathF.Abs(f8 - f33) <= 1f;
            bool wheelOk = Near(wh8, 200f, 1f) && Near(wh16, 200f, 1f) && Near(wh33, 200f, 1f);
            bool snapOk = Near(sn8, 0f, 0.5f) && Near(sn16, 0f, 0.5f) && Near(sn33, 0f, 0.5f);
            Check("gate.scroll.dt-invariance the same stream at dt∈{8,16,33}ms produces the same trajectory within 1 DIP across contact (resampler), fling (CoastStep), wheel chase, and snap-back — frame-rate independence (pins R2/R3/R5)",
                contactOk && flingOk && wheelOk && snapOk,
                $"contactDev=({cd8:0.00},{cd16:0.00},{cd33:0.00})≤0.5 fling=({f8:0.0},{f16:0.0},{f33:0.0}) wheel=({wh8:0.0},{wh16:0.0},{wh33:0.0}) snap=({sn8:0.00},{sn16:0.00},{sn33:0.00})");
        }

        // gate.scroll.resample-cadence (§8.3, pins R2): a constant-velocity stream at 1-packet/2-packet ALTERNATING cadence
        // (8ms packets against a 12ms frame → 1,2,1,2 packets/frame) produces monotonic, NEAR-CONSTANT per-frame displacement
        // (the §4.1 resampler samples the same linear position at frameT−5ms, so the packet cadence alias is gone). Without
        // resampling the per-frame displacement would alternate δ,2δ — the textbook 125Hz-into-60Hz judder.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("v2-resample", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe(), frameTime: new FixedFrameTimeSource(12f));
            host.RunFrame();
            var vp = host.Scene.Root;
            var prod = new HeadlessScrollProducer(window, host, center) { Device = (byte)ScrollDeviceClass.Touchpad };
            const float vel = 0.5f;   // DIP/ms → 4 DIP per 8ms packet, 6 DIP per 12ms frame
            uint packetMs = prod.Ms;
            prod.ContactBegin(0f); prod.Frame(12f);
            float prevOff = 0f; bool havePrev = false; float minD = float.MaxValue, maxD = 0f; bool monotonic = true; int measured = 0;
            for (int kf = 0; kf < 40; kf++)
            {
                while (packetMs + 8 <= prod.FrameMs) { packetMs += 8; prod.Ms = packetMs; prod.ContactUpdate(vel * 8f); }   // deliver due 8ms packets
                prod.Frame(12f);
                host.Scene.TryGetScroll(vp, out var s);
                if (kf >= 6 && s.Phase == ScrollIntegrator.TouchpadTracking && s.OffsetY < 2400f)   // past warmup, in-range
                {
                    if (havePrev)
                    {
                        float d = s.OffsetY - prevOff;
                        if (d + 0.01f < 0f) monotonic = false;
                        minD = MathF.Min(minD, d); maxD = MathF.Max(maxD, d); measured++;
                    }
                    prevOff = s.OffsetY; havePrev = true;
                }
            }
            float spread = measured > 0 ? maxD - minD : 999f;
            bool ok = monotonic && measured >= 10 && spread <= 0.6f;   // constant 6 DIP/frame ⇒ spread ≈ 0 (bound 0.6)
            Check("gate.scroll.resample-cadence a constant-velocity stream at 1/2-packet-alternating cadence produces monotonic, near-constant per-frame displacement (spread ≤ 0.6 DIP) — the §4.1 resampler kills the packet-cadence alias (pins R2)",
                ok, $"perFrameΔ min={minD:0.00} max={maxD:0.00} spread={spread:0.00} monotonic={monotonic} n={measured}");
        }

        // gate.scroll.contact-1to1 (§8.4): during TouchpadTracking the applied offset equals the resampled finger position
        // (anchor + Σδ resampled to frameT−5ms) within 0.5 DIP every frame — the resampler neither lags nor gains.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("v2-1to1", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
            host.RunFrame();
            var vp = host.Scene.Root;
            var prod = new HeadlessScrollProducer(window, host, center) { Device = (byte)ScrollDeviceClass.Touchpad };
            const float vel = 0.4f;
            double t0 = prod.FrameMs;
            prod.ContactBegin(0f); prod.Frame(16f);
            float maxErr = 0f; int frames = 0;
            for (int kf = 0; kf < 40; kf++)
            {
                prod.Ms = (uint)prod.FrameMs;
                prod.ContactUpdate(vel * 16f);
                double present = prod.FrameMs;
                prod.Frame(16f);
                host.Scene.TryGetScroll(vp, out var s);
                if (kf < 3 || s.Phase != ScrollIntegrator.TouchpadTracking) continue;
                if (s.OffsetY > 1f && s.OffsetY < 2600f)
                {
                    float expected = (float)(vel * (present - ScrollTuning.ResampleLatencyMs - t0));
                    maxErr = MathF.Max(maxErr, MathF.Abs(s.OffsetY - expected)); frames++;
                }
            }
            Check("gate.scroll.contact-1to1 during TouchpadTracking the applied offset tracks the resampled finger position (anchor + Σδ @ frameT−5ms) within 0.5 DIP every frame",
                maxErr <= 0.5f && frames >= 10, $"maxErr={maxErr:0.000} DIP over {frames} tracking frames (bound 0.5)");
        }

        // gate.scroll.coast-distance (§8.5, pins R3): a wheel notch coasts EXACTLY its perNotch distance (max(48,10%·vp)),
        // identical at 60/120 Hz; a fling coasts v0/k (the exact closed-form asymptote) ±1 DIP. Wheel via the pipeline
        // (WheelAnimating chase lands on the hard-clamped PendingTarget); fling via the exact CoastStep integral.
        {
            float WheelSettle(float dt)
            {
                using var app = new HeadlessPlatformApp();
                var w = new HeadlessWindow(new WindowDesc("v2-coast-wheel", new Size2(360, 460), 1f)); w.Show();
                using var h = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe(), frameTime: new FixedFrameTimeSource(dt));
                h.Input.SmoothScroll = true; h.RunFrame();
                var v2 = h.Scene.Root;
                var pr = new HeadlessScrollProducer(w, h, center);
                pr.WheelNotch(1f); pr.Frame(dt);
                for (int i = 0; i < 400; i++) { pr.Frame(dt); h.Scene.TryGetScroll(v2, out var s); if (s.Phase == ScrollIntegrator.Idle) break; }
                h.Scene.TryGetScroll(v2, out var fin);
                return fin.OffsetY;
            }
            float perNotch = MathF.Max(48f, 0.10f * 400f);   // vp = 400 ⇒ floor 48
            float w60 = WheelSettle(1000f / 60f), w120 = WheelSettle(1000f / 120f);
            float vf = 1000f, coast = 0f; for (int i = 0; i < 20000 && MathF.Abs(vf) >= 0.5f; i++) coast += OverscrollPhysics.CoastStep(ref vf, 1000f / 60f, ScrollIntegrator.FlingDecayPerS);
            float asymptote = 1000f / k;   // ≈ 499.4
            bool wheelOk = Near(w60, perNotch, 0.5f) && Near(w120, perNotch, 0.5f);
            bool flingOk = Near(coast, asymptote, 1f);
            Check("gate.scroll.coast-distance a wheel notch coasts its exact perNotch distance (max(48,10%·vp)) ±0.5 DIP identically at 60/120 Hz, and a fling coasts the exact v0/k asymptote ±1 DIP (pins R3)",
                wheelOk && flingOk, $"wheel60={w60:0.0} wheel120={w120:0.0} (perNotch={perNotch:0}) flingCoast={coast:0.0} (v0/k={asymptote:0.0})");
        }

        // gate.scroll.impulse-velocity (§8.6, pins R6): the single-window IMPULSE estimator sign(W)·√(2|W|). Five sub-cases
        // on the phase-contract (fallback) lift path: (a) constant drag ⇒ exact hand speed; (b) a ≥40ms gap before lift ⇒ 0;
        // (c) a decaying tail then silence ⇒ v<50 (no double inertia); (d) an abrupt lift ⇒ exactly one coast; (e) a reversal
        // ⇒ no stale-direction (positive) coast. decay1 folds the single End-frame tick that decays the fresh seed once.
        {
            const byte Fb = (byte)ScrollDeviceClass.WheelHiResFallback;
            float decay1 = MathF.Exp(MathF.Log(ScrollIntegrator.FlingDecayPerS) * 16f / 1000f);
            (float v, byte phase) Drive(float[] deltas, uint packetGap, uint liftGap)
            {
                using var app = new HeadlessPlatformApp();
                var w = new HeadlessWindow(new WindowDesc("v2-impulse", new Size2(360, 460), 1f)); w.Show();
                using var h = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
                h.RunFrame();
                var v2 = h.Scene.Root;
                var pr = new HeadlessScrollProducer(w, h, center) { Device = Fb };
                pr.ContactBegin(0f); pr.Frame(16f);
                foreach (float d in deltas) { pr.Ms += packetGap; pr.ContactUpdate(d); pr.Frame(16f); }
                pr.Ms += liftGap; pr.ContactEnd(); pr.Frame(16f);
                h.Scene.TryGetScroll(v2, out var s);
                return (s.FlingVelocity, s.Phase);
            }
            float[] constStream = { 8f, 8f, 8f, 8f, 8f, 8f, 8f, 8f };            // 8 DIP / 8ms = 1000 DIP/s
            float[] decelStream = { 8f, 8f, 8f, 8f, 4f, 2f, 1f, 0.4f };
            float[] revStream = { 16f, 16f, 16f, 16f, -16f, -16f, -16f, -16f };
            var a = Drive(constStream, 8, 8);                                     // (a)+(d): abrupt lift, exact speed, one coast
            var b = Drive(constStream, 8, 60);                                    // (b): ≥40ms gap ⇒ 0
            var c = Drive(decelStream, 16, 60);                                   // (c): decayed tail + silence ⇒ no double inertia
            var e = Drive(revStream, 8, 8);                                       // (e): reversal ⇒ no stale-down coast
            bool aOk = a.phase == ScrollIntegrator.Fling && MathF.Abs(a.v - 1000f * decay1) <= 1000f * decay1 * 0.04f;
            bool bOk = b.phase != ScrollIntegrator.Fling || MathF.Abs(b.v) < 1f;
            bool cOk = c.phase != ScrollIntegrator.Fling || MathF.Abs(c.v) < ScrollTuning.FlingSeedGate;
            bool eOk = e.v <= 1f;   // recent motion is UP (negative); no positive downward stale coast
            Check("gate.scroll.impulse-velocity the single 40ms IMPULSE estimator: constant drag ⇒ exact hand speed + one coast; a ≥40ms gap ⇒ 0; a decayed tail then silence ⇒ v<50; a reversal ⇒ no stale-direction coast (pins R6, one window one gate)",
                aOk && bOk && cOk && eOk,
                $"const={a.v:0}(exp {1000f * decay1:0}) gap={b.v:0.0} decel={c.v:0.0} reversal={e.v:0.0}");
        }

        // gate.scroll.overscroll-rational (§8.7, pins R5): the iOS asymptotic map + its EXACT inverse round-trip within 0.5
        // DIP INCLUDING at/above the old saturation point (x = 2·limit and 10·limit) — the map never reaches the asymptote d
        // (marginal slope > 0 everywhere); and the ω=12.5 snap-back decays to ≤10% of the band in 300–360 ms (WebKit λ=12.5).
        {
            const float vp = 400f;
            float limit = OverscrollPhysics.BandLimit(vp);     // 0.1·vp = 40
            float d = OverscrollPhysics.BandAsymptoteFraction * vp;   // 60 (asymptote)
            float worst = 0f; bool belowAsymptote = true;
            foreach (float x in new[] { 5f, 40f, 2f * limit, 200f, 10f * limit })
            {
                float band = OverscrollPhysics.BandFromExcess(x, vp);
                if (MathF.Abs(band) >= d) belowAsymptote = false;                // never reaches the wall
                worst = MathF.Max(worst, MathF.Abs(OverscrollPhysics.ExcessFromBand(band, vp) - x));
            }
            // Snap-back settle-to-10%: seed a 60-DIP band, step the ω=12.5 spring at 4ms, time to |band| ≤ 10% of x0.
            float p0 = 60f, sp = 60f, sv = 0f, tMs = 0f; int settle10 = -1;
            for (int i = 0; i < 400; i++)
            {
                OverscrollPhysics.StepSpring(ref sp, ref sv, 4f, OverscrollPhysics.SnapBackOmega); tMs += 4f;
                if (settle10 < 0 && MathF.Abs(sp) <= 0.10f * p0) { settle10 = (int)tMs; break; }
            }
            bool rtOk = worst < 0.5f && belowAsymptote;
            bool settleOk = settle10 >= 300 && settle10 <= 360;
            // scroll-feel-v2.1 §A.1/§A.4: the edge bounce is VELOCITY-ONLY (position untouched). SeedFromEdgeMomentum
            // leaves the band at the current stretch (0 here) and seeds bandVel = clamp(γ·v, ±Cpeak·d·ω·e); the
            // critically-damped v0·t·e^(−ωt) peaks at v0/(ω·e) ≤ Cpeak·d = 0.6·d, so even the MAX-velocity flick never
            // approaches the asymptote (kills F6's teleport), and a re-grab AT the peak folds a finite, well-inside-domain
            // excess that round-trips (peak < d ⇒ the F7 near-asymptote divergence is unreachable on a bounce).
            float bandPk = 0f, bandVk = 0f;
            OverscrollPhysics.SeedFromEdgeMomentum(ref bandVk, ScrollTuning.FlingMaxVelocityPxPerS, vp);   // 8000 px/s max seed (velocity-only: bandPk stays 0)
            float peak = MathF.Abs(bandPk);
            for (float bp = bandPk, bv = bandVk, i = 0; i < 400; i++)
            { if (OverscrollPhysics.StepSpring(ref bp, ref bv, 4f, OverscrollPhysics.SnapBackOmega)) break; peak = MathF.Max(peak, MathF.Abs(bp)); }
            float cap = OverscrollPhysics.MomentumPeakDepthFraction * d;   // 0.6·d = 36
            float regrabExcess = OverscrollPhysics.ExcessFromBand(peak, vp);
            float regrabBand = OverscrollPhysics.BandFromExcess(regrabExcess, vp);
            bool bounceOk = peak <= cap + 0.5f && float.IsFinite(regrabExcess) && MathF.Abs(regrabBand - peak) < 0.5f;
            Check("gate.scroll.overscroll-rational the iOS rubber-band round-trips (ExcessFromBand∘BandFromExcess) within 0.5 DIP incl. x∈{2·limit,10·limit} (never reaches the asymptote), the ω=12.5 snap-back settles to 10% in 300–360 ms (pins R5), AND the velocity-only edge bounce peaks ≤ 0.6·d with a re-grab round-trip at the peak (§A.1/§A.4, F6/F7)",
                rtOk && settleOk && bounceOk, $"worstRoundTrip={worst:0.000} belowAsymptote={belowAsymptote} settle10%={settle10}ms bouncePeak={peak:0.0}/cap={cap:0.0} regrabRT={MathF.Abs(regrabBand - peak):0.000}");
        }

        // gate.scroll.relatch-catchup (scroll-feel-v2.1 §A.6, resolves F8): an OS-momentum stream that includes a post-hitch
        // catch-up (a 34ms stall frame delivering one big summed delta) applies the FULL owed displacement 1:1 — there is NO
        // max-per-frame delta clamp. Chromium coalesces GSUs and applies the summed delta; Android/Flutter evaluate at
        // absolute time (a full jump after a long frame); no shipping system clamps a catch-up. Because the resampler tracks
        // the cumulative position line (not per-frame deltas), the final offset converges to Σ(all deltas) regardless of
        // frame pacing — a hypothetical per-frame clamp would truncate the 193 DIP hitch and fall far short.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("v2-relatch", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
            host.RunFrame();
            var vp = host.Scene.Root;
            var pr = new HeadlessScrollProducer(window, host, center) { Device = (byte)ScrollDeviceClass.Touchpad };
            float total = 0f;
            pr.ContactBegin(0f); pr.Step(16);
            for (int i = 0; i < 6; i++) { pr.ContactUpdate(20f); total += 20f; pr.Step(16); }   // latch + track interior (~120 DIP)
            pr.MomentumBegin(); pr.Step(16);
            for (int i = 0; i < 4; i++) { pr.MomentumUpdate(24f); total += 24f; pr.Step(16); }   // smooth OS inertia
            pr.MomentumUpdate(193f); total += 193f; pr.Step(34f);                                 // the F8 hitch: 34ms stall → one 193 DIP catch-up
            for (int i = 0; i < 5; i++) { pr.MomentumUpdate(10f); total += 10f; pr.Step(16); }    // slow tail so the resampler fully realizes the jump
            pr.MomentumEnd();
            for (int i = 0; i < 40; i++) { pr.Step(16); host.Scene.TryGetScroll(vp, out var q); if (q.Phase == ScrollIntegrator.Idle) break; }
            host.Scene.TryGetScroll(vp, out var s);
            float applied = s.OffsetY;
            // Full owed displacement (a few DIP of resampler lag = end-velocity × 5ms is the only shortfall; a real clamp
            // would lose ~150 DIP of the 193 hitch). Stayed interior (no edge conversion) throughout.
            bool oneToOne = MathF.Abs(applied - total) < 8f;
            Check("gate.scroll.relatch-catchup an OS-momentum stream with a 34ms hitch (one 193 DIP catch-up) applies the full owed displacement 1:1 within a vsync — no max-per-frame delta clamp (§A.6, resolves F8)",
                oneToOne, $"applied={applied:0.0} expectedTotal={total:0.0} phase={s.Phase}");
        }

        // gate.scroll.pointerdown-cancels (§8.8, pins R6): a pointer-down over a coasting/animating viewport zeros its motion
        // the SAME frame with no residual drift. A mouse click, a touch-down, and a scrollbar-grab all route through the same
        // OnCancelFling call (fixes R6's dead CancelFling). Seed a fling, then fire the down mid-coast.
        {
            (bool cancelled, bool noDrift) DownCancels(PointerKind kind)
            {
                using var app = new HeadlessPlatformApp();
                var w = new HeadlessWindow(new WindowDesc("v2-downcancel", new Size2(360, 460), 1f)); w.Show();
                using var h = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
                h.RunFrame();
                var v2 = h.Scene.Root;
                var pr = new HeadlessScrollProducer(w, h, center) { Device = (byte)ScrollDeviceClass.WheelHiResFallback };
                pr.ContactBegin(0f); pr.Frame(16f);
                for (int i = 0; i < 8; i++) { pr.Ms += 8; pr.ContactUpdate(8f); pr.Frame(16f); }   // 1000 DIP/s
                pr.Ms += 8; pr.ContactEnd(); pr.Frame(16f);                                          // seed a fling
                pr.Frame(16f); pr.Frame(16f);                                                        // coast a couple frames
                h.Scene.TryGetScroll(v2, out var mid);
                bool wasFlinging = mid.Phase == ScrollIntegrator.Fling && MathF.Abs(mid.FlingVelocity) > 50f;
                pr.PointerDownAt(center, kind, kind == PointerKind.Touch ? 5u : 0u); pr.Frame(16f);  // the down cancels the coast
                h.Scene.TryGetScroll(v2, out var afterDown);
                bool cancelled = afterDown.Phase != ScrollIntegrator.Fling && MathF.Abs(afterDown.FlingVelocity) < 1f;
                float offAfter = afterDown.OffsetY;
                pr.Frame(16f);                                                                       // no drift the next frame
                h.Scene.TryGetScroll(v2, out var next);
                return (wasFlinging && cancelled, MathF.Abs(next.OffsetY - offAfter) < 0.5f);
            }
            var mouse = DownCancels(PointerKind.Mouse);
            var touch = DownCancels(PointerKind.Touch);
            Check("gate.scroll.pointerdown-cancels a mouse click / touch-down over a live Fling zeros velocity the SAME frame with no residual drift (the shared OnCancelFling — scrollbar-grab routes here too; pins R6)",
                mouse.cancelled && mouse.noDrift && touch.cancelled && touch.noDrift,
                $"mouse(cancel={mouse.cancelled},noDrift={mouse.noDrift}) touch(cancel={touch.cancelled},noDrift={touch.noDrift})");
        }

        // gate.scroll.wheel-lines (§8.9): the SPI wheel-lines preference scales per-notch distance (distance =
        // notch·(lines/3)·perNotch), page mode ⇒ 0.875·viewport per notch, and the sub-120 signed carryover accumulates the
        // raw delta and emits one notch per 120 crossed keeping a signed remainder (reset on direction change — the Win32
        // producer's §3.2 algorithm, verified here headlessly).
        {
            float NotchTarget(float preScaledNotch)
            {
                using var app = new HeadlessPlatformApp();
                var w = new HeadlessWindow(new WindowDesc("v2-wheel-lines", new Size2(360, 460), 1f)); w.Show();
                using var h = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
                h.Input.SmoothScroll = true; h.RunFrame();
                var v2 = h.Scene.Root;
                var pr = new HeadlessScrollProducer(w, h, center);
                pr.WheelNotch(preScaledNotch); pr.Frame(16f);
                h.Scene.TryGetScroll(v2, out var s);
                return s.PendingTargetY;   // WheelAnimating hard-clamped accumulated target = notch·perNotch
            }
            float perNotch = MathF.Max(48f, 0.10f * 400f);   // 48
            float lines3 = NotchTarget(1f * (3f / 3f));       // lines=3 ⇒ ×1 ⇒ 48
            float lines1 = NotchTarget(1f * (1f / 3f));       // lines=1 ⇒ ×1/3 ⇒ 16
            float lines6 = NotchTarget(1f * (6f / 3f));       // lines=6 ⇒ ×2 ⇒ 96
            bool linesOk = Near(lines3, perNotch, 0.5f) && Near(lines1, perNotch / 3f, 0.5f) && Near(lines6, 2f * perNotch, 0.5f);
            // Page mode: a notch pages 0.875·viewport (a DIP delta, not a notch-scaled distance).
            float pageExpected = 0.875f * 400f;
            float pageTarget;
            using (var app = new HeadlessPlatformApp())
            {
                var w = new HeadlessWindow(new WindowDesc("v2-wheel-page", new Size2(360, 460), 1f)); w.Show();
                using var h = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
                h.Input.SmoothScroll = true; h.RunFrame();
                var v2 = h.Scene.Root;
                var pr = new HeadlessScrollProducer(w, h, center);
                w.QueueInput(new InputEvent(InputKind.Wheel, center, 0, 0, ScrollDelta: pageExpected, Pointer: PointerKind.Mouse, TimestampMs: pr.Ms));
                pr.Frame(16f);
                h.Scene.TryGetScroll(v2, out var s);
                pageTarget = s.PendingTargetY;
            }
            bool pageOk = Near(pageTarget, pageExpected, 0.5f);
            // Signed carryover (the §3.2 producer algorithm): accumulate raw units, emit per 120, keep signed remainder,
            // reset the remainder on a direction change.
            static (int notches, int rem) Carry(int prevRem, int raw) { int acc = prevRem + raw; return (acc / 120, acc % 120); }
            var s1 = Carry(0, 60);        // (0, 60)   — sub-notch held
            var s2 = Carry(s1.rem, 60);   // (1, 0)    — crossed 120
            var s3 = Carry(s2.rem, 130);  // (1, 10)   — one notch + signed remainder
            var s4 = Carry(0, -60);       // (0, -60)  — reset on direction flip, signed remainder
            bool carryOk = s1 == (0, 60) && s2 == (1, 0) && s3 == (1, 10) && s4 == (0, -60);
            Check("gate.scroll.wheel-lines SPI wheel-lines scales per-notch distance (lines 1/3/6 ⇒ ×1/3, ×1, ×2), page mode pages 0.875·viewport, and the signed sub-120 carryover accumulates + resets on direction change (§3.2)",
                linesOk && pageOk && carryOk,
                $"lines1={lines1:0.0} lines3={lines3:0.0} lines6={lines6:0.0} page={pageTarget:0.0}(exp {pageExpected:0}) carry={carryOk}");
        }

        // gate.scroll.subpixel-stability (§8.10): a slow sub-pixel pan produces monotonic WHOLE-device-px translate steps
        // (tx = round((offset+band)·scale)/scale) while the logical offset stays continuous float — and a ScrollBind sticky
        // pin sharing the same origin computes the SAME rounded translation (no 1px seam). scale = 2 ⇒ steps of 0.5 DIP.
        {
            const float scale = 2f;
            NodePaint cp = default; var bounds = new RectF(0, 0, 300, 3200);
            float prevTx = float.NaN; bool monotonic = true, wholePx = true, stepOk = true;
            for (int i = 0; i <= 40; i++)
            {
                float off = i * 0.1f;   // 0..4 DIP in 0.1 steps (sub-device-pixel at scale 2)
                OverscrollPhysics.WriteContentTransform(ref cp, in bounds, horizontal: false, offset: off, band: 0f, zoomFactor: 1f, scale: scale);
                float tx = -cp.LocalTransform.Dy;                       // translation Y = −tx
                if (MathF.Abs(tx * scale - MathF.Round(tx * scale)) > 1e-4f) wholePx = false;   // integral device px
                if (!float.IsNaN(prevTx))
                {
                    float step = tx - prevTx;
                    if (step + 1e-4f < 0f) monotonic = false;
                    if (!(step < 1e-4f || Near(step, 1f / scale, 1e-3f))) stepOk = false;        // step is 0 or one device px
                }
                prevTx = tx;
            }
            // Sticky-header share-origin (finding-4 fix): drive a REAL pinned ScrollBind through the host across a
            // sub-pixel offset sweep and assert the pinned header lands on the SAME device-pixel grid as the rounded
            // content — ApplyPin now rounds its shift to whole device px (ScrollBindEval.ApplyPin), so a header never seams
            // a sub-pixel step against the content beneath it. (The prior sub-check called WriteContentTransform TWICE with
            // identical args and asserted equality — tautological; it never exercised ApplyPin, so a real pin/content seam
            // — ApplyPin wrote an UNROUNDED Affine2D.Translation(0, shift) while content was device-px rounded — shipped unverified.)
            bool pinDeviceAligned = true, pinWholePx = true, pinnedEver = false; string pinLog = "";
            {
                using var papp = new HeadlessPlatformApp();
                var pwin = new HeadlessWindow(new WindowDesc("subpixel-pin", new Size2(320, 240), 2f)); pwin.Show();
                NodeHandle headerN = NodeHandle.Null;
                var proot = new W0fStaticProbe
                {
                    Build = () => Ui.ScrollView(new BoxEl
                    {
                        Direction = 1,
                        Children =
                        [
                            new BoxEl { Height = 100f },                                  // lead-in
                            new BoxEl { Direction = 1, Children =
                            [
                                new BoxEl { Height = 40f, ScrollBinds = [ new() { PinTop = 0f } ], OnRealized = h => headerN = h },
                                new BoxEl { Height = 400f },
                            ] },
                            new BoxEl { Height = 800f },
                        ],
                    }),
                };
                using var phost = new AppHost(papp, pwin, new HeadlessGpuDevice(), fonts, strings, proot);
                phost.RunFrame();
                var ps = phost.Scene;
                NodeHandle FindVp(NodeHandle n)
                {
                    if (n.IsNull) return NodeHandle.Null;
                    if (ps.HasScroll(n)) return n;
                    for (var c = ps.FirstChild(n); !c.IsNull; c = ps.NextSibling(c)) { var r = FindVp(c); if (!r.IsNull) return r; }
                    return NodeHandle.Null;
                }
                var pvp = FindVp(ps.Root);
                var pcontent = ps.ScrollRef(pvp).ContentNode;
                float ds = ps.DeviceScale;   // = 2 (the window scale) — the grid the pin must share with the content
                for (int i = 0; i <= 24 && !headerN.IsNull; i++)
                {
                    float y = 250f + i * 0.1f;   // sub-device-pixel offsets, all inside the header's pin range [100,500]
                    ref ScrollState pst = ref ps.ScrollRef(pvp);
                    pst.OffsetY = y; pst.TargetY = y;
                    // Round the content translation exactly as the offset chokepoint does (device-px snap) so a shared-grid
                    // pin cannot seam; then the real ApplyPinAndFlagPass pins the header with its (now rounded) shift.
                    OverscrollPhysics.WriteContentTransform(ref ps.Paint(pcontent), in bounds, false, y, 0f, 1f, ds);
                    ps.Mark(pcontent, NodeFlags.TransformDirty | NodeFlags.PaintDirty);
                    pwin.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(8f, 8f), 0, 0));
                    phost.RunFrame();
                    if ((ps.Flags(headerN) & NodeFlags.StickyPinned) != 0) pinnedEver = true;
                    float shiftDy = ps.Paint(headerN).LocalTransform.Dy;                         // the applied pin shift
                    if (MathF.Abs(shiftDy * ds - MathF.Round(shiftDy * ds)) > 1e-3f) pinWholePx = false;
                    float absY = ps.AbsoluteRect(headerN).Y;                                     // on-screen (content + pin composed)
                    if (MathF.Abs(absY * ds - MathF.Round(absY * ds)) > 1e-3f) { pinDeviceAligned = false; if (pinLog.Length == 0) pinLog = $"seam@y={y:0.0} absY={absY:0.###}"; }
                }
                if (headerN.IsNull) { pinDeviceAligned = false; pinLog = "header not realized"; }
            }
            Check("gate.scroll.subpixel-stability a slow sub-pixel pan advances in monotonic whole-device-px steps (tx=round((off+band)·s)/s) while logical offset stays float, and a REAL pinned ScrollBind shares the content's device grid — its shift AND on-screen position snap to whole device px (no 1px seam)",
                monotonic && wholePx && stepOk && pinnedEver && pinWholePx && pinDeviceAligned,
                $"monotonic={monotonic} wholePx={wholePx} stepOk={stepOk} pinnedEver={pinnedEver} pinWholePx={pinWholePx} pinDeviceAligned={pinDeviceAligned} {pinLog}");
        }

        // gate.scroll.transition-matrix (§8.11, structural guard for R1): drive the feel-critical legal transitions and
        // assert each resulting Phase; a wheel NEVER produces a band (WheelAnimating→Overscroll is undefined — the §2.2 extent
        // asymmetry), which is asserted as a hard negative.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("v2-matrix", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
            host.Input.SmoothScroll = true; host.RunFrame();
            var vp = host.Scene.Root;
            var log = new System.Text.StringBuilder();
            bool AssertPhase(string label, byte got, byte want) { bool ok = got == want; if (!ok) log.Append($"[{label}:got {got}!={want}]"); return ok; }
            bool m = true;

            var pr = new HeadlessScrollProducer(window, host, center) { Device = (byte)ScrollDeviceClass.Touchpad };
            pr.ContactBegin(0f); pr.Step(16); pr.ContactUpdate(30f); pr.Step(16);
            host.Scene.TryGetScroll(vp, out var s1); m &= AssertPhase("Idle→Track", s1.Phase, ScrollIntegrator.TouchpadTracking);
            pr.Device = (byte)ScrollDeviceClass.WheelHiResFallback;
            pr.ContactBegin(0f); pr.Step(16);
            for (int i = 0; i < 8; i++) { pr.Ms += 8; pr.ContactUpdate(8f); pr.Frame(16f); }
            pr.Ms += 8; pr.ContactEnd(); pr.Frame(16f);
            host.Scene.TryGetScroll(vp, out var s2); m &= AssertPhase("Track→Fling", s2.Phase, ScrollIntegrator.Fling);
            pr.PointerDownAt(center); pr.Frame(16f);
            host.Scene.TryGetScroll(vp, out var s3); m &= AssertPhase("Fling→Idle(down)", s3.Phase, ScrollIntegrator.Idle);
            for (int i = 0; i < 40; i++) { pr.Frame(16f); host.Scene.TryGetScroll(vp, out var q); if (q.Phase == ScrollIntegrator.Idle && MathF.Abs(q.OverscrollPx) < 0.1f) break; }
            pr.WheelNotch(1f); pr.Frame(16f);
            host.Scene.TryGetScroll(vp, out var s4); m &= AssertPhase("Idle→Wheel", s4.Phase, ScrollIntegrator.WheelAnimating);
            pr.PointerDownAt(center); pr.Frame(16f);
            host.Scene.TryGetScroll(vp, out var s5); m &= AssertPhase("Wheel→Idle(down)", s5.Phase, ScrollIntegrator.Idle);
            for (int i = 0; i < 40; i++) { pr.Frame(16f); host.Scene.TryGetScroll(vp, out var q); if (q.Phase == ScrollIntegrator.Idle) break; }
            for (int i = 0; i < 30; i++) { pr.WheelNotch(-1f); pr.Frame(16f); }   // hammer the TOP extent with wheel
            for (int i = 0; i < 60; i++) { pr.Frame(16f); host.Scene.TryGetScroll(vp, out var q); if (q.Phase == ScrollIntegrator.Idle) break; }
            host.Scene.TryGetScroll(vp, out var s6);
            bool wheelNoBand = MathF.Abs(s6.OverscrollPx) < 0.01f && s6.Phase != ScrollIntegrator.Overscroll;
            if (!wheelNoBand) log.Append($"[illegal Wheel→band:{s6.OverscrollPx:0.0}]");
            pr.Device = (byte)ScrollDeviceClass.Touchpad;
            pr.ContactBegin(0f); pr.Step(16);
            for (int i = 0; i < 10; i++) { pr.ContactUpdate(-60f); pr.Step(16); }   // past the top edge → Overscroll band
            host.Scene.TryGetScroll(vp, out var sOver); bool overOk = sOver.Phase == ScrollIntegrator.Overscroll || MathF.Abs(sOver.OverscrollPx) > 1f;
            pr.ContactEnd(); pr.Step(16);
            host.Scene.TryGetScroll(vp, out var s7); m &= AssertPhase("Overscroll→SnapBack", s7.Phase, ScrollIntegrator.SnapBack);
            for (int i = 0; i < 120; i++) { pr.Step(16); host.Scene.TryGetScroll(vp, out var q); if (q.Phase == ScrollIntegrator.Idle && MathF.Abs(q.OverscrollPx) < 0.1f) break; }
            host.Scene.TryGetScroll(vp, out var s8); m &= AssertPhase("SnapBack→Idle", s8.Phase, ScrollIntegrator.Idle);
            Check("gate.scroll.transition-matrix the feel-critical legal transitions (Idle→Track→Fling, Fling/Wheel→Idle on pointer-down, Idle→Wheel, Overscroll→SnapBack→Idle) each land on the correct §2.2 Phase, and a wheel NEVER bands at the extent (undefined ⇒ hard fail)",
                m && overOk && wheelNoBand, log.Length == 0 ? "all transitions correct; wheelNoBand=True" : log.ToString());
        }

        // gate.scroll.alloc-zero (§8.12): a full contact + fling + momentum + wheel cycle allocates 0 managed bytes on the
        // hot half (phases 6–13), including the DM-style momentum sink cadence. Fill-only bound rows (no per-row string
        // intern), warmed once before the measured window.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("v2-alloc-zero", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new BoundVirtualFillOnlyProbe());
            host.Input.SmoothScroll = true; host.RunFrame();
            long Cycle(bool warm)
            {
                var pr = new HeadlessScrollProducer(window, host, center) { Device = (byte)ScrollDeviceClass.Touchpad };
                long worst = 0;
                void Acc(FrameStats f) { if (!warm && f.HotPhaseAllocBytes > worst) worst = f.HotPhaseAllocBytes; }
                pr.ContactBegin(0f); Acc(pr.Frame(16f));
                for (int i = 0; i < 6; i++) { pr.Ms += 8; pr.ContactUpdate(20f); Acc(pr.Frame(16f)); }
                pr.MomentumBegin(); Acc(pr.Frame(16f));
                for (int i = 0; i < 8; i++) { pr.Ms += 8; pr.MomentumUpdate(12f); Acc(pr.Frame(16f)); }   // OS inertia sink cadence
                pr.MomentumEnd(); Acc(pr.Frame(16f));
                pr.WheelNotch(2f); Acc(pr.Frame(16f));
                for (int i = 0; i < 30; i++) Acc(pr.Frame(16f));
                return worst;
            }
            Cycle(warm: true);   // JIT the whole path outside the measured window
            for (int i = 0; i < 40; i++) host.RunFrame();
            long worst = Cycle(warm: false);
            Check("gate.scroll.alloc-zero a full contact+fling+momentum+wheel cycle (incl. the OS-momentum sink cadence) allocates 0 managed bytes on the hot half (phases 6–13)",
                worst == 0, $"worstHotAlloc={worst}B across the scripted cycle");
        }

        // gate.scroll.anchor-repin-under-gesture (Fix 1: the homepage touchpad-jitter repro): jump DEEP into a MEASURED
        // virtual list (the sticky-gate raw-ScrollRef pattern, so the rows above the jump target stay UNREALIZED at their
        // 40px estimate), then drag UPWARD — rows entering from above realize at 64px, and every correction to a row
        // strictly ABOVE the anchor fires the virtualization anchor re-pin (FlexLayout.RecordAnchorShift) with a +24 delta
        // WHILE the touchpad contact gesture is tracking. (A downward drag from the top is vacuous: corrections land at or
        // below the anchor and never move OffsetOf(anchorIndex).) Fix 1 records each re-pin as a coordinate shift
        // (ScrollState.PendingAnchorShift) the phase-7 integrator drains into the resampler anchor (_rs.Anchor), so the
        // finger-driven offset moves WITH the re-pin instead of being overwritten/fought a tick later. Decomposition: the
        // finger leg is reconstructed INDEPENDENTLY of the offset — exactly as gate.scroll.contact-1to1: one packet/frame
        // at the present time keeps the resampler interpolating the constant-velocity line ⇒
        // finger = −vel·(present − ResampleLatencyMs − t0). The remaining term Σshift = off − latch − finger must then be
        // a genuine accumulation of anchor re-pin deltas:
        //   • FIRED (maxShift ≥ ~one 24-DIP correction) — the discriminator: on pre-fix code TouchpadTracking overwrites
        //     the pin with Clamp(unshifted anchor + xStar) next tick, so Σshift never accumulates (or oscillates);
        //   • NON-NEGATIVE (over-measure rows only grow content above the anchor; a dropped re-pin makes it lag);
        //   • MONOTONE non-decreasing (a fought re-pin oscillates — the felt jitter);
        //   • BOUNDED by the total possible above-correction (rowsAbove·overMeasure).
        // Σshift is NOT compared to an exact predicted value: the per-frame re-pin delta depends on the internal
        // budgeted-realize schedule (which above-viewport rows correct that frame) — an implementation detail.
        // Tolerance: 0.5 DIP (the contact-1to1 interpolation bound; the shift accumulation is exact POD-float arithmetic).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("anchor-repin-gesture", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new AnchorRepinProbe());
            host.RunFrame();
            var vp = host.Scene.Root;
            // Jump deep without realizing the rows above (raw ScrollRef write, the sticky-gate pattern): rows < ~400 keep
            // their 40px estimate, so the upward drag below realizes them mid-gesture and fires genuine re-pins.
            const float seed = 16000f;
            {
                ref ScrollState st = ref host.Scene.ScrollRef(vp);
                st.OffsetY = seed; st.TargetY = seed;
            }
            window.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(8f, 8f), 0, 0));
            for (int i = 0; i < 12; i++) host.RunFrame();   // let the realize window + local corrections settle at the seed
            var prod = new HeadlessScrollProducer(window, host, new Point2(150, 150)) { Device = (byte)ScrollDeviceClass.Touchpad };
            const float vel = 0.9f;   // DIP/ms upward — ~860 DIP over the run, ~20 estimate-priced rows entering from above
            const float overMeasure = AnchorRepinProbe.Real - AnchorRepinProbe.Estimate;   // 24 DIP per row
            host.Scene.TryGetScroll(vp, out var sL); float latchOff = sL.OffsetY;   // settle may itself have re-pinned; latch from live
            double t0 = prod.FrameMs;
            prod.ContactBegin(0f); prod.Frame(16f);
            bool shiftNonNeg = true, shiftMonotone = true, shiftBounded = true;
            float prevShift = 0f, maxShift = 0f; bool havePrev = false; int frames = 0;
            for (int kf = 0; kf < 60; kf++)
            {
                prod.Ms = (uint)prod.FrameMs;                  // deliver one packet AT the present time (interpolation regime)
                prod.ContactUpdate(-vel * 16f);                // UPWARD — toward the unrealized estimate-priced region
                double present = prod.FrameMs;
                prod.Frame(16f);
                host.Scene.TryGetScroll(vp, out var s);
                if (kf < 3 || s.Phase != ScrollIntegrator.TouchpadTracking) continue;
                if (!(s.OffsetY > 1f)) continue;                                                 // well clear of the top clamp
                float finger = (float)(-vel * (present - ScrollTuning.ResampleLatencyMs - t0));  // INDEPENDENT resampled finger position
                float shift = s.OffsetY - latchOff - finger;                                     // observed Σ(anchor re-pin deltas)
                if (havePrev && shift - prevShift < -0.5f) shiftMonotone = false;    // a fought re-pin oscillates (the felt jitter)
                if (shift < -0.5f) shiftNonNeg = false;                              // a dropped re-pin makes the offset lag the finger
                if (shift > s.AnchorIndex * overMeasure + 1f) shiftBounded = false;  // ≤ total possible above-correction
                maxShift = MathF.Max(maxShift, shift);
                prevShift = shift; havePrev = true; frames++;
            }
            bool firedRepin = maxShift >= overMeasure - 4f;   // ≥ ~one genuine 24-DIP re-pin — the scenario can't go vacuous
            Check("gate.scroll.anchor-repin-under-gesture an upward monotone touchpad gesture from a deep seed realizes estimate-priced rows above the anchor mid-gesture, and the offset stays = latch + resampled-finger + a FIRED/non-negative/monotone/bounded Σ(anchor re-pin deltas) — the re-pin is consumed by the phase-7 integrator (Fix 1), never dropped or fought",
                firedRepin && shiftNonNeg && shiftMonotone && shiftBounded && frames >= 20,
                $"frames={frames} maxRepinShift={maxShift:0.00} firedRepin={firedRepin} shiftNonNeg={shiftNonNeg} shiftMonotone={shiftMonotone} shiftBounded={shiftBounded}");
        }

        // gate.scroll.wheel-chase-extent-shrink (Fix 1 tail: the ArrangeViewport PendingTarget re-clamp): a WheelAnimating
        // chase is seeded toward the bottom of a tall list, then the content extent is shrunk HARD (row count 400 → 60)
        // mid-chase so maxOff collapses far below the accumulated PendingTargetY. ArrangeViewport now re-clamps
        // PendingTargetX/Y (NaN-guarded) to the live [0,max] extent, so the chase rides the shrunk extent, lands on the new
        // bottom, and SETTLES to Idle — instead of a stale target beyond the moving clamp keeping the offset pinned in a
        // never-settling WheelAnimating fight (the near-bottom oscillation / bounce). Assert: the chase never reverses
        // against its down direction; PendingTargetY is re-clamped onto the new extent (or NaN once settled); the chase
        // reaches Idle at the corrected bottom.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("wheel-chase-shrink", new Size2(360, 460), 1f)); window.Show();
            var probe = new ShrinkChaseProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.Input.SmoothScroll = true;   // a mouse notch drives a WheelAnimating chase (accumulated PendingTarget), not a synchronous jump
            host.RunFrame();
            var vp = host.Scene.Root;
            // Seed a large accumulated chase toward the bottom (WheelNotch is in notch units × PerNotchDip): 480 notches ×
            // 48 = 23040 DIP, just under the initial maxOff (400·60 − 300 = 23700) so it seeds without being clamped.
            host.Input.Dispatch(new[] { new InputEvent(InputKind.Wheel, new Point2(150, 150), 0, 0, WheelNotch: 480f, Pointer: PointerKind.Mouse, TimestampMs: 1000) });
            host.Scene.TryGetScroll(vp, out var seeded);
            bool seededChase = seeded.Phase == ScrollIntegrator.WheelAnimating && !float.IsNaN(seeded.PendingTargetY) && seeded.PendingTargetY > 10000f;
            // Shrink the content HARD before the chase advances: 400 → 60 rows ⇒ content 3600, maxOff 3300 — far below the
            // 23040 target. The re-clamp must pull PendingTargetY down onto the new extent; without it the chase would keep
            // fighting a target beyond the clamp and never settle.
            probe.Count.Value = 60;
            float prevOff = seeded.OffsetY, worstBackStep = 0f; bool settled = false;
            for (int f = 0; f < 3000; f++)
            {
                host.RunFrame();
                host.Scene.TryGetScroll(vp, out var s);
                float d = s.OffsetY - prevOff;
                if (d < worstBackStep) worstBackStep = d;   // most-negative step against the down-chase
                prevOff = s.OffsetY;
                if (s.Phase == ScrollIntegrator.Idle) { settled = true; break; }
            }
            host.Scene.TryGetScroll(vp, out var fin);
            float newMax = MathF.Max(0f, fin.ContentH - fin.ViewportH);
            bool noReversal = worstBackStep >= -0.5f;                                                        // never steps backward (settling is fine)
            bool targetReclamped = float.IsNaN(fin.PendingTargetY) || fin.PendingTargetY <= newMax + 0.5f;   // rode the shrunk extent
            bool landed = Near(fin.OffsetY, newMax, 2f);                                                     // ended at the corrected bottom
            Check("gate.scroll.wheel-chase-extent-shrink a WheelAnimating chase toward the bottom survives the content extent shrinking far below its target mid-chase — ArrangeViewport re-clamps PendingTargetY onto the live extent so the offset never reverses, lands on the corrected bottom, and settles to Idle (no stale-target never-settling fight)",
                seededChase && noReversal && targetReclamped && landed && settled,
                $"seeded={seededChase} pendingSeed={seeded.PendingTargetY:0} newMax={newMax:0} finalOff={fin.OffsetY:0} finalPending={fin.PendingTargetY:0} worstBackStep={worstBackStep:0.00} settled={settled}");
        }
    }

    // ── Touch Phase-4 snap + overscroll exit criteria (gate.touch4.*): a touch fling retargets its friction decay to land
    // EXACTLY on a configured snap point (the ScrollSnap applicable-zone math + the ScrollIntegrator velocity re-solve), the
    // snap landing is dt-invariant (the integrator-determinism sweep extended to a snap fling), a touch pan PAST the clamp
    // boundary produces a damped rubber-band displacement that springs back to exactly 0 (while ScrollState.Offset NEVER
    // leaves [0, max] — asserted via state, not pixels), a WHEEL past the edge stays hard-clamped with NO band, and the
    // whole overscroll+spring+snap sequence is 0-alloc on the hot half. Reuses the Phase-1 touch harness.
    static void TouchSnapOverscrollChecks(StringTable strings)
    {
        var fonts = new HeadlessFontSystem(strings);

        // gate.touch4.fling-snap-lands-on-snap: a flick over a snap-configured list (SnapInterval = RowH) retargets its
        // decay so the offset settles on an EXACT RowH multiple (interior — the content is large, so the snap target is
        // never the clamp). Without snapping the 0.95/s decay settles wherever v_min/k lands (an arbitrary sub-row offset).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("touch4-snap", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new SnapFlingProbe());
            host.RunFrame();
            var vp = host.Scene.Root;
            host.Scene.ScrollRef(vp).SnapInterval = SnapFlingProbe.RowH;   // survives reconcile (the patch never touches snap fields)

            // A modest flick (the 0.95/s decay is near-frictionless, so even a slow flick coasts many rows). Settle to the
            // snap with a generous frame budget (the free-fling gate uses 600; a snap target can be ~tens of rows away).
            TouchGesture(window, host, new Point2(150, 300), new Point2(150, 240), 10, pointerId: 51, msPerStep: 16f);
            int settledAt = -1;
            for (int i = 0; i < 4000; i++) { host.RunFrame(); host.Scene.TryGetScroll(vp, out var s); if (s.Phase == 0) { settledAt = i; break; } }
            host.Scene.TryGetScroll(vp, out var settled);
            float rem = settled.OffsetY % SnapFlingProbe.RowH;
            float distToSnap = MathF.Min(rem, SnapFlingProbe.RowH - rem);   // distance to the nearest RowH multiple
            float maxOff = MathF.Max(0f, settled.ContentH - settled.ViewportH);
            bool onSnap = distToSnap < 0.5f;
            bool interior = settled.OffsetY > SnapFlingProbe.RowH && settled.OffsetY < maxOff - SnapFlingProbe.RowH;   // a real snap, not the clamp
            bool settledMode = settled.Phase == 0 && settled.FlingVelocity == 0f;
            Check("gate.touch4.fling-snap-lands-on-snap a touch flick over a snap-configured virtual list (SnapInterval=RowH) retargets its friction decay to settle EXACTLY on a RowH multiple, interior to the content (not the clamp)",
                onSnap && interior && settledMode && settledAt >= 0,
                $"offset={settled.OffsetY:0.###} distToSnap={distToSnap:0.###} interval={SnapFlingProbe.RowH} interior={interior} mode={settled.Phase} settledAtFrame={settledAt}");
        }

        // gate.touch4.snap-fling-dt-invariant: the integrator-determinism sweep, extended to a SNAP fling. The same event
        // script replayed at dt ∈ {8.33, 16.67, 33.3} ms lands on the IDENTICAL snap offset (the snap value is a property
        // of the event-clock velocity + the snap grid, NOT the animation timestep — so unlike a free fling, which settles
        // at dt-dependent offsets, a SNAP fling settles at the same value every dt). And the arena resolution trace stays
        // identical across the sweep (the validation.md:1145 property — the snap landing is downstream of the arbitration).
        {
            string r833 = SnapFlingResolutionTrace(strings, 8.33f, out float o833);
            string r1667 = SnapFlingResolutionTrace(strings, 16.67f, out float o1667);
            string r333 = SnapFlingResolutionTrace(strings, 33.3f, out float o333);
            bool traceIdentical = r833 == r1667 && r1667 == r333;
            bool landingsIdentical = Near(o833, o1667, 0.5f) && Near(o1667, o333, 0.5f);   // dt-INVARIANT (the snap pins the landing)
            float interval = SnapFlingProbe.RowH;
            float rem = o1667 % interval; float dist = MathF.Min(rem, interval - rem);
            bool onSnap = dist < 0.5f;
            if (!traceIdentical) Console.WriteLine($"    [snap dt-sweep diff]\n8.33:\n{r833}16.67:\n{r1667}33.3:\n{r333}");
            Check("gate.touch4.snap-fling-dt-invariant the §12.6 integrator sweep extended to a SNAP fling: the same event script at dt ∈ {8.33,16.67,33.3}ms produces an IDENTICAL arena resolution trace AND lands on the IDENTICAL snap offset (the snap pins the landing dt-invariantly, unlike a free fling), the offset an exact snap multiple",
                traceIdentical && landingsIdentical && onSnap,
                $"traceIdentical={traceIdentical} landings=({o833:0.#},{o1667:0.#},{o333:0.#}) identical={landingsIdentical} distToSnap={dist:0.###}");
        }

        // gate.touch4.overscroll-springback: a touch pan dragging PAST the top clamp (at offset 0, finger pulls DOWN)
        // produces a transient damped displacement band (OverscrollPx != 0) WHILE OffsetY stays pinned at 0 — the band is a
        // separate visual term, the clamp contract is never relaxed. On release the band springs back to EXACTLY 0 (phase-7
        // StepSpring). Asserted via ScrollState (recorder/state, not pixels): the offset NEVER leaves [0, max] across the
        // whole drag+release, the band peaks while dragging, and it settles at 0.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("touch4-overscroll", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
            host.RunFrame();
            var vp = host.Scene.Root;
            host.Scene.TryGetScroll(vp, out var sc0);
            float maxOff = MathF.Max(0f, sc0.ContentH - sc0.ViewportH);

            // Drive a pan past the TOP: down at y=120, then pull the finger DOWN (y increases) to y=300 — content wants to
            // go above offset 0 ⇒ clamps at 0, the excess becomes a negative band. Manual moves so we can read the band
            // mid-drag and confirm the offset never goes negative.
            uint t = s_touchClockMs;
            var ev = new InputEvent[1];
            ev[0] = Touch(InputKind.PointerDown, new Point2(150, 120), t, 61); host.Input.Dispatch(ev); host.RunFrame();
            float worstNegOffset = 0f, peakBand = 0f, worstOverMax = 0f;
            for (int i = 1; i <= 12; i++)
            {
                t += 16;
                ev[0] = Touch(InputKind.PointerMove, new Point2(150, 120 + i * 15), t, 61); host.Input.Dispatch(ev); host.RunFrame();
                host.Scene.TryGetScroll(vp, out var s);
                if (s.OffsetY < worstNegOffset) worstNegOffset = s.OffsetY;
                if (s.OffsetY - maxOff > worstOverMax) worstOverMax = s.OffsetY - maxOff;
                if (MathF.Abs(s.OverscrollPx) > MathF.Abs(peakBand)) peakBand = s.OverscrollPx;
            }
            host.Scene.TryGetScroll(vp, out var dragging);
            bool bandWhileDragging = MathF.Abs(dragging.OverscrollPx) > 1f;     // a real displacement past the edge
            bool offsetPinned = dragging.OffsetY == 0f;                          // the clamp held — offset never went negative
            float capLimit = TouchFlingSettleProbe_ViewportH(host, vp) * 0.1f;   // WinUI 10% overpan cap
            bool bandCapped = MathF.Abs(peakBand) <= capLimit + 0.5f;            // damping asymptotes to the cap

            // Release: the band springs back to exactly 0 (and the offset still never leaves [0, max]).
            t += 16;
            ev[0] = Touch(InputKind.PointerUp, new Point2(150, 300), t, 61); host.Input.Dispatch(ev); host.RunFrame();
            s_touchClockMs = t + 1000;
            bool offsetOk = true;
            float bandAfter = 1f;
            for (int i = 0; i < 200; i++)
            {
                host.RunFrame();
                host.Scene.TryGetScroll(vp, out var s);
                if (s.OffsetY < -0.001f || s.OffsetY > maxOff + 0.001f) offsetOk = false;
                bandAfter = s.OverscrollPx;
                if (s.OverscrollPx == 0f && s.Phase == 0) break;
            }
            bool sprungToZero = bandAfter == 0f;
            Check("gate.touch4.overscroll-springback a touch pan past the top clamp shows a damped displacement band (peaks ≤ 10%-viewport cap) WHILE OffsetY stays pinned at 0 (offset never negative, never > max across the whole drag), then springs back to EXACTLY 0 on release",
                bandWhileDragging && offsetPinned && bandCapped && worstNegOffset == 0f && worstOverMax <= 0f && sprungToZero && offsetOk,
                $"peakBand={peakBand:0.##} cap={capLimit:0.##} offsetPinned={offsetPinned} worstNeg={worstNegOffset:0.##} sprungTo={bandAfter:0.###} offsetOk={offsetOk}");
        }

        // gate.touch4.wheel-hard-clamps-no-band: a WHEEL past the top edge (negative delta at offset 0) stays HARD-clamped
        // — OffsetY pinned at 0, and NO overscroll band is produced (the band is touch-pan-only; wheel/keyboard/programmatic
        // are never rubber-banded, the SetScrollOffset clamp contract). The existing fling-stops-at-clamp gate stays green.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("touch4-wheel-clamp", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
            host.RunFrame();
            var vp = host.Scene.Root;
            var ptr = new Point2(150, 200);
            // Already at offset 0 (top). A big negative wheel delta tries to go above the top: must stay 0 with no band.
            for (int i = 0; i < 5; i++) { window.QueueInput(new InputEvent(InputKind.Wheel, ptr, 0, 0, -50_000f)); host.RunFrame(); }
            host.Scene.TryGetScroll(vp, out var top);
            bool topClamped = top.OffsetY == 0f && top.OverscrollPx == 0f;
            // And past the BOTTOM: scroll way down, then keep wheeling past max — pinned at max, still no band.
            for (int i = 0; i < 30; i++) { window.QueueInput(new InputEvent(InputKind.Wheel, ptr, 0, 0, 50_000f)); host.RunFrame(); }
            host.Scene.TryGetScroll(vp, out var bot);
            float maxOff = MathF.Max(0f, bot.ContentH - bot.ViewportH);
            bool botClamped = Near(bot.OffsetY, maxOff, 0.5f) && bot.OverscrollPx == 0f;
            Check("gate.touch4.wheel-hard-clamps-no-band a wheel past the top AND past the bottom stays hard-clamped (OffsetY pinned at the boundary) with NO overscroll band — the rubber band is touch-pan-only, the clamp contract is never relaxed for wheel/keyboard/programmatic",
                topClamped && botClamped,
                $"top=(off {top.OffsetY:0},band {top.OverscrollPx:0.##}) bottom=(off {bot.OffsetY:0}->max {maxOff:0},band {bot.OverscrollPx:0.##})");
        }

        // gate.touch4.alloc-zero: the overscroll drag + spring-back + a snap fling sequence allocates 0 managed bytes on
        // the hot half. The struct-only bound list (Fill channel only) keeps the reconcile edge clean, so the band write,
        // the phase-7 spring step, the snap retarget + decay, and the SetScrollOffset re-realize must all be 0-alloc.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("touch4-alloc", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new SnapFlingProbe());
            host.RunFrame();
            var vp = host.Scene.Root;
            host.Scene.ScrollRef(vp).SnapInterval = SnapFlingProbe.RowH;
            for (int i = 0; i < 30; i++) host.RunFrame();   // drain residual

            // Warm the overscroll + snap paths (JIT) outside the measured window.
            DriveOverscrollAndSnap(window, host, vp);
            for (int i = 0; i < 40; i++) host.RunFrame();

            long worst = DriveOverscrollAndSnap(window, host, vp);   // returns worst hot-phase alloc across the sequence
            for (int i = 0; i < 60; i++) { var f = host.RunFrame(); if (f.HotPhaseAllocBytes > worst) worst = f.HotPhaseAllocBytes; }
            Check("gate.touch4.snap-overscroll-alloc-zero an overscroll pan-past-edge + spring-back + snap fling sequence allocates 0 managed bytes on the hot half (the band write, the phase-7 spring step, the snap retarget + friction decay, and the virtual re-realize stayed clean)",
                worst == 0, $"worstHotAlloc={worst}B");
        }
    }

    // ── Touchpad scroll-feel exit criteria (gate.touchpad.*/gate.scroll.*): the scroll-feel-rework-v2 physics kernels —
    // the exact closed-form CoastStep fling integral (distance + frame-rate independence), the iOS asymptotic rubber-band
    // + its exact inverse, the ω=12.5 snap-back, and the WheelAnimating hard-clamped PendingTarget chase (§4.2/§4.3/§4.4/
    // §4.5). The deleted v1 second integrator (TickTouchpad/PanTouchpad/ShapeTouchpadPacketDelta/soft-knee band) is gone —
    // touchpad/PTP contact now rides the phase-tagged contract into the single phase-7 integrator (see ScrollV2ValidationChecks).
    static void TouchpadFeelChecks(StringTable strings)
    {
        var fonts = new HeadlessFontSystem(strings);

        // gate.scroll.decay-kernel-distance: seed a coast at v0 = 1000 px/s and integrate OverscrollPhysics.CoastStep at a
        // fixed 60 Hz dt until the speed drops below the production settle cutoff (FlingMinVelocityPxPerS = 13 px/s). The
        // total coast = ~330 px (the v→0 asymptote is v0/−ln(0.05) = 333.8 px; the 13 px/s cutoff stops it ~4 px short).
        // This explicitly locks the reusable kernel to the Windows-like feel and its roughly 1.5s 1000 px/s tail.
        {
            const float v0 = 1000f, dtMs = 1000f / 60f;
            float settle = ScrollIntegrator.FlingMinVelocityPxPerS;   // tracks the production settle cutoff (13 px/s) so the gate stays honest
            float v = v0, coast = 0f; int frames = 0;
            while (frames < 100000)
            {
                coast += OverscrollPhysics.CoastStep(ref v, dtMs, ScrollIntegrator.FlingDecayPerS);
                frames++;
                if (MathF.Abs(v) < settle) break;
            }
            bool ok = Near(ScrollIntegrator.FlingDecayPerS, 0.05f, 0.0001f)
                   && Near(coast, 330f, 2f)
                   && frames >= 85 && frames <= 92;
            Check("gate.scroll.decay-kernel-distance a v0=1000 px/s coast at fixed 60 Hz settles at ~330 px in ~1.5s (locks WinUI-like FlingDecayPerS=0.05 + the 13 px/s settle)",
                ok, $"decay={ScrollIntegrator.FlingDecayPerS:0.###} coast={coast:0.##}px (expect ~330 ±2) frames={frames} (expect 85..92) k={-MathF.Log(ScrollIntegrator.FlingDecayPerS):0.###}");
        }

        // gate.scroll.decay-kernel-frame-rate-independence: the SAME v0=1000 px/s coast integrated at dt = 1000/60, 1000/120, 1000/144
        // settles at the IDENTICAL distance (within 0.5 px). The exact closed-form per-step integral (Δpos = v(1−decay^dt)/k)
        // telescopes to the same geometric sum at any timestep — a plain v·dt Riemann step would diverge ~4 px across these
        // rates. Locks the Pow(decay, dt) decay form AND the closed-form position step.
        {
            static float Coast(float dtMs)
            {
                float v = 1000f, coast = 0f; int frames = 0;
                while (frames < 100000)
                {
                    coast += OverscrollPhysics.CoastStep(ref v, dtMs, ScrollIntegrator.FlingDecayPerS);
                    frames++;
                    if (MathF.Abs(v) < ScrollIntegrator.FlingMinVelocityPxPerS) break;   // production settle cutoff (13 px/s)
                }
                return coast;
            }
            float c60 = Coast(1000f / 60f), c120 = Coast(1000f / 120f), c144 = Coast(1000f / 144f);
            bool ok = Near(c60, c120, 0.5f) && Near(c120, c144, 0.5f) && Near(c60, c144, 0.5f);
            Check("gate.scroll.decay-kernel-frame-rate-independence the same v0=1000 px/s coast at dt∈{60,120,144}Hz settles at the IDENTICAL distance within 0.5px (the exact closed-form integral is frame-rate-independent; v·dt would diverge ~4px)",
                ok, $"coast 60Hz={c60:0.###} 120Hz={c120:0.###} 144Hz={c144:0.###} (spread={MathF.Max(MathF.Max(c60, c120), c144) - MathF.Min(MathF.Min(c60, c120), c144):0.###})");
        }

        // gate.touchpad.band-roundtrip (v2): the iOS rubber-band must round-trip — ExcessFromBand is the EXACT inverse of
        // BandFromExcess for ALL excess (the v2 map never saturates, so the inverse holds everywhere with no early-out
        // branch — scroll-feel-rework-v2 §4.4/§8 gate 7). With vp=3000 the asymptote is d=0.15·vp=450; x∈{5,50,200} sit
        // in the near-linear region and x∈{600,3000} are the OLD saturation points (2·limit / 10·limit at the old
        // limit=300) that the v1 min()-knee could NOT invert — v2 round-trips them within 0.5 px.
        {
            const float vp = 3000f;   // d = 0.15·vp = 450 ⇒ band(200)=88.4, band(3000)=353.6, all < d (never reaches the wall)
            float worst = 0f;
            foreach (float x in new[] { 5f, 50f, 200f, 600f, 3000f })
            {
                float band = OverscrollPhysics.BandFromExcess(x, vp);
                float rt = OverscrollPhysics.ExcessFromBand(band, vp);
                worst = MathF.Max(worst, MathF.Abs(rt - x));
            }
            bool ok = worst < 0.5f;
            Check("gate.touchpad.band-roundtrip ExcessFromBand(BandFromExcess(x)) ≈ x for x∈{5,50,200,600,3000} within 0.5px (the v2 iOS map never saturates ⇒ the closed-form inverse is exact everywhere, incl. at/above the old saturation point)",
                ok, $"worstRoundTripErr={worst:0.######}px");
        }

        // (The pre-rework touchpad gates — progressive-packet-curve, settle-determinism, os-tail-no-double-inertia,
        // the touchpad alloc-zero, inter-burst-no-restart, edge-release-bounded, edge-tail-no-plateau — are DELETED with
        // the second integrator they gated: ShapeTouchpadPacketDelta / TickTouchpad / TouchpadActive / the velocity-
        // enveloped band no longer exist. Their behaviors re-gate on the phase-tagged contract per
        // docs/plans/scroll-feel-rework-design.md §12/§13 (gates 2/5/6/9/11).)

        // gate.scroll.phase-release-velocity — regression lock for two ON-DEVICE-MEASURED estimator defects on the
        // phase-contract (touchpad wheel-fallback) path:
        // (a) FOLD FIDELITY (the axis-swap defect): TWO ScrollUpdate packets per frame — the ring folds each pair and
        //     deposits the overwritten packet's running sums into the velocity side ring. A constant-velocity vertical
        //     stream must read the EXACT hand speed; the swapped-axis deposit fed the pan axis flat plateaus + per-frame
        //     spikes and inflated the release ~4-6× (oversized flings, violent edge bounces). An abrupt stop at speed
        //     still seeds exactly ONE fling (the trailing gate must not kill real flicks).
        // (b) DECEL-THEN-SILENCE (the phantom-fling defect, v2 single-gate form): a stream decelerating to near-rest and
        //     then going SILENT ≥40ms before the lift seeds NO fling. v1 leaned on a trailing-32ms displacement gate to
        //     beat the work-energy ledger's remembered START energy; v2 DELETES that dual gate (scroll-feel-rework-v2
        //     §4.3) — the completed tail + silence is caught by AssumeStoppedMs alone (newest sample older than 40ms at
        //     lift ⇒ v=0). One window, one gate. (A decel ramp still MOVING at lift correctly seeds a proportional fling
        //     — that is the honest v2 hand speed, not a phantom; the double-inertia case is specifically the silent tail.)
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("phase-release", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
            host.RunFrame();
            var vp = host.Scene.Root;
            var pos = new Point2(150, 200);
            const byte Fb = (byte)ScrollDeviceClass.WheelHiResFallback;
            float decay1 = MathF.Exp(MathF.Log(ScrollIntegrator.FlingDecayPerS) * 16f / 1000f);   // the End frame's phase-7 tick decays the fresh seed once

            // (a) 1000 px/s hand speed: ScrollBegin + 16 ScrollUpdates of 8 DIP at 8 ms stamps, TWO per frame.
            uint t = 5000;
            window.QueueInput(new InputEvent(InputKind.ScrollBegin, pos, 0, 0, ScrollDelta: 8f,
                Pointer: PointerKind.Touchpad, TimestampMs: t, PointerId: 9, DeviceClassRaw: Fb));
            host.RunFrame();
            for (int i = 0; i < 8; i++)
            {
                window.QueueInput(new InputEvent(InputKind.ScrollUpdate, pos, 0, 0, ScrollDelta: 8f,
                    Pointer: PointerKind.Touchpad, TimestampMs: t += 8, PointerId: 9, DeviceClassRaw: Fb));
                window.QueueInput(new InputEvent(InputKind.ScrollUpdate, pos, 0, 0, ScrollDelta: 8f,
                    Pointer: PointerKind.Touchpad, TimestampMs: t += 8, PointerId: 9, DeviceClassRaw: Fb));
                host.RunFrame();   // the pair coalesces in the ring; the overwritten packet feeds the side ring
            }
            window.QueueInput(new InputEvent(InputKind.ScrollEnd, pos, 0, 0,
                Pointer: PointerKind.Touchpad, TimestampMs: t, PointerId: 9, DeviceClassRaw: Fb));   // lift = last packet's stamp (design §2)
            host.RunFrame();
            host.Scene.TryGetScroll(vp, out var scA);
            float vFold = MathF.Abs(scA.FlingVelocity);
            bool foldExact = scA.Phase == ScrollIntegrator.Fling && MathF.Abs(vFold - 1000f * decay1) <= 1000f * decay1 * 0.03f;   // ±3%
            for (int i = 0; i < 400; i++) { host.RunFrame(); host.Scene.TryGetScroll(vp, out var s); if (s.Phase == 0) break; }

            // (b) decelerate to near-rest THEN a ≥40ms silence: steady 8-DIP packets, then a 4/2/0.6/0.3 ramp (one per
            // frame, 16 ms stamps), then the lift arrives 60 ms after the last packet — a completed tail then silence. The
            // v2 single 40ms IMPULSE window would read ~90 px/s over the ramp, but AssumeStoppedMs (newest sample >40ms
            // before lift) zeroes it ⇒ NO fling. This is the v2 double-inertia guard (the deleted trailing-32ms dual gate).
            uint t2 = t + 2000;
            window.QueueInput(new InputEvent(InputKind.ScrollBegin, pos, 0, 0, ScrollDelta: 8f,
                Pointer: PointerKind.Touchpad, TimestampMs: t2, PointerId: 9, DeviceClassRaw: Fb));
            host.RunFrame();
            foreach (float d in new[] { 8f, 8f, 8f, 8f, 8f, 8f, 8f, 4f, 2f, 0.6f, 0.3f })
            {
                window.QueueInput(new InputEvent(InputKind.ScrollUpdate, pos, 0, 0, ScrollDelta: d,
                    Pointer: PointerKind.Touchpad, TimestampMs: t2 += 16, PointerId: 9, DeviceClassRaw: Fb));
                host.RunFrame();
            }
            window.QueueInput(new InputEvent(InputKind.ScrollEnd, pos, 0, 0,
                Pointer: PointerKind.Touchpad, TimestampMs: t2 + 60, PointerId: 9, DeviceClassRaw: Fb));   // 60ms silence → AssumeStopped → v=0
            host.RunFrame();
            host.Scene.TryGetScroll(vp, out var scB);
            bool decelNoFling = scB.Phase != ScrollIntegrator.Fling || MathF.Abs(scB.FlingVelocity) < 1f;

            Check("gate.scroll.phase-release-velocity the phase-contract release estimator: a ring-FOLDED (two packets/frame) constant-velocity stream reads the exact hand speed and an abrupt stop seeds ONE fling (axis-swap regression lock); a decelerate-then-silence stream seeds NO fling (v2 §4.3 single 40ms IMPULSE window + AssumeStoppedMs — the deleted dual gate)",
                foldExact && decelNoFling,
                $"fold={vFold:0} (expect {1000f * decay1:0} ±3%) phase={scA.Phase} decelFling={(scB.Phase == ScrollIntegrator.Fling ? scB.FlingVelocity : 0f):0.0}");
        }

        // gate.touchpad.mouse-wheel-takeover: a phase-driven scroll gesture (touchpad fallback) can still own a TOP
        // rubber-band when a physical mouse wheel arrives (no touchpad-up event exists). The mouse must synchronously take
        // ownership: cancel the gesture (CancelGesture), clear the band, reset Offset==Target, then seed ONE
        // WheelAnimating chase (accumulated PendingTarget; scroll-feel-rework-v2 §4.2). Historic defect this locks: two
        // scroll owners writing the same ScrollState concurrently produced positive OffsetY with a negative top band.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("tp-wheel-takeover", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
            host.RunFrame();
            host.Input.SmoothScroll = true;   // shipping Windows path: mouse wheel seeds WheelAnimating
            var vp = host.Scene.Root;
            var pos = new Point2(150, 200);

            // Pull above the top with two phase-contract contact packets (the wheel-fallback producer's shape) so the
            // gesture owns a real negative band.
            window.QueueInput(new InputEvent(InputKind.ScrollBegin, pos, 0, 0, ScrollDelta: -120f,
                Pointer: PointerKind.Touchpad, TimestampMs: 1000, PointerId: 7,
                DeviceClassRaw: (byte)ScrollDeviceClass.WheelHiResFallback));
            host.RunFrame();
            window.QueueInput(new InputEvent(InputKind.ScrollUpdate, pos, 0, 0, ScrollDelta: -120f,
                Pointer: PointerKind.Touchpad, TimestampMs: 1016, PointerId: 7,
                DeviceClassRaw: (byte)ScrollDeviceClass.WheelHiResFallback));
            host.RunFrame();
            host.Scene.TryGetScroll(vp, out var before);
            bool touchpadHeldBand = host.Input.GestureActive && before.OverscrollPx < -1f && before.OffsetY == 0f;

            // Dispatch the mouse event directly so the state is observed immediately after input ownership transfers,
            // before the integrator advances the newly-seeded WheelAnimating chase.
            var mouse = new[]
            {
                new InputEvent(InputKind.Wheel, pos, 0, 0, WheelNotch: 1f,
                    Pointer: PointerKind.Mouse, TimestampMs: 1032),
            };
            host.Input.Dispatch(mouse);
            host.Scene.TryGetScroll(vp, out var handed);
            bool cleanHandoff = !host.Input.GestureActive
                                && handed.OverscrollPx == 0f && !handed.Overscrolling
                                && handed.OverscrollVel == 0f
                                && handed.Phase == ScrollIntegrator.WheelAnimating
                                && !float.IsNaN(handed.PendingTargetY) && handed.PendingTargetY > 0f
                                && handed.OffsetY == 0f && handed.TargetY == handed.OffsetY;

            float minOff = handed.OffsetY;
            bool noBandReturned = true;
            for (int i = 0; i < 30; i++)
            {
                host.RunFrame();
                host.Scene.TryGetScroll(vp, out var s);
                minOff = MathF.Min(minOff, s.OffsetY);
                noBandReturned &= s.OverscrollPx == 0f && !s.Overscrolling;
            }
            host.Scene.TryGetScroll(vp, out var after);
            bool wheelAdvanced = after.OffsetY > 5f && minOff >= 0f;
            Check("gate.touchpad.mouse-wheel-takeover a physical mouse wheel synchronously cancels an active phase-driven scroll gesture, clears its held overscroll band, and advances under one WheelAnimating owner (accumulated PendingTarget) — no positive offset + negative top-band dead zone",
                touchpadHeldBand && cleanHandoff && noBandReturned && wheelAdvanced,
                $"before=(active {touchpadHeldBand},off {before.OffsetY:0.0},band {before.OverscrollPx:0.0}) handoff=(active {host.Input.GestureActive},phase {handed.Phase},pending {handed.PendingTargetY:0},band {handed.OverscrollPx:0.0}) after=(off {after.OffsetY:0.0},band {after.OverscrollPx:0.0})");
        }

        // gate.scroll.wheel-accumulates-to-extent (v2 §4.2): a fast detented-wheel burst does NOT accumulate an unbounded
        // coast velocity — v1's WheelFlingMode + WheelFlingMaxVelocityPxPerS velocity cap is gone. Each notch advances the
        // accumulated, HARD-CLAMPED PendingTarget; a burst of many notches stops EXACTLY at min(Σnotch, content extent),
        // never past the edge (§2.2 extent asymmetry — a wheel hard-stops, never bands). The integrator then chases it with
        // the velocity-preserving crit-damped WheelAnimating spring.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("wheel-accum-extent", new Size2(360, 460), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchFlingSettleProbe());
            host.RunFrame();
            host.Input.SmoothScroll = true;   // exercise the shipping wheel path (WheelAnimating), not direct headless scrolling
            var pos = new Point2(150, 200);
            var burst = new InputEvent[16];
            for (int i = 0; i < burst.Length; i++)
                burst[i] = new InputEvent(InputKind.Wheel, pos, 0, 0, WheelNotch: 1f,
                    Pointer: PointerKind.Mouse, TimestampMs: (uint)(1000 + i * 4));
            host.Input.Dispatch(burst);   // all 16 accumulate at offset 0 (no tick between dispatches)
            host.Scene.TryGetScroll(host.Scene.Root, out var seeded);
            float perNotch = host.Input.Tuning.PerNotchDip(seeded.ViewportH);
            float maxOff = MathF.Max(0f, seeded.ContentH - seeded.ViewportH);
            float expected = MathF.Min(16f * perNotch, maxOff);   // §4.2: clamp(Σdistance, 0, max) — hard-stops at the extent
            bool capped = seeded.Phase == ScrollIntegrator.WheelAnimating
                          && !float.IsNaN(seeded.PendingTargetY)
                          && Near(seeded.PendingTargetY, expected, 0.5f)
                          && seeded.PendingTargetY <= maxOff + 0.5f;
            Check("gate.scroll.wheel-accumulates-to-extent a rapid 16-notch wheel burst accumulates the hard-clamped PendingTarget and stops EXACTLY at min(Σnotch, content extent) — no unbounded coast velocity, no overshoot past the edge (v2 §4.2 supersedes the v1 velocity cap)",
                capped, $"pending={seeded.PendingTargetY:0.###} expected={expected:0.###} maxOff={maxOff:0.###} perNotch={perNotch:0.#} phase={seeded.Phase}");
        }

        // gate.scroll.mouse-wheel-zero-dt-survives: the real stopwatch clock intentionally returns dt=0 on the first
        // interactive frame after Resync. The §5 dt≤0 Resync bail (now covering ALL states) must preserve the freshly
        // seeded WheelAnimating intent (Phase + PendingTarget) on the dt=0 frame — a zero-duration step made no movement
        // and must not be mistaken for a settle/clamp — then advance normally on the next positive tick.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("wheel-zero-dt", new Size2(360, 460), 1f)); window.Show();
            var clock = new ManualFrameTimeSource();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings,
                new TouchFlingSettleProbe(), frameTime: clock);
            host.RunFrame();   // initial layout, dt=0
            host.Input.SmoothScroll = true;
            var vp = host.Scene.Root;
            window.QueueInput(new InputEvent(InputKind.Wheel, new Point2(150, 200), 0, 0,
                WheelNotch: 1f, Pointer: PointerKind.Mouse, TimestampMs: 1000));
            host.RunFrame();   // input seeds WheelAnimating; clock still returns dt=0 → the tick bails, intent preserved
            host.Scene.TryGetScroll(vp, out var held);
            bool survivedZero = held.Phase == ScrollIntegrator.WheelAnimating && !float.IsNaN(held.PendingTargetY) && held.OffsetY == 0f;

            clock.Advance(16f);
            host.RunFrame();
            host.Scene.TryGetScroll(vp, out var advanced);
            bool advancedNext = advanced.Phase == ScrollIntegrator.WheelAnimating && advanced.OffsetY > 0f;
            Check("gate.scroll.mouse-wheel-zero-dt-survives a WheelAnimating chase survives the cadence-resync dt=0 frame (intent preserved) and moves on the next positive tick — no repeated no-scroll dead zone",
                survivedZero && advancedNext,
                $"held=(phase {held.Phase},pending {held.PendingTargetY:0},off {held.OffsetY:0.0}) advanced=(phase {advanced.Phase},off {advanced.OffsetY:0.0})");
        }
    }

    // (DriveTouchpadPan — the Wheel+PointerKind.Touchpad packet driver of the deleted second-integrator gates — is GONE
    // with them; headless touchpad streams script the phase-tagged contract directly, design §1/§13.)

    /// <summary>Viewport inner extent along the scroll axis (for the overscroll cap assertion). Reads the published
    /// ScrollState ViewportH/W per Orientation.</summary>
    static float TouchFlingSettleProbe_ViewportH(AppHost host, NodeHandle vp)
    {
        host.Scene.TryGetScroll(vp, out var sc);
        return sc.Orientation == 1 ? sc.ViewportW : sc.ViewportH;
    }

    /// <summary>Drive a touch pan PAST the top clamp (rubber band) + release (spring-back) + a snap flick, returning the
    /// worst <see cref="FrameStats.HotPhaseAllocBytes"/> across every frame of the sequence (the gate.touch4 0-alloc gate).
    /// The viewport must be a snap-configured SnapFlingProbe (so the flick exercises the snap retarget too).</summary>
    static long DriveOverscrollAndSnap(HeadlessWindow window, AppHost host, NodeHandle vp)
    {
        long worst = 0;
        var ev = new InputEvent[1];
        uint t = s_touchClockMs;
        // First flick up to an interior position (seeds a snap fling), let it settle.
        worst = Math.Max(worst, TouchGesture(window, host, new Point2(150, 360), new Point2(150, 140), 12, pointerId: 71, msPerStep: 16f));
        for (int i = 0; i < 120; i++) { var f = host.RunFrame(); if (f.HotPhaseAllocBytes > worst) worst = f.HotPhaseAllocBytes; host.Scene.TryGetScroll(vp, out var s); if (s.Phase == 0) break; }
        // Now drag past the bottom: pull the finger UP hard from a low anchor so the content runs past max → band.
        t = s_touchClockMs;
        ev[0] = Touch(InputKind.PointerDown, new Point2(150, 360), t, 72); host.Input.Dispatch(ev); { var f = host.RunFrame(); if (f.HotPhaseAllocBytes > worst) worst = f.HotPhaseAllocBytes; }
        for (int i = 1; i <= 10; i++)
        {
            t += 16;
            ev[0] = Touch(InputKind.PointerMove, new Point2(150, 360 - i * 18), t, 72); host.Input.Dispatch(ev);
            var f = host.RunFrame(); if (f.HotPhaseAllocBytes > worst) worst = f.HotPhaseAllocBytes;
        }
        t += 16;
        ev[0] = Touch(InputKind.PointerUp, new Point2(150, 180), t, 72); host.Input.Dispatch(ev); { var f = host.RunFrame(); if (f.HotPhaseAllocBytes > worst) worst = f.HotPhaseAllocBytes; }
        s_touchClockMs = t + 1000;
        for (int i = 0; i < 60; i++) { var f = host.RunFrame(); if (f.HotPhaseAllocBytes > worst) worst = f.HotPhaseAllocBytes; host.Scene.TryGetScroll(vp, out var s); if (s.OverscrollPx == 0f && s.Phase == 0) break; }
        return worst;
    }

    /// <summary>The snap-fling twin of <see cref="FlingResolutionTrace"/>: a snap-configured viewport (SnapInterval = RowH)
    /// flicked with a fixed event script at animation timestep <paramref name="dtMs"/>. The snap retarget makes the landing
    /// dt-INVARIANT (the same snap offset at every dt), while the arena resolution stays identical — the §12.6 integrator
    /// sweep over a SNAP fling. Returns the resolution signature; outputs the settled offset.</summary>
    static string SnapFlingResolutionTrace(StringTable strings, float dtMs, out float settledOff)
    {
        var fonts = new HeadlessFontSystem(strings);
        var rec = new GestureArenaRecorder();
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("det-snap-fling-dt", new Size2(360, 460), 1f)); window.Show();
        using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new SnapFlingProbe(), frameTime: new FixedFrameTimeSource(dtMs));
        host.RunFrame();
        host.Scene.ScrollRef(host.Scene.Root).SnapInterval = SnapFlingProbe.RowH;
        host.Input.Arena.Recorder = rec;
        var vp = host.Scene.Root;
        // A modest, fixed flick (event clock identical across the dt sweep ⇒ identical sampled velocity ⇒ identical snap
        // target). Generous settle budget so even the finest dt (8.33ms ⇒ ~4× the frames of 33.3ms) fully lands.
        TouchGesture(window, host, new Point2(150, 300), new Point2(150, 240), 10, pointerId: 93, msPerStep: 16f);
        for (int i = 0; i < 8000; i++) { host.RunFrame(); host.Scene.TryGetScroll(vp, out var sc); if (sc.Phase == 0) break; }
        host.Scene.TryGetScroll(vp, out var settled);
        settledOff = settled.OffsetY;
        return rec.ResolutionSignature();
    }

    // ── Touch Phase-4 SIP (software input panel / touch keyboard) trigger seam (input-a11y.md §10; gate.touch4.sip.*):
    // a TOUCH focus on an editable field requests the on-screen keyboard exactly once and a MOUSE focus never does (the
    // WinUI InputPaneHandler.cpp policy keyed off the focus pointer's device type); focus loss dismisses it; a simulated
    // InputPane Showing OccludedRect reflows the focused editor's caret above the pane (the WinUI EnsureFocusedElementInView
    // bring-into-view, dxaml InputPaneHandler.cpp). The headless HeadlessTextInput records the show/hide requests and
    // re-fires the OccludedRect callback on a test cue — VerticalSlice stays TerraFX-free (the Windows InputPane2 impl is
    // device-only). Reuses the Phase-1 touch harness (Touch / s_touchClockMs monotonic stamps).
    static void Touch4SipChecks(StringTable strings)
    {
        var fonts = new HeadlessFontSystem(strings);

        // (1) SHOW on touch focus / NOT on mouse focus: tap an EditableText with a touch contact ⇒ TryShowTouchKeyboard
        //     fires exactly once; a fresh field clicked with a MOUSE never raises the panel.
        int touchShow, mouseShow;
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("sip-show", new Size2(360, 320), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchEditInScrollerProbe());
            host.RunFrame();
            var ti = (HeadlessTextInput)window.TextInput;
            var field = FindRole(host.Scene, host.Scene.Root, AutomationRole.Text);
            var fr = host.Scene.AbsoluteRect(field);
            var p = new Point2(fr.X + 6f, fr.Y + fr.H / 2f);
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, p, t, 60)); host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerUp, p, t + 16, 60)); host.RunFrame();
            s_touchClockMs = t + 1000;
            touchShow = ti.ShowCount;
        }
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("sip-mouse", new Size2(360, 320), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchEditInScrollerProbe());
            host.RunFrame();
            var ti = (HeadlessTextInput)window.TextInput;
            var field = FindRole(host.Scene, host.Scene.Root, AutomationRole.Text);
            ClickNode(host, window, field);   // mouse PointerDown+Up (PointerKind.Mouse) → focuses, must NOT show the SIP
            mouseShow = ti.ShowCount;
        }
        Check("gate.touch4.sip.show-on-touch a touch focus on an editable field shows the touch keyboard exactly once; a mouse focus never does",
            touchShow == 1 && mouseShow == 0, $"touchShow={touchShow} mouseShow={mouseShow}");

        // (2) HIDE on focus loss: after the touch focus, blur the field (focus → null) ⇒ TryHideTouchKeyboard fires.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("sip-hide", new Size2(360, 320), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new TouchEditInScrollerProbe());
            host.RunFrame();
            var ti = (HeadlessTextInput)window.TextInput;
            var field = FindRole(host.Scene, host.Scene.Root, AutomationRole.Text);
            var fr = host.Scene.AbsoluteRect(field);
            var p = new Point2(fr.X + 6f, fr.Y + fr.H / 2f);
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, p, t, 61)); host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerUp, p, t + 16, 61)); host.RunFrame();
            s_touchClockMs = t + 1000;
            int hideBefore = ti.HideCount;
            host.Input.SetFocus(NodeHandle.Null);   // focus leaves the editor for a non-editable target (WinUI hides the SIP)
            host.RunFrame();
            Check("gate.touch4.sip.hide-on-blur focus loss from the editor dismisses the touch keyboard",
                hideBefore == 0 && ti.HideCount >= 1 && !ti.TouchKeyboardShown,
                $"showCount={ti.ShowCount} hideBefore={hideBefore} hideCount={ti.HideCount} shown={ti.TouchKeyboardShown}");
        }

        // (3) REFLOW on Showing: touch-focus a field that sits low in a scroller, then fire a simulated InputPane Showing
        //     OccludedRect that covers it ⇒ the scroller scrolls the field's caret ABOVE the pane top (offset moved to
        //     expose the caret), and an empty (Hiding) rect leaves the clamp untouched (a hidden pane needs no reflow).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("sip-reflow", new Size2(220, 240), 1f)); window.Show();
            var probe = new TouchSipReflowProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            var ti = (HeadlessTextInput)window.TextInput;
            var field = FindRole(host.Scene, host.Scene.Root, AutomationRole.Text);
            var vp = FindScrollable(host.Scene, host.Scene.Root);
            // Touch-focus the field (its Showing-driven reflow uses the focused node).
            var fr0 = host.Scene.AbsoluteRect(field);
            var p = new Point2(fr0.X + 6f, fr0.Y + fr0.H / 2f);
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, p, t, 62)); host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerUp, p, t + 16, 62)); host.RunFrame();
            s_touchClockMs = t + 1000;

            host.Scene.TryGetScroll(vp, out var sc0);
            float offBefore = sc0.OffsetY;
            var fieldBefore = host.Scene.AbsoluteRect(field);
            // The pane covers the bottom of the viewport from y = paneTop down — chosen to overlap the field's bottom edge
            // (the field is ~180 DIP down in a 240-tall viewport, so a paneTop above its bottom forces a reflow).
            float paneTop = fieldBefore.Y + 10f;   // pane top sits 10 DIP into the field ⇒ a real occlusion
            ti.FireOccludedRect(new RectF(0f, paneTop, 200f, 240f - paneTop));
            host.RunFrame();

            host.Scene.TryGetScroll(vp, out var sc1);
            float offAfter = sc1.OffsetY;
            var fieldAfter = host.Scene.AbsoluteRect(field);
            bool moved = offAfter > offBefore + 0.5f;          // the viewport scrolled the content up
            bool exposed = fieldAfter.Y + fieldAfter.H <= paneTop + 0.5f;   // the field's bottom now clears the pane top

            // Hiding (empty rect) must NOT move the offset further (a hidden pane has nothing to clear).
            ti.FireOccludedRect(default);
            host.RunFrame();
            host.Scene.TryGetScroll(vp, out var sc2);
            bool hideNoReflow = MathF.Abs(sc2.OffsetY - offAfter) < 0.5f;

            Check("gate.touch4.sip.reflow a Showing OccludedRect scrolls the focused editor's caret above the pane; Hiding leaves the clamp untouched",
                moved && exposed && hideNoReflow,
                $"off {offBefore:0.#}->{offAfter:0.#} fieldBottom {fieldBefore.Y + fieldBefore.H:0.#}->{fieldAfter.Y + fieldAfter.H:0.#} paneTop={paneTop:0.#} moved={moved} exposed={exposed} hideNoReflow={hideNoReflow}");
        }

        // (4) 0-ALLOC steady: the SIP show/reflow path runs at focus/pane edges, never per frame — steady frames after a
        //     touch focus + a Showing reflow allocate 0 managed bytes on the hot half (the seam is edge-driven).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("sip-alloc", new Size2(220, 240), 1f)); window.Show();
            var probe = new TouchSipReflowProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            var ti = (HeadlessTextInput)window.TextInput;
            var field = FindRole(host.Scene, host.Scene.Root, AutomationRole.Text);
            var fr = host.Scene.AbsoluteRect(field);
            var p = new Point2(fr.X + 6f, fr.Y + fr.H / 2f);
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, p, t, 63)); host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerUp, p, t + 16, 63)); host.RunFrame();
            s_touchClockMs = t + 1000;
            ti.FireOccludedRect(new RectF(0f, fr.Y + 10f, 200f, 200f));
            host.RunFrame();
            long worst = 0;
            for (int i = 0; i < 10; i++) { var fs = host.RunFrame(); if (fs.HotPhaseAllocBytes > worst) worst = fs.HotPhaseAllocBytes; }
            Check("gate.touch4.sip.alloc-zero steady frames after a SIP touch-focus + Showing reflow allocate 0 managed bytes on the hot half",
                worst == 0, $"worstHotAlloc={worst}B");
        }
    }

    // ── Touch Phase-4 Hold EXECUTION + the stationary-hold WAKE source (gate.touch4.*): a touch long-press fires the
    // context flyout (the same action a right-click fires) and, because a STATIONARY held finger emits no input, a wake
    // source keeps frames coming until the ~500ms timer fires, then clears so the loop idles. Plus the §7A.3 control-layer
    // verdict for RatingControl touch tap-to-rate. Reuses the Phase-1 harness (Touch / s_touchClockMs / fixed 16ms clock).
    static void Touch4HoldWakeChecks(StringTable strings)
    {
        var fonts = new HeadlessFontSystem(strings);

        // gate.touch4.hold-fires-context: row 0 of a scroller is BOTH clickable and context-requesting. (1) a STATIONARY
        // ≥500ms press fires the context request (the press held, no scroll, no click); (2) a SUB-500ms release fires the
        // CLICK and no context (the Hold timer never promoted); (3) a MOVE-PAST-SLOP claims the Pan (scroll), firing
        // NEITHER context nor click (the arena sweeps both the Hold and the Tap — WinUI Pressed→Canceled, never Released).
        {
            // (1) Stationary long-press → context.
            using var app1 = new HeadlessPlatformApp();
            var w1 = new HeadlessWindow(new WindowDesc("hold-ctx", new Size2(360, 360), 1f)); w1.Show();
            var p1 = new TouchHoldContextProbe();
            using var h1 = new AppHost(app1, w1, new HeadlessGpuDevice(), fonts, strings, p1);
            h1.RunFrame();
            var pt1 = CenterOf(h1.Scene, p1.Row0);
            uint t1 = s_touchClockMs;
            w1.QueueInput(Touch(InputKind.PointerDown, pt1, t1, 91));
            h1.RunFrame();
            // Hold idle for 600ms (=38 fixed 16ms frames > the 500ms HoldUs) so the timer promotes the Hold → context.
            // The press visual is still HELD through the fire (the finger has not lifted).
            for (int i = 0; i < 7; i++) h1.RunFrame();
            bool pressedDuringHold = (h1.Scene.Flags(p1.Row0) & NodeFlags.Pressed) != 0;
            for (int i = 0; i < 31; i++) h1.RunFrame();
            bool firedHeldStillPressed = p1.Contexts == 1 && (h1.Scene.Flags(p1.Row0) & NodeFlags.Pressed) != 0;
            w1.QueueInput(Touch(InputKind.PointerUp, pt1, t1 + 620, 91));
            h1.RunFrame();
            s_touchClockMs = t1 + 2000;
            bool stationaryFiresContext = p1.Contexts == 1 && p1.Clicks == 0 && pressedDuringHold && firedHeldStillPressed;

            // (2) Sub-500ms release → click, NOT context.
            using var app2 = new HeadlessPlatformApp();
            var w2 = new HeadlessWindow(new WindowDesc("hold-tap", new Size2(360, 360), 1f)); w2.Show();
            var p2 = new TouchHoldContextProbe();
            using var h2 = new AppHost(app2, w2, new HeadlessGpuDevice(), fonts, strings, p2);
            h2.RunFrame();
            var pt2 = CenterOf(h2.Scene, p2.Row0);
            uint t2 = s_touchClockMs;
            w2.QueueInput(Touch(InputKind.PointerDown, pt2, t2, 92)); h2.RunFrame();
            for (int i = 0; i < 12; i++) h2.RunFrame();   // ~192ms held, well under 500ms
            w2.QueueInput(Touch(InputKind.PointerUp, pt2, t2 + 200, 92)); h2.RunFrame();
            s_touchClockMs = t2 + 2000;
            bool quickReleaseClicks = p2.Clicks == 1 && p2.Contexts == 0;

            // (3) Move-past-slop → pan (scroll), no context, no click.
            using var app3 = new HeadlessPlatformApp();
            var w3 = new HeadlessWindow(new WindowDesc("hold-pan", new Size2(360, 360), 1f)); w3.Show();
            var p3 = new TouchHoldContextProbe();
            using var h3 = new AppHost(app3, w3, new HeadlessGpuDevice(), fonts, strings, p3);
            h3.RunFrame();
            var vp3 = h3.Scene.Root;
            var pt3 = CenterOf(h3.Scene, p3.Row0);
            h3.Scene.TryGetScroll(vp3, out var sc3before);
            uint t3 = s_touchClockMs;
            w3.QueueInput(Touch(InputKind.PointerDown, pt3, t3, 93)); h3.RunFrame();
            // Drag the finger UP 60px over several frames (content scrolls DOWN → OffsetY increases from the top clamp).
            // Crossing the 4px pan slop on the scroll axis claims the Pan and SWEEPS the Hold + Tap; then keep holding past
            // 500ms to prove the swept Hold never re-fires the context.
            for (int i = 1; i <= 6; i++)
            {
                w3.QueueInput(Touch(InputKind.PointerMove, new Point2(pt3.X, pt3.Y - i * 10f), t3 + (uint)(i * 16), 93));
                h3.RunFrame();
            }
            for (int i = 0; i < 38; i++) h3.RunFrame();   // hold past 500ms after the pan claim
            w3.QueueInput(Touch(InputKind.PointerUp, new Point2(pt3.X, pt3.Y - 60f), t3 + 700, 93)); h3.RunFrame();
            h3.Scene.TryGetScroll(vp3, out var sc3after);
            s_touchClockMs = t3 + 2000;
            bool movePansNoContext = p3.Contexts == 0 && p3.Clicks == 0 && sc3after.OffsetY > sc3before.OffsetY + 4f;

            using var app4 = new HeadlessPlatformApp();
            var w4 = new HeadlessWindow(new WindowDesc("hold-radial-cancel", new Size2(360, 360), 1f)); w4.Show();
            var p4 = new TouchHoldContextProbe();
            using var h4 = new AppHost(app4, w4, new HeadlessGpuDevice(), fonts, strings, p4);
            h4.RunFrame();
            var pt4 = CenterOf(h4.Scene, p4.Row0);
            uint t4 = s_touchClockMs;
            w4.QueueInput(Touch(InputKind.PointerDown, pt4, t4, 94)); h4.RunFrame();
            var cross = new Point2(pt4.X + InputDispatcher.TouchSlopPx + 4f, pt4.Y);
            w4.QueueInput(Touch(InputKind.PointerMove, cross, t4 + 16, 94)); h4.RunFrame();
            for (int i = 0; i < 38; i++) h4.RunFrame();
            w4.QueueInput(Touch(InputKind.PointerUp, cross, t4 + 700, 94)); h4.RunFrame();
            bool radialMoveCancelsBoth = p4.Contexts == 0 && p4.Clicks == 0;
            s_touchClockMs = t4 + 2000;

            Check("gate.touch4.hold-fires-context a stationary ≥500ms touch press on a clickable+context row opens its context flyout (press held through the fire); a sub-500ms release fires the click not the context; a move-past-slop claims the scroller pan (scrolls) and fires neither context nor click",
                stationaryFiresContext && quickReleaseClicks && movePansNoContext && radialMoveCancelsBoth,
                $"stationary(ctx={p1.Contexts} clk={p1.Clicks} heldPress={firedHeldStillPressed})={stationaryFiresContext} quick(clk={p2.Clicks} ctx={p2.Contexts})={quickReleaseClicks} pan(ctx={p3.Contexts} clk={p3.Clicks} dOff={sc3after.OffsetY - sc3before.OffsetY:0.#})={movePansNoContext} radial={radialMoveCancelsBoth}");
        }

        // gate.touch4.hold-wake: a STATIONARY hold with NO further input still resolves — the GestureHold wake bit keeps
        // frames coming until TickGestureArenas fires the ~500ms Hold (mirrors gate.wake.idle-attribution). After the fire
        // the bit clears (the Hold resolved); lifting + draining returns the idle mask to None. A bare context box (no
        // scroller/click) so the ONLY post-down wake reason attributable to the hold is GestureHold.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("hold-wake", new Size2(300, 240), 1f)); window.Show();
            var probe = new ArenaHoldProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            var br = host.Scene.AbsoluteRect(host.Scene.Root);
            var p = new Point2(br.X + 40f, br.Y + 40f);
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, p, t, 94));
            host.RunFrame();
            // The down armed the Hold: the wake mask must light GestureHold so a stationary finger keeps frames coming.
            bool holdBitLit = (host.CurrentWakeReasons & WakeReasons.GestureHold) != 0;
            // Drive the loop ONLY while it claims active work (NO further input) — exactly the real idle loop. The Hold
            // must promote + fire purely off the wake-driven frames (capped well above the 500ms/16ms ≈ 32 frames).
            int pumped = 0;
            for (; pumped < 120; pumped++)
            {
                if (!host.HasActiveWork) break;
                host.RunFrame();
            }
            bool firedViaWake = probe.Contexts == 1;
            // After resolution the GestureHold bit is cleared even though the finger is STILL down (the Hold won; the arena
            // is resolved). The bare context handler queues no further work, so the loop is now idle.
            bool bitClearedAfter = (host.CurrentWakeReasons & WakeReasons.GestureHold) == 0;
            // Lift + drain: the idle mask returns fully to None (mirror gate.wake.idle-attribution).
            window.QueueInput(Touch(InputKind.PointerUp, p, t + (uint)(pumped + 2) * 16, 94));
            host.RunFrame();
            int drained = 0;
            for (; drained < 120; drained++) { if (!host.HasActiveWork) break; host.RunFrame(); }
            bool idleNone = host.CurrentWakeReasons == WakeReasons.None;
            s_touchClockMs = t + 4000;
            Check("gate.touch4.hold-wake a stationary hold with NO further input still resolves — the GestureHold wake bit keeps frames coming until the ~500ms Hold fires the context, then the bit clears (Hold resolved, finger still down) and after lifting the idle mask returns to None (mirrors gate.wake.idle-attribution)",
                holdBitLit && firedViaWake && bitClearedAfter && idleNone,
                $"holdBitLit={holdBitLit} firedViaWake={firedViaWake}(ctx={probe.Contexts} pumped={pumped}) bitClearedAfter={bitClearedAfter} idleNone={idleNone}(final={host.CurrentWakeReasons} drained={drained})");
        }

        // gate.touch4.rating-tap: a touch TAP on the 4th star of a 5-star RatingControl rates it 4 (OnPointerDown=Sweep
        // sets the preview at the tapped X; OnClick=Commit on release applies it — touch tap-to-rate, the commit-on-release
        // RatingControl.cpp lifecycle, here via the eager OnDrag implicit-capture single-recognizer fast-path).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("rating-tap", new Size2(320, 120), 1f)); window.Show();
            var probe = new RatingTapProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            // The interactive star row (the Sweep/Commit OnDrag surface) is the Rating container's first child; its 4th
            // star centre in panel-local px is StarCenter(3) = 16·3.5 + 3·8 = 80 (StarsAt maps that to ceil(80/112·5)=4).
            var rating = FindRole(host.Scene, host.Scene.Root, AutomationRole.Rating);
            var starRow = Child(host.Scene, rating, 0);
            var sr = host.Scene.AbsoluteRect(starRow);
            float star4LocalX = RatingControlTemplateSettings.StarCenter(3, 16f, 8f);   // = 80
            var tapPt = new Point2(sr.X + star4LocalX, sr.Y + sr.H / 2f);
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, tapPt, t, 95)); host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerUp, tapPt, t + 16, 95)); host.RunFrame();
            s_touchClockMs = t + 1000;
            float rated = probe.Val?.Value ?? -1f;
            Check("gate.touch4.rating-tap a touch tap on the 4th star of a 5-star RatingControl rates it 4 (OnPointerDown=Sweep preview + OnClick=Commit on release — touch tap-to-rate via the eager OnDrag single-recognizer capture)",
                Near(rated, 4f, 0.01f), $"rated={rated} (expected 4) starRowX={sr.X:0.#} tapX={tapPt.X:0.#}");
        }
    }

    // ── ContextMenu attach layer (gate.ctx.*): drives real right-click / Menu-key / touch long-press through the AppHost
    //    onto ContextMenu.Attach-wired rows over an OverlayHost, asserting the open/place/dismiss/redispatch contract.
    static void ContextMenuChecks(StringTable strings)
    {
        var fonts = new HeadlessFontSystem(strings);

        static void Right(HeadlessWindow w, Point2 p)
        {
            w.QueueInput(new InputEvent(InputKind.PointerDown, p, 1, 0));   // button 1 = right
            w.QueueInput(new InputEvent(InputKind.PointerUp, p, 1, 0));
        }
        static void Left(HeadlessWindow w, Point2 p)
        {
            w.QueueInput(new InputEvent(InputKind.PointerDown, p, 0, 0));
            w.QueueInput(new InputEvent(InputKind.PointerUp, p, 0, 0));
        }
        static void RunN(AppHost h, int n) { for (int i = 0; i < n; i++) h.RunFrame(); }
        static NodeHandle FindScroll(SceneStore s, NodeHandle n)
        {
            if (n.IsNull) return NodeHandle.Null;
            if (s.TryGetScroll(n, out _)) return n;
            for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
            { var r = FindScroll(s, c); if (!r.IsNull) return r; }
            return NodeHandle.Null;
        }

        // gate.ctx.open-at-pointer — a right press+release on an attached row opens ONE menu whose first row lands ON the
        // right-tap point (OpenAtLocal: owner rect + local − FlyoutMargin ⇒ presenter top-left at the point), light-dismiss.
        {
            using var app = new HeadlessPlatformApp();
            var w = new HeadlessWindow(new WindowDesc("ctx-open", new Size2(480, 400), 1f)); w.Show();
            var probe = new ContextMenuProbe();
            using var host = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            var pt = CenterOf(host.Scene, probe.RowA);
            Right(w, pt); RunN(host, 3);
            var mi = FindRole(host.Scene, host.Scene.Root, AutomationRole.MenuItem);
            var r = mi.IsNull ? default : host.Scene.AbsoluteRect(mi);
            bool opened = probe.Service!.AnyOpen && !mi.IsNull;
            bool atPoint = !mi.IsNull && Near(r.X, pt.X, 30f) && r.Y >= pt.Y - 2f && r.Y <= pt.Y + 30f;
            Check("gate.ctx.open-at-pointer right-click on an attached row opens one menu at the tap point (presenter top-left on the point, light-dismiss)",
                opened && atPoint, $"open={opened} first=({r.X:0.#},{r.Y:0.#}) pt=({pt.X:0.#},{pt.Y:0.#})");
        }

        // gate.ctx.lazy-items — the factory is NOT invoked at render (a re-render leaves the count at 0); it runs exactly
        // once, AT OPEN, so a bound row reads current state at open time (RowScope.Index.Peek()).
        {
            using var app = new HeadlessPlatformApp();
            var w = new HeadlessWindow(new WindowDesc("ctx-lazy", new Size2(480, 400), 1f)); w.Show();
            var probe = new ContextMenuProbe();
            using var host = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame(); host.RunFrame();   // mount + a re-render
            bool notAtRender = probe.BuildsA == 0;
            Right(w, CenterOf(host.Scene, probe.RowA)); RunN(host, 3);
            bool builtAtOpen = probe.BuildsA == 1 && probe.Service!.AnyOpen;
            Check("gate.ctx.lazy-items the items factory runs at OPEN time, not render (count 0 across renders, 1 after the right-click)",
                notAtRender && builtAtOpen, $"atRender={probe.BuildsA} (want 0 pre-open) open={probe.Service!.AnyOpen}");
        }

        // gate.ctx.empty-menu-no-open — a null factory result opens nothing (the factory still ran).
        {
            using var app = new HeadlessPlatformApp();
            var w = new HeadlessWindow(new WindowDesc("ctx-empty", new Size2(480, 400), 1f)); w.Show();
            var probe = new ContextMenuProbe { ReturnNull = true };
            using var host = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            Right(w, CenterOf(host.Scene, probe.RowA)); RunN(host, 3);
            bool noOpen = !probe.Service!.AnyOpen && FindRole(host.Scene, host.Scene.Root, AutomationRole.MenuItem).IsNull;
            Check("gate.ctx.empty-menu-no-open a null/empty model opens nothing (factory ran, no overlay)",
                noOpen && probe.BuildsA == 1, $"anyOpen={probe.Service!.AnyOpen} builds={probe.BuildsA}");
        }

        // gate.ctx.disabled-rows — a model of only disabled/separator rows opens nothing.
        {
            using var app = new HeadlessPlatformApp();
            var w = new HeadlessWindow(new WindowDesc("ctx-disabled", new Size2(480, 400), 1f)); w.Show();
            var probe = new ContextMenuProbe { AllDisabled = true };
            using var host = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            Right(w, CenterOf(host.Scene, probe.RowA)); RunN(host, 3);
            bool noOpen = !probe.Service!.AnyOpen && FindRole(host.Scene, host.Scene.Root, AutomationRole.MenuItem).IsNull;
            Check("gate.ctx.disabled-rows an all-disabled model opens nothing",
                noOpen, $"anyOpen={probe.Service!.AnyOpen}");
        }

        // gate.ctx.keyboard-at-node — focus a row, VK_APPS ⇒ the menu anchors to the row RECT (not a point), the first
        // row takes focus, and Esc restores focus to the row (SavedFocus).
        {
            using var app = new HeadlessPlatformApp();
            var w = new HeadlessWindow(new WindowDesc("ctx-kbd", new Size2(480, 400), 1f)); w.Show();
            var probe = new ContextMenuProbe();
            using var host = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            var rowRect = host.Scene.AbsoluteRect(probe.RowA);
            Left(w, CenterOf(host.Scene, probe.RowA)); RunN(host, 2);   // focus the row (pointer focus)
            w.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.Apps)); RunN(host, 4);
            var mi = FindRole(host.Scene, host.Scene.Root, AutomationRole.MenuItem);
            var r = mi.IsNull ? default : host.Scene.AbsoluteRect(mi);
            bool nodeAnchored = !mi.IsNull && Near(r.X, rowRect.X, 30f) && r.Y >= rowRect.Bottom - 2f;   // below the ROW, not at a point
            bool firstFocused = !mi.IsNull && host.Input.Focused == mi;
            w.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.Escape)); RunN(host, 45);
            bool restored = host.Input.Focused == probe.RowA && !probe.Service!.AnyOpen;
            Check("gate.ctx.keyboard-at-node VK_APPS anchors the menu to the row rect + focuses the first item; Esc restores focus to the row",
                nodeAnchored && firstFocused && restored,
                $"nodeAnchored={nodeAnchored} firstFocused={firstFocused}(focus={host.Input.Focused.Raw.Index} first={mi.Raw.Index}) restored={restored}");
        }

        // gate.ctx.dismiss-reopen-one-gesture — THE pitfall: a menu open on row A; ONE right-click on row B closes A AND
        // opens B's menu at the B point (the scrim's OnContextRequested → CloseTop + RedispatchContextAt through the
        // synchronously-unmarked scrim).
        {
            using var app = new HeadlessPlatformApp();
            var w = new HeadlessWindow(new WindowDesc("ctx-reopen", new Size2(480, 400), 1f)); w.Show();
            var probe = new ContextMenuProbe();
            using var host = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            Right(w, CenterOf(host.Scene, probe.RowA)); RunN(host, 3);
            bool aOpen = probe.Service!.AnyOpen && probe.BuildsA == 1;
            var ptB = CenterOf(host.Scene, probe.RowB);
            Right(w, ptB); RunN(host, 45);   // one gesture on B: dismiss A + reopen at B, then settle A away
            var mi = FindRole(host.Scene, host.Scene.Root, AutomationRole.MenuItem);
            var r = mi.IsNull ? default : host.Scene.AbsoluteRect(mi);
            bool reopenedAtB = probe.Service!.AnyOpen && probe.BuildsB == 1 && !mi.IsNull
                               && Near(r.X, ptB.X, 30f) && r.Y >= ptB.Y - 2f && r.Y <= ptB.Y + 30f;
            Check("gate.ctx.dismiss-reopen-one-gesture a right-click on B while A's menu is open dismisses A AND opens B's menu at the B point (scrim redispatch)",
                aOpen && reopenedAtB, $"aOpen={aOpen} reopenB={reopenedAtB} buildsB={probe.BuildsB} first=({r.X:0.#},{r.Y:0.#}) ptB=({ptB.X:0.#},{ptB.Y:0.#})");
        }

        // gate.ctx.dismiss-only-on-empty-area — a right-click on inert background while a menu is open dismisses it and
        // opens nothing (the redispatch finds no ContextBit under the point).
        {
            using var app = new HeadlessPlatformApp();
            var w = new HeadlessWindow(new WindowDesc("ctx-empty-area", new Size2(480, 400), 1f)); w.Show();
            var probe = new ContextMenuProbe();
            using var host = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            Right(w, CenterOf(host.Scene, probe.RowA)); RunN(host, 3);
            bool aOpen = probe.Service!.AnyOpen;
            Right(w, new Point2(430f, 380f)); RunN(host, 45);   // inert corner (no attached row there)
            bool dismissedOnly = !probe.Service!.AnyOpen && FindRole(host.Scene, host.Scene.Root, AutomationRole.MenuItem).IsNull;
            Check("gate.ctx.dismiss-only-on-empty-area a right-click on inert background dismisses the open menu and opens nothing",
                aOpen && dismissedOnly, $"aOpen={aOpen} dismissedOnly={dismissedOnly}");
        }

        // gate.ctx.race-open-close-open — a rapid supersede (open A, then reopen via B before A settles) leaves exactly
        // one live windowed popup after settle (no leaked PopupWindowToken).
        {
            using var app = new HeadlessPlatformApp();
            var w = new HeadlessWindow(new WindowDesc("ctx-race", new Size2(480, 400), 1f)); w.Show();
            var probe = new ContextMenuProbe();
            using var host = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            Right(w, CenterOf(host.Scene, probe.RowA)); RunN(host, 2);   // rapid: reopen before A's open settles
            Right(w, CenterOf(host.Scene, probe.RowB)); RunN(host, 45);
            // <=1 (not ==1): catches a leaked token (would be ≥2) while tolerating a constrained (non-windowed) fallback (0).
            bool oneLive = probe.Service!.AnyOpen && host.PopupWindows.Count <= 1;
            Check("gate.ctx.race-open-close-open a rapid open→close→open leaves at most one live windowed popup (no leaked token) with a menu still open",
                oneLive, $"anyOpen={probe.Service!.AnyOpen} popupWindows={host.PopupWindows.Count}");
        }

        // gate.ctx.scrim-blocks-wheel — with a menu open the light-dismiss scrim is the topmost hit, so a wheel over the
        // covered list scrolls NOTHING (the ancestor-only wheel walk finds no scrollable); once closed, the same wheel
        // scrolls the list (proving the wheel is real and the scrim was blocking it).
        {
            using var app = new HeadlessPlatformApp();
            var w = new HeadlessWindow(new WindowDesc("ctx-wheel", new Size2(480, 400), 1f)); w.Show();
            var probe = new ContextWheelProbe();
            using var host = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            var scroller = FindScroll(host.Scene, host.Scene.Root);
            host.Scene.TryGetScroll(scroller, out var before);
            Right(w, CenterOf(host.Scene, probe.Row)); RunN(host, 3);
            bool opened = probe.Service!.AnyOpen;
            var listPt = new Point2(150f, 250f);   // over the list, under the scrim
            w.QueueInput(new InputEvent(InputKind.Wheel, listPt, 0, 0, 240f)); RunN(host, 2);
            host.Scene.TryGetScroll(scroller, out var afterBlocked);
            bool blocked = Near(afterBlocked.OffsetY, before.OffsetY, 0.5f);
            probe.Service!.CloseAll(); RunN(host, 45);
            w.QueueInput(new InputEvent(InputKind.Wheel, listPt, 0, 0, 240f)); RunN(host, 3);
            host.Scene.TryGetScroll(scroller, out var afterFree);
            bool scrolls = afterFree.OffsetY > before.OffsetY + 4f;
            Check("gate.ctx.scrim-blocks-wheel a wheel over the covered list does not scroll while a menu is open; the same wheel scrolls it once closed",
                !scroller.IsNull && opened && blocked && scrolls,
                $"opened={opened} blocked={blocked}(off={afterBlocked.OffsetY:0.#}) scrolls={scrolls}(off={afterFree.OffsetY:0.#})");
        }

        // gate.ctx.touch-hold-opens — a synthetic touch down + a >500ms stationary hold fires the context request
        // (Trigger.Hold) and opens the menu at the contact point (the pressed visual is held through the fire).
        {
            using var app = new HeadlessPlatformApp();
            var w = new HeadlessWindow(new WindowDesc("ctx-hold", new Size2(480, 400), 1f)); w.Show();
            var probe = new ContextMenuProbe();
            using var host = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            var pt = CenterOf(host.Scene, probe.RowA);
            uint t = s_touchClockMs;
            w.QueueInput(Touch(InputKind.PointerDown, pt, t, 97));
            host.RunFrame();
            bool pressedDuringHold = (host.Scene.Flags(probe.RowA) & NodeFlags.Pressed) != 0;
            for (int i = 0; i < 38; i++) host.RunFrame();   // > 500ms hold → Hold win fires the context request
            var mi = FindRole(host.Scene, host.Scene.Root, AutomationRole.MenuItem);
            var r = mi.IsNull ? default : host.Scene.AbsoluteRect(mi);
            bool opened = probe.Service!.AnyOpen && !mi.IsNull && Near(r.X, pt.X, 30f) && r.Y >= pt.Y - 2f && r.Y <= pt.Y + 30f;
            w.QueueInput(Touch(InputKind.PointerUp, pt, t + 620, 97)); host.RunFrame();
            s_touchClockMs = t + 2000;
            Check("gate.ctx.touch-hold-opens a >500ms stationary touch long-press opens the menu at the contact (press held through the fire)",
                pressedDuringHold && opened, $"pressedDuringHold={pressedDuringHold} opened={opened} first=({r.X:0.#},{r.Y:0.#}) pt=({pt.X:0.#},{pt.Y:0.#})");
        }

        // gate.ctx.re-render-anchor — the regression the ContextRequestEventArgs.Node carry fixed: after row A RE-RENDERS
        // (a plain OnRealized capture would have gone stale → menu at the window origin), a right-click still opens the
        // menu AT the tap point because ContextMenu.Attach anchors from args.Node (the live ContextBit owner), not a
        // captured handle. Mirror gate.ctx.open-at-pointer, but bump the probe's Rev between frames to force the re-render.
        {
            using var app = new HeadlessPlatformApp();
            var w = new HeadlessWindow(new WindowDesc("ctx-rerender", new Size2(480, 400), 1f)); w.Show();
            var probe = new ContextMenuProbe();
            using var host = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            probe.Rev.Value = 1; RunN(host, 2);   // re-render row A (would stale a captured anchor)
            probe.Rev.Value = 2; RunN(host, 2);
            var pt = CenterOf(host.Scene, probe.RowA);
            Right(w, pt); RunN(host, 3);
            var mi = FindRole(host.Scene, host.Scene.Root, AutomationRole.MenuItem);
            var r = mi.IsNull ? default : host.Scene.AbsoluteRect(mi);
            bool opened = probe.Service!.AnyOpen && !mi.IsNull;
            bool atPoint = !mi.IsNull && Near(r.X, pt.X, 30f) && r.Y >= pt.Y - 2f && r.Y <= pt.Y + 30f;
            Check("gate.ctx.re-render-anchor after row A re-renders, a right-click still opens the menu at the tap point (anchors from args.Node, not a stale OnRealized capture)",
                opened && atPoint, $"open={opened} first=({r.X:0.#},{r.Y:0.#}) pt=({pt.X:0.#},{pt.Y:0.#})");
        }

        // gate.ctx.invoke-anchors-source — a LEFT click on row B's "…" (ClickRequestsContext) opens ONE menu anchored
        // at the BUTTON rect (ContextRequestTrigger.Invoke → rect-anchored on args.Source, the Keyboard rule
        // generalized), and the first item is NOT focused (pointer-originated).
        {
            using var app = new HeadlessPlatformApp();
            var w = new HeadlessWindow(new WindowDesc("ctx-invoke", new Size2(480, 400), 1f)); w.Show();
            var probe = new ContextMenuProbe();
            using var host = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            var btn = host.Scene.AbsoluteRect(probe.MoreB);
            Left(w, CenterOf(host.Scene, probe.MoreB)); RunN(host, 3);
            var mi = FindRole(host.Scene, host.Scene.Root, AutomationRole.MenuItem);
            var r = mi.IsNull ? default : host.Scene.AbsoluteRect(mi);
            bool opened = probe.Service!.AnyOpen && probe.BuildsB == 1 && !mi.IsNull;
            bool atButton = !mi.IsNull && Near(r.X, btn.X, 30f) && r.Y >= btn.Bottom - 2f && r.Y <= btn.Bottom + 30f;
            bool firstNotFocused = !mi.IsNull && host.Input.Focused != mi;
            Check("gate.ctx.invoke-anchors-source a left click on the \"…\" opens one menu anchored at the BUTTON rect, first item NOT focused",
                opened && atButton && firstNotFocused,
                $"open={opened} first=({r.X:0.#},{r.Y:0.#}) btn=({btn.X:0.#},{btn.Bottom:0.#}) notFocused={firstNotFocused}");
        }

        // gate.ctx.invoke-source-field — the args carry: right-click ⇒ Source == Node (== row B, the ContextBit owner);
        // "…" click ⇒ Trigger=Invoke, Source == the button, Node == the row (the funnel re-entered at the button, the
        // walk stopped at the row).
        {
            using var app = new HeadlessPlatformApp();
            var w = new HeadlessWindow(new WindowDesc("ctx-invoke-src", new Size2(480, 400), 1f)); w.Show();
            var probe = new ContextMenuProbe();
            using var host = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            Right(w, CenterOf(host.Scene, probe.RowB)); RunN(host, 3);
            bool rightSourceIsNode = probe.LastTrigger == ContextRequestTrigger.Pointer
                                  && probe.LastNode == probe.RowB && probe.LastSource == probe.RowB;
            probe.Service!.CloseAll(); RunN(host, 45);
            Left(w, CenterOf(host.Scene, probe.MoreB)); RunN(host, 3);
            bool invokeFields = probe.LastTrigger == ContextRequestTrigger.Invoke
                             && probe.LastNode == probe.RowB && probe.LastSource == probe.MoreB;
            Check("gate.ctx.invoke-source-field right-click: Source==Node==row; \"…\" click: Trigger=Invoke, Source=button, Node=row",
                rightSourceIsNode && invokeFields,
                $"right={rightSourceIsNode} invoke={invokeFields} trig={probe.LastTrigger} node={probe.LastNode.Raw.Index} src={probe.LastSource.Raw.Index}");
        }

        // gate.ctx.invoke-keyboard-focuses-first — Space on the FOCUSED "…" dispatches a Keyboard-trigger request
        // (key-activation keeps WinUI TryGetPosition-false semantics), so the menu anchors to the button rect AND
        // focuses its first item — unlike the pointer Invoke above.
        {
            using var app = new HeadlessPlatformApp();
            var w = new HeadlessWindow(new WindowDesc("ctx-invoke-kbd", new Size2(480, 400), 1f)); w.Show();
            var probe = new ContextMenuProbe();
            using var host = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            var btn = host.Scene.AbsoluteRect(probe.MoreB);
            host.Input.SetFocus(probe.MoreB);
            w.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.Space));
            w.QueueInput(new InputEvent(InputKind.KeyUp, default, 0, Keys.Space));
            RunN(host, 4);
            var mi = FindRole(host.Scene, host.Scene.Root, AutomationRole.MenuItem);
            var r = mi.IsNull ? default : host.Scene.AbsoluteRect(mi);
            bool opened = probe.Service!.AnyOpen && !mi.IsNull && probe.LastTrigger == ContextRequestTrigger.Keyboard;
            bool atButton = !mi.IsNull && Near(r.X, btn.X, 30f) && r.Y >= btn.Bottom - 2f;
            bool firstFocused = !mi.IsNull && host.Input.Focused == mi;
            Check("gate.ctx.invoke-keyboard-focuses-first Space on the focused \"…\" opens a Keyboard-trigger menu at the button rect, first item focused",
                opened && atButton && firstFocused,
                $"open={opened} trig={probe.LastTrigger} atButton={atButton} firstFocused={firstFocused}");
        }

        // gate.ctx.invoke-re-render-anchor — the stale-capture bug the prop kills: bump the probe Rev (row B re-renders,
        // an OnRealized capture would have gone stale) then click the "…" — the menu anchors to the LIVE button rect
        // (RequestContextFrom reads AbsoluteRect(source) at dispatch time; no captured node, no captured rect).
        {
            using var app = new HeadlessPlatformApp();
            var w = new HeadlessWindow(new WindowDesc("ctx-invoke-rerender", new Size2(480, 400), 1f)); w.Show();
            var probe = new ContextMenuProbe();
            using var host = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            probe.Rev.Value = 1; RunN(host, 2);   // re-render row B (would stale a captured anchor)
            probe.Rev.Value = 2; RunN(host, 2);
            var btn = host.Scene.AbsoluteRect(probe.MoreB);
            Left(w, CenterOf(host.Scene, probe.MoreB)); RunN(host, 3);
            var mi = FindRole(host.Scene, host.Scene.Root, AutomationRole.MenuItem);
            var r = mi.IsNull ? default : host.Scene.AbsoluteRect(mi);
            bool opened = probe.Service!.AnyOpen && probe.BuildsB == 1 && !mi.IsNull;
            bool atButton = !mi.IsNull && Near(r.X, btn.X, 30f) && r.Y >= btn.Bottom - 2f && r.Y <= btn.Bottom + 30f;
            Check("gate.ctx.invoke-re-render-anchor after row B re-renders, the \"…\" click still anchors the menu to the LIVE button rect",
                opened && atButton, $"open={opened} first=({r.X:0.#},{r.Y:0.#}) btn=({btn.X:0.#},{btn.Bottom:0.#})");
        }

        // gate.ctx.invoke-disabled — the DISABLED "…" opens nothing: disabled nodes don't hit-test, so the click never
        // reaches the ClickRequestsContext bit (and the fall-through row click is a plain click, not a context request).
        {
            using var app = new HeadlessPlatformApp();
            var w = new HeadlessWindow(new WindowDesc("ctx-invoke-disabled", new Size2(480, 400), 1f)); w.Show();
            var probe = new ContextMenuProbe();
            using var host = new AppHost(app, w, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            Left(w, CenterOf(host.Scene, probe.MoreBDisabled)); RunN(host, 3);
            bool noOpen = !probe.Service!.AnyOpen && probe.BuildsB == 0
                       && FindRole(host.Scene, host.Scene.Root, AutomationRole.MenuItem).IsNull;
            Check("gate.ctx.invoke-disabled a disabled \"…\" opens nothing",
                noOpen, $"anyOpen={probe.Service!.AnyOpen} buildsB={probe.BuildsB}");
        }
    }

    // ── ThemedIcon layered vector icons (gate.icon.*): the SVG parser/rasterizer/geometry table (pure, portable), the
    //    IconLayerEl→DrawIconMask record path, theme-live recolor with NO re-raster, 0-alloc phases 6–13, and the
    //    mode/state (outline/disabled) role resolution. Everything here is Engine + Controls — TerraFX-free by construction.
    static void IconChecks(StringTable strings)
    {
        var fonts = new HeadlessFontSystem(strings);
        static bool SameRgb(ColorF a, ColorF b) => Near(a.R, b.R, 0.02f) && Near(a.G, b.G, 0.02f) && Near(a.B, b.B, 0.02f);

        // gate.icon.parse — the SVG path parser + geometry table: a straight-line polygon interns as an exact contour
        // (1 contour / 3 points / view-box-normalized bounds); a cubic flattens to many points in one contour; malformed
        // input never throws (clamp-not-crash, validation.md). Uses a LOCAL table so the shared RasterCount stays clean.
        {
            var tbl = new IconGeometryTable();
            int tri = tbl.Register("M4 3 L13 8 L4 13 Z", 16f, 16f, evenOdd: false);
            var (triC, triP) = tbl.ShapeOf(tri);
            var tb = tbl.BoundsOf(tri);
            bool triOk = triC == 1 && triP == 3
                && Near(tb.MinX, 4f / 16f, 0.01f) && Near(tb.MaxX, 13f / 16f, 0.01f)
                && Near(tb.MinY, 3f / 16f, 0.01f) && Near(tb.MaxY, 13f / 16f, 0.01f);

            int cur = tbl.Register("M2 8 C2 2 14 2 14 8 Z", 16f, 16f, evenOdd: false);
            var (curC, curP) = tbl.ShapeOf(cur);
            var cb = tbl.BoundsOf(cur);
            bool curveOk = curC == 1 && curP > 6 && cb.MinX >= 0f && cb.MaxX <= 1.001f && cb.MinY >= 0f && cb.MaxY <= 1.001f;

            bool noThrow = true;
            try { tbl.Register("M q z 9-.,,", 16f, 16f); tbl.Register("!!!garbage###", 16f, 16f); tbl.Register("A5 5 0 0", 16f, 16f); }
            catch { noThrow = false; }

            Check("gate.icon.parse polygon interns exact (1/3 + bounds), a cubic flattens to one many-point contour, malformed input never throws",
                triOk && curveOk && noThrow, $"tri=({triC}/{triP}) curve=({curC}/{curP}) bounds=({tb.MinX:0.00}..{tb.MaxX:0.00}) noThrow={noThrow}");
        }

        // gate.icon.raster — the scanline fill: a full 0..1 square covers the whole buffer (center 255); two same-wound
        // overlapping squares DIVERGE by fill rule — even-odd punches a hole (center ~0), nonzero keeps it filled (~255).
        {
            var sq = new float[] { 0f, 0f, 1f, 0f, 1f, 1f, 0f, 1f };
            var starts1 = new[] { 0 }; var counts1 = new[] { 4 };
            var full = new byte[16 * 16];
            IconRaster.Rasterize(sq, starts1, counts1, evenOdd: false, 16, 16, full);
            byte center = full[8 * 16 + 8];

            // outer 0..1 + inner 0.25..0.75, IDENTICAL vertex order (same winding).
            var two = new float[] { 0f, 0f, 1f, 0f, 1f, 1f, 0f, 1f,   0.25f, 0.25f, 0.75f, 0.25f, 0.75f, 0.75f, 0.25f, 0.75f };
            var starts2 = new[] { 0, 4 }; var counts2 = new[] { 4, 4 };
            var eo = new byte[16 * 16]; var nz = new byte[16 * 16];
            IconRaster.Rasterize(two, starts2, counts2, evenOdd: true, 16, 16, eo);
            IconRaster.Rasterize(two, starts2, counts2, evenOdd: false, 16, 16, nz);
            byte eoCenter = eo[8 * 16 + 8]; byte nzCenter = nz[8 * 16 + 8];

            Check("gate.icon.raster a 0..1 square fills solid (center 255); even-odd holes the overlap (center ~0) while nonzero fills it (~255)",
                center == 255 && eoCenter < 40 && nzCenter > 200, $"full={center} eoCenter={eoCenter} nzCenter={nzCenter}");
        }

        // gate.icon.record — mounting a layered ThemedIcon ("Copy" = 4 role layers) emits 4 DrawIconMask ops, each with a
        // live PathId and an opaque tint; the neutral Base + the accent highlight are present with their resolved tints.
        {
            using var app = new HeadlessPlatformApp();
            var w = new HeadlessWindow(new WindowDesc("icon-record", new Size2(240, 240), 1f)); w.Show();
            var dev = new HeadlessGpuDevice();
            using var host = new AppHost(app, w, dev, fonts, strings, new IconProbe { Name = "Copy" });
            host.RunFrame();
            int n = dev.LastIconMasks.Count;
            bool allLive = n > 0; bool base_ = false, accent = false;
            foreach (var m in dev.LastIconMasks)
            {
                if (m.PathId == 0 || m.Tint.A <= 0f) allLive = false;
                if (SameRgb(m.Tint, Tok.IconBase)) base_ = true;
                if (SameRgb(m.Tint, Tok.AccentDefault)) accent = true;
            }
            Check("gate.icon.record a layered ThemedIcon emits one DrawIconMask per role layer with live PathIds + resolved Base/Accent tints",
                n == 4 && allLive && base_ && accent, $"masks={n} allLive={allLive} base={base_} accent={accent}");
        }

        // gate.icon.retheme — an accent swap re-fires the bound Tint thunk → the accent layer's DrawIconMask tint changes
        // in the stream, WITHOUT any re-raster (masks are colorless: IconGeometryTable.Shared.RasterCount is unchanged).
        {
            using var app = new HeadlessPlatformApp();
            var w = new HeadlessWindow(new WindowDesc("icon-retheme", new Size2(240, 240), 1f)); w.Show();
            var dev = new HeadlessGpuDevice();
            using var host = new AppHost(app, w, dev, fonts, strings, new IconProbe { Name = "Play" });   // single accent layer
            host.RunFrame();
            ColorF tint0 = dev.LastIconMasks.Count > 0 ? dev.LastIconMasks[0].Tint : default;
            long rc0 = IconGeometryTable.Shared.RasterCount;
            try
            {
                Tok.SetAccent(ColorF.FromRgba(0xE0, 0x40, 0x40));   // red override
                host.Reconciler.RethemeAll();
                host.RunFrame();
                ColorF tint1 = dev.LastIconMasks.Count > 0 ? dev.LastIconMasks[0].Tint : default;
                long rc1 = IconGeometryTable.Shared.RasterCount;
                bool changed = !SameRgb(tint0, tint1) && tint1.R > tint1.B + 0.1f;   // now reddish
                bool noReRaster = rc1 == rc0;
                Check("gate.icon.retheme an accent swap recolors the icon's DrawIconMask tint with NO re-raster (RasterCount unchanged)",
                    changed && noReRaster, $"tint0=({tint0.R:0.00},{tint0.G:0.00},{tint0.B:0.00}) tint1=({tint1.R:0.00},{tint1.G:0.00},{tint1.B:0.00}) raster {rc0}->{rc1}");
            }
            finally { Tok.SetAccent(null); host.Reconciler.RethemeAll(); }   // restore global accent for later gates
        }

        // gate.theme.accent-ramp — an accent override resolves the accent FILL THEME-AWARE: AccentDefault is the WinUI
        // Dark1 shade in LIGHT and the Light2 shade in DARK (the fix for the light-theme accent bug, where one flat color
        // was reused in both themes). The exact shades come from AccentRamp.Derive. Restores theme + accent in finally.
        {
            var savedTheme = Tok.Theme;
            try
            {
                var baseC = ColorF.FromRgba(0x00, 0x78, 0xD4);   // the WinUI default accent
                var ramp = AccentRamp.Derive(baseC);
                Tok.SetAccent(baseC);
                Tok.Use(ThemeKind.Light); var light = Tok.AccentDefault;
                Tok.Use(ThemeKind.Dark);  var dark  = Tok.AccentDefault;
                bool lightIsDark1 = SameRgb(light, ramp.Dark1);
                bool darkIsLight2 = SameRgb(dark, ramp.Light2);
                bool differ = !SameRgb(light, dark);
                Check("gate.theme.accent-ramp an accent override resolves AccentDefault theme-aware (Dark1 in light, Light2 in dark, distinct)",
                    lightIsDark1 && darkIsLight2 && differ,
                    $"light=({light.R:0.00},{light.G:0.00},{light.B:0.00}) dark=({dark.R:0.00},{dark.G:0.00},{dark.B:0.00}) dark1=({ramp.Dark1.R:0.00},{ramp.Dark1.G:0.00},{ramp.Dark1.B:0.00}) light2=({ramp.Light2.R:0.00},{ramp.Light2.G:0.00},{ramp.Light2.B:0.00})");
            }
            finally { Tok.SetAccent(null); Tok.Use(savedTheme); }
        }

        // gate.icon.alloc — icons on screen record as pure POD: 0 managed bytes in phases 6–13 across steady frames
        // (warm frames skipped for JIT, per the flaky-alloc note).
        {
            using var app = new HeadlessPlatformApp();
            var w = new HeadlessWindow(new WindowDesc("icon-alloc", new Size2(240, 240), 1f)); w.Show();
            var dev = new HeadlessGpuDevice();
            using var host = new AppHost(app, w, dev, fonts, strings, new IconProbe { Name = "Copy" });
            long worst = 0;
            for (int i = 0; i < 12; i++) { var f = host.RunFrame(); if (i >= 3 && f.HotPhaseAllocBytes > worst) worst = f.HotPhaseAllocBytes; }
            Check("gate.icon.alloc icons on screen record with 0 managed alloc in phases 6–13 (steady frames)",
                worst == 0, $"worstHotAlloc={worst}B");
        }

        // gate.icon.outline / gate.icon.disabled — the role resolution: Outline mode paints the Base (foreground) role
        // and returns a single leaf; a disabled layer resolves to TextDisabled regardless of role, and a status recolor
        // routes the Accent layer to the severity fill.
        {
            ColorF baseOn = ThemedIcon.ResolveRole(IconRole.Base, IconColorType.Normal, enabled: true, onAccent: false, 1f);
            ColorF accOn = ThemedIcon.ResolveRole(IconRole.Accent, IconColorType.Normal, enabled: true, onAccent: false, 1f);
            ColorF accOff = ThemedIcon.ResolveRole(IconRole.Accent, IconColorType.Normal, enabled: false, onAccent: false, 1f);
            ColorF critical = ThemedIcon.ResolveRole(IconRole.Accent, IconColorType.Critical, enabled: true, onAccent: false, 1f);
            var outline = ThemedIcon.Create("Folder", 16f, mode: IconMode.Outline);   // Folder ships a single Outline path
            bool outlineOk = outline is IconLayerEl && SameRgb(baseOn, Tok.IconBase);
            bool disabledOk = SameRgb(accOff, Tok.TextDisabled) && !SameRgb(accOn, accOff) && SameRgb(accOn, Tok.AccentDefault);
            bool statusOk = SameRgb(critical, Tok.SystemFillCritical);
            Check("gate.icon.outline/disabled Outline paints Base + returns a leaf; a disabled layer is TextDisabled; a status recolor routes Accent to the severity fill",
                outlineOk && disabledOk && statusOk, $"outline={outline.GetType().Name} baseOk={SameRgb(baseOn, Tok.IconBase)} disabled={disabledOk} status={statusOk}");
        }
    }

    // ── Touch Phase-2 exit criteria: touch-correct visuals (Pressed-no-hover), light-dismiss parity with the mouse path,
    // text caret/selection by touch, the overlay scrollbar thumb-drag by touch, and a 0-alloc hot half across the
    // flyout-open/dismiss + caret-drag sequences. Reuses the Phase-1 touch harness (Touch / TouchGesture / s_touchClockMs
    // monotonic stamps + the fixed animation clock). These are the formal Phase-2 gate (gate.touch2.*).
    static void TouchPhase2Checks(StringTable strings)
    {
        var fonts = new HeadlessFontSystem(strings);
        const float Adv = 14f * 0.55f;   // headless advance model @ FontSize 14 (the EditableTextCoreChecks model)

        static NodeHandle TextVisual(SceneStore s, NodeHandle n)
        {
            if (n.IsNull) return NodeHandle.Null;
            if (s.Paint(n).VisualKind == VisualKind.Text) return n;
            for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
            {
                var r = TextVisual(s, c);
                if (!r.IsNull) return r;
            }
            return NodeHandle.Null;
        }

        // gate.touch2.pressed-no-hover: a touch TAP on a Button drives the Pressed visual (NodeFlags.Pressed + the
        // InteractionAnimator's PressT — the OnPressChanged → SetPress arm, observed as a live animator census) on the
        // DOWN edge, then releases to Normal on UP (Pressed clears, hover NEVER set — touch has no cursor, so a released
        // tap settles to Normal, not PointerOver). A contact moving across the button ROW by sequential taps fires the
        // Pressed visual on each button it taps yet delivers ZERO hover callbacks the whole way (a tap never sets hover;
        // any transient move-hover would be cleared on up regardless — here there is no intra-tap move, so none is set).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("touch2-press", new Size2(320, 80), 1f)); window.Show();
            var probe = new TouchButtonRowProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            var scene = host.Scene;
            // Locate the three button nodes by role (left→right).
            var btns = new List<NodeHandle>();
            CollectRole(scene, scene.Root, AutomationRole.Button, btns);

            // TAP button 0: down → Pressed + PressT armed + NO hover; up → Normal (no Pressed, no resting hover).
            var b0 = CenterOf(scene, btns[0]);
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, b0, t, 21));
            host.RunFrame();
            bool pressedOnDown = (scene.Flags(btns[0]) & NodeFlags.Pressed) != 0;
            bool pressArmed = host.HasActiveWork;                            // PressT easing armed (OnPressChanged → SetPress)
            bool noHoverOnDown = AnyHovered(scene, scene.Root).IsNull;       // a touch press never sets hover
            int pressedB0 = probe.Pressed[0];                               // OnPointerPressed delivered on the down edge
            window.QueueInput(Touch(InputKind.PointerUp, b0, t + 16, 21));
            host.RunFrame();
            bool releasedToNormal = (scene.Flags(btns[0]) & NodeFlags.Pressed) == 0 && AnyHovered(scene, scene.Root).IsNull;
            int clickedB0 = probe.Clicked[0];
            s_touchClockMs = t + 1000;

            // MOVE across the row by sequential taps on buttons 1 then 2 (the contact point travels right): each taps its
            // own button (Pressed visual + click), and across the WHOLE sequence not one hover callback ever fired.
            for (int i = 1; i < TouchButtonRowProbe.N; i++)
            {
                var c = CenterOf(scene, btns[i]);
                uint ti = s_touchClockMs;
                window.QueueInput(Touch(InputKind.PointerDown, c, ti, 21));
                host.RunFrame();
                bool pr = (scene.Flags(btns[i]) & NodeFlags.Pressed) != 0;
                window.QueueInput(Touch(InputKind.PointerUp, c, ti + 16, 21));
                host.RunFrame();
                if (!pr) probe.Pressed[i] = -1000;   // poison the assert if a tapped button never showed Pressed
                s_touchClockMs = ti + 1000;
            }
            bool everyTapPressed = probe.Pressed[0] == 1 && probe.Pressed[1] == 1 && probe.Pressed[2] == 1
                                   && probe.Clicked[0] == 1 && probe.Clicked[1] == 1 && probe.Clicked[2] == 1;
            bool noHoverEver = probe.HoverCallbacks == 0;                    // touch never delivered hover to any button
            bool noRestingHover = AnyHovered(scene, scene.Root).IsNull;     // and nothing rests hovered at the end

            Check("gate.touch2.pressed-no-hover a touch tap drives the Pressed visual (NodeFlags.Pressed + PressT armed) and releases to Normal on up; taps moving across a button row deliver zero hover callbacks and leave no resting hover (touch has no cursor)",
                pressedOnDown && pressArmed && noHoverOnDown && pressedB0 == 1 && clickedB0 == 1
                && releasedToNormal && everyTapPressed && noHoverEver && noRestingHover,
                $"pressedDown={pressedOnDown} pressArmed={pressArmed} hoverDown={!noHoverOnDown} normalAfterUp={releasedToNormal} pressed=[{probe.Pressed[0]},{probe.Pressed[1]},{probe.Pressed[2]}] clicked=[{probe.Clicked[0]},{probe.Clicked[1]},{probe.Clicked[2]}] hoverCallbacks={probe.HoverCallbacks} restingHover={!noRestingHover}");
        }

        // gate.touch2.light-dismiss: a TOUCH press outside an open light-dismiss flyout closes it AND is consumed by the
        // scrim (the behind-content never clicks through), and that observable outcome MATCHES the MOUSE path on the SAME
        // scene — the requirement is parity, so the scenario runs once by mouse and once by touch and the two outcomes are
        // compared (both dismiss == true, both no-click-through == true). The press lands on the full-bleed scrim (topmost
        // while a popup is open), whose OnClick = CloseTop(LightDismiss); the scrim eats the press so the behind surface
        // never sees it (WinUI CPopupRoot::OnPointerPressed Handled=didCloseAPopup, popup.cpp:5206).
        {
            (bool dismissed, int behindClicks) RunDismiss(bool touch)
            {
                using var app = new HeadlessPlatformApp();
                var window = new HeadlessWindow(new WindowDesc(touch ? "touch2-dismiss-t" : "touch2-dismiss-m", new Size2(480, 360), 1f)); window.Show();
                var probe = new TouchDismissProbe();
                using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
                host.RunFrame();
                var svc = probe.Service!;
                Func<Element> menu = () => new BoxEl
                {
                    Width = 140, Direction = 1,
                    Children = [new BoxEl { Height = 32, Role = AutomationRole.MenuItem, OnClick = () => svc.CloseTop(), Children = [Ui.Text("Item A")] }],
                };
                bool MenuOpen() => !FindRole(host.Scene, host.Scene.Root, AutomationRole.MenuItem).IsNull;
                void Settle() { for (int i = 0; i < 16; i++) host.RunFrame(); }
                var outside = new Point2(460, 350);   // over the behind-content, far from the BottomLeft popup over (20,20)

                svc.Open(() => probe.Anchor, menu, FlyoutPlacement.BottomLeft);
                host.RunFrame();
                if (touch)
                {
                    uint t = s_touchClockMs;
                    window.QueueInput(Touch(InputKind.PointerDown, outside, t, 31));
                    window.QueueInput(Touch(InputKind.PointerUp, outside, t + 16, 31));
                    host.RunFrame();
                    s_touchClockMs = t + 1000;
                }
                else
                {
                    window.QueueInput(new InputEvent(InputKind.PointerDown, outside, 0, 0));
                    window.QueueInput(new InputEvent(InputKind.PointerUp, outside, 0, 0));
                    host.RunFrame();
                }
                Settle();
                return (!MenuOpen(), probe.BehindClicks);
            }

            var (mDismiss, mBehind) = RunDismiss(touch: false);
            var (tDismiss, tBehind) = RunDismiss(touch: true);
            bool mouseDismissedConsumed = mDismiss && mBehind == 0;
            bool touchDismissedConsumed = tDismiss && tBehind == 0;
            bool parity = mouseDismissedConsumed == touchDismissedConsumed && touchDismissedConsumed;

            Check("gate.touch2.light-dismiss a touch press outside an open flyout dismisses it and is consumed by the scrim (no click-through), MATCHING the mouse path's observable outcome on the same scene",
                parity, $"mouse(dismiss={mDismiss},behind={mBehind}) touch(dismiss={tDismiss},behind={tBehind}) parity={parity}");
        }

        // gate.touch2.caret-and-select: a touch TAP in an EditableText places the caret at the tapped offset (the OnDrag
        // node's OnPointerPressed → HandlePressed, ClickCount=1 → SetCaret at the hit), and a touch DRAG from inside the
        // text EXTENDS the selection (the OnDrag implicit-capture: TouchDown set _dragTarget=field, each move drives
        // HandleDrag → SetCaret(extend) — the selection LENGTH grows monotonically with the drag), while the editor
        // sitting INSIDE a scrollable does NOT pan (the OnDrag capture owns the contact; no pan candidate is armed).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("touch2-caret", new Size2(360, 320), 1f)); window.Show();
            var root = new TouchEditInScrollerProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            var field = FindRole(scene, scene.Root, AutomationRole.Text);
            var tn = TextVisual(scene, field);
            var ta = scene.AbsoluteRect(tn);
            var scroller = FindScrollable(scene, scene.Root);
            float wy = ta.Y + ta.H / 2f;

            // (1) TAP at offset 4 ("hell|o world") → caret lands at 4 (same HitTestText the mouse uses).
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(ta.X + 4f * Adv + 1f, wy), t, 12));
            host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(ta.X + 4f * Adv + 1f, wy), t + 16, 12));
            host.RunFrame();
            s_touchClockMs = t + 1000;
            int caretAfterTap = root.Edit!.Core.Active;   // captured at tap-time (the later drag moves the caret)
            bool caretAtTap = caretAfterTap == 4 && root.Edit!.SelectionLength == 0;

            // (2) DRAG from offset 1 rightward, reading the selection length after EACH step so it can be asserted to GROW
            // (the drag, not a tap, is extending the editor's selection). A big downward component on the drag is on the
            // scroll axis — proving the editor's OnDrag wins over a content pan even with vertical travel.
            scene.TryGetScroll(scroller, out var beforeDrag);
            float panBefore = beforeDrag.OffsetY;
            uint t2 = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(ta.X + 1f * Adv + 1f, wy), t2, 13));
            host.RunFrame();
            int prevLen = root.Edit!.SelectionLength;
            int growthSteps = 0, shrinkSteps = 0;
            for (int i = 1; i <= 6; i++)
            {
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(ta.X + (1f + i) * Adv + 1f, wy + i * 12f), t2 + (uint)i * 16, 13));
                host.RunFrame();
                int len = root.Edit!.SelectionLength;
                if (len > prevLen) growthSteps++;
                else if (len < prevLen) shrinkSteps++;
                prevLen = len;
            }
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(ta.X + 7f * Adv + 1f, wy + 72f), t2 + 7 * 16, 13));
            host.RunFrame();
            s_touchClockMs = t2 + 1000;
            scene.TryGetScroll(scroller, out var afterDrag);
            bool selectionGrew = root.Edit!.SelectionStart == 1 && root.Edit!.SelectionLength == 6 && growthSteps >= 5 && shrinkSteps == 0;
            bool noPanWhileSelecting = Near(afterDrag.OffsetY, panBefore);   // the scroller never moved while drag-selecting

            Check("gate.touch2.caret-and-select a touch tap places the caret at the tapped offset; a touch drag extends the selection (length grows monotonically with the drag) and the editor inside a scrollable does not pan while drag-selecting",
                caretAtTap && selectionGrew && noPanWhileSelecting,
                $"caretAtTap={caretAtTap} (caretAfterTap={caretAfterTap}) sel(start={root.Edit!.SelectionStart},len={root.Edit!.SelectionLength}) grow={growthSteps} shrink={shrinkSteps} pan={afterDrag.OffsetY:0.#}->was {panBefore:0.#}");
        }

        // gate.touch2.thumb-drag: a touch press+drag on the conscious overlay-scrollbar THUMB scrolls PROPORTIONALLY — the
        // offset follows the track fraction (so the thumb sweeping its full travel drives the offset to the content-end
        // clamp), driven by the per-PointerId _scrollDragNode — and the conscious bar REVEALS for the contact's duration
        // (PointerOverScrollbar + FadeT>0 while held, dropped on release so it fades). A plain (non-virtual) 800px-over-200px
        // scroller isolates the drag machinery (no realize-edge churn).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("touch2-thumb", new Size2(260, 260), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new ScrollProbe());
            host.RunFrame();
            var vp = host.Scene.Root;
            host.Scene.TryGetScroll(vp, out var sc0);
            float maxOff = MathF.Max(0f, sc0.ContentH - sc0.ViewportH);   // 800 − 200 = 600
            float laneX = 194f;   // the 200-wide viewport's scrollbar lane (x∈[188,200]); the thumb rests at the top

            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(laneX, 12f), t, 14));   // grab the thumb at the top
            host.RunFrame();
            host.Scene.TryGetScroll(vp, out var grabbed);
            bool revealedDuringContact = grabbed.PointerOverScrollbar && grabbed.FadeT > 0f;   // conscious bar revealed+expanded

            float lastOff = grabbed.OffsetY;
            int advanceSteps = 0, regressions = 0;
            const int dragSteps = 60;
            for (int s = 1; s <= dragSteps; s++)
            {
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(laneX, 12f + s * 4f), t + (uint)s, 14));   // sweep the lane
                host.RunFrame();
                host.Scene.TryGetScroll(vp, out var dsc);
                if (dsc.OffsetY > lastOff + 0.5f) advanceSteps++;
                else if (dsc.OffsetY < lastOff - 0.5f) regressions++;
                lastOff = dsc.OffsetY;
            }
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(laneX, 12f + dragSteps * 4f), t + dragSteps + 1, 14));
            host.RunFrame();
            host.Scene.TryGetScroll(vp, out var afterUp);
            s_touchClockMs = t + 1000;
            // Track-fraction proportional drive: ~240px of finger travel sweeps the thumb its whole track and the offset to
            // the content-end clamp (a 4px-axis CONTENT pan would have moved the offset ~240px and never reached max=600).
            bool proportionalToEnd = Near(afterUp.OffsetY, maxOff, 1f) && advanceSteps >= 25 && regressions == 0;
            bool fadesAfterRelease = !afterUp.PointerOverScrollbar;   // contact-duration reveal ended ⇒ the bar can fade

            Check("gate.touch2.thumb-drag a touch press+drag on the overlay scrollbar thumb scrolls proportionally (offset follows the track fraction to the content end, not a content pan) and the conscious bar reveals during the contact",
                revealedDuringContact && proportionalToEnd && fadesAfterRelease,
                $"revealed={revealedDuringContact} advanced={advanceSteps}/{dragSteps} regress={regressions} off={afterUp.OffsetY:0}/max={maxOff:0} fadesAfterRelease={fadesAfterRelease}");
        }

        // gate.touch2.alloc-zero: HotPhaseAllocBytes==0 across the flyout-open/dismiss + caret-drag sequences, measured the
        // SAME way gate.touch.fling-alloc-steady-zero does — the HOT half, not the reconcile edge. A flyout open/dismiss
        // round-trip is run end-to-end for coverage, but the per-frame HOT path measured for 0-alloc is the steady frame
        // while the flyout is OPEN (overlay live, no churn). The OPEN build, the CloseTop component re-render, and the
        // subtree TEARDOWN are Rendered=true RECONCILE-edge frames — the corpus's documented bounded-Gen0 render/reconcile
        // edge (the same class gate.touch.fling-realize-edge-is-wheel attributes to the shared reconcile edge, not touch),
        // NOT a frame-phase-6–13 hot path — so they are excluded exactly like the cold press-arg edge (PointerEventArgs per
        // Events.cs) is. The caret half measures a steady touch drag-select MOVE frame the same way.
        {
            // (A) flyout open → steady-open hot frame → touch-dismiss (the round-trip runs; the OPEN steady frame is measured).
            using (var app = new HeadlessPlatformApp())
            {
                var window = new HeadlessWindow(new WindowDesc("touch2-alloc-dismiss", new Size2(480, 360), 1f)); window.Show();
                var probe = new TouchDismissProbe();
                using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
                host.RunFrame();
                var svc = probe.Service!;
                Func<Element> menu = () => new BoxEl
                {
                    Width = 140, Direction = 1,
                    Children = [new BoxEl { Height = 32, Role = AutomationRole.MenuItem, OnClick = () => svc.CloseTop(), Children = [Ui.Text("Item A")] }],
                };
                var outside = new Point2(460, 350);

                // Warm the full open/dismiss path once (JIT the overlay open + scrim tap + close driver + teardown), drain.
                svc.Open(() => probe.Anchor, menu, FlyoutPlacement.BottomLeft); host.RunFrame();
                { uint tw = s_touchClockMs; window.QueueInput(Touch(InputKind.PointerDown, outside, tw, 41)); window.QueueInput(Touch(InputKind.PointerUp, outside, tw + 16, 41)); host.RunFrame(); s_touchClockMs = tw + 1000; }
                for (int i = 0; i < 16; i++) host.RunFrame();

                // Re-open; let the open animation settle, then MEASURE the steady-open hot frames (overlay live, no churn).
                svc.Open(() => probe.Anchor, menu, FlyoutPlacement.BottomLeft);
                host.RunFrame();   // open frame: builds the popup subtree (cold reconcile edge) — not measured
                for (int i = 0; i < 8; i++) host.RunFrame();   // let the open clip/opacity animation settle
                long worstOpenSteady = 0;
                for (int i = 0; i < 8; i++) { var f = host.RunFrame(); if (f.HotPhaseAllocBytes > worstOpenSteady) worstOpenSteady = f.HotPhaseAllocBytes; }

                // Exercise the dismiss (touch tap on the scrim) to run the path end-to-end; the CloseTop re-render + teardown
                // are reconcile-edge frames (not measured for 0-alloc, like every overlay open/close in the suite). Assert it
                // actually dismissed, so the round-trip is genuinely exercised (not a vacuous skip).
                uint t = s_touchClockMs;
                window.QueueInput(Touch(InputKind.PointerDown, outside, t, 42));
                window.QueueInput(Touch(InputKind.PointerUp, outside, t + 16, 42));
                host.RunFrame();
                for (int i = 0; i < 16; i++) host.RunFrame();   // settle the close fade + teardown
                bool dismissed = FindRole(host.Scene, host.Scene.Root, AutomationRole.MenuItem).IsNull;
                s_touchClockMs = t + 1000;

                // (B) caret drag-select hot half: warm the slab, then measure a steady drag-select MOVE frame (per-id slot
                // rebind + OnDrag drive + pooled rect slab — byte-identical to the mouse _dragTarget branch, proved clean).
                var window2 = new HeadlessWindow(new WindowDesc("touch2-alloc-caret", new Size2(360, 320), 1f)); window2.Show();
                var root = new TouchEditInScrollerProbe();
                using var host2 = new AppHost(app, window2, new HeadlessGpuDevice(), fonts, strings, root);
                host2.RunFrame();
                var scene2 = host2.Scene;
                var field2 = FindRole(scene2, scene2.Root, AutomationRole.Text);
                var tn2 = TextVisual(scene2, field2);
                var ta2 = scene2.AbsoluteRect(tn2);
                float wy2 = ta2.Y + ta2.H / 2f;

                uint t3 = s_touchClockMs;
                window2.QueueInput(Touch(InputKind.PointerDown, new Point2(ta2.X + 1f * Adv + 1f, wy2), t3, 43));
                host2.RunFrame();   // down: cold press args + caret place — not measured
                for (int i = 1; i <= 4; i++)   // warm the drag-select (pooled rect slab) over a few moves
                {
                    window2.QueueInput(Touch(InputKind.PointerMove, new Point2(ta2.X + (i % 2 == 0 ? 6f : 7f) * Adv + 1f, wy2 + 8f), t3 + (uint)i * 16, 43));
                    host2.RunFrame();
                }
                // Measure several steady drag-select MOVE frames (the caret moves back and forth inside the text, so the
                // selection re-extends each frame: per-id slot rebind + OnDrag drive + pooled rect slab, all 0-alloc). The
                // length VARIES across the back-and-forth moves — proof the measured frames were live drag-select, not no-ops.
                long worstCaret = 0;
                int minLen = int.MaxValue, maxLen = int.MinValue;
                for (int i = 0; i < 6; i++)
                {
                    float gx = ta2.X + (i % 2 == 0 ? 6f : 8f) * Adv + 1f;
                    window2.QueueInput(Touch(InputKind.PointerMove, new Point2(gx, wy2 + 8f), t3 + (uint)(6 + i) * 16, 43));
                    var f = host2.RunFrame();
                    if (f.HotPhaseAllocBytes > worstCaret) worstCaret = f.HotPhaseAllocBytes;
                    int len = root.Edit!.SelectionLength;
                    if (len < minLen) minLen = len;
                    if (len > maxLen) maxLen = len;
                }
                window2.QueueInput(Touch(InputKind.PointerUp, new Point2(ta2.X + 8f * Adv + 1f, wy2 + 8f), t3 + 13 * 16, 43));
                host2.RunFrame();
                bool caretDragLive = maxLen > minLen;   // the selection re-extended across the moves ⇒ live drag-select
                s_touchClockMs = t3 + 1000;

                Check("gate.touch2.alloc-zero the steady flyout-open hot frame AND steady touch caret drag-select frames allocate 0 managed bytes on phases 6–13 (the open-build/CloseTop-render/teardown reconcile edges + the cold press-args excluded, like the existing touch alloc gates)",
                    worstOpenSteady == 0 && worstCaret == 0 && dismissed && caretDragLive,
                    $"worstOpenSteadyHotAlloc={worstOpenSteady}B worstCaretDragHotAlloc={worstCaret}B dismissed={dismissed} caretDragLive={caretDragLive}");
            }
        }

        // gate.touch2.bar-reveals-during-pan: while touch never latches hover, the thin scrollbar INDICATOR must still reveal
        // THROUGHOUT a finger-down content pan (the WinUI TouchIndicator shows for the whole manipulation, not just the
        // post-lift fling). A content pan drives the viewport through SetScrollOffset (Offset == Target every move), so the
        // ScrollIntegrator can't infer motion from |Target − Offset|; the synchronous-move pulse reveals FadeT for each pan frame.
        // Contract: FadeT climbs > 0 DURING the drag moves (not only after lift) WITHOUT setting PointerOver (touch sets no
        // hover) and WITHOUT the 400ms full-gutter expand (ExpandT stays ~0) — exactly the lane-page-step flash. A plain
        // (non-virtual) 800px-over-200px ScrollProbe isolates the pan machinery from any realize-edge churn.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("touch2-pan-reveal", new Size2(260, 260), 1f)); window.Show();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, new ScrollProbe());
            host.RunFrame();
            var vp = host.Scene.Root;
            var vpRect = host.Scene.AbsoluteRect(vp);

            // A vertical content pan starting inside the content area (x at the viewport's content column, well clear of the
            // lane on the right edge; y at ~80% height so 12 upward 10px steps stay inside) up by 120px across 12 frames (one
            // move per RunFrame so the ring keeps each). Sample FadeT/PointerOver/ExpandT mid-drag.
            float panX = vpRect.X + 60f;
            float startY = vpRect.Y + vpRect.H * 0.8f;
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(panX, startY), t, 71));
            host.RunFrame();   // down: records the anchor, no claim yet, no reveal
            host.Scene.TryGetScroll(vp, out var atDown);
            float fadeAtDown = atDown.FadeT;   // baseline: the press alone reveals nothing (below-slop)

            float maxFadeDuringPan = 0f, maxExpandDuringPan = 0f, maxOffDuringPan = 0f;
            bool pointerOverEverSet = false;
            const int panSteps = 12;
            for (int s = 1; s <= panSteps; s++)
            {
                var p = new Point2(panX, startY - s * 10f);   // 10px/step ⇒ crosses the 4px slop on step 1, then keeps panning
                window.QueueInput(Touch(InputKind.PointerMove, p, t + (uint)(s * 16), 71));
                host.RunFrame();
                host.Scene.TryGetScroll(vp, out var dsc);
                if (dsc.FadeT > maxFadeDuringPan) maxFadeDuringPan = dsc.FadeT;
                if (dsc.ExpandT > maxExpandDuringPan) maxExpandDuringPan = dsc.ExpandT;
                if (dsc.OffsetY > maxOffDuringPan) maxOffDuringPan = dsc.OffsetY;
                if (dsc.PointerOver) pointerOverEverSet = true;
            }
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(panX, startY - panSteps * 10f), t + (uint)((panSteps + 1) * 16), 71));
            host.RunFrame();
            s_touchClockMs = t + 2000;

            bool panned = maxOffDuringPan > 50f;                       // the finger drag actually scrolled the content
            bool revealedDuringPan = maxFadeDuringPan > 0.5f;          // the thin indicator was VISIBLE mid-drag (the bug: stayed 0)
            bool noHoverLatched = !pointerOverEverSet;                 // touch never set PointerOver (no hover to clear on lift)
            bool noFullExpand = maxExpandDuringPan < 0.1f;             // a content pan never triggers the 400ms full-gutter expand
            Check("gate.touch2.bar-reveals-during-pan a finger-down content pan reveals the thin scrollbar indicator throughout the drag (FadeT>0 mid-pan, not only post-lift) without latching PointerOver or expanding the gutter",
                panned && revealedDuringPan && noHoverLatched && noFullExpand,
                $"maxFadeT_DURING_pan={maxFadeDuringPan:0.000} (down baseline {fadeAtDown:0.000}) maxExpandT={maxExpandDuringPan:0.000} pointerOver={pointerOverEverSet} pannedTo={maxOffDuringPan:0}");
        }
    }

    // ── Phase 3 ArenaCore: GestureArena (§7A) + PointerFsm (§7B) as STANDALONE units ──────────────────────────
    // Pure-logic checks driving the arena coordinator and the per-pointer FSMs DIRECTLY with synthetic votes/streams —
    // no dispatcher integration yet. They exercise the §7A.2 resolution rule (eager-win / first-accept-when-closed /
    // last-standing / pointer-up sweep / hold-release), the synthetic-GestureRejected loser reset, the innermost-first
    // priority tiebreak, and the slab's zero-per-frame-heap property over a 100-arena churn (the GC.GetAllocatedBytes
    // pattern the existing gates use). The single-recognizer common case (one member → last-standing/up-sweep) stays
    // OBSERVABLY synchronous, matching §7A.5. A small NodeHandle helper fabricates distinct route nodes for enrollment.
    static void ArenaCoreChecks(StringTable strings)
    {
        // gate.arena.eager-win-sweeps-midstream: the moment a Drag member crosses slop (EagerAccept) it wins immediately
        // and sweeps a competing Tap mid-stream (no PointerUp wait) — §7A.2 rule 1. The Tap loser is reset (Reject + the
        // synthetic GestureRejected fired exactly once).
        {
            var arena = new GestureArena();
            int rejected = 0, won = 0;
            arena.OnMemberRejected = _ => rejected++;
            arena.OnMemberWon = _ => won++;
            int slot = arena.OpenArena(pointerId: 1);
            int tap = arena.Enroll(slot, NodeAt(1), GestureKind.Tap);     // innermost first (priority 0)
            int drag = arena.Enroll(slot, NodeAt(2), GestureKind.Drag);   // priority 1
            arena.CloseArena(slot);
            // Pre-cross: both Pending, nothing resolves.
            int r0 = arena.ResolveStep(slot);
            // Drag crosses slop → EagerAccept.
            arena.SetVote(drag, ArenaVote.EagerAccept);
            int r1 = arena.ResolveStep(slot);
            bool eagerOk = r0 < 0 && r1 == drag && arena.VoteOf(drag) == ArenaVote.EagerAccept
                          && arena.VoteOf(tap) == ArenaVote.Reject && rejected == 1 && won == 1;
            Check("gate.arena.eager-win-sweeps-midstream a Drag crossing slop (EagerAccept) wins immediately and sweeps the competing Tap mid-stream (the loser is Reject + one synthetic GestureRejected), with no PointerUp wait",
                eagerOk, $"r0={r0} r1={r1}(drag={drag}) tapVote={arena.VoteOf(tap)} rejected={rejected} won={won}");
        }

        // gate.arena.first-accept-waits-for-closed: a member that votes Accept does NOT win while the arena is still OPEN
        // (a recognizer ahead could still claim it); it wins only once Closed AND no lower-priority member is Pending —
        // §7A.2 rule 2. Here the innermost (priority 0) stays Pending, so even after Close the Accept (priority 1) waits;
        // once the innermost rejects, the Accept resolves.
        {
            var arena = new GestureArena();
            int slot = arena.OpenArena(pointerId: 2);
            int inner = arena.Enroll(slot, NodeAt(1), GestureKind.Pan);    // priority 0, stays Pending
            int outer = arena.Enroll(slot, NodeAt(2), GestureKind.Tap);    // priority 1, votes Accept
            arena.SetVote(outer, ArenaVote.Accept);
            int rOpen = arena.ResolveStep(slot);                            // OPEN → Accept must NOT win yet
            arena.CloseArena(slot);
            int rClosedPending = arena.ResolveStep(slot);                   // Closed but inner still Pending AHEAD → wait
            arena.SetVote(inner, ArenaVote.Reject);
            int rClosedClear = arena.ResolveStep(slot);                     // inner gone → Accept wins
            bool firstAcceptOk = rOpen < 0 && rClosedPending < 0 && rClosedClear == outer;
            Check("gate.arena.first-accept-waits-for-closed an Accept vote does not win while the arena is open, nor while a higher-priority member is still Pending ahead of it; it resolves only once Closed and the path ahead is clear (§7A.2 rule 2)",
                firstAcceptOk, $"open={rOpen} closedPending={rClosedPending} closedClear={rClosedClear}(outer={outer})");
        }

        // gate.arena.last-standing-while-pending: a lone surviving member wins by default even while still Pending (a Tap
        // that never moved), as soon as all others reject — §7A.2 rule 3 — provided the arena is NOT Held. This is the
        // single-recognizer common case: one member resolves synchronously the moment it is the last alive.
        {
            var arena = new GestureArena();
            int won = 0; arena.OnMemberWon = _ => won++;
            int slot = arena.OpenArena(pointerId: 3);
            int tap = arena.Enroll(slot, NodeAt(1), GestureKind.Tap);     // priority 0
            int pan = arena.Enroll(slot, NodeAt(2), GestureKind.Pan);    // priority 1
            int rTwo = arena.ResolveStep(slot);                           // two alive, both Pending → no winner
            arena.SetVote(pan, ArenaVote.Reject);                         // pan bows out (never overflowed/never moved)
            int rOne = arena.ResolveStep(slot);                          // Tap is last-standing → wins while Pending
            bool lastStandingOk = rTwo < 0 && rOne == tap && won == 1 && arena.VoteOf(tap) == ArenaVote.Accept;
            // Single-recognizer fast-path: one member alone is last-standing IMMEDIATELY (synchronous, §7A.5).
            var solo = new GestureArena();
            int s2 = solo.OpenArena(pointerId: 33);
            int only = solo.Enroll(s2, NodeAt(9), GestureKind.Tap);
            int rSolo = solo.ResolveStep(s2);
            bool soloSync = rSolo == only;
            Check("gate.arena.last-standing-while-pending the lone survivor wins by default while still Pending once all others reject (§7A.2 rule 3); a SINGLE enrolled recognizer is last-standing immediately (the synchronous single-recognizer common case, §7A.5)",
                lastStandingOk && soloSync, $"two={rTwo} one={rOne}(tap={tap}) won={won} solo={rSolo}(only={only})");
        }

        // gate.arena.up-sweep-clean-tap: a clean tap (no slop crossed, single contact, no eager) stays unresolved through
        // the move stream and resolves on the PointerUp sweep — the highest-priority Accept/Pending member wins, the rest
        // reject — §7A.2 rule 4. Two non-rejecting members: the up-sweep picks the innermost (priority 0).
        {
            var arena = new GestureArena();
            int slot = arena.OpenArena(pointerId: 4);
            int inner = arena.Enroll(slot, NodeAt(1), GestureKind.Tap);    // priority 0 → up-sweep favors it
            int outer = arena.Enroll(slot, NodeAt(2), GestureKind.Tap);    // priority 1
            arena.CloseArena(slot);
            arena.SetVote(inner, ArenaVote.Accept);                         // both report a clean tap on up
            arena.SetVote(outer, ArenaVote.Accept);
            int up = arena.ResolveUp(slot);
            bool upSweepOk = up == inner && arena.VoteOf(outer) == ArenaVote.Reject;
            Check("gate.arena.up-sweep-clean-tap an unresolved clean tap resolves on the PointerUp sweep to the highest-priority (innermost) Accept/Pending member; the rest reject (§7A.2 rule 4)",
                upSweepOk, $"up={up}(inner={inner}) outerVote={arena.VoteOf(outer)}");
        }

        // gate.arena.doubletap-hold-retroactive: a DoubleTap member sets Held after the first up, keeping the arena OPEN
        // across the inter-tap window — last-standing is SUPPRESSED while Held and the up-sweep does NOT resolve it. On
        // the inter-tap TIMEOUT the hold releases and the single-Tap member wins RETROACTIVELY — §7A.2 rule 5.
        {
            var arena = new GestureArena();
            int slot = arena.OpenArena(pointerId: 5);
            int tap = arena.Enroll(slot, NodeAt(1), GestureKind.Tap);          // the retroactive single-tap winner
            int dbl = arena.Enroll(slot, NodeAt(1), GestureKind.DoubleTap);   // requests the hold
            arena.CloseArena(slot);
            // First up: the DoubleTap is waiting for a 2nd tap (its FSM stays Pending — §7B OnUp's await-2nd-tap branch)
            // and requests Held; the single Tap is ALSO still Pending (it has not decided — it wins only retroactively if
            // no double forms). Both Pending + Held ⇒ nothing resolves (last-standing AND the up-sweep are suppressed).
            arena.SetHeld(slot, true);
            int held = arena.ResolveStep(slot);            // Held → last-standing suppressed, both Pending → stays open
            int heldUp = arena.ResolveUp(slot);            // up-sweep on a Held arena resolves NOTHING (waits for the 2nd tap)
            // Inter-tap timeout: no qualifying second tap arrived → the hold releases, single-tap wins retroactively
            // (the up-sweep that now runs picks the highest-priority non-rejected member — the Tap at priority 0).
            int released = arena.ResolveHoldRelease(slot);
            bool holdOk = held < 0 && heldUp < 0 && released == tap && !arena.ArenaAt(slot).Held;
            Check("gate.arena.doubletap-hold-retroactive a DoubleTap Held keeps the arena open across the inter-tap window (last-standing AND the up-sweep both suppressed); on the inter-tap timeout the hold releases and the single Tap wins retroactively (§7A.2 rule 5)",
                holdOk, $"held={held} heldUp={heldUp} released={released}(tap={tap}) stillHeld={arena.ArenaAt(slot).Held}");
        }

        // gate.arena.loser-reset-emits-nothing: a swept loser receives the synthetic GestureRejected — its vote becomes
        // Reject and its FSM is reset to Idle (it emits NOTHING) — §7A.5. Driven over a real PointerFsm bank: a Tap loser
        // swept by a Drag eager-win resets to Idle/Pending and would fire no Tapped.
        {
            var arena = new GestureArena();
            var fsms = new PointerFsm[GestureArena.MaxArenas * GestureArena.MaxMembersPerArena];
            int rejectFires = 0;
            // The reject/win sinks drive the FSM bank exactly as the dispatcher will (reset the loser; let the winner emit).
            arena.OnMemberRejected = slot => { fsms[slot].Reset(); rejectFires++; };
            int aSlot = arena.OpenArena(pointerId: 6);
            int tapM = arena.Enroll(aSlot, NodeAt(1), GestureKind.Tap);
            int dragM = arena.Enroll(aSlot, NodeAt(2), GestureKind.Drag);
            fsms[tapM].Init(GestureKind.Tap); fsms[dragM].Init(GestureKind.Drag);
            arena.CloseArena(aSlot);
            // The Tap saw the down and accumulated a tap (TapCount=1) but is STILL Pending (no move yet); the Drag, on a
            // separate finger path, crosses slop and EagerAccepts. The Tap is swept by the SYNTHETIC GestureRejected (not a
            // self-reject) — the arena's Sweep fires OnMemberRejected, which resets the Tap FSM to Idle/Pending and wipes
            // its tap accumulation so it emits no deferred Tapped (§7A.5).
            long t = 1_000_000;
            fsms[tapM].OnDown(new Point2(100, 100), t);     // Tap is Pending with TapCount=1 (a candidate tap)
            fsms[dragM].OnDown(new Point2(100, 100), t);
            t += 16_000;
            var dragVote = fsms[dragM].OnMove(new Point2(140, 100), t);   // +40px → Drag EagerAccept (the Tap never moved)
            arena.SetVote(tapM, fsms[tapM].Vote);            // still Pending
            arena.SetVote(dragM, dragVote);
            bool tapWasArmed = arena.VoteOf(tapM) == ArenaVote.Pending && fsms[tapM].TapCount == 1;   // armed BEFORE the sweep
            int winner = arena.ResolveStep(aSlot);
            bool loserResetOk = tapWasArmed && winner == dragM && rejectFires == 1
                               && fsms[tapM].Phase == GesturePhase.Idle && fsms[tapM].Vote == ArenaVote.Pending
                               && fsms[tapM].TapCount == 0;     // synthetic reset wiped the tap accumulation → no deferred Tapped
            Check("gate.arena.loser-reset-emits-nothing a Pending Tap loser is reset to Idle/Pending by the SYNTHETIC GestureRejected (the arena's sweep fires the reject sink exactly once; the tap accumulation is wiped → emits nothing) while the eager Drag wins (§7A.5)",
                loserResetOk, $"armedPre={tapWasArmed} winner={winner}(drag={dragM}) rejectFires={rejectFires} tapPhase={fsms[tapM].Phase} tapVote={fsms[tapM].Vote} tapCount={fsms[tapM].TapCount}");
        }

        // gate.arena.innermost-priority-tiebreak: two members resolve eligibly in the SAME step — the INNERMOST (earlier
        // enrollment, lower Priority) wins; the outer rejects. §7A.1 (innermost-first) + §7A.2 (ties broken by Priority).
        // Checked on both the eager path (two EagerAccept) and the first-accept path (two Accept, Closed).
        {
            var arena = new GestureArena();
            int slot = arena.OpenArena(pointerId: 7);
            int inner = arena.Enroll(slot, NodeAt(1), GestureKind.Drag);   // priority 0 (innermost)
            int outer = arena.Enroll(slot, NodeAt(2), GestureKind.Drag);   // priority 1
            arena.SetVote(inner, ArenaVote.EagerAccept);
            arena.SetVote(outer, ArenaVote.EagerAccept);                   // both eager in one frame
            int eagerWin = arena.ResolveStep(slot);

            var arena2 = new GestureArena();
            int slot2 = arena2.OpenArena(pointerId: 8);
            int inner2 = arena2.Enroll(slot2, NodeAt(1), GestureKind.Tap);
            int outer2 = arena2.Enroll(slot2, NodeAt(2), GestureKind.Tap);
            arena2.CloseArena(slot2);
            arena2.SetVote(inner2, ArenaVote.Accept);
            arena2.SetVote(outer2, ArenaVote.Accept);
            int acceptWin = arena2.ResolveStep(slot2);

            bool tiebreakOk = eagerWin == inner && arena.VoteOf(outer) == ArenaVote.Reject
                             && acceptWin == inner2 && arena2.VoteOf(outer2) == ArenaVote.Reject;
            Check("gate.arena.innermost-priority-tiebreak when two members resolve eligibly in one step the innermost (lower Priority, earlier enrollment) wins and the outer rejects — on both the eager-win and the first-accept paths (§7A.1 + §7A.2)",
                tiebreakOk, $"eagerWin={eagerWin}(inner={inner}) acceptWin={acceptWin}(inner2={inner2})");
        }

        // gate.arena.force-close-provisional: PointerCaptureLost (§7A.5) force-closes the arena — the highest-priority
        // non-rejected member wins by default, the rest reject — even mid-stream with everyone Pending.
        {
            var arena = new GestureArena();
            int slot = arena.OpenArena(pointerId: 9);
            int a = arena.Enroll(slot, NodeAt(1), GestureKind.Pan);     // priority 0
            int b = arena.Enroll(slot, NodeAt(2), GestureKind.Tap);    // priority 1
            int forced = arena.ForceClose(slot);                       // capture lost → provisional winner = innermost
            bool forceOk = forced == a && arena.VoteOf(b) == ArenaVote.Reject;
            Check("gate.arena.force-close-provisional PointerCaptureLost force-closes the arena: the highest-priority non-rejected member wins by default and the rest reject, even mid-stream (§7A.5)",
                forceOk, $"forced={forced}(a={a}) bVote={arena.VoteOf(b)}");
        }

        // gate.arena.fsm-clean-tap-stream: a real PointerFsm drives a clean below-slop down→up = an Accept vote (a tap);
        // a Pinch FSM fed a second contact = EagerAccept (the Phase-4 pinch trigger, signature exercised now). Pure §7B.
        {
            // Monotonic non-zero µs stamps (a 0 down-time is the "no prior down" sentinel, like the touch harness's
            // 1000ms-start clock; the plan documents 0-stamps as the vacuous-fling case).
            var tapFsm = new PointerFsm(); tapFsm.Init(GestureKind.Tap);
            long t = 1_000_000;
            tapFsm.OnDown(new Point2(50, 50), t);
            t += 10_000; tapFsm.OnMove(new Point2(52, 51), t);   // 2px, within slop
            t += 10_000; var tapVote = tapFsm.OnUp(new Point2(51, 50), t);
            bool tapOk = tapVote == ArenaVote.Accept && tapFsm.Phase == GesturePhase.Tapping
                        && tapFsm.Start.X == 50 && tapFsm.Start.Y == 50;   // Start buffered as the DOWN position (§7A.5)

            var pinchFsm = new PointerFsm(); pinchFsm.Init(GestureKind.Pinch);
            pinchFsm.OnDown(new Point2(100, 100), 1_000_000);
            var pinchPending = pinchFsm.Vote;                              // a lone contact: still Pending
            var pinchVote = pinchFsm.OnSecondContact(new Point2(200, 100), 1_005_000);
            bool pinchOk = pinchPending == ArenaVote.Pending && pinchVote == ArenaVote.EagerAccept
                          && pinchFsm.Phase == GesturePhase.Manipulating;

            // Hold: a long-press timer tick ≥ 500ms with the contact still down/within slop promotes to EagerAccept.
            var holdFsm = new PointerFsm(); holdFsm.Init(GestureKind.Hold);
            long hd = 1_000_000;
            holdFsm.OnDown(new Point2(70, 70), hd);
            var holdEarly = holdFsm.OnFrameTick(hd + 300_000);            // +300ms → not yet
            var holdLate = holdFsm.OnFrameTick(hd + 550_000);            // +550ms → fires
            bool holdOk = holdEarly == ArenaVote.Pending && holdLate == ArenaVote.EagerAccept;

            Check("gate.arena.fsm-votes a clean within-slop down→up FSM votes Accept (tap, Start buffered as the DOWN position); a Pinch FSM's second contact votes EagerAccept; a Hold FSM's ≥500ms tick promotes to EagerAccept (§7B)",
                tapOk && pinchOk && holdOk,
                $"tap={tapVote}/{tapFsm.Phase} startBuf=({tapFsm.Start.X},{tapFsm.Start.Y}) pinch={pinchVote}/{pinchFsm.Phase} holdEarly={holdEarly} holdLate={holdLate}");
        }

        // gate.arena.doubletap-second-tap-wins: the OTHER branch of rule 5 — a qualifying second tap arrives inside the
        // window, so the DoubleTap FSM reaches TapCount 2 and votes Accept; fed into the arena it wins over the single Tap.
        {
            var arena = new GestureArena();
            int slot = arena.OpenArena(pointerId: 10);
            int tapM = arena.Enroll(slot, NodeAt(1), GestureKind.Tap);
            int dblM = arena.Enroll(slot, NodeAt(1), GestureKind.DoubleTap);
            arena.CloseArena(slot);
            var dbl = new PointerFsm(); dbl.Init(GestureKind.DoubleTap);
            long t = 2_000_000;
            dbl.OnDown(new Point2(80, 80), t); t += 10_000;
            dbl.OnUp(new Point2(80, 80), t); t += 120_000;          // first tap (within slop); waits for the 2nd
            dbl.OnDown(new Point2(81, 80), t); t += 10_000;          // 2nd down inside DoubleClickMs window → TapCount→2
            var dblVote = dbl.OnUp(new Point2(80, 80), t);
            arena.SetVote(dblM, dblVote);
            arena.SetVote(tapM, ArenaVote.Reject);                  // the single-tap recognizer yields to the matched double
            int winner = arena.ResolveStep(slot);
            bool secondTapOk = dbl.TapCount == 2 && dblVote == ArenaVote.Accept && winner == dblM;
            Check("gate.arena.doubletap-second-tap-wins a qualifying second tap inside the window accumulates TapCount to 2 and the DoubleTap FSM votes Accept, winning the arena over the single Tap (§7A.2 rule 5, the matched branch)",
                secondTapOk, $"tapCount={dbl.TapCount} dblVote={dblVote} winner={winner}(dbl={dblM})");
        }

        // gate.arena.velocity-sampler-ring: the VelocitySampler ring measures a steady flick speed from monotonic
        // (dtMs,dPos) samples, and a 0/duplicate-stamp stream measures ZERO (the vacuous-fling guard the harness relies on).
        {
            var vs = new VelocitySampler();
            vs.Reset(new Point2(0, 200), 1000);
            // 10 monotonic samples, 16ms apart, -6px/sample on Y → 6px/16ms = 375 px/s upward (negative Y).
            uint ms = 1000;
            float y = 200;
            for (int i = 0; i < 10; i++) { ms += 16; y -= 6; vs.Sample(new Point2(0, y), ms); }
            var v = vs.Velocity();
            bool steadyOk = v.Y < -300f && v.Y > -450f && MathF.Abs(v.X) < 1f;   // ~ -375 px/s, no X drift

            // Zero/duplicate stamps → no ring entries → zero velocity (a 0-stamp gesture is a vacuous fling).
            var vz = new VelocitySampler();
            vz.Reset(new Point2(0, 200), 0);
            float yz = 200;
            for (int i = 0; i < 10; i++) { yz -= 30; vz.Sample(new Point2(0, yz), 0); }   // all 0-stamp
            var vzero = vz.Velocity();
            bool zeroOk = vzero.X == 0f && vzero.Y == 0f;
            Check("gate.arena.velocity-sampler-ring the VelocitySampler ring measures a steady flick speed (~-375px/s) from monotonic (dtMs,dPos) samples; a 0/duplicate-stamp stream measures exactly zero (the vacuous-fling guard, §7B)",
                steadyOk && zeroOk, $"steady=({v.X:0},{v.Y:0}) zero=({vzero.X:0},{vzero.Y:0})");
        }

        // gate.arena.churn-zero-alloc: 100 full arena lifecycles (open → enroll 3 → vote → resolve → free) allocate ZERO
        // managed bytes after warmup — the slab seats/member spans/votes are all fixed storage reused in place (the
        // GC.GetAllocatedBytesForCurrentThread delta the existing 0-alloc gates use). Proves the §7A.4 zero-per-frame-heap
        // claim for the coordinator. A SHARED arena instance is reused across the churn (seat recycle, no growth).
        {
            var arena = new GestureArena();
            arena.OnMemberRejected = static _ => { };   // non-null sinks (the dispatcher always wires them) — no closure alloc per call
            arena.OnMemberWon = static _ => { };
            // Warm: JIT the open/enroll/resolve/free path + let the sinks settle before measuring.
            ChurnArenas(arena, 4);
            long before = GC.GetAllocatedBytesForCurrentThread();
            ChurnArenas(arena, 100);
            long after = GC.GetAllocatedBytesForCurrentThread();
            long delta = after - before;
            bool zeroAlloc = delta == 0;
            Check("gate.arena.churn-zero-alloc 100 full arena lifecycles (open→enroll 3→vote→resolve→free) allocate 0 managed bytes after warmup — slab seats, (offset,len) member spans, and in-place votes are reused with zero growth (§7A.4)",
                zeroAlloc, $"delta={delta}B over 100 arenas, openCount={arena.OpenArenaCount}");
        }

        // gate.arena.team: the §7A.3 selection team (SelectionDrag + Tap under a Tap captain). The prose (NOT the §7A.2
        // pseudocode) governs: internal members never reject each other pre-slop; the captain stands for the team; on a
        // CLEAN UP the captain picks Tap (tap-count, no movement); on a SLOP-CROSS the drag-extend teammate makes the team
        // eager-win and the captain picks the drag. Driven directly over the arena + a real PointerFsm bank (the gate.arena
        // unit pattern), with one NON-team competitor (an outer Pan) so the win still sweeps non-teammates.
        {
            // (A) PRE-SLOP non-rejection + CLEAN-UP picks Tap.
            var arena = new GestureArena();
            var fsms = new PointerFsm[GestureArena.MaxArenas * GestureArena.MaxMembersPerArena];
            int rejects = 0;
            arena.OnMemberRejected = slot => { fsms[slot].Reset(); rejects++; };
            int slotA = arena.OpenArena(pointerId: 21);
            int selDrag = arena.Enroll(slotA, NodeAt(1), GestureKind.SelectionDrag);   // innermost team member (drag-extend)
            int selTap = arena.Enroll(slotA, NodeAt(1), GestureKind.Tap);              // the captain
            int outPan = arena.Enroll(slotA, NodeAt(2), GestureKind.Pan);              // a NON-team competitor (outer scroller)
            arena.EnrollTeam(slotA, captainSlot: selTap, memberOffset: selDrag, memberLen: selTap - selDrag + 1);
            fsms[selDrag].Init(GestureKind.SelectionDrag); fsms[selTap].Init(GestureKind.Tap); fsms[outPan].Init(GestureKind.Pan);
            long t = 1_000_000;
            fsms[selDrag].OnDown(new Point2(60, 60), t); arena.SetVote(selDrag, fsms[selDrag].Vote);
            fsms[selTap].OnDown(new Point2(60, 60), t); arena.SetVote(selTap, fsms[selTap].Vote);
            fsms[outPan].OnDown(new Point2(60, 60), t); arena.SetVote(outPan, fsms[outPan].Vote);
            // A within-slop move: NObody crosses slop. ResolveStep must NOT internally reject a teammate (§7A.3) and must
            // NOT resolve (the team + the Pan are two live entries, both Pending).
            t += 16_000;
            fsms[selDrag].OnMove(new Point2(62, 61), t); arena.SetVote(selDrag, fsms[selDrag].Vote);   // within slop → Pending
            fsms[outPan].OnMove(new Point2(62, 61), t); arena.SetVote(outPan, fsms[outPan].Vote);
            int midResolve = arena.ResolveStep(slotA);
            bool preSlopNoReject = midResolve < 0 && rejects == 0
                                   && arena.VoteOf(selDrag) != ArenaVote.Reject && arena.VoteOf(selTap) != ArenaVote.Reject;
            // Clean up: the Tap captain votes Accept (within slop), the drag stays Pending, the outer Pan votes Reject (a
            // lone contact lifting is no pan). The up-sweep resolves to the team's CAPTAIN (not the innermost drag), the
            // drag teammate is RETAINED (not rejected — only the non-team Pan is swept), and the captain picks Tap.
            t += 16_000;
            arena.SetVote(selTap, fsms[selTap].OnUp(new Point2(61, 60), t));    // within slop → Accept
            arena.SetVote(outPan, fsms[outPan].OnUp(new Point2(61, 60), t));    // Pan → Reject
            int upWin = arena.ResolveUp(slotA);
            bool cleanUpPicksTap = upWin == selTap
                                   && arena.CaptainPick(slotA) == GestureKind.Tap
                                   && arena.VoteOf(selDrag) != ArenaVote.Reject   // teammate retained (no internal reject)
                                   && arena.VoteOf(outPan) == ArenaVote.Reject;   // the non-team competitor was swept

            // (B) SLOP-CROSS picks the drag. Fresh arena; the drag-extend teammate crosses slop → the team eager-wins.
            var arena2 = new GestureArena();
            var fsms2 = new PointerFsm[GestureArena.MaxArenas * GestureArena.MaxMembersPerArena];
            int rejects2 = 0;
            arena2.OnMemberRejected = slot => { fsms2[slot].Reset(); rejects2++; };
            int slotB = arena2.OpenArena(pointerId: 22);
            int selDrag2 = arena2.Enroll(slotB, NodeAt(1), GestureKind.SelectionDrag);
            int selTap2 = arena2.Enroll(slotB, NodeAt(1), GestureKind.Tap);
            int outPan2 = arena2.Enroll(slotB, NodeAt(2), GestureKind.Pan);
            arena2.EnrollTeam(slotB, captainSlot: selTap2, memberOffset: selDrag2, memberLen: selTap2 - selDrag2 + 1);
            fsms2[selDrag2].Init(GestureKind.SelectionDrag); fsms2[selTap2].Init(GestureKind.Tap); fsms2[outPan2].Init(GestureKind.Pan);
            long t2 = 2_000_000;
            fsms2[selDrag2].OnDown(new Point2(60, 60), t2); arena2.SetVote(selDrag2, fsms2[selDrag2].Vote);
            fsms2[selTap2].OnDown(new Point2(60, 60), t2); arena2.SetVote(selTap2, fsms2[selTap2].Vote);
            fsms2[outPan2].OnDown(new Point2(60, 60), t2); arena2.SetVote(outPan2, fsms2[outPan2].Vote);
            t2 += 16_000;
            arena2.SetVote(selDrag2, fsms2[selDrag2].OnMove(new Point2(110, 60), t2));   // +50px → SelectionDrag EagerAccept
            int dragWin = arena2.ResolveStep(slotB);
            // The team eager-wins via the captain; CaptainPick returns the drag (movement); the Tap teammate is retained;
            // the outer Pan is swept (it is not in the team).
            bool slopCrossPicksDrag = dragWin == selTap2
                                      && arena2.CaptainPick(slotB) == GestureKind.SelectionDrag
                                      && arena2.VoteOf(selTap2) != ArenaVote.Reject
                                      && arena2.VoteOf(outPan2) == ArenaVote.Reject
                                      && rejects2 == 1;   // exactly the non-team Pan was rejected (the teammate was not)

            Check("gate.arena.team a SelectionDrag+Tap selection team (captain=Tap) never internally rejects pre-slop; a clean up resolves to the CAPTAIN and CaptainPick=Tap (the drag teammate retained, the outer Pan swept); a slop-cross makes the team eager-win and CaptainPick=SelectionDrag (§7A.3, the prose semantics)",
                preSlopNoReject && cleanUpPicksTap && slopCrossPicksDrag,
                $"preSlopNoReject={preSlopNoReject}(mid={midResolve} rej={rejects}) cleanUp={cleanUpPicksTap}(win={upWin} sel={selTap} pick={arena.CaptainPick(slotA)}) slopCross={slopCrossPicksDrag}(win={dragWin} pick={arena2.CaptainPick(slotB)} rej2={rejects2})");
        }
    }

    /// <summary>Run N full arena lifecycles on a shared coordinator (open → enroll Tap/Drag/Pan → vote a Drag eager-win →
    /// resolve → free) with NO heap allocation — the churn body for <c>gate.arena.churn-zero-alloc</c>. Each iteration
    /// recycles the same seat, so the cap-10 slab never grows.</summary>
    static void ChurnArenas(GestureArena arena, int n)
    {
        for (int i = 0; i < n; i++)
        {
            int slot = arena.OpenArena(pointerId: (uint)(i % GestureArena.MaxArenas));
            if (slot < 0) { continue; }   // (won't happen: each is freed before the next, but guard deterministically)
            int tap = arena.Enroll(slot, NodeAt(1), GestureKind.Tap);
            int drag = arena.Enroll(slot, NodeAt(2), GestureKind.Drag);
            arena.Enroll(slot, NodeAt(3), GestureKind.Pan);
            arena.CloseArena(slot);
            arena.SetVote(drag, ArenaVote.EagerAccept);
            arena.ResolveStep(slot);
            arena.CloseAndFree(slot);
        }
    }

    /// <summary>Fabricate a distinct, stable <see cref="NodeHandle"/> for arena enrollment in the standalone unit checks
    /// (the arena treats it as an opaque route-node identity — it never dereferences it without a SceneStore). Index i,
    /// generation 1.</summary>
    static NodeHandle NodeAt(uint i) => new NodeHandle(new Handle(i, 1));

    // Phase-3 CONSUMER checks (the arena's client surface, end-to-end through the dispatcher): drag-reorder-vs-pan
    // resolved by the arena's axis-locked votes (DragController.YieldsToPan subsumed on the touch path), and the
    // UseGesture(Tap) hook routing the §13 gesture to the handler. Driven by the Phase-1 touch harness (Touch /
    // TouchGesture / s_touchClockMs monotonic stamps + the fixed animation clock), the same way the Phase-2 gates are.
    static void ArenaConsumerChecks(StringTable strings)
    {
        var fonts = new HeadlessFontSystem(strings);

        // gate.arena.reorder-vs-pan: a horizontal CanDrag strip (item-drag axis = X) inside a vertical scroller (overflow
        // on Y). A horizontal touch drag on item 0 runs ALONG the item axis ⇒ the DragReorder member eager-wins the arena
        // (the item lifts: OnDragStarted + deltas fire; the lifted node carries the DragGhost flag; the list does NOT
        // scroll). A vertical touch drag on item 0 is CROSS-axis ⇒ the Pan member eager-wins (the scroller scrolls; no
        // drag starts). Deterministic, via the arena's axis-locked votes — YieldsToPan is bypassed on the touch path.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("arena-reorder", new Size2(360, 340), 1f)); window.Show();
            var probe = new ArenaReorderInScrollerProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            var scene = host.Scene;
            var scroller = FindScrollable(scene, scene.Root);
            scene.TryGetScroll(scroller, out var sc0);
            // ContentNode → child 0 = the Direction=0 strip → its child 0 = item "a".
            var strip = Child(scene, sc0.ContentNode, 0);
            var itemA = Child(scene, strip, 0);
            var aCenter = CenterOf(scene, itemA);

            // (1) HORIZONTAL drag along the item axis ⇒ DragReorder wins. The drag stays within the strip's Y so the
            // gesture is purely along X (the item's reorder axis). 140px of X travel >> the 4px slop.
            float panBefore = sc0.OffsetY;
            TouchGesture(window, host, aCenter, new Point2(aCenter.X + 140f, aCenter.Y), 12, pointerId: 31, msPerStep: 16f);
            scene.TryGetScroll(scroller, out var afterReorder);
            bool reorderWon = probe.StartedA >= 1 && probe.DeltaA >= 1 && probe.CompletedA >= 1;
            bool listDidNotScroll = Near(afterReorder.OffsetY, panBefore);

            // (2) Fresh contact: a VERTICAL (cross-axis) drag on item 0 ⇒ Pan wins, the scroller scrolls, NO new drag.
            int startedBeforePan = probe.StartedA;
            var aCenter2 = CenterOf(scene, Child(scene, Child(scene, sc0.ContentNode, 0), 0));   // re-resolve the strip's item 0
            TouchGesture(window, host, aCenter2, new Point2(aCenter2.X, aCenter2.Y - 180f), 12, pointerId: 32, msPerStep: 16f);
            scene.TryGetScroll(scroller, out var afterPan);
            bool panWon = afterPan.OffsetY > 100f && probe.StartedA == startedBeforePan;   // scrolled + no new item-drag

            Check("gate.arena.reorder-vs-pan a horizontal touch drag-reorder of a list item inside a scroller resolves to DragReorder (item lifts, list does not scroll) while a cross-axis vertical drag pans (the scroller scrolls, no drag) — deterministic, via the arena's axis-locked votes (YieldsToPan subsumed)",
                reorderWon && listDidNotScroll && panWon,
                $"reorder(started={probe.StartedA} delta={probe.DeltaA} done={probe.CompletedA} scroll={afterReorder.OffsetY:0}->was {panBefore:0}) pan(scroll={afterPan.OffsetY:0} newStarts={probe.StartedA - startedBeforePan})");
        }

        // gate.arena.use-gesture: a UseGesture(Tap) component (its node is not otherwise clickable) receives the tap with
        // the correct position. The arena enrolls a Tap member purely from the §13 declaration; the up-sweep resolves it
        // and RouteGestureWin fires the handler with the up position. A below-slop down→up at a known point is the tap.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("arena-gesture", new Size2(320, 240), 1f)); window.Show();
            var probe = new UseGestureTapProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            // The probe's BoxEl IS the rendered root (HostNode = Scene.Root for the top-level component), so the gesture
            // sub lives on Scene.Root; a tap inside its rect hits it. Tap at a known offset inside the box.
            var br = host.Scene.AbsoluteRect(host.Scene.Root);
            var tapPt = new Point2(br.X + 30f, br.Y + 20f);
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, tapPt, t, 41));
            host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerUp, tapPt, t + 16, 41));
            host.RunFrame();
            s_touchClockMs = t + 1000;
            bool tapReceived = probe.Taps == 1;
            bool positionOk = Near(probe.LastPos.X, tapPt.X) && Near(probe.LastPos.Y, tapPt.Y);
            Check("gate.arena.use-gesture a UseGesture(Tap) component receives the tap (arena Tap member enrolled from the §13 declaration, routed on the up-sweep) with the correct position",
                tapReceived && positionOk,
                $"taps={probe.Taps} pos=({probe.LastPos.X:0.#},{probe.LastPos.Y:0.#}) expected=({tapPt.X:0.#},{tapPt.Y:0.#}) subs={host.Scene.HasGestureSubs}");
        }

        // gate.arena.swipe-phone-settle: the iOS-model swipe resolution statics. Signed velocity projection opens a
        // fast short flick and a reversed flick cancels; the fresh-open threshold sits at 0.6×cluster; an open row
        // holds positional wobble but closes on a deliberate >=31px/s inward flick; a FullSwipe (Execute) side tracks
        // 1:1 to the full control width (no rubber band — the full-swipe zone needs the travel) while a Reveal side
        // keeps the bounded elastic; the full-swipe arm threshold is CLUSTER-TIED (cluster + 80..140 slack, ceilinged
        // by 0.5×controlW — ≈0.5×width on a phone-width row, no dead band past a small cluster on a desktop-width
        // row) and the release commit uses the PROJECTED rest against the same threshold (a reversed flick cancels
        // a positional arm).
        {
            float resisted = SwipeControlCore.ResistPastExtent(-168f, -68f, 68f);
            bool boundedGive = resisted < -68f && resisted > -81.6f;   // give, but below the 20%-extent asymptote
            bool fastShortOpens = SwipeControlCore.ShouldRestOpen(false, 30f, 68f, 600f);
            bool reversedCancels = !SwipeControlCore.ShouldRestOpen(false, 80f, 68f, -600f);
            bool freshAtSixTenths = SwipeControlCore.ShouldRestOpen(false, 41f, 68f, 0f)      // 0.6×68 = 40.8
                                 && !SwipeControlCore.ShouldRestOpen(false, 40f, 68f, 0f);
            bool openWobbleHolds = SwipeControlCore.ShouldRestOpen(true, 60f, 68f, 0f);
            bool inwardFlickCloses = !SwipeControlCore.ShouldRestOpen(true, 60f, 68f, -40f);
            bool halfwayCloses = !SwipeControlCore.ShouldRestOpen(true, 20f, 68f, 0f);
            bool executeFreeTravel = SwipeControlCore.DragOffset(-290f, 0f, 76f, false, true, 300f) == -290f   // 1:1 past the cluster…
                                  && SwipeControlCore.DragOffset(-400f, 0f, 76f, false, true, 300f) == -300f;  // …hard stop at controlW
            float revealResist = SwipeControlCore.DragOffset(-168f, 0f, 68f, false, false, 300f);
            bool revealBands = revealResist < -68f && revealResist > -81.6f;                   // Reveal keeps the elastic
            float armPhone = SwipeControlCore.ArmThreshold(300f, 68f);     // 68 + clamp(150−68, 80, 140) = 150 ⇒ 0.5×W where the cluster is near half-width
            float armDesktop = SwipeControlCore.ArmThreshold(900f, 90f);   // 90 + 140 slack cap = 230 ⇒ no dead band past a small cluster on a wide row
            float armCramped = SwipeControlCore.ArmThreshold(300f, 160f);  // 160 + 80 slack floor = 240 ⇒ arming stays a distinct step past resting open
            bool armThresholdTiers = armPhone == 150f && armDesktop == 230f && armCramped == 240f;
            bool armFlips = !SwipeControlCore.IsArmed(149f, armPhone) && SwipeControlCore.IsArmed(150f, armPhone);
            bool commitProjects = SwipeControlCore.ShouldCommit(SwipeControlCore.ProjectedDistance(80f, 600f), armPhone)
                               && !SwipeControlCore.ShouldCommit(SwipeControlCore.ProjectedDistance(80f, -600f), armPhone);
            float livePlate = SwipeControlCore.ExpandedPrimaryWidth(450f, 52f, 0f);
            bool plateFollowsReveal = livePlate == 430f && livePlate < 900f;   // 20px insets; never jumps to row width
            Check("gate.arena.swipe-phone-settle swipe resolution statics: signed flick projection (fast short opens, reversed cancels), 0.6x-cluster fresh-open threshold, halfway open-state hysteresis with the 31px/s inward-close floor, FullSwipe 1:1 travel to controlW vs Reveal bounded elastic, cluster-tied arm threshold (0.5xW phone / cluster+140 desktop / cluster+80 floor), projected-velocity commit, and armed primary width follows the live reveal",
                boundedGive && fastShortOpens && reversedCancels && freshAtSixTenths && openWobbleHolds && inwardFlickCloses && halfwayCloses && executeFreeTravel && revealBands && armThresholdTiers && armFlips && commitProjects && plateFollowsReveal,
                $"resisted={resisted:0.0} fastOpen={fastShortOpens} reverseCancel={reversedCancels} fresh0.6={freshAtSixTenths} wobble={openWobbleHolds} inwardClose={inwardFlickCloses} halfwayClose={halfwayCloses} execFree={executeFreeTravel} revealBand={revealResist:0.0} armTiers=({armPhone:0}/{armDesktop:0}/{armCramped:0}) armFlip={armFlips} commit={commitProjects} livePlate={livePlate:0}");
        }

        // gate.arena.swipe-in-scroller: a SwipeControl row (right reveal actions, a DragYieldsToPan cross-axis Drag) at the
        // top of a VERTICAL scroller — the canonical §7A race. A HORIZONTAL touch swipe along the row reveals the actions
        // (the swipe's X-axis Drag eager-wins the arena; the scroller does NOT scroll), while a VERTICAL drag on the SAME
        // row scrolls the list (the Y-axis-locked Pan eager-wins; the swipe stays closed). Both deterministic, via the
        // axis-locked Drag-vs-Pan votes — the OnDrag eager-capture is suppressed for DragYieldsToPan so Pan can compete.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("arena-swipe", new Size2(380, 340), 1f)); window.Show();
            var probe = new SwipeInScrollerProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            var scene = host.Scene;
            var scroller = FindScrollable(scene, scene.Root);
            scene.TryGetScroll(scroller, out var sc0);
            // ContentNode → child 0 = the SwipeControl row. Its centre is the gesture anchor (well within the row's height).
            var row = Child(scene, sc0.ContentNode, 0);
            var rowCenter = CenterOf(scene, row);
            // Start a touch nearer the LEFT edge of the row so a +X swipe has room to travel along the row toward the right
            // (revealing the trailing/right actions which open on a leftward... — the engine reveals the right side on a
            // negative offset; we swipe LEFT, toward -X, to reveal the right actions).
            var swStart = new Point2(rowCenter.X + 120f, rowCenter.Y);

            // (1) HORIZONTAL swipe along the row (−X, toward the right reveal) ⇒ the swipe Drag wins: content slides, list
            // stays put. 150px of X travel >> the 4px slop and >> the 100px open threshold.
            float scrollBefore = sc0.OffsetY;
            TouchGesture(window, host, swStart, new Point2(swStart.X - 150f, swStart.Y), 12, pointerId: 51, msPerStep: 16f);
            for (int i = 0; i < 4; i++) host.RunFrame();   // let the open glide seed/advance
            scene.TryGetScroll(scroller, out var afterSwipe);
            float revealedX = MaxAbsTrackX(host, scroller);
            bool swipeOpened = revealedX > 1f;                       // content translated sideways (revealed)
            bool listHeld = Near(afterSwipe.OffsetY, scrollBefore);  // the list did NOT scroll

            // (2) Fresh contact: a VERTICAL drag on the SAME row ⇒ Pan wins, the list scrolls. (The swipe from (1) is still
            // open; a vertical drag must scroll the list regardless, NOT pan the swipe further.) 180px of Y travel up.
            var row2 = Child(scene, sc0.ContentNode, 0);
            var v2Start = CenterOf(scene, row2);
            float scrollBeforeV = afterSwipe.OffsetY;
            TouchGesture(window, host, v2Start, new Point2(v2Start.X, v2Start.Y - 180f), 12, pointerId: 52, msPerStep: 16f);
            scene.TryGetScroll(scroller, out var afterPan);
            bool listScrolled = afterPan.OffsetY > scrollBeforeV + 100f;   // the list scrolled on the vertical drag

            Check("gate.arena.swipe-in-scroller a horizontal touch swipe on a SwipeControl row inside a vertical scroller reveals the row's actions (the cross-axis Drag eager-wins; the list holds) while a vertical drag on the same row scrolls the list (the scroll-axis Pan eager-wins) — deterministic via the axis-locked Drag-vs-Pan votes (DragYieldsToPan)",
                swipeOpened && listHeld && listScrolled,
                $"swipe(revealX={revealedX:0.#} listOffset={afterSwipe.OffsetY:0}->was {scrollBefore:0}) pan(offset={afterPan.OffsetY:0}->was {scrollBeforeV:0})");
        }

        // gate.arena.swipe-wrapped-interactive-row: the Phase-D §7A.1 route-walk composition. A SwipeControl wraps a
        // CLICKABLE row (OnClick, no drag handler of its OWN) inside a vertical scroller — so the dispatcher must WALK
        // from the hit row to the wrapper's DragYieldsToPan Drag member for the swipe to arm. (a) a horizontal touch
        // swipe reveals the actions WITHOUT clicking the row; (b) a vertical drag scrolls the list; (c) a below-slop tap
        // still clicks the row (the Tap wins the up-sweep — the enrolled swipe Drag never crossed slop); (d) a MOUSE
        // press+horizontal-move never pans (mouse OnDrag is hit-node-only, the walk is touch-only, and the TouchOnly belt
        // no-ops PanMove). This is the exact composition RowSwipe ships on queue/eager rows.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("swipe-wrapped", new Size2(380, 340), 1f)); window.Show();
            var probe = new SwipeWrappedRowProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            var scene = host.Scene;
            var scroller = FindScrollable(scene, scene.Root);
            scene.TryGetScroll(scroller, out var sc0);
            var row = Child(scene, sc0.ContentNode, 0);
            var rowCenter = CenterOf(scene, row);

            // (c) below-slop tap ⇒ the inner ROW clicks (the walk enrolls a swipe Drag member, but below slop nothing
            // eager-wins → the up-sweep resolves the row's Tap → OnClick). Done first, while the row is closed.
            uint tt = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, rowCenter, tt, 81));
            host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(rowCenter.X + 2f, rowCenter.Y), tt + 16, 81));
            host.RunFrame();
            s_touchClockMs = tt + 1000;
            bool tapClicked = probe.RowClicks == 1;

            // (a) horizontal swipe (−X toward the right reveal) ⇒ the walk-found wrapper Drag eager-wins: content slides,
            // the row does NOT click, the list holds. 150px of X travel >> the 4px slop and the 100px open threshold.
            int clicksBeforeSwipe = probe.RowClicks;
            float scrollBefore = sc0.OffsetY;
            var swStart = new Point2(rowCenter.X + 120f, rowCenter.Y);
            TouchGesture(window, host, swStart, new Point2(swStart.X - 150f, swStart.Y), 12, pointerId: 82, msPerStep: 16f);
            for (int i = 0; i < 4; i++) host.RunFrame();   // let the open glide seed/advance
            scene.TryGetScroll(scroller, out var afterSwipe);
            float revealedX = MaxAbsTrackX(host, scroller);
            bool swipeRevealed = revealedX > 1f;
            bool noClickOnSwipe = probe.RowClicks == clicksBeforeSwipe;
            bool listHeld = Near(afterSwipe.OffsetY, scrollBefore);

            // A press elsewhere in the list dismisses the open row through the host-level pointer observer.
            var outside = new Point2(20f, 300f);
            window.QueueInput(new InputEvent(InputKind.PointerDown, outside, 0, 0));
            window.QueueInput(new InputEvent(InputKind.PointerUp, outside, 0, 0));
            host.RunFrame();
            for (int i = 0; i < 12; i++) host.RunFrame();
            bool outsidePressClosed = MaxAbsTrackX(host, scroller) < 1f;

            TouchGesture(window, host, swStart, new Point2(swStart.X - 150f, swStart.Y), 12, pointerId: 84, msPerStep: 16f);
            for (int i = 0; i < 4; i++) host.RunFrame();

            // Routed focus leaving the SwipeControl subtree closes it; no translated row may remain stranded after
            // the user tabs/clicks elsewhere.
            host.Input.SetFocus(NodeHandle.Null);
            for (int i = 0; i < 12; i++) host.RunFrame();
            bool focusLossClosed = MaxAbsTrackX(host, scroller) < 1f;

            TouchGesture(window, host, swStart, new Point2(swStart.X - 150f, swStart.Y), 12, pointerId: 85, msPerStep: 16f);
            for (int i = 0; i < 4; i++) host.RunFrame();
            window.IsActive = false; host.RunFrame();
            for (int i = 0; i < 12; i++) host.RunFrame();
            bool windowBlurClosed = MaxAbsTrackX(host, scroller) < 1f;
            window.IsActive = true; host.RunFrame();

            // (b) fresh contact: a vertical drag scrolls the list (the scroll-axis Pan eager-wins; the open-row tap shield
            // carries no drag handler, so the press still route-walks to the wrapper and the Pan competes normally).
            var v2 = CenterOf(scene, Child(scene, sc0.ContentNode, 0));
            float scrollBeforeV = afterSwipe.OffsetY;
            TouchGesture(window, host, v2, new Point2(v2.X, v2.Y - 180f), 12, pointerId: 83, msPerStep: 16f);
            scene.TryGetScroll(scroller, out var afterPan);
            bool listScrolled = afterPan.OffsetY > scrollBeforeV + 100f;

            // (d) MOUSE press + horizontal move on a FRESH host ⇒ NO pan: the content must not translate.
            using var appM = new HeadlessPlatformApp();
            var windowM = new HeadlessWindow(new WindowDesc("swipe-wrapped-mouse", new Size2(380, 340), 1f)); windowM.Show();
            var probeM = new SwipeWrappedRowProbe();
            using var hostM = new AppHost(appM, windowM, new HeadlessGpuDevice(), fonts, strings, probeM);
            hostM.RunFrame();
            var sceneM = hostM.Scene;
            var scrollerM = FindScrollable(sceneM, sceneM.Root);
            sceneM.TryGetScroll(scrollerM, out var scM);
            var rcM = CenterOf(sceneM, Child(sceneM, scM.ContentNode, 0));
            windowM.QueueInput(new InputEvent(InputKind.PointerDown, new Point2(rcM.X + 120f, rcM.Y), 0, 0, 0f, KeyModifiers.None, PointerKind.Mouse, false, 5_000));
            hostM.RunFrame();
            for (int i = 1; i <= 12; i++)
            {
                windowM.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(rcM.X + 120f - i * 12f, rcM.Y), 0, 0, 0f, KeyModifiers.None, PointerKind.Mouse, false, 5_000 + (uint)i * 16));
                hostM.RunFrame();
            }
            windowM.QueueInput(new InputEvent(InputKind.PointerUp, new Point2(rcM.X - 30f, rcM.Y), 0, 0, 0f, KeyModifiers.None, PointerKind.Mouse, false, 5_000 + 13 * 16));
            hostM.RunFrame();
            float mouseTrackX = MaxAbsTrackX(hostM, scrollerM);
            bool mouseNoSwipe = mouseTrackX < 1f;

            Check("gate.arena.swipe-wrapped-interactive-row a SwipeControl wrapping a CLICKABLE row (no drag handler of its own) inside a vertical scroller route-walks to the wrapper's Drag member: a horizontal touch swipe reveals the actions without clicking the row, a vertical drag scrolls, a below-slop tap still clicks the row, and a mouse press+move never pans (touch-only arena + the TouchOnly belt)",
                tapClicked && swipeRevealed && noClickOnSwipe && listHeld && outsidePressClosed && focusLossClosed && windowBlurClosed && listScrolled && mouseNoSwipe,
                $"tap(click={probe.RowClicks}) swipe(revealX={revealedX:0.#} click+={probe.RowClicks - clicksBeforeSwipe} listHeld={listHeld} outside={outsidePressClosed} focus={focusLossClosed} blur={windowBlurClosed}) pan(off={afterPan.OffsetY:0}->was {scrollBeforeV:0}) mouseTrackX={mouseTrackX:0.##}");
        }

        // gate.arena.swipe-recycle-reset: the bound-slot RECYCLE contract. An OPEN SwipeControl row snap-closes
        // (TranslateX → 0, NO glide) when its ResetKey signal bumps — a scrolled-off slot rebinding to a new track must
        // present it CLOSED the same frame. Open the row by a horizontal swipe, bump the key, assert the pan zeroed.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("swipe-reset", new Size2(380, 340), 1f)); window.Show();
            var probe = new SwipeResetProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            var scene = host.Scene;
            var scroller = FindScrollable(scene, scene.Root);
            scene.TryGetScroll(scroller, out var sc0);
            var rc = CenterOf(scene, Child(scene, sc0.ContentNode, 0));
            var swStart = new Point2(rc.X + 120f, rc.Y);
            TouchGesture(window, host, swStart, new Point2(swStart.X - 150f, swStart.Y), 12, pointerId: 84, msPerStep: 16f);
            for (int i = 0; i < 4; i++) host.RunFrame();
            float openX = MaxAbsTrackX(host, scroller);
            bool opened = openX > 1f;

            probe.ResetKey.Value = probe.ResetKey.Peek() + 1;   // recycle bump → the snap-close effect fires
            for (int i = 0; i < 4; i++) host.RunFrame();
            float afterReset = MaxAbsTrackX(host, scroller);
            bool snappedClosed = afterReset < 1f;

            Check("gate.arena.swipe-recycle-reset an open SwipeControl row snap-closes (TranslateX → 0, no glide) when its ResetKey signal bumps — the bound-slot recycle contract (a reused slot presents the new track closed the same frame)",
                opened && snappedClosed,
                $"openX={openX:0.#} afterResetBump={afterReset:0.##}");
        }

        // gate.arena.flipview-flick-velocity: a FlipView (UseTouchAnimationsForAllNavigation) commits on REAL release
        // velocity through the MandatorySingle snap — a fast flick navigates to the adjacent page even short of 50%, while
        // a slow drag that stays under 50% springs back to the same page. This is the velocity-projected resting offset
        // (live + v/-ln(decay)) rounded to the nearest index, rail-bounded to one page (FlipView_Partial.cpp:1643-1699).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("flip-flick", new Size2(420, 280), 1f)); window.Show();
            var probe = new FlipFlickProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            var scene = host.Scene;
            var center = CenterOf(scene, scene.Root);

            // (1) FAST flick LEFT (−X), short travel (90px << 200px = 50% of the 400px page) but high speed (8ms/step over
            // 9 steps ⇒ ~1250px/s) ⇒ the projected resting offset rails to the next page: navigates to index 1.
            TouchGesture(window, host, center, new Point2(center.X - 90f, center.Y), 9, pointerId: 61, msPerStep: 8f);
            for (int i = 0; i < 18; i++) host.RunFrame();   // let the navigate glide settle
            int afterFlick = probe.Selected;
            bool flickNavigated = afterFlick == 1;

            // (2) SLOW drag LEFT, short travel (60px << 50%) at LOW speed (60ms/step over 10 steps ⇒ ~100px/s) ⇒ the
            // projected resting offset stays under 50% ⇒ springs back to the SAME page (index 1, unchanged).
            var c2 = CenterOf(scene, scene.Root);
            TouchGesture(window, host, c2, new Point2(c2.X - 60f, c2.Y), 10, pointerId: 62, msPerStep: 60f);
            for (int i = 0; i < 18; i++) host.RunFrame();
            int afterSlow = probe.Selected;
            bool slowSprungBack = afterSlow == afterFlick;   // no further navigation (stayed on the page the flick reached)

            Check("gate.arena.flipview-flick-velocity a fast FlipView touch flick navigates the adjacent page even short of 50% (velocity-projected MandatorySingle snap) while a slow under-50% drag springs back to the same page (UseTouchAnimationsForAllNavigation, real arena velocity)",
                flickNavigated && slowSprungBack,
                $"flick→idx={afterFlick} (want 1) slow→idx={afterSlow} (want {afterFlick}, sprung-back)");
        }
    }

    // ── Phase 3 DETERMINISM: the validation.md §12.6 gesture-arena determinism gate + the remaining Phase-3 exits ──────
    // validation.md §12.6 (validation.md:1018) specifies an L2 gate that pins the gesture arena's arbitration to be
    // DETERMINISTIC — "for a fixed multi-pointer script, the gesture arena resolves to the same winner every run", with an
    // EXACT golden over "the arena resolution trace (ordered accept/reject events) + the winner", plus the capture-
    // becomes-tentative shift. validation.md:1145 (the §12.6 / §12.9-shared determinism battery) demands the same target
    // at dt ∈ {8.33, 16.67, 33.3} ms produce an identical RESOLUTION trace (offsets may differ per dt; the arbitration
    // identity must not). No code existed for this gate — it was a Phase-3 work item (the plan, §"Build the §12.6
    // recorder"). The GestureArenaRecorder (Input assembly, opt-in via GestureArena.Recorder — the Diag/WakeDiagnostics
    // zero-cost-when-off discipline) is that ledger; these gates drive it through the real dispatcher.
    static void ArenaDeterminismChecks(StringTable strings)
    {
        // gate.arena.determinism: a scripted multi-gesture sequence — tap, double-tap, hold, drag-reorder-in-scroller,
        // swipe-in-scroller, pan+fling — driven TWICE from a FRESH scene each time, with one recorder accumulating the
        // whole arbitration ledger per run. The two signatures (winner ids, vote order, sweep order) MUST be BIT-IDENTICAL
        // — the §12.6 "resolves to the same winner every run" property over the full ledger, not just the final winner.
        {
            var recA = new GestureArenaRecorder();
            var recB = new GestureArenaRecorder();
            int gesturesA = DriveArenaScript(strings, recA);
            int gesturesB = DriveArenaScript(strings, recB);
            string sigA = recA.Signature();
            string sigB = recB.Signature();
            bool identical = sigA == sigB;
            bool nonTrivial = recA.Count > 20 && !recA.Overflowed && !recB.Overflowed;   // the script exercised real arbitration
            bool sameShape = gesturesA == gesturesB && gesturesA == 6;
            if (!identical) Console.WriteLine("    [determinism diff]\n--- run A ---\n" + sigA + "--- run B ---\n" + sigB);
            Check("gate.arena.determinism a scripted tap/double-tap/hold/drag-reorder-in-scroller/swipe-in-scroller/pan+fling sequence run twice from a fresh scene produces a BIT-IDENTICAL arena trace (winner ids, vote order, sweep order) — the validation.md §12.6 L2 arena-resolution determinism property over the full ledger",
                identical && nonTrivial && sameShape,
                $"identical={identical} entriesA={recA.Count} entriesB={recB.Count} gesturesA={gesturesA} gesturesB={gesturesB} overflowA={recA.Overflowed}");
            s_arenaDeterminism = $"identical={identical} entriesA={recA.Count} entriesB={recB.Count} gesturesA={gesturesA} gesturesB={gesturesB}";
        }

        // gate.arena.determinism.integrator-sweep: the same pan+fling target, replayed at the three animation timesteps
        // validation.md:1145 names (dt ∈ {8.33, 16.67, 33.3} ms), must produce an IDENTICAL arena RESOLUTION trace
        // (winner + sweep order). The event script (positions + event stamps) is held fixed across the sweep; only the
        // animation dt varies — so the post-up fling decay lands at DIFFERENT offsets per dt (the gate asserts that too),
        // but the arena's arbitration (who wins the pan, in what order the losers are swept) is dt-invariant, exactly as
        // §12.6/validation.md:1145 demands ("same target + timestep ⇒ identical trace"; here, identical ACROSS timesteps
        // because the arbitration is on the event clock, not the animation clock — the integrator is downstream of it).
        {
            string res833 = FlingResolutionTrace(strings, dtMs: 8.33f, out float off833);
            string res1667 = FlingResolutionTrace(strings, dtMs: 16.67f, out float off1667);
            string res333 = FlingResolutionTrace(strings, dtMs: 33.3f, out float off333);
            bool traceIdentical = res833 == res1667 && res1667 == res333;
            bool nonEmptyTrace = res1667.Contains("WIN ") && res1667.Contains("Pan");   // the Pan really won (a real resolution)
            // Offsets may differ per dt — assert at least one pair DIFFERS so the sweep is genuinely varying the integrator
            // (a degenerate "all equal" would make the trace-identity vacuous). All three landing identically would still
            // pass trace-identity, but the differing-offset assertion proves the integrator actually ran at three rates.
            // The exact coast integral is intentionally almost frame-rate invariant; only the discrete settle cutoff
            // leaves a small timestep-dependent remainder. With the faster WinUI-like decay that remainder is subpixel,
            // so use a diagnostic epsilon rather than a visible-distance tolerance.
            bool offsetsVary = !Near(off833, off333, 0.01f) || !Near(off833, off1667, 0.01f);
            if (!traceIdentical) Console.WriteLine($"    [dt-sweep diff]\n8.33:\n{res833}16.67:\n{res1667}33.3:\n{res333}");
            Check("gate.arena.determinism.integrator-sweep the same pan+fling target replayed at dt ∈ {8.33,16.67,33.3}ms produces an IDENTICAL arena resolution trace (winner + sweep order) while the fling settles at dt-dependent offsets — the validation.md:1145 integrator-determinism sweep (arbitration is on the event clock, not the animation clock)",
                traceIdentical && nonEmptyTrace && offsetsVary,
                $"traceIdentical={traceIdentical} offsets=({off833:0.#},{off1667:0.#},{off333:0.#}) vary={offsetsVary} trace=[{res1667.Replace('\n', '|')}]");
            // Condense the winner line "WIN p91 m0 Pan" → "WIN Pan" (action token + gesture kind) for the summary echo.
            s_arenaIntegratorSweep = $"traceIdentical={traceIdentical} offsets=({off833:0.#},{off1667:0.#},{off333:0.#}) vary={offsetsVary} trace={CondenseWinTrace(res1667)}";
        }

        // gate.arena.fastpath-sync: the §7A.5 fast-path regression guard. A SINGLE-recognizer Slider touch drag (one
        // OnDrag member) must capture SYNCHRONOUSLY and fire OnDrag the SAME frame — the arena with one member is
        // last-standing immediately, so capture is NOT tentative and the value tracks from the first move (no deferral).
        // This is the §7A.5 "common single-recognizer case is unchanged in observable behavior" contract, asserted
        // explicitly (the regression bar: Slider/SwipeControl/EditableText must not regress under the arena).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("arena-fastpath", new Size2(320, 160), 1f)); window.Show();
            var fonts = new HeadlessFontSystem(strings);
            var probe = new FastPathSliderProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            var scene = host.Scene;
            var sliderNode = FindRole(scene, scene.Root, AutomationRole.Slider);
            var sr = scene.AbsoluteRect(sliderNode.IsNull ? scene.Root : sliderNode);
            // Press at 30% of the track, then ONE move to ~70%. The single OnDrag recognizer must capture on the first move
            // and the value must change THAT frame (synchronous capture; no across-frame deferral).
            uint t = s_touchClockMs;
            float y = sr.Y + sr.H / 2f;
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(sr.X + sr.W * 0.30f, y), t, 1));
            host.RunFrame();
            float valAfterPress = probe.Val;
            // ONE move past slop → OnDrag must fire and the value must move THIS same frame; capture must be hard (resolved),
            // not tentative (a single-member arena resolves on enrollment via last-standing).
            window.QueueInput(Touch(InputKind.PointerMove, new Point2(sr.X + sr.W * 0.70f, y), t + 16, 1));
            host.RunFrame();
            float valAfterOneMove = probe.Val;
            bool tentativeMidDrag = host.Input.Arena.CaptureIsTentative;   // a lone OnDrag recognizer ⇒ NOT tentative
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(sr.X + sr.W * 0.70f, y), t + 32, 1));
            host.RunFrame();
            s_touchClockMs = t + 1000;
            bool movedSameFrame = valAfterOneMove > valAfterPress + 0.05f;   // OnDrag fired on the first move (synchronous)
            bool capturedSync = !tentativeMidDrag;                          // single recognizer → immediate hard capture
            Check("gate.arena.fastpath-sync a single-recognizer Slider touch drag captures synchronously and fires OnDrag the SAME frame (the lone member is last-standing immediately, capture is not tentative) — the §7A.5 fast-path regression guard",
                movedSameFrame && capturedSync,
                $"press={valAfterPress:0.00} after1move={valAfterOneMove:0.00} tentativeMidDrag={tentativeMidDrag}");
            s_arenaFastpath = $"press={valAfterPress:0.00} after1move={valAfterOneMove:0.00} tentativeMidDrag={tentativeMidDrag}";
        }

        // gate.arena.alloc-zero: a MULTI-recognizer competition gesture allocates 0 managed bytes on the FRAME HOT HALF —
        // the phase-7+ work the resolved gesture drives (the captured drag/reorder controller + the scroll write/virtual
        // re-realize + record) is slab/fixed storage. Drive the reorder-vs-pan race (DragReorder + Tap + Pan members
        // competing, axis-locked votes resolving) for 30 frames and assert HotPhaseAllocBytes==0 the whole window.
        // SCOPE (matters): HotPhaseAllocBytes = GetAllocatedBytesForCurrentThread delta captured INSIDE Paint (AppHost.cs:597)
        // → it spans phases 3-11 ONLY. The per-event arena arbitration itself — EnrollTouchArena / the StepTouchArena vote
        // loop / the PointerFsm bank / the selection-team enroll / UpSweepTouchArena — runs in phase-2 Dispatch (RunFrame,
        // BEFORE Paint), OUTSIDE this window. So this gate proves the DOWNSTREAM (post-resolution) path is 0-alloc; the
        // per-event coordinator surface is covered DIRECTLY by gate.arena.dispatch-alloc-zero below (a delta wrapped around
        // host.Input.Dispatch). No recorder is attached (the production path; the recorder is a test seam).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("arena-alloc", new Size2(360, 340), 1f)); window.Show();
            var fonts = new HeadlessFontSystem(strings);
            var probe = new ArenaReorderInScrollerProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            var scene = host.Scene;
            var scroller = FindScrollable(scene, scene.Root);
            scene.TryGetScroll(scroller, out var sc0);
            var strip = Child(scene, sc0.ContentNode, 0);
            var itemA = Child(scene, strip, 0);
            var aCenter = CenterOf(scene, itemA);

            // Down on the draggable item: opens the arena with DragReorder + Tap + Pan members all competing. Then 30 moves
            // along a DIAGONAL that stays just under BOTH axis slops for the first frames (keeps three members live and
            // re-voting — the genuine multi-recognizer competition) before crossing. The down + the first warm moves JIT
            // the arena/FSM path; the measured window is the steady competition + resolution.
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, aCenter, t, 71));
            host.RunFrame();   // open + enroll (cold; excluded from the measured window)
            // Warm a couple of move frames (JIT the StepTouchArena vote/resolve path) before measuring.
            for (int i = 1; i <= 2; i++) { window.QueueInput(Touch(InputKind.PointerMove, new Point2(aCenter.X + i * 1.0f, aCenter.Y + i * 1.0f), t + (uint)i * 16, 71)); host.RunFrame(); }

            long worst = 0;
            // 30 steady competition/resolution frames: a horizontal sweep (the reorder eager-wins partway, then the
            // captured drag drives the controller) — all on fixed storage. Each move is its own frame (no coalescing).
            for (int i = 3; i <= 32; i++)
            {
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(aCenter.X + i * 6f, aCenter.Y), t + (uint)i * 16, 71));
                var f = host.RunFrame();
                if (f.HotPhaseAllocBytes > worst) worst = f.HotPhaseAllocBytes;
            }
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(aCenter.X + 33 * 6f, aCenter.Y), t + 33 * 16, 71));
            var fu = host.RunFrame();
            if (fu.HotPhaseAllocBytes > worst) worst = fu.HotPhaseAllocBytes;
            s_touchClockMs = t + 2000;
            Check("gate.arena.alloc-zero a 30-frame multi-recognizer competition (DragReorder vs Tap vs Pan, axis-locked votes resolving) allocates 0 managed bytes on the frame hot half (phases 3-11) — the resolved gesture's downstream drag/scroll/re-realize/record is slab/fixed storage (§7A.4); the per-event arbitration in phase-2 dispatch is gated by gate.arena.dispatch-alloc-zero",
                worst == 0, $"{worst} bytes worst over the 30-frame reorder-vs-pan race");
            s_arenaAllocZero = $"{worst} bytes";
        }

        // gate.arena.dispatch-alloc-zero: the COMPANION that closes gate.arena.alloc-zero's instrument gap. It measures the
        // GetAllocatedBytesForCurrentThread delta wrapped DIRECTLY around the phase-2 dispatch entrypoint — host.Input.Dispatch
        // (the public seam RunFrame calls at AppHost.cs:494, BEFORE Paint) — so the measured window IS the per-event arena
        // path the headline names: EnrollTouchArena (OpenArena + innermost-first Enroll + ArmMemberFsm = PointerFsm.Init/OnDown
        // + EnrollTeam), the StepTouchArena vote loop (PointerFsm.OnMove per live member + ResolveStep + the RouteGestureWin
        // sink), and UpSweepTouchArena (PointerFsm.OnUp + ResolveUp). Two REAL multi-recognizer scenes are driven through the
        // real dispatcher: (A) DragReorder-vs-Tap-vs-Pan (the full StepTouchArena vote loop + an eager-win sweep), and (B) a
        // selectable editor inside a scroller (the §7A.3 selection TEAM enroll: Tap/DoubleTap/SelectionDrag under a captain,
        // plus the VelocitySampler ring on the captured drag). The scene is laid out by RunFrame BEFORE measuring; the down +
        // a couple of warm moves JIT the path; the steady move stream + up is the measured window. A forced alloc on ANY of
        // those phase-2 paths (e.g. a stray new[]/closure in StepTouchArena) is caught HERE — the gap the audit demonstrated
        // with a `new byte[64]` in StepTouchArena that gate.arena.alloc-zero could not see. No recorder attached.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("arena-dispatch-alloc", new Size2(360, 340), 1f)); window.Show();
            var fonts = new HeadlessFontSystem(strings);

            // Dispatch directly via a reused 1-element buffer so the SPAN itself never allocates (the measured window must
            // contain only the dispatcher's own work, not the harness's plumbing). DispatchOne returns the dispatch's click
            // count (unused) — the call is the point. The buffer is filled in place per event.
            var one = new InputEvent[1];
            long deltaA = 0, deltaB = 0;

            // (A) The DragReorder-vs-Tap-vs-Pan race: opens an arena with three competing members and runs the full
            // StepTouchArena vote loop (axis-locked OnMove votes + ResolveStep) every move, then an eager-win sweep.
            {
                var probe = new ArenaReorderInScrollerProbe();
                using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
                host.RunFrame();                                   // lay out the scene (cold; not measured)
                var scene = host.Scene;
                var scroller = FindScrollable(scene, scene.Root);
                scene.TryGetScroll(scroller, out var sc0);
                var strip = Child(scene, sc0.ContentNode, 0);
                var itemA = Child(scene, strip, 0);
                var aCenter = CenterOf(scene, itemA);

                // Helper: drive ONE complete horizontal drag-reorder gesture (down → slop-crossing moves → up) through the
                // real dispatcher. DragReorder eager-wins along the item axis, so this exercises ClaimTouchReorder →
                // DragController.Promote/Move/Complete (the drag-ghost SetShadow/ClearShadow round-trip) AND the FSM bank.
                void DriveReorder(uint t0)
                {
                    one[0] = Touch(InputKind.PointerDown, aCenter, t0, 71); host.Input.Dispatch(one);
                    for (int i = 1; i <= 14; i++) { one[0] = Touch(InputKind.PointerMove, new Point2(aCenter.X + i * 6f, aCenter.Y), t0 + (uint)i * 16, 71); host.Input.Dispatch(one); }
                    one[0] = Touch(InputKind.PointerUp, new Point2(aCenter.X + 15 * 6f, aCenter.Y), t0 + 15 * 16, 71); host.Input.Dispatch(one);
                }

                // WARM a FULL gesture first: besides JITting the claim/promote path, this seats the drag-ghost's shadow in
                // the SceneStore shadow side-table (a Dictionary whose backing is lazily grown on the first insert, then
                // freed-not-shrunk on ClearShadow at drag-up). The MEASURED gesture below reuses that freed slot at zero
                // alloc — the one-time side-table init is a cold edge (the same warm-up discipline the churn gate uses),
                // not steady per-event work. Without this warm, the first SetShadow's Dictionary growth shows as ~256B.
                DriveReorder(s_touchClockMs);
                s_touchClockMs += 2000;

                // MEASURED: a second identical complete drag-reorder gesture. The arena open/enroll/vote/resolve/sweep, the
                // PointerFsm bank, ClaimTouchReorder, and the SetShadow/ClearShadow round-trip all run on warmed storage.
                uint t = s_touchClockMs;
                long before = GC.GetAllocatedBytesForCurrentThread();
                DriveReorder(t);
                deltaA = GC.GetAllocatedBytesForCurrentThread() - before;
                s_touchClockMs = t + 2000;
            }

            // (B) The selection TEAM: a selectable editor inside a scroller. The down enrolls Tap + DoubleTap + SelectionDrag
            // (the editor's OnDrag) under a captain (EnrollTeam) and arms their FSMs; the drag-extend moves run the captured
            // OnDrag (the §7A.5 fast-path) while the VelocitySampler ring samples — all on fixed storage.
            {
                const float Adv = 14f * 0.55f;   // headless advance model @ FontSize 14 (the EditableTextCoreChecks model)
                static NodeHandle TextVis(SceneStore s, NodeHandle n)   // nearest Text-visual descendant (the Phase-2 helper, inlined)
                {
                    if (n.IsNull) return NodeHandle.Null;
                    if (s.Paint(n).VisualKind == VisualKind.Text) return n;
                    for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c)) { var r = TextVis(s, c); if (!r.IsNull) return r; }
                    return NodeHandle.Null;
                }
                var root = new TouchEditInScrollerProbe();
                using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, root);
                host.RunFrame();                                   // lay out the scene (cold; not measured)
                var scene = host.Scene;
                var field = FindRole(scene, scene.Root, AutomationRole.Text);
                var tn = TextVis(scene, field);
                var ta = scene.AbsoluteRect(tn);
                float wy = ta.Y + ta.H / 2f;
                uint t = s_touchClockMs;

                // Down (opens the arena + enrolls the selection team + arms the FSMs) + 2 warm moves — excluded.
                one[0] = Touch(InputKind.PointerDown, new Point2(ta.X + 1f * Adv + 1f, wy), t, 17); host.Input.Dispatch(one);
                for (int i = 1; i <= 2; i++) { one[0] = Touch(InputKind.PointerMove, new Point2(ta.X + (1f + i) * Adv + 1f, wy), t + (uint)i * 16, 17); host.Input.Dispatch(one); }

                // Measured: 8 drag-extend moves (captured OnDrag + VelocitySampler ring) + the up.
                long before = GC.GetAllocatedBytesForCurrentThread();
                for (int i = 3; i <= 10; i++) { one[0] = Touch(InputKind.PointerMove, new Point2(ta.X + (1f + i) * Adv + 1f, wy + i * 4f), t + (uint)i * 16, 17); host.Input.Dispatch(one); }
                one[0] = Touch(InputKind.PointerUp, new Point2(ta.X + 11f * Adv + 1f, wy + 44f), t + 11 * 16, 17); host.Input.Dispatch(one);
                deltaB = GC.GetAllocatedBytesForCurrentThread() - before;
                s_touchClockMs = t + 2000;
            }

            long worst = Math.Max(deltaA, deltaB);
            Check("gate.arena.dispatch-alloc-zero the per-event arena path itself — EnrollTouchArena / the StepTouchArena vote loop / the PointerFsm bank / the selection-team enroll / UpSweepTouchArena, measured by a GetAllocatedBytesForCurrentThread delta wrapped DIRECTLY around host.Input.Dispatch (phase-2, before Paint) — allocates 0 managed bytes across a reorder-vs-pan race AND a selection-team drag (§7A.4)",
                worst == 0, $"reorder-vs-pan={deltaA}B selection-team={deltaB}B (direct phase-2 dispatch delta)");
            s_arenaDispatchAllocZero = $"{worst} bytes";
        }
    }

    /// <summary>Condense a §12.6 resolution-signature winner line ("WIN p&lt;id&gt; m&lt;slot&gt; &lt;Kind&gt;", possibly with
    /// trailing sweep lines) to the "&lt;action&gt; &lt;Kind&gt;" headline echoed in the final summary — the first (action)
    /// and last (gesture-kind) tokens of the first non-empty trace line. Used only by the summary echo (test/debug).</summary>
    static string CondenseWinTrace(string sig)
    {
        foreach (var line in sig.Split('\n'))
        {
            string ln = line.Trim();
            if (ln.Length == 0) continue;
            var toks = ln.Split(' ', StringSplitOptions.RemoveEmptyEntries);
            return toks.Length >= 2 ? $"{toks[0]} {toks[^1]}" : ln;
        }
        return sig.Trim();
    }

    /// <summary>Drive the fixed §12.6 multi-gesture script (tap → double-tap → hold → drag-reorder-in-scroller →
    /// swipe-in-scroller → pan+fling), each leg on a FRESH host/scene with the shared <paramref name="rec"/> attached to
    /// that host's arena, so one recorder accumulates the whole arbitration ledger. Returns the number of gesture legs
    /// driven (6) for the gate to assert the script ran in full. The trace records only ops+ids+kind+vote (no stamps), so
    /// two runs that start at different shared-clock bases produce identical ledgers.</summary>
    static int DriveArenaScript(StringTable strings, GestureArenaRecorder rec)
    {
        var fonts = new HeadlessFontSystem(strings);
        int legs = 0;

        // (1) TAP: a below-slop down→up on a clickable virtual-list row → the Tap member wins on the up-sweep.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("det-tap", new Size2(320, 420), 1f)); window.Show();
            var probe = new TouchTapPanProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            host.Input.Arena.Recorder = rec;   // attach after the mount frame (no mount-time arena activity to record)
            var row = host.Scene.Root;
            var rr = host.Scene.AbsoluteRect(row);
            var tapPt = new Point2(rr.X + 40f, rr.Y + 30f);
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, tapPt, t, 81));
            host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerUp, tapPt, t + 16, 81));
            host.RunFrame();
            s_touchClockMs = t + 1000;
            legs++;
        }

        // (2) DOUBLE-TAP: two quick within-slop taps in a selectable EditableText → the DoubleTap team member wins.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("det-dbltap", new Size2(360, 320), 1f)); window.Show();
            var probe = new TouchEditInScrollerProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            host.Input.Arena.Recorder = rec;
            var field = FindRole(host.Scene, host.Scene.Root, AutomationRole.Text);
            var tn = TextVisualNode(host.Scene, field.IsNull ? host.Scene.Root : field);
            var ta = host.Scene.AbsoluteRect(tn.IsNull ? field : tn);
            var p = new Point2(ta.X + 6f, ta.Y + ta.H / 2f);
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, p, t, 82)); host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerUp, p, t + 16, 82)); host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerDown, p, t + 80, 82)); host.RunFrame();   // 2nd tap inside the inter-tap window
            window.QueueInput(Touch(InputKind.PointerUp, p, t + 96, 82)); host.RunFrame();
            s_touchClockMs = t + 1000;
            legs++;
        }

        // (3) HOLD: a finger down on a context-request box, held idle past the long-press window → the Hold member is
        // promoted to EagerAccept by the timer tick (TickGestureArenas on the held frames) and wins.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("det-hold", new Size2(280, 220), 1f)); window.Show();
            var probe = new ArenaHoldProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            host.Input.Arena.Recorder = rec;
            var br = host.Scene.AbsoluteRect(host.Scene.Root);
            var p = new Point2(br.X + 40f, br.Y + 40f);
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, p, t, 83));
            host.RunFrame();
            // Hold idle (no move) for 45 fixed 16ms frames (=720ms > the 500ms HoldUs) so the timer promotes the Hold.
            for (int i = 0; i < 45; i++) host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerUp, p, t + 760, 83));
            host.RunFrame();
            s_touchClockMs = t + 2000;
            legs++;
        }

        // (4) DRAG-REORDER-IN-SCROLLER: a horizontal drag of a CanDrag item inside a vertical scroller → DragReorder
        // eager-wins (along the item axis), sweeping the Tap and the Pan.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("det-reorder", new Size2(360, 340), 1f)); window.Show();
            var probe = new ArenaReorderInScrollerProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            host.Input.Arena.Recorder = rec;
            host.Scene.TryGetScroll(FindScrollable(host.Scene, host.Scene.Root), out var sc0);
            var itemA = Child(host.Scene, Child(host.Scene, sc0.ContentNode, 0), 0);
            var aCenter = CenterOf(host.Scene, itemA);
            TouchGesture(window, host, aCenter, new Point2(aCenter.X + 140f, aCenter.Y), 12, pointerId: 84, msPerStep: 16f);
            legs++;
        }

        // (5) SWIPE-IN-SCROLLER: a horizontal swipe of a SwipeControl row inside a vertical scroller → the cross-axis
        // Drag eager-wins (along the row axis), sweeping the Pan.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("det-swipe", new Size2(380, 340), 1f)); window.Show();
            var probe = new SwipeInScrollerProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            host.Input.Arena.Recorder = rec;
            host.Scene.TryGetScroll(FindScrollable(host.Scene, host.Scene.Root), out var sc0);
            var row = Child(host.Scene, sc0.ContentNode, 0);
            var rowCenter = CenterOf(host.Scene, row);
            var swStart = new Point2(rowCenter.X + 120f, rowCenter.Y);
            TouchGesture(window, host, swStart, new Point2(swStart.X - 150f, swStart.Y), 12, pointerId: 85, msPerStep: 16f);
            legs++;
        }

        // (6) PAN+FLING: a vertical flick over a bound virtual list → the Pan member eager-wins (sweeping nothing else
        // on a bare list, but the Pan WIN is recorded); the fling decays downstream of the arena (on ScrollIntegrator).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("det-fling", new Size2(360, 460), 1f)); window.Show();
            var probe = new TouchFlingSettleProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            host.Input.Arena.Recorder = rec;
            TouchFlick(window, host, new Point2(150, 384), new Point2(150, 44), 16, pointerId: 86, msPerStep: 16f, decayFrames: 20);
            legs++;
        }

        return legs;
    }

    /// <summary>Drive ONE pan+fling over a bound list at animation timestep <paramref name="dtMs"/> with a recorder
    /// attached, and return its RESOLUTION sub-trace (the ordered Win + Sweep events) plus the settled offset
    /// (<paramref name="settledOff"/>). The EVENT script (positions + 16ms event stamps) is identical across calls; only
    /// the animation dt varies (a FixedFrameTimeSource at <paramref name="dtMs"/>), so the arena resolution is dt-invariant
    /// while the fling lands at a dt-dependent offset — the validation.md:1145 integrator-determinism sweep.</summary>
    static string FlingResolutionTrace(StringTable strings, float dtMs, out float settledOff)
    {
        var fonts = new HeadlessFontSystem(strings);
        var rec = new GestureArenaRecorder();
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("det-fling-dt", new Size2(360, 460), 1f)); window.Show();
        var probe = new TouchFlingSettleProbe();
        using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe, frameTime: new FixedFrameTimeSource(dtMs));
        host.RunFrame();
        host.Input.Arena.Recorder = rec;
        var vp = host.Scene.Root;
        // The event stamps (msPerStep:16) are the SAME across the dt sweep — only the animation clock differs. So the
        // velocity sampled at up is identical, the arena resolves identically, and only the post-up decay differs per dt.
        TouchGesture(window, host, new Point2(150, 384), new Point2(150, 44), 16, pointerId: 91, msPerStep: 16f);
        for (int i = 0; i < 200; i++)   // let the fling settle (more frames so the coarse dt also reaches the clamp)
        {
            host.RunFrame();
            host.Scene.TryGetScroll(vp, out var sc);
            if (sc.Phase == 0) break;   // settled (fling ended)
        }
        host.Scene.TryGetScroll(vp, out var settled);
        settledOff = settled.OffsetY;
        return rec.ResolutionSignature();
    }

    // ImageCache: state machine (Pending→Ready), source dedup, and liveness-pinned LRU eviction (pinned = on screen,
    // never evicted — the single biggest real-world image-cache bug per the research).
    static void ImageCacheChecks()
    {
        var cache = new ImageCache(new FakeImageDecoder(), budgetBytes: 1000);   // tiny budget to force eviction
        var a = cache.Request("a", 10, 10);                                      // 10×10×4 = 400 bytes when ready
        bool pending = cache.StateOf(a) == ImageState.Pending;
        cache.Pump();
        bool ready = cache.StateOf(a) == ImageState.Ready && cache.SizeOf(a) == (10, 10);
        bool dedup = cache.Request("a", 10, 10).Id == a.Id;

        cache.Pin(a);                                                            // a is "on screen"
        var b = cache.Request("b", 10, 10);
        var c = cache.Request("c", 10, 10);
        cache.Pump();                                                           // a+b+c = 1200 > 1000 → evict LRU unpinned (b)
        bool keptPinned = cache.StateOf(a) == ImageState.Ready;                  // pinned survived eviction
        bool withinBudget = cache.UsedBytes <= 1000;
        bool evictedTombstone = cache.StateOf(b) == ImageState.None;
        cache.Pin(b);                                                            // retained ImageEl re-enters with the old handle
        bool rehydratePending = cache.StateOf(b) == ImageState.Pending;
        cache.Pump();
        bool rehydrated = cache.StateOf(b) == ImageState.Ready && cache.RefsOf(b) == 1;
        Check("45. ImageCache: states, dedup, liveness-pinned LRU evict, re-pin rehydrates evicted handles",
            pending && ready && dedup && keptPinned && withinBudget && evictedTombstone && rehydratePending && rehydrated,
            $"used={cache.UsedBytes} ready={cache.ReadyCount} aRefs={cache.RefsOf(a)} b={cache.StateOf(b)} bRefs={cache.RefsOf(b)}");

        // GPU admission is part of readiness: a decoded image rejected by the backend must be Failed with zero
        // residency bytes, not a texture-less Ready handle. It retries only after the visible owner unpins it.
        bool admit = false;
        var admission = new ImageCache(new FakeImageDecoder());
        admission.SetPixelAttemptSink((_, _, _, _) =>
            admit ? ImageUploadResult.Accepted : ImageUploadResult.ResourceExhausted);
        var rejected = admission.Request("capacity", 32, 32);
        admission.Pin(rejected);
        admission.Pump();
        bool rejectedClean = admission.StateOf(rejected) == ImageState.Failed
            && admission.FailureOf(rejected) == ImageFailureKind.GpuResourceExhausted
            && admission.UsedBytes == 0 && admission.ReadyCount == 0;
        admission.Request("capacity", 32, 32);                                  // still pinned: no retry loop
        bool noPinnedRetry = admission.PendingCount == 0;
        admission.Unpin(rejected);
        admit = true;
        var retried = admission.Request("capacity", 32, 32);                    // later remount: retry same handle
        bool retryPending = retried == rejected && admission.StateOf(retried) == ImageState.Pending;
        admission.Pump();
        bool retryReady = admission.StateOf(retried) == ImageState.Ready && admission.UsedBytes == 32 * 32 * 4;
        Check("45b. ImageCache: GPU rejection never becomes Ready; unpinned remount retries",
            rejectedClean && noPinnedRetry && retryPending && retryReady,
            $"state={admission.StateOf(retried)} fail={admission.FailureOf(retried)} used={admission.UsedBytes} pending={admission.PendingCount}");

        // A saturated prefetch lane must not poison the real visible image. The scheduler reports "not accepted";
        // ImageCache leaves a non-pending tombstone under the same key, so the following Visible request restarts it.
        var droppedPrefetch = new ImageCache(new DropPrefetchDecoder());
        var warm = droppedPrefetch.Prefetch("warm", 64, 64);
        bool dropDidNotStick = droppedPrefetch.StateOf(warm) == ImageState.None && droppedPrefetch.PendingCount == 0;
        var visible = droppedPrefetch.Request("warm", 64, 64, ImagePriority.Visible);
        bool visibleRestarted = visible == warm && droppedPrefetch.StateOf(visible) == ImageState.Pending
            && droppedPrefetch.PendingCount == 1;
        droppedPrefetch.Pump();
        bool visibleReady = droppedPrefetch.StateOf(visible) == ImageState.Ready && droppedPrefetch.SizeOf(visible) == (64, 64);
        Check("45c. ImageCache: dropped prefetch does not leave a forever-pending handle; visible request restarts it",
            dropDidNotStick && visibleRestarted && visibleReady,
            $"afterDrop={droppedPrefetch.StateOf(warm)} pending={droppedPrefetch.PendingCount} ready={visibleReady}");

        // Static derivatives are keyed only by source pixels + bake parameters, never viewport/style state. They stay
        // Pending until the render handoff posts completion, then account against the derived residency budget.
        var baked = new ImageCache(new FakeImageDecoder());
        var bakeQueue = new FluentGpu.Hosting.Threading.BakedBlurQueue();
        baked.SetBakedBlurQueue(bakeQueue);
        var source = baked.Request("baked-source", 512, 256);
        baked.Pump();
        var spec = new BakedBlurSpec(26f, 0.5f);
        var d0 = baked.RequestBakedBlur(source, 512, 256, in spec);
        var d0Again = baked.RequestBakedBlur(source, 512, 256, in spec);
        var otherSpec = new BakedBlurSpec(18f, 0.5f);
        var d1 = baked.RequestBakedBlur(source, 512, 256, in otherSpec);
        bool jobs = bakeQueue.TryDequeueJob(out var j0) && bakeQueue.TryDequeueJob(out var j1);
        bool keying = d0 == d0Again && d0 != d1 && jobs && j0.SourceId == source.Id && j0.OutputW == 256 && j0.OutputH == 128;
        bakeQueue.Post(new FluentGpu.Hosting.Threading.BakedBlurQueue.Result(j0.Id, j0.Generation, true, j0.OutputW, j0.OutputH));
        baked.Pump();
        bool derivedReady = baked.StateOf(d0) == ImageState.Ready && baked.SizeOf(d0) == (256, 128)
            && baked.DerivedUsedBytes == 256 * 128 * 4;
        Check("45d. ImageCache baked blur: position/style-independent dedup, parameter fork, queued completion, derived byte accounting",
            keying && derivedReady,
            $"dedup={d0==d0Again} fork={d0!=d1} job={jobs} size={baked.SizeOf(d0)} bytes={baked.DerivedUsedBytes}");
    }

    // ImageEl end-to-end: the reconciler requests the decode + pins residency, the cache completes it (Pump), and the
    // recorder emits a DrawImage carrying the handle + ready flag + placeholder.
    static void ImageElChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("img", new Size2(480, 320), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new ImageProbe());

        host.RunFrame();
        bool drawn = device.LastImages.Count == 1;
        var cmd = drawn ? device.LastImages[0] : default;
        var h = new ImageHandle(cmd.ImageId);
        bool ready = drawn && cmd.Ready == 1 && cmd.ImageId != 0 && host.Images.StateOf(h) == ImageState.Ready;
        bool pinned = host.Images.RefsOf(h) == 1;
        bool placeholder = Near(cmd.Placeholder.R, 0x33 / 255f) && Near(cmd.Radii.TopLeft, 6f);
        Check("46. ImageEl: decode→ready, residency-pinned, DrawImage emitted", drawn && ready && pinned && placeholder,
            $"images={device.LastImages.Count} ready={cmd.Ready} refs={host.Images.RefsOf(h)}");

        // The decode's pixels must reach the GPU backend via the UploadImage seam (media-pipeline §4.1) at the decoded
        // bucket size — proves the decoder→cache.Pump→host sink→device texture-upload chain end to end.
        bool uploaded = device.Uploads.Count == 1
            && device.Uploads[0].id == cmd.ImageId && device.Uploads[0].w == 80 && device.Uploads[0].h == 80
            && device.ResidentImages.ContainsKey(cmd.ImageId);
        int uw = device.Uploads.Count > 0 ? device.Uploads[0].w : 0;
        int uh = device.Uploads.Count > 0 ? device.Uploads[0].h : 0;
        Check("46b. ImageEl: decoded pixels uploaded to the GPU backend at bucket size", uploaded,
            $"uploads={device.Uploads.Count} dims={uw}x{uh}");

        using var bakedApp = new HeadlessPlatformApp();
        var bakedWindow = new HeadlessWindow(new WindowDesc("baked-img", new Size2(480, 320), 1f));
        bakedWindow.Show();
        var bakedDevice = new HeadlessGpuDevice();
        using var bakedHost = new AppHost(bakedApp, bakedWindow, bakedDevice, fonts, strings, new BakedImageProbe());
        bakedHost.RunFrame();
        int fallbackId = bakedDevice.LastImages.Count == 1 ? bakedDevice.LastImages[0].ImageId : 0;
        bakedHost.RunFrame();
        var bakedCmd = bakedDevice.LastImages.Count == 1 ? bakedDevice.LastImages[0] : default;
        bool oneQuad = bakedDevice.LastImages.Count == 1 && bakedDevice.LastLayers.Count == 0;
        bool selectedDerived = bakedCmd.ImageId != 0 && bakedCmd.ImageId != fallbackId
            && bakedHost.Images.StateOf(new ImageHandle(bakedCmd.ImageId)) == ImageState.Ready;
        bool styling = Near(bakedCmd.Overlay.A, 0.42f) && bakedCmd.MaskEdges == (int)EdgeMask.Top
            && Near(bakedCmd.MaskTop, 24f) && Near(bakedCmd.MaskIntensity, 1f);
        Check("46c. Baked ImageEl: source fallback then persistent derived handle; overlay+mask stay in one DrawImage with zero layers",
            oneQuad && selectedDerived && styling,
            $"fallback={fallbackId} derived={bakedCmd.ImageId} draws={bakedDevice.LastImages.Count} layers={bakedDevice.LastLayers.Count} mask={bakedCmd.MaskEdges}");
    }

    // Renders the AspectTileProbe headlessly and returns the laid-out art rect + the card's inner (content) width.
    static (RectF art, float innerW) RenderAspectTile(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("aspect", new Size2(640, 520), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new AspectTileProbe());
        host.RunFrame();
        var art = device.LastImages.Count > 0 ? device.LastImages[0].Rect : default;
        return (art, AspectTileProbe.CardWidth - 24f);   // 12px padding each side
    }

    // ImageFit content mapping + aspect-ratio sizing (the album-grid overflow fix).
    static void ImageFitChecks(StringTable strings)
    {
        // A) Content-fit math (pure function the recorder uses). Source vs box aspect drives the crop/inset.
        var (drId, uvId) = SceneRecorder.ImageContentFit(ImageFit.Cover, new RectF(0, 0, 100, 100), 300, 300);  // square→square: no crop
        bool coverSquare = Near(uvId.X, 0) && Near(uvId.Y, 0) && Near(uvId.W, 1) && Near(uvId.H, 1) && Near(drId.W, 100) && Near(drId.H, 100);
        var (_, uvWide) = SceneRecorder.ImageContentFit(ImageFit.Cover, new RectF(0, 0, 200, 100), 100, 100);   // wide box, square src → crop top/bottom, centered
        bool coverWide = Near(uvWide.X, 0) && Near(uvWide.Y, 0.25f, 0.001f) && Near(uvWide.W, 1) && Near(uvWide.H, 0.5f, 0.001f);
        var (_, uvTall) = SceneRecorder.ImageContentFit(ImageFit.Cover, new RectF(0, 0, 100, 200), 100, 100);   // tall box → crop left/right
        bool coverTall = Near(uvTall.X, 0.25f, 0.001f) && Near(uvTall.Y, 0) && Near(uvTall.W, 0.5f, 0.001f) && Near(uvTall.H, 1);
        var (drContain, uvContain) = SceneRecorder.ImageContentFit(ImageFit.Contain, new RectF(0, 0, 200, 100), 100, 100);   // wide box, square src → quad shrinks to 100, centered; uv full
        bool contain = Near(uvContain.W, 1) && Near(uvContain.H, 1) && Near(drContain.X, 50) && Near(drContain.W, 100) && Near(drContain.H, 100);
        var (drFill, uvFill) = SceneRecorder.ImageContentFit(ImageFit.Fill, new RectF(0, 0, 200, 100), 100, 100);   // identity (stretch)
        bool fill = Near(uvFill.W, 1) && Near(uvFill.H, 1) && Near(drFill.W, 200) && Near(drFill.H, 100);
        var (drUnk, uvUnk) = SceneRecorder.ImageContentFit(ImageFit.Cover, new RectF(0, 0, 200, 100), 0, 0);   // unknown source → identity
        bool unknown = Near(uvUnk.W, 1) && Near(drUnk.W, 200);
        Check("46e. ImageFit math: Cover crops centered (wide/tall), Contain insets, Fill/unknown identity",
            coverSquare && coverWide && coverTall && contain && fill && unknown,
            $"coverWide uv=({uvWide.X:0.##},{uvWide.Y:0.##},{uvWide.W:0.##},{uvWide.H:0.##}) contain dr.x={drContain.X:0}");

        // B) Aspect-ratio sizing end-to-end: a responsive square tile fills its card's content width (no fixed extent),
        // stays square, and scales with the card — so a narrow cell can't overflow a hard-coded tile (the reported bug).
        AspectTileProbe.CardWidth = 200f;
        var (artN, innerN) = RenderAspectTile(strings);
        AspectTileProbe.CardWidth = 360f;
        var (artW, innerW2) = RenderAspectTile(strings);
        bool squareN = Near(artN.W, artN.H) && Near(artN.W, innerN);     // fills the 176px content width, square
        bool squareW = Near(artW.W, artW.H) && Near(artW.W, innerW2);    // fills the 336px content width, square
        bool noOverflow = artN.W <= innerN + 0.5f && artW.W <= innerW2 + 0.5f;
        bool responsive = artW.W > artN.W + 100f;                        // scales with the card, not a fixed 64/150 tile
        Check("46f. responsive image: art fills its card width & stays square (fixed-size overflow fixed)",
            squareN && squareW && noOverflow && responsive,
            $"narrow={artN.W:0}x{artN.H:0} (inner {innerN:0}) wide={artW.W:0}x{artW.H:0} (inner {innerW2:0})");
    }

    // Deterministic test codec/fetcher exercise the REAL DecodeScheduler (worker pool, channels, retry) with no network.
    sealed class TestCodec : IImageCodec
    {
        readonly Action? _onDecode;
        public TestCodec(Action? onDecode = null) => _onDecode = onDecode;
        public bool DecodeConstrained(ReadOnlySpan<byte> encoded, int tw, int th, Span<byte> dst, out int w, out int h)
        {
            _onDecode?.Invoke();
            w = tw; h = th;
            dst.Slice(0, tw * th * 4).Fill(0xFF);
            return true;
        }
    }

    sealed class TestFetcher : IImageFetcher
    {
        readonly Func<string, FetchResult>? _map;
        public TestFetcher(Func<string, FetchResult>? map = null) => _map = map;
        public Task<FetchResult> FetchAsync(string source, System.Threading.CancellationToken ct)
        {
            if (_map != null) return Task.FromResult(_map(source));
            return Task.FromResult(FetchResult.Pooled(ArrayPool<byte>.Shared.Rent(16), 16));
        }
    }

    sealed class DropPrefetchDecoder : IImageDecoder
    {
        readonly Queue<(int id, int w, int h)> _pending = new();
        byte[] _scratch = Array.Empty<byte>();

        public bool Begin(int id, string source, int targetW, int targetH, ImagePriority priority = ImagePriority.Visible)
        {
            if (priority != ImagePriority.Visible) return false;
            _pending.Enqueue((id, targetW <= 0 ? 1 : targetW, targetH <= 0 ? 1 : targetH));
            return true;
        }

        public void Pump(ImageCompleteHandler onComplete, ImageReadyHandler onPixels)
        {
            while (_pending.Count > 0)
            {
                var (id, w, h) = _pending.Dequeue();
                int bytes = w * h * 4;
                if (_scratch.Length < bytes) _scratch = new byte[bytes];
                _scratch.AsSpan(0, bytes).Fill(0xFF);
                onPixels(id, _scratch.AsSpan(0, bytes), w, h);
                onComplete(id, true, w, h, ImageFailureKind.None, 1);
            }
        }
    }

    static (bool ok, ImageFailureKind fail, int att) DrainOne(DecodeScheduler sched, int id)
    {
        sched.Begin(id, "x", 8, 8);
        (bool ok, ImageFailureKind fail, int att) res = (false, ImageFailureKind.None, 0);
        bool got = false;
        var sw = System.Diagnostics.Stopwatch.StartNew();
        while (!got && sw.ElapsedMilliseconds < 5000)
        {
            sched.Pump((cid, ok, w, h, f, a) => { res = (ok, f, a); got = true; }, (cid, px, w, h) => { });
            System.Threading.Thread.Sleep(3);
        }
        return res;
    }

    // The A+B asks (off-thread + parallel + non-blocking) and the robustness taxonomy, on the real scheduler.
    static void DecodeSchedulerChecks()
    {
        int cur = 0, maxc = 0; object g = new();
        var codec = new TestCodec(() =>
        {
            int c = System.Threading.Interlocked.Increment(ref cur);
            lock (g) { if (c > maxc) maxc = c; }
            System.Threading.Thread.Sleep(60);                       // hold the worker so decodes overlap
            System.Threading.Interlocked.Decrement(ref cur);
        });
        int done = 0;
        using (var sched = new DecodeScheduler(codec, new TestFetcher(), new DecodeOptions { MaxConcurrency = 4 }))
        {
            const int M = 8;
            for (int i = 1; i <= M; i++) sched.Begin(i, "t" + i, 8, 8);   // non-blocking enqueues
            var sw = System.Diagnostics.Stopwatch.StartNew();
            while (done < M && sw.ElapsedMilliseconds < 5000)
            {
                sched.Pump((id, ok, w, h, f, a) => { if (ok) done++; }, (id, px, w, h) => { });
                System.Threading.Thread.Sleep(3);                    // UI stays responsive while workers decode
            }
            Check("46c. DecodeScheduler: off-thread, parallel (N-way), non-blocking decode",
                done == 8 && maxc >= 2, $"done={done}/8 maxConcurrent={maxc} workers={sched.WorkerCount}");
        }

        (bool ok, ImageFailureKind fail, int att) r1;
        using (var sched = new DecodeScheduler(new TestCodec(), new TestFetcher(_ => FetchResult.Fail(ImageFailureKind.NotFound)),
                   new DecodeOptions { MaxAttempts = 3, BackoffBase = TimeSpan.FromMilliseconds(1) }))
            r1 = DrainOne(sched, 1);

        int calls = 0;
        var flaky = new TestFetcher(_ =>
        {
            int c = System.Threading.Interlocked.Increment(ref calls);
            return c < 3 ? FetchResult.Fail(ImageFailureKind.ServerError) : FetchResult.Pooled(ArrayPool<byte>.Shared.Rent(16), 16);
        });
        (bool ok, ImageFailureKind fail, int att) r2;
        using (var sched = new DecodeScheduler(new TestCodec(), flaky, new DecodeOptions { MaxAttempts = 3, BackoffBase = TimeSpan.FromMilliseconds(1) }))
            r2 = DrainOne(sched, 1);

        bool permanent = !r1.ok && r1.fail == ImageFailureKind.NotFound && r1.att == 1;   // 404 → fail fast, no retry
        bool transient = r2.ok && r2.att == 3;                                            // 5xx ×2 then 200 → success on attempt 3
        Check("46d. DecodeScheduler: 404 fails fast (no retry); transient 5xx retried to success",
            permanent && transient, $"404=(ok={r1.ok} {r1.fail} att={r1.att}) flaky=(ok={r2.ok} att={r2.att})");
    }

    // Bounded CPU pixel pool (media-pipeline.md §3): pow2 buckets, cap-bounded retention, always-succeeding Rent, GC drop
    // past the cap, zero-alloc warm reuse, full idle Trim, and end-to-end through a real DecodeScheduler under a storm.
    static void PixelBufferPoolChecks()
    {
        // P1 — pow2 rounding + reuse identity + retained accounting. A non-pow2 minBytes rounds up to the next bucket;
        // a returned buffer is parked (RetainedBytes == its rounded length) and the next Rent pops that SAME array.
        {
            var pool = new FluentGpu.Media.PixelBufferPool();
            byte[] a = pool.Rent(20000);                     // 20000 → 32768 (2^15)
            bool rounded = a.Length == 32768;
            pool.Return(a);
            bool parked = pool.RetainedBytes == 32768;
            byte[] b = pool.Rent(20000);
            bool reused = ReferenceEquals(a, b) && pool.RetainedBytes == 0;
            Check("46p1. PixelBufferPool: pow2 rounding + reuse identity + retained accounting",
                rounded && parked && reused, $"len={a.Length} parked={parked} reused={ReferenceEquals(a, b)} retained={pool.RetainedBytes}");
        }

        // P2 — Rent ALWAYS succeeds past the cap (8×32KB live vs a 64KB cap); after returning all, RetainedBytes and
        // PeakRetainedBytes never exceed the cap (the surplus is dropped for the GC, not parked).
        {
            var pool = new FluentGpu.Media.PixelBufferPool(64 * 1024);
            var live = new byte[8][];
            bool allRented = true;
            for (int i = 0; i < 8; i++) { live[i] = pool.Rent(32 * 1024); if (live[i].Length != 32 * 1024) allRented = false; }
            for (int i = 0; i < 8; i++) pool.Return(live[i]);
            bool bounded = pool.RetainedBytes == 64 * 1024 && pool.PeakRetainedBytes == 64 * 1024
                           && pool.RetainedBytes <= pool.RetainedCapBytes && pool.PeakRetainedBytes <= pool.RetainedCapBytes;
            Check("46p2. PixelBufferPool: Rent never fails past the cap; retained/peak bounded by the cap after returns",
                allRented && bounded, $"rented={allRented} retained={pool.RetainedBytes} peak={pool.PeakRetainedBytes} cap={pool.RetainedCapBytes}");
        }

        // P3 — an oversize request (MaxBucketBytes+1) is served exact-size and is NEVER retained on Return.
        {
            var pool = new FluentGpu.Media.PixelBufferPool();
            byte[] big = pool.Rent(FluentGpu.Media.PixelBufferPool.MaxBucketBytes + 1);
            bool exact = big.Length == FluentGpu.Media.PixelBufferPool.MaxBucketBytes + 1;
            pool.Return(big);
            bool unretained = pool.RetainedBytes == 0;
            Check("46p3. PixelBufferPool: oversize is exact-size + unpooled (Return drops it)",
                exact && unretained, $"len={big.Length} retained={pool.RetainedBytes}");
        }

        // P4 — warm rent/return ×1000 allocates 0 managed bytes (bucket hit pops the parked array, Return pushes it back;
        // no fresh allocation once the bucket and its Stack backing are warm).
        {
            var pool = new FluentGpu.Media.PixelBufferPool();
            byte[] warm = pool.Rent(16 * 1024); pool.Return(warm);   // seed the bucket + grow the Stack backing once
            warm = pool.Rent(16 * 1024); pool.Return(warm);
            long before = GC.GetAllocatedBytesForCurrentThread();
            for (int i = 0; i < 1000; i++) { byte[] x = pool.Rent(16 * 1024); pool.Return(x); }
            long delta = GC.GetAllocatedBytesForCurrentThread() - before;
            Check("46p4. PixelBufferPool: warm rent/return ×1000 is zero-alloc", delta == 0, $"delta={delta}B");
        }

        // P5 — Trim releases every parked array to the GC → RetainedBytes == 0.
        {
            var pool = new FluentGpu.Media.PixelBufferPool();
            pool.Return(pool.Rent(16 * 1024));
            pool.Return(pool.Rent(64 * 1024));
            pool.Trim();
            Check("46p5. PixelBufferPool: Trim() drops all parked arrays", pool.RetainedBytes == 0, $"retained={pool.RetainedBytes}");
        }

        // P6 — decode storm through a REAL DecodeScheduler on the shared pool: 48 varied-size decodes, 512KB cap; every
        // decode lands and the max observed retained stays ≤ cap (the FGGUARD double-return tripwire is live in Debug).
        {
            var storm = new FluentGpu.Media.PixelBufferPool(512 * 1024);
            long maxRetained = 0;
            int done = 0;
            var sizes = new (int w, int h)[] { (64, 64), (128, 64), (128, 128), (256, 128), (100, 100), (200, 150) };
            using (var sched = new DecodeScheduler(new TestCodec(), new TestFetcher(),
                       new DecodeOptions { MaxConcurrency = 4, PixelPool = storm }))
            {
                const int N = 48;
                for (int i = 1; i <= N; i++) { var (w, h) = sizes[i % sizes.Length]; sched.Begin(i, "s" + i, w, h); }
                var sw = System.Diagnostics.Stopwatch.StartNew();
                while (done < N && sw.ElapsedMilliseconds < 8000)
                {
                    sched.Pump((id, ok, w, h, f, a) => { if (ok) done++; }, (id, px, w, h) => { });
                    long r = storm.RetainedBytes; if (r > maxRetained) maxRetained = r;
                    System.Threading.Thread.Sleep(2);
                }
            }
            Check("46p6. PixelBufferPool: 48-decode storm lands fully; retained never exceeds the cap",
                done == 48 && maxRetained <= storm.RetainedCapBytes && storm.PeakRetainedBytes <= storm.RetainedCapBytes,
                $"done={done}/48 maxRetained={maxRetained} peak={storm.PeakRetainedBytes} cap={storm.RetainedCapBytes}");
        }
    }

    static void BlurHashChecks(StringTable strings)
    {
        // (a) the decoder produces a valid, non-uniform preview from the canonical hash.
        Span<byte> px = stackalloc byte[8 * 8 * 4];
        bool decoded = BlurHash.Decode("LEHV6nWB2yk8pyo0adR*.7kCMdnj", 8, 8, px);
        bool varies = decoded && (px[0] != px[63 * 4] || px[1] != px[63 * 4 + 1] || px[2] != px[63 * 4 + 2]);

        // (b) pipeline: the 32×32 LQIP is uploaded at request (before the 64×64 full-res decode in the same frame).
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("blur", new Size2(320, 320), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new BlurHashProbe());
        host.RunFrame();
        bool lqipFirst = device.Uploads.Count >= 2
            && device.Uploads[0].w == 32 && device.Uploads[0].h == 32   // blurhash preview, uploaded first
            && device.Uploads[1].w == 64 && device.Uploads[1].h == 64;  // full-res, replaces it

        Check("46e. BlurHash: decoder valid + LQIP uploaded instantly, replaced by full-res", varies && lqipFirst,
            $"decoded={decoded} varies={varies} uploads={device.Uploads.Count}");
    }

    static void ImageTransitionChecks()
    {
        var cache = new ImageCache(new FakeImageDecoder());
        var h = cache.Request("x", 16, 16);   // default reveal (220ms FluentDecelerate)
        cache.Pump();                          // decode completes → texture appears at t=0
        float cf0 = cache.CrossFadeOf(h);      // just appeared → ~0
        for (int i = 0; i < 20; i++) cache.Tick(16f);   // 320ms elapsed > 220ms
        float cf1 = cache.CrossFadeOf(h);      // settled → 1
        bool fades = cf0 < 0.2f && cf1 >= 0.999f;

        var hn = cache.Request("y", 16, 16, ImagePriority.Visible, null, ImageTransition.None);   // disabled
        cache.Pump();
        bool disabled = cache.CrossFadeOf(hn) >= 0.999f;   // instant, no fade

        Check("46f. ImageTransition: default fade eases 0→1; None disables (instant)", fades && disabled,
            $"cf0={cf0:0.00} cf1={cf1:0.00}");
    }

    static void ImageEvictChecks()
    {
        // Unpinned images over budget → LRU eviction, each freeing its GPU texture via the evict sink.
        var evicted = new List<int>();
        var cache = new ImageCache(new FakeImageDecoder(), budgetBytes: 50_000);
        cache.SetEvictSink(evicted.Add);
        for (int i = 0; i < 5; i++) cache.Request("img" + i, 64, 64);   // 5 × 16KB = 80KB > 50KB
        cache.Pump();                                                    // decode → ready → evict unpinned LRU
        bool freed = evicted.Count >= 1;

        // Pinned (on-screen) images are NEVER evicted, regardless of budget.
        var evicted2 = new List<int>();
        var pinned = new ImageCache(new FakeImageDecoder(), budgetBytes: 50_000);
        pinned.SetEvictSink(evicted2.Add);
        for (int i = 0; i < 5; i++) pinned.Pin(pinned.Request("p" + i, 64, 64));
        pinned.Pump();
        bool pinnedSafe = evicted2.Count == 0;

        Check("46g. Residency: evicts unpinned LRU + frees its GPU texture; never evicts pinned", freed && pinnedSafe,
            $"evicted={evicted.Count} pinnedEvicted={evicted2.Count}");
    }

    // Decoder that fails the first completion with Timeout, then succeeds — exercises transient-failure retry.
    sealed class TimeoutThenOkDecoder : IImageDecoder
    {
        readonly Dictionary<int, int> _attempts = new();
        readonly Queue<(int id, int w, int h)> _pending = new();
        byte[] _scratch = Array.Empty<byte>();

        public bool Begin(int id, string source, int targetW, int targetH, ImagePriority priority = ImagePriority.Visible)
        {
            _pending.Enqueue((id, targetW <= 0 ? 1 : targetW, targetH <= 0 ? 1 : targetH));
            return true;
        }

        public void Pump(ImageCompleteHandler onComplete, ImageReadyHandler onPixels)
        {
            while (_pending.Count > 0)
            {
                var (id, w, h) = _pending.Dequeue();
                int n = _attempts.TryGetValue(id, out var a) ? a + 1 : 1;
                _attempts[id] = n;
                if (n == 1) { onComplete(id, false, 0, 0, ImageFailureKind.Timeout, 1); continue; }
                int bytes = w * h * 4;
                if (_scratch.Length < bytes) _scratch = new byte[bytes];
                _scratch.AsSpan(0, bytes).Fill(0xFF);
                onPixels(id, _scratch.AsSpan(0, bytes), w, h);
                onComplete(id, true, w, h, ImageFailureKind.None, n);
            }
        }
    }

    // Decoder that reports Canceled when Cancel(id) was called before Pump drains the job.
    sealed class CancelAwareDecoder : IImageDecoder
    {
        readonly Queue<(int id, int w, int h)> _pending = new();
        readonly HashSet<int> _canceled = new();
        byte[] _scratch = Array.Empty<byte>();

        public bool Begin(int id, string source, int targetW, int targetH, ImagePriority priority = ImagePriority.Visible)
        {
            _canceled.Remove(id);
            _pending.Enqueue((id, targetW <= 0 ? 1 : targetW, targetH <= 0 ? 1 : targetH));
            return true;
        }

        public void Cancel(int id) => _canceled.Add(id);

        public void Pump(ImageCompleteHandler onComplete, ImageReadyHandler onPixels)
        {
            while (_pending.Count > 0)
            {
                var (id, w, h) = _pending.Dequeue();
                if (_canceled.Remove(id)) { onComplete(id, false, 0, 0, ImageFailureKind.Canceled, 1); continue; }
                int bytes = w * h * 4;
                if (_scratch.Length < bytes) _scratch = new byte[bytes];
                _scratch.AsSpan(0, bytes).Fill(0xFF);
                onPixels(id, _scratch.AsSpan(0, bytes), w, h);
                onComplete(id, true, w, h, ImageFailureKind.None, 1);
            }
        }
    }

    // Decoder that withholds completion until Arm() — lets us observe Pending→Ready across two frames.
    sealed class GatedDecoder : IImageDecoder
    {
        readonly Queue<(int id, int w, int h)> _pending = new();
        byte[] _scratch = Array.Empty<byte>();
        bool _armed;

        public void Arm() => _armed = true;

        public bool Begin(int id, string source, int targetW, int targetH, ImagePriority priority = ImagePriority.Visible)
        {
            _pending.Enqueue((id, targetW <= 0 ? 1 : targetW, targetH <= 0 ? 1 : targetH));
            return true;
        }

        public void Pump(ImageCompleteHandler onComplete, ImageReadyHandler onPixels)
        {
            if (!_armed) return;
            while (_pending.Count > 0)
            {
                var (id, w, h) = _pending.Dequeue();
                int bytes = w * h * 4;
                if (_scratch.Length < bytes) _scratch = new byte[bytes];
                _scratch.AsSpan(0, bytes).Fill(0xFF);
                onPixels(id, _scratch.AsSpan(0, bytes), w, h);
                onComplete(id, true, w, h, ImageFailureKind.None, 1);
            }
        }
    }

    sealed class GatedCancelAwareDecoder : IImageDecoder
    {
        readonly Queue<(int id, int w, int h)> _pending = new();
        readonly HashSet<int> _canceled = new();
        readonly Dictionary<int, int> _cancelCounts = new();
        byte[] _scratch = Array.Empty<byte>();
        bool _armed;

        public void Arm() => _armed = true;
        public int CancelCount(int id) => _cancelCounts.TryGetValue(id, out int n) ? n : 0;

        public bool Begin(int id, string source, int targetW, int targetH, ImagePriority priority = ImagePriority.Visible)
        {
            _canceled.Remove(id);
            _pending.Enqueue((id, targetW <= 0 ? 1 : targetW, targetH <= 0 ? 1 : targetH));
            return true;
        }

        public void Cancel(int id)
        {
            _canceled.Add(id);
            _cancelCounts[id] = CancelCount(id) + 1;
        }

        public void Pump(ImageCompleteHandler onComplete, ImageReadyHandler onPixels)
        {
            if (!_armed) return;
            while (_pending.Count > 0)
            {
                var (id, w, h) = _pending.Dequeue();
                if (_canceled.Remove(id)) { onComplete(id, false, 0, 0, ImageFailureKind.Canceled, 1); continue; }
                int bytes = w * h * 4;
                if (_scratch.Length < bytes) _scratch = new byte[bytes];
                _scratch.AsSpan(0, bytes).Fill(0xFF);
                onPixels(id, _scratch.AsSpan(0, bytes), w, h);
                onComplete(id, true, w, h, ImageFailureKind.None, 1);
            }
        }
    }

    static void ImageLifecycleChecks(StringTable strings)
    {
        var retryDec = new TimeoutThenOkDecoder();
        var retryCache = new ImageCache(retryDec);
        var rh = retryCache.Request("retry-me", 64, 64, ImagePriority.Prefetch);
        retryCache.Pump();
        bool timedOut = retryCache.StateOf(rh) == ImageState.Failed
            && retryCache.FailureOf(rh) == ImageFailureKind.Timeout;
        retryCache.Tick(3000);
        retryCache.Pin(rh);
        bool restarted = retryCache.StateOf(rh) == ImageState.Pending;
        retryCache.Pump();
        bool retryReady = retryCache.StateOf(rh) == ImageState.Ready;
        Check("46i. image.retry.visible: transient Timeout retries after backoff when pinned",
            timedOut && restarted && retryReady,
            $"state={retryCache.StateOf(rh)} fail={retryCache.FailureOf(rh)}");

        var cancelDec = new CancelAwareDecoder();
        var cancelCache = new ImageCache(cancelDec);
        var ch = cancelCache.Request("cancel-me", 64, 64);
        cancelCache.Cancel(ch);
        cancelCache.Pump();
        bool canceled = cancelCache.StateOf(ch) == ImageState.Failed
            && cancelCache.FailureOf(ch) == ImageFailureKind.Canceled;
        cancelCache.Tick(3000);
        var ch2 = cancelCache.Request("cancel-me", 64, 64, ImagePriority.Visible);
        bool sameHandle = ch2 == ch && cancelCache.StateOf(ch2) == ImageState.Pending;
        cancelCache.Pump();
        bool cancelReady = cancelCache.StateOf(ch2) == ImageState.Ready;
        Check("46j. image.cancel.recycle: canceled decode restarts and completes",
            canceled && sameHandle && cancelReady,
            $"state={cancelCache.StateOf(ch2)} fail={cancelCache.FailureOf(ch2)}");

        var gated = new GatedDecoder();
        var gatedCache = new ImageCache(gated);
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("imgdirty", new Size2(200, 200), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new ImageProbe(), gatedCache);
        host.RunFrame();
        bool pendingDraw = device.LastImages.Count == 1 && device.LastImages[0].Ready == 0;
        gated.Arm();
        host.RunFrame();
        bool readyDraw = device.LastImages.Count == 1 && device.LastImages[0].Ready == 1
            && gatedCache.StateOf(new ImageHandle(device.LastImages[0].ImageId)) == ImageState.Ready;
        Check("46k. image.status.marks-dirty: Pending→Ready repaints with ready=true",
            pendingDraw && readyDraw,
            $"frame1Ready={!pendingDraw} frame2Ready={device.LastImages.Count > 0 && device.LastImages[0].Ready == 1}");

        var entered = new System.Threading.ManualResetEventSlim(false);
        var release = new System.Threading.ManualResetEventSlim(false);
        int decodeCalls = 0;
        var blockingCodec = new TestCodec(() =>
        {
            if (System.Threading.Interlocked.Increment(ref decodeCalls) == 1)
            {
                entered.Set();
                release.Wait();
            }
        });
        bool queuedRestarted, queuedReady;
        using (var sched = new DecodeScheduler(blockingCodec, new TestFetcher(), new DecodeOptions { MaxConcurrency = 1 }))
        {
            var queuedCache = new ImageCache(sched);
            queuedCache.Request("blocker", 8, 8);
            var sw = System.Diagnostics.Stopwatch.StartNew();
            while (!entered.IsSet && sw.ElapsedMilliseconds < 5000) System.Threading.Thread.Sleep(2);

            var victim = queuedCache.Request("queued-victim", 8, 8);
            queuedCache.Cancel(victim);
            var visibleVictim = queuedCache.Request("queued-victim", 8, 8, ImagePriority.Visible);
            queuedCache.Pin(visibleVictim);
            queuedCache.Pump();
            queuedRestarted = visibleVictim == victim
                && queuedCache.StateOf(victim) == ImageState.Pending
                && queuedCache.RefsOf(victim) == 1;

            release.Set();
            sw.Restart();
            while (queuedCache.StateOf(victim) != ImageState.Ready && sw.ElapsedMilliseconds < 5000)
            {
                queuedCache.Pump();
                System.Threading.Thread.Sleep(2);
            }
            queuedReady = queuedCache.StateOf(victim) == ImageState.Ready;
        }
        entered.Dispose(); release.Dispose();
        Check("46l. image.cancel.queued: queued scheduler cancel does not leave a visible handle forever-pending",
            queuedRestarted && queuedReady,
            $"restarted={queuedRestarted} ready={queuedReady}");

        var sharedDec = new GatedCancelAwareDecoder();
        var sharedCache = new ImageCache(sharedDec);
        using var sharedApp = new HeadlessPlatformApp();
        var sharedWindow = new HeadlessWindow(new WindowDesc("shared-img", new Size2(200, 120), 1f));
        sharedWindow.Show();
        var sharedDevice = new HeadlessGpuDevice();
        var sharedFonts = new HeadlessFontSystem(strings);
        var sharedProbe = new SharedImageSwapProbe();
        using var sharedHost = new AppHost(sharedApp, sharedWindow, sharedDevice, sharedFonts, strings, sharedProbe, sharedCache);
        sharedHost.RunFrame();
        int sharedId = sharedDevice.LastImages.Count >= 2 ? sharedDevice.LastImages[0].ImageId : 0;
        var sharedHandle = new ImageHandle(sharedId);
        bool sharedInitial = sharedId != 0
            && sharedDevice.LastImages.Count >= 2
            && sharedDevice.LastImages[1].ImageId == sharedId
            && sharedCache.RefsOf(sharedHandle) == 2
            && sharedCache.StateOf(sharedHandle) == ImageState.Pending;
        sharedProbe.SecondSource.Value = "album/other";
        sharedHost.RunFrame();
        bool sharedNotCanceled = sharedInitial
            && sharedDec.CancelCount(sharedId) == 0
            && sharedCache.RefsOf(sharedHandle) == 1
            && sharedCache.StateOf(sharedHandle) == ImageState.Pending;
        sharedDec.Arm();
        for (int i = 0; i < 4 && sharedCache.StateOf(sharedHandle) != ImageState.Ready; i++) sharedHost.RunFrame();
        bool sharedReady = sharedCache.StateOf(sharedHandle) == ImageState.Ready;
        Check("46m. image.shared-handle: rebinding one ImageEl does not cancel another visible owner",
            sharedNotCanceled && sharedReady,
            $"initial={sharedInitial} cancels={sharedDec.CancelCount(sharedId)} refs={sharedCache.RefsOf(sharedHandle)} state={sharedCache.StateOf(sharedHandle)}");
    }

    static void UseImageChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("useimg", new Size2(200, 200), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new UseImageProbe());
        host.RunFrame();   // render → UseImage requests; pump completes the fake decode; status-change marks dirty
        host.RunFrame();   // re-render: UseImage now reports Ready → the component swaps the spinner for the image
        Check("46h. UseImage: hook surfaces load state to the component (spinner → ready)",
            UseImageProbe.LastState == ImageState.Ready, $"state={UseImageProbe.LastState}");
    }

    // Controls: a slider press-sets and drag-scrubs its value; a toggle flips; an icon button clicks; a scrollbar drags.
    // ── gate.ctl.recipe.* — WS3 P1 InteractionRecipe (the app-authoring interactive-styling surface) ────────────
    // The HYBRID: the brush half rides the BoxEl Fill/Hover/Pressed field ramp + BrushTransitionMs; the motion half
    // rides the declarative WhileHover/WhilePressed + Transition token. `.Interactive` is a pure with-expansion.
    static void RecipeChecks(StringTable strings)
    {
        // A deterministic (theme-independent) recipe with BOTH halves + a stroke ramp.
        var fillRamp = new StateBrush(ColorF.FromRgba(10, 10, 10), ColorF.FromRgba(20, 20, 20), ColorF.FromRgba(30, 30, 30), ColorF.FromRgba(5, 5, 5));
        var strokeRamp = new StateBrush(ColorF.FromRgba(40, 40, 40), ColorF.FromRgba(50, 50, 50), ColorF.FromRgba(60, 60, 60), ColorF.FromRgba(35, 35, 35));
        var recipe = new InteractionRecipe
        {
            Fill = fillRamp, Stroke = strokeRamp, StrokeWidth = 2f,
            HoverScale = 1.04f, PressScale = 0.96f, HoverOpacity = 0.9f,
            BrushMs = 120f, Motion = MotionTokenId.StandardSpring,
        };
        // Pre-set channels the recipe does NOT name (must survive) + a caller While* leg (must be preserved).
        var pre = new BoxEl
        {
            Width = 33f, Padding = Edges4.All(7), Corners = CornerRadius4.All(5f),
            WhileFocus = new MotionTarget { Scale = 1.5f }, OnClick = static () => { },
        };

        // gate.ctl.recipe.expand — the exact field writes + untouched channels.
        var box = pre.Interactive(recipe);
        bool brush = box.Fill.Value == fillRamp.Rest && box.HoverFill.Value == fillRamp.Hover && box.PressedFill.Value == fillRamp.Pressed
                     && box.BrushTransitionMs == 120f && box.IsEnabled;
        bool border = box.BorderColor.Value == strokeRamp.Rest && box.HoverBorderColor == strokeRamp.Hover
                      && box.PressedBorderColor == strokeRamp.Pressed && box.BorderWidth == 2f;
        bool motion = box.WhileHover is { } wh && wh.Scale == 1.04f && wh.Opacity == 0.9f
                      && box.WhilePressed is { } wp && wp.Scale == 0.96f && wp.Opacity == 1f
                      && box.Transition is not null;
        bool untouched = box.Width.Value == 33f && box.WhileFocus is { } wf && wf.Scale == 1.5f && box.OnClick is not null;
        Check("gate.ctl.recipe.expand .Interactive writes fill/border/brush-ms + While* targets; unnamed channels untouched",
            brush && border && motion && untouched, $"brush={brush} border={border} motion={motion} untouched={untouched}");

        // A recipe with NO motion half must not touch While*/Transition (don't stomp channels the recipe doesn't use).
        var noMotion = new InteractionRecipe { Fill = fillRamp };   // HoverScale/PressScale default 1, opacities NaN
        var b2 = pre.Interactive(noMotion);
        Check("gate.ctl.recipe.expand no-motion recipe leaves While*/Transition untouched (caller WhileFocus survives, no WhileHover)",
            b2.WhileHover is null && b2.WhilePressed is null && b2.Transition is null && b2.WhileFocus is { } f2 && f2.Scale == 1.5f,
            $"hover={b2.WhileHover is null} press={b2.WhilePressed is null} transition={b2.Transition is null}");

        // One-transform-owner: a bound Transform suppresses the recipe's While* (the bound matrix is the sole owner).
        var bound = new BoxEl { Transform = Prop.Of(() => Affine2D.Identity), OnClick = static () => { } }.Interactive(recipe);
        Check("gate.ctl.recipe.expand bound Transform suppresses the While* motion half (one transform owner)",
            bound.WhileHover is null && bound.WhilePressed is null && bound.Fill.Value == fillRamp.Rest,
            $"hover={bound.WhileHover is null} press={bound.WhilePressed is null} brushStillApplied={bound.Fill.Value == fillRamp.Rest}");

        // gate.ctl.recipe.presets — the four presets resolve the expected Tok values, and a theme swap re-resolves them.
        var kind0 = Tok.Theme;
        bool subtleNow = Interaction.Subtle.Fill.Hover == Tok.FillSubtleSecondary && Interaction.Subtle.Fill.Rest == Tok.FillSubtleTransparent;
        bool listRowNow = Interaction.ListRow.Fill.Hover == Tok.FillSubtleSecondary;
        bool cardNow = Interaction.Card.Fill.Rest == Tok.FillCardDefault && Interaction.Card.Stroke is { } cs && cs.Rest == Tok.StrokeCardDefault
                       && Interaction.Card.PressScale == 0.985f && Interaction.Card.Motion == MotionTokenId.StandardSpring;
        bool ghostNow = Interaction.AccentGhost.Fill.Hover == Tok.AccentSubtle && Interaction.AccentGhost.Fill.Rest == ColorF.Transparent;
        var subtleHover0 = Interaction.Subtle.Fill.Hover;
        var cardRest0 = Interaction.Card.Fill.Rest;
        // Flip the theme kind: FillSubtleSecondary / FillCardDefault differ light↔dark, so a live re-resolve must change.
        Tok.Use(kind0 == ThemeKind.Dark ? ThemeKind.Light : ThemeKind.Dark);
        bool reResolved = Interaction.Subtle.Fill.Hover == Tok.FillSubtleSecondary && Interaction.Subtle.Fill.Hover != subtleHover0
                          && Interaction.Card.Fill.Rest == Tok.FillCardDefault && Interaction.Card.Fill.Rest != cardRest0;
        Tok.Use(kind0);   // restore the original theme kind
        Check("gate.ctl.recipe.presets Subtle/ListRow/Card/AccentGhost resolve Tok values; a theme swap re-resolves (theme-live)",
            subtleNow && listRowNow && cardNow && ghostNow && reResolved,
            $"subtle={subtleNow} listRow={listRowNow} card={cardNow} ghost={ghostNow} reResolved={reResolved}");

        // gate.ctl.recipe.disabled — isEnabled=false applies the Disabled legs, sets IsEnabled=false (the engine's
        // hover/press gate), and suppresses the motion half (no hover/press response).
        var dis = pre.Interactive(recipe, isEnabled: false);
        bool disElem = !dis.IsEnabled && dis.Fill.Value == fillRamp.Disabled && dis.BorderColor.Value == strokeRamp.Disabled
                       && dis.WhileHover is null && dis.WhilePressed is null;
        // Reconcile it and confirm the scene Disabled flag is set (what actually blocks hover/press dispatch).
        using (var app = new HeadlessPlatformApp())
        {
            var window = new HeadlessWindow(new WindowDesc("recipe-dis", new Size2(200, 200), 1f)); window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            NodeHandle n = default;
            var root = new W0fStaticProbe { Build = () => (pre with { OnRealized = h => n = h }).Interactive(recipe, isEnabled: false) };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            bool flagged = !n.IsNull && (host.Scene.Flags(n) & NodeFlags.Disabled) != 0;
            Check("gate.ctl.recipe.disabled disabled legs + IsEnabled=false (scene Disabled flag) + no While* motion",
                disElem && flagged, $"elem={disElem} disabledFlag={flagged}");
        }

        // gate.ctl.recipe.zero-alloc — a scene of N recipe-styled boxes, once mounted, adds NO per-frame paint cost: the
        // recipe bakes into scene columns at reconcile (the cold path), so steady frames are 0-alloc in the hot window
        // (the HotPhaseAllocBytes window spans flush + record + submit + present). Proven the same way as slice gate 9.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("recipe-alloc", new Size2(400, 400), 1f)); window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            const int N = 24;
            InteractionRecipe[] presets = [Interaction.Subtle, Interaction.ListRow, Interaction.Card, Interaction.AccentGhost];
            var root = new W0fStaticProbe
            {
                Build = () =>
                {
                    var kids = new Element[N];
                    for (int i = 0; i < N; i++)
                        kids[i] = new BoxEl { Width = 40f, Height = 20f, Corners = Radii.ControlAll, OnClick = static () => { } }
                            .Interactive(presets[i % presets.Length]);
                    return new BoxEl { Direction = 1, Gap = 2f, Children = kids };
                },
            };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            for (int i = 0; i < 8; i++) host.RunFrame();   // warm (mount + JIT) → memoized steady state
            var steady = host.RunFrame();
            Check("gate.ctl.recipe.zero-alloc 24 recipe-styled boxes, steady frame: memoized + hot window 0 bytes",
                !steady.Rendered && steady.HotPhaseAllocBytes == 0, $"rendered={steady.Rendered} hot={steady.HotPhaseAllocBytes}B");
        }
    }

    // ── gate.ctl.bind.* — WS3 P2 the controlled-input contract: the value is a concrete Signal the control writes on
    //    user interaction FIRST, then fires onChange; a programmatic signal write re-skins with NO onChange echo and
    //    without re-rendering the owner (the controlled-everything decoupling); auto-materialize is one code path.
    static void ControlBindChecks(StringTable strings)
    {
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);

        // gate.ctl.bind.toggle — user toggle writes the value signal then fires onChange ONCE; a programmatic write
        // re-skins with NO echo and never re-invokes the owner's render (adjustment #8's decoupling regression pin).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("bind-toggle", new Size2(320, 160), 1f)); window.Show();
            var sig = new Signal<bool>(false);
            int probeRenders = 0, changes = 0; bool lastV = false;
            using var host = new AppHost(app, window, device, fonts, strings,
                new W0fStaticProbe { Build = () => { probeRenders++; return new BoxEl { Padding = Edges4.All(12),
                    Children = [ToggleSwitch.Create(sig, onChange: v => { changes++; lastV = v; })] }; } });
            host.RunFrame();
            int rendersAtMount = probeRenders;
            var ts = FindRole(host.Scene, host.Scene.Root, AutomationRole.ToggleSwitch);
            ClickNode(host, window, ts);
            bool wrote = sig.Value && changes == 1 && lastV;
            int changesBefore = changes;
            sig.Value = false;                      // programmatic write
            host.RunFrame();
            bool noEcho = changes == changesBefore;
            bool decoupled = probeRenders == rendersAtMount;   // the Signal write never re-rendered the owner
            Check("gate.ctl.bind.toggle ToggleSwitch: user toggle writes the signal then fires onChange once; programmatic write re-skins with no echo (owner not re-rendered)",
                wrote && noEcho && decoupled, $"wrote={wrote} changes={changes} noEcho={noEcho} ownerRenders={probeRenders}(mount {rendersAtMount})");
        }

        // gate.ctl.bind.automaterialize — a signal-less ToggleSwitch toggles via its OWN internal signal; an external
        // signal controls another; BOTH ride the one `IsOn ?? own` code path.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("bind-auto", new Size2(320, 220), 1f)); window.Show();
            var extSig = new Signal<bool>(false);
            int autoN = 0, extN = 0;
            using var host = new AppHost(app, window, device, fonts, strings,
                new W0fStaticProbe { Build = () => new BoxEl { Direction = 1, Gap = 8, Padding = Edges4.All(12),
                    Children = [
                        ToggleSwitch.Create(onChange: _ => autoN++),            // signal-less → internal signal
                        ToggleSwitch.Create(extSig, onChange: _ => extN++),     // caller-owned signal
                    ] } });
            host.RunFrame();
            var toggles = Roles(host.Scene, AutomationRole.ToggleSwitch);
            ClickNode(host, window, toggles[0]);
            bool autoToggled = autoN == 1;         // the internal signal drove a toggle
            toggles = Roles(host.Scene, AutomationRole.ToggleSwitch);
            ClickNode(host, window, toggles[1]);
            bool extToggled = extSig.Value && extN == 1;
            Check("gate.ctl.bind.automaterialize signal-less ToggleSwitch toggles via its own internal signal; a caller signal controls another; one code path",
                autoToggled && extToggled, $"auto={autoN} ext={extSig.Value}/{extN}");
        }

        // gate.ctl.bind.check + gate.ctl.bind.tristate — CheckBox 2-state click writes the bool signal; the CheckState
        // overload cycles Unchecked → Checked → Indeterminate → Unchecked through the signal.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("bind-check", new Size2(360, 240), 1f)); window.Show();
            var b = new Signal<bool>(false);
            var tri = new Signal<CheckState>(CheckState.Unchecked);
            int bN = 0, tN = 0;
            using var host = new AppHost(app, window, device, fonts, strings,
                new W0fStaticProbe { Build = () => new BoxEl { Direction = 1, Gap = 8, Padding = Edges4.All(12),
                    Children = [
                        CheckBox.Create("two", b, onChange: _ => bN++),
                        CheckBox.Create("tri", tri, onChange: _ => tN++),
                    ] } });
            host.RunFrame();
            var boxes = Roles(host.Scene, AutomationRole.CheckBox);
            ClickNode(host, window, boxes[0]);
            bool check2 = b.Value && bN == 1;
            boxes = Roles(host.Scene, AutomationRole.CheckBox);
            ClickNode(host, window, boxes[1]); bool c1 = tri.Value == CheckState.Checked;
            boxes = Roles(host.Scene, AutomationRole.CheckBox);
            ClickNode(host, window, boxes[1]); bool c2 = tri.Value == CheckState.Indeterminate;
            boxes = Roles(host.Scene, AutomationRole.CheckBox);
            ClickNode(host, window, boxes[1]); bool c3 = tri.Value == CheckState.Unchecked;
            Check("gate.ctl.bind.check CheckBox 2-state click writes the bool signal (onChange once)",
                check2, $"val={b.Value} changes={bN}");
            Check("gate.ctl.bind.tristate CheckBox CheckState click cycles Unchecked→Checked→Indeterminate→Unchecked via the signal",
                c1 && c2 && c3 && tN == 3, $"c1={c1} c2={c2} c3={c3} changes={tN}");
        }

        // gate.ctl.bind.radio — a RadioButtons click WRITES the selected-index signal (onChange once); arrow roving
        // (Down) moves the selection and updates the SAME signal (selection follows focus).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("bind-radio", new Size2(320, 240), 1f)); window.Show();
            var sel = new Signal<int>(0);   // start at 0 so Tab lands on the roving stop (item 0)
            int rN = 0;
            using var host = new AppHost(app, window, device, fonts, strings,
                new W0fStaticProbe { Build = () => new BoxEl { Padding = Edges4.All(12),
                    Children = [RadioButtons.Create(new[] { "A", "B", "C" }, sel, onChange: _ => rN++, maxColumns: 1)] } });
            host.RunFrame();
            // arrow roving: Tab focuses the single roving stop, Down moves selection (selection follows focus) → writes the signal.
            window.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.Tab)); host.RunFrame();
            window.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.Down)); host.RunFrame();
            bool roved = sel.Value == 1 && rN == 1;
            // click selects: clicking item C writes index 2 (mutual exclusion via the one shared signal).
            ClickNode(host, window, Roles(host.Scene, AutomationRole.RadioButton)[2]);
            bool clickWrote = sel.Value == 2 && rN == 2;
            Check("gate.ctl.bind.radio RadioButtons: arrow roving updates the index signal; a click writes the selected index (onChange each)",
                roved && clickWrote, $"afterDown={(roved ? 1 : sel.Value)}@{rN} afterClick={sel.Value}");
        }

        // gate.ctl.bind.naming — the closed callback-name set is enforced: NO public control factory (Create/Group)
        // parameter is named onToggle/onSelect/onTextChanged/OnValueChanged (the eliminated Action<TOld,TNew>/idiom
        // spellings). A reflection scan over the whole FluentGpu.Controls surface (comprehensive — catches any control,
        // migrated or not). Param names are present under JIT (the gate run); under AOT trimming they degrade to a
        // vacuous pass, never a false failure.
        {
            string[] banned = { "ontoggle", "onselect", "ontextchanged", "onvaluechanged" };
            var offenders = new List<string>();
            foreach (var t in typeof(ToggleSwitch).Assembly.GetExportedTypes())
                foreach (var m in t.GetMethods(System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Static))
                {
                    if (m.Name != "Create" && m.Name != "Group") continue;
                    foreach (var pi in m.GetParameters())
                        if (Array.IndexOf(banned, (pi.Name ?? "").ToLowerInvariant()) >= 0)
                            offenders.Add($"{t.Name}.{m.Name}({pi.Name})");
                }
            Check("gate.ctl.bind.naming no public control factory parameter named onToggle/onSelect/onTextChanged/OnValueChanged remains",
                offenders.Count == 0, offenders.Count == 0 ? "clean" : string.Join(", ", offenders));
        }

        // gate.ctl.bind.textbox-options — TextBox is built via the TextBoxOptions record (the long tail) + a controlled
        // value signal; a user edit round-trips text THROUGH the signal and fires onChange; the mount-time signal seed
        // does NOT fire onChange (onChange is an edit callback, not a re-push echo).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("bind-tb", new Size2(420, 240), 1f)); window.Show();
            var text = new Signal<string>("");
            int changes = 0; string last = "";
            using var host = new AppHost(app, window, device, fonts, strings,
                new W0fStaticProbe { Build = () => new BoxEl { Padding = Edges4.All(12),
                    Children = [TextBox.Create(text, onChange: s => { changes++; last = s; },
                        new TextBox.TextBoxOptions { Placeholder = "ph", Width = 200f, Header = "H" })] } });
            host.RunFrame();
            bool mountQuiet = changes == 0;   // the mount-time seed sync does not fire onChange
            var field = FindRole(host.Scene, host.Scene.Root, AutomationRole.Text);
            ClickNode(host, window, field);
            foreach (char c in "hi") window.QueueInput(new InputEvent(InputKind.Char, default, 0, c));
            host.RunFrame();
            bool userWrote = text.Value == "hi" && changes >= 1 && last == "hi";   // user edit → signal round-trip + onChange
            Check("gate.ctl.bind.textbox-options TextBox via TextBoxOptions round-trips text through the signal; onChange fires on user edits (not the mount seed)",
                mountQuiet && userWrote, $"mountQuiet={mountQuiet} text='{text.Peek()}' changes={changes} last='{last}'");
        }
    }

    static void ControlsChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("ctl", new Size2(480, 480), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var probe = new ControlsProbe();
        using var host = new AppHost(app, window, device, fonts, strings, probe);
        host.RunFrame();

        NodeHandle Kid(int i) => Child(host.Scene, host.Scene.Root, i);
        void Press(NodeHandle n, float lx, float ly)
        {
            var r = host.Scene.AbsoluteRect(n);
            window.QueueInput(new InputEvent(InputKind.PointerDown, new Point2(r.X + lx, r.Y + ly), 0, 0));
        }

        // slider: press at x=100/200 → 0.5
        Press(Kid(0), 100f, 12f);
        host.RunFrame();
        bool press = Near(probe.SliderVal, 0.5f);
        // drag to x=160 → 0.8 (the drag target survives the in-place re-render)
        var sr = host.Scene.AbsoluteRect(Kid(0));
        window.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(sr.X + 160f, sr.Y + 12f), 0, 0));
        host.RunFrame();
        bool drag = Near(probe.SliderVal, 0.8f);
        window.QueueInput(new InputEvent(InputKind.PointerUp, new Point2(sr.X + 160f, sr.Y + 12f), 0, 0));
        host.RunFrame();
        Check("47. Slider press-sets + drag-scrubs value", press && drag, $"press={probe.SliderVal:0.0} (0.5→0.8)");

        // 47t. The SAME slider, by TOUCH: a touch press-sets and the touch drag scrubs through the shared OnDrag
        // implicit-capture (_dragTarget) — proof that the dispatcher's single-recognizer touch path honors an OnDrag node
        // exactly like the mouse, so the editor's drag-select (W0e.t4) and the slider scrub ride the one mechanism. Press
        // x=60 → 0.3, drag x=140 → 0.7 (distinct from the mouse 0.8 above, so this is the touch path doing the work).
        var st = host.Scene.AbsoluteRect(Kid(0));
        uint tms = s_touchClockMs;
        window.QueueInput(Touch(InputKind.PointerDown, new Point2(st.X + 60f, st.Y + 12f), tms, 1));
        host.RunFrame();
        bool touchPress = Near(probe.SliderVal, 0.3f);
        for (int i = 1; i <= 8; i++)
        {
            window.QueueInput(Touch(InputKind.PointerMove, new Point2(st.X + 60f + i * 10f, st.Y + 12f), tms + (uint)i * 16, 1));
            host.RunFrame();
        }
        bool touchDrag = Near(probe.SliderVal, 0.7f);
        window.QueueInput(Touch(InputKind.PointerUp, new Point2(st.X + 140f, st.Y + 12f), tms + 9 * 16, 1));
        host.RunFrame();
        s_touchClockMs = tms + 1000;
        Check("47t. Slider press-sets + drag-scrubs by TOUCH (the shared OnDrag implicit-capture the editor drag-select also rides)",
            touchPress && touchDrag, $"press={probe.SliderVal:0.0} (0.3→0.7)");

        // toggle: click flips on
        var tr = host.Scene.AbsoluteRect(Kid(1));
        window.QueueInput(new InputEvent(InputKind.PointerDown, new Point2(tr.X + tr.W / 2, tr.Y + tr.H / 2), 0, 0));
        window.QueueInput(new InputEvent(InputKind.PointerUp, new Point2(tr.X + tr.W / 2, tr.Y + tr.H / 2), 0, 0));
        host.RunFrame();
        bool toggled = probe.Toggled;

        // icon button: click increments
        var ir = host.Scene.AbsoluteRect(Kid(2));
        window.QueueInput(new InputEvent(InputKind.PointerDown, new Point2(ir.X + ir.W / 2, ir.Y + ir.H / 2), 0, 0));
        window.QueueInput(new InputEvent(InputKind.PointerUp, new Point2(ir.X + ir.W / 2, ir.Y + ir.H / 2), 0, 0));
        host.RunFrame();
        bool iconClicked = probe.IconClicks == 1;

        // scrollbar: drag the thumb to ~bottom → position near 1
        Press(Kid(3), 5f, 190f);
        host.RunFrame();
        bool scrolled = probe.ScrollPos > 0.5f;

        Check("48. Toggle flips, IconButton clicks, ScrollBar drags", toggled && iconClicked && scrolled,
            $"toggled={probe.Toggled} icon={probe.IconClicks} scrollPos={probe.ScrollPos:0.0}");
    }

    // Navigation as serializable state: push/pop/depth + round-trip serialize for deep-link / cold-launch restore.
    static void NavigationChecks()
    {
        var nav = new Navigator(new Route("home"));
        bool d1 = nav.Current.Name == "home" && !nav.CanGoBack && nav.Depth == 1;
        nav.Push("playlist", "p1");
        bool d2 = nav.Current is { Name: "playlist", Arg: "p1" } && nav.CanGoBack && nav.Depth == 2;
        string ser = nav.Serialize();
        nav.Pop();
        bool d3 = nav.Current.Name == "home" && !nav.CanGoBack;
        var restored = Navigator.Deserialize(ser);
        bool d4 = restored.Depth == 2 && restored.Current is { Name: "playlist", Arg: "p1" };
        Check("49. Navigator: push/pop/depth + serialize round-trip", d1 && d2 && d3 && d4, ser);
    }

    // PageHost renders the top route and re-renders the view tree on push/pop (the back stack drives the UI).
    static void PageHostChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("nav", new Size2(480, 320), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var nav = new Navigator(new Route("home"));
        Element View(Route r) => r.Name == "home"
            ? new BoxEl { Children = [new TextEl("HOME PAGE")] }
            : new BoxEl { Children = [new TextEl("PLAYLIST " + r.Arg)] };
        using var host = new AppHost(app, window, device, fonts, strings, new PageHost(nav, View));

        host.RunFrame();
        bool onHome = HasGlyph(device, strings, "HOME PAGE");
        nav.Push("playlist", "x1");
        host.RunFrame();
        bool onDetail = HasGlyph(device, strings, "PLAYLIST x1");
        nav.Pop();
        host.RunFrame();
        bool backHome = HasGlyph(device, strings, "HOME PAGE");
        Check("50. PageHost renders + navigates the back stack", onHome && onDetail && backHome, "home → playlist → back");
    }

    // Grid: 3 equal Star tracks across 320 (gaps 10) → 100px columns; 5 cells flow row-major into 2 rows.
    // KeepAlive is opt-in: active route pages stay mounted while inactive pages are detached, unpinned, and LRU-evicted.
    static void KeepAliveChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("keepalive", new Size2(260, 220), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var probe = new KeepAliveProbe { MaxEntries = 2 };
        var imageCache = new ImageCache(new FakeImageDecoder(), budgetBytes: 24 * 24 * 4);
        using var host = new AppHost(app, window, device, fonts, strings, probe, images: imageCache);

        host.RunFrame();
        var imgA = host.Images.Request("keepalive-a", 24, 24);
        bool initial = HasGlyph(device, strings, "a:0") && host.Images.RefsOf(imgA) == 1;

        var buttonA = FindRole(host.Scene, host.Scene.Root, AutomationRole.Button);
        ClickNode(host, window, buttonA);
        bool clicked = HasGlyph(device, strings, "a:1") && !FocusedNode(host.Scene, host.Scene.Root).IsNull;

        var scrollA = FindScrollable(host.Scene, host.Scene.Root);
        var sr = host.Scene.AbsoluteRect(scrollA);
        window.QueueInput(new InputEvent(InputKind.Wheel, new Point2(sr.X + 20f, sr.Y + 20f), 0, 0, 120f));
        host.RunFrame();
        host.Scene.TryGetScroll(scrollA, out var scA);
        float offsetA = scA.OffsetY;

        probe.Route!.Value = "b";
        host.RunFrame();
        bool detached = HasGlyph(device, strings, "b:0") && !HasGlyph(device, strings, "a:1")
                        && FocusedNode(host.Scene, host.Scene.Root).IsNull
                        && host.Images.RefsOf(imgA) == 0;

        var pressure = host.Images.Request("keepalive-pressure", 64, 64);
        host.Images.Pump();   // evicts inactive A's decoded payload while its retained scene node still holds ImageId
        bool inactiveImageEvicted = host.Images.StateOf(imgA) == ImageState.None
                                    && host.Images.StateOf(pressure) == ImageState.None;

        probe.Route.Value = "a";
        host.RunFrame();
        var scrollA2 = FindScrollable(host.Scene, host.Scene.Root);
        host.Scene.TryGetScroll(scrollA2, out var scA2);
        bool restored = HasGlyph(device, strings, "a:1") && scA2.OffsetY > offsetA - 0.5f
                        && host.Images.RefsOf(imgA) == 1 && host.Images.StateOf(imgA) == ImageState.Ready;

        probe.Route.Value = "b"; host.RunFrame();
        probe.Route.Value = "c"; host.RunFrame();   // with MaxEntries=2, inactive A is the LRU victim
        probe.Route.Value = "a"; host.RunFrame();
        bool evictedFresh = HasGlyph(device, strings, "a:0") && !HasGlyph(device, strings, "a:1");

        Check("50a. KeepAlive opt-in caches page state/scroll, detaches inactive input/draw, releases image pins, and LRU-evicts inactive pages",
            initial && clicked && offsetA > 1f && detached && inactiveImageEvicted && restored && evictedFresh,
            $"initial={initial} clicked={clicked} off={offsetA:0.#}->{scA2.OffsetY:0.#} detached={detached} imgEvicted={inactiveImageEvicted} restored={restored} evictedFresh={evictedFresh} refsA={host.Images.RefsOf(imgA)} stateA={host.Images.StateOf(imgA)}");

        using var presenceApp = new HeadlessPlatformApp();
        var presenceWindow = new HeadlessWindow(new WindowDesc("keepalive-presence", new Size2(260, 220), 1f));
        presenceWindow.Show();
        var presenceDevice = new HeadlessGpuDevice();
        var presenceFonts = new HeadlessFontSystem(strings);
        var presenceProbe = new KeepAlivePresenceProbe();
        using var presenceHost = new AppHost(presenceApp, presenceWindow, presenceDevice, presenceFonts, strings, presenceProbe);

        presenceHost.RunFrame();
        bool presenceA = HasGlyph(presenceDevice, strings, "presence-a");
        presenceProbe.Route!.Value = "b";
        presenceHost.RunFrame();
        bool parkedExitHardRemoved = HasGlyph(presenceDevice, strings, "presence-b")
                                     && !HasGlyph(presenceDevice, strings, "presence-a")
                                     && presenceHost.Scene.OrphanCount == 0;
        Check("50a2. animated presence removal inside a parked KeepAlive page is hard-removed (no cross-route orphan)",
            presenceA && parkedExitHardRemoved,
            $"initial={presenceA} switched={parkedExitHardRemoved} orphans={presenceHost.Scene.OrphanCount}");

        using var nestedApp = new HeadlessPlatformApp();
        var nestedWindow = new HeadlessWindow(new WindowDesc("nested-hit-visibility", new Size2(260, 220), 1f));
        nestedWindow.Show();
        var nestedDevice = new HeadlessGpuDevice();
        var nestedFonts = new HeadlessFontSystem(strings);
        var nestedProbe = new NestedHitVisibilityProbe();
        using var nestedHost = new AppHost(nestedApp, nestedWindow, nestedDevice, nestedFonts, strings, nestedProbe);
        nestedHost.RunFrame();
        nestedProbe.Live.Value = true;
        nestedHost.RunFrame();
        var nestedScroll = FindScrollable(nestedHost.Scene, nestedHost.Scene.Root);
        var nestedRect = nestedHost.Scene.AbsoluteRect(nestedScroll);
        var nestedPoint = new Point2(nestedRect.X + 30f, nestedRect.Y + 30f);
        var nestedRouted = nestedHost.Input.ScrollableUnderForAxis(nestedPoint, wantHorizontal: false);
        nestedWindow.QueueInput(new InputEvent(InputKind.Wheel, nestedPoint, 0, 0, 120f));
        nestedHost.RunFrame();
        nestedHost.Scene.TryGetScroll(nestedScroll, out var nestedState);
        Check("50a3. nested transparent component boundaries remain input-traversable when an inner branch becomes hit-testable",
            !nestedScroll.IsNull && nestedRouted == nestedScroll && nestedState.OffsetY > 1f,
            $"scroll=n#{nestedScroll.Raw.Index} routed=n#{nestedRouted.Raw.Index} offset={nestedState.OffsetY:0.#}");
    }

    // Component activation lifecycle: UseActivation fires once per park/minimize transition (never at mount), and a
    // parked subtree's looping animation is auto-quiesced so AnimEngine.HasActive (the Anim wake reason) drops.
    static void ActivationLifecycleChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("activation", new Size2(260, 220), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var probe = new ActivationProbe { MaxEntries = 4 };
        using var host = new AppHost(app, window, device, fonts, strings, probe);

        host.RunFrame();
        // Mount = active: neither callback fires; the page's loop animation keeps the Anim wake reason set.
        probe.On.TryGetValue("a", out int aOn0); probe.Off.TryGetValue("a", out int aOff0);
        bool mountSilent = aOn0 == 0 && aOff0 == 0;
        bool animAwake = (host.CurrentWakeReasons & WakeReasons.Anim) != 0;

        // Switch away → "a" parks → onDeactivated fires once (and its loop track is quiesced — see auto-quiesce below).
        probe.Route!.Value = "b"; host.RunFrame();
        probe.On.TryGetValue("a", out int aOn1); probe.Off.TryGetValue("a", out int aOff1);
        bool parkedFires = aOn1 == 0 && aOff1 == 1;

        // Switch back → "a" reactivates (onActivated); "b" parks (its onDeactivated).
        probe.Route.Value = "a"; host.RunFrame();
        probe.On.TryGetValue("a", out int aOn2); probe.Off.TryGetValue("a", out int aOff2);
        probe.Off.TryGetValue("b", out int bOff2);
        bool reactivateFires = aOn2 == 1 && aOff2 == 1 && bOff2 == 1;

        // Window minimize → the ACTIVE (un-parked) page goes inactive too (onDeactivated), then restore → onActivated.
        window.State = FluentGpu.Pal.WindowState.Minimized; host.RunFrame();
        probe.Off.TryGetValue("a", out int aOff3);
        bool minimizeFires = aOff3 == 2;
        window.State = FluentGpu.Pal.WindowState.Normal; host.RunFrame();
        probe.On.TryGetValue("a", out int aOn4);
        bool restoreFires = aOn4 == 2;

        Check("50b. UseActivation fires once per park/minimize transition, silent at mount (parked OR minimized → inactive)",
            mountSilent && animAwake && parkedFires && reactivateFires && minimizeFires && restoreFires,
            $"mountSilent={mountSilent} parked(off={aOff1}) reactivate(on={aOn2},bOff={bOff2}) min(off={aOff3}) restore(on={aOn4})");

        // Auto-quiesce: with the only live page being non-animated ("blank"), the parked pages' loop tracks no longer
        // keep the app awake (HasActive excludes parked tracks) → the Anim wake reason clears; it resumes on return.
        probe.Route.Value = "blank"; host.RunFrame();
        bool quiesced = (host.CurrentWakeReasons & WakeReasons.Anim) == 0;
        probe.Route.Value = "a"; host.RunFrame();
        bool resumed = (host.CurrentWakeReasons & WakeReasons.Anim) != 0;
        Check("50c. Auto-quiesce: a parked subtree's looping animation drops AnimEngine.HasActive (idle wake-stop), resumes on return",
            animAwake && quiesced && resumed, $"animAwake={animAwake} quiesced={quiesced} resumed={resumed}");
    }

    // Engine TextEl auto-fit (TextEl.MinSize / TextStyle.MinSizeDip): a long run shrinks to fit MaxLines at the
    // available width (a SHORTER box than the same run capped+trimmed at the authored size); a run that already fits is
    // NOT shrunk. Asserted against the headless advance model via the laid-out box heights.
    static void AutoFitTextChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("autofit", new Size2(320, 320), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var probe = new AutoFitProbe();
        using var host = new AppHost(app, window, device, fonts, strings, probe);
        host.RunFrame();

        float longFit    = host.Scene.AbsoluteRect(probe.LongFit).H;
        float longFixed  = host.Scene.AbsoluteRect(probe.LongFixed).H;
        float shortFit   = host.Scene.AbsoluteRect(probe.ShortFit).H;
        float shortFixed = host.Scene.AbsoluteRect(probe.ShortFixed).H;

        bool longShrank = longFit > 0f && longFit < longFixed - 1f;   // shrank to fit → shorter than the capped 40px run
        bool shortKept  = Near(shortFit, shortFixed, 1f);             // already fits at the authored size → no shrink

        Check("AF1. TextEl auto-fit (MinSize): a long title shrinks to fit MaxLines; a short title is unchanged",
            longShrank && shortKept,
            $"longFit={longFit:0.#} < longFixed={longFixed:0.#} | shortFit={shortFit:0.#} ~= shortFixed={shortFixed:0.#}");
    }

    // G3 - token system: OnAccent (contrast baked at accent-set time, never at paint), on-media ink/scrim static
    // identity, generated Tok accessors forward the live TokenSet across a theme swap, and the generated Icons table.
    static void G3TokenChecks()
    {
        var savedPalette = Tok.Palette;
        var savedTheme = Tok.Theme;

        // gate.tok.onaccent-contrast
        // Extreme 1: white fill (dark theme -> Light2(white) == white) -> near-black ink, AA-passing, memoized per epoch.
        Tok.Use(savedPalette, ThemeKind.Dark);
        Tok.SetAccent(ColorF.FromRgba(0xFF, 0xFF, 0xFF));
        ColorF bgW = Tok.AccentDefault;
        int cA = Tok.OnAccentComputeCount;
        ColorF inkW = Tok.OnAccent;
        ColorF inkW2 = Tok.OnAccent;               // second read, same epoch -> cached (no recompute)
        int cB = Tok.OnAccentComputeCount;
        bool memoized = cB == cA + 1 && inkW2 == inkW;
        bool wMatches = inkW == ColorContrast.PickContrast(bgW) && ColorContrast.Ratio(inkW, bgW) >= 4.5f;

        // Extreme 2: near-black fill (light theme -> Dark1(#161616) very dark) -> white ink, AA-passing.
        Tok.Use(savedPalette, ThemeKind.Light);
        Tok.SetAccent(ColorF.FromRgba(0x16, 0x16, 0x16));
        ColorF bgB = Tok.AccentDefault;
        ColorF inkB = Tok.OnAccent;
        bool bMatches = inkB == ColorContrast.PickContrast(bgB) && ColorContrast.Ratio(inkB, bgB) >= 4.5f;

        // Mid-saturated fill: picks the WCAG-better ink of the pair.
        Tok.SetAccent(ColorF.FromRgba(0x2E, 0x6C, 0xE0));
        ColorF bgM = Tok.AccentDefault;
        bool mMatches = Tok.OnAccent == ColorContrast.PickContrast(bgM);
        Check("gate.tok.onaccent-contrast", wMatches && bMatches && mMatches && memoized,
            $"whiteAA={ColorContrast.Ratio(inkW, bgW):0.0} blackAA={ColorContrast.Ratio(inkB, bgB):0.0} midMatch={mMatches} memo={memoized}(compute {cA}->{cB})");

        // gate.tok.onmedia-static-identity: scrim/ink getters return identical instances/values (no per-read alloc).
        var s1 = Tok.ScrimBottom; var s2 = Tok.ScrimBottom;
        var t1 = Tok.ScrimTop; var t2 = Tok.ScrimTop;
        bool gradSame = ReferenceEquals(s1.Stops, s2.Stops) && ReferenceEquals(t1.Stops, t2.Stops);
        bool inkStatic = Tok.OnMediaPrimary == new ColorF(1f, 1f, 1f, 1f)
                      && Tok.OnMediaSecondary == new ColorF(1f, 1f, 1f, 0.80f)
                      && Tok.OnMediaTertiary == new ColorF(1f, 1f, 1f, 0.60f)
                      && Tok.MediaScrim == new ColorF(0f, 0f, 0f, 0.55f);
        Check("gate.tok.onmedia-static-identity", gradSame && inkStatic,
            $"scrimStopsIdentical={gradSame} inkScrimValues={inkStatic}");

        // gate.tok.generated-accessors: a GENERATED forward reflects the live TokenSet across a theme swap.
        Tok.Use(savedPalette, ThemeKind.Dark);
        ColorF darkVal = Tok.FillCardDefault;                     // generated `=> T.FillCardDefault`
        bool darkMatch = darkVal == Tok.T.FillCardDefault;
        Tok.Use(savedPalette, ThemeKind.Light);
        ColorF lightVal = Tok.FillCardDefault;
        bool lightMatch = lightVal == Tok.T.FillCardDefault;
        bool flipped = darkVal != lightVal;                       // the table swap is visible through the generated getter
        Check("gate.tok.generated-accessors", darkMatch && lightMatch && flipped,
            $"darkMatch={darkMatch} lightMatch={lightMatch} flipped={flipped}");

        // gate.icons.generated-table: the generated Icons table matches (golden few incl. a Wavee fold-in).
        // Compared by codepoint (ASCII-safe source; no raw PUA glyphs, per the engine icon-font convention).
        bool iconsOk = Icons.Play.Length == 1 && Icons.Play[0] == (char)0xE768
                    && Icons.Pause[0] == (char)0xE769 && Icons.Home[0] == (char)0xE80F
                    && Icons.ChromeClose[0] == (char)0xE8BB && Icons.Album[0] == (char)0xE93C
                    && Icons.Delete[0] == (char)0xE74D;
        Check("gate.icons.generated-table", iconsOk,
            $"Play=U+{(int)Icons.Play[0]:X4} Album=U+{(int)Icons.Album[0]:X4} Delete=U+{(int)Icons.Delete[0]:X4}");

        Tok.SetAccent(null);                                      // restore (headless slice runs with no injected accent)
        Tok.Use(savedPalette, savedTheme);
    }

    // G3 - layout primitives: Ui.AspectRatio derive-missing-dimension + an aspect box is NOT a relayout boundary.
    static void G3AspectChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("aspect", new Size2(640, 480), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new AspectProbe());
        host.RunFrame();

        var root = host.Scene.Root;
        var wBox = Child(host.Scene, root, 0);
        var hBox = Child(host.Scene, root, 1);
        var wb = host.Scene.Bounds(wBox);
        var hb = host.Scene.Bounds(hBox);
        bool wDerives = Near(wb.W, 320f, 0.5f) && Near(wb.H, 180f, 0.5f);   // 320 / (16/9) = 180
        bool hDerives = Near(hb.W, 160f, 0.5f) && Near(hb.H, 90f, 0.5f);    // 90 * (16/9) = 160
        // Not a layout boundary: exactly one authored dimension stays NaN (IsLayoutBoundary needs both set).
        bool notBoundary = float.IsNaN(host.Scene.Layout(wBox).Height) && float.IsNaN(host.Scene.Layout(hBox).Width);
        Check("gate.layout.aspect-derive", wDerives && hDerives && notBoundary,
            $"w=({wb.W:0}x{wb.H:0}) h=({hb.W:0}x{hb.H:0}) notBoundary={notBoundary}");
    }

    // G3 - Spacer / Spacer(px) / Wrap / Center primitives (arranged-rect assertions).
    static void G3PrimitiveChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("primitives", new Size2(640, 640), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new PrimitivesProbe());
        host.RunFrame();

        var s = host.Scene;
        var root = s.Root;
        var row0 = Child(s, root, 0);
        var row1 = Child(s, root, 1);
        var wrap = Child(s, root, 2);
        var centerOuter = Child(s, root, 3);

        // Spacer() grows: the trailing box is pushed to the far edge (300 - 40 - 60 = 200 slack -> box2.X == 240).
        float grownX = s.AbsoluteRect(Child(s, row0, 2)).X - s.AbsoluteRect(row0).X;
        bool spacerGrows = Near(grownX, 240f, 1f);
        // Spacer(24) is rigid: trailing box sits right after the 24px gap (box2.X == 40 + 24 == 64).
        float fixedX = s.AbsoluteRect(Child(s, row1, 2)).X - s.AbsoluteRect(row1).X;
        bool spacerFixed = Near(fixedX, 64f, 1f);
        // Wrap: the third 120-wide box wraps to a new line (Y drops one row, X returns to the line start).
        var w0 = s.AbsoluteRect(Child(s, wrap, 0));
        var w2 = s.AbsoluteRect(Child(s, wrap, 2));
        bool wraps = w2.Y > w0.Y + 20f && Near(w2.X, w0.X, 1f);
        // Center: the 40x40 child is centered on both axes in the 200x200 box.
        var outer = s.AbsoluteRect(centerOuter);
        var inner = s.AbsoluteRect(Child(s, Child(s, centerOuter, 0), 0));
        bool centered = Near(inner.X - outer.X, (outer.W - inner.W) / 2f, 1f)
                     && Near(inner.Y - outer.Y, (outer.H - inner.H) / 2f, 1f);
        Check("gate.ui.spacer-wrap-center", spacerGrows && spacerFixed && wraps && centered,
            $"grow={grownX:0} fixed={fixedX:0} wrapDy={w2.Y - w0.Y:0} centerOff={inner.X - outer.X:0}");
    }

    static void GridChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("grid", new Size2(640, 480), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new GridProbe());
        host.RunFrame();

        var grid = host.Scene.Root;
        var b0 = host.Scene.Bounds(Child(host.Scene, grid, 0));
        var b1 = host.Scene.Bounds(Child(host.Scene, grid, 1));
        var b2 = host.Scene.Bounds(Child(host.Scene, grid, 2));
        var b3 = host.Scene.Bounds(Child(host.Scene, grid, 3));
        var b4 = host.Scene.Bounds(Child(host.Scene, grid, 4));
        bool cols = Near(b0.X, 0) && Near(b1.X, 110) && Near(b2.X, 220) && Near(b0.W, 100);
        bool rows = Near(b3.X, 0) && Near(b3.Y, 60) && Near(b4.X, 110) && Near(b4.Y, 60);
        Check("51. Grid: star tracks split width + row-major auto-flow", cols && rows,
            $"cols x={b0.X:0},{b1.X:0},{b2.X:0} w={b0.W:0}; row2 y={b3.Y:0}");
    }

    // Overflow guard: a GridEl whose FIXED columns exceed its width must shrink them to fit — every column stays
    // within [0, width] (no past-edge/negative colX) and columns never overlap (each starts at/after the prev right).
    static void GridOverflowChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("gridoverflow", new Size2(640, 480), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new GridOverflowProbe());
        host.RunFrame();

        const float W = 120f;
        var grid = host.Scene.Root;
        bool within = true, ordered = true;
        float prevRight = 0f;
        var detail = new System.Text.StringBuilder();
        for (int i = 0; i < 4; i++)
        {
            var b = host.Scene.Bounds(Child(host.Scene, grid, i));
            detail.Append($" c{i}=({b.X:0.#},{b.W:0.#})");
            if (b.X < -0.5f || b.X + b.W > W + 0.5f) within = false;   // no column positioned/sized past the edge
            if (b.X + 0.5f < prevRight) ordered = false;               // no overlap (starts at/after the prev right edge)
            prevRight = b.X + b.W;
        }
        Check("51c. Grid: fixed columns exceeding width shrink-to-fit (no overflow / no overlap)", within && ordered,
            $"W={W:0}{detail}");
    }

    // Regression: a stretch-width grid (no explicit Width) must measure its real content height so a following
    // sibling stacks below it instead of overlapping. 8 cells / 4 cols = 2 rows × 90 + one 12 row-gap = 192.
    static void GridStretchChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("gridstretch", new Size2(640, 480), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new GridStretchProbe());
        host.RunFrame();

        var root = host.Scene.Root;
        var grid = Child(host.Scene, root, 0);
        var after = Child(host.Scene, root, 1);
        var gb = host.Scene.Bounds(grid);
        var ab = host.Scene.Bounds(after);
        bool gridHeight = Near(gb.H, 192f, 1f);          // grid measured its 2 real rows (not 0)
        bool gridWidth = Near(gb.W, 420f, 1f);           // stretched to fill the 420-wide column
        bool noOverlap = ab.Y >= 192f - 0.5f;            // sibling below the grid's real content, not on top of it
        Check("51b. Grid: stretch-width grid measures content height (sibling doesn't overlap)",
            gridHeight && gridWidth && noOverlap, $"gridW={gb.W:0} gridH={gb.H:0} afterY={ab.Y:0}");
    }

    // Detail-page header-vs-row column alignment: the header grid (chrome padding) and the row grid (RowSkin margin +
    // Direction=0 lane + grid padding) must place every column at the SAME X when their containers are equally wide.
    static void ColumnAlignChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("colalign", new Size2(1000, 500), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new ColumnAlignProbe());
        host.RunFrame();

        var scene = host.Scene;
        var root = scene.Root;
        var headerGrid = Child(scene, Child(scene, Child(scene, root, 0), 0), 0);   // root→chrome→headerBox→grid

        // Locate the scroller, its content panel, the first realized row (RowSkin) → lane → grid.
        static NodeHandle FindScroll(SceneStore s, NodeHandle n)
        {
            if (s.TryGetScroll(n, out _)) return n;
            for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c)) { var r = FindScroll(s, c); if (!r.IsNull) return r; }
            return NodeHandle.Null;
        }
        var vp = FindScroll(scene, root);
        NodeHandle firstRow = NodeHandle.Null;
        if (!vp.IsNull && scene.TryGetScroll(vp, out var sc)) firstRow = scene.FirstChild(sc.ContentNode);
        bool haveScroll = !firstRow.IsNull;
        var rowGrid = firstRow.IsNull ? NodeHandle.Null : Child(scene, Child(scene, firstRow, 0), 0);   // RowSkin→lane→grid

        var hsb = new System.Text.StringBuilder();
        var rsb = new System.Text.StringBuilder();
        bool aligned = !rowGrid.IsNull;
        if (!rowGrid.IsNull)
            for (int i = 0; i < 7; i++)
            {
                float hx = scene.AbsoluteRect(Child(scene, headerGrid, i)).X;   // window-space (sums the parent chain)
                float rx = scene.AbsoluteRect(Child(scene, rowGrid, i)).X;
                hsb.Append($"{hx:0.#} ");
                rsb.Append($"{rx:0.#} ");
                if (!Near(hx, rx, 0.5f)) aligned = false;
            }
        Check("51d. virtualized list items honor their Margin → a fixed header's columns align with the scrolled row columns", aligned,
            $"scroll={haveScroll} hdr=[ {hsb}] row=[ {rsb}]");
    }

    // Auto-fill responsive grid: 520 inner width, minCol 120, gap 10 → floor((520+10)/(120+10)) = 4 columns, each
    // (520 − 3×10)/4 = 122.5, packed flush so the 4th column's right edge meets the inner width (no ragged gap).
    static void AutoGridChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("autogrid", new Size2(640, 480), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new AutoGridProbe());
        host.RunFrame();

        var grid = host.Scene.Root;
        var b0 = host.Scene.Bounds(Child(host.Scene, grid, 0));
        var b3 = host.Scene.Bounds(Child(host.Scene, grid, 3));
        var b4 = host.Scene.Bounds(Child(host.Scene, grid, 4));
        bool count = Near(b0.W, 122.5f, 0.5f) && Near(b0.X, 0) && Near(b3.X, 397.5f, 0.5f);   // 4 columns
        bool fillsWidth = Near(b3.X + b3.W, 520f, 0.5f);                                       // right edge flush — fills the width
        bool wraps = Near(b4.X, 0) && Near(b4.Y, 60f, 0.5f);                                   // 5th cell wraps to row 2 (50 + 10 gap)
        Check("51c. AutoGrid: auto-fill packs equal columns that fill the width + reflow",
            count && fillsWidth && wraps, $"col0w={b0.W:0.0} col3right={b3.X + b3.W:0.0} row2y={b4.Y:0}");
    }

    // The Wavee skeleton acceptance test: the shell composes nav + grid + images + controls; navigating to the
    // playlist renders a VIRTUALIZED 5,000-row list (first track realized, last track NOT) — all subsystems at once.
    static void WaveeSkeletonChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("wavee", new Size2(1100, 720), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var shell = new WaveeShell();
        using var host = new AppHost(app, window, device, fonts, strings, shell);

        host.RunFrame();
        bool home = HasGlyph(device, strings, "Album 0") && HasGlyph(device, strings, "Home");
        bool playerBar = HasGlyph(device, strings, "Now Playing") && HasGlyph(device, strings, "Shuffle");
        bool artRequested = host.Images.Count >= 12;   // 12 album cards + now-playing art all requested + pinned

        shell.Nav.Push("playlist", "p0");
        host.RunFrame();
        long liveOnPlaylist = host.Scene.LiveCount;
        bool virtualized = HasGlyph(device, strings, "Track 0")
            && !HasGlyph(device, strings, "Track 4999")     // last row never realized → virtualization holds in the shell
            && liveOnPlaylist < 600;                         // 5,000 rows × multiple nodes would be ≫ this if not virtualized

        bool back = false;
        if (shell.Nav.Pop()) { host.RunFrame(); back = HasGlyph(device, strings, "Album 0"); }   // back-stack returns Home

        Check("52. Wavee skeleton: shell composes nav + grid + images + controls + virtualized list", home && playerBar && artRequested && virtualized && back,
            $"home={home} player={playerBar} art={host.Images.Count} liveOnList={liveOnPlaylist} back={back}");
    }

    // VirtualGrid (2-D): a 1,000-item, 4-column grid realizes only the visible row-window and positions items in cells.
    static void VirtualGridChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("vgrid", new Size2(800, 600), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new VGridProbe());
        host.RunFrame();

        var vp = host.Scene.Root;
        host.Scene.TryGetScroll(vp, out var sc);
        var content = sc.ContentNode;
        int realized = host.Scene.ChildCount(content);
        bool windowed = realized >= 16 && realized < 80;                 // ~visible rows × 4 cols, not 1000
        // ContentExtent = 250 rows × 100 + 249 gaps × 12 = 27,988
        bool contentSize = Near(sc.ContentH, 27988f, 2f);
        // colW = (520 − 3×12)/4 = 121; item 0 at (0,0), item 1 at (133,0), item 4 at (0,112)
        var b0 = host.Scene.Bounds(Child(host.Scene, content, 0));
        var b1 = host.Scene.Bounds(Child(host.Scene, content, 1));
        var b4 = host.Scene.Bounds(Child(host.Scene, content, 4));
        bool cells = Near(b0.X, 0) && Near(b0.W, 121, 1f) && Near(b1.X, 133, 1f) && Near(b4.X, 0) && Near(b4.Y, 112, 1f);

        long live0 = host.Scene.LiveCount;
        for (int s = 0; s < 40; s++) { window.QueueInput(new InputEvent(InputKind.Wheel, new Point2(200, 200), 0, 0, 4000f)); host.RunFrame(); }
        long liveEnd = host.Scene.LiveCount;
        bool recycled = liveEnd < 120 && Math.Abs(liveEnd - live0) < 40;

        Check("53. VirtualGrid: 2-D row-window + cell positions + recycle", windowed && contentSize && cells && recycled,
            $"realized={realized} content={sc.ContentH:0} cell0w={b0.W:0} live {live0}→{liveEnd}");
    }

    // NavigationView adapts its pane to available width: Expanded (labels) → Compact (icon rail) → Minimal (hamburger).
    static (bool label, bool content, float rootW) NavAt(StringTable strings, int width, float scale = 1f)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("nav", new Size2(width, 700), scale));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new NavProbe());
        host.RunFrame();
        return (HasGlyph(device, strings, "Home"), HasGlyph(device, strings, "PAGE:home"), host.Scene.AbsoluteRect(host.Scene.Root).W);
    }

    static void NavigationViewChecks(StringTable strings)
    {
        var exp = NavAt(strings, 1200);   // ≥1008 → Expanded (labels visible)
        var comp = NavAt(strings, 760);   // 641..1008 → Compact (icon rail, no labels)
        var min = NavAt(strings, 520);    // <641 → Minimal (hamburger, no rail labels)
        var dpiComp = NavAt(strings, 1200, 1.5f);
        bool modes = exp.label && !comp.label && !min.label;
        bool content = exp.content && comp.content && min.content;
        Check("54. NavigationView adapts Expanded/Compact/Minimal by width", modes && content,
            $"labels exp={exp.label} comp={comp.label} min={min.label}; content={content}");
        Check("54a. AppHost lays out scaled windows in DIPs", !dpiComp.label && Near(dpiComp.rootW, 800f),
            $"rootW={dpiComp.rootW:0.#} label={dpiComp.label}");

        // 54c — a per-monitor DPI hop MID-SESSION (the WM_DPICHANGED path): EnsureSize watches scale as well as px
        // size, so a scale-only change re-lays-out in the new DIP viewport, and the suggested-rect resize restores it.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("dpihop", new Size2(1200, 700), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            using var host = new AppHost(app, window, device, fonts, strings, new NavProbe());
            host.RunFrame();
            bool labels1 = HasGlyph(device, strings, "Home");
            float w1 = host.Scene.AbsoluteRect(host.Scene.Root).W;          // 1200 DIP @1x → Expanded

            window.Scale = 1.5f;                                            // monitor hop, px not yet adjusted
            host.RunFrame();
            bool labels2 = HasGlyph(device, strings, "Home");
            float w2 = host.Scene.AbsoluteRect(host.Scene.Root).W;          // 800 DIP @1.5x → Compact

            window.ClientSizePx = new Size2(1800, 1050);                    // the OS-suggested rect at the new DPI
            host.RunFrame();
            bool labels3 = HasGlyph(device, strings, "Home");
            float w3 = host.Scene.AbsoluteRect(host.Scene.Root).W;          // 1200 DIP again → Expanded restored

            Check("54c. mid-session DPI change re-lays-out in the new DIP viewport (scale-only, then the suggested-rect resize)",
                labels1 && Near(w1, 1200f) && !labels2 && Near(w2, 800f) && labels3 && Near(w3, 1200f),
                $"w {w1:0}@1x → {w2:0}@1.5x (labels={labels2}) → {w3:0}@1.5x/1800px (labels={labels3})");
        }
    }

    static void NavigationViewAnimationChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("navanim", new Size2(1200, 700), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new NavProbe());
        host.RunFrame();

        NodeHandle FindTopLeftButton()
        {
            NodeHandle best = default;
            void Visit(NodeHandle n)
            {
                if (n.IsNull || !best.IsNull) return;
                var role = host.Scene.Interaction(n).Role;
                var r = host.Scene.AbsoluteRect(n);
                if (role == AutomationRole.Button && r.X < 64f && r.Y < 64f && r.W >= 36f && r.W <= 52f && r.H >= 36f && r.H <= 52f)
                {
                    best = n;
                    return;
                }
                for (var c = host.Scene.FirstChild(n); !c.IsNull; c = host.Scene.NextSibling(c)) Visit(c);
            }
            Visit(host.Scene.Root);
            return best;
        }

        // The content frame's presented LEFT edge slides 320 → 48 as the pane collapses. AbsoluteRect includes the
        // in-flight LocalTransform, so this reads the ANIMATING value (the model x snaps; the projection animates it).
        float ContentLeft()
        {
            float best = 1e9f;
            void Visit(NodeHandle n)
            {
                if (n.IsNull) return;
                var r = host.Scene.AbsoluteRect(n);
                if (r.W > 400f && r.H > 600f && r.X > 30f && r.X < 340f) best = MathF.Min(best, r.X);
                for (var c = host.Scene.FirstChild(n); !c.IsNull; c = host.Scene.NextSibling(c)) Visit(c);
            }
            Visit(host.Scene.Root);
            return best > 1e8f ? -1f : best;
        }

        float x0 = ContentLeft();                 // expanded: content frame at ~320
        var toggle = FindTopLeftButton();
        var tr = host.Scene.AbsoluteRect(toggle);
        var center = new Point2(tr.X + tr.W * 0.5f, tr.Y + tr.H * 0.5f);
        window.QueueInput(new InputEvent(InputKind.PointerDown, center, 0, 0));
        window.QueueInput(new InputEvent(InputKind.PointerUp, center, 0, 0));
        host.RunFrame();                          // reconcile: collapse → seed the content slide + label exits
        var compositorFrame = host.RunFrame();    // next frame advances the springs with NO reconcile / NO relayout
        bool compositorOnly = !compositorFrame.Rendered && host.Animation.HasActive;
        float x1 = ContentLeft();                 // mid-slide: strictly between 48 and 320
        for (int i = 0; i < 30; i++) host.RunFrame();
        float x2 = ContentLeft();                 // settled: ~48

        Check("54b. NavigationView collapse slides content via compositor-only projection (no re-render ticks)",
            !toggle.IsNull && x0 > 300f && x1 < x0 - 4f && x1 > 48f && Near(x2, 48f, 3f) && compositorOnly,
            $"contentX={x0:0}->{x1:0}->{x2:0} compositorOnly={compositorOnly}");
    }

    // ZStack overlays children at the origin (last on top); ItemsRepeater builds (Inline) or virtualizes (Stack).
    static void ZStackRepeaterChecks(StringTable strings)
    {
        var scene = LayoutTree(strings, Ui.ZStack(
            new BoxEl { Width = 120, Height = 40, Fill = ColorF.FromRgba(200, 0, 0) },
            new BoxEl { Width = 60, Height = 20, Fill = ColorF.FromRgba(0, 200, 0) }) with { Width = 200, Height = 100 });
        var z0 = scene.AbsoluteRect(Child(scene, scene.Root, 0));
        var z1 = scene.AbsoluteRect(Child(scene, scene.Root, 1));
        bool zstack = Near(z0.X, 0) && Near(z0.Y, 0) && Near(z1.X, 0) && Near(z1.Y, 0) && Near(z0.W, 120) && Near(z1.W, 60);

        var inlineEl = Repeater.ItemsRepeater(5, i => new BoxEl { Width = 10, Height = 10 }, RepeatLayout.Inline(gap: 2f), keyOf: i => "k" + i);
        bool inlineN = inlineEl is BoxEl box && box.Children.Length == 5 && box.Children[0].Key == "k0";
        bool stackVirtual = Repeater.ItemsRepeater(1000, i => new BoxEl(), RepeatLayout.Stack(40f)) is VirtualListEl;

        Check("55. ZStack overlays at origin; ItemsRepeater builds (Inline) / virtualizes (Stack)", zstack && inlineN && stackVirtual,
            $"z0=({z0.X:0},{z0.Y:0}) z1=({z1.X:0},{z1.Y:0}) inlineN={inlineN} stackVirt={stackVirtual}");
    }

    // Per-run font family threads from TextEl → TextStyle → DrawGlyphRun (the renderer resolves the face by family);
    // Ui.Icon renders a glyph from the icon font. (Real glyph rendering is needs-pixels; the threading is verified here.)
    static void FontFamilyChecks(StringTable strings)
    {
        var scene = new SceneStore();
        new TreeReconciler(scene, strings).ReconcileRoot(
            new BoxEl { Direction = 1, Children = [new TextEl("hi") { FontFamily = "Segoe Fluent Icons" }, new TextEl("plain")] }, null);
        new FlexLayout(scene, new HeadlessFontSystem(strings)).Run(scene.Root);
        var dl = new DrawList();
        SceneRecorder.Record(scene, dl);
        var dev = new HeadlessGpuDevice();
        dev.SubmitDrawList(dl.Bytes, dl.SortKeys, new FrameInfo(new Size2(400, 300), 1f, ColorF.Transparent));

        bool hiFam = false, plainEmpty = false;
        foreach (var g in dev.LastGlyphs)
        {
            string t = strings.Resolve(g.Text), fam = strings.Resolve(g.Family);
            if (t == "hi") hiFam = fam == "Segoe Fluent Icons";
            if (t == "plain") plainEmpty = fam.Length == 0;
        }
        var icon = Ui.Icon(Icons.Play, 20f);
        bool iconFactory = icon.FontFamily == Theme.IconFont && icon.Text.Value == Icons.Play && icon.Size == 20f;
        Check("56. per-run font family threads to the glyph cmd; Ui.Icon uses the icon font", hiFam && plainEmpty && iconFactory,
            $"hiFam={hiFam} plainEmpty={plainEmpty} iconFont='{icon.FontFamily}'");
    }

    // Gradient elevation border (WinUI ControlElevationBorderBrush): a BoxEl with a 2-stop vertical BorderBrush emits a
    // DrawGradientStroke band (inset by bw/2, the gradient PS sampled vertically) on top of the solid fill.
    static void GradientBorderChecks(StringTable strings)
    {
        var brush = Ui.LinearGradient(90f,
            new GradientStop(0.33f, ColorF.FromRgba(0xFF, 0xFF, 0xFF, 0x18)),
            new GradientStop(1f, ColorF.FromRgba(0xFF, 0xFF, 0xFF, 0x12)));
        var scene = LayoutTree(strings, new BoxEl
        {
            Width = 120, Height = 40, Corners = CornerRadius4.All(4f), Fill = ColorF.FromRgba(20, 20, 20),
            BorderBrush = brush, BorderWidth = 1f,
        });
        var dl = new DrawList();
        SceneRecorder.Record(scene, dl);
        var dev = new HeadlessGpuDevice();
        dev.SubmitDrawList(dl.Bytes, dl.SortKeys, new FrameInfo(new Size2(400, 300), 1f, ColorF.Transparent));

        bool oneStroke = dev.LastGradientStrokes.Count == 1;
        var gs = oneStroke ? dev.LastGradientStrokes[0] : default;
        bool band = oneStroke && Near(gs.StrokeWidth, 1f) && gs.StopCount == 2
            && Near(gs.Rect.X, 0.5f) && Near(gs.Rect.W, 119f);          // ring inset by bw/2, width = bounds − bw
        bool solidFill = dev.LastRects.Count == 1;                      // the fill drew once (full bounds), border is the gradient stroke
        Check("57. gradient elevation border emits a DrawGradientStroke band", oneStroke && band && solidFill,
            $"strokes={dev.LastGradientStrokes.Count} w={gs.StrokeWidth:0.0} stops={gs.StopCount} ring=({gs.Rect.X:0.0},{gs.Rect.W:0.0})");

        var fillScene = LayoutTree(strings, new BoxEl
        {
            Width = 120, Height = 40, Corners = CornerRadius4.All(4f),
            Gradient = Ui.LinearGradient(0f, new GradientStop(0f, ColorF.FromRgba(0, 0, 0)), new GradientStop(1f, ColorF.FromRgba(255, 255, 255))),
        });
        dl.Reset();
        SceneRecorder.Record(fillScene, dl);
        dev.SubmitDrawList(dl.Bytes, dl.SortKeys, new FrameInfo(new Size2(400, 300), 1f, ColorF.Transparent));
        bool oneFill = dev.LastGradients.Count == 1 && dev.LastGradients[0].StopCount == 2 && dev.LastRects.Count == 0;
        Check("57b. gradient-only BoxEl emits a DrawGradientRect", oneFill,
            $"gradients={dev.LastGradients.Count} rects={dev.LastRects.Count}");

        var chromeScene = LayoutTree(strings, new BoxEl
        {
            Width = 120,
            Height = 72,
            Corners = Radii.OverlayAll,
            Fill = ColorF.FromRgba(0x20, 0x20, 0x20),
            BorderColor = ColorF.FromRgba(0x80, 0x80, 0x80),
            BorderWidth = 1f,
            Children =
            [
                new BoxEl
                {
                    Width = 120,
                    Height = 36,
                    Fill = ColorF.FromRgba(0x40, 0x40, 0x40),
                },
            ],
        });
        dl.Reset();
        SceneRecorder.Record(chromeScene, dl);
        int firstFill = -1, secondFill = -1, stroke = -1, opIndex = 0, pos = 0;
        var bytes = dl.Bytes;
        while (pos + sizeof(int) <= bytes.Length)
        {
            var op = (DrawOp)MemoryMarshal.Read<int>(bytes.Slice(pos));
            pos += sizeof(int);
            if (op == DrawOp.FillRoundRect)
            {
                if (firstFill < 0) firstFill = opIndex;
                else if (secondFill < 0) secondFill = opIndex;
            }
            else if (op == DrawOp.DrawRoundRectStroke && stroke < 0)
            {
                stroke = opIndex;
            }
            pos += DrawPayloadSize(op);
            opIndex++;
        }
        bool chromeOrder = firstFill >= 0 && secondFill > firstFill && stroke > secondFill;
        Check("57c. BoxEl chrome order: parent border records after descendant fills",
            chromeOrder, $"parentFill={firstFill} childFill={secondFill} stroke={stroke}");

        // 57e — WinUI MappingMode=Absolute (ControlElevationBorderBrush EndPoint 0,3): AxisLengthPx squeezes the stop
        // ramp into 3 physical px of the 40px axis (offsets ×3/40); AnchorEnd (the light/accent ScaleY=-1 mirror)
        // measures the band from the BOTTOM, reversing the stop order so offsets stay ascending.
        {
            var sec = ColorF.FromRgba(0x10, 0x10, 0x10);
            var def = ColorF.FromRgba(0xF0, 0xF0, 0xF0);
            var absBand = new GradientSpec(GradientShape.Linear, 90f,
                [new GradientStop(0.33f, sec), new GradientStop(1f, def)]) { AxisLengthPx = 3f };
            var topScene = LayoutTree(strings, new BoxEl
            {
                Width = 120, Height = 40, Corners = CornerRadius4.All(4f), BorderBrush = absBand, BorderWidth = 1f,
            });
            var dl2 = new DrawList();
            SceneRecorder.Record(topScene, dl2);
            var dev2 = new HeadlessGpuDevice();
            dev2.SubmitDrawList(dl2.Bytes, dl2.SortKeys, new FrameInfo(new Size2(400, 300), 1f, ColorF.Transparent));
            var g1 = dev2.LastGradientStrokes[0];
            float k = 3f / 40f;
            bool topBand = Near(g1.O0, 0.33f * k) && Near(g1.O1, k) && g1.C0 == sec && g1.C1 == def;

            var bottomScene = LayoutTree(strings, new BoxEl
            {
                Width = 120, Height = 40, Corners = CornerRadius4.All(4f),
                BorderBrush = absBand with { AnchorEnd = true }, BorderWidth = 1f,
            });
            var dl3 = new DrawList();
            SceneRecorder.Record(bottomScene, dl3);
            var dev3 = new HeadlessGpuDevice();
            dev3.SubmitDrawList(dl3.Bytes, dl3.SortKeys, new FrameInfo(new Size2(400, 300), 1f, ColorF.Transparent));
            var g2 = dev3.LastGradientStrokes[0];
            bool bottomBand = Near(g2.O0, 1f - k) && Near(g2.O1, 1f - 0.33f * k) && g2.C0 == def && g2.C1 == sec;

            Check("57e. absolute-axis elevation band: 3px ramp at the top; AnchorEnd mirrors it to the bottom (stops reversed)",
                topBand && bottomBand,
                $"top=({g1.O0:0.0000},{g1.O1:0.0000} secFirst={g1.C0 == sec}) bottom=({g2.O0:0.0000},{g2.O1:0.0000} defFirst={g2.C0 == def})");
        }
    }

    // Hover cross-fade: the InteractionAnimator eases HoverT and the recorder lerps Fill→HoverFill in LINEAR light
    // (the WinUI ~83ms BackgroundTransition) — it must ease through an intermediate value, not snap, then settle.
    static void PolylineStrokeChecks(StringTable strings)
    {
        var scene = LayoutTree(strings, new PolylineStrokeEl
        {
            Width = 24,
            Height = 24,
            P0 = new Point2(2, 12),
            P1 = new Point2(10, 20),
            P2 = new Point2(22, 4),
            PointCount = 3,
            Color = ColorF.FromRgba(255, 255, 255),
            Thickness = 2f,
            TrimEnd = 0.5f,
        });
        var dl = new DrawList();
        SceneRecorder.Record(scene, dl);
        var dev = new HeadlessGpuDevice();
        dev.SubmitDrawList(dl.Bytes, dl.SortKeys, new FrameInfo(new Size2(100, 100), 1f, ColorF.Transparent));

        bool staticStroke = dev.LastPolylines.Count == 1 && Near(dev.LastPolylines[0].TrimEnd, 0.5f, 0.001f)
            && dev.LastPolylines[0].PointCount == 3;

        var anim = new AnimEngine(scene);
        anim.Keyframes(scene.Root, AnimChannel.StrokeTrimEnd,
            [new Keyframe(0f, 0f, Easing.Linear), new Keyframe(1f, 1f, EasingSpec.CubicBezier(0.55f, 0f, 0f, 1f))], 100f);
        anim.Tick(0f);
        float t0 = scene.Paint(scene.Root).StrokeTrimEnd;
        anim.Tick(16f);
        float t16 = scene.Paint(scene.Root).StrokeTrimEnd;
        dl.Reset();
        SceneRecorder.Record(scene, dl);
        dev.SubmitDrawList(dl.Bytes, dl.SortKeys, new FrameInfo(new Size2(100, 100), 1f, ColorF.Transparent));

        bool animatedStroke = Near(t0, 0f, 0.001f) && t16 > 0f && t16 < 0.35f
            && dev.LastPolylines.Count == 1 && Near(dev.LastPolylines[0].TrimEnd, t16, 0.001f);
        Check("57d. PolylineStroke emits DrawPolylineStroke and supports animated trim-end",
            staticStroke && animatedStroke, $"static={staticStroke} t0={t0:0.00} t16={t16:0.00} cmds={dev.LastPolylines.Count}");
    }

    static void CrossfadeChecks(StringTable strings)
    {
        var scene = LayoutTree(strings, new BoxEl
        {
            Width = 100, Height = 40, Fill = ColorF.FromRgba(0, 0, 0), HoverFill = ColorF.FromRgba(255, 255, 255),
        });
        var node = scene.Root;
        var ia = new AnimEngine(scene);   // hover/press now engine-driven (InteractionAnimator subsumed)
        ia.SetHover(node, true);

        var dl = new DrawList();
        var dev = new HeadlessGpuDevice();
        float Grey()
        {
            dl.Reset(); SceneRecorder.Record(scene, dl);
            dev.SubmitDrawList(dl.Bytes, dl.SortKeys, new FrameInfo(new Size2(200, 100), 1f, ColorF.Transparent));
            return dev.LastRects[0].Fill.R;
        }

        ia.Tick(4f);                                   // small step → partway, not snapped
        float mid = Grey();
        bool eased = mid > 0.02f && mid < 0.98f;
        for (int i = 0; i < 16; i++) ia.Tick(16f);     // run past 83ms → settle
        float settled = Grey();
        bool done = settled > 0.99f && !ia.HasActive;
        Check("58. hover cross-fade eases in linear light, then settles", eased && done, $"mid={mid:0.00} settled={settled:0.00}");
    }

    static SceneStore Single(StringTable strings)
    {
        var scene = new SceneStore();
        new TreeReconciler(scene, strings).ReconcileRoot(new BoxEl { Width = 20, Height = 20, Fill = ColorF.FromRgba(200, 0, 0) }, null);
        return scene;
    }

    // Granular re-render: a nested component's setState re-renders ONLY that component — not its sibling, not the app.
    static void GranularityChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("gran", new Size2(480, 320), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        Gran.Counts[0] = 0; Gran.Counts[1] = 0; Gran.Parent = 0;
        using var host = new AppHost(app, window, device, fonts, strings, new GranParent());
        host.RunFrame();
        int p0 = Gran.Parent, a0 = Gran.Counts[0], b0 = Gran.Counts[1];

        var child0 = Child(host.Scene, host.Scene.Root, 0);     // GranChild(0) anchor
        var box0 = Child(host.Scene, child0, 0);                // its rendered clickable box
        var r = host.Scene.AbsoluteRect(box0);
        var c = new Point2(r.X + r.W / 2f, r.Y + r.H / 2f);
        window.QueueInput(new InputEvent(InputKind.PointerDown, c, 0, 0));
        window.QueueInput(new InputEvent(InputKind.PointerUp, c, 0, 0));
        var f = host.RunFrame();

        bool only0 = Gran.Counts[0] == a0 + 1 && Gran.Counts[1] == b0 && Gran.Parent == p0;
        Check("59. setState re-renders ONLY the owning component (granular, not the app)",
            only0 && f.ComponentsRendered == 1 && HasGlyph(device, strings, "c0:1"),
            $"c0+{Gran.Counts[0] - a0} c1+{Gran.Counts[1] - b0} parent+{Gran.Parent - p0} componentsRendered={f.ComponentsRendered}");
    }

    // The slider tank, fixed: a signal-bound slider drag updates the thumb/fill transforms with no render/reconcile/layout.
    static void SliderSignalChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("slidersig", new Size2(320, 120), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        SliderSignalProbe.Renders = 0;
        var root = new SliderSignalProbe();
        using var host = new AppHost(app, window, device, fonts, strings, root);
        host.RunFrame();
        int renders0 = SliderSignalProbe.Renders;

        var thumbRow = Child(host.Scene, host.Scene.Root, 1);
        var thumb = Child(host.Scene, thumbRow, 0);
        float dx0 = host.Scene.Paint(thumb).LocalTransform.Dx;

        root.Sig!.Value = 0.7f;          // a drag would do exactly this
        var f = host.RunFrame();
        float dx1 = host.Scene.Paint(thumb).LocalTransform.Dx;

        bool moved = MathF.Abs(dx1 - dx0) > 50f;                  // ~0.4 * 200 = 80px
        bool noRerender = SliderSignalProbe.Renders == renders0;  // the owning component did NOT re-render
        bool compositorOnly = !f.Rendered;                        // no reconcile + no layout this frame
        Check("60. signal-bound slider: value→transform, NO re-render/reconcile/layout (the slider tank, fixed)",
            moved && noRerender && compositorOnly,
            $"thumbDx {dx0:0}→{dx1:0} renders+{SliderSignalProbe.Renders - renders0} rendered={f.Rendered}");
    }

    // Reactive control-flow: For (keyed list) + Show (conditional) restructure the tree with NO parent re-render.
    static void FlowChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("flow", new Size2(320, 480), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        FlowProbe.Renders = 0;
        var root = new FlowProbe();
        using var host = new AppHost(app, window, device, fonts, strings, root);
        host.RunFrame();
        int r0 = FlowProbe.Renders;
        bool init = HasGlyph(device, strings, "row0") && HasGlyph(device, strings, "row2") && !HasGlyph(device, strings, "row3") && HasGlyph(device, strings, "SHOWN");

        root.Count!.Value = 5;
        host.RunFrame();
        bool grew = HasGlyph(device, strings, "row4") && FlowProbe.Renders == r0;

        root.Toggle!.Value = false;
        host.RunFrame();
        bool toggled = HasGlyph(device, strings, "HIDDEN") && !HasGlyph(device, strings, "SHOWN") && FlowProbe.Renders == r0;

        Check("61. reactive For/Show restructure the tree with NO parent re-render", init && grew && toggled,
            $"init={init} grew={grew} toggled={toggled} parentRenders+{FlowProbe.Renders - r0}");
    }

    // A PURE keyed reorder (reverse: same keys, same count) must still relayout — the diff creates/removes nothing,
    // but the re-appended child order has to move the rows (the gallery "Reverse does nothing" regression).
    static void FlowReorderChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("flowreorder", new Size2(320, 480), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        FlowReorderProbe.Renders = 0;
        var root = new FlowReorderProbe();
        using var host = new AppHost(app, window, device, fonts, strings, root);
        host.RunFrame();
        int r0 = FlowReorderProbe.Renders;

        var forHost = Child(host.Scene, host.Scene.Root, 0);
        var rowA = Child(host.Scene, forHost, 0);                 // the "fa" row — identity must survive the reorder
        var b0 = host.Scene.Bounds(rowA);

        var rev = new List<string>(root.Items!.Peek()); rev.Reverse();
        root.Items!.Value = rev;                                  // pure move: no add, no remove, count unchanged
        host.RunFrame();
        var b1 = host.Scene.Bounds(rowA);

        bool lastIsA = Child(host.Scene, forHost, 2) == rowA;     // scene order reversed, node preserved by key
        bool movedInLayout = MathF.Abs(b1.X - b0.X) + MathF.Abs(b1.Y - b0.Y) > 10f;   // and layout actually moved it
        Check("61b. Flow.For pure reorder (reverse) relayouts the rows (key-preserved node moves slots)",
            lastIsA && movedInLayout && FlowReorderProbe.Renders == r0,
            $"rowA ({b0.X:0},{b0.Y:0})→({b1.X:0},{b1.Y:0}) lastIsA={lastIsA} parentRenders+{FlowReorderProbe.Renders - r0}");
    }

    // A Show branch built from PARENT render state must refresh IN PLACE on a parent re-render — the new children take
    // hold (new text, old glyphs gone) while the branch scene node keeps its handle (no remount, no Enter replay), and
    // toggling the condition afterwards still hides the branch. This is the shy-header frozen-accent engine fix.
    static void FlowShowRefreshChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("flowshowrefresh", new Size2(320, 480), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        FlowShowRefreshProbe.Renders = 0;
        var root = new FlowShowRefreshProbe();
        using var host = new AppHost(app, window, device, fonts, strings, root);
        host.RunFrame();

        var showHost = Child(host.Scene, host.Scene.Root, 0);      // the Show boundary node
        var branch0 = Child(host.Scene, showHost, 0);              // the active branch box — identity must survive the refresh
        bool init = HasGlyph(device, strings, "alpha") && !branch0.IsNull;

        root.Label!.Value = "beta";                               // mutate parent-read state → parent re-renders
        host.RunFrame();
        var branch1 = Child(host.Scene, showHost, 0);
        bool refreshed = HasGlyph(device, strings, "beta") && !HasGlyph(device, strings, "alpha");   // new text, old gone
        bool reRendered = FlowShowRefreshProbe.Renders > 1;       // the parent actually re-rendered (not a Show-internal toggle)
        bool sameNode = branch1 == branch0 && !branch1.IsNull;    // in-place Update, NOT a remount

        root.Show!.Value = false;                                 // the condition still hides the branch afterwards
        host.RunFrame();
        bool hidden = !HasGlyph(device, strings, "beta") && Child(host.Scene, showHost, 0).IsNull;

        Check("61c. parent re-render refreshes a Show boundary's branch in place (new children, same node, still hides)",
            init && refreshed && reRendered && sameNode && hidden,
            $"init={init} refreshed={refreshed} reRendered={reRendered} sameNode={sameNode} hidden={hidden} parentRenders={FlowShowRefreshProbe.Renders}");
    }

    static int DirectChildCount(SceneStore s, NodeHandle n)
    {
        int c = 0;
        for (var ch = s.FirstChild(n); !ch.IsNull; ch = s.NextSibling(ch)) c++;
        return c;
    }

    // Flow.For<T> — typed, mandatory-key reactive lists (gate.for.*). Keyed diff preserves row identity; the source is
    // snapshotted ONCE per boundary run; a parent re-render re-points the row closures (the UpdateShow-parity fix);
    // duplicate keys trip a DEBUG guard; and a settled list is 0-alloc on a quiet frame.
    static void ForTypedChecks(StringTable strings)
    {
        var fonts = new HeadlessFontSystem(strings);

        // gate.for.typed-keyed-diff — insert/remove/reorder preserve a row's scene node (⇒ its component state) by key.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("for-keyed", new Size2(240, 400), 1f)); window.Show();
            var probe = new ForKeyedDiffProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            var forHost = Child(host.Scene, host.Scene.Root, 0);
            var rowB = Child(host.Scene, forHost, 1);            // the "b" row — its handle must survive every mutation
            bool init = !rowB.IsNull && DirectChildCount(host.Scene, forHost) == 3;

            probe.Items.Value = new[] { "d", "a", "b", "c" };    // insert 'd' at front → b shifts to index 2, node preserved
            host.RunFrame();
            bool afterInsert = Child(host.Scene, forHost, 2) == rowB && DirectChildCount(host.Scene, forHost) == 4;

            probe.Items.Value = new[] { "d", "b", "c" };         // remove 'a' → b at index 1, node preserved
            host.RunFrame();
            bool afterRemove = Child(host.Scene, forHost, 1) == rowB && DirectChildCount(host.Scene, forHost) == 3;

            probe.Items.Value = new[] { "c", "b", "d" };         // pure reorder → b at index 1, node preserved
            host.RunFrame();
            bool afterReorder = Child(host.Scene, forHost, 1) == rowB && DirectChildCount(host.Scene, forHost) == 3;

            Check("gate.for.typed-keyed-diff insert/remove/reorder preserve a row's node (state) by key",
                init && afterInsert && afterRemove && afterReorder,
                $"init={init} insert={afterInsert} remove={afterRemove} reorder={afterReorder}");
        }

        // gate.for.snapshot-single-read — the items source is read EXACTLY ONCE per boundary run (kills the old N+1).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("for-snapshot", new Size2(240, 400), 1f)); window.Show();
            var probe = new ForSnapshotProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            int afterMount = probe.ItemsReads;                   // 1 read for 5 rows (not 6)
            probe.Items.Value = new[] { 1, 2, 3, 4, 5, 6 };
            host.RunFrame();
            int afterChange = probe.ItemsReads;                  // +1 for the structural change
            Check("gate.for.snapshot-single-read the items thunk runs exactly once per boundary run (N rows, 1 read)",
                afterMount == 1 && afterChange == 2, $"afterMount={afterMount} afterChange={afterChange}");
        }

        // gate.for.update-repoints-closures — a parent re-render rebuilds the For with a fresh Row closure; rows must
        // reflect the NEW captured state IN PLACE (same node), not freeze at mount. Pre-fix (ForEl.Update no-op) fails.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("for-update", new Size2(240, 400), 1f)); window.Show();
            var device = new HeadlessGpuDevice();
            ForUpdateProbe.Renders = 0;
            var probe = new ForUpdateProbe();
            using var host = new AppHost(app, window, device, fonts, strings, probe);
            host.RunFrame();
            var forHost = Child(host.Scene, host.Scene.Root, 0);
            var row0 = Child(host.Scene, forHost, 0);            // the "k1" row — identity must survive the parent re-render
            bool init = HasGlyph(device, strings, "A1") && !row0.IsNull;

            probe.Prefix!.Value = "B";                           // mutate parent-read state → parent re-renders → fresh Row closure
            host.RunFrame();
            var row0b = Child(host.Scene, forHost, 0);
            bool refreshed = HasGlyph(device, strings, "B1") && !HasGlyph(device, strings, "A1");
            bool reRendered = ForUpdateProbe.Renders > 1;
            bool sameNode = row0b == row0 && !row0b.IsNull;      // in-place update by key, NOT a remount
            Check("gate.for.update-repoints-closures parent re-render re-points the For row closures in place (UpdateShow parity)",
                init && refreshed && reRendered && sameNode,
                $"init={init} refreshed={refreshed} reRendered={reRendered} sameNode={sameNode} renders={ForUpdateProbe.Renders}");
        }

        // gate.for.duplicate-key-tripwire (DEBUG) — two rows sharing a key throw inside Fill, naming the key.
        {
#if DEBUG
            bool threw = false; string detail = "no throw";
            try
            {
                using var app = new HeadlessPlatformApp();
                var window = new HeadlessWindow(new WindowDesc("for-dup", new Size2(200, 120), 1f)); window.Show();
                var probe = new ForDupKeyProbe();
                using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
                host.RunFrame();
            }
            catch (InvalidOperationException ex) when (ex.Message.Contains("duplicate key")) { threw = true; detail = "threw naming the dup key"; }
            catch (Exception ex) { detail = "wrong exception: " + ex.GetType().Name; }
            Check("gate.for.duplicate-key-tripwire DEBUG: two rows sharing a key throw inside Fill", threw, detail);
#else
            Check("gate.for.duplicate-key-tripwire DEBUG: two rows sharing a key throw inside Fill", true, "release: DEBUG-only tripwire compiled out");
#endif
        }

        // gate.for.effect-zero-steady-alloc — a settled For adds 0 bytes to the hot phase on a quiet frame.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("for-alloc", new Size2(240, 300), 1f)); window.Show();
            var probe = new ForAllocProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            for (int i = 0; i < 4 && host.HasActiveWork; i++) host.RunFrame();
            for (int i = 0; i < 6; i++) host.Paint(0);           // warm the paths (JIT)
            long worst = 0;
            for (int i = 0; i < 10; i++) { var f = host.Paint(0); if (f.HotPhaseAllocBytes > worst) worst = f.HotPhaseAllocBytes; }
            Check("gate.for.effect-zero-steady-alloc a settled For adds 0 bytes to the hot phase on a quiet frame",
                worst == 0, $"worst={worst} bytes");
        }
    }

    // Pump frames until <paramref name="cond"/> holds (or the frame budget runs out) — drains the UsePost queue each frame
    // so an async completion (posted from a threadpool continuation) lands. Returns whether the condition held.
    static bool PumpUntil(AppHost host, Func<bool> cond, int maxFrames = 200)
    {
        for (int i = 0; i < maxFrames; i++)
        {
            if (cond()) return true;
            host.RunFrame();
        }
        return cond();
    }

    // UseResource — the full stale-while-revalidate contract (gate.resource.*): epoch-ordered completions, refresh SWR,
    // refresh-failure keeps data, optimistic mutate, keep-previous-data, deps re-key to Pending, and stale-time via the
    // HostTimerQueue. Loads are controllable TaskCompletionSources so completion ORDER is scripted deterministically.
    static void ResourceChecks(StringTable strings)
    {
        var fonts = new HeadlessFontSystem(strings);

        // gate.resource.epoch-ordering — start A (slow), re-key to B (fast); B lands; A completing LATER is dropped by
        // the epoch guard (the loader ignores cancellation, so only the epoch stamp — not the token — can drop A).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("res-epoch", new Size2(200, 120), 1f)); window.Show();
            var probe = new ResourceProbe { ObserveCancellation = false };
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            System.Threading.SpinWait.SpinUntil(() => probe.Gates.Count >= 1, 3000);   // load A started (deps=0)
            probe.Key.Value = 1; host.RunFrame();                                       // re-key → load B (deps=1)
            System.Threading.SpinWait.SpinUntil(() => probe.Gates.Count >= 2, 3000);
            probe.Gates[1].SetResult("B");
            bool bLanded = PumpUntil(host, () => probe.Res.Loadable.IsReady && probe.Res.Loadable.Value.Peek() == "B");
            probe.Gates[0].SetResult("A");                                              // the superseded (older-epoch) load completes late
            for (int i = 0; i < 24; i++) host.RunFrame();
            bool aDropped = probe.Res.Loadable.Value.Peek() == "B";
            Check("gate.resource.epoch-ordering out-of-order completion never regresses: B lands, older A is dropped",
                bLanded && aDropped, $"bLanded={bLanded} aDropped={aDropped} value='{probe.Res.Loadable.Value.Peek()}'");
        }

        // gate.resource.refresh-swr — Refresh() keeps Ready(old) visible while fetching (IsFetching true), lands
        // Ready(new); IsFetching toggles false; IsStale flips true after Ready (staleTime=0 default).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("res-swr", new Size2(200, 120), 1f)); window.Show();
            var probe = new ResourceProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            System.Threading.SpinWait.SpinUntil(() => probe.Gates.Count >= 1, 3000);
            probe.Gates[0].SetResult("v0");
            bool ready0 = PumpUntil(host, () => probe.Res.Loadable.Value.Peek() == "v0");
            bool staleAfterReady = probe.Res.IsStale.Peek();                            // staleTime=0 ⇒ stale as soon as Ready
            bool notFetching0 = !probe.Res.IsFetching.Peek();

            probe.Res.Refresh();
            System.Threading.SpinWait.SpinUntil(() => probe.Gates.Count >= 2, 3000);
            bool duringSwr = probe.Res.Loadable.IsReady && probe.Res.Loadable.Value.Peek() == "v0"
                             && probe.Res.IsFetching.Peek() && !probe.Res.IsStale.Peek();
            probe.Gates[1].SetResult("v1");
            bool ready1 = PumpUntil(host, () => probe.Res.Loadable.Value.Peek() == "v1" && !probe.Res.IsFetching.Peek());
            Check("gate.resource.refresh-swr Refresh keeps Ready(old) while fetching, lands Ready(new); IsFetching/IsStale toggle",
                ready0 && staleAfterReady && notFetching0 && duringSwr && ready1,
                $"ready0={ready0} staleAfterReady={staleAfterReady} notFetching0={notFetching0} duringSwr={duringSwr} ready1={ready1}");
        }

        // gate.resource.refresh-failure-keeps-data — a refresh that FAILS keeps the prior Ready value + sets LastError.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("res-failkeep", new Size2(200, 120), 1f)); window.Show();
            var probe = new ResourceProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            System.Threading.SpinWait.SpinUntil(() => probe.Gates.Count >= 1, 3000);
            probe.Gates[0].SetResult("v0");
            PumpUntil(host, () => probe.Res.Loadable.Value.Peek() == "v0");
            probe.Res.Refresh();
            System.Threading.SpinWait.SpinUntil(() => probe.Gates.Count >= 2, 3000);
            probe.Gates[1].SetException(new InvalidOperationException("boom"));
            bool settled = PumpUntil(host, () => !probe.Res.IsFetching.Peek() && probe.Res.LastError is not null);
            bool keptData = probe.Res.Loadable.IsReady && probe.Res.Loadable.Value.Peek() == "v0";
            bool errored = probe.Res.LastError is not null;
            Check("gate.resource.refresh-failure-keeps-data a failed refresh keeps Ready(old) + sets LastError",
                settled && keptData && errored,
                $"settled={settled} keptData={keptData} err={(errored ? probe.Res.LastError!.Message : "null")}");
        }

        // gate.resource.mutate-optimistic — Mutate writes Ready(optimistic) immediately; the revalidation replaces it.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("res-mutate", new Size2(200, 120), 1f)); window.Show();
            var probe = new ResourceProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            System.Threading.SpinWait.SpinUntil(() => probe.Gates.Count >= 1, 3000);
            probe.Gates[0].SetResult("v0");
            PumpUntil(host, () => probe.Res.Loadable.Value.Peek() == "v0");
            probe.Res.Mutate("optimistic");
            bool optimisticNow = probe.Res.Loadable.IsReady && probe.Res.Loadable.Value.Peek() == "optimistic" && probe.Res.IsFetching.Peek();
            System.Threading.SpinWait.SpinUntil(() => probe.Gates.Count >= 2, 3000);
            probe.Gates[1].SetResult("revalidated");
            bool revalidated = PumpUntil(host, () => probe.Res.Loadable.Value.Peek() == "revalidated");
            Check("gate.resource.mutate-optimistic Mutate shows the optimistic value immediately; revalidation replaces it",
                optimisticNow && revalidated, $"optimisticNow={optimisticNow} revalidated={revalidated}");
        }

        // gate.resource.keep-previous-data — a deps change with KeepPreviousData keeps the old value + IsFetching visible.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("res-keepprev", new Size2(200, 120), 1f)); window.Show();
            var probe = new ResourceProbe { Options = new ResourceOptions { KeepPreviousData = true } };
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            System.Threading.SpinWait.SpinUntil(() => probe.Gates.Count >= 1, 3000);
            probe.Gates[0].SetResult("v0");
            PumpUntil(host, () => probe.Res.Loadable.Value.Peek() == "v0");
            probe.Key.Value = 1; host.RunFrame();                                       // deps change — keep-previous
            System.Threading.SpinWait.SpinUntil(() => probe.Gates.Count >= 2, 3000);
            bool keptPrev = probe.Res.Loadable.IsReady && probe.Res.Loadable.Value.Peek() == "v0" && probe.Res.IsFetching.Peek();
            probe.Gates[1].SetResult("v1");
            bool landedNew = PumpUntil(host, () => probe.Res.Loadable.Value.Peek() == "v1");
            Check("gate.resource.keep-previous-data deps change shows the previous value + IsFetching until the new lands",
                keptPrev && landedNew, $"keptPrev={keptPrev} landedNew={landedNew}");
        }

        // gate.resource.deps-rekey-pending — default (no KeepPreviousData): a deps change resets to Pending(seed).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("res-rekey", new Size2(200, 120), 1f)); window.Show();
            var probe = new ResourceProbe();
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            System.Threading.SpinWait.SpinUntil(() => probe.Gates.Count >= 1, 3000);
            probe.Gates[0].SetResult("v0");
            PumpUntil(host, () => probe.Res.Loadable.Value.Peek() == "v0");
            probe.Key.Value = 1; host.RunFrame();                                       // deps change — reset to Pending(seed)
            System.Threading.SpinWait.SpinUntil(() => probe.Gates.Count >= 2, 3000);
            bool pendingSeed = probe.Res.Loadable.IsLoading && probe.Res.Loadable.Value.Peek() == "" && probe.Res.IsFetching.Peek();
            Check("gate.resource.deps-rekey-pending a deps change (default) resets the resource to Pending(seed)",
                pendingSeed, $"isLoading={probe.Res.Loadable.IsLoading} value='{probe.Res.Loadable.Value.Peek()}' fetching={probe.Res.IsFetching.Peek()}");
        }

        // gate.resource.stale-timer — staleTime>0: IsStale stays false after Ready, then flips true once the
        // HostTimerQueue one-shot fires (frame-clock driven; NOT the media clock).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("res-stale", new Size2(200, 120), 1f)); window.Show();
            var probe = new ResourceProbe { Options = new ResourceOptions { StaleTimeMs = 200f } };
            using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
            host.RunFrame();
            System.Threading.SpinWait.SpinUntil(() => probe.Gates.Count >= 1, 3000);
            probe.Gates[0].SetResult("v0");
            PumpUntil(host, () => probe.Res.Loadable.Value.Peek() == "v0");
            bool freshAfterReady = !probe.Res.IsStale.Peek();                           // still fresh right after Ready
            for (int i = 0; i < 20; i++) host.Paint(0);                                 // advance ~320 ms past the 200 ms stale timer
            bool staleAfterTimeout = probe.Res.IsStale.Peek();
            Check("gate.resource.stale-timer staleTime>0 keeps data fresh until the HostTimerQueue one-shot fires",
                freshAfterReady && staleAfterTimeout, $"freshAfterReady={freshAfterReady} staleAfterTimeout={staleAfterTimeout}");
        }
    }

    static void RepeatButtonChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("repeat", new Size2(320, 200), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var root = new RepeatProbe();
        using var host = new AppHost(app, window, device, fonts, strings, root);

        host.RunFrame();
        var btn = FindRole(host.Scene, host.Scene.Root, AutomationRole.Button);
        var center = CenterOf(host.Scene, btn);

        // Press and HOLD (no up): the ticker fires once immediately, then repeats while held.
        window.QueueInput(new InputEvent(InputKind.PointerDown, center, 0, 0));
        host.RunFrame();
        int afterPress = root.Clicks;                     // 1 (fired on arm)
        bool activeHeld = host.HasActiveWork;             // frames keep flowing while held
        for (int i = 0; i < 45; i++) host.RunFrame();     // ~720ms: past the 500ms initial delay + a few intervals
        int heldClicks = root.Clicks;

        // Release: the repeat stops; clicks no longer grow (no busy loop).
        window.QueueInput(new InputEvent(InputKind.PointerUp, center, 0, 0));
        host.RunFrame();
        int atRelease = root.Clicks;
        for (int i = 0; i < 10; i++) host.RunFrame();
        int afterRelease = root.Clicks;

        Check("62. RepeatButton: press fires once, holds repeat, release stops",
            afterPress == 1 && activeHeld && heldClicks >= 2 && afterRelease == atRelease,
            $"press={afterPress} held={heldClicks} release={atRelease}→{afterRelease}");
        Check("62a. RepeatButton: idle after release does no work (no busy loop)", !host.HasActiveWork);
    }

    // Wave 2 — the button/input-state controls adopt the Wave-1 primitives: the IsEnabled engine gate (P1) and the
    // TextEl foreground ramps (P2). Verified end-to-end through the real Button factory.
    static void Wave2ControlChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("wave2", new Size2(320, 240), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var root = new ButtonProbe();
        using var host = new AppHost(app, window, device, fonts, strings, root);

        host.RunFrame();
        var buttons = Roles(host.Scene, AutomationRole.Button);
        var enabledBtn = buttons[0];
        var disabledBtn = buttons[1];
        var restFg = GlyphColor(device, strings, "enabled-btn");   // resting foreground (ButtonForeground = TextPrimary)

        // W2.a the disabled Button swallows the click (the control now sets IsEnabled=false instead of nulling handlers).
        ClickNode(host, window, disabledBtn);
        int afterDisabledClick = root.Clicks;
        ClickNode(host, window, enabledBtn);
        Check("W2.a Button adopts the IsEnabled gate (disabled swallows click; enabled clicks)",
            afterDisabledClick == 0 && root.Clicks == 1, $"disabledClicks={afterDisabledClick} enabled={root.Clicks}");

        // W2.b the disabled Button's label resolves ButtonForegroundDisabled — matched on FULL ARGB (WinUI dims via ALPHA),
        // and proven actually dimmer than the resting foreground (not just the same white RGB).
        var disFg = GlyphColor(device, strings, "disabled-btn");
        var disExpect = Tok.TextDisabled;
        bool disMatchesToken = ColorClose(disFg, disExpect, 0.03f);
        bool disActuallyDimmer = disFg.A < restFg.A - 0.05f;
        Check("W2.b disabled Button label = DisabledForeground (ARGB) and is dimmer than resting",
            disMatchesToken && disActuallyDimmer,
            $"label=({disFg.R:0.00},{disFg.G:0.00},{disFg.B:0.00},A={disFg.A:0.00}) token A={disExpect.A:0.00} restA={restFg.A:0.00}");

        // W2.c pressing the enabled Button ramps its label to ButtonForegroundPressed (TextSecondary) — full ARGB, and
        // the alpha actually changed from resting (the WinUI press dim).
        var c = CenterOf(host.Scene, enabledBtn);
        window.QueueInput(new InputEvent(InputKind.PointerDown, c, 0, 0));
        for (int i = 0; i < 20; i++) host.RunFrame();
        var pressFg = GlyphColor(device, strings, "enabled-btn");
        var pressExpect = Tok.TextSecondary;
        bool pressMatchesToken = ColorClose(pressFg, pressExpect, 0.06f);
        bool pressChangedFromRest = MathF.Abs(pressFg.A - restFg.A) > 0.02f || !ColorClose(pressFg, restFg, 0.02f);
        window.QueueInput(new InputEvent(InputKind.PointerUp, c, 0, 0));
        host.RunFrame();
        Check("W2.c pressed Button label ramps to PressedForeground (ARGB, changed from resting)",
            pressMatchesToken && pressChangedFromRest,
            $"label=({pressFg.R:0.00},{pressFg.G:0.00},{pressFg.B:0.00},A={pressFg.A:0.00}) pressTokenA={pressExpect.A:0.00} restA={restFg.A:0.00}");

        // W2.d HyperlinkButton uses the accent TEXT palette (AccentTextPrimary), NOT the accent FILL (AccentDefault),
        // and that foreground tracks a live accent override (OS accent / Tok.SetAccent) by recomputing its shade.
        ColorF LinkForeground(string id)
        {
            using var a = new HeadlessPlatformApp();
            var w = new HeadlessWindow(new WindowDesc(id, new Size2(240, 120), 1f)); w.Show();
            var dev = new HeadlessGpuDevice();
            using var h = new AppHost(a, w, dev, new HeadlessFontSystem(strings), strings, new HyperlinkProbe());
            h.RunFrame();
            return GlyphColor(dev, strings, "link-text");
        }

        var defFg = LinkForeground("hlink");
        bool usesAccentText = ColorClose(defFg, Tok.AccentTextPrimary, 0.02f) && !ColorClose(defFg, Tok.AccentDefault, 0.02f);

        Tok.SetAccent(ColorF.FromRgba(0xE0, 0x40, 0x40));   // developer/OS override (red)
        var ovFg = LinkForeground("hlink2");
        Tok.SetAccent(null);                                 // clear the override (revert to theme default)
        bool tracksOverride = !ColorClose(ovFg, defFg, 0.05f) && ovFg.R > ovFg.B + 0.1f;   // now reddish, changed

        Check("W2.d HyperlinkButton foreground = accent TEXT (not fill) and tracks the accent override",
            usesAccentText && tracksOverride,
            $"def=({defFg.R:0.00},{defFg.G:0.00},{defFg.B:0.00}) override=({ovFg.R:0.00},{ovFg.G:0.00},{ovFg.B:0.00}) accentFill=({Tok.AccentDefault.R:0.00},{Tok.AccentDefault.G:0.00},{Tok.AccentDefault.B:0.00})");
    }

    // Wave 1 / P3 — typed computed "TemplateSettings" convention: the Expander derives ExpanderTemplateSettings once from
    // its open state and feeds them into channels — the chevron ROTATION (one glyph, down→up) and the content reveal.
    static void ExpanderSettingsChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("expander", new Size2(360, 240), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var root = new Expander { Header = "Section", Content = new TextEl("expander-body") { Size = 14f }, InitiallyExpanded = false };
        using var host = new AppHost(app, window, device, fonts, strings, root);

        host.RunFrame();   // collapsed (chevron rotation seeded to 0° → identity)
        var chevron0 = Child(host.Scene, Child(host.Scene, host.Scene.Root, 0), 1);
        float m11Collapsed = host.Scene.Paint(chevron0).LocalTransform.M11;
        bool noContent = Child(host.Scene, Child(host.Scene, host.Scene.Root, 1), 0).IsNull;   // clip mounted, panel not

        // Toggle open. (a) The chevron rotation TWEENS (167ms): track peak sin θ — a tween passes through a mid-angle
        // (sin θ → ~1 near 90°), an instant snap never leaves ~0. (b) The content panel SLIDES out from under the
        // header: the clip wrapper's SizeMode.Reflow Trailing anchor keeps the panel's bottom edge on the reveal edge
        // (ChildShiftY < 0 mid-flight, 0 at rest) — an instant appear would read 0 every frame.
        ClickNode(host, window, Child(host.Scene, host.Scene.Root, 0));
        float peakSin = 0f, minShift = 0f;
        for (int i = 0; i < 16; i++)
        {
            host.RunFrame();
            var ch = Child(host.Scene, Child(host.Scene, host.Scene.Root, 0), 1);
            peakSin = MathF.Max(peakSin, MathF.Abs(host.Scene.Paint(ch).LocalTransform.M12));
            var clipW = Child(host.Scene, host.Scene.Root, 1);   // the reflow clip wrapper carries the child-shift
            if (!clipW.IsNull) minShift = MathF.Min(minShift, host.Scene.Paint(clipW).ChildShiftY);
        }
        bool rotating = peakSin > 0.5f;
        bool contentSlidIn = minShift < -4f;

        for (int i = 0; i < 16; i++) host.RunFrame();   // settle
        var chevronDone = Child(host.Scene, Child(host.Scene, host.Scene.Root, 0), 1);
        float m11Done = host.Scene.Paint(chevronDone).LocalTransform.M11;   // cos 180° ≈ -1
        bool settled = m11Done < -0.9f;
        bool hasContent = !Child(host.Scene, Child(host.Scene, host.Scene.Root, 1), 0).IsNull && HasGlyph(device, strings, "expander-body");

        Check("W1-P3.a Expander animates chevron rotation + content slide (mid-flight)",
            Near(m11Collapsed, 1f, 0.05f) && rotating && settled && contentSlidIn && hasContent,
            $"m11→{m11Done:0.00} peakSinθ={peakSin:0.00} minShift={minShift:0.0} content {!noContent}→{hasContent}");
    }

    // Wave 1 / P5a — popup placement result: vertical flip when a side can't fit, corner-join against the anchor, and
    // height clamping under a full collision. Pure math — deterministic, no host.
    static void PlacementChecks()
    {
        var vp = new Size2(480, 400);

        // Anchor near the bottom: a 120-tall free flyout can't fit below → flips ABOVE; free flyouts keep all corners.
        var low = new RectF(20, 380, 100, 24);
        var pa = FlyoutPositioner.Place(in low, new Size2(100, 120), in vp, FlyoutPlacement.BottomLeft);
        bool flipped = pa.OpensUp && pa.Y < low.Y && pa.CornerJoin == CornerJoin.None;

        // Anchor near the top: a free flyout opens BELOW (default) and still keeps all corners rounded.
        var high = new RectF(20, 10, 100, 24);
        var pb = FlyoutPositioner.Place(in high, new Size2(100, 120), in vp, FlyoutPlacement.BottomLeft);
        // WinUI FlyoutBase::FlyoutMargin = 4 (FlyoutBase_Partial.cpp:65) — the flyout sits 4px off the anchor edge.
        bool below = !pb.OpensUp && pb.Y >= high.Y + high.H + 3.5f && pb.CornerJoin == CornerJoin.None;

        // Attached stretch dropdowns (ComboBox/AutoSuggest style) stay flush and join the field edge.
        var attach = FlyoutPositioner.Place(in high, new Size2(100, 120), in vp, FlyoutPlacement.BottomStretch);
        bool attachedJoin = !attach.OpensUp && Near(attach.Y, high.Y + high.H, 0.01f) && attach.CornerJoin == CornerJoin.Top;

        // Popup taller than the viewport (collides both ways): clamp MeasuredH to the larger side (here, below).
        var mid = new RectF(20, 180, 100, 24);
        var pc = FlyoutPositioner.Place(in mid, new Size2(100, 600), in vp, FlyoutPlacement.BottomLeft);
        bool clamped = pc.MeasuredH > 0f && pc.MeasuredH < 600f;

        Check("W1-P5.a placement: flip-up + free/attached corner-join + collision clamp",
            flipped && below && attachedJoin && clamped,
            $"flip={flipped} below={below} attach={attachedJoin} clampH={pc.MeasuredH:0}");
    }

    // Wave 1 / P5b — overlay focus-restoration: an overlay captures the focused node at open time and restores it when
    // it finishes closing (host-wired through the InputHooks focus get/restore delegates).
    static void OverlayFocusRestoreChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("ovfocus", new Size2(480, 360), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var root = new FocusRestoreProbe();
        using var host = new AppHost(app, window, device, fonts, strings, root);

        host.RunFrame();
        ClickNode(host, window, root.AnchorNode);   // focus the anchor (pre-open focus)
        bool anchorFocused = (host.Scene.Flags(root.AnchorNode) & NodeFlags.Focused) != 0;

        // Open an overlay (captures SavedFocus = anchor), Tab moves focus into it, then close and let it settle.
        root.Handle = root.Service!.Open(() => root.AnchorNode,
            () => new BoxEl { Width = 120, Height = 80, Children = [new BoxEl { Width = 100, Height = 24, OnClick = () => { } }] });
        host.RunFrame();
        window.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.Tab));
        host.RunFrame();
        bool movedAway = (host.Scene.Flags(root.AnchorNode) & NodeFlags.Focused) == 0;
        void DumpP5b(NodeHandle n, int d)
        {
            var fl = host.Scene.Flags(n);
            Console.Error.WriteLine($"[DBG-P5b] {new string(' ', d * 2)}{n} focusable={(fl & NodeFlags.Focusable) != 0} focused={(fl & NodeFlags.Focused) != 0} role={host.Scene.Interaction(n).Role}");
            for (var c = host.Scene.FirstChild(n); !c.IsNull; c = host.Scene.NextSibling(c)) DumpP5b(c, d + 1);
        }
        DumpP5b(host.Scene.Root, 0);

        Console.Error.WriteLine($"[DBG-P5b] beforeClose anchor={root.AnchorNode}");
        root.Handle.Close();
        Console.Error.WriteLine($"[DBG-P5b] afterClose anchorFocused={(host.Scene.Flags(root.AnchorNode) & NodeFlags.Focused) != 0}");
        for (int i = 0; i < 30; i++)
        {
            host.RunFrame();   // close fade settles → Finalize → restore
            if (i < 5 || i == 29) Console.Error.WriteLine($"[DBG-P5b] f{i} anchorFocused={(host.Scene.Flags(root.AnchorNode) & NodeFlags.Focused) != 0}");
        }
        bool restored = (host.Scene.Flags(root.AnchorNode) & NodeFlags.Focused) != 0;

        Check("W1-P5.b overlay restores focus to the pre-open node on close",
            anchorFocused && movedAway && restored, $"anchor0={anchorFocused} movedAway={movedAway} restored={restored}");
    }

    // Wave 1 / P6 — focus/keyboard navigation service: TabIndex-respecting tab order, XY arrow navigation, and scoped
    // roving (within an overlay/menu subtree). Drives the InputDispatcher directly (no AppHost needed).
    // E2 — the widened input vocabulary: modifiers, Space-on-keyup activation, click count, right-tap context,
    // accelerators, access keys, focus scopes, window blur, hover-resolved cursors.
    static void InputVocabularyChecks(StringTable strings)
    {
        var fonts = new HeadlessFontSystem(strings);

        // E2.a — Shift+Tab walks focus backward.
        {
            var scene = new SceneStore();
            new TreeReconciler(scene, strings).ReconcileRoot(new BoxEl
            {
                Direction = 0, Gap = 10,
                Children =
                [
                    new BoxEl { Key = "A", Width = 20, Height = 20, OnClick = () => { } },
                    new BoxEl { Key = "B", Width = 20, Height = 20, OnClick = () => { } },
                ],
            }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            var a = Child(scene, scene.Root, 0); var b = Child(scene, scene.Root, 1);
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Tab) });
            var f1 = disp.Focused;   // A
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Tab, Mods: KeyModifiers.Shift) });
            var f2 = disp.Focused;   // wraps back to B
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Tab, Mods: KeyModifiers.Shift) });
            var f3 = disp.Focused;   // back to A
            Check("E2.a Shift+Tab walks focus backward (wraps)", f1 == a && f2 == b && f3 == a,
                $"f1=A?{f1 == a} f2=B?{f2 == b} f3=A?{f3 == a}");
        }

        // E2.b/c/d — WinUI ButtonBase activation (ButtonBaseKeyProcess.h): Space/Enter key-DOWN arms the pressed
        // visual (held-key repeats ignored — ONE activation per hold); the click fires on key-UP (ClickMode.Release,
        // ButtonBase_Partial.cpp:475-483); Escape or ANY other key while held cancels without firing (:64-70).
        {
            var scene = new SceneStore();
            int clicks = 0;
            new TreeReconciler(scene, strings).ReconcileRoot(
                new BoxEl { Width = 40, Height = 20, OnClick = () => clicks++ }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            disp.MoveFocus(forward: true);
            var node = disp.Focused;

            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Enter) });
            bool enterArms = clicks == 0 && (scene.Flags(node) & NodeFlags.Pressed) != 0;   // pressed, no click yet
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Enter, IsRepeat: true) });
            bool heldOnce = clicks == 0;                                                    // held Enter never re-fires
            disp.Dispatch(new[] { new InputEvent(InputKind.KeyUp, default, 0, Keys.Enter) });
            bool enterUp = clicks == 1 && (scene.Flags(node) & NodeFlags.Pressed) == 0;     // click on the UP edge

            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Space) });
            bool armedNoFire = clicks == 1 && (scene.Flags(node) & NodeFlags.Pressed) != 0;
            disp.Dispatch(new[] { new InputEvent(InputKind.KeyUp, default, 0, Keys.Space) });
            bool firedOnUp = clicks == 2 && (scene.Flags(node) & NodeFlags.Pressed) == 0;
            Check("E2.b Space/Enter arm pressed on key-down, click on key-up; a held key activates exactly once",
                enterArms && heldOnce && enterUp && armedNoFire && firedOnUp,
                $"enterArm={enterArms} held={heldOnce} enterUp={enterUp} spaceArm={armedNoFire} spaceUp={firedOnUp}");

            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Space) });
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Escape) });
            disp.Dispatch(new[] { new InputEvent(InputKind.KeyUp, default, 0, Keys.Space) });
            Check("E2.c Escape cancels a held Space without firing",
                clicks == 2 && (scene.Flags(node) & NodeFlags.Pressed) == 0, $"clicks={clicks}");

            // ANY other key while held also cancels without firing (ButtonBaseKeyProcess.h:64-70) — the press visual
            // clears on the foreign key-down and the eventual Space-up does nothing.
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Space) });
            bool reArmed = (scene.Flags(node) & NodeFlags.Pressed) != 0;
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.A) });
            bool canceledByKey = (scene.Flags(node) & NodeFlags.Pressed) == 0;
            disp.Dispatch(new[] { new InputEvent(InputKind.KeyUp, default, 0, Keys.Space) });
            Check("E2.c2 any other key-down cancels a held Space/Enter press without firing",
                reArmed && canceledByKey && clicks == 2, $"armed={reArmed} canceled={canceledByKey} clicks={clicks}");
        }

        // E2.e — double/triple-click promotion (timestamps + slop) surfaces in OnPointerPressed.ClickCount.
        {
            var scene = new SceneStore();
            var counts = new List<byte>();
            new TreeReconciler(scene, strings).ReconcileRoot(
                new BoxEl { Width = 60, Height = 30, OnPointerPressed = e => counts.Add(e.ClickCount) }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            var p = new Point2(10, 10);
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, p, 0, 0, TimestampMs: 1000) });
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, p, 0, 0, TimestampMs: 1040) });
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, p, 0, 0, TimestampMs: 1100) });
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, p, 0, 0, TimestampMs: 1140) });
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, p, 0, 0, TimestampMs: 1200) });
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, p, 0, 0, TimestampMs: 1240) });
            // A press 600ms later resets to 1; so does a press 5px away.
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, p, 0, 0, TimestampMs: 2400) });
            Check("E2.e click count promotes 1→2→3 inside the window and resets after it",
                counts.Count == 4 && counts[0] == 1 && counts[1] == 2 && counts[2] == 3 && counts[3] == 1,
                string.Join(",", counts));
        }

        // E2.f/g — right-click release fires OnContextRequested (left never does); the Menu key (VK_APPS) fires it
        // on the focused node at its centre.
        {
            var scene = new SceneStore();
            int ctx = 0; Point2 ctxAt = default; ContextRequestTrigger ctxTrigger = default;
            new TreeReconciler(scene, strings).ReconcileRoot(
                new BoxEl
                {
                    Width = 60, Height = 30, OnClick = () => { },
                    OnContextRequested = e => { ctx++; ctxAt = e.Position; ctxTrigger = e.Trigger; },
                }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            var p = new Point2(20, 10);
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, p, 0, 0) });
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, p, 0, 0) });
            bool leftSilent = ctx == 0;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, p, 1, 0) });
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, p, 1, 0) });
            bool rightFired = ctx == 1 && ctxTrigger == ContextRequestTrigger.Pointer
                && Near(ctxAt.X, 20) && Near(ctxAt.Y, 10);
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Apps) });   // focused by the left click
            bool appsFired = ctx == 2 && ctxTrigger == ContextRequestTrigger.Keyboard
                && Near(ctxAt.X, 30) && Near(ctxAt.Y, 15);                                  // node centre
            Check("E2.f right-click release fires OnContextRequested (left stays silent)", leftSilent && rightFired,
                $"left={leftSilent} right={rightFired} at=({ctxAt.X:0.#},{ctxAt.Y:0.#})");
            Check("E2.g VK_APPS requests the context menu at the focused node's centre", appsFired,
                $"ctx={ctx} at=({ctxAt.X:0.#},{ctxAt.Y:0.#})");
        }

        // E2.m — BoxEl.ClickRequestsContext (input-a11y §6.5.1): the declarative "this button opens the ancestor's
        // context menu". (a) the prop reconciles to ClickBit|ClickRequestsContextBit with a NULL click-handler column
        // (+ the focusable implication); (b) a left click on the button fires the NEAREST OnContextRequested as an
        // Invoke request (Source = the button, Node = the row) and fires NO click; (c) toggling the prop off clears
        // bit 16 without stomping neighbor bits — the R1 regression guard for the HandlerMask ushort→uint widening
        // (every no-handler clear-site runs AFTER the bit is set in the same reconcile, so a single surviving
        // ushort-truncated `&=` would stomp bit 16 before (a) ever reads it).
        {
            var scene = new SceneStore();
            var recon = new TreeReconciler(scene, strings);
            int ctx = 0, keys = 0;
            Point2 ctxAt = default; ContextRequestTrigger ctxTrigger = default;
            NodeHandle ctxNode = default, ctxSource = default;
            BoxEl Tree(bool crc) => new BoxEl
            {
                Key = "row", Width = 100, Height = 30, Direction = 0,
                OnContextRequested = e => { ctx++; ctxAt = e.Position; ctxTrigger = e.Trigger; ctxNode = e.Node; ctxSource = e.Source; },
                Children =
                [
                    new BoxEl { Key = "spacer", Width = 40, Height = 30 },
                    // OnKeyDown + Cursor ride along as NEIGHBOR bits (KeyBit, CursorBit) for the (c) stomp check.
                    new BoxEl { Key = "more", Width = 20, Height = 20, OnKeyDown = _ => keys++, Cursor = CursorId.Hand, ClickRequestsContext = crc },
                ],
            };
            var t1 = Tree(true);
            recon.ReconcileRoot(t1, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var row = scene.Root;
            var more = Child(scene, row, 1);
            ref readonly var ii1 = ref scene.Interaction(more);
            bool bitsSet = (ii1.HandlerMask & InteractionInfo.ClickBit) != 0
                        && (ii1.HandlerMask & InteractionInfo.ClickRequestsContextBit) != 0;
            bool nullClick = scene.GetClickHandler(more) is null;
            bool focusable = ii1.Focusable;
            Check("E2.m.a ClickRequestsContext reconciles to ClickBit|ClickRequestsContextBit with a null click handler (+ focusable)",
                bitsSet && nullClick && focusable, $"mask={ii1.HandlerMask:x} nullClick={nullClick} focusable={focusable}");

            var disp = new InputDispatcher(scene);
            var br = scene.AbsoluteRect(more);
            var pt = new Point2(br.X + br.W / 2f, br.Y + br.H / 2f);
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, pt, 0, 0) });
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, pt, 0, 0) });
            bool invoked = ctx == 1 && ctxTrigger == ContextRequestTrigger.Invoke
                        && ctxNode == row && ctxSource == more
                        && Near(ctxAt.X, pt.X) && Near(ctxAt.Y, pt.Y);   // the button centre, row-local (row at origin)
            Check("E2.m.b a left click on the button raises the nearest OnContextRequested as Invoke (Source=button, Node=row), no click",
                invoked, $"ctx={ctx} trig={ctxTrigger} node={ctxNode.Raw.Index}/{row.Raw.Index} src={ctxSource.Raw.Index}/{more.Raw.Index} at=({ctxAt.X:0.#},{ctxAt.Y:0.#})");

            var t2 = Tree(false);
            recon.ReconcileRoot(t2, t1);
            ref readonly var ii2 = ref scene.Interaction(more);
            bool bit16Cleared = (ii2.HandlerMask & InteractionInfo.ClickRequestsContextBit) == 0
                             && (ii2.HandlerMask & InteractionInfo.ClickBit) == 0;   // no OnClick either → ClickBit clears too
            bool neighborsIntact = (ii2.HandlerMask & InteractionInfo.KeyBit) != 0
                                && (ii2.HandlerMask & InteractionInfo.CursorBit) != 0;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, pt, 0, 0) });
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, pt, 0, 0) });
            bool inert = ctx == 1;   // the prop off → the click no longer re-enters the context funnel
            Check("E2.m.c toggling the prop off clears bit 16 without stomping neighbor bits (the uint HandlerMask R1 guard)",
                bit16Cleared && neighborsIntact && inert, $"mask={ii2.HandlerMask:x} inert={inert}");
        }

        // E2.h/i — a Ctrl+K accelerator and an Alt+S access-key chord invoke their owner from anywhere.
        {
            var scene = new SceneStore();
            int accel = 0, access = 0;
            new TreeReconciler(scene, strings).ReconcileRoot(new BoxEl
            {
                Direction = 0, Gap = 8,
                Children =
                [
                    new BoxEl { Key = "plain", Width = 20, Height = 20, OnClick = () => { } },
                    new BoxEl { Key = "accel", Width = 20, Height = 20, OnClick = () => accel++, Accelerator = new KeyAccelerator(Keys.K, KeyModifiers.Ctrl) },
                    new BoxEl { Key = "access", Width = 20, Height = 20, OnClick = () => access++, AccessKey = 'S' },
                ],
            }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            disp.MoveFocus(forward: true);   // focus the PLAIN node — accelerator must still find its owner
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.K, Mods: KeyModifiers.Ctrl) });
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.K) });   // bare K: no accelerator
            Check("E2.h Ctrl+K accelerator invokes its owner from anywhere (bare K does not)", accel == 1, $"accel={accel}");
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.S, Mods: KeyModifiers.Alt) });
            Check("E2.i Alt+S access-key chord invokes the mnemonic owner", access == 1, $"access={access}");
        }

        // E2.j — a pushed focus scope traps Tab inside its subtree until popped (dialog focus trap).
        {
            var scene = new SceneStore();
            new TreeReconciler(scene, strings).ReconcileRoot(new BoxEl
            {
                Direction = 1,
                Children =
                [
                    new BoxEl { Key = "outside", Width = 20, Height = 20, OnClick = () => { } },
                    new BoxEl { Key = "dialog", Direction = 0, Gap = 4, Children = [
                        new BoxEl { Key = "d1", Width = 20, Height = 20, OnClick = () => { } },
                        new BoxEl { Key = "d2", Width = 20, Height = 20, OnClick = () => { } } ] },
                ],
            }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            var outside = Child(scene, scene.Root, 0);
            var dialog = Child(scene, scene.Root, 1);
            var d1 = Child(scene, dialog, 0); var d2 = Child(scene, dialog, 1);
            disp.PushFocusScope(dialog);
            bool stays = true;
            disp.MoveFocus(forward: true);
            for (int i = 0; i < 4; i++)
            {
                disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Tab) });
                stays &= disp.Focused == d1 || disp.Focused == d2;
            }
            disp.PopFocusScope();
            bool escapes = false;   // scope released → full-tree cycling reaches the outside node again
            for (int i = 0; i < 3 && !escapes; i++)
            {
                disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Tab) });
                escapes = disp.Focused == outside;
            }
            Check("E2.j focus scope traps Tab inside the dialog subtree until popped", stays && escapes,
                $"trapped={stays} released={escapes}");
        }

        // E2.k — WindowBlur clears pressed/hover state and raises the host blur hook (light-dismiss trigger).
        {
            var scene = new SceneStore();
            new TreeReconciler(scene, strings).ReconcileRoot(
                new BoxEl { Width = 40, Height = 20, OnClick = () => { } }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            bool blurred = false;
            disp.OnWindowBlur = () => blurred = true;
            var node = Child(scene, scene.Root, 0).IsNull ? scene.Root : scene.Root;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, new Point2(10, 10), 0, 0) });
            bool pressedBefore = (scene.Flags(scene.Root) & NodeFlags.Pressed) != 0;
            disp.Dispatch(new[] { new InputEvent(InputKind.WindowBlur, default, 0, 0) });
            bool clearedAfter = (scene.Flags(scene.Root) & NodeFlags.Pressed) == 0;
            Check("E2.k WindowBlur clears pressed state and raises the blur hook",
                pressedBefore && clearedAfter && blurred, $"before={pressedBefore} after={clearedAfter} hook={blurred}");
        }

        // E2.l — hover resolves the cursor with WinUI semantics: clickability does NOT imply the hand (arrow unless an
        // element declares a cursor — WinUI sets the hand only on HyperlinkButton); an explicit cursor INHERITS down to
        // cursor-less descendants; and an explicit Arrow on a child MASKS an ancestor's I-beam (CursorBit stops the
        // walk — WinUI's forced SetCursor(MouseCursorArrow) on TextBox's delete button, TextBox_Partial.cpp:884).
        {
            var scene = new SceneStore();
            new TreeReconciler(scene, strings).ReconcileRoot(new BoxEl
            {
                Direction = 0, Gap = 10, Padding = Edges4.All(0),
                Children =
                [
                    new BoxEl { Key = "plain", Width = 20, Height = 20, OnClick = () => { } },
                    new BoxEl
                    {
                        Key = "field", Direction = 0, Gap = 10, Cursor = CursorId.IBeam,   // an editing surface
                        Children =
                        [
                            new BoxEl { Key = "text", Width = 20, Height = 20, OnClick = () => { } },                            // inherits I-beam
                            new BoxEl { Key = "affix", Width = 20, Height = 20, OnClick = () => { }, Cursor = CursorId.Arrow }, // masks I-beam
                        ],
                    },
                    new BoxEl { Key = "link", Width = 20, Height = 20, OnClick = () => { }, Cursor = CursorId.Hand },
                ],
            }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            CursorId last = CursorId.Arrow;
            disp.OnCursorChanged = c => last = c;
            // Row layout: plain 0–20 | field 30–80 (text 30–50, gap 50–60, affix 60–80) | link 90–110.
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(100, 10), 0, 0) });
            bool hand = last == CursorId.Hand;                  // explicit Hand (the HyperlinkButton case)
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(10, 10), 0, 0) });
            bool plainArrow = last == CursorId.Arrow;           // clickable WITHOUT a declared cursor → arrow, not hand
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(40, 10), 0, 0) });
            bool inherited = last == CursorId.IBeam;            // cursor-less child falls through to the field's I-beam
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(70, 10), 0, 0) });
            bool masked = last == CursorId.Arrow;               // child's explicit Arrow masks the ancestor I-beam
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(55, 10), 0, 0) });
            bool ownSurface = last == CursorId.IBeam;           // the field's OWN gap resolves its I-beam (CursorBit
                                                                // makes a cursor-declared node hover-resolvable, like
                                                                // WinUI's background-gated hit testing)
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(300, 200), 0, 0) });
            bool offArrow = last == CursorId.Arrow;             // off-control: a REAL IBeam→Arrow transition must fire
            Check("E2.l hover resolves the cursor (no clickable hand; explicit inherits; Arrow masks ancestor I-beam; own surface; off→arrow)",
                hand && plainArrow && inherited && masked && ownSurface && offArrow,
                $"hand={hand} plain={plainArrow} inherit={inherited} mask={masked} own={ownSurface} off={offArrow}");
        }
    }

    // E5 — the drag-reorder gesture engine: BoxEl.CanDrag arms Input.DragController on press; pointer travel past the
    // 4px per-axis drag box (Win32 SM_CXDRAG/SM_CYDRAG defaults — microsoft-ui-xaml
    // dxaml\xcp\dxaml\lib\ListViewBaseItem_Partial.cpp:1864-1878 IsOutsideDragRectangle: dx > maxDx || dy > maxDy)
    // promotes the press to a drag: the node follows the pointer at WinUI ListViewItemDragThemeOpacity 0.80
    // (controls\dev\CommonStyles\ListViewItem_themeresources.xaml:7) with a flyout-class shadow, stops hit-testing,
    // and the eventual release SUPPRESSES the click (a finished WinUI drag never raises the item's click/Tapped).
    // ReorderList carries the live-reorder slot math: midpoint rule (GetDragOverIndex —
    // ListViewBase_Partial_Reorder.cpp:984-1063), the 200ms LISTVIEW_LIVEREORDER_TIMER dwell (:50) and the
    // part-to-make-room displacement (MoveItemsForLiveReorder :2125-2158).
    // Wave B input-semantics parity (WinUI ButtonBase/RepeatButton/NumberBox/TabView ground truth): pressed tracks the
    // held pointer, repeat pause/resume, focus-on-press + AllowFocusOnInteraction, middle-click release routing, the
    // element wheel hook, ActivateOnEnter opt-out, keyboard repeat arming, cancel delivery, touch hover, theme text
    // default, and the PersonPicture geometry contract.
    static void WaveBInputChecks(StringTable strings)
    {
        var fonts = new HeadlessFontSystem(strings);

        // B.1 — pressed visual tracks the pointer while held (ButtonBase_Partial.cpp:629-638): drag-off un-presses,
        // drag-back re-presses, and a release back over the node still clicks.
        {
            var scene = new SceneStore();
            int clicks = 0;
            new TreeReconciler(scene, strings).ReconcileRoot(
                new BoxEl { Width = 40, Height = 20, OnClick = () => clicks++ }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            var node = scene.Root;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, new Point2(10, 10), 0, 0) });
            bool pressed = (scene.Flags(node) & NodeFlags.Pressed) != 0;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(200, 100), 0, 0) });
            bool offCleared = (scene.Flags(node) & NodeFlags.Pressed) == 0;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(10, 10), 0, 0) });
            bool backPressed = (scene.Flags(node) & NodeFlags.Pressed) != 0;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, new Point2(10, 10), 0, 0) });
            bool clicked = clicks == 1 && (scene.Flags(node) & NodeFlags.Pressed) == 0;
            Check("B.1 pressed tracks the held pointer (off→clear, back→press, release-over→click)",
                pressed && offCleared && backPressed && clicked,
                $"down={pressed} off={offCleared} back={backPressed} click={clicked}");
        }

        // B.2 — repeat pause/resume hooks fire on drag-off/drag-back while held; ticker honors per-node Delay/Interval
        // with a FRESH delay (no immediate re-fire) on resume (RepeatButton_Partial.cpp:530-574).
        {
            var scene = new SceneStore();
            int clicks = 0;
            new TreeReconciler(scene, strings).ReconcileRoot(
                new BoxEl { Width = 40, Height = 20, Repeats = true, RepeatDelayMs = 80f, RepeatIntervalMs = 30f, OnClick = () => clicks++ }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var ticker = new FluentGpu.Animation.RepeatTicker(scene);
            var disp = new InputDispatcher(scene)
            {
                OnRepeatArmed = ticker.Arm, OnRepeatReleased = ticker.Disarm,
                OnRepeatPaused = ticker.Pause, OnRepeatResumed = ticker.Resume,
            };
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, new Point2(10, 10), 0, 0) });
            bool armFired = clicks == 1;                       // Arm fires once immediately (ClickMode.Press)
            ticker.Tick(100f);                                 // crosses the 80ms custom delay → second fire
            bool delayHonored = clicks == 2;
            ticker.Tick(60f);                                  // two 30ms intervals
            bool intervalHonored = clicks == 4;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(200, 100), 0, 0) });   // off → pause
            ticker.Tick(500f);
            bool pausedNoFire = clicks == 4 && !ticker.HasActive;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(10, 10), 0, 0) });     // back → resume
            bool resumedNoImmediate = clicks == 4 && ticker.HasActive;   // fresh delay, NO re-fire on re-entry
            ticker.Tick(79f);
            bool freshDelay = clicks == 4;                     // still inside the fresh 80ms delay
            ticker.Tick(2f);
            bool resumedFires = clicks == 5;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, new Point2(10, 10), 0, 0) });
            bool releaseStops = !ticker.HasActive && clicks == 5;   // release does NOT re-click a repeat node
            Check("B.2 repeat: per-node 80/30 cadence; drag-off pauses; re-entry resumes with a fresh delay",
                armFired && delayHonored && intervalHonored && pausedNoFire && resumedNoImmediate && freshDelay && resumedFires && releaseStops,
                $"arm={armFired} delay={delayHonored} interval={intervalHonored} pause={pausedNoFire} resume={resumedNoImmediate} fresh={freshDelay} fires={resumedFires} stop={releaseStops}");
        }

        // B.3 — pointer focus moves on the PRESS edge (ButtonBase_Partial.cpp:700-709); AllowFocusOnInteraction=false
        // blocks the move entirely while Tab still reaches the node (AppBarButton_themeresources.xaml:136).
        {
            var scene = new SceneStore();
            new TreeReconciler(scene, strings).ReconcileRoot(new BoxEl
            {
                Direction = 0, Gap = 10,
                Children =
                [
                    new BoxEl { Key = "a", Width = 20, Height = 20, OnClick = () => { } },
                    new BoxEl { Key = "b", Width = 20, Height = 20, OnClick = () => { }, AllowFocusOnInteraction = false },
                ],
            }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            var a = Child(scene, scene.Root, 0); var b = Child(scene, scene.Root, 1);
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, new Point2(10, 10), 0, 0) });
            bool focusOnPress = disp.Focused == a;             // BEFORE any release
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, new Point2(10, 10), 0, 0) });
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, new Point2(40, 10), 0, 0) });
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, new Point2(40, 10), 0, 0) });
            bool blocked = disp.Focused == a;                  // press on b never moved focus
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Tab) });
            bool tabReaches = disp.Focused == b;               // keyboard still reaches it
            Check("B.3 pointer focus on press; AllowFocusOnInteraction=false blocks pointer focus, Tab still works",
                focusOnPress && blocked && tabReaches, $"press={focusOnPress} blocked={blocked} tab={tabReaches}");
        }

        // B.4 — middle-button release over the press target delivers OnPointerPressed with Button=2 (the WinUI
        // TabViewItem middle-click-close commit, TabViewItem.cpp:418-462); release elsewhere delivers nothing.
        {
            var scene = new SceneStore();
            var seen = new List<byte>();
            new TreeReconciler(scene, strings).ReconcileRoot(
                new BoxEl { Width = 40, Height = 20, OnPointerPressed = e => seen.Add(e.Button) }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, new Point2(10, 10), 2, 0) });
            bool noneOnDown = seen.Count == 0;                 // middle never presses/activates on the down edge
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, new Point2(10, 10), 2, 0) });
            bool delivered = seen.Count == 1 && seen[0] == 2;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, new Point2(10, 10), 2, 0) });
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, new Point2(200, 100), 2, 0) });
            bool offDropped = seen.Count == 1;                 // release elsewhere → no delivery
            Check("B.4 middle-click: typed args Button=2 on release-over-same; nothing on down or off-release",
                noneOnDown && delivered && offDropped, $"down={noneOnDown} hit={delivered} off={offDropped}");
        }

        // B.5 — the element wheel hook sees the wheel BEFORE the viewport and consumes it when Handled
        // (NumberBox.cpp:578-597); an unhandled hook lets the dispatch fall through.
        {
            var scene = new SceneStore();
            float sawDelta = 0f; int calls = 0;
            new TreeReconciler(scene, strings).ReconcileRoot(
                new BoxEl { Width = 40, Height = 20, OnPointerWheel = e => { calls++; sawDelta = e.Delta; e.Handled = true; } }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            int handled = disp.Dispatch(new[] { new InputEvent(InputKind.Wheel, new Point2(10, 10), 0, 0, ScrollDelta: -48f) });
            Check("B.5 element wheel hook consumes the wheel (Handled) with the raw delta",
                handled == 1 && calls == 1 && sawDelta == -48f, $"handled={handled} calls={calls} delta={sawDelta}");
        }

        // B.6 — ActivateOnEnter=false (CheckBox/RadioButton/ToggleSwitch — KeyPress::Button bAcceptsReturn=false):
        // Enter does NOT activate (it routes to OnKeyDown instead); Space still activates on key-up.
        {
            var scene = new SceneStore();
            int clicks = 0, sawKey = 0;
            new TreeReconciler(scene, strings).ReconcileRoot(
                new BoxEl { Width = 40, Height = 20, ActivateOnEnter = false, OnClick = () => clicks++, OnKeyDown = a => sawKey = a.KeyCode }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            disp.MoveFocus(forward: true);
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Enter) });
            disp.Dispatch(new[] { new InputEvent(InputKind.KeyUp, default, 0, Keys.Enter) });
            bool enterRouted = clicks == 0 && sawKey == Keys.Enter;
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Space) });
            disp.Dispatch(new[] { new InputEvent(InputKind.KeyUp, default, 0, Keys.Space) });
            bool spaceClicks = clicks == 1;
            Check("B.6 ActivateOnEnter=false: Enter falls through to key routing; Space still toggles",
                enterRouted && spaceClicks, $"enter={enterRouted} (saw={sawKey}) space={spaceClicks}");
        }

        // B.7 — keyboard repeat: a held Space arms the engine repeat timer ONCE (no OS auto-repeat involvement);
        // Enter on a repeat node yields exactly one click on its down edge (RepeatButton_Partial.cpp:212-217, :29).
        {
            var scene = new SceneStore();
            int clicks = 0, armed = 0, released = 0;
            new TreeReconciler(scene, strings).ReconcileRoot(
                new BoxEl { Width = 40, Height = 20, Repeats = true, OnClick = () => clicks++ }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene) { OnRepeatArmed = _ => armed++, OnRepeatReleased = _ => released++ };
            disp.MoveFocus(forward: true);
            var node = disp.Focused;
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Space) });
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Space, IsRepeat: true) });
            bool armedOnce = armed == 1 && (scene.Flags(node) & NodeFlags.Pressed) != 0;   // OS repeat ignored
            disp.Dispatch(new[] { new InputEvent(InputKind.KeyUp, default, 0, Keys.Space) });
            bool releasedOnce = released == 1 && clicks == 0;   // ticker owns the clicks; key-up never re-fires
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Enter) });
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Enter, IsRepeat: true) });
            disp.Dispatch(new[] { new InputEvent(InputKind.KeyUp, default, 0, Keys.Enter) });
            bool enterOnce = clicks == 1 && armed == 1;         // Enter: ONE direct click, never arms the timer
            Check("B.7 keyboard repeat: Space arms the ticker once; Enter fires exactly one click on a repeat node",
                armedOnce && releasedOnce && enterOnce, $"armed={armedOnce} released={releasedOnce} enter={enterOnce}");
        }

        // B.8 — PointerCancel delivers OnPointerExit to the captured OnDrag target (capture-loss reset — the
        // RatingControl alt-tab mid-sweep case); touch lift clears hover (no resting touch hover).
        {
            var scene = new SceneStore();
            int exits = 0;
            new TreeReconciler(scene, strings).ReconcileRoot(
                new BoxEl { Width = 40, Height = 20, OnDrag = _ => { }, OnPointerExit = () => exits++ }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, new Point2(10, 10), 0, 0) });
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerCancel, default, 0, 0) });
            bool cancelExit = exits >= 1;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(10, 10), 0, 0, Pointer: PointerKind.Touch) });
            bool hovered = (scene.Flags(scene.Root) & NodeFlags.Hovered) != 0;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, new Point2(10, 10), 0, 0, Pointer: PointerKind.Touch) });
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, new Point2(10, 10), 0, 0, Pointer: PointerKind.Touch) });
            bool touchHoverCleared = (scene.Flags(scene.Root) & NodeFlags.Hovered) == 0;
            Check("B.8 cancel delivers exit to the captured drag target; touch lift clears hover",
                cancelExit && hovered && touchHoverCleared, $"exit={cancelExit} hover={hovered} lifted={touchHoverCleared}");
        }

        // B.9 — TextEl's default Color is the BOUND semantic brush (one shared singleton thunk, so text retained inside
        // stateful controls follows a live re-theme instead of freezing a construction-resolved value, and the recycle
        // path can identity-match it). The thunk resolves the LIVE theme's TextFillColorPrimary: dark #FFFFFF stays
        // WinUI-faithful; light is Wavee's warm off-black #1F1E1B (the light-mode warm-ramp retint), NOT WinUI's
        // #E4000000. Guards against both a hardcoded revert AND a per-element (non-singleton) thunk.
        {
            var a = new TextEl("x").Color;
            var b = new TextEl("y").Color;
            bool singleton = a.IsBound && b.IsBound && a.Thunk is not null && ReferenceEquals(a.Thunk, b.Thunk);
            bool dark = a.Thunk!() == Tok.TextPrimary && a.Thunk() == ColorF.FromRgba(0xFF, 0xFF, 0xFF);
            Tok.Use(ThemeKind.Light);
            bool light = a.Thunk() == Tok.TextPrimary && a.Thunk() == ColorF.FromRgba(0x1F, 0x1E, 0x1B);
            Tok.Use(ThemeKind.Dark);
            Check("B.9 TextEl default color = the bound singleton theme brush resolving TextFillColorPrimary (dark #FFFFFF / light #1F1E1B warm off-black)",
                singleton && dark && light, $"singleton={singleton} dark={dark} light={light}");
        }

        // B.9b — theme-derived CONTROL defaults and a bound border remain live after mount. The same EditableText
        // instance keeps its document/focus lifetime while its typed-text brush changes; the shell-card border bind
        // follows the same RethemeAll pass. TitleBar/DropZone/TabStrip defaults use live semantic fallbacks too.
        {
            ThemeKind saved = Tok.Theme;
            try
            {
                Tok.Use(ThemeKind.Dark);
                using var app = new HeadlessPlatformApp();
                var window = new HeadlessWindow(new WindowDesc("theme-defaults", new Size2(320, 120), 1f));
                window.Show();
                var probe = new LiveThemeDefaultsProbe();
                using var host = new AppHost(app, window, new HeadlessGpuDevice(), fonts, strings, probe);
                host.RunFrame();

                NodeHandle FindBorder(NodeHandle n)
                {
                    if (host.Scene.Paint(n).BorderWidth > 0f) return n;
                    for (var c = host.Scene.FirstChild(n); !c.IsNull; c = host.Scene.NextSibling(c))
                    {
                        var hit = FindBorder(c);
                        if (!hit.IsNull) return hit;
                    }
                    return NodeHandle.Null;
                }

                var textNode = FindTextNode(host.Scene, strings, host.Scene.Root, "typed");
                var borderNode = FindBorder(host.Scene.Root);
                ColorF darkText = host.Scene.Paint(textNode).TextColor;
                ColorF darkBorder = host.Scene.Paint(borderNode).BorderColor;
                var title = new TitleBar();
                var drop = new DropZone();
                var tabs = new TabStrip();
                var marquee = Marquee.Default;
                ColorF darkTitle = title.IconColor;
                ColorF darkDrop = drop.Accent;
                ColorF darkTab = tabs.SelectedFill.Thunk!();
                ColorF darkMarquee = marquee.Foreground.Thunk!();

                Tok.Use(ThemeKind.Light);
                host.Reconciler.RethemeAll();
                host.RunFrame();

                var textAfter = FindTextNode(host.Scene, strings, host.Scene.Root, "typed");
                var borderAfter = FindBorder(host.Scene.Root);
                bool retained = probe.FieldConstructions == 1 && textAfter == textNode && borderAfter == borderNode;
                bool textLive = darkText != Tok.TextPrimary && host.Scene.Paint(textAfter).TextColor == Tok.TextPrimary;
                bool borderLive = darkBorder != Tok.StrokeCardDefault && host.Scene.Paint(borderAfter).BorderColor == Tok.StrokeCardDefault;
                bool defaultsLive = darkTitle != title.IconColor && title.IconColor == Tok.AccentDefault
                                 && darkDrop != drop.Accent && drop.Accent == Tok.AccentDefault
                                 && darkTab != tabs.SelectedFill.Thunk!() && tabs.SelectedFill.Thunk!() == Tok.FillSolidTertiary
                                 && darkMarquee != marquee.Foreground.Thunk!() && marquee.Foreground.Thunk!() == Tok.TextPrimary;
                Check("B.9b retained control defaults + bound border follow RethemeAll in place (no EditableText remount)",
                    retained && textLive && borderLive && defaultsLive,
                    $"retained={retained} text={textLive} border={borderLive} defaults={defaultsLive} builds={probe.FieldConstructions}");
            }
            finally { Tok.Use(saved); }
        }

        // B.10 — PersonPicture geometry contract: initials centered in the circle; the badge plate hangs 4px outside
        // the top-right (root UNclipped, left = size+4−plate, top = −4); a negative badge number shows NO badge.
        {
            var scene = new SceneStore();
            new TreeReconciler(scene, strings).ReconcileRoot(PersonPicture.Create("JD", 96f, badgeNumber: 5), null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var root = scene.Root;
            bool unclipped = (scene.Flags(root) & NodeFlags.ClipsToBounds) == 0;
            var face = Child(scene, root, 0);
            var text = Child(scene, face, 0);
            var rootR = scene.AbsoluteRect(root);
            var textR = scene.AbsoluteRect(text);
            bool centered = MathF.Abs((textR.X + textR.W / 2f) - (rootR.X + 48f)) <= 1f
                         && MathF.Abs((textR.Y + textR.H / 2f) - (rootR.Y + 48f)) <= 1f;
            var badge = Child(scene, root, 1);
            var badgeR = scene.AbsoluteRect(badge);
            bool badgePos = MathF.Abs(badgeR.X - rootR.X - 52f) <= 0.5f && MathF.Abs(badgeR.Y - rootR.Y + 4f) <= 0.5f
                         && MathF.Abs(badgeR.W - 48f) <= 0.5f;

            var scene2 = new SceneStore();
            new TreeReconciler(scene2, strings).ReconcileRoot(PersonPicture.Create("JD", 96f, badgeNumber: -3, badgeGlyph: ""), null);
            bool negativeNoBadge = Child(scene2, scene2.Root, 1).IsNull;   // number<0 owns the slot → NO badge, glyph ignored
            Check("B.10 PersonPicture: centered initials; badge at (52,−4) 48px on an unclipped root; negative number = no badge",
                unclipped && centered && badgePos && negativeNoBadge,
                $"unclipped={unclipped} centered={centered} badge={badgePos} negNone={negativeNoBadge}");
        }

        // B.11 — the TabView "+" appends through the REAL click path (the WinUI Gallery AddButtonClick handler,
        // TabViewPage.xaml.cs:51-54): a click on the captured add button runs OnAddTabButtonClick and the returned
        // TabViewItem joins the strip (one more AutomationRole.Tab plate). Guards the gallery wiring fix end-to-end —
        // a null handler stays a no-op (the correct WinUI contract), a wired handler appends.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("tabadd", new Size2(640, 240), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            int adds = 0;
            var root = new W0fStaticProbe
            {
                Build = () => new BoxEl
                {
                    Direction = 1, Grow = 1f,
                    Children =
                    [
                        TabView.Create(
                            new[] { "Document 1", "Document 2" },
                            onAddTabButtonClick: () => { adds++; return new TabViewItem { Header = "Document " + (adds + 2), Icon = Icons.Document }; }),
                    ],
                },
            };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var s = host.Scene;

            // The add button is the right-most AutomationRole.Button in the strip (tabs + their close buttons sit to
            // its left; the trailing Grow spacer pushes nothing focusable past it).
            NodeHandle AddButton()
            {
                var buttons = Roles(s, AutomationRole.Button);
                var pick = NodeHandle.Null; float maxX = float.NegativeInfinity;
                foreach (var b in buttons)
                {
                    float cx = CenterOf(s, b).X;
                    if (cx > maxX) { maxX = cx; pick = b; }
                }
                return pick;
            }

            int tabsBefore = Roles(s, AutomationRole.Tab).Count;
            var add = AddButton();
            bool foundAdd = !add.IsNull;
            ClickNode(host, window, add);
            int tabsAfterOne = Roles(s, AutomationRole.Tab).Count;
            ClickNode(host, window, AddButton());   // re-find: the strip rebuilt with the new tab
            int tabsAfterTwo = Roles(s, AutomationRole.Tab).Count;
            bool appended = tabsBefore == 2 && tabsAfterOne == 3 && tabsAfterTwo == 4 && adds == 2;
            Check("B.11 TabView '+' appends a tab through the live click path (Gallery AddButtonClick wiring)",
                foundAdd && appended,
                $"found={foundAdd} before={tabsBefore} after1={tabsAfterOne} after2={tabsAfterTwo} adds={adds}");
        }
    }

    static void E5DragDropChecks(StringTable strings)
    {
        var fonts = new HeadlessFontSystem(strings);

        // e5dragdrop.1 — a press that never leaves the 4px per-axis drag box stays a plain click: release fires
        // OnClick, no drag lifecycle event fires, and the node's transform is untouched. +4/+4 sits ON the box edge —
        // WinUI promotes only strictly OUTSIDE it (dx > maxDx || dy > maxDy, ListViewBaseItem_Partial.cpp:1877).
        {
            var scene = new SceneStore();
            int clicks = 0, started = 0, deltas = 0, completed = 0, canceled = 0;
            new TreeReconciler(scene, strings).ReconcileRoot(new BoxEl
            {
                Width = 200, Height = 60, CanDrag = true,
                OnClick = () => clicks++,
                OnDragStarted = _ => started++,
                OnDragDelta = _ => deltas++,
                OnDragCompleted = _ => completed++,
                OnDragCanceled = () => canceled++,
            }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            var node = scene.Root;

            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, new Point2(100, 30), 0, 0) });
            bool armed = disp.Drag.IsArmed && !disp.Drag.IsActive;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(104, 34), 0, 0) });
            bool stillArmed = disp.Drag.IsArmed && !disp.Drag.IsActive && started == 0;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, new Point2(104, 34), 0, 0) });
            bool clicked = clicks == 1 && started == 0 && deltas == 0 && completed == 0 && canceled == 0;
            bool untouched = scene.Paint(node).LocalTransform.Dx == 0f && !disp.Drag.IsArmed && !disp.Drag.IsActive;
            Check("e5dragdrop.1 press inside the 4px per-axis drag box stays a click (no drag lifecycle)",
                armed && stillArmed && clicked && untouched,
                $"armed={armed} stillArmed={stillArmed} clicks={clicks} started={started}");
        }

        // e5dragdrop.ext — the OS file-drop seam matches the hand-vtable IDropTarget backend: HOVER is DATA-FREE
        // (ExternalDragEnter is given EMPTY paths, so the session payload is an empty FileDropData while hovering — the
        // backend reads no file data during DragEnter/Over), Enter/Over report Copy + flip OnEnter/OnLeave, and the
        // PATH-BEARING ExternalDropFiles fills the payload at drop so OnDrop sees the real FileDropData. Off-target
        // reports None + fires OnLeave.
        {
            var scene = new SceneStore();
            string[]? dropped = null; int enters = 0, leaves = 0, hoverPayloadCount = -1;
            new TreeReconciler(scene, strings).ReconcileRoot(new BoxEl
            {
                Width = 200, Height = 200, Fill = ColorF.FromRgba(20, 20, 20),
                DropTarget = new DropTargetSpec(
                    new[] { DropKinds.Files },
                    OnEnter: s => { enters++; if (s.Payload is FileDropData d) hoverPayloadCount = d.Count; },
                    OnLeave: _ => leaves++,
                    OnDrop: s => { if (s.Payload is FileDropData d) dropped = d.Paths; }),
            }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);

            var paths = new[] { @"C:\music\track.flac", @"C:\music\album" };
            var inside = new Point2(100, 100);
            var outside = new Point2(400, 400);   // off the 200×200 target

            var eff1 = disp.ExternalDragEnter(inside, System.Array.Empty<string>(), KeyModifiers.None);   // DATA-FREE hover
            var eff2 = disp.ExternalDragOver(inside, KeyModifiers.None);
            bool dropOk = disp.ExternalDropFiles(inside, paths, KeyModifiers.None);                        // paths arrive at DROP
            bool acceptOk = eff1 == DropEffect.Copy && eff2 == DropEffect.Copy && dropOk
                            && enters == 1 && hoverPayloadCount == 0   // hover saw an EMPTY payload (data-free)
                            && dropped is { Length: 2 } && dropped[0] == paths[0] && dropped[1] == paths[1];

            // off-target: a fresh enter inside, then a move OUTSIDE the target reports None and fires OnLeave; no drop.
            var eff3 = disp.ExternalDragEnter(inside, System.Array.Empty<string>(), KeyModifiers.None);
            var eff4 = disp.ExternalDragOver(outside, KeyModifiers.None);
            disp.ExternalDragLeave();
            bool leaveOk = eff3 == DropEffect.Copy && eff4 == DropEffect.None && leaves == 1;

            Check("e5dragdrop.ext an OS file drop (IDropTarget seam) hovers DATA-FREE (empty payload, Enter/Over=Copy) then ExternalDropFiles delivers the real FileDropData to a DropTarget accepting DropKinds.Files; off-target reports None + fires OnLeave",
                acceptOk && leaveOk,
                $"enter={eff1} over={eff2} drop={dropOk} hoverCount={hoverPayloadCount} paths={(dropped is null ? "null" : string.Join("|", dropped))} off(eff={eff4},leaves={leaves})");
        }

        // e5dragdrop.style — DragSource.Style overrides the lifted ghost's opacity (the default 0.80 → a custom value).
        // A drag promotes on a Draggable carrying Style{Opacity=0.5}; after promotion the node's painted opacity is 0.5.
        {
            var scene = new SceneStore();
            new TreeReconciler(scene, strings).ReconcileRoot(new BoxEl
            {
                Width = 200, Height = 60, CanDrag = true,
                Draggable = new DragSource("chip", () => "p") { Style = new DragVisualStyle { Opacity = 0.5f } },
            }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            var node = scene.Root;

            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, new Point2(100, 30), 0, 0) });
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(140, 30), 0, 0) });   // cross the box → promote
            float ghostOpacity = scene.Paint(node).Opacity;
            bool styledGhost = disp.Drag.IsActive && System.MathF.Abs(ghostOpacity - 0.5f) < 0.001f;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, new Point2(140, 30), 0, 0) });

            Check("e5dragdrop.style DragSource.Style.Opacity overrides the lifted ghost opacity (default 0.80 → 0.50)",
                styledGhost, $"active={disp.Drag.IsActive} ghostOpacity={ghostOpacity:0.00}");
        }

        // e5dragdrop.2/.2b — crossing the drag box on a press that began on a CHILD of the CanDrag row promotes the
        // ROW (TryArm walks up like WinUI's item container): OnDragStarted fires once BEFORE the first OnDragDelta,
        // the transient pressed visuals are cleared, and the row carries the drag visuals — opacity 0.80
        // (ListViewItemDragThemeOpacity — ListViewItem_themeresources.xaml:7), the flyout-class shadow, hit-test off,
        // and a parent-space translate equal to the gesture delta. Release restores everything, fires DragCompleted,
        // SUPPRESSES the click, and hands OnSettle the (drop → resting) rects for the FLIP glide.
        {
            var scene = new SceneStore();
            int rowClicks = 0, childClicks = 0, started = 0, deltas = 0, completed = 0;
            int firstEvent = 0;                       // 1 = started first, 2 = delta first — order proof
            float doneDx = 0f, doneDy = 0f;
            NodeHandle settleNode = default; RectF settleFrom = default, settleTo = default; int settles = 0;
            new TreeReconciler(scene, strings).ReconcileRoot(new BoxEl
            {
                Width = 240, Height = 120,
                Children =
                [
                    new BoxEl
                    {
                        Key = "row", Width = 200, Height = 60, CanDrag = true,
                        OnClick = () => rowClicks++,
                        OnDragStarted = _ => { started++; if (firstEvent == 0) firstEvent = 1; },
                        OnDragDelta = _ => { deltas++; if (firstEvent == 0) firstEvent = 2; },
                        OnDragCompleted = e => { completed++; doneDx = e.TotalDx; doneDy = e.TotalDy; },
                        Children = [new BoxEl { Key = "child", Width = 80, Height = 30, OnClick = () => childClicks++ }],
                    },
                ],
            }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            disp.Drag.OnSettle = (n, from, to) => { settles++; settleNode = n; settleFrom = from; settleTo = to; };
            var row = Child(scene, scene.Root, 0);
            var child = Child(scene, row, 0);

            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, new Point2(40, 15), 0, 0) });
            bool pressedChild = (scene.Flags(child) & NodeFlags.Pressed) != 0 && disp.Drag.IsArmed;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(50, 15), 0, 0) });   // dx 10 > 4 → promote
            bool promoted = started == 1 && deltas == 1 && firstEvent == 1
                && disp.Drag.IsActive && disp.Drag.ActiveNode == row
                && (scene.Flags(child) & NodeFlags.Pressed) == 0;                  // pressed visuals cleared on promotion
            bool visuals = Near(scene.Paint(row).Opacity, 0.80f)                   // ListViewItemDragThemeOpacity
                && scene.TryGetShadow(row, out var sh) && sh == DragController.DragShadow
                && (scene.Flags(row) & NodeFlags.HitTestVisible) == 0              // drop-targets see THROUGH the visual
                && Near(scene.Paint(row).LocalTransform.Dx, 10f) && Near(scene.Paint(row).LocalTransform.Dy, 0f);
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(70, 40), 0, 0) });
            bool follows = deltas == 2
                && Near(scene.Paint(row).LocalTransform.Dx, 30f) && Near(scene.Paint(row).LocalTransform.Dy, 25f);
            Check("e5dragdrop.2 over-threshold promotes the CanDrag row (child press arms it): Started→Delta, pressed cleared, drag visuals on",
                pressedChild && promoted && visuals && follows,
                $"pressed={pressedChild} promoted={promoted} visuals={visuals} follows={follows}");

            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, new Point2(70, 40), 0, 0) });
            bool suppressed = rowClicks == 0 && childClicks == 0;                  // WinUI: a finished drag never clicks
            bool restored = Near(scene.Paint(row).Opacity, 1f) && !scene.TryGetShadow(row, out _)
                && (scene.Flags(row) & NodeFlags.HitTestVisible) != 0
                && scene.Paint(row).LocalTransform.Dx == 0f && scene.Paint(row).LocalTransform.Dy == 0f
                && !disp.Drag.IsActive && disp.Drag.ActiveNode.IsNull;
            bool settled = completed == 1 && Near(doneDx, 30f) && Near(doneDy, 25f)
                && settles == 1 && settleNode == row
                && Near(settleFrom.X - settleTo.X, 30f) && Near(settleFrom.Y - settleTo.Y, 25f);
            Check("e5dragdrop.2b release after a drag suppresses the click, restores resting visuals, and hands OnSettle the drop→resting rects",
                suppressed && restored && settled,
                $"suppressed={suppressed} restored={restored} completed={completed} settles={settles} dxdy=({doneDx:0.#},{doneDy:0.#})");
        }

        // e5dragdrop.3 — DragEventArgs: Total deltas measured from the arming press, Absolute = the raw pointer,
        // Local ≈ the grab offset on the MOVING box, and the ~50ms-EMA pointer velocity driven by PLATFORM timestamps
        // (alpha = dt/(dt+50): 10px/16ms moves → 625 px/s instantaneous → 151.5 then 266.3 px/s smoothed). A gesture
        // whose events carry TimestampMs == 0 (the headless default) leaves the velocity at 0.
        {
            var scene = new SceneStore();
            float vx = float.NaN, vy = float.NaN, dx = float.NaN, dy = float.NaN;
            Point2 local = default, abs = default;
            new TreeReconciler(scene, strings).ReconcileRoot(new BoxEl
            {
                Width = 200, Height = 100, CanDrag = true,
                OnDragDelta = e => { vx = e.VelocityX; vy = e.VelocityY; dx = e.TotalDx; dy = e.TotalDy; local = e.Local; abs = e.Absolute; },
            }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);

            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, new Point2(50, 50), 0, 0, 0f, KeyModifiers.None, PointerKind.Mouse, false, 1_000) });
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(60, 50), 0, 0, 0f, KeyModifiers.None, PointerKind.Mouse, false, 1_016) });
            bool firstMove = Near(dx, 10f) && Near(vx, 151.5f, 0.5f) && vy == 0f;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(70, 50), 0, 0, 0f, KeyModifiers.None, PointerKind.Mouse, false, 1_032) });
            bool secondMove = Near(dx, 20f) && Near(dy, 0f) && Near(vx, 266.3f, 0.5f)
                && Near(abs.X, 70f) && Near(abs.Y, 50f)
                && Near(local.X, 50f) && Near(local.Y, 50f);   // grab offset: Local tracks the MOVING box
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, new Point2(70, 50), 0, 0, 0f, KeyModifiers.None, PointerKind.Mouse, false, 1_048) });

            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, new Point2(50, 50), 0, 0) });
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(80, 50), 0, 0) });
            bool zeroStamp = Near(dx, 30f) && vx == 0f && vy == 0f;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, new Point2(80, 50), 0, 0) });
            Check("e5dragdrop.3 DragEventArgs coords + ~50ms-EMA velocity from platform timestamps (0-stamps leave velocity 0)",
                firstMove && secondMove && zeroStamp, $"first={firstMove} second={secondMove} zero={zeroStamp} vx={vx:0.#}");
        }

        // e5dragdrop.4 — cancel paths: Escape mid-drag (the most-modal gesture — WinUI drag cancel routes before any
        // other key handling) and window deactivation both abort the drag: resting visuals restore, OnDragCanceled
        // fires (never OnDragCompleted), OnSettle glides the visual home, and the still-down pointer's eventual
        // release does NOT click (a canceled drag never raises a click or a drop).
        {
            var scene = new SceneStore();
            int clicks = 0, canceled = 0, completed = 0, settles = 0;
            new TreeReconciler(scene, strings).ReconcileRoot(new BoxEl
            {
                Width = 200, Height = 60, CanDrag = true,
                OnClick = () => clicks++,
                OnDragCompleted = _ => completed++,
                OnDragCanceled = () => canceled++,
            }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            var node = scene.Root;
            disp.Drag.OnSettle = (_, _, _) => settles++;

            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, new Point2(50, 30), 0, 0) });
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(70, 30), 0, 0) });
            bool active1 = disp.Drag.IsActive && Near(scene.Paint(node).LocalTransform.Dx, 20f);
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Escape) });
            bool escCancel = canceled == 1 && completed == 0 && settles == 1 && !disp.Drag.IsActive
                && scene.Paint(node).LocalTransform.Dx == 0f && Near(scene.Paint(node).Opacity, 1f)
                && !scene.TryGetShadow(node, out _) && (scene.Flags(node) & NodeFlags.HitTestVisible) != 0;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, new Point2(70, 30), 0, 0) });
            bool noClick1 = clicks == 0;

            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, new Point2(50, 30), 0, 0) });
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(75, 30), 0, 0) });
            bool active2 = disp.Drag.IsActive;
            disp.Dispatch(new[] { new InputEvent(InputKind.WindowBlur, default, 0, 0) });
            bool blurCancel = canceled == 2 && settles == 2 && !disp.Drag.IsActive
                && scene.Paint(node).LocalTransform.Dx == 0f && Near(scene.Paint(node).Opacity, 1f);
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, new Point2(75, 30), 0, 0) });
            bool noClick2 = clicks == 0 && completed == 0;
            Check("e5dragdrop.4 Escape / window-blur cancel the drag: visuals restore, DragCanceled fires, release does not click",
                active1 && escCancel && noClick1 && active2 && blurCancel && noClick2,
                $"esc={escCancel} blur={blurCancel} clicks={clicks} canceled={canceled} settles={settles}");
        }

        // e5dragdrop.5 — arena-lite (promotion-time arbitration, DragController.YieldsToPan): the item's reorder axis
        // is its PARENT container's main axis; a dominant-axis gesture PERPENDICULAR to it yields to a scrollable
        // ancestor that actually overflows along the gesture axis (the WinUI manipulation-arena outcome for a tab
        // strip inside a scrolling page) — the candidate silently disarms, no DragStarted. Along-axis gestures and
        // no-overflow scrollables never yield.
        {
            // a) horizontal strip (row ⇒ items drag horizontally) inside a vertically OVERFLOWING scroll viewport.
            var sceneA = new SceneStore();
            int startedA = 0;
            new TreeReconciler(sceneA, strings).ReconcileRoot(new ScrollEl
            {
                Width = 200, Height = 100,
                Content = new BoxEl
                {
                    Direction = 1,
                    Children =
                    [
                        new BoxEl
                        {
                            Direction = 0,
                            Children =
                            [
                                new BoxEl { Key = "a", Width = 60, Height = 40, CanDrag = true, OnDragStarted = _ => startedA++ },
                                new BoxEl { Key = "b", Width = 60, Height = 40, CanDrag = true, OnDragStarted = _ => startedA++ },
                                new BoxEl { Key = "c", Width = 60, Height = 40, CanDrag = true, OnDragStarted = _ => startedA++ },
                            ],
                        },
                        new BoxEl { Key = "filler", Width = 10, Height = 300 },
                    ],
                },
            }, null);
            new FlexLayout(sceneA, fonts).Run(sceneA.Root);
            var dispA = new InputDispatcher(sceneA);
            sceneA.TryGetScroll(sceneA.Root, out var scA);
            bool overflows = scA.ContentH - scA.ViewportH > 0.5f;   // 340 content over a 100 viewport

            dispA.Dispatch(new[] { new InputEvent(InputKind.PointerDown, new Point2(30, 20), 0, 0) });
            bool armedA = dispA.Drag.IsArmed;
            dispA.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(30, 60), 0, 0) });   // dy 40 ⊥ the row axis
            bool yielded = startedA == 0 && !dispA.Drag.IsActive && !dispA.Drag.IsArmed;                 // the pan owns it
            dispA.Dispatch(new[] { new InputEvent(InputKind.PointerUp, new Point2(30, 60), 0, 0) });

            dispA.Dispatch(new[] { new InputEvent(InputKind.PointerDown, new Point2(30, 20), 0, 0) });
            dispA.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(80, 20), 0, 0) });   // dx 50 along the row axis
            bool alongDrags = startedA == 1 && dispA.Drag.IsActive;
            dispA.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Escape) });

            // b) the same strip in a NON-overflowing viewport: the vertical gesture has no pan to yield to → it drags.
            var sceneB = new SceneStore();
            int startedB = 0;
            new TreeReconciler(sceneB, strings).ReconcileRoot(new ScrollEl
            {
                Width = 200, Height = 100,
                Content = new BoxEl
                {
                    Direction = 0,
                    Children =
                    [
                        new BoxEl { Key = "a", Width = 60, Height = 40, CanDrag = true, OnDragStarted = _ => startedB++ },
                        new BoxEl { Key = "b", Width = 60, Height = 40, CanDrag = true, OnDragStarted = _ => startedB++ },
                    ],
                },
            }, null);
            new FlexLayout(sceneB, fonts).Run(sceneB.Root);
            var dispB = new InputDispatcher(sceneB);
            dispB.Dispatch(new[] { new InputEvent(InputKind.PointerDown, new Point2(30, 20), 0, 0) });
            dispB.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(30, 60), 0, 0) });
            bool noOverflowDrags = startedB == 1 && dispB.Drag.IsActive;
            dispB.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Escape) });

            // c) a vertical (column) list inside the overflowing vertical viewport: the vertical gesture runs ALONG
            //    the item's own reorder axis → the drag wins even over a real pan candidate.
            var sceneC = new SceneStore();
            int startedC = 0;
            new TreeReconciler(sceneC, strings).ReconcileRoot(new ScrollEl
            {
                Width = 200, Height = 100,
                Content = new BoxEl
                {
                    Direction = 1,
                    Children =
                    [
                        new BoxEl { Key = "a", Width = 160, Height = 60, CanDrag = true, OnDragStarted = _ => startedC++ },
                        new BoxEl { Key = "b", Width = 160, Height = 60, CanDrag = true, OnDragStarted = _ => startedC++ },
                        new BoxEl { Key = "c", Width = 160, Height = 60, CanDrag = true, OnDragStarted = _ => startedC++ },
                    ],
                },
            }, null);
            new FlexLayout(sceneC, fonts).Run(sceneC.Root);
            var dispC = new InputDispatcher(sceneC);
            sceneC.TryGetScroll(sceneC.Root, out var scC);
            bool overflowsC = scC.ContentH - scC.ViewportH > 0.5f;   // 180 content over a 100 viewport
            dispC.Dispatch(new[] { new InputEvent(InputKind.PointerDown, new Point2(80, 30), 0, 0) });
            dispC.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(80, 70), 0, 0) });
            bool axisDrags = startedC == 1 && dispC.Drag.IsActive;
            dispC.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Escape) });

            Check("e5dragdrop.5 arena-lite: cross-axis gesture over an overflowing scrollable yields to the pan; along-axis and no-overflow gestures drag",
                overflows && armedA && yielded && alongDrags && noOverflowDrags && overflowsC && axisDrags,
                $"overflow={overflows} yielded={yielded} along={alongDrags} noOverflow={noOverflowDrags} axis={axisDrags}");
        }

        // e5dragdrop.6 — ReorderList midpoint slot math: the dragged item's centre crossing a sibling's midpoint
        // claims its slot (GetDragOverIndex — ListViewBase_Partial_Reorder.cpp:984-1063); the SHOWN target waits on
        // the 200ms live-reorder dwell that re-arms on every pending change (LISTVIEW_LIVEREORDER_TIMER :50, restart
        // :1068-1074); displaced items shift one dragged-extent (+spacing) toward the vacated slot.
        {
            var rl = new ReorderList();
            bool defaults = rl.DwellMs == ReorderList.ListDwellMs && ReorderList.ListDwellMs == 200f && ReorderList.GridDwellMs == 300f;
            rl.Begin(1, 5, itemExtent: 40f, spacing: 8f);     // starts 0,48,96,144,192; dragged centre 68
            bool init = rl.IsActive && rl.DraggedIndex == 1 && rl.PendingIndex == 1 && rl.TargetIndex == 1;
            bool stay = !rl.Update(47f) && rl.PendingIndex == 1;                       // 115 < sibling-2 mid 116
            bool cross = rl.Update(49f) && rl.PendingIndex == 2 && rl.TargetIndex == 1;   // 117 > 116; dwell pending
            bool dwellHeld = !rl.Advance(199f) && rl.TargetIndex == 1;
            bool dwellFire = rl.Advance(1f) && rl.TargetIndex == 2;
            bool hints = Near(rl.OffsetFor(2), -48f) && rl.OffsetFor(0) == 0f && rl.OffsetFor(1) == 0f
                && rl.OffsetFor(3) == 0f && rl.OffsetFor(4) == 0f;
            Span<int> order = stackalloc int[5];
            rl.ProjectOrder(order);
            bool proj = order[0] == 0 && order[1] == 2 && order[2] == 1 && order[3] == 3 && order[4] == 4;
            bool tgtStart = Near(rl.DraggedTargetStart, 96f);

            bool flip = rl.Update(-100f) && rl.PendingIndex == 0 && rl.TargetIndex == 2;   // centre −32 < sibling-0 mid 20
            bool reArm = !rl.Advance(199f) && rl.Advance(1f) && rl.TargetIndex == 0;       // the dwell re-armed in full
            bool upHints = Near(rl.OffsetFor(0), 48f) && rl.OffsetFor(2) == 0f;
            rl.ProjectOrder(order);
            bool upProj = order[0] == 1 && order[1] == 0 && order[2] == 2 && Near(rl.DraggedTargetStart, 0f);
            Check("e5dragdrop.6 ReorderList midpoint slot math + 200ms dwell-committed target + displacement hints + ProjectOrder",
                defaults && init && stay && cross && dwellHeld && dwellFire && hints && proj && tgtStart && flip && reArm && upHints && upProj,
                $"init={init} stay={stay} cross={cross} dwell={dwellHeld}/{dwellFire} hints={hints} proj={proj} flip={flip} reArm={reArm}");
        }

        // e5dragdrop.7 — drop commit: Complete() lands at the LATEST pending slot (the release point never waits for
        // the dwell), resets all hints BEFORE firing OnCommit (from,to in ORIGINAL indices), and ReorderList.Move
        // applies exactly WinUI's RemoveAt(from)+Insert(to) drop (ListViewBase::ReorderItemsTo —
        // ListViewBase_Partial_Reorder.cpp:1536-1537). Cancel drops the hints without committing. Variable extents
        // honor per-item midpoints; DwellMs = 0 commits the shown target on the next Advance.
        {
            var rl = new ReorderList { DwellMs = 0f };
            rl.Begin(0, new[] { 30f, 50f, 20f }, spacing: 4f);    // starts 0,34,88; dragged centre 15
            bool varStay = !rl.Update(40f);                       // 55 < sibling-1 mid 59
            bool varCross = rl.Update(45f) && rl.PendingIndex == 1;   // 60 > 59
            bool zeroDwell = rl.Advance(0f) && rl.TargetIndex == 1 && Near(rl.OffsetFor(1), -34f);
            rl.Cancel();
            bool dropped = !rl.IsActive && rl.OffsetFor(1) == 0f && rl.PendingIndex == -1;

            int commitFrom = -1, commitTo = -1; bool hintsClearedAtCommit = false;
            var rl2 = new ReorderList();
            rl2.OnCommit = (from, to) => { commitFrom = from; commitTo = to; hintsClearedAtCommit = rl2.TargetIndex == -1 && rl2.OffsetFor(1) == 0f; };
            rl2.Begin(0, 4, itemExtent: 40f);                     // starts 0,40,80,120; dragged centre 20
            rl2.Update(85f);                                      // 105 > mid-1 60 and > mid-2 100 → pending 2 (no Advance)
            int dest = rl2.Complete();
            bool commit = dest == 2 && commitFrom == 0 && commitTo == 2 && hintsClearedAtCommit && !rl2.IsActive;

            var list = new List<char> { 'a', 'b', 'c', 'd' };
            ReorderList.Move(list, 0, 2);
            bool moved = list[0] == 'b' && list[1] == 'c' && list[2] == 'a' && list[3] == 'd';
            ReorderList.Move(list, 0, 9);                         // out of range → ignored
            ReorderList.Move(list, 2, 2);                         // no-op
            bool guarded = list[0] == 'b' && list[1] == 'c' && list[2] == 'a' && list[3] == 'd';
            Check("e5dragdrop.7 Complete commits at the latest pending slot (hints reset before OnCommit); Move applies RemoveAt+Insert; Cancel drops",
                varStay && varCross && zeroDwell && dropped && commit && moved && guarded,
                $"varCross={varCross} zeroDwell={zeroDwell} dropped={dropped} dest={dest} commit=({commitFrom}->{commitTo}) moved={moved}");
        }

        // e5dragdrop.7b — the full pipeline: CanDrag rows wired to ReorderList through the drag lifecycle (Begin in
        // OnDragStarted, Update(e.TotalDy) in OnDragDelta, Complete in OnDragCompleted); dragging row 0 past row 1's
        // midpoint and releasing commits the collection move 0→1 via OnCommit + ReorderList.Move.
        {
            var scene = new SceneStore();
            var items = new List<int> { 0, 1, 2 };
            var rl = new ReorderList();
            rl.OnCommit = (from, to) => ReorderList.Move(items, from, to);
            var children = new Element[3];
            for (int i = 0; i < 3; i++)
            {
                int idx = i;
                children[i] = new BoxEl
                {
                    Key = "row" + i, Width = 120, Height = 40, CanDrag = true,
                    OnDragStarted = _ => rl.Begin(idx, 3, itemExtent: 40f),
                    OnDragDelta = e => rl.Update(e.TotalDy),
                    OnDragCompleted = _ => rl.Complete(),
                    OnDragCanceled = rl.Cancel,
                };
            }
            new TreeReconciler(scene, strings).ReconcileRoot(new BoxEl { Direction = 1, Children = children }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);

            disp.Dispatch(new[] { new InputEvent(InputKind.PointerDown, new Point2(60, 20), 0, 0) });
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(60, 40), 0, 0) });   // promote; centre 40 < mid-1 60
            bool pendingHome = rl.IsActive && rl.DraggedIndex == 0 && rl.PendingIndex == 0;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerMove, new Point2(60, 67), 0, 0) });   // centre 67 > mid-1 60 → pending 1
            bool pendingNext = rl.PendingIndex == 1;
            disp.Dispatch(new[] { new InputEvent(InputKind.PointerUp, new Point2(60, 67), 0, 0) });
            bool committed = !rl.IsActive && items[0] == 1 && items[1] == 0 && items[2] == 2;
            Check("e5dragdrop.7b end-to-end: dragging row 0 past row 1's midpoint commits the reorder through the drag lifecycle",
                pendingHome && pendingNext && committed,
                $"home={pendingHome} next={pendingNext} items=[{string.Join(",", items)}]");
        }

        // e5dragdrop.8 — steady-state drag dispatch is allocation-free: the controller reuses ONE DragEventArgs for
        // the whole gesture and the move path writes only scene columns (no closures, no boxing).
        {
            var scene = new SceneStore();
            float lastDx = 0f;
            new TreeReconciler(scene, strings).ReconcileRoot(new BoxEl
            {
                Width = 400, Height = 60, CanDrag = true, OnDragDelta = e => lastDx = e.TotalDx,
            }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            var ev = new InputEvent[1];
            ev[0] = new InputEvent(InputKind.PointerDown, new Point2(50, 30), 0, 0, 0f, KeyModifiers.None, PointerKind.Mouse, false, 1_000);
            disp.Dispatch(ev);
            for (int i = 1; i <= 6; i++)   // promote + warm the move path (shadow row, EMA, transform writes)
            {
                ev[0] = new InputEvent(InputKind.PointerMove, new Point2(50 + i * 10, 30), 0, 0, 0f, KeyModifiers.None, PointerKind.Mouse, false, 1_000 + (uint)(i * 16));
                disp.Dispatch(ev);
            }
            ev[0] = new InputEvent(InputKind.PointerMove, new Point2(140, 30), 0, 0, 0f, KeyModifiers.None, PointerKind.Mouse, false, 1_200);
            long before = GC.GetAllocatedBytesForCurrentThread();
            disp.Dispatch(ev);
            long bytes = GC.GetAllocatedBytesForCurrentThread() - before;
            Check("e5dragdrop.8 steady drag-move dispatch allocates 0 bytes (one reused DragEventArgs per gesture)",
                bytes == 0 && Near(lastDx, 90f), $"{bytes} bytes dx={lastDx:0.#}");
        }

        // e5dragdrop.8b — the whole drag FRAME at pointer rate is 0-alloc on phases 6–13: a drag move never
        // reconciles or relayouts (LocalTransform + dirty flags only), and the record/submit of the lifted visual
        // (0.80 opacity + shadow) reuses pooled storage.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("e5-alloc", new Size2(480, 320), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var root = new DragFrameProbe();
            using var host = new AppHost(app, window, device, fonts, strings, root);

            host.RunFrame();   // mount + layout
            var item = Child(host.Scene, host.Scene.Root, 0);
            var c = CenterOf(host.Scene, item);
            window.QueueInput(new InputEvent(InputKind.PointerDown, c, 0, 0, 0f, KeyModifiers.None, PointerKind.Mouse, false, 1_000));
            host.RunFrame();
            for (int i = 1; i <= 12; i++)   // promote, then warm: shadow slab, draw-list growth, eased press/hover settle
            {
                window.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(c.X + i * 4, c.Y), 0, 0, 0f, KeyModifiers.None, PointerKind.Mouse, false, 1_000 + (uint)(i * 16)));
                host.RunFrame();
            }
            window.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(c.X + 60, c.Y), 0, 0, 0f, KeyModifiers.None, PointerKind.Mouse, false, 1_300));
            var dragFrame = host.RunFrame();
            bool zero = dragFrame.HotPhaseAllocBytes == 0;
            // E5b spring-lag follow (the adopted Flutter/rbd ghost feel): with real timestamps the lifted visual EASES
            // toward the pointer instead of snapping, so the transform reaches 60 only once the spring settles —
            // assert the SETTLED position, while the 0-alloc gate stays on the immediate pointer-rate drag frame.
            for (int i = 0; i < 30; i++) host.RunFrame();
            bool tracked = Near(root.LastTotalDx, 60f) && Near(host.Scene.Paint(item).LocalTransform.Dx, 60f, 1.5f)
                && Near(host.Scene.Paint(item).Opacity, 0.80f);
            Check("e5dragdrop.8b steady drag frame is 0-alloc on phases 6–13 (transform-only repaint of the lifted visual)",
                zero && tracked, $"{dragFrame.HotPhaseAllocBytes} bytes dx={root.LastTotalDx:0.#} tdx={host.Scene.Paint(item).LocalTransform.Dx:0.#}");
        }
    }

    // E1 — the WinUI focus visual: 2px primary + 1px secondary BOTH outside the bounds (FocusVisualMargin −3 default),
    // keyboard-only, margin-aware (Slider −7,0,−7,0), light-theme inner alpha #B3FFFFFF.
    static void FocusRingChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("focusring", new Size2(300, 200), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var root = new FocusRingProbe();
        using var host = new AppHost(app, window, device, fonts, strings, root);
        host.RunFrame();

        // Pointer focus: click the button — NO ring may appear (keyboard-only focus visuals).
        var btn = Child(host.Scene, host.Scene.Root, 0);
        ClickNode(host, window, btn);
        host.RunFrame();
        bool pointerSilent = device.LastStrokes.Count == 0;

        // Keyboard focus: the click focused button1, so Tab lands on button2 — the ASYMMETRIC margin (−7,0,−7,0):
        // 100×40 ⇒ focus rect (−7,0,114,40); primary centerline inset 1 ⇒ (−6,1,112,38).
        window.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.Tab));
        host.RunFrame();
        DrawRoundRectStrokeCmd p2 = default;
        foreach (var s in device.LastStrokes) if (Near(s.StrokeWidth, 2f)) p2 = s;
        bool asym = Near(p2.Rect.X, -6f) && Near(p2.Rect.Y, 1f) && Near(p2.Rect.W, 112f) && Near(p2.Rect.H, 38f);
        Check("E1.b FocusVisualMargin −7,0,−7,0 widens the ring horizontally only (Slider shape)", asym,
            $"prim=({p2.Rect.X:0.#},{p2.Rect.Y:0.#} {p2.Rect.W:0.#}x{p2.Rect.H:0.#})");

        // Second Tab wraps to button1 — the DEFAULT margin −3: focus rect (−3,−3,106,46); primary inset 1; secondary 2.5.
        window.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.Tab));
        host.RunFrame();
        DrawRoundRectStrokeCmd primary = default, secondary = default;
        foreach (var s in device.LastStrokes)
        {
            if (Near(s.StrokeWidth, 2f)) primary = s;
            else if (Near(s.StrokeWidth, 1f)) secondary = s;
        }
        bool primaryGeom = Near(primary.Rect.X, -2f) && Near(primary.Rect.Y, -2f) && Near(primary.Rect.W, 104f) && Near(primary.Rect.H, 44f);
        bool secondaryGeom = Near(secondary.Rect.X, -0.5f) && Near(secondary.Rect.Y, -0.5f) && Near(secondary.Rect.W, 101f) && Near(secondary.Rect.H, 41f);
        bool colors = ColorClose(primary.Color, Tok.FocusOuter, 0.004f) && ColorClose(secondary.Color, Tok.FocusInner, 0.004f);
        Check("E1.a keyboard focus draws the WinUI dual ring OUTSIDE the bounds (pointer focus stays bare)",
            pointerSilent && primaryGeom && secondaryGeom && colors,
            $"ptr={pointerSilent} prim=({primary.Rect.X:0.#},{primary.Rect.Y:0.#} {primary.Rect.W:0.#}x{primary.Rect.H:0.#}) " +
            $"sec=({secondary.Rect.X:0.#},{secondary.Rect.Y:0.#} {secondary.Rect.W:0.#}x{secondary.Rect.H:0.#}) colors={colors}");

        // Light theme: FocusStrokeColorInner is #B3FFFFFF (white @ 0.70) — the audit's alpha fix.
        var light = Tok.Light.FocusInner;
        Check("E1.c Light FocusStrokeColorInner = #B3FFFFFF (alpha corrected)",
            ColorClose(light, ColorF.FromRgba(0xFF, 0xFF, 0xFF, 0xB3), 0.004f),
            $"A={light.A:0.###} R={light.R:0.###}");

        // E1.d — a focused ClipsToBounds control (a TextBox field) must NOT scissor away its own ring: the ring is
        // recorded AFTER the node's clip pops, so its strokes decode at the PARENT clip depth (0 here), full geometry.
        {
            using var app2 = new HeadlessPlatformApp();
            var window2 = new HeadlessWindow(new WindowDesc("focusclip", new Size2(300, 200), 1f));
            window2.Show();
            var device2 = new HeadlessGpuDevice();
            var root2 = new FocusClipProbe();
            using var host2 = new AppHost(app2, window2, device2, fonts, strings, root2);
            host2.RunFrame();
            window2.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.Tab));
            host2.RunFrame();
            bool ringFound = false, outsideClip = true, geom = false;
            for (int i = 0; i < device2.LastStrokes.Count; i++)
            {
                var s = device2.LastStrokes[i];
                if (!Near(s.StrokeWidth, 2f)) continue;
                ringFound = true;
                outsideClip &= device2.LastStrokeClipDepths[i] == 0;
                geom = Near(s.Rect.X, -2f) && Near(s.Rect.W, 104f);
            }
            Check("E1.d focus ring escapes the focused node's OWN ClipsToBounds scissor (clipped-TextBox-ring fix)",
                ringFound && outsideClip && geom && device2.LastClips.Count > 0,
                $"found={ringFound} depth0={outsideClip} geom={geom} clips={device2.LastClips.Count}");
        }
    }

    // E1.d — one clipping, clickable field (the EditableText shape: ClipToBounds + focusable).
    sealed class FocusClipProbe : Component
    {
        public override Element Render() => new BoxEl
        {
            Padding = Edges4.All(30),
            Children =
            [
                new BoxEl
                {
                    Width = 100, Height = 40, Fill = ColorF.FromRgba(0x20, 0x20, 0x20),
                    ClipToBounds = true, OnClick = () => { },
                    Children = [new TextEl("clip") { Size = 12f }],
                },
            ],
        };
    }

    // W0a — the clipboard + IME PAL seams (headless fakes drive the full composition lifecycle deterministically).
    static void TextServicesSeamChecks()
    {
        using var app = new HeadlessPlatformApp();
        var clip = app.Clipboard;
        uint seq0 = clip.SequenceNumber;
        clip.SetText("héllo ✂");
        bool roundTrip = clip.TryGetText(out var read) && read == "héllo ✂" && clip.SequenceNumber == seq0 + 1;
        ((HeadlessClipboard)clip).Clear();
        bool cleared = !clip.TryGetText(out _) && clip.SequenceNumber == seq0 + 2;
        Check("W0a.1 clipboard seam: unicode round-trip + epoch bumps + clear", roundTrip && cleared,
            $"read='{read}' seq={clip.SequenceNumber - seq0}");

        var window = new HeadlessWindow(new WindowDesc("ime", new Size2(100, 100), 1f));
        var ti = (HeadlessTextInput)window.TextInput;
        var sink = new RecordingSink();
        ti.SetSink(sink);
        ti.BeginComposition();                       // not editable yet → must no-op
        bool gated = sink.Log.Count == 0;
        ti.SetEditable(true);
        ti.BeginComposition();
        ti.UpdateComposition("にほ", 2, new ImeClause(0, 2, ImeClauseKind.Input));
        ti.UpdateComposition("日本", 2, new ImeClause(0, 2, ImeClauseKind.TargetConverted));
        ti.Commit("日本");
        bool flow = sink.Log.Count == 5 && sink.Log[0] == "start" && sink.Log[1] == "upd:にほ@2:Input"
                    && sink.Log[2] == "upd:日本@2:TargetConverted" && sink.Log[3] == "commit:日本" && sink.Log[4] == "end";
        sink.Log.Clear();
        ti.BeginComposition();
        ti.UpdateComposition("か", 1, new ImeClause(0, 1, ImeClauseKind.Input));
        ti.SetEditable(false);                       // focus leaves the editor mid-composition → cancel (empty update + end)
        bool cancelled = sink.Log.Count == 4 && sink.Log[2] == "upd:@0:" && sink.Log[3] == "end";
        Check("W0a.2 IME seam: editable gate, composition lifecycle, cancel-on-blur", gated && flow && cancelled,
            $"gated={gated} flow={flow} cancel={cancelled} log=[{string.Join("|", sink.Log)}]");
    }

    private sealed class RecordingSink : FluentGpu.Pal.ITextInputSink
    {
        public readonly List<string> Log = new();
        public void OnCompositionStart() => Log.Add("start");
        public void OnCompositionUpdate(ReadOnlySpan<char> text, int caret, ReadOnlySpan<FluentGpu.Pal.ImeClause> clauses)
            => Log.Add($"upd:{text.ToString()}@{caret}:{(clauses.Length > 0 ? clauses[0].Kind.ToString() : "")}");
        public void OnCompositionCommit(ReadOnlySpan<char> text) => Log.Add($"commit:{text.ToString()}");
        public void OnCompositionEnd() => Log.Add("end");
    }

    // W0e — EditableText rebuilt on TextEditCore: the full WinUI editing matrix, exercised headlessly against the
    // deterministic advance model (advance = 0.55×size, line = 1.4×size @ FontSize 14) — geometry asserts are exact math.
    static void EditableTextCoreChecks(StringTable strings)
    {
        const float Adv = 14f * 0.55f;     // 7.7 dip per UTF-16 unit
        const float LineH = 14f * 1.4f;    // 19.6 dip per line

        static NodeHandle TextVisual(SceneStore s, NodeHandle n)
        {
            if (n.IsNull) return NodeHandle.Null;
            if (s.Paint(n).VisualKind == VisualKind.Text) return n;
            for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
            {
                var r = TextVisual(s, c);
                if (!r.IsNull) return r;
            }
            return NodeHandle.Null;
        }

        // ── "hello world": caret click, keyboard selection, double/triple click, drag rects (+0-alloc), clipboard ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0e", new Size2(420, 240), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0eProbe { Initial = "hello world" };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            var field = FindRole(scene, scene.Root, AutomationRole.Text);
            var tn = TextVisual(scene, field);
            var ta = scene.AbsoluteRect(tn);

            void Press(float x, float y, uint t, KeyModifiers mods = KeyModifiers.None)
            {
                window.QueueInput(new InputEvent(InputKind.PointerDown, new Point2(x, y), 0, 0, 0f, mods, PointerKind.Mouse, false, t));
                window.QueueInput(new InputEvent(InputKind.PointerUp, new Point2(x, y), 0, 0, 0f, mods, PointerKind.Mouse, false, t + 10));
                host.RunFrame();
            }
            void Key(int key, KeyModifiers mods = KeyModifiers.None)
            {
                window.QueueInput(new InputEvent(InputKind.Key, default, 0, key, 0f, mods));
                host.RunFrame();
            }

            // W0e.1 — caret click placement round-trips the advance model; pointer focus arms the blinker.
            Press(ta.X + 3f * Adv + 1f, ta.Y + ta.H / 2f, 1_000);
            scene.TryGetTextEdit(tn, out var tes1);
            const byte focusedBits = TextEditState.Focused | TextEditState.CaretVisible;
            Check("W0e.1 caret click placement round-trips the headless advance model; focus arms the blinker",
                root.Edit!.Core.Active == 3 && Near(tes1.CaretX, 3f * Adv)
                && (tes1.Flags & focusedBits) == focusedBits && (scene.Flags(field) & NodeFlags.Focused) != 0,
                $"caret={root.Edit!.Core.Active} caretX={tes1.CaretX:0.##} flags={tes1.Flags}");

            // W0e.2 — Shift+arrow / Ctrl+Shift+arrow word / Ctrl+A selection states (+SelectionChanged fires).
            Key(Keys.Right, KeyModifiers.Shift);
            Key(Keys.Right, KeyModifiers.Shift);
            bool s1 = root.Edit!.SelectionStart == 3 && root.Edit!.SelectionLength == 2 && root.Edit!.SelectedText == "lo";
            Key(Keys.Right, KeyModifiers.Shift | KeyModifiers.Ctrl);
            bool s2 = root.Edit!.SelectionStart == 3 && root.Edit!.SelectionLength == 3 && root.Edit!.SelectedText == "lo ";
            Key(Keys.A, KeyModifiers.Ctrl);
            bool s3 = root.Edit!.SelectionStart == 0 && root.Edit!.SelectionLength == 11;
            Check("W0e.2 Shift+arrow extends, Ctrl+Shift+arrow extends by word, Ctrl+A selects all (+SelectionChanged)",
                s1 && s2 && s3 && root.SelLog.Count >= 3, $"s1={s1} s2={s2} s3={s3} selEvents={root.SelLog.Count}");

            // W0e.3 — double-click selects the word at the hit; triple-click selects all (ClickCount synthesis).
            float wx = ta.X + 7f * Adv + 1f;   // inside "world"
            float wy = ta.Y + ta.H / 2f;
            Press(wx, wy, 5_000);
            Press(wx, wy, 5_100);              // chained within slop+window → ClickCount 2
            bool dbl = root.Edit!.SelectedText == "world" && root.Edit!.SelectionStart == 6;
            Press(wx, wy, 5_200);              // → ClickCount 3
            bool trp = root.Edit!.SelectionStart == 0 && root.Edit!.SelectionLength == 11;
            Check("W0e.3 double-click selects the word at the hit; triple-click selects all", dbl && trp, $"dbl={dbl} trp={trp}");

            // W0e.4 — drag-select publishes rects into the scene slab (count + X/W math) while the button is held.
            window.QueueInput(new InputEvent(InputKind.PointerDown, new Point2(ta.X + 1f * Adv + 1f, wy), 0, 0, 0f, KeyModifiers.None, PointerKind.Mouse, false, 9_000));
            host.RunFrame();
            window.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(ta.X + 7f * Adv + 1f, wy), 0, 0));
            host.RunFrame();
            var selRects = scene.GetTextEditSelectionRects(tn);
            scene.TryGetTextEdit(tn, out var tes4);
            bool dragSel = selRects.Length == 1 && Near(selRects[0].X, 1f * Adv) && Near(selRects[0].W, 6f * Adv)
                && root.Edit!.SelectionStart == 1 && root.Edit!.SelectionLength == 6
                && (tes4.Flags & TextEditState.SelectionActive) != 0;
            Check("W0e.4 drag-select updates the selection rects in the scene slab (count + first-rect X/W math)",
                dragSel, $"rects={selRects.Length} x={(selRects.Length > 0 ? selRects[0].X : -1f):0.##} w={(selRects.Length > 0 ? selRects[0].W : -1f):0.##}");

            for (int i = 0; i < 5; i++)        // warm the pooled slab, then a steady pointer-rate drag frame
            {
                window.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(ta.X + (i % 2 == 0 ? 6f : 7f) * Adv + 1f, wy), 0, 0));
                host.RunFrame();
            }
            window.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(ta.X + 8f * Adv + 1f, wy), 0, 0));
            var dragSteady = host.RunFrame();
            Check("W0e.4b drag-select frame is 0-alloc on phases 6–13 (pooled slab, no re-render)",
                dragSteady.HotPhaseAllocBytes == 0, $"{dragSteady.HotPhaseAllocBytes} bytes");
            window.QueueInput(new InputEvent(InputKind.PointerUp, new Point2(ta.X + 8f * Adv + 1f, wy), 0, 0, 0f, KeyModifiers.None, PointerKind.Mouse, false, 9_500));
            host.RunFrame();

            // W0e.5 — clipboard round-trip via the HeadlessClipboard seam.
            var clip = (HeadlessClipboard)app.Clipboard;
            root.Edit!.Select(6, 5);           // "world"
            Key(Keys.C, KeyModifiers.Ctrl);
            bool copied = clip.TryGetText(out var c1) && c1 == "world";
            root.Edit!.Select(0, 6);           // "hello "
            Key(Keys.X, KeyModifiers.Ctrl);
            bool cutOk = clip.TryGetText(out var c2) && c2 == "hello " && root.Text!.Peek() == "world";
            Key(Keys.End);
            Key(Keys.V, KeyModifiers.Ctrl);
            bool pasted = root.Text!.Peek() == "worldhello ";
            Check("W0e.5 clipboard: Ctrl+C copies, Ctrl+X removes, Ctrl+V inserts at the caret",
                copied && cutOk && pasted, $"copy='{c1}' cut='{c2}' text='{root.Text!.Peek()}'");
        }

        // ── W0e.t — TOUCH caret/drag-select/double-tap on the SAME HandlePressed/HandleDrag the mouse drives ──
        // The dispatcher's touch path (TouchDown/Move/Up) feeds a real touch press into the editor: focus-on-press,
        // caret at the hit offset (ClickCount=1), drag-select via the OnDrag implicit-capture, word-select on a
        // double-tap (the pointer-kind-agnostic click counter). Probe + advance model are W0e's; only the gesture differs.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0e-touch", new Size2(420, 240), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0eProbe { Initial = "hello world" };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            var field = FindRole(scene, scene.Root, AutomationRole.Text);
            var tn = TextVisual(scene, field);
            var ta = scene.AbsoluteRect(tn);
            float wy = ta.Y + ta.H / 2f;

            // W0e.t1 — a touch tap focuses the field and places the caret at the tapped offset (same HitTestText as mouse).
            uint t1 = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(ta.X + 3f * Adv + 1f, wy), t1, 1));
            host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(ta.X + 3f * Adv + 1f, wy), t1 + 16, 1));
            host.RunFrame();
            s_touchClockMs = t1 + 1000;
            scene.TryGetTextEdit(tn, out var tesT1);
            const byte focusedBitsT = TextEditState.Focused | TextEditState.CaretVisible;
            bool tapCaret = root.Edit!.Core.Active == 3 && Near(tesT1.CaretX, 3f * Adv)
                && (scene.Flags(field) & NodeFlags.Focused) != 0 && (tesT1.Flags & focusedBitsT) == focusedBitsT;
            Check("W0e.t1 a touch tap focuses the editor and lands the caret at the tapped text offset (same HitTestText as the mouse)",
                tapCaret, $"caret={root.Edit!.Core.Active} caretX={tesT1.CaretX:0.##} focused={(scene.Flags(field) & NodeFlags.Focused) != 0} flags={tesT1.Flags}");

            // W0e.t2 — a touch drag from inside the text extends the selection (the OnDrag implicit-capture: TouchDown set
            // _dragTarget=field, each move drives HandleDrag). A vertical component on the drag proves the editor's drag
            // wins over any pan — a single-line editor isn't scrollable, but this is the same _dragTarget mechanism the
            // in-scroller arbitration (W0e.t4) relies on.
            uint t2 = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(ta.X + 1f * Adv + 1f, wy), t2, 2));
            host.RunFrame();
            for (int i = 1; i <= 6; i++)
            {
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(ta.X + (1f + i) * Adv + 1f, wy + i * 4f), t2 + (uint)i * 16, 2));
                host.RunFrame();
            }
            var selT2 = scene.GetTextEditSelectionRects(tn);
            bool dragSel = root.Edit!.SelectionStart == 1 && root.Edit!.SelectionLength == 6
                && selT2.Length == 1 && Near(selT2[0].X, 1f * Adv) && Near(selT2[0].W, 6f * Adv);
            // A steady touch-drag-select move is 0-alloc on phases 6–13: the per-id slot rebind + the OnDrag drive
            // (GetDrag → HandleDrag → SyncVisual's pooled rect slab) stays clean (the touch path's drive is byte-identical
            // to the mouse _dragTarget branch W0e.4b proves clean). Warm the slab over a few moves, then measure one.
            uint warmMs = t2 + 7 * 16;
            for (int i = 0; i < 4; i++)
            {
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(ta.X + (i % 2 == 0 ? 6f : 7f) * Adv + 1f, wy + 24f), warmMs + (uint)i * 16, 2));
                host.RunFrame();
            }
            window.QueueInput(Touch(InputKind.PointerMove, new Point2(ta.X + 8f * Adv + 1f, wy + 24f), warmMs + 4 * 16, 2));
            var dragSteadyT = host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(ta.X + 8f * Adv + 1f, wy + 24f), warmMs + 5 * 16, 2));
            host.RunFrame();
            s_touchClockMs = warmMs + 6 * 16 + 1000;
            Check("W0e.t2 a touch drag from inside the text extends the selection by character (the editor's OnDrag capture, not a tap)",
                dragSel, $"start={root.Edit!.SelectionStart} len={root.Edit!.SelectionLength} rects={selT2.Length}");
            Check("W0e.t2b a steady touch drag-select frame is 0-alloc on phases 6–13 (per-id slot rebind + OnDrag drive + pooled slab)",
                dragSteadyT.HotPhaseAllocBytes == 0, $"{dragSteadyT.HotPhaseAllocBytes} bytes");

            // W0e.t3 — a touch DOUBLE-TAP selects the word at the hit, exactly like a mouse double-click (the click
            // counter is pointer-kind-agnostic — TouchDown now tracks it and forwards ClickCount=2 to OnPointerPressed).
            float wxd = ta.X + 7f * Adv + 1f;   // inside "world" (chars 6..10)
            uint t3 = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(wxd, wy), t3, 3));
            host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(wxd, wy), t3 + 16, 3));
            host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(wxd, wy), t3 + 120, 3));   // 2nd tap inside slop+DoubleClickMs → ClickCount 2
            host.RunFrame();
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(wxd, wy), t3 + 136, 3));
            host.RunFrame();
            s_touchClockMs = t3 + 1000;
            bool dblTap = root.Edit!.SelectedText == "world" && root.Edit!.SelectionStart == 6;
            Check("W0e.t3 a touch double-tap selects the word at the hit (pointer-kind-agnostic click count → ClickCount=2)",
                dblTap, $"sel='{root.Edit!.SelectedText}' start={root.Edit!.SelectionStart}");
        }

        // ── W0e.t4 — the single-recognizer ARBITRATION: an EditableText INSIDE a vertical ScrollView ──
        // A touch drag that STARTS on the text must extend the editor's selection and NOT pan the scroller (the OnDrag
        // implicit-capture owns the contact; the pan candidate is never armed). A touch drag that starts on the non-text
        // filler below still pans. Same shared _dragTarget mechanism the Slider drag rides (proved elsewhere by the
        // Slider working by touch); documented Phase-3 nuance: tap-vs-drag ambiguity within slop is the selection team's.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0e-touch-scroll", new Size2(360, 320), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new TouchEditInScrollerProbe();
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            var field = FindRole(scene, scene.Root, AutomationRole.Text);
            var tn = TextVisual(scene, field);
            var ta = scene.AbsoluteRect(tn);
            var scroller = FindScrollable(scene, scene.Root);
            float wy = ta.Y + ta.H / 2f;

            // DRAG ON THE TEXT (rightward to extend the selection, with a big downward component on the scroll axis): the
            // editor's drag wins, the scroller does NOT move.
            uint t = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(ta.X + 1f * Adv + 1f, wy), t, 4));
            host.RunFrame();
            for (int i = 1; i <= 6; i++)
            {
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(ta.X + (1f + i) * Adv + 1f, wy + i * 12f), t + (uint)i * 16, 4));
                host.RunFrame();
            }
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(ta.X + 7f * Adv + 1f, wy + 72f), t + 7 * 16, 4));
            host.RunFrame();
            s_touchClockMs = t + 1000;
            scene.TryGetScroll(scroller, out var afterTextDrag);
            bool textDragSelected = root.Edit!.SelectionStart == 1 && root.Edit!.SelectionLength == 6;
            bool textDragNoPan = Near(afterTextDrag.OffsetY, 0f);

            // DRAG ON THE FILLER (below the editor): a touch on non-text chrome still pans the scroller.
            float fillerY = ta.Y + ta.H + 60f;   // on the tall filler box, clear of the editor
            float fillerX = ta.X + ta.W / 2f;
            uint t2 = s_touchClockMs;
            window.QueueInput(Touch(InputKind.PointerDown, new Point2(fillerX, fillerY), t2, 5));
            host.RunFrame();
            for (int i = 1; i <= 8; i++)
            {
                window.QueueInput(Touch(InputKind.PointerMove, new Point2(fillerX, fillerY - i * 12f), t2 + (uint)i * 16, 5));
                host.RunFrame();
            }
            window.QueueInput(Touch(InputKind.PointerUp, new Point2(fillerX, fillerY - 96f), t2 + 9 * 16, 5));
            host.RunFrame();
            s_touchClockMs = t2 + 1000;
            scene.TryGetScroll(scroller, out var afterFillerDrag);
            bool fillerPanned = afterFillerDrag.OffsetY > 40f;

            Check("W0e.t4 a touch drag starting ON an EditableText inside a scroller extends the selection and never pans; a drag on the non-text filler pans (single-recognizer arbitration: OnDrag capture wins over content-pan)",
                textDragSelected && textDragNoPan && fillerPanned,
                $"textSel(start={root.Edit!.SelectionStart},len={root.Edit!.SelectionLength}) panOnText={afterTextDrag.OffsetY:0.#} panOnFiller={afterFillerDrag.OffsetY:0.#}");
        }

        // ── W0e.6 — PasswordBox mask: '●' display, copy/cut blocked, paste allowed ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0e-mask", new Size2(420, 240), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0eProbe { Initial = "secret", MaskOn = true };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            var field = FindRole(scene, scene.Root, AutomationRole.Text);
            var tn = TextVisual(scene, field);
            void Key(int key, KeyModifiers mods = KeyModifiers.None)
            {
                window.QueueInput(new InputEvent(InputKind.Key, default, 0, key, 0f, mods));
                host.RunFrame();
            }
            ClickNode(host, window, field);
            Key(Keys.A, KeyModifiers.Ctrl);
            var clip = (HeadlessClipboard)app.Clipboard;
            clip.Clear();
            Key(Keys.C, KeyModifiers.Ctrl);
            bool copyBlocked = !clip.TryGetText(out _);
            Key(Keys.X, KeyModifiers.Ctrl);
            bool cutBlocked = root.Text!.Peek() == "secret" && !clip.TryGetText(out _);
            clip.SetText("pw");
            Key(Keys.V, KeyModifiers.Ctrl);    // paste replaces the (kept) select-all
            host.RunFrame();
            string disp = strings.Resolve(scene.Paint(tn).Text);
            Check("W0e.6 Mask blocks copy/cut, allows paste; display is '\\u25CF' per grapheme (model text real)",
                copyBlocked && cutBlocked && root.Text!.Peek() == "pw" && disp == "●●",
                $"copyBlocked={copyBlocked} cutBlocked={cutBlocked} text='{root.Text!.Peek()}' disp='{disp}'");
        }

        // ── W0e.7 — undo coalescing: a typing burst is ONE step; paste is its own step; Ctrl+Z/Ctrl+Y replay ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0e-undo", new Size2(420, 240), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0eProbe();
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            var field = FindRole(scene, scene.Root, AutomationRole.Text);
            void Key(int key, KeyModifiers mods = KeyModifiers.None)
            {
                window.QueueInput(new InputEvent(InputKind.Key, default, 0, key, 0f, mods));
                host.RunFrame();
            }
            void Type(string s)
            {
                foreach (char c in s) window.QueueInput(new InputEvent(InputKind.Char, default, 0, c));
                host.RunFrame();
            }
            ClickNode(host, window, field);
            Type("abc");
            bool oneStep = root.Edit!.Core.UndoDepth == 1 && root.Text!.Peek() == "abc";
            Key(Keys.Z, KeyModifiers.Ctrl);
            bool undone = root.Text!.Peek() == "";
            Key(Keys.Y, KeyModifiers.Ctrl);
            bool redone = root.Text!.Peek() == "abc";
            ((HeadlessClipboard)app.Clipboard).SetText("XY");
            Key(Keys.End);
            Key(Keys.V, KeyModifiers.Ctrl);
            bool pasteStep = root.Text!.Peek() == "abcXY" && root.Edit!.Core.UndoDepth == 2;
            Type("z");
            bool thirdStep = root.Edit!.Core.UndoDepth == 3;
            Key(Keys.Z, KeyModifiers.Ctrl);
            Key(Keys.Z, KeyModifiers.Ctrl);
            bool back = root.Text!.Peek() == "abc";
            Check("W0e.7 undo coalescing: 'abc' = one step back to empty; paste = its own step; Ctrl+Z/Ctrl+Y replay",
                oneStep && undone && redone && pasteStep && thirdStep && back,
                $"one={oneStep} undo={undone} redo={redone} paste={pasteStep} depth3={thirdStep} back='{root.Text!.Peek()}'");
        }

        // ── W0e.8 — MaxLength clamp + BeforeTextChanging rejection ──
        bool maxClamp;
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0e-max", new Size2(420, 240), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0eProbe { MaxLen = 5 };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            ClickNode(host, window, FindRole(host.Scene, host.Scene.Root, AutomationRole.Text));
            foreach (char c in "abcdefgh") window.QueueInput(new InputEvent(InputKind.Char, default, 0, c));
            host.RunFrame();
            maxClamp = root.Text!.Peek() == "abcde";
        }
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0e-before", new Size2(420, 240), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0eProbe { Before = s => s.Length <= 3 };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            ClickNode(host, window, FindRole(host.Scene, host.Scene.Root, AutomationRole.Text));
            foreach (char c in "abcde") window.QueueInput(new InputEvent(InputKind.Char, default, 0, c));
            host.RunFrame();
            Check("W0e.8 MaxLength clamps inserts at the limit; BeforeTextChanging(false) rejects the proposed edit",
                maxClamp && root.Text!.Peek() == "abc", $"maxLen→'{(maxClamp ? "abcde" : "?")}' gated='{root.Text!.Peek()}'");
        }

        // ── W0e.9 — IsReadOnly: caret + selection + copy work, typing gated, IME stays disabled ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0e-ro", new Size2(420, 240), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0eProbe { Initial = "locked", ReadOnly = true };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            var field = FindRole(scene, scene.Root, AutomationRole.Text);
            var tn = TextVisual(scene, field);
            var ta = scene.AbsoluteRect(tn);
            window.QueueInput(new InputEvent(InputKind.PointerDown, new Point2(ta.X + 2f * Adv + 1f, ta.Y + ta.H / 2f), 0, 0, 0f, KeyModifiers.None, PointerKind.Mouse, false, 1_000));
            window.QueueInput(new InputEvent(InputKind.PointerUp, new Point2(ta.X + 2f * Adv + 1f, ta.Y + ta.H / 2f), 0, 0, 0f, KeyModifiers.None, PointerKind.Mouse, false, 1_010));
            host.RunFrame();
            bool caretOk = root.Edit!.Core.Active == 2;
            window.QueueInput(new InputEvent(InputKind.Char, default, 0, 'z'));
            window.QueueInput(new InputEvent(InputKind.Char, default, 0, 'z'));
            host.RunFrame();
            bool typingGated = root.Text!.Peek() == "locked";
            void Key(int key, KeyModifiers mods = KeyModifiers.None)
            {
                window.QueueInput(new InputEvent(InputKind.Key, default, 0, key, 0f, mods));
                host.RunFrame();
            }
            Key(Keys.A, KeyModifiers.Ctrl);
            Key(Keys.C, KeyModifiers.Ctrl);
            bool copyOk = ((HeadlessClipboard)app.Clipboard).TryGetText(out var t) && t == "locked";
            bool imeOff = !((HeadlessTextInput)window.TextInput).Editable;
            Check("W0e.9 IsReadOnly gates typing but allows caret placement, selection and copy (IME disabled)",
                caretOk && typingGated && copyOk && imeOff, $"caret={root.Edit!.Core.Active} text='{root.Text!.Peek()}' copy='{t}' imeOff={imeOff}");
        }

        // ── W0e.10 — Enter commits + KEEPS focus; Escape reverts to the focus-time snapshot + cancels + blurs ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0e-esc", new Size2(420, 240), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0eProbe { Initial = "seed" };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            var field = FindRole(scene, scene.Root, AutomationRole.Text);
            var tn = TextVisual(scene, field);
            void Key(int key, KeyModifiers mods = KeyModifiers.None)
            {
                window.QueueInput(new InputEvent(InputKind.Key, default, 0, key, 0f, mods));
                host.RunFrame();
            }
            void Type(string s)
            {
                foreach (char c in s) window.QueueInput(new InputEvent(InputKind.Char, default, 0, c));
                host.RunFrame();
            }
            ClickNode(host, window, field);    // center is beyond the text → caret at end
            Type("XY");
            Key(Keys.Enter);
            bool committed = root.Committed == "seedXY" && (scene.Flags(field) & NodeFlags.Focused) != 0;
            Type("Z");
            Key(Keys.Escape);
            scene.TryGetTextEdit(tn, out var tesEsc);
            bool reverted = root.Text!.Peek() == "seed" && root.CancelCount == 1
                && (scene.Flags(field) & NodeFlags.Focused) == 0 && (tesEsc.Flags & TextEditState.Focused) == 0;
            Check("W0e.10 Enter commits and KEEPS focus (WinUI); Escape reverts to the focus-time snapshot, cancels, blurs",
                committed && reverted, $"committed='{root.Committed}' text='{root.Text!.Peek()}' cancels={root.CancelCount}");
        }

        // ── W0e.11/12 — IME composition lifecycle + caret blink ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0e-ime", new Size2(420, 240), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0eProbe();
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            var field = FindRole(scene, scene.Root, AutomationRole.Text);
            var tn = TextVisual(scene, field);
            ClickNode(host, window, field);
            var ti = (HeadlessTextInput)window.TextInput;
            bool editable = ti.Editable;

            ti.BeginComposition();
            ti.UpdateComposition("にほ", 2, new ImeClause(0, 2, ImeClauseKind.Input));
            host.RunFrame();
            scene.TryGetTextEdit(tn, out var ic);
            var ul = scene.GetTextEditUnderlineRects(tn);
            // The honest contract under test: the provisional composition lives in the DOC (display shows it) while the
            // SIGNAL stays unchanged until commit.
            bool provisional = strings.Resolve(scene.Paint(tn).Text) == "にほ" && root.Text!.Peek().Length == 0
                && ic.CompStart == 0 && ic.CompLen == 2 && ul.Length == 1 && Near(ul[0].H, 1f);

            ti.UpdateComposition("日本", 2, new ImeClause(0, 2, ImeClauseKind.TargetConverted));
            host.RunFrame();
            var ul2 = scene.GetTextEditUnderlineRects(tn);
            bool targetThick = ul2.Length == 1 && Near(ul2[0].H, 2f);

            ti.Commit("日本");
            host.RunFrame();
            scene.TryGetTextEdit(tn, out var ic2);
            bool committed = root.Text!.Peek() == "日本" && strings.Resolve(scene.Paint(tn).Text) == "日本"
                && ic2.CompLen == 0 && scene.GetTextEditUnderlineRects(tn).Length == 0 && root.Edit!.Core.UndoDepth == 1;

            ti.BeginComposition();
            ti.UpdateComposition("か", 1, new ImeClause(0, 1, ImeClauseKind.Input));
            host.RunFrame();
            bool midCancel = strings.Resolve(scene.Paint(tn).Text) == "日本か" && root.Text!.Peek() == "日本";
            ti.Cancel();
            host.RunFrame();
            bool cancelled = strings.Resolve(scene.Paint(tn).Text) == "日本" && root.Text!.Peek() == "日本";
            bool caretRect = Near(ti.LastCaretRectPx.X, scene.AbsoluteRect(tn).X + 2f * Adv);
            Check("W0e.11 IME: provisional in the DOC only (signal commits on commit), clause underline kinds, cancel restores, caret-rect placed",
                editable && provisional && targetThick && committed && midCancel && cancelled && caretRect,
                $"editable={editable} prov={provisional} thick={targetThick} commit={committed} mid={midCancel} cancel={cancelled} rectX={ti.LastCaretRectPx.X:0.#}");

            // W0e.12 — caret blink toggles CaretVisible over frames (500ms half-period @16ms fixed dt) + resets on edit.
            bool wentOff = false;
            int frames = 0;
            for (; frames < 90 && !wentOff; frames++)
            {
                host.RunFrame();
                scene.TryGetTextEdit(tn, out var bf);
                wentOff = (bf.Flags & TextEditState.CaretVisible) == 0;
            }
            window.QueueInput(new InputEvent(InputKind.Char, default, 0, 'x'));
            host.RunFrame();
            scene.TryGetTextEdit(tn, out var br);
            bool resetOn = (br.Flags & TextEditState.CaretVisible) != 0;
            Check("W0e.12 caret blink toggles CaretVisible over frames and snaps visible on edit",
                wentOff && resetOn, $"offAfter={frames}f resetOn={resetOn}");
            for (int i = 0; i < 6; i++) host.RunFrame();
            var blinkSteady = host.RunFrame();
            Check("W0e.12b focused steady (caret blink) frame allocates 0 on phases 6–13",
                blinkSteady.HotPhaseAllocBytes == 0, $"{blinkSteady.HotPhaseAllocBytes} bytes");
        }

        // ── W0e.13 — Tab (keyboard) focus selects all; the DeleteButton clears + keeps focus + hides when empty ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0e-del", new Size2(420, 240), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0eProbe { Initial = "abc", ShowDelete = true };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            var field = FindRole(scene, scene.Root, AutomationRole.Text);
            window.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.Tab));
            host.RunFrame();
            host.RunFrame();   // the focus re-render mounts the delete button
            bool selAll = root.Edit!.SelectionStart == 0 && root.Edit!.SelectionLength == 3;
            bool visual = (scene.Flags(field) & NodeFlags.FocusVisual) != 0;
            var btns = Roles(scene, AutomationRole.Button);
            bool shown = btns.Count == 1;
            if (shown) ClickNode(host, window, btns[0]);
            host.RunFrame();
            bool cleared = root.Text!.Peek() == "" && (scene.Flags(field) & NodeFlags.Focused) != 0;
            bool gone = Roles(scene, AutomationRole.Button).Count == 0;
            Check("W0e.13 Tab keyboard-focus selects all; DeleteButton (E894) clears, keeps focus, hides when empty",
                selAll && visual && shown && cleared && gone,
                $"selAll={selAll} visual={visual} shown={shown} cleared={cleared} gone={gone}");
        }

        // ── W0e.14 — caret-follow: ScrollX clamps the caret into the viewport; the wrapper transform applies -ScrollX ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0e-scroll", new Size2(420, 240), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0eProbe { W = 80f };   // lane viewport = 80 − (10+6) padding = 64
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            var field = FindRole(scene, scene.Root, AutomationRole.Text);
            var tn = TextVisual(scene, field);
            ClickNode(host, window, field);
            for (int i = 0; i < 20; i++) window.QueueInput(new InputEvent(InputKind.Char, default, 0, 'm'));
            host.RunFrame();
            scene.TryGetTextEdit(tn, out var tf);
            // caret = 20×7.7 = 154; follow wants 154−(64−8) = 98, clamped to maxScroll = (154+2)−64 = 92.
            bool follow = Near(tf.CaretX, 154f) && Near(tf.ScrollX, 92f);
            host.RunFrame();   // the TransformBind flush applies -ScrollX to the wrapper
            var scroller = scene.Parent(tn);
            float appliedDx = scene.Paint(scroller).LocalTransform.Dx;
            bool applied = Near(appliedDx, -92f);
            window.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.Home));
            host.RunFrame();
            scene.TryGetTextEdit(tn, out var th);
            bool home = Near(th.ScrollX, 0f);
            Check("W0e.14 caret-follow clamps ScrollX (caret stays inside the viewport) and the wrapper transform applies -ScrollX",
                follow && applied && home, $"caretX={tf.CaretX:0.#} scrollX={tf.ScrollX:0.#} dx={appliedDx:0.#} home={th.ScrollX:0.#}");
            for (int i = 0; i < 6; i++) host.RunFrame();
            var idle = host.RunFrame();
            Check("W0e.14b typing-burst-then-idle steady frame allocates 0 on phases 6–13",
                idle.HotPhaseAllocBytes == 0, $"{idle.HotPhaseAllocBytes} bytes");
        }

        // ── W0e.15 — multi-line: Up/Down honor the StickyX goal column over wrapped lines; Enter inserts '\r' ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0e-multi", new Size2(420, 240), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            // wrap width 144 → "aaaa bbbb cccc " | "dddd eeee" (greedy word wrap of the headless model)
            var root = new W0eProbe { Multi = true, W = 160f, H = 64f, Initial = "aaaa bbbb cccc dddd eeee" };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            var field = FindRole(scene, scene.Root, AutomationRole.Text);
            var tn = TextVisual(scene, field);
            var ta = scene.AbsoluteRect(tn);
            void Key(int key, KeyModifiers mods = KeyModifiers.None)
            {
                window.QueueInput(new InputEvent(InputKind.Key, default, 0, key, 0f, mods));
                host.RunFrame();
            }
            window.QueueInput(new InputEvent(InputKind.PointerDown, new Point2(ta.X + 2f * Adv + 1f, ta.Y + LineH * 0.5f), 0, 0, 0f, KeyModifiers.None, PointerKind.Mouse, false, 1_000));
            window.QueueInput(new InputEvent(InputKind.PointerUp, new Point2(ta.X + 2f * Adv + 1f, ta.Y + LineH * 0.5f), 0, 0, 0f, KeyModifiers.None, PointerKind.Mouse, false, 1_010));
            host.RunFrame();
            bool caretLine1 = root.Edit!.Core.Active == 2;
            Key(Keys.Down);
            bool down1 = root.Edit!.Core.Active == 17;     // line 2 starts at 15; sticky column 2 → 15+2
            Key(Keys.Down);
            bool down2 = root.Edit!.Core.Active == 17;     // clamped at the last line
            Key(Keys.Up);
            bool up1 = root.Edit!.Core.Active == 2;        // StickyX goal column held across the round-trip
            Key(Keys.Down, KeyModifiers.Shift);
            bool extended = root.Edit!.SelectionStart == 2 && root.Edit!.SelectionLength == 15;
            Key(Keys.Right);                                // collapse to the selection end (17)
            Key(Keys.Enter);                                // multi-line Enter inserts a hard '\r' break
            string after = root.Text!.Peek();
            bool newline = after.Length == 25 && after[17] == '\r';
            Check("W0e.15 multi-line: Up/Down/StickyX over wrapped lines (clamped at edges); Shift+Down extends; Enter inserts '\\r'",
                caretLine1 && down1 && down2 && up1 && extended && newline,
                $"caret={caretLine1} d1={down1} d2={down2} up={up1} ext={extended} nl={newline}");
        }
    }

    // W0f — the text-input consumer controls on the rewritten EditableText: PasswordBox peek/reveal-mode matrix,
    // NumberBox keyboard stepping + Text/format seam + spin visuals, AutoSuggestBox TextChanged-reason matrix +
    // SuggestionChosen semantics + UpdateTextOnSelect, editable ComboBox prefix-match/TextSubmitted/Escape.
    static void TextConsumerControlChecks(StringTable strings)
    {
        const float Adv = 14f * 0.55f;     // headless advance model @ FontSize 14 (see EditableTextCoreChecks)

        static NodeHandle TextVisual(SceneStore s, NodeHandle n)
        {
            if (n.IsNull) return NodeHandle.Null;
            if (s.Paint(n).VisualKind == VisualKind.Text) return n;
            for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
            {
                var r = TextVisual(s, c);
                if (!r.IsNull) return r;
            }
            return NodeHandle.Null;
        }

        // ── W0f.1 — PasswordBox Peek: press-and-hold reveals, release re-masks; reveal button = F78D @ width 30 ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0f-pw", new Size2(420, 240), 1f)); window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0fPasswordProbe();
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            var field = FindRole(scene, scene.Root, AutomationRole.Text);
            var tn = TextVisual(scene, field);
            bool masked0 = strings.Resolve(scene.Paint(tn).Text) == "●●●●●●";
            bool noBtn0 = Roles(scene, AutomationRole.Button).Count == 0;   // ButtonCollapsed while unfocused

            ClickNode(host, window, field);
            host.RunFrame();
            // Focusing a POPULATED box does NOT show the eye: CPasswordBox::OnGotFocus clears m_fCanShowRevealButton
            // (PasswordBox.cpp:572–581) and CanInvokeRevealButton requires it (PasswordBox.cpp:618–626).
            bool noBtnOnFocus = Roles(scene, AutomationRole.Button).Count == 0;

            // Empty the box, then type a fresh password — the empty→non-empty content change arms the button
            // (OnContentChanged, PasswordBox.cpp:366–377: "only allow password reveal button if transitioning from
            // empty to non-empty state").
            window.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.A, 0f, KeyModifiers.Ctrl));
            window.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.Back, 0f, KeyModifiers.None));
            host.RunFrame();
            foreach (char c in "secret") window.QueueInput(new InputEvent(InputKind.Char, default, 0, c));
            host.RunFrame();
            host.RunFrame();
            var btns = Roles(scene, AutomationRole.Button);
            bool shown = btns.Count == 1;
            bool w30 = shown && Near(scene.AbsoluteRect(btns[0]).W, 30f);
            // RevealButton glyph F78D @ TextControlButtonForeground = TextFillColorSecondary #C5FFFFFF (dark)
            // (PasswordBox_themeresources.xaml:100 + TextBox_themeresources.xaml:45).
            bool glyph = shown && HasGlyph(device, strings, "")
                && ColorClose(GlyphColor(device, strings, ""), Tok.TextSecondary, 0.004f);

            // Press-and-HOLD (no release yet) → the password shows in clear text.
            var bc = CenterOf(scene, btns[0]);
            window.QueueInput(new InputEvent(InputKind.PointerDown, bc, 0, 0, 0f, KeyModifiers.None, PointerKind.Mouse, false, 2_000));
            host.RunFrame();
            host.RunFrame();
            bool peeked = strings.Resolve(scene.Paint(tn).Text) == "secret";

            // Release → re-masks and the FIELD keeps focus (WinUI keeps the field focused across reveal interactions).
            window.QueueInput(new InputEvent(InputKind.PointerUp, bc, 0, 0, 0f, KeyModifiers.None, PointerKind.Mouse, false, 2_100));
            host.RunFrame();
            host.RunFrame();
            bool remasked = strings.Resolve(scene.Paint(tn).Text) == "●●●●●●";
            bool focusKept = (scene.Flags(field) & NodeFlags.Focused) != 0;
            Check("W0f.1 PasswordBox Peek: no eye on focusing a populated box; typing fresh content shows it (F78D, width 30, TextSecondary); press-and-hold reveals, release re-masks + keeps focus",
                masked0 && noBtn0 && noBtnOnFocus && shown && w30 && glyph && peeked && remasked && focusKept,
                $"masked0={masked0} noBtn0={noBtn0} noBtnOnFocus={noBtnOnFocus} shown={shown} w30={w30} glyph={glyph} peeked={peeked} remasked={remasked} focus={focusKept}");
        }

        // ── W0f.1b — PasswordBox reveal arming (the REAL WinUI ButtonStates rule): the eye appears while TYPING a
        // new password from empty (CPasswordBox::OnContentChanged arms m_fCanShowRevealButton only on the
        // empty→non-empty transition, PasswordBox.cpp:366–377; CanInvokeRevealButton = canShow ∧ hasSpace ∧ focused,
        // PasswordBox.cpp:618–626), and does NOT appear from merely focusing a populated box
        // (CPasswordBox::OnGotFocus clears m_fCanShowRevealButton, PasswordBox.cpp:572–581). ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0f-pwt", new Size2(420, 240), 1f)); window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0fPasswordProbe { Initial = "" };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            var field = FindRole(scene, scene.Root, AutomationRole.Text);

            ClickNode(host, window, field);
            host.RunFrame();
            bool noBtnEmptyFocused = Roles(scene, AutomationRole.Button).Count == 0;   // focused but empty → collapsed

            // Type into the focused empty box — the empty→non-empty content change arms the reveal button
            // (PasswordBox.cpp:366–377) and it must actually RENDER (F78D glyph, the user-visible eye).
            foreach (char c in "abc") window.QueueInput(new InputEvent(InputKind.Char, default, 0, c));
            host.RunFrame();
            host.RunFrame();
            int countAfterType = Roles(scene, AutomationRole.Button).Count;
            bool glyphAfterType = HasGlyph(device, strings, "");   // the reveal eye (PasswordBox_themeresources.xaml:100)
            bool shownAfterType = countAfterType == 1 && glyphAfterType;

            // Clear to empty → the flag drops (OnContentChanged: IsEmpty ⇒ m_fCanShowRevealButton = FALSE,
            // PasswordBox.cpp:430–434) and the button unmounts.
            void Key(int key, KeyModifiers mods = KeyModifiers.None)
            {
                window.QueueInput(new InputEvent(InputKind.Key, default, 0, key, 0f, mods));
                host.RunFrame();
            }
            Key(Keys.A, KeyModifiers.Ctrl);
            Key(Keys.Back);
            host.RunFrame();
            bool hiddenOnEmpty = Roles(scene, AutomationRole.Button).Count == 0;

            // Typing again from empty re-arms (the empty→non-empty transition, PasswordBox.cpp:366–377).
            window.QueueInput(new InputEvent(InputKind.Char, default, 0, 'z'));
            host.RunFrame();
            host.RunFrame();
            bool rearmed = Roles(scene, AutomationRole.Button).Count == 1;
            Check("W0f.1b PasswordBox reveal arming: typing from empty shows the eye; focused-empty does not; emptying hides + retype re-arms",
                noBtnEmptyFocused && shownAfterType && hiddenOnEmpty && rearmed,
                $"noBtnEmptyFocused={noBtnEmptyFocused} shownAfterType={shownAfterType} (count={countAfterType} glyph={glyphAfterType}) hiddenOnEmpty={hiddenOnEmpty} rearmed={rearmed}");
        }

        // ── W0f.2 — PasswordRevealMode matrix: Hidden = no button + masked; Visible = no button + clear; copy blocked ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0f-pwh", new Size2(420, 240), 1f)); window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0fPasswordProbe { Mode = PasswordRevealMode.Hidden };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            var field = FindRole(scene, scene.Root, AutomationRole.Text);
            var tn = TextVisual(scene, field);
            ClickNode(host, window, field);
            host.RunFrame();
            bool hiddenOk = strings.Resolve(scene.Paint(tn).Text) == "●●●●●●"
                && Roles(scene, AutomationRole.Button).Count == 0;

            using var app2 = new HeadlessPlatformApp();
            var window2 = new HeadlessWindow(new WindowDesc("w0f-pwv", new Size2(420, 240), 1f)); window2.Show();
            var device2 = new HeadlessGpuDevice();
            var fonts2 = new HeadlessFontSystem(strings);
            var root2 = new W0fPasswordProbe { Mode = PasswordRevealMode.Visible };
            using var host2 = new AppHost(app2, window2, device2, fonts2, strings, root2);
            host2.RunFrame();
            var scene2 = host2.Scene;
            var field2 = FindRole(scene2, scene2.Root, AutomationRole.Text);
            var tn2 = TextVisual(scene2, field2);
            bool visibleOk = strings.Resolve(scene2.Paint(tn2).Text) == "secret";
            ClickNode(host2, window2, field2);
            host2.RunFrame();
            bool noBtnVisible = Roles(scene2, AutomationRole.Button).Count == 0;
            // Copy stays BLOCKED even while revealed (WinUI never allows copying out of a PasswordBox).
            void Key2(int key, KeyModifiers mods = KeyModifiers.None)
            {
                window2.QueueInput(new InputEvent(InputKind.Key, default, 0, key, 0f, mods));
                host2.RunFrame();
            }
            Key2(Keys.A, KeyModifiers.Ctrl);
            Key2(Keys.C, KeyModifiers.Ctrl);
            bool copyBlocked = !((HeadlessClipboard)app2.Clipboard).TryGetText(out _);
            Check("W0f.2 PasswordRevealMode: Hidden = masked + no reveal button; Visible = clear text + no button, copy still blocked",
                hiddenOk && visibleOk && noBtnVisible && copyBlocked,
                $"hidden={hiddenOk} visible={visibleOk} noBtn={noBtnVisible} copyBlocked={copyBlocked}");
        }

        // ── W0f.3 — PasswordChar customization (WinUI PasswordBox.PasswordChar, default '●') ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0f-pwc", new Size2(420, 240), 1f)); window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0fPasswordProbe { Char = '*' };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            var tn = TextVisual(scene, FindRole(scene, scene.Root, AutomationRole.Text));
            Check("W0f.3 PasswordBox PasswordChar: a custom mask char renders per grapheme",
                strings.Resolve(scene.Paint(tn).Text) == "******", $"disp='{strings.Resolve(scene.Paint(tn).Text)}'");
        }

        // ── W0f.4 — NumberBox keyboard stepping: Up/Down=SmallChange, PageUp/PageDown=LargeChange, clamp + Text ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0f-nb", new Size2(420, 240), 1f)); window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0fNumberProbe();
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            bool textSeed = root.Txt!.Peek() == "5";   // mount Value→Text sync (UpdateTextToValue)
            ClickNode(host, window, FindRole(scene, scene.Root, AutomationRole.Text));
            void Key(int key)
            {
                window.QueueInput(new InputEvent(InputKind.Key, default, 0, key));
                host.RunFrame();
            }
            Key(Keys.Up);
            bool up = root.Val!.Peek() == 6;                       // +SmallChange (NumberBox.cpp:538–541)
            Key(Keys.PageUp);
            bool pgUp = root.Val!.Peek() == 10;                    // +LargeChange 6+5=11 → clamp 10 (cpp:548–551)
            Key(Keys.Up);
            bool clamped = root.Val!.Peek() == 10;                 // at Maximum: stays (Coerce clamps)
            Key(Keys.PageDown);
            bool pgDn = root.Val!.Peek() == 5;                     // −LargeChange (cpp:553–556)
            Key(Keys.Down);
            bool dn = root.Val!.Peek() == 4 && root.Txt!.Peek() == "4";   // −SmallChange + Text reformat
            Check("W0f.4 NumberBox keys: Up/Down step SmallChange, PageUp/PageDown step LargeChange, clamped at bounds; Text carries the formatted value",
                textSeed && up && pgUp && clamped && pgDn && dn,
                $"seed={textSeed} up={up} pgUp={pgUp} clamp={clamped} pgDn={pgDn} dn={dn} txt='{root.Txt!.Peek()}'");
        }

        // ── W0f.5 — NumberBox: NaN does not step (cpp StepValue isnan guard); programmatic Text validates + clamps ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0f-nbn", new Size2(420, 240), 1f)); window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0fNumberProbe { Initial = double.NaN };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            ClickNode(host, window, FindRole(scene, scene.Root, AutomationRole.Text));
            window.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.Up));
            host.RunFrame();
            bool nanNoStep = double.IsNaN(root.Val!.Peek()) && root.Txt!.Peek() == "";   // cpp:604–629

            using var app2 = new HeadlessPlatformApp();
            var window2 = new HeadlessWindow(new WindowDesc("w0f-nbt", new Size2(420, 240), 1f)); window2.Show();
            var device2 = new HeadlessGpuDevice();
            var fonts2 = new HeadlessFontSystem(strings);
            var root2 = new W0fNumberProbe();
            using var host2 = new AppHost(app2, window2, device2, fonts2, strings, root2);
            host2.RunFrame();
            root2.Txt!.Value = "7";    // external programmatic Text write — OnTextPropertyChanged → ValidateInput (cpp:325–340)
            host2.RunFrame();
            bool progSet = root2.Val!.Peek() == 7;
            root2.Txt!.Value = "25";   // out-of-range → InvalidInputOverwritten clamps to Maximum, text reformats
            host2.RunFrame();
            bool progClamp = root2.Val!.Peek() == 10 && root2.Txt!.Peek() == "10";
            Check("W0f.5 NumberBox: NaN value does not step; a programmatic Text write validates immediately (clamping out-of-range)",
                nanNoStep && progSet && progClamp,
                $"nanNoStep={nanNoStep} progSet={progSet} progClamp={progClamp} v={root2.Val!.Peek()} t='{root2.Txt!.Peek()}'");
        }

        // ── W0f.6 — NumberBox spin visuals: inline E70E/E70D @ TextSecondary in 32-wide cells; Compact EC8F indicator,
        //            popup opens on focus with 36×36 spin buttons and closes on blur ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0f-nbi", new Size2(420, 240), 1f)); window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0fNumberProbe { Mode = NumberBoxSpinButtonPlacementMode.Inline };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            // Glyphs E70E/E70D (NumberBox.xaml:174–175) at TextControlButtonForeground = TextFillColorSecondary
            // #C5FFFFFF dark (TextBox_themeresources.xaml:45) — full-ARGB.
            bool glyphs = HasGlyph(device, strings, "") && HasGlyph(device, strings, "")
                && ColorClose(GlyphColor(device, strings, ""), Tok.TextSecondary, 0.004f)
                && ColorClose(GlyphColor(device, strings, ""), Tok.TextSecondary, 0.004f);
            var spins = Roles(scene, AutomationRole.Button);
            bool cells = spins.Count == 2
                && Near(scene.AbsoluteRect(spins[0]).W, 32f) && Near(scene.AbsoluteRect(spins[1]).W, 32f);   // MinWidth 32 (NumberBox.xaml:185)
            ClickNode(host, window, spins[0]);   // up spin → +SmallChange
            bool stepped = root.Val!.Peek() == 6;

            using var app2 = new HeadlessPlatformApp();
            var window2 = new HeadlessWindow(new WindowDesc("w0f-nbc", new Size2(420, 320), 1f)); window2.Show();
            var device2 = new HeadlessGpuDevice();
            var fonts2 = new HeadlessFontSystem(strings);
            var root2 = new W0fNumberProbe { Mode = NumberBoxSpinButtonPlacementMode.Compact };
            using var host2 = new AppHost(app2, window2, device2, fonts2, strings, root2);
            host2.RunFrame();
            var scene2 = host2.Scene;
            bool indicator = HasGlyph(device2, strings, "");          // PopupIndicator (NumberBox.xaml:365)
            bool noPopup0 = Roles(scene2, AutomationRole.Button).Count == 0; // the indicator is NOT a button
            ClickNode(host2, window2, FindRole(scene2, scene2.Root, AutomationRole.Text));   // focus → popup opens
            host2.RunFrame();
            var popupBtns = Roles(scene2, AutomationRole.Button);
            bool popupOpen = popupBtns.Count == 2
                && Near(scene2.AbsoluteRect(popupBtns[0]).W, 36f) && Near(scene2.AbsoluteRect(popupBtns[0]).H, 36f);   // 36×36 (NumberBox.xaml:197–198)
            window2.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.Escape));      // Escape blurs → popup closes
            for (int i = 0; i < 10; i++) host2.RunFrame();   // ride out the 83ms overlay close fade
            bool popupClosed = Roles(scene2, AutomationRole.Button).Count == 0;
            Check("W0f.6 NumberBox spin visuals: inline 32-wide E70E/E70D cells @ TextSecondary step on click; Compact = non-interactive EC8F indicator, popup (36×36 spins) opens on focus / closes on blur",
                glyphs && cells && stepped && indicator && noPopup0 && popupOpen && popupClosed,
                $"glyphs={glyphs} cells={cells} stepped={stepped} ind={indicator} no0={noPopup0} open={popupOpen} closed={popupClosed}");
        }

        // ── W0f.7 — AutoSuggestBox TextChanged-reason matrix + arrow preview + SuggestionChosen-per-selection ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0f-asb", new Size2(420, 320), 1f)); window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0fAsbProbe();
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            ClickNode(host, window, FindRole(scene, scene.Root, AutomationRole.Text));
            void Key(int key)
            {
                window.QueueInput(new InputEvent(InputKind.Key, default, 0, key));
                host.RunFrame();
            }
            foreach (char c in "ca") window.QueueInput(new InputEvent(InputKind.Char, default, 0, c));
            host.RunFrame();
            host.RunFrame();   // overlay content realizes
            bool typed = root.Changes.Count > 0 && root.Changes[^1] == ("ca", TextChangeReason.UserInput)
                && Roles(scene, AutomationRole.MenuItem).Count == 3;

            Key(Keys.Down);    // selection → item 0: preview text + SuggestionChosen (reason SuggestionChosen)
            host.RunFrame();   // the deferred TextChanged effect
            bool preview = root.Query!.Peek() == "Cascadia Code"
                && root.Chosen.Count == 1 && root.Chosen[0] == "Cascadia Code"
                && root.Changes[^1] == ("Cascadia Code", TextChangeReason.SuggestionChosen);

            Key(Keys.Down); Key(Keys.Down);   // → Calendar → Calculator
            Key(Keys.Down);                   // past the end → restore the typed text (reason ProgrammaticChange)
            host.RunFrame();
            bool restored = root.Query!.Peek() == "ca" && root.Chosen.Count == 3
                && root.Changes[^1] == ("ca", TextChangeReason.ProgrammaticChange);

            Key(Keys.Down);                   // back onto item 0
            int chosenBeforeEnter = root.Chosen.Count;
            Key(Keys.Enter);                  // submit: QueryText = field text; NO extra SuggestionChosen (cpp:1149–1160)
            bool submitted = root.Submitted.Count == 1 && root.Submitted[0] == "Cascadia Code"
                && root.Chosen.Count == chosenBeforeEnter;
            Check("W0f.7 AutoSuggestBox: TextChanged reasons (UserInput → SuggestionChosen preview → ProgrammaticChange restore); SuggestionChosen per selection move, NOT on Enter",
                typed && preview && restored && submitted,
                $"typed={typed} preview={preview} restored={restored} submit={submitted} chosen={root.Chosen.Count} changes={root.Changes.Count}");
        }

        // ── W0f.8 — AutoSuggestBox UpdateTextOnSelect=false: arrows cycle + SuggestionChosen, field text untouched ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0f-asbu", new Size2(420, 320), 1f)); window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0fAsbProbe { UpdateTextOnSelect = false };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            ClickNode(host, window, FindRole(scene, scene.Root, AutomationRole.Text));
            foreach (char c in "cal") window.QueueInput(new InputEvent(InputKind.Char, default, 0, c));
            host.RunFrame();
            host.RunFrame();
            window.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.Down));
            host.RunFrame();
            bool ok = root.Query!.Peek() == "cal" && root.Chosen.Count == 1 && root.Chosen[0] == "Calendar";
            Check("W0f.8 AutoSuggestBox UpdateTextOnSelect=false: arrow keeps the typed text but still raises SuggestionChosen (cpp:2367 gates only the text write)",
                ok, $"query='{root.Query!.Peek()}' chosen={string.Join("|", root.Chosen)}");
        }

        // ── W0f.9 — AutoSuggestBox row click: SuggestionChosen BEFORE QuerySubmitted; item content inset 12 ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0f-asbc", new Size2(420, 320), 1f)); window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0fAsbProbe();
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            ClickNode(host, window, FindRole(scene, scene.Root, AutomationRole.Text));
            foreach (char c in "cal") window.QueueInput(new InputEvent(InputKind.Char, default, 0, c));
            host.RunFrame();
            host.RunFrame();
            var rows = Roles(scene, AutomationRole.MenuItem);
            // Content inset: DefaultListViewItemStyle Padding 16,0,12,0 from the ITEM edge; plate inset 4 → 12 inside.
            var rowText = TextVisual(scene, rows[1]);
            float inset = scene.AbsoluteRect(rowText).X - scene.AbsoluteRect(rows[1]).X;
            bool insetOk = Near(inset, 12f);
            ClickNode(host, window, rows[1]);   // "Calculator"
            int ci = root.Order.IndexOf("C:Calculator");
            int qi = root.Order.IndexOf("Q:Calculator");
            bool ordered = ci >= 0 && qi > ci && root.Query!.Peek() == "Calculator";
            Check("W0f.9 AutoSuggestBox click: SelectionChanged → SuggestionChosen → QuerySubmitted sequential; row content inset 12 (ListViewItem 16,0,12,0 minus the 4px plate)",
                insetOk && ordered, $"inset={inset:0.#} order=[{string.Join(",", root.Order)}]");
        }

        // ── W0f.10 — editable ComboBox: prefix auto-match autocompletes with the suffix selected, commit on Enter ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0f-cmb", new Size2(420, 320), 1f)); window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0fComboProbe();
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            var field = FindRole(scene, scene.Root, AutomationRole.Text);
            var tn = TextVisual(scene, field);
            ClickNode(host, window, field);
            foreach (char c in "gr") window.QueueInput(new InputEvent(InputKind.Char, default, 0, c));
            host.RunFrame();
            // ProcessSearch prefix hit → auto-complete "Green" with the completed suffix "een" selected
            // (ComboBox_Partial.cpp:4108–4119 + UpdateEditableTextBox :1543–1551); SelectedIndex NOT committed while
            // typing (SelectionChangedTrigger default = Committed).
            var selRects = scene.GetTextEditSelectionRects(tn);
            bool completed = root.Txt!.Peek() == "Green" && root.Sel!.Peek() == -1
                && selRects.Length == 1 && Near(selRects[0].X, 2f * Adv) && Near(selRects[0].W, 3f * Adv);
            window.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.Enter));
            host.RunFrame();
            bool committed = root.Sel!.Peek() == 1 && root.Submitted.Count == 0;   // a search hit commits WITHOUT TextSubmitted
            Check("W0f.10 editable ComboBox: typing 'gr' auto-completes to 'Green' with 'een' selected (no commit); Enter commits the match, no TextSubmitted",
                completed && committed,
                $"txt='{root.Txt!.Peek()}' sel={root.Sel!.Peek()} rects={selRects.Length} committed={committed}");
        }

        // ── W0f.11 — editable ComboBox TextSubmitted: unhandled → custom value (sel −1); handled → selection kept ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0f-cmbt", new Size2(420, 320), 1f)); window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0fComboProbe();
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            var field = FindRole(scene, scene.Root, AutomationRole.Text);
            void Key(int key, KeyModifiers mods = KeyModifiers.None)
            {
                window.QueueInput(new InputEvent(InputKind.Key, default, 0, key, 0f, mods));
                host.RunFrame();
            }
            void Type(string s)
            {
                foreach (char c in s) window.QueueInput(new InputEvent(InputKind.Char, default, 0, c));
                host.RunFrame();
            }
            ClickNode(host, window, field);
            Type("gr"); Key(Keys.Enter);                       // commit "Green" (sel 1)
            Key(Keys.A, KeyModifiers.Ctrl); Type("xyz"); Key(Keys.Enter);
            bool custom = root.Submitted.Count == 1 && root.Submitted[0] == "xyz"
                && root.Sel!.Peek() == -1 && root.Txt!.Peek() == "xyz";   // unhandled: custom value, no selection (cpp:2540–2543)

            using var app2 = new HeadlessPlatformApp();
            var window2 = new HeadlessWindow(new WindowDesc("w0f-cmbh", new Size2(420, 320), 1f)); window2.Show();
            var device2 = new HeadlessGpuDevice();
            var fonts2 = new HeadlessFontSystem(strings);
            var root2 = new W0fComboProbe { HandleSubmit = true };
            using var host2 = new AppHost(app2, window2, device2, fonts2, strings, root2);
            host2.RunFrame();
            var scene2 = host2.Scene;
            var field2 = FindRole(scene2, scene2.Root, AutomationRole.Text);
            void Key2(int key, KeyModifiers mods = KeyModifiers.None)
            {
                window2.QueueInput(new InputEvent(InputKind.Key, default, 0, key, 0f, mods));
                host2.RunFrame();
            }
            ClickNode(host2, window2, field2);
            foreach (char c in "gr") window2.QueueInput(new InputEvent(InputKind.Char, default, 0, c));
            host2.RunFrame();
            Key2(Keys.Enter);                                  // sel = 1
            Key2(Keys.A, KeyModifiers.Ctrl);
            foreach (char c in "xyz") window2.QueueInput(new InputEvent(InputKind.Char, default, 0, c));
            host2.RunFrame();
            Key2(Keys.Enter);
            bool handled = root2.Submitted.Count == 1 && root2.Sel!.Peek() == 1 && root2.Txt!.Peek() == "xyz";
            Check("W0f.11 editable ComboBox TextSubmitted: unhandled custom value → SelectedIndex −1 + text kept; handled (return true) → selection untouched",
                custom && handled,
                $"custom={custom} (sel={root.Sel!.Peek()} txt='{root.Txt!.Peek()}') handled={handled} (sel2={root2.Sel!.Peek()})");
        }

        // ── W0f.12 — editable ComboBox: arrows preview without committing; Escape restores the pre-edit text ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0f-cmbe", new Size2(420, 320), 1f)); window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0fComboProbe();
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var scene = host.Scene;
            var field = FindRole(scene, scene.Root, AutomationRole.Text);
            void Key(int key)
            {
                window.QueueInput(new InputEvent(InputKind.Key, default, 0, key));
                host.RunFrame();
            }
            ClickNode(host, window, field);   // focus snapshot: "" / sel −1
            Key(Keys.Down);
            bool prev1 = root.Txt!.Peek() == "Red" && root.Sel!.Peek() == -1;     // preview select-all, NO commit (cpp:2939–2949)
            Key(Keys.Down);
            bool prev2 = root.Txt!.Peek() == "Green" && root.Sel!.Peek() == -1;
            Key(Keys.Escape);
            host.RunFrame();
            bool reverted = root.Txt!.Peek() == "" && root.Sel!.Peek() == -1
                && (scene.Flags(field) & NodeFlags.Focused) == 0;                  // Escape reverts + blurs, no commit
            Check("W0f.12 editable ComboBox: Up/Down preview into the field without committing; Escape restores the pre-edit text + selection",
                prev1 && prev2 && reverted,
                $"prev1={prev1} prev2={prev2} reverted={reverted} txt='{root.Txt!.Peek()}' sel={root.Sel!.Peek()}");
        }

        // ── W0f.13 — header/description chrome: TextControlHeaderForeground (+disabled) and the Description row ──
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("w0f-hdr", new Size2(420, 320), 1f)); window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new W0fStaticProbe
            {
                Build = () => new BoxEl
                {
                    Direction = 1, Gap = 12,
                    Children =
                    [
                        TextBox.Create(options: new TextBox.TextBoxOptions { Placeholder = "ph", Width = 280f, Header = "Email", Description = "Helper" }),
                        PasswordBox.Create("Password", 280f, "Pw", isEnabled: false,
                                           password: new Signal<string>("secret")),
                    ],
                },
            };
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            // Header = TextControlHeaderForeground (BaseHigh #FFFFFFFF dark, generic.xaml:886+207); Description =
            // SystemControlDescriptionTextForegroundBrush (BaseMedium #99FFFFFF dark, generic.xaml:327+209); disabled
            // header = TextControlHeaderForegroundDisabled (BaseMediumLow #66FFFFFF dark, generic.xaml:887+211);
            // disabled field TEXT = TemporaryTextFillColorDisabled #5DFEFEFE (TextBox_themeresources.xaml:22+34).
            bool header = ColorClose(GlyphColor(device, strings, "Email"), Tok.TextControlHeaderForeground, 0.004f);
            bool desc = ColorClose(GlyphColor(device, strings, "Helper"), Tok.TextControlDescriptionForeground, 0.004f);
            bool disHeader = ColorClose(GlyphColor(device, strings, "Pw"), Tok.TextControlHeaderForegroundDisabled, 0.004f);
            bool disText = ColorClose(GlyphColor(device, strings, "●●●●●●"), Tok.TextControlForegroundDisabled, 0.004f);
            Check("W0f.13 header/description chrome: header BaseHigh, description BaseMedium, disabled header BaseMediumLow, disabled field text #5DFEFEFE (full ARGB)",
                header && desc && disHeader && disText,
                $"header={header} desc={desc} disHeader={disHeader} disText={disText}");
        }
    }

    // E3 — implicit BrushTransition: a logical flip cross-fades fill + foreground over 83ms (no snap), then settles
    // exactly at the target and the frame loop idles again (the row self-removes).
    static void BrushTransitionChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("brush", new Size2(300, 200), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var root = new BrushTransitionProbe();
        using var host = new AppHost(app, window, device, fonts, strings, root);
        host.RunFrame();

        static FillRoundRectCmd ProbeRect(HeadlessGpuDevice dev)
        {
            foreach (var r in dev.LastRects) if (Near(r.Rect.W, 77f) && Near(r.Rect.H, 33f)) return r;
            return default;
        }

        bool restingA = ColorClose(ProbeRect(device).Fill, BrushTransitionProbe.FillA, 0.004f);

        root.On!.Value = true;   // logical flip → re-render with FillB/TextB
        host.RunFrame();         // first frame: T has advanced one fixed dt (~16.7/83) — mid-fade
        var mid = ProbeRect(device).Fill;
        var midText = GlyphColor(device, strings, "bt");
        bool fillMid = mid.B > 0.05f && mid.B < 0.95f && mid.R > 0.05f && mid.R < 0.95f;
        bool textMid = midText.G > 0.05f && midText.G < 0.95f && midText.B > 0.05f && midText.B < 0.95f;

        for (int i = 0; i < 10; i++) host.RunFrame();   // ≥83ms of fixed frames → settled
        bool fillSettled = ColorClose(ProbeRect(device).Fill, BrushTransitionProbe.FillB, 0.004f);
        bool textSettled = ColorClose(GlyphColor(device, strings, "bt"), BrushTransitionProbe.TextB, 0.004f);
        bool idle = !host.HasActiveWork;

        Check("E3.a BrushTransition cross-fades the fill on a logical flip (mid ≠ snap, settles exact)",
            restingA && fillMid && fillSettled, $"rest={restingA} mid=({mid.R:0.##},{mid.G:0.##},{mid.B:0.##}) settled={fillSettled}");
        Check("E3.b BrushTransition cross-fades the text foreground too, then the loop idles",
            textMid && textSettled && idle, $"mid=({midText.R:0.##},{midText.G:0.##},{midText.B:0.##}) settled={textSettled} idle={idle}");
    }

    static void FocusNavChecks(StringTable strings)
    {
        var fonts = new HeadlessFontSystem(strings);

        // P6.a — TabIndex orders tab navigation: document order A,B,C but TabIndex 3,1,2 → visits B→C→A.
        {
            var scene = new SceneStore();
            new TreeReconciler(scene, strings).ReconcileRoot(new BoxEl
            {
                Direction = 0, Gap = 10,
                Children =
                [
                    new BoxEl { Key = "A", Width = 20, Height = 20, OnClick = () => { }, TabIndex = 3 },
                    new BoxEl { Key = "B", Width = 20, Height = 20, OnClick = () => { }, TabIndex = 1 },
                    new BoxEl { Key = "C", Width = 20, Height = 20, OnClick = () => { }, TabIndex = 2 },
                ],
            }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            var a = Child(scene, scene.Root, 0); var b = Child(scene, scene.Root, 1); var c = Child(scene, scene.Root, 2);
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Tab) }); var f1 = disp.Focused;
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Tab) }); var f2 = disp.Focused;
            disp.Dispatch(new[] { new InputEvent(InputKind.Key, default, 0, Keys.Tab) }); var f3 = disp.Focused;
            Check("W1-P6.a TabIndex orders tab navigation (1→2→3, not document order)",
                f1 == b && f2 == c && f3 == a, $"f1=B?{f1 == b} f2=C?{f2 == c} f3=A?{f3 == a}");
        }

        // P6.b — XY arrow navigation across a 2×2 grid: Right→Down→Left→Up walks TL→TR→BR→BL→TL.
        {
            var scene = new SceneStore();
            new TreeReconciler(scene, strings).ReconcileRoot(new BoxEl
            {
                Direction = 1, Gap = 10,
                Children =
                [
                    new BoxEl { Direction = 0, Gap = 10, Children = [
                        new BoxEl { Key = "TL", Width = 30, Height = 20, OnClick = () => { } },
                        new BoxEl { Key = "TR", Width = 30, Height = 20, OnClick = () => { } } ] },
                    new BoxEl { Direction = 0, Gap = 10, Children = [
                        new BoxEl { Key = "BL", Width = 30, Height = 20, OnClick = () => { } },
                        new BoxEl { Key = "BR", Width = 30, Height = 20, OnClick = () => { } } ] },
                ],
            }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            var r0 = Child(scene, scene.Root, 0); var r1 = Child(scene, scene.Root, 1);
            var tl = Child(scene, r0, 0); var tr = Child(scene, r0, 1);
            var bl = Child(scene, r1, 0); var br = Child(scene, r1, 1);
            disp.SetFocus(tl, visual: true);
            disp.MoveFocusArrow(FocusDirection.Right); var aRight = disp.Focused;
            disp.MoveFocusArrow(FocusDirection.Down); var aDown = disp.Focused;
            disp.MoveFocusArrow(FocusDirection.Left); var aLeft = disp.Focused;
            disp.MoveFocusArrow(FocusDirection.Up); var aUp = disp.Focused;
            Check("W1-P6.b arrow XY nav walks the 2×2 grid (R→D→L→U)",
                aRight == tr && aDown == br && aLeft == bl && aUp == tl,
                $"R=TR?{aRight == tr} D=BR?{aDown == br} L=BL?{aLeft == bl} U=TL?{aUp == tl}");
        }

        // P6.c — scoped roving: NextFocusableIn cycles within a subtree and never escapes to an outside focusable.
        {
            var scene = new SceneStore();
            new TreeReconciler(scene, strings).ReconcileRoot(new BoxEl
            {
                Direction = 1,
                Children =
                [
                    new BoxEl { Key = "outside", Width = 20, Height = 20, OnClick = () => { } },
                    new BoxEl { Key = "sub", Direction = 0, Gap = 4, Children = [
                        new BoxEl { Key = "s1", Width = 20, Height = 20, OnClick = () => { } },
                        new BoxEl { Key = "s2", Width = 20, Height = 20, OnClick = () => { } },
                        new BoxEl { Key = "s3", Width = 20, Height = 20, OnClick = () => { } } ] },
                ],
            }, null);
            new FlexLayout(scene, fonts).Run(scene.Root);
            var disp = new InputDispatcher(scene);
            var outside = Child(scene, scene.Root, 0);
            var sub = Child(scene, scene.Root, 1);
            var s1 = Child(scene, sub, 0); var s3 = Child(scene, sub, 2);
            var next = disp.NextFocusableIn(sub, s1);          // s1 → s2
            var wrap = disp.NextFocusableIn(sub, s3);          // s3 → s1 (cycles, never escapes to 'outside')
            var first = disp.FirstFocusableIn(sub);
            var last = disp.LastFocusableIn(sub);
            Check("W1-P6.c scoped roving cycles within a subtree (never escapes)",
                next == Child(scene, sub, 1) && wrap == s1 && first == s1 && last == s3 && first != outside,
                $"next=s2?{next == Child(scene, sub, 1)} wrap=s1?{wrap == s1} first=s1?{first == s1} last=s3?{last == s3}");
        }
    }

    // Wave 1 / P4a — authored clip-rect channel: AnimEngine ClipL/T/R/B drive NodePaint.ClipRect (node-local); the
    // recorder intersects it into the child clip. Un-animated edges default to the node box; settling clears the override.
    static void ClipChannelChecks()
    {
        var scene = new SceneStore();
        var node = scene.CreateNode(1);
        scene.Root = node;
        scene.Bounds(node) = new RectF(0f, 0f, 100f, 80f);
        var engine = new AnimEngine(scene);

        bool startInfinite = scene.Paint(node).ClipRect.IsInfinite;   // no clip before any animation

        // Reveal the bottom edge 0 → 80 (a one-edge clip; L/T/R default to the node box → only the bottom clips).
        engine.Animate(node, AnimChannel.ClipB, 0f, 80f, 100f, Easing.Linear);
        engine.Tick(0f);
        engine.Tick(50f);
        var mid = scene.Paint(node).ClipRect;
        bool applied = !mid.IsInfinite && Near(mid.X, 0f) && Near(mid.Y, 0f) && Near(mid.W, 100f) && Near(mid.H, 40f, 2f);

        engine.Tick(60f);   // 110ms total → animation completes and the clip override clears
        bool reset = scene.Paint(node).ClipRect.IsInfinite;

        Check("W1-P4a.a clip-rect channel applies mid-anim (bottom reveal), resets on settle",
            startInfinite && applied && reset,
            $"mid=({mid.X:0},{mid.Y:0},{mid.W:0},{mid.H:0}) start∞={startInfinite} reset∞={reset}");
    }

    // Wave 1 / P1 — the engine disabled gate: a single NodeFlags.Disabled bit gates hit-test, focus, and keyboard
    // activation, replacing each control's hand-rolled handler-nulling. Visuals stay control-chosen.
    static void DisabledChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("disabled", new Size2(320, 240), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var root = new DisabledProbe();
        using var host = new AppHost(app, window, device, fonts, strings, root);

        host.RunFrame();   // mount — the gated box starts disabled

        // disabled-no-hit: clicking the disabled box invokes nothing; the always-enabled box still clicks.
        ClickNode(host, window, root.GatedBox);
        int gatedAfterDisabledClick = root.GatedClicks;
        ClickNode(host, window, root.EnabledBox);
        Check("W1-P1.a disabled node does not hit-test (click swallowed); enabled still clicks",
            gatedAfterDisabledClick == 0 && root.EnabledClicks == 1,
            $"gated={gatedAfterDisabledClick} enabled={root.EnabledClicks}");

        // disabled-no-focus: Tab skips the disabled box → focus lands on the only enabled focusable.
        window.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.Tab));
        host.RunFrame();
        bool focusEnabled = FocusedNode(host.Scene, host.Scene.Root) == root.EnabledBox;
        bool gatedNotFocused = (host.Scene.Flags(root.GatedBox) & NodeFlags.Focused) == 0;
        Check("W1-P1.b disabled node is not a tab stop (focus skips it)", focusEnabled && gatedNotFocused,
            $"focusEnabled={focusEnabled} gatedFocused={!gatedNotFocused}");

        // disabled-no-key-activate: Enter activates the focused ENABLED box (pressed on down, click on key-UP — the
        // WinUI ClickMode.Release contract); the disabled box never key-activates.
        int beforeEnter = root.EnabledClicks;
        window.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.Enter));
        window.QueueInput(new InputEvent(InputKind.KeyUp, default, 0, Keys.Enter));
        host.RunFrame();
        Check("W1-P1.c Enter activates the focused enabled node; disabled never key-activates",
            root.EnabledClicks == beforeEnter + 1 && root.GatedClicks == 0,
            $"enabled={root.EnabledClicks} gated={root.GatedClicks}");

        // disabled-toggle-reenables: flip IsEnabled via the signal → the box now hit-tests and clicks.
        root.Gate!.Value = true;
        host.RunFrame();
        ClickNode(host, window, root.GatedBox);
        Check("W1-P1.d flipping IsEnabled re-enables hit-test (Mark/Unmark each reconcile)",
            root.GatedClicks == 1, $"gated={root.GatedClicks}");

        // zero-alloc: the gate is a flag bittest — steady idle frames allocate nothing on the paint half.
        for (int i = 0; i < 6; i++) host.RunFrame();
        var steady = host.RunFrame();
        Check("W1-P1.e disabled gate adds no steady-state allocation", steady.HotPhaseAllocBytes == 0,
            $"{steady.HotPhaseAllocBytes} bytes");
    }

    // Wave 1 / P2 — stateful text/glyph foreground ramps: a TextEl under an interactive box inherits the box's eased
    // hover/press progress (no per-control animator) and steps to a disabled color via the P1 gate flag on its ancestor.
    static void TextRampChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("textramp", new Size2(320, 200), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var root = new TextRampProbe();
        using var host = new AppHost(app, window, device, fonts, strings, root);

        host.RunFrame();   // mount
        var box = host.Scene.Root;
        var c = CenterOf(host.Scene, box);
        var outside = new Point2(c.X + 300f, c.Y + 300f);

        var rest = GlyphColor(device, strings, "ramp");
        bool restOk = rest.R > 0.5f && rest.G < 0.2f && rest.B < 0.2f;   // resting = red

        // hover → green (eased through the ancestor box's interaction progress)
        window.QueueInput(new InputEvent(InputKind.PointerMove, c, 0, 0));
        for (int i = 0; i < 24; i++) host.RunFrame();
        var hov = GlyphColor(device, strings, "ramp");
        bool hovOk = hov.G > 0.5f && hov.R < 0.2f;

        // press → blue (press composes over hover)
        window.QueueInput(new InputEvent(InputKind.PointerDown, c, 0, 0));
        for (int i = 0; i < 24; i++) host.RunFrame();
        var prs = GlyphColor(device, strings, "ramp");
        bool prsOk = prs.B > 0.5f && prs.G < 0.2f;

        // release + leave → back to red
        window.QueueInput(new InputEvent(InputKind.PointerUp, c, 0, 0));
        window.QueueInput(new InputEvent(InputKind.PointerMove, outside, 0, 0));
        for (int i = 0; i < 24; i++) host.RunFrame();
        var back = GlyphColor(device, strings, "ramp");
        bool backOk = back.R > 0.5f && back.G < 0.2f;

        Check("W1-P2.a text foreground ramps: hover→green, press→blue, release→red",
            restOk && hovOk && prsOk && backOk,
            $"rest=({rest.R:0.0},{rest.G:0.0},{rest.B:0.0}) hov=({hov.R:0.0},{hov.G:0.0},{hov.B:0.0}) prs=({prs.R:0.0},{prs.G:0.0},{prs.B:0.0}) back=({back.R:0.0},{back.G:0.0},{back.B:0.0})");

        // disabled → white (a step, regardless of pointer position; gated by the ancestor's NodeFlags.Disabled)
        root.Enabled!.Value = false;
        host.RunFrame();
        var dis = GlyphColor(device, strings, "ramp");
        Check("W1-P2.b disabled text uses the DisabledColor step", dis.R > 0.8f && dis.G > 0.8f && dis.B > 0.8f,
            $"dis=({dis.R:0.00},{dis.G:0.00},{dis.B:0.00})");

        // zero-alloc: the resolve walks ancestors with struct reads only — steady idle frames allocate nothing.
        for (int i = 0; i < 6; i++) host.RunFrame();
        var steady = host.RunFrame();
        Check("W1-P2.c text ramp adds no steady-state allocation", steady.HotPhaseAllocBytes == 0, $"{steady.HotPhaseAllocBytes} bytes");
    }

    // Wave 1 / P4b — stateful gradient transitions: the recorder per-frame interpolates the resting gradient's stops
    // toward the hover/pressed gradients by the eased progress (no new GradientSpec per frame).
    static void GradientRampChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("gradramp", new Size2(320, 200), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var root = new GradientRampProbe();
        using var host = new AppHost(app, window, device, fonts, strings, root);

        host.RunFrame();
        var c = CenterOf(host.Scene, host.Scene.Root);
        var outside = new Point2(c.X + 300f, c.Y + 300f);

        var rest = FirstGradientC0(device);
        bool restOk = rest.R > 0.5f && rest.G < 0.2f && rest.B < 0.2f;

        window.QueueInput(new InputEvent(InputKind.PointerMove, c, 0, 0));
        for (int i = 0; i < 24; i++) host.RunFrame();
        var hov = FirstGradientC0(device);
        bool hovOk = hov.G > 0.5f && hov.R < 0.2f;

        window.QueueInput(new InputEvent(InputKind.PointerDown, c, 0, 0));
        for (int i = 0; i < 24; i++) host.RunFrame();
        var prs = FirstGradientC0(device);
        bool prsOk = prs.B > 0.5f && prs.G < 0.2f;

        window.QueueInput(new InputEvent(InputKind.PointerUp, c, 0, 0));
        window.QueueInput(new InputEvent(InputKind.PointerMove, outside, 0, 0));
        for (int i = 0; i < 24; i++) host.RunFrame();
        var back = FirstGradientC0(device);
        bool backOk = back.R > 0.5f && back.G < 0.2f;

        Check("W1-P4b.a gradient fill ramps: hover→green, press→blue, release→red",
            restOk && hovOk && prsOk && backOk,
            $"rest=({rest.R:0.0},{rest.G:0.0},{rest.B:0.0}) hov=({hov.R:0.0},{hov.G:0.0},{hov.B:0.0}) prs=({prs.R:0.0},{prs.G:0.0},{prs.B:0.0}) back=({back.R:0.0},{back.G:0.0},{back.B:0.0})");

        for (int i = 0; i < 6; i++) host.RunFrame();
        var steady = host.RunFrame();
        Check("W1-P4b.b gradient ramp adds no steady-state allocation", steady.HotPhaseAllocBytes == 0, $"{steady.HotPhaseAllocBytes} bytes");
    }

    static void TextInputChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("edit", new Size2(320, 200), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var root = new EditTextProbe();
        using var host = new AppHost(app, window, device, fonts, strings, root);

        host.RunFrame();
        var field = FindRole(host.Scene, host.Scene.Root, AutomationRole.Text);
        bool found = !field.IsNull;
        var center = CenterOf(host.Scene, field);

        // Focus the field, then type "hi5" via WM_CHAR-style events.
        window.QueueInput(new InputEvent(InputKind.PointerDown, center, 0, 0));
        window.QueueInput(new InputEvent(InputKind.PointerUp, center, 0, 0));
        host.RunFrame();
        window.QueueInput(new InputEvent(InputKind.Char, default, 0, 'h'));
        window.QueueInput(new InputEvent(InputKind.Char, default, 0, 'i'));
        window.QueueInput(new InputEvent(InputKind.Char, default, 0, '5'));
        host.RunFrame();
        string typed = root.Text!.Peek();

        // Backspace removes the last char.
        window.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.Back));
        host.RunFrame();
        string afterBack = root.Text!.Peek();

        // Sanitize clamps to 8 chars: type a long run.
        for (int i = 0; i < 12; i++) window.QueueInput(new InputEvent(InputKind.Char, default, 0, 'x'));
        host.RunFrame();
        string clamped = root.Text!.Peek();

        Check("63. text input: focused field accepts WM_CHAR, backspace, sanitize",
            found && typed == "hi5" && afterBack == "hi" && clamped.Length == 8,
            $"typed='{typed}' back='{afterBack}' clampedLen={clamped.Length}");
    }

    static void OverlayChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("overlay", new Size2(480, 360), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var root = new OverlayProbe();
        using var host = new AppHost(app, window, device, fonts, strings, root);

        host.RunFrame();
        var svc = root.Service!;
        Func<Element> menu = () => new BoxEl
        {
            Width = 140, Direction = 1,
            Children =
            [
                new BoxEl
                {
                    Height = 32, Role = AutomationRole.MenuItem, OnClick = () => { root.Selected = 7; svc.CloseTop(); },
                    Children = [Ui.Text("Item A")],
                },
            ],
        };

        // Let the close fade animation (83ms) settle, then the OverlayCloseDriver removes the popup.
        void Settle() { for (int i = 0; i < 16; i++) host.RunFrame(); }

        // Open → the popup (a MenuItem) appears in the scene.
        svc.Open(() => root.Anchor, menu, FlyoutPlacement.BottomLeft);
        host.RunFrame();
        bool opened = !FindRole(host.Scene, host.Scene.Root, AutomationRole.MenuItem).IsNull;

        // Escape closes it (via the dispatcher key-preview hook).
        window.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.Escape));
        host.RunFrame();
        Settle();
        bool escClosed = FindRole(host.Scene, host.Scene.Root, AutomationRole.MenuItem).IsNull;

        // Re-open → light dismiss: a click away from the popup hits the scrim and closes it.
        svc.Open(() => root.Anchor, menu, FlyoutPlacement.BottomLeft);
        host.RunFrame();
        window.QueueInput(new InputEvent(InputKind.PointerDown, new Point2(460, 350), 0, 0));
        window.QueueInput(new InputEvent(InputKind.PointerUp, new Point2(460, 350), 0, 0));
        host.RunFrame();
        Settle();
        bool lightDismissed = FindRole(host.Scene, host.Scene.Root, AutomationRole.MenuItem).IsNull;

        // Re-open → click the item: invokes its command and closes.
        svc.Open(() => root.Anchor, menu, FlyoutPlacement.BottomLeft);
        host.RunFrame();
        var item = FindRole(host.Scene, host.Scene.Root, AutomationRole.MenuItem);
        var ic = CenterOf(host.Scene, item);
        window.QueueInput(new InputEvent(InputKind.PointerDown, ic, 0, 0));
        window.QueueInput(new InputEvent(InputKind.PointerUp, ic, 0, 0));
        host.RunFrame();
        Settle();
        bool invoked = root.Selected == 7 && FindRole(host.Scene, host.Scene.Root, AutomationRole.MenuItem).IsNull;

        // Caller-owned overlays (ToolTip) must not create an input-blocking scrim. The click reaches the page beneath
        // while the bubble stays open; a light-dismiss flyout still uses the blocking path above.
        int bg0 = root.BackgroundClicks;
        var passive = svc.Open(() => root.Anchor,
            () => new BoxEl { Width = 64, Height = 28, Fill = Tok.FillCardDefault, Children = [Ui.Text("tip")] },
            FlyoutPlacement.BottomLeft,
            new PopupOptions(DismissBehavior: DismissBehavior.None, Chrome: PopupChrome.Raw));
        host.RunFrame();
        var blank = new Point2(190, 110);
        window.QueueInput(new InputEvent(InputKind.PointerDown, blank, 0, 0));
        window.QueueInput(new InputEvent(InputKind.PointerUp, blank, 0, 0));
        host.RunFrame();
        bool passiveDoesNotBlock = passive.IsOpen && root.BackgroundClicks == bg0 + 1;
        passive.Close(); Settle();

        // Global focus exit: unhandled Escape clears keyboard focus, and a non-focusable page click clears it too.
        var ac = CenterOf(host.Scene, root.Anchor);
        window.QueueInput(new InputEvent(InputKind.PointerDown, ac, 0, 0));
        window.QueueInput(new InputEvent(InputKind.PointerUp, ac, 0, 0));
        host.RunFrame();
        bool focused = host.Input.Focused == root.Anchor;
        window.QueueInput(new InputEvent(InputKind.Key, default, 0, Keys.Escape)); host.RunFrame();
        bool escapeClears = host.Input.Focused.IsNull;
        window.QueueInput(new InputEvent(InputKind.PointerDown, ac, 0, 0));
        window.QueueInput(new InputEvent(InputKind.PointerUp, ac, 0, 0)); host.RunFrame();
        window.QueueInput(new InputEvent(InputKind.PointerDown, blank, 0, 0));
        window.QueueInput(new InputEvent(InputKind.PointerUp, blank, 0, 0)); host.RunFrame();
        bool clickAwayClears = host.Input.Focused.IsNull;

        Check("64. overlay: anchored flyout opens, Escape + light-dismiss close, item invokes",
            opened && escClosed && lightDismissed && invoked && passiveDoesNotBlock && focused && escapeClears && clickAwayClears,
            $"open={opened} esc={escClosed} dismiss={lightDismissed} invoke={invoked} passiveInput={passiveDoesNotBlock} focus={focused} escBlur={escapeClears} clickBlur={clickAwayClears}");
    }

    static void OverlayAnimationChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("ovanim", new Size2(480, 400), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        var root = new OverlayProbe();
        var clock = new ManualFrameTimeSource();
        using var host = new AppHost(app, window, device, fonts, strings, root, frameTime: clock);
        host.RunFrame();

        var svc = root.Service!;
        Func<Element> menu = () => MenuFlyout.Build(new[]
        {
            new MenuFlyoutItem("One"), new MenuFlyoutItem("Two"), new MenuFlyoutItem("Three"),
            new MenuFlyoutItem("Four"), new MenuFlyoutItem("Five"),
        }, () => svc.CloseTop());

        NodeHandle SurfaceOf(NodeHandle n)
        {
            for (; !n.IsNull; n = host.Scene.Parent(n))
            {
                if (host.Scene.TryGetAcrylic(n, out _)) return n;
                // D67 menu chrome: the acrylic lives on the stretch PLATE (first child); the channels live on its parent.
                for (var c = host.Scene.FirstChild(n); !c.IsNull; c = host.Scene.NextSibling(c))
                    if (host.Scene.TryGetAcrylic(c, out _)) return n;
            }
            return NodeHandle.Null;
        }
        NodeHandle SmokeScrim()
        {
            NodeHandle best = NodeHandle.Null;
            float bestArea = 0f;
            void Walk(NodeHandle n)
            {
                if (n.IsNull) return;
                ref var p = ref host.Scene.Paint(n);
                var r = host.Scene.AbsoluteRect(n);
                float area = r.W * r.H;
                if (p.Fill.A > 0.1f && r.W >= 400f && r.H >= 320f && area > bestArea)
                {
                    best = n;
                    bestArea = area;
                }
                for (var c = host.Scene.FirstChild(n); !c.IsNull; c = host.Scene.NextSibling(c)) Walk(c);
            }
            Walk(host.Scene.Root);
            return best;
        }

        (bool Fading, bool Settled, bool NoPopBack, float MaxSurface, float MaxScrim) CloseChrome(PopupChrome chrome)
        {
            NodeHandle body = NodeHandle.Null;
            Func<Element> content = () => new BoxEl
            {
                Width = chrome == PopupChrome.TeachingTip ? 320f : 260f,
                Height = chrome == PopupChrome.TeachingTip ? 96f : 88f,
                Fill = Tok.FillCardDefault,
                OnRealized = h => body = h,
                Children = [new TextEl("overlay body") { Color = Tok.TextPrimary }],
            };
            var options = new PopupOptions(
                FocusTrap: chrome == PopupChrome.Modal,
                DismissBehavior: chrome == PopupChrome.Modal ? DismissBehavior.Modal : DismissBehavior.LightDismiss,
                Chrome: chrome);
            svc.Open(() => root.Anchor, content, FlyoutPlacement.BottomLeft, options);
            host.RunFrame();
            for (int i = 0; i < 24; i++) { clock.Advance(16f); host.RunFrame(); }

            NodeHandle surface = NodeHandle.Null;
            if (!body.IsNull)
            {
                if (chrome == PopupChrome.Flyout)
                {
                    surface = SurfaceOf(body);
                }
                else
                {
                    for (var n = host.Scene.Parent(body); !n.IsNull; n = host.Scene.Parent(n))
                    {
                        if ((host.Scene.Flags(n) & NodeFlags.ClipsToBounds) != 0) { surface = n; break; }
                    }
                }
            }
            NodeHandle scrim = chrome == PopupChrome.Modal ? SmokeScrim() : NodeHandle.Null;

            svc.CloseTop();
            host.RunFrame();
            clock.Advance(16f);
            host.RunFrame();
            float closeOp = !surface.IsNull && host.Scene.IsLive(surface) ? host.Scene.Paint(surface).Opacity : 0f;
            float closeScrim = !scrim.IsNull && host.Scene.IsLive(scrim) ? host.Scene.Paint(scrim).Opacity : 0f;
            // The TeachingTip close is the muxc CONTRACT animation: scale 1 → 20/Width over 200ms
            // cubic-bezier(0.7,0,1,0.5) with NO opacity keyframes (TeachingTip.cpp:1695-1712 contractAnimation;
            // TeachingTip.h:235 + :306-307) — the host-owned close is a live scale track, not a fade (the ease-in
            // curve has barely moved at a 16ms sample, so assert the seeded track; 64k samples the kinematics).
            bool fading = chrome == PopupChrome.TeachingTip
                ? !surface.IsNull && host.Scene.IsLive(surface) && host.Animation.HasTracks(surface)
                : !surface.IsNull && host.Scene.IsLive(surface) && closeOp < 0.99f
                    && (chrome != PopupChrome.Modal || (!scrim.IsNull && host.Scene.IsLive(scrim) && closeScrim < 0.99f));

            for (int i = 0; i < 16; i++) { clock.Advance(16f); host.RunFrame(); }
            bool settled = surface.IsNull || !host.Scene.IsLive(surface) || !host.Animation.HasTracks(surface);
            if (chrome == PopupChrome.Modal && !scrim.IsNull && host.Scene.IsLive(scrim))
                settled &= !host.Animation.HasTracks(scrim);

            bool noPopBack = true;
            float maxSurface = 0f;
            float maxScrim = 0f;
            for (int i = 0; i < 6; i++)
            {
                clock.Advance(16f);
                host.RunFrame();
                if (!surface.IsNull && host.Scene.IsLive(surface))
                {
                    float liveOp = host.Scene.Paint(surface).Opacity;
                    maxSurface = MathF.Max(maxSurface, liveOp);
                    if (liveOp > 0.01f) noPopBack = false;
                }
                if (!scrim.IsNull && host.Scene.IsLive(scrim))
                {
                    float liveScrim = host.Scene.Paint(scrim).Opacity;
                    maxScrim = MathF.Max(maxScrim, liveScrim);
                    if (liveScrim > 0.01f) noPopBack = false;
                }
            }
            return (fading, settled, noPopBack, maxSurface, maxScrim);
        }

        svc.Open(() => root.Anchor, menu, FlyoutPlacement.BottomLeft);
        host.RunFrame();   // mount + seed the authored clip-rect reveal + fade (seed runs in a layout effect)
        clock.Advance(16f);
        host.RunFrame();   // tick the animation once → the first ClipRect lands
        var surface = SurfaceOf(FindRole(host.Scene, host.Scene.Root, AutomationRole.MenuItem));
        float fullH = surface.IsNull ? 0f : host.Scene.Bounds(surface).H;
        RectF cr1 = surface.IsNull ? RectF.Infinite : host.Scene.Paint(surface).ClipRect;   // mid-reveal: finite, < full height
        bool revealing = !surface.IsNull && !cr1.IsInfinite && cr1.H > 1f && cr1.H < fullH - 2f;

        for (int i = 0; i < 24; i++) { clock.Advance(16f); host.RunFrame(); }             // open settles
        RectF cr2 = surface.IsNull ? RectF.Infinite : host.Scene.Paint(surface).ClipRect;
        bool revealed = cr2.IsInfinite;

        // Close → the surface fades (opacity animates down) while staying on top (not removed instantly).
        svc.CloseTop();
        host.RunFrame();
        clock.Advance(16f);
        host.RunFrame();
        float op = host.Scene.IsLive(surface) ? host.Scene.Paint(surface).Opacity : 0f;
        bool fading = host.Scene.IsLive(surface) && op < 0.99f;

        Check("64d. flyout: open clip-reveals (authored ClipRect) then close fades", revealing && revealed && fading,
            $"clipH {cr1.H:0}/{fullH:0}→{(cr2.IsInfinite ? "∞" : cr2.H.ToString("0"))} closeOpacity={op:0.00}");
        // Regression for overlay close "pop back": after the close track settles, later frames must not record the
        // surface visible while structural overlay removal catches up.
        for (int i = 0; i < 10; i++) { clock.Advance(16f); host.RunFrame(); }
        bool settled = surface.IsNull || !host.Scene.IsLive(surface) || !host.Animation.HasTracks(surface);
        bool noPopBack = true;
        float maxAfterSettle = 0f;
        for (int i = 0; i < 4; i++)
        {
            clock.Advance(16f);
            host.RunFrame();
            if (!surface.IsNull && host.Scene.IsLive(surface))
            {
                float liveOp = host.Scene.Paint(surface).Opacity;
                maxAfterSettle = MathF.Max(maxAfterSettle, liveOp);
                if (liveOp > 0.01f) noPopBack = false;
            }
        }
        Check("64e. overlay close settles without a one-frame pop-back", settled && noPopBack,
            $"settled={settled} maxOpacityAfterSettle={maxAfterSettle:0.00} live={(!surface.IsNull && host.Scene.IsLive(surface))}");

        var flyoutClose = CloseChrome(PopupChrome.Flyout);
        var modalClose = CloseChrome(PopupChrome.Modal);
        var teachingClose = CloseChrome(PopupChrome.TeachingTip);
        bool allChrome = flyoutClose.Fading && flyoutClose.Settled && flyoutClose.NoPopBack
            && modalClose.Fading && modalClose.Settled && modalClose.NoPopBack
            && teachingClose.Fading && teachingClose.Settled && teachingClose.NoPopBack;
        Check("64f. overlay close lifecycle is host-owned for flyout, modal scrim+card, and TeachingTip",
            allChrome,
            $"flyout=({flyoutClose.Fading},{flyoutClose.Settled},max={flyoutClose.MaxSurface:0.00}) " +
            $"modal=({modalClose.Fading},{modalClose.Settled},card={modalClose.MaxSurface:0.00},scrim={modalClose.MaxScrim:0.00}) " +
            $"tip=({teachingClose.Fading},{teachingClose.Settled},max={teachingClose.MaxSurface:0.00})");

        // ── 64g–64l. Per-kind WinUI motion: KEYFRAME SAMPLES at known t (ManualFrameTimeSource). ──
        // cubic-bezier(0,0,0,1) (the WinUI "control fast out / slow in" curve used by MenuPopup/Split open) has the
        // closed form y(x) = 3·x^(2/3) − 2x (P1.x = P2.x = 0 ⇒ x(s) = s³): E(48/250)=0.6144, E(128/250)=0.8960,
        // E(48/167)=0.7320 — the expected sample values asserted below.
        {
            (NodeHandle Surface, OverlayHandle Handle) OpenKind(PopupChrome chrome, float w = 240f, float h = 88f)
            {
                NodeHandle body = NodeHandle.Null;
                var hd = svc.Open(() => root.Anchor,
                    () => new BoxEl { Width = w, Height = h, Fill = Tok.FillCardDefault, OnRealized = n => body = n },
                    FlyoutPlacement.BottomLeft,
                    new PopupOptions(Chrome: chrome));
                host.RunFrame();   // mount + place + seed (layout effect)
                host.RunFrame();   // compose the t=0 keyframes
                NodeHandle s = SurfaceOf(body);
                if (s.IsNull)      // bare chromes (Raw/TeachingTip) have no acrylic — find the clipping surface box
                    for (var n = host.Scene.Parent(body); !n.IsNull; n = host.Scene.Parent(n))
                        if ((host.Scene.Flags(n) & NodeFlags.ClipsToBounds) != 0) { s = n; break; }
                return (s, hd);
            }
            void SettleAll() { for (int i = 0; i < 40; i++) { clock.Advance(16f); host.RunFrame(); } }

            // 64g — menus (MenuPopupThemeTransition load, LayoutTransition_partial.cpp:465-473): a DOWNWARD menu
            // (AnimationDirection_Top) slides its content TranslateY from −openedLength·ClosedRatio(0.5) → 0 while a
            // counter-translated clip animates — node-local, the NEAR/TOP clip edge (ClipT = ClipRect.Y) slides
            // slide → 0 with the BOTTOM edge resting at H — over s_OpenDuration=250ms cubic-bezier(0,0,0,1), with NO
            // presenter opacity at load. Unload = 83ms linear fade.
            {
                var (s, _) = OpenKind(PopupChrome.Flyout);
                float menuH = host.Scene.Bounds(s).H, slide = menuH * 0.5f;
                var p0 = host.Scene.Paint(s);
                // t=0: content translated up by slide; the top clip edge sits at slide (near edge glued), bottom = H.
                bool t0 = !p0.ClipRect.IsInfinite && Near(p0.ClipRect.Y, slide, 1f) && Near(p0.ClipRect.Bottom, menuH, 1f)
                    && Near(p0.LocalTransform.Dy, -slide, 0.5f) && p0.Opacity > 0.99f;
                clock.Advance(128f); host.RunFrame();
                var p1 = host.Scene.Paint(s);
                // t=128: ClipT = slide·(1−E) and TranslateY = −slide·(1−E), E(128/250)=0.8960 for cb(0,0,0,1).
                bool t128 = !p1.ClipRect.IsInfinite && Near(p1.ClipRect.Y, slide * (1f - 0.8960f), 1f)
                    && Near(p1.LocalTransform.Dy, -slide * (1f - 0.8960f), 1f) && p1.Opacity > 0.99f;
                clock.Advance(160f); host.RunFrame();   // t=288 > 250 → settled
                var p2 = host.Scene.Paint(s);
                bool tEnd = p2.ClipRect.IsInfinite && Near(p2.LocalTransform.Dy, 0f, 0.1f);
                svc.CloseTop(); host.RunFrame();
                clock.Advance(48f); host.RunFrame();
                float op48 = host.Scene.IsLive(s) ? host.Scene.Paint(s).Opacity : -1f;
                bool close48 = Near(op48, 1f - 48f / 83f, 0.02f);   // 83ms LINEAR fade → 0.4217 at t=48
                SettleAll();
                Check("64g. menu motion: content TranslateY −slide→0 + top clip ClipT slide→0 over 250ms cb(0,0,0,1), no open fade; close = 83ms linear fade",
                    t0 && t128 && tEnd && close48,
                    $"t0={t0} (clipT={p0.ClipRect.Y:0.0}/{slide:0.0} clipB={p0.ClipRect.Bottom:0.0} dy={p0.LocalTransform.Dy:0.0}/{-slide:0.0}) t128={t128} " +
                    $"(clipT={p1.ClipRect.Y:0.0}≈{slide * (1f - 0.8960f):0.0} dy={p1.LocalTransform.Dy:0.0}) end={tEnd} close48={close48} (op={op48:0.000}≈{1f - 48f / 83f:0.000})");
            }

            // 64h — ComboBox dropdown (SplitOpen/SplitCloseThemeAnimation, generic.xaml:9047/9056). Open: the clip
            // grows from closedRatio 0.50 over 250ms cubic-bezier(0,0,0,1) with NO content translate (the template
            // sets no ContentTranslationOffset, ThemeAnimations.cpp:692-711) and NO fade (opacity pinned 1,
            // cpp:684). Close: clip collapses to closedRatio 0.15 over s_CloseDuration=167ms (cpp:741 + 826-828),
            // opacity fades only during the LAST 83ms (s_OpacityChangeBeginTime = 167−83 = 84,
            // SplitCloseThemeAnimation_Partial.h:16-18).
            {
                var (s, _) = OpenKind(PopupChrome.Dropdown);
                float ddH = host.Scene.Bounds(s).H;
                var p0 = host.Scene.Paint(s);
                bool t0 = Near(p0.ClipRect.H, ddH * 0.5f, 1f) && Near(p0.LocalTransform.Dy, 0f, 0.1f) && p0.Opacity > 0.99f;
                clock.Advance(128f); host.RunFrame();
                var p1 = host.Scene.Paint(s);
                bool t128 = Near(p1.ClipRect.H, ddH * (0.5f + 0.5f * 0.8960f), 1f)
                    && Near(p1.LocalTransform.Dy, 0f, 0.1f) && p1.Opacity > 0.99f;
                clock.Advance(160f); host.RunFrame();
                bool tEnd = host.Scene.Paint(s).ClipRect.IsInfinite;
                svc.CloseTop(); host.RunFrame();
                clock.Advance(48f); host.RunFrame();
                var c48 = host.Scene.Paint(s);
                // t=48 < 84ms begin time → STILL FULLY OPAQUE while the clip is already collapsing: E(48/167)=0.7320
                // → clipH = H·(1 − 0.85·0.7320) = 0.3778·H.
                bool close48 = c48.Opacity > 0.99f && Near(c48.ClipRect.H, ddH * (1f - 0.85f * 0.7320f), 1.5f);
                clock.Advance(64f); host.RunFrame();   // t=112 → fade progress (112−84)/83 = 0.3373
                float op112 = host.Scene.IsLive(s) ? host.Scene.Paint(s).Opacity : -1f;
                bool close112 = Near(op112, 1f - (112f - 84f) / 83f, 0.03f);
                SettleAll();
                Check("64h. ComboBox dropdown samples: SplitOpen clip 0.5H→H 250ms no translate/fade; SplitClose 167ms clip→0.15H + fade only after 84ms",
                    t0 && t128 && tEnd && close48 && close112,
                    $"t0={t0} (clipH={p0.ClipRect.H:0.0}/{ddH * 0.5f:0.0}) t128={t128} (clipH={p1.ClipRect.H:0.0}≈{ddH * 0.948f:0.0}) " +
                    $"end={tEnd} close48={close48} (op={c48.Opacity:0.00} clipH={c48.ClipRect.H:0.0}≈{ddH * 0.3778f:0.0}) close112={close112} (op={op112:0.000})");
            }

            // 64i — Flyout/FlyoutPresenter (PopupThemeTransition → TAS_SHOWPOPUP/TAS_HIDEPOPUP; FlyoutBase attaches it,
            // FlyoutBase_Partial.cpp:1968-1975). OS PVL ground truth (uxtheme "Animations" storyboard 18/19 dump,
            // stock Windows 11): TRANSLATE offset→0 over 367ms cubic-bezier(0.1,0.9,0.2,1.0); OPACITY 0→1 with
            // start=83ms dur=83ms LINEAR (holds 0 for the first 83ms); hide = OPACITY →0 over 83ms linear. The
            // offset is ±g_entranceThemeOffset = 50px (FlyoutBase_Partial.cpp:68 + 2024-2059): below-anchor starts
            // 50px above its resting spot.
            {
                var (s, _) = OpenKind(PopupChrome.Popup);
                var p0 = host.Scene.Paint(s);
                bool t0 = Near(p0.LocalTransform.Dy, -50f, 1f) && p0.Opacity < 0.01f;
                clock.Advance(48f); host.RunFrame();
                var p1 = host.Scene.Paint(s);
                bool t48 = p1.Opacity < 0.01f                       // still inside the 83ms opacity hold
                    && p1.LocalTransform.Dy > -25f && p1.LocalTransform.Dy < -10f;   // decel curve well underway
                clock.Advance(80f); host.RunFrame();                // t=128 → fade progress (128−83)/83 = 0.5422
                var p2 = host.Scene.Paint(s);
                bool t128 = Near(p2.Opacity, (128f - 83f) / 83f, 0.03f)
                    && p2.LocalTransform.Dy > -8f && p2.LocalTransform.Dy < -0.5f;
                clock.Advance(320f); host.RunFrame();               // t=448 > 367 → settled
                var p3 = host.Scene.Paint(s);
                bool tEnd = Near(p3.LocalTransform.Dy, 0f, 0.1f) && p3.Opacity > 0.99f;
                svc.CloseTop(); host.RunFrame();
                clock.Advance(48f); host.RunFrame();
                float op48 = host.Scene.IsLive(s) ? host.Scene.Paint(s).Opacity : -1f;
                bool close48 = Near(op48, 1f - 48f / 83f, 0.02f);   // TAS_HIDEPOPUP: 83ms linear
                SettleAll();
                Check("64i. Flyout samples: PopupThemeTransition slide −50→0 over 367ms decel + opacity 0 held 83ms then 83ms linear; close 83ms fade",
                    t0 && t48 && t128 && tEnd && close48,
                    $"t0={t0} (dy={p0.LocalTransform.Dy:0.0} op={p0.Opacity:0.00}) t48={t48} (dy={p1.LocalTransform.Dy:0.0} op={p1.Opacity:0.00}) " +
                    $"t128={t128} (op={p2.Opacity:0.000}≈{(128f - 83f) / 83f:0.000} dy={p2.LocalTransform.Dy:0.0}) end={tEnd} close48={close48} (op={op48:0.000})");
            }

            // 64j — ToolTip (FadeIn/FadeOutThemeAnimation, the template's Opened/Closed states,
            // ToolTip_themeresources.xaml:56-70): TAS_FADEIN/TAS_FADEOUT = OPACITY over 167ms LINEAR both ways
            // (OS PVL storyboard 4/5 dump; WinTheme.cpp:165-182).
            {
                var (s, _) = OpenKind(PopupChrome.Raw);
                clock.Advance(80f); host.RunFrame();
                float opIn = host.Scene.Paint(s).Opacity;
                bool in80 = Near(opIn, 80f / 167f, 0.02f);
                SettleAll();
                bool inEnd = host.Scene.Paint(s).Opacity > 0.99f;
                svc.CloseTop(); host.RunFrame();
                clock.Advance(80f); host.RunFrame();
                float opOut = host.Scene.IsLive(s) ? host.Scene.Paint(s).Opacity : -1f;
                bool out80 = Near(opOut, 1f - 80f / 167f, 0.02f);
                SettleAll();
                Check("64j. ToolTip samples: FadeIn/FadeOut 167ms linear (TAS_FADEIN/TAS_FADEOUT)",
                    in80 && inEnd && out80,
                    $"in80={in80} (op={opIn:0.000}≈{80f / 167f:0.000}) inEnd={inEnd} out80={out80} (op={opOut:0.000}≈{1f - 80f / 167f:0.000})");
            }

            // 64k — TeachingTip (muxc expand/contract): expand scale Min(0.01, 20/W)→1 over 300ms
            // cubic-bezier(0.1,0.9,0.2,1) (TeachingTip.cpp:1660-1664; TeachingTip.h:234+304-305); contract 1→20/W
            // over 200ms cubic-bezier(0.7,0,1,0.5) (cpp:1695-1712; h:235+306-307). NEITHER storyboard has opacity
            // keyframes — the tip is fully opaque while scaling.
            {
                var (s, _) = OpenKind(PopupChrome.TeachingTip, w: 320f, h: 96f);
                var p0 = host.Scene.Paint(s);
                bool t0 = Near(p0.LocalTransform.M11, 0.01f, 0.005f) && p0.Opacity > 0.99f;
                clock.Advance(160f); host.RunFrame();
                bool mid = host.Scene.Paint(s).Opacity > 0.99f;   // no fade at any point of the expand
                SettleAll();
                var pEnd = host.Scene.Paint(s);
                bool tEnd = Near(pEnd.LocalTransform.M11, 1f, 0.01f) && pEnd.Opacity > 0.99f;
                svc.CloseTop(); host.RunFrame();
                clock.Advance(208f); host.RunFrame();             // ≥200ms → contract target reached
                var pC = host.Scene.Paint(s);
                bool contracted = !host.Scene.IsLive(s) || Near(pC.LocalTransform.M11, 20f / 320f, 0.01f) || pC.Opacity < 0.01f;
                SettleAll();
                Check("64k. TeachingTip samples: expand scale 0.01→1 (300ms), contract →20/W (200ms), NO opacity keyframes",
                    t0 && mid && tEnd && contracted,
                    $"t0={t0} (sx={p0.LocalTransform.M11:0.000}) mid={mid} end={tEnd} (sx={pEnd.LocalTransform.M11:0.00}) contracted={contracted}");
            }

            // 64l — AutoSuggestBox suggestions (a bare WinUI Popup, no TransitionCollection in the template and
            // AutoSuggestBox_Partial.cpp attaches none): NO open/close animation — instant in, instant out.
            {
                var (s, _) = OpenKind(PopupChrome.Static);
                var p0 = host.Scene.Paint(s);
                bool instantIn = p0.Opacity > 0.99f && p0.ClipRect.IsInfinite
                    && Near(p0.LocalTransform.Dy, 0f, 0.1f) && !host.Animation.HasTracks(s);
                svc.CloseTop(); host.RunFrame();
                bool instantOut = !host.Scene.IsLive(s) || host.Scene.Paint(s).Opacity < 0.01f;
                SettleAll();
                Check("64l. AutoSuggest popup: bare Popup — no open/close animation (instant show/hide)",
                    instantIn && instantOut, $"in={instantIn} out={instantOut}");
            }
        }
    }

    // ── E4 — popup windowing: out-of-bounds popup WINDOWS (WinUI windowed CPopup — Popup_Partial.cpp:951-970,
    // FlyoutBase_Partial.cpp:3181-3205 SetIsWindowedPopup), monitor work-area placement (FlyoutBase_Partial.cpp:
    // 3382-3392 useMonitorBounds), window-deactivation light dismiss (Popup_Partial.h:38 DismissalTriggerFlags),
    // the full FlyoutPlacementMode matrix + fallback (FlyoutBase_Partial.cpp:2503-2659), ToolTipService timing
    // (ToolTipService_Partial.cpp:1771-1780), focus-restore-at-close-START (Popup_Partial.h:63-64 SavedFocusState)
    // and nested cascade close (MenuFlyoutSubItem child-first close order). All headless.
    static void E4PopupWindowingChecks(StringTable strings)
    {
        // e4popup.1 — WindowBlur (WM_ACTIVATE WA_INACTIVE) closes every LIGHT-DISMISS overlay; Modal (ContentDialog)
        // and None (ToolTip) stay. WinUI: DismissalTriggerFlags::WindowDeactivated is part of the default
        // light-dismiss trigger set (Popup_Partial.h:38); ContentDialog's modal popup excludes it; ToolTipService
        // owns its tooltip's close itself.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("e4blur", new Size2(480, 360), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new OverlayProbe();
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var svc = root.Service!;

            static Func<Element> Body(string label) => () => new BoxEl
            {
                Width = 120, Height = 40,
                Children = [new TextEl(label) { Size = 12f }],
            };
            var light = svc.Open(() => root.Anchor, Body("ld-body"), FlyoutPlacement.BottomLeft);
            var modal = svc.Open(() => root.Anchor, Body("modal-body"), FlyoutPlacement.BottomLeft,
                new PopupOptions(FocusTrap: true, DismissBehavior: DismissBehavior.Modal, Chrome: PopupChrome.Modal));
            var none = svc.Open(() => root.Anchor, Body("none-body"), FlyoutPlacement.BottomLeft,
                new PopupOptions(DismissBehavior: DismissBehavior.None, Chrome: PopupChrome.Raw));
            host.RunFrame();
            bool allOpen = !FindTextNode(host.Scene, strings, host.Scene.Root, "ld-body").IsNull
                && !FindTextNode(host.Scene, strings, host.Scene.Root, "modal-body").IsNull
                && !FindTextNode(host.Scene, strings, host.Scene.Root, "none-body").IsNull;

            window.QueueInput(new InputEvent(InputKind.WindowBlur, default, 0, 0));
            host.RunFrame();
            bool lightClosedNow = !light.IsOpen && modal.IsOpen && none.IsOpen;
            for (int i = 0; i < 20; i++) host.RunFrame();   // the 83ms close fade settles → entry finalized
            bool after = FindTextNode(host.Scene, strings, host.Scene.Root, "ld-body").IsNull
                && !FindTextNode(host.Scene, strings, host.Scene.Root, "modal-body").IsNull
                && !FindTextNode(host.Scene, strings, host.Scene.Root, "none-body").IsNull;
            Check("e4popup.1 WindowBlur closes light-dismiss overlays only (Modal + None stay)",
                allOpen && lightClosedNow && after,
                $"allOpen={allOpen} closedNow={lightClosedNow} after={after}");
        }

        // e4popup.2 — work-area clamp math (pure FlyoutPositioner). Windowed popups collide against the MONITOR work
        // area passed as the container (FlyoutBase_Partial.cpp:3382-3392) and skip the final min-edge clamp
        // (cpp:2648-2653 — applied to non-windowed popups only), so they may extend above/left of the window.
        {
            // (a) min-edge clamp: a flyout fitting EXACTLY above lands at container-top − FlyoutMargin(4) after the
            // margin shift (cpp:2622-2646); non-windowed clamps back to the container origin, windowed keeps −4.
            var anchorA = new RectF(100, 60, 80, 20);
            var view = new RectF(0, 0, 480, 360);
            var pcA = FlyoutPositioner.Place(anchorA, new Size2(100, 60), view, FlyoutPlacement.TopEdgeAlignedLeft, isWindowed: false);
            var pwA = FlyoutPositioner.Place(anchorA, new Size2(100, 60), view, FlyoutPlacement.TopEdgeAlignedLeft, isWindowed: true);
            bool minEdge = Near(pcA.X, 100) && Near(pcA.Y, 0) && pcA.OpensUp
                        && Near(pwA.X, 100) && Near(pwA.Y, -4) && pwA.OpensUp;

            // (b) monitor container vs viewport: an anchor near the window top fits ABOVE against the work area
            // (negative window-DIP coords) but must FLIP BELOW when constrained to the viewport.
            var anchorB = new RectF(10, 10, 50, 20);
            var workB = new RectF(-500, -300, 1000, 400);
            var pwB = FlyoutPositioner.Place(anchorB, new Size2(100, 50), workB, FlyoutPlacement.TopEdgeAlignedLeft, isWindowed: true);
            var pcB = FlyoutPositioner.Place(anchorB, new Size2(100, 50), view, FlyoutPlacement.TopEdgeAlignedLeft, isWindowed: false);
            bool monitor = pwB.OpensUp && Near(pwB.X, 10) && Near(pwB.Y, 10 - 50 - 4)
                        && !pcB.OpensUp && Near(pcB.Y, 30 + 4) && pcB.Placement == FlyoutPlacement.BottomEdgeAlignedLeft;

            // (c) secondary-axis clamp INTO the work area: a left-justified popup wider than the space right of the
            // anchor slides left to stay on the monitor (TestAndCenterAlignWithinLimits clamp, cpp:415-483).
            var anchorC = new RectF(940, 50, 50, 20);
            var workC = new RectF(0, 0, 1000, 400);
            var pwC = FlyoutPositioner.Place(anchorC, new Size2(200, 60), workC, FlyoutPlacement.BottomEdgeAlignedLeft, isWindowed: true);
            bool secondary = Near(pwC.X, 800) && Near(pwC.Y, 74) && !pwC.OpensUp;

            Check("e4popup.2 work-area clamp math: windowed skips the min-edge clamp, collides vs the monitor rect, clamps the secondary axis",
                minEdge && monitor && secondary,
                $"minEdge={minEdge} monitor={monitor} secondary={secondary} (pwA.Y={pwA.Y:0.#} pwB.Y={pwB.Y:0.#} pwC.X={pwC.X:0.#})");
        }

        // e4popup.3 — the windowed-popup headless pipeline: PopupOptions.ConstrainToRootBounds=false leases a PAL
        // popup window + its own swapchain, the subtree records into ITS OWN DrawList re-origined to the popup's
        // (0,0) (SceneRecorder.RecordSubtree) while the MAIN record skips it (skipRoots); default (true) keeps
        // today's in-window path, and PopupWindowsEnabled=false falls back silently (CPopup::
        // DoesPlatformSupportWindowedPopup == false, FlyoutBase_Partial.cpp:3188).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("e4win", new Size2(480, 360), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new OverlayProbe();
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var svc = root.Service!;
            var anchorRect = host.Scene.AbsoluteRect(root.Anchor);

            var popupBody = new PopupExitProbeBody();
            var hWin = svc.Open(() => root.Anchor,
                () => Embed.Comp(() => popupBody),
                FlyoutPlacement.BottomLeft, new PopupOptions { ConstrainToRootBounds = false });
            host.RunFrame();

            bool leased = host.PopupWindows.Count == 1 && app.PopupWindows.Count == 1;
            PopupWindowSlot? slot = host.PopupWindows.Count > 0 ? host.PopupWindows[0] : null;
            HeadlessPopupWindow? pal = app.PopupWindows.Count > 0 ? app.PopupWindows[0] : null;
            bool shown = pal is { IsShown: true } && pal.ShowCount >= 1;
            // BottomLeft = below the anchor + FlyoutMargin 4; window scale 1 + client origin (0,0) ⇒ px == DIP. BoundsDip
            // stays the logical menu rect; the popup WINDOW (WindowBoundsDip == pal px) is inflated by the WinUI medium-popup
            // shadow insets (L10 T2 R10 B18 DIP) so the composition drop shadow has margin to render into.
            bool placed = slot is not null && pal is not null
                && Near(slot.BoundsDip.X, anchorRect.X) && Near(slot.BoundsDip.Y, anchorRect.Bottom + FlyoutPositioner.FlyoutMargin)
                && slot.BoundsDip.W >= 180f && slot.BoundsDip.H >= 80f
                && Near(slot.WindowBoundsDip.X, slot.BoundsDip.X - 10f) && Near(slot.WindowBoundsDip.Y, slot.BoundsDip.Y - 2f)
                && Near(slot.WindowBoundsDip.W, slot.BoundsDip.W + 20f) && Near(slot.WindowBoundsDip.H, slot.BoundsDip.H + 20f)
                && Near(pal.BoundsPx.X, slot.WindowBoundsDip.X) && Near(pal.BoundsPx.Y, slot.WindowBoundsDip.Y)
                && Near(pal.BoundsPx.W, slot.WindowBoundsDip.W) && Near(pal.BoundsPx.H, slot.WindowBoundsDip.H);
            bool osBackdrop = slot is { Material: PopupWindowMaterial.TransientAcrylic }
                && pal is { Material: PopupWindowMaterial.TransientAcrylic, Dark: true };

            for (int i = 0; i < 20; i++) host.RunFrame();   // the 250ms open clip-reveal settles → full content records

            var scratch = new HeadlessGpuDevice();          // decode the popup's own DrawList
            if (slot is not null)
                scratch.SubmitDrawList(slot.DrawList.Bytes, slot.DrawList.SortKeys,
                    new FrameInfo(new Size2(slot.BoundsDip.W, slot.BoundsDip.H), 1f, default));
            bool routed = HasGlyph(scratch, strings, "popup-exit-old");
            bool noEngineAcrylic = scratch.LastLayers.Count == 0;   // OS-backed menu acrylic: no in-engine PushLayer blur.
            bool reorigined = false;
            foreach (var g in scratch.LastGlyphs)
                if (strings.Resolve(g.Text) == "popup-exit-old")
                    reorigined = slot is not null && g.Bounds.X >= -1f && g.Bounds.Y >= -1f
                        && g.Bounds.Right <= slot.BoundsDip.W + 1f && g.Bounds.Bottom <= slot.BoundsDip.H + 1f;
            bool mainSkips = !HasGlyph(device, strings, "popup-exit-old") && HasGlyph(device, strings, "anchor")
                && !FindTextNode(host.Scene, strings, host.Scene.Root, "popup-exit-old").IsNull;   // scene keeps it (hit-test)
            bool presented = slot?.Swapchain is HeadlessSwapchain sc && sc.PresentCount >= 1;

            // Swap a keyed row while it is hosted in the popup window. The old row is now an exit orphan: it must remain
            // in this popup DrawList (behind the incoming row) and must not leak into the main-window DrawList.
            popupBody.Swap.Value = true;
            host.RunFrame();
            if (slot is not null)
                scratch.SubmitDrawList(slot.DrawList.Bytes, slot.DrawList.SortKeys,
                    new FrameInfo(new Size2(slot.BoundsDip.W, slot.BoundsDip.H), 1f, default));
            bool popupExitRouted = HasGlyph(scratch, strings, "popup-exit-old")
                && HasGlyph(scratch, strings, "popup-exit-new")
                && !HasGlyph(device, strings, "popup-exit-old");

            // Default (ConstrainToRootBounds = true): in-window popup — no window lease, content in the MAIN DrawList.
            var hIn = svc.Open(() => root.Anchor,
                () => new BoxEl { Width = 120, Height = 40, Children = [new TextEl("inwin-body") { Size = 12f }] },
                FlyoutPlacement.BottomLeft);
            host.RunFrame();
            bool defaultInWindow = app.PopupWindows.Count == 1 && HasGlyph(device, strings, "inwin-body");
            hIn.Close();
            for (int i = 0; i < 20; i++) host.RunFrame();

            // Close: a CLOSING entry keeps its popup window while it fades; the lease releases with the entry.
            hWin.Close();
            host.RunFrame();   // 16ms into the 83ms fade
            bool keptWhileFading = host.PopupWindows.Count == 1 && pal is { IsShown: true };
            for (int i = 0; i < 20; i++) host.RunFrame();
            bool released = host.PopupWindows.Count == 0 && pal is { Disposed: true, IsShown: false };

            // PopupWindowsEnabled = false (the DoesPlatformSupportWindowedPopup gate): silent constrained fallback.
            host.PopupWindowsEnabled = false;
            var hFb = svc.Open(() => root.Anchor,
                () => new BoxEl { Width = 120, Height = 40, Children = [new TextEl("fb-body") { Size = 12f }] },
                FlyoutPlacement.BottomLeft, new PopupOptions { ConstrainToRootBounds = false });
            for (int i = 0; i < 20; i++) host.RunFrame();
            bool fallback = app.PopupWindows.Count == 1 && HasGlyph(device, strings, "fb-body");
            hFb.Close();
            for (int i = 0; i < 20; i++) host.RunFrame();

            Check("e4popup.3 windowed popup: PAL lease + own DrawList/swapchain, main record skips the subtree; default + disabled stay in-window",
                leased && shown && placed && osBackdrop && routed && noEngineAcrylic && reorigined && mainSkips && presented
                && popupExitRouted && defaultInWindow && keptWhileFading && released && fallback,
                $"leased={leased} shown={shown} placed={placed} os={osBackdrop} routed={routed} noAcrylic={noEngineAcrylic} reorig={reorigined} skip={mainSkips} exitRoute={popupExitRouted} present={presented} def={defaultInWindow} kept={keptWhileFading} rel={released} fb={fallback}");
        }

        // e4popup.4 — the GetWorkArea seam through the host: the work-area query lands at the anchor's centre in
        // physical virtual-screen px (client origin + scale, IPlatformWindow.ClientOriginPx), the windowed popup
        // flips ABOVE because the MONITOR (not the viewport) has no room below, may take negative window-DIP Y
        // (out-of-bounds), and the PAL window bounds round-trip DIP→px. A constrained popup at the same anchor
        // stays BELOW (the viewport has room) — the monitor flip is windowed-only behavior.
        {
            using var app = new HeadlessPlatformApp();
            Point2 queried = default;
            app.WorkAreaResolver = p => { queried = p; return new RectF(0f, 0f, 2000f, 800f); };
            var window = new HeadlessWindow(new WindowDesc("e4wa", new Size2(960, 720), 2f)) { ClientOriginPx = new Point2(1000f, 600f) };
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new OverlayProbe();
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var svc = root.Service!;
            var anchorRect = host.Scene.AbsoluteRect(root.Anchor);   // (20,20,120,32) DIP

            var hWin = svc.Open(() => root.Anchor,
                () => new BoxEl { Width = 180, Height = 80, Children = [new TextEl("wa-body") { Size = 12f }] },
                FlyoutPlacement.BottomLeft, new PopupOptions { ConstrainToRootBounds = false });
            host.RunFrame();

            bool leased = host.PopupWindows.Count == 1 && app.PopupWindows.Count == 1;
            PopupWindowSlot? slot = host.PopupWindows.Count > 0 ? host.PopupWindows[0] : null;
            HeadlessPopupWindow? pal = app.PopupWindows.Count > 0 ? app.PopupWindows[0] : null;
            bool query = Near(queried.X, 1000f + (anchorRect.X + anchorRect.W * 0.5f) * 2f)
                      && Near(queried.Y, 600f + (anchorRect.Y + anchorRect.H * 0.5f) * 2f);
            float hDip = slot?.BoundsDip.H ?? 0f;
            // Work area px (0,0,2000,800) → window DIP (−500,−300,1000,400): monitor bottom = 100 DIP < the popup's
            // below-anchor bottom ⇒ flips ABOVE the anchor, past the window top (negative DIP Y).
            bool flipped = slot is not null
                && Near(slot.BoundsDip.Y, anchorRect.Y - hDip - FlyoutPositioner.FlyoutMargin) && slot.BoundsDip.Y < 0f;
            // The popup WINDOW px is the inflated WindowBoundsDip (menu rect + shadow insets) × scale + client origin.
            bool px = slot is not null && pal is not null
                && Near(pal.BoundsPx.X, 1000f + slot.WindowBoundsDip.X * 2f) && Near(pal.BoundsPx.Y, 600f + slot.WindowBoundsDip.Y * 2f)
                && Near(pal.BoundsPx.W, slot.WindowBoundsDip.W * 2f) && Near(pal.BoundsPx.H, slot.WindowBoundsDip.H * 2f);
            bool inWork = pal is not null && pal.BoundsPx.Y >= 0f && pal.BoundsPx.Y + pal.BoundsPx.H <= 800f;

            var hIn = svc.Open(() => root.Anchor,
                () => new BoxEl { Width = 180, Height = 80, Children = [new TextEl("wa-in-body") { Size = 12f }] },
                FlyoutPlacement.BottomLeft);
            for (int i = 0; i < 20; i++) host.RunFrame();
            var inBody = FindTextNode(host.Scene, strings, host.Scene.Root, "wa-in-body");
            bool constrainedBelow = !inBody.IsNull && host.Scene.AbsoluteRect(inBody).Y > anchorRect.Bottom;

            Check("e4popup.4 GetWorkArea seam: px query at the anchor centre, monitor flip above the window (negative DIP Y), DIP→px bounds round-trip",
                leased && query && flipped && px && inWork && constrainedBelow,
                $"leased={leased} query={query}@({queried.X:0.#},{queried.Y:0.#}) flip={flipped}(dipY={slot?.BoundsDip.Y ?? 0f:0.#}) px={px} inWork={inWork} below={constrainedBelow}");
        }

        // e4popup.5 — the 8 edge-aligned FlyoutPlacementMode variants (FlyoutBase_Partial.cpp:84-110 major side +
        // :78-113 edge justification; TryPlacement cpp:415-483) with room on every side: exact rects including the
        // FlyoutMargin 4 shift away from the anchor (cpp:65 + 2622-2646).
        {
            var anchor = new RectF(200, 150, 80, 40);
            var c = new RectF(0, 0, 600, 500);
            var size = new Size2(100, 60);
            bool At(FlyoutPlacement p, float x, float y, bool up)
            {
                var r = FlyoutPositioner.Place(anchor, size, c, p, isWindowed: false);
                return Near(r.X, x) && Near(r.Y, y) && r.OpensUp == up && r.Placement == p;
            }
            bool tal = At(FlyoutPlacement.TopEdgeAlignedLeft, 200, 86, true);       // y = 150−60−4
            bool tar = At(FlyoutPlacement.TopEdgeAlignedRight, 180, 86, true);      // x = 280−100
            bool bal = At(FlyoutPlacement.BottomEdgeAlignedLeft, 200, 194, false);  // y = 190+4
            bool bar = At(FlyoutPlacement.BottomEdgeAlignedRight, 180, 194, false);
            bool lat = At(FlyoutPlacement.LeftEdgeAlignedTop, 96, 150, false);      // x = 200−100−4
            bool lab = At(FlyoutPlacement.LeftEdgeAlignedBottom, 96, 130, false);   // y = 190−60
            bool rat = At(FlyoutPlacement.RightEdgeAlignedTop, 284, 150, false);    // x = 280+4
            bool rab = At(FlyoutPlacement.RightEdgeAlignedBottom, 284, 130, false);
            Check("e4popup.5 the 8 edge-aligned placements produce the exact WinUI rects (major side + edge justify + FlyoutMargin 4)",
                tal && tar && bal && bar && lat && lab && rat && rab,
                $"TAL={tal} TAR={tar} BAL={bal} BAR={bar} LAT={lat} LAB={lab} RAT={rat} RAB={rab}");
        }

        // e4popup.6 — PerformPlacementWithFallback (FlyoutBase_Partial.cpp:488-537; per-side order cpp:2559-2593):
        // a side that can't fit walks its fallback order and REPORTS the effective placement; an edge justification
        // survives a vertical↔vertical (or horizontal↔horizontal) flip and centers on a perpendicular fallback.
        {
            var c = new RectF(0, 0, 600, 500);
            var size = new Size2(100, 60);

            var low = new RectF(50, 440, 80, 20);     // no room below → Bottom flips to Top, Left justify kept
            var pb = FlyoutPositioner.Place(low, size, c, FlyoutPlacement.BottomEdgeAlignedLeft, isWindowed: false);
            bool flipUp = pb.OpensUp && Near(pb.X, 50) && Near(pb.Y, 376) && pb.Placement == FlyoutPlacement.TopEdgeAlignedLeft;

            var right = new RectF(520, 100, 60, 30);  // no room right → Right flips to Left (order R,L,T,B), Top justify kept
            var pr = FlyoutPositioner.Place(right, size, c, FlyoutPlacement.RightEdgeAlignedTop, isWindowed: false);
            bool flipLeft = !pr.OpensUp && Near(pr.X, 416) && Near(pr.Y, 100) && pr.Placement == FlyoutPlacement.LeftEdgeAlignedTop;

            var wide = new RectF(10, 200, 280, 30);   // Left AND Right blocked → 3rd choice Top (order L,R,T,B), centered
            var narrow = new RectF(0, 0, 300, 500);
            var pt = FlyoutPositioner.Place(wide, size, narrow, FlyoutPlacement.Left, isWindowed: false);
            bool thirdChoice = pt.OpensUp && Near(pt.X, 100) && Near(pt.Y, 136) && pt.Placement == FlyoutPlacement.Top;

            Check("e4popup.6 placement fallback: Bottom→Top and Right→Left flips keep the justification; a blocked Left walks to Top centered",
                flipUp && flipLeft && thirdChoice,
                $"flipUp={flipUp} flipLeft={flipLeft} third={thirdChoice} (pb=({pb.X:0.#},{pb.Y:0.#}) pr=({pr.X:0.#},{pr.Y:0.#}) pt=({pt.X:0.#},{pt.Y:0.#}))");
        }

        // e4popup.7 — ToolTipService timing (ToolTipService_Partial.cpp:1771-1780): mouse initial show delay =
        // SPI_GETMOUSEHOVERTIME(400) × 2 = 800ms; auto-dismiss after SPI_GETMESSAGEDURATION = 5s
        // (DEFAULT_SHOW_DURATION_SECONDS, ToolTipService_Partial.h:19; the close timer is armed on automatic open,
        // cpp:429-459); a re-hover within BETWEEN_SHOW_DELAY_MS 200ms of the close (cpp:659, .h:17) uses the RESHOW
        // delay = 400ms — ×1, because the shipping static_cast<INT64>(1.5) truncates (cpp:1775).
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("e4tip", new Size2(480, 360), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new E4ToolTipProbe();
            var clock = new ManualFrameTimeSource();
            using var host = new AppHost(app, window, device, fonts, strings, root, frameTime: clock);
            host.RunFrame();

            bool TipOpen() => !FindTextNode(host.Scene, strings, host.Scene.Root, "tip-body").IsNull;
            void Hover(float x, float y) { window.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(x, y), 0, 0)); host.RunFrame(); }
            void Step(float ms) { clock.Advance(ms); host.RunFrame(); }
            // 0-dt frames: a just-seeded AnimEngine track consumes no dt on its FIRST tick (AnimEngine.cs JustSeeded —
            // idle time pending before the seed must not run a track early), and a finished track frees at the END of
            // the tick that crossed it with the clock firing one passive pass later. Polling at dt=0 drains that
            // frame-granularity latency WITHOUT advancing the clock — the ms thresholds below stay exact.
            void Poll() { for (int i = 0; i < 4; i++) host.RunFrame(); }

            Hover(50f, 50f);                  // pointer enters the target → the 800ms show-delay clock arms
            Poll();                           // the countdown track seeds + clears JustSeeded at 0ms
            Step(700f);
            Poll();
            bool notAt700 = !TipOpen();       // 700ms < 800 — must still be closed
            Step(150f);                       // 850ms total ≥ 800 → the delay elapses
            Poll();
            bool openAt800 = TipOpen();

            Poll();                           // the 5s auto-dismiss clock seeds with the open bubble
            Step(4800f);                      // dwell: 4.8s of the 5s auto-dismiss window
            Poll();
            bool stillOpenAt4800 = TipOpen();
            Step(300f);                       // ≥ 5000 → auto-dismiss fires
            Poll();
            for (int i = 0; i < 4; i++) Step(80f);   // the FadeOut (167ms) settles → bubble removed
            Poll();
            bool autoClosed = !TipOpen();

            Hover(10f, 10f);                  // auto-dismiss latches until a real owner leave
            Hover(52f, 50f);                  // re-enter < 200ms (wall) after the close → RESHOW delay (400ms)
            Poll();
            Step(300f);
            Poll();
            bool reshowNotAt300 = !TipOpen(); // 300ms < 400 — must still be closed
            Step(150f);                       // 450ms ≥ 400 → fires (an un-truncated 1.5× = 600ms would still be closed)
            Poll();
            bool reshowAt400 = TipOpen();

            Check("e4popup.7 ToolTip timing: 800ms initial show, 5s auto-dismiss, 400ms reshow inside the 200ms window",
                notAt700 && openAt800 && stillOpenAt4800 && autoClosed && reshowNotAt300 && reshowAt400,
                $"!700={notAt700} 800={openAt800} dwell={stillOpenAt4800} auto={autoClosed} !300={reshowNotAt300} 400={reshowAt400}");
        }

        // e4popup.7b — an OPEN tooltip never blocks input: the bubble is hit-test-invisible (ToolTip.cs) AND the
        // overlay host's full-bleed positioning wrappers + the Raw chrome surface yield self (HitTestPassThrough),
        // so with the bubble open over a scrollable page (a) a wheel AT the bubble scrolls the page beneath it and
        // (b) a wheel anywhere ELSE in the window still resolves the page scroller. (The regression: the entry's
        // full-bleed wrapper was HitTestAny's window-wide deepest hit — no scroller in its ancestor chain — so
        // wheel input died EVERYWHERE while any popup/tooltip was open.)
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("e4tipwheel", new Size2(480, 360), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new E4ToolTipWheelProbe();
            var clock = new ManualFrameTimeSource();
            using var host = new AppHost(app, window, device, fonts, strings, root, frameTime: clock);
            host.RunFrame();
            var s = host.Scene;
            NodeHandle FindScrollable(NodeHandle n)
            {
                if (n.IsNull) return NodeHandle.Null;
                if (s.HasScroll(n)) return n;
                for (var c = s.FirstChild(n); !c.IsNull; c = s.NextSibling(c))
                {
                    var r = FindScrollable(c);
                    if (!r.IsNull) return r;
                }
                return NodeHandle.Null;
            }
            var vp = FindScrollable(s.Root);

            void Hover(float x, float y) { window.QueueInput(new InputEvent(InputKind.PointerMove, new Point2(x, y), 0, 0)); host.RunFrame(); }
            void Step(float ms) { clock.Advance(ms); host.RunFrame(); }
            void Poll() { for (int i = 0; i < 4; i++) host.RunFrame(); }
            float ScrollProgress() { ref var st = ref s.ScrollRef(vp); return MathF.Max(st.TargetY, st.OffsetY); }

            Hover(60f, 116f);                 // over the wrapped target (content y 100..132)
            Poll(); Step(850f); Poll();       // the 800ms show delay elapses → bubble open
            var bubbleText = FindTextNode(s, strings, s.Root, "tip-wheel");
            bool open = !bubbleText.IsNull;
            var br = open ? s.AbsoluteRect(bubbleText) : default;

            // (a) wheel AT the open bubble: the page beneath must scroll (bubble + overlay wrappers all yield).
            window.QueueInput(new InputEvent(InputKind.Wheel, new Point2(br.X + 2f, br.Y + 2f), 0, 0, 60f));
            for (int i = 0; i < 6; i++) Step(16f);
            float afterBubbleWheel = ScrollProgress();

            // (b) wheel far from the bubble while the entry is still open: must also reach the page scroller.
            window.QueueInput(new InputEvent(InputKind.Wheel, new Point2(420f, 320f), 0, 0, 60f));
            for (int i = 0; i < 6; i++) Step(16f);
            float afterFarWheel = ScrollProgress();

            Check("e4popup.7b an open tooltip never blocks input — wheel scrolls the page at the bubble AND anywhere else",
                open && afterBubbleWheel > 1f && afterFarWheel > afterBubbleWheel + 1f,
                $"open={open} afterBubble={afterBubbleWheel:0.#} afterFar={afterFarWheel:0.#}");
        }

        // e4popup.8 — focus restores to the pre-open node when the close STARTS, not when the fade finishes: WinUI
        // restores the popup's SavedFocusState synchronously in Hide()/CPopup::Close (Popup_Partial.h:63-64;
        // FlyoutBase returns focus to the invoker on Hide, not after the close animation) — the popup is still on
        // screen fading while the invoker already has focus back.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("e4focus", new Size2(480, 360), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new OverlayProbe();
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var svc = root.Service!;

            ClickNode(host, window, root.Anchor);   // pre-open focus = the anchor
            bool anchorFocused0 = (host.Scene.Flags(root.Anchor) & NodeFlags.Focused) != 0;

            NodeHandle body = default;
            var h = svc.Open(() => root.Anchor, () => new BoxEl
            {
                Width = 140, Height = 60, Padding = Edges4.All(10),
                Children = [new BoxEl { Width = 100, Height = 24, Role = AutomationRole.Button, OnClick = () => { }, OnRealized = n => body = n }],
            }, FlyoutPlacement.BottomLeft);
            for (int i = 0; i < 18; i++) host.RunFrame();   // the open reveal settles
            ClickNode(host, window, body);                  // focus moves INTO the popup
            bool movedIn = (host.Scene.Flags(body) & NodeFlags.Focused) != 0;

            h.Close();   // the restore happens HERE — synchronously at close start
            bool restoredAtCloseStart = (host.Scene.Flags(root.Anchor) & NodeFlags.Focused) != 0;
            bool stillFadingNow = host.Scene.IsLive(body) && !h.IsOpen;
            host.RunFrame();   // 16ms into the 83ms fade — the popup is still alive on screen
            bool fadingAfterFrame = host.Scene.IsLive(body);
            for (int i = 0; i < 20; i++) host.RunFrame();
            bool removed = !host.Scene.IsLive(body) && (host.Scene.Flags(root.Anchor) & NodeFlags.Focused) != 0;

            Check("e4popup.8 focus restores at close START (popup still fading) and survives the removal",
                anchorFocused0 && movedIn && restoredAtCloseStart && stillFadingNow && fadingAfterFrame && removed,
                $"pre={anchorFocused0} in={movedIn} atStart={restoredAtCloseStart} fading={stillFadingNow}/{fadingAfterFrame} removed={removed}");
        }

        // e4popup.9 — nested cascade close (WinUI MenuFlyoutSubItem close order): closing the parent closes its
        // children FIRST; each level restores its own saved focus, so the chain unwinds child → parent content →
        // original invoker; both windowed-popup leases release with their entries.
        {
            using var app = new HeadlessPlatformApp();
            var window = new HeadlessWindow(new WindowDesc("e4cascade", new Size2(480, 360), 1f));
            window.Show();
            var device = new HeadlessGpuDevice();
            var fonts = new HeadlessFontSystem(strings);
            var root = new OverlayProbe();
            using var host = new AppHost(app, window, device, fonts, strings, root);
            host.RunFrame();
            var svc = root.Service!;
            ClickNode(host, window, root.Anchor);   // pre-open focus = the anchor

            NodeHandle pItem = default, cItem = default;
            OverlayHandle? hChild = null;
            var hParent = svc.Open(() => root.Anchor, () => new BoxEl
            {
                Width = 160, Height = 80, Padding = Edges4.All(8),
                Children =
                [
                    new BoxEl
                    {
                        Width = 120, Height = 24, Role = AutomationRole.MenuItem, OnRealized = n => pItem = n,
                        OnClick = () => hChild = svc.Open(() => pItem, () => new BoxEl
                        {
                            Width = 120, Height = 50,
                            Children = [new BoxEl { Width = 100, Height = 24, Role = AutomationRole.MenuItem, OnClick = () => { }, OnRealized = n2 => cItem = n2 }],
                        }, FlyoutPlacement.RightEdgeAlignedTop, new PopupOptions { ConstrainToRootBounds = false }),
                    },
                ],
            }, FlyoutPlacement.BottomLeft, new PopupOptions { ConstrainToRootBounds = false });
            for (int i = 0; i < 18; i++) host.RunFrame();   // parent open settles

            ClickNode(host, window, pItem);                  // focuses the item + opens the windowed child
            for (int i = 0; i < 18; i++) host.RunFrame();    // child open settles
            bool bothLeased = app.PopupWindows.Count == 2 && host.PopupWindows.Count == 2;

            ClickNode(host, window, cItem);                  // focus moves into the CHILD popup
            bool inChild = (host.Scene.Flags(cItem) & NodeFlags.Focused) != 0;

            hParent.Close();
            bool cascade = !hParent.IsOpen && hChild is { IsOpen: false };
            // Child closed first: its restore put focus on pItem (inside the parent wrapper), so the parent's restore
            // then chained to the original anchor — a parent-first order would strand focus on pItem.
            bool chained = (host.Scene.Flags(root.Anchor) & NodeFlags.Focused) != 0;
            for (int i = 0; i < 20; i++) host.RunFrame();
            bool released = host.PopupWindows.Count == 0
                && app.PopupWindows.Count == 2 && app.PopupWindows[0].Disposed && app.PopupWindows[1].Disposed;
            bool gone = !host.Scene.IsLive(pItem) && !host.Scene.IsLive(cItem);

            Check("e4popup.9 cascade close: parent close closes children first, focus chains back to the invoker, windowed leases release",
                bothLeased && inChild && cascade && chained && released && gone,
                $"leased={bothLeased} inChild={inChild} cascade={cascade} chained={chained} released={released} gone={gone}");
        }
    }

    // 64m — every WinUI transient surface records the ONE default acrylic recipe (PushLayer cmd) in BOTH themes.
    // WinUI ground truth (AcrylicBrush_themeresources.xaml): AcrylicBackgroundFillColorDefaultBrush ==
    // AcrylicInAppFillColorDefaultBrush =
    //   dark  "Default": TintColor #2C2C2C, TintOpacity 0.15, TintLuminosityOpacity 0.96, FallbackColor #2C2C2C
    //   light "Light":   TintColor #FCFCFC, TintOpacity 0.0,  TintLuminosityOpacity 0.85, FallbackColor #F9F9F9
    // Carried by: FlyoutPresenterBackground (FlyoutPresenter_themeresources.xaml:5/15), the MenuFlyout system
    // backdrop AcrylicBackgroundFillColorDefaultBackdrop (MenuFlyout_themeresources.xaml:264+271),
    // ComboBoxDropDownBackground (ComboBox_themeresources.xaml:63/273), AutoSuggestBoxSuggestionsListBackground
    // (AutoSuggestBox_themeresources.xaml:5/17) and ToolTipBackgroundBrush (ToolTip_themeresources.xaml:14/40).
    // The FALLBACK color in the PushLayer cmd is the solid paint when blur is unavailable (AcrylicBrush FallbackColor).
    static void FlyoutAcrylicChecks(StringTable strings)
    {
        try
        {
            foreach (var (kind, label) in new[] { (ThemeKind.Dark, "dark"), (ThemeKind.Light, "light") })
            {
                Tok.Use(kind);
                ColorF tint = kind == ThemeKind.Dark ? ColorF.FromRgba(0x2C, 0x2C, 0x2C) : ColorF.FromRgba(0xFC, 0xFC, 0xFC);
                ColorF fall = kind == ThemeKind.Dark ? ColorF.FromRgba(0x2C, 0x2C, 0x2C) : ColorF.FromRgba(0xF9, 0xF9, 0xF9);
                float tintOp = kind == ThemeKind.Dark ? 0.15f : 0.0f;
                float lumOp = kind == ThemeKind.Dark ? 0.96f : 0.85f;

                using var app = new HeadlessPlatformApp();
                var window = new HeadlessWindow(new WindowDesc("acry-" + label, new Size2(480, 400), 1f)); window.Show();
                var device = new HeadlessGpuDevice();
                var fonts = new HeadlessFontSystem(strings);
                var root = new OverlayProbe();
                using var host = new AppHost(app, window, device, fonts, strings, root);
                host.RunFrame();
                var svc = root.Service!;

                bool SurfaceLayerOk(PopupChrome chrome)
                {
                    var hd = svc.Open(() => root.Anchor,
                        () => new BoxEl { Width = 220f, Height = 80f, Fill = Tok.FillCardDefault },
                        FlyoutPlacement.BottomLeft, new PopupOptions(Chrome: chrome));
                    host.RunFrame();
                    host.RunFrame();
                    bool found = false;
                    foreach (var l in device.LastLayers)
                        if (ColorClose(l.Tint, tint, 0.004f) && ColorClose(l.Fallback, fall, 0.004f)
                            && Near(l.TintOpacity, tintOp, 0.005f) && Near(l.LuminosityOpacity, lumOp, 0.005f)
                            && Near(l.BlurSigma, 30f, 0.5f) && l.NoiseOpacity > 0f)
                            found = true;
                    hd.Close();
                    for (int i = 0; i < 16; i++) host.RunFrame();
                    return found;
                }

                bool menuOk = SurfaceLayerOk(PopupChrome.Flyout);      // MenuFlyoutPresenter (system backdrop recipe)
                bool comboOk = SurfaceLayerOk(PopupChrome.Dropdown);   // ComboBox PopupBorder
                bool suggestOk = SurfaceLayerOk(PopupChrome.Static);   // AutoSuggestBox SuggestionsContainer
                bool flyoutOk = SurfaceLayerOk(PopupChrome.Popup);     // FlyoutPresenter
                // ToolTip + the Slider value tip bind Tok.AcrylicFlyout directly (ToolTip.cs BubbleContent /
                // Slider.cs TipBubble) — assert the token equals the WinUI recipe so those surfaces are covered too.
                var spec = Tok.AcrylicFlyout;
                bool tokenOk = ColorClose(spec.Tint, tint, 0.004f) && ColorClose(spec.Fallback, fall, 0.004f)
                    && Near(spec.TintOpacity, tintOp, 0.005f) && Near(spec.LuminosityOpacity, lumOp, 0.005f);
                Check($"64m. {label} flyout acrylic: PushLayer tint/fallback/tint-opacity/luminosity match the WinUI default acrylic on every transient surface",
                    menuOk && comboOk && suggestOk && flyoutOk && tokenOk,
                    $"menu={menuOk} combo={comboOk} suggest={suggestOk} flyout={flyoutOk} token={tokenOk}");
            }
        }
        finally { Tok.Use(ThemeKind.Dark); }
    }

    // 64n — the in-app acrylic effect runner's portable math (FluentGpu.Render AcrylicBackdropMath; consumed by the
    // D3D12 AcrylicCompositor's PushLayer{Acrylic} schedule: region snapshot → pooled downsampled RT → two-pass
    // separable gaussian → WinUI composite). WinUI ground truth: microsoft-ui-xaml AcrylicBrush.h:64
    // sc_blurRadius = 30.0f applied as GaussianBlurEffect.BlurAmount (= gaussian STANDARD DEVIATION in DIPs,
    // AcrylicBrush.cpp:521-525). The runner reproduces sigma = 30·dpiScale physical px with the Flutter-Impeller / Skia
    // downsample curve: down = pow2up(ceil(sigmaPhys/4)) so the intermediate's EFFECTIVE texel sigma ≤ 4 (the
    // production-validated quality threshold), and the separable kernel is REBUILT for that texel sigma per bucket
    // (uploaded as blur-pass constants, not baked). The composited GPU pixels themselves are needs-pixels (manual
    // --shot) — these checks pin every number the leaf composites with.
    static void AcrylicBackdropMathChecks()
    {
        // Kernel: BuildKernel(texelSigma) is a normalized symmetric bilinear-tap gaussian for the VARIABLE ≤4 texel
        // sigma. Verify at the σ=30-DIP@100% bucket (down 8 ⇒ texel σ 3.75) and a small σ (narrower ⇒ fewer taps).
        Span<float> koff = stackalloc float[AcrylicBackdropMath.MaxTapCount];
        Span<float> kwgt = stackalloc float[AcrylicBackdropMath.MaxTapCount];
        float texelSig = AcrylicBackdropMath.EffectiveTexelSigma(30f, 1f, AcrylicBackdropMath.DownsampleFactor(30f, 1f)); // 3.75
        int nt = AcrylicBackdropMath.BuildKernel(texelSig, koff, kwgt);
        double mass = kwgt[0];                                        // total kernel mass: center + 2·(mirrored taps)
        double variance = 0;
        for (int i = 1; i < nt; i++) { mass += 2.0 * kwgt[i]; variance += 2.0 * kwgt[i] * koff[i] * koff[i]; }
        double sigma = Math.Sqrt(variance);                          // effective std-dev of the folded bilinear kernel
        bool monotone = true;
        for (int i = 2; i < nt; i++) if (koff[i] <= koff[i - 1]) monotone = false;
        int ntSmall = AcrylicBackdropMath.BuildKernel(1.5f, koff, kwgt);   // small σ ⇒ radius ~5 ⇒ ~4 taps (< the 3.75 bucket)
        bool kernelOk = nt >= 2 && nt <= AcrylicBackdropMath.MaxTapCount
            && koff[0] == 0f && kwgt[0] > 0f && monotone
            && koff[nt - 1] <= AcrylicBackdropMath.MaxKernelRadius
            && Math.Abs(mass - 1.0) < 1e-4 && Math.Abs(sigma - texelSig) < 0.4
            && ntSmall >= 2 && ntSmall < nt;                          // a smaller texel σ emits a narrower (fewer-tap) kernel
        Check("64n. acrylic blur kernel: normalized symmetric linear-tap gaussian rebuilt for the variable <=4 texel sigma",
            kernelOk,
            $"taps={nt} mass={mass:0.00000} sigma={sigma:0.000} (texelSigma {texelSig:0.000}) smallTaps={ntSmall}");

        // Downsample curve (Flutter-Impeller / Skia): down = smallest pow2 >= ceil(sigmaPhys/4), clamped [1,16], so the
        // effective texel sigma stays ≤ 4; at sigmaPhys ≤ 4 down stays 1 (no downsample, exact).
        bool downOk = AcrylicBackdropMath.DownsampleFactor(30f, 1f) == 8       // sigmaPhys 30  → ceil(7.5)=8  → pow2 8
            && AcrylicBackdropMath.DownsampleFactor(30f, 1.5f) == 16           // sigmaPhys 45  → ceil(11.25)=12 → pow2 16
            && AcrylicBackdropMath.DownsampleFactor(30f, 2f) == 16             // sigmaPhys 60  → ceil(15)=15  → pow2 16
            && AcrylicBackdropMath.DownsampleFactor(15f, 1f) == 4              // sigmaPhys 15  → ceil(3.75)=4 → pow2 4
            && AcrylicBackdropMath.DownsampleFactor(120f, 2f) == 16            // sigmaPhys 240 → ceil(60)=60  → pow2 64 → clamp 16
            && AcrylicBackdropMath.DownsampleFactor(4f, 1f) == 1               // sigmaPhys 4   → down 1 (no downsample at σ≤4)
            && AcrylicBackdropMath.DownsampleFactor(8f, 1f) == 2;             // sigmaPhys 8   → ceil(2)=2 → pow2 2 (texel σ 4)
        // Effective texel sigma is ≤ 4 always, and EXACT (never clamped up) when smaller than 4.
        bool texelOk = AcrylicBackdropMath.EffectiveTexelSigma(30f, 1f, AcrylicBackdropMath.DownsampleFactor(30f, 1f)) <= 4f + 1e-4f
            && Math.Abs(AcrylicBackdropMath.EffectiveTexelSigma(3f, 1f, AcrylicBackdropMath.DownsampleFactor(3f, 1f)) - 3f) < 1e-4  // down 1 → texel σ 3 (exact)
            && Math.Abs(AcrylicBackdropMath.EffectiveTexelSigma(8f, 1f, AcrylicBackdropMath.DownsampleFactor(8f, 1f)) - 4f) < 1e-4; // down 2 → texel σ 4
        Check("64n2. acrylic downsample factor: pow2-snapped down keeps effective texel sigma <=4 (Skia/Impeller), down 1 at σ<=4",
            downOk && texelOk,
            $"down@1x={AcrylicBackdropMath.DownsampleFactor(30f, 1f)} @1.5x={AcrylicBackdropMath.DownsampleFactor(30f, 1.5f)} @2x={AcrylicBackdropMath.DownsampleFactor(30f, 2f)} texelOk={texelOk}");

        // Snapshot region: the layer rect inflated by the FULL blur support (kernelRadiusTexels·down phys px ≈ 3·sigmaPhys)
        // on every side (so blurred texels under the rect see real backdrop — bit-identical to blurring the whole backdrop
        // inside the rect), clamped to the canvas at window edges. Pad is derived from the actual kernel, not a constant.
        int down1 = AcrylicBackdropMath.DownsampleFactor(30f, 1f);                          // 8
        int rTex1 = AcrylicBackdropMath.KernelRadiusTexels(AcrylicBackdropMath.EffectiveTexelSigma(30f, 1f, down1)); // 12
        int pad = rTex1 * down1;                                                            // 96 px @ 100% (σ=30)
        AcrylicBackdropMath.SnapshotRegion(new RectF(200f, 160f, 200f, 120f), 1f, down1, rTex1, 1920, 1080, out int x, out int y, out int w, out int h);
        bool interiorOk = x == 200 - pad && y == 160 - pad && w == 200 + 2 * pad && h == 120 + 2 * pad;
        AcrylicBackdropMath.SnapshotRegion(new RectF(2f, 2f, 60f, 40f), 1f, down1, rTex1, 480, 400, out int cx, out int cy, out int cw, out int ch);
        bool clampOk = cx == 0 && cy == 0 && cw == 2 + 60 + pad && ch == 2 + 40 + pad;   // left/top clamped at the canvas edge
        int down2 = AcrylicBackdropMath.DownsampleFactor(30f, 2f);                          // 16
        int rTex2 = AcrylicBackdropMath.KernelRadiusTexels(AcrylicBackdropMath.EffectiveTexelSigma(30f, 2f, down2)); // 12
        int pad2 = rTex2 * down2;                                                           // 192 px @ 200% (σ=30)
        AcrylicBackdropMath.SnapshotRegion(new RectF(200f, 160f, 100f, 60f), 2f, down2, rTex2, 4000, 4000, out int sx, out int sy, out int sw, out int sh);
        bool scaleOk = sx == 400 - pad2 && sy == 320 - pad2 && sw == 200 + 2 * pad2 && sh == 120 + 2 * pad2;   // DIP→phys at 200% DPI
        Check("64n3. acrylic snapshot region: rect inflated by the actual kernel support and clamped to the canvas (phys px, DPI-aware)",
            interiorOk && clampOk && scaleOk, $"interior={interiorOk} clamp={clampOk} scale={scaleOk} pad={pad}");

        // LayerPool size buckets (gpu-renderer.md §7.1 quantized pow2 buckets, floor 64): monotone, covering, few
        // distinct sizes ⇒ a steady-state frame re-acquires the same bucket and never creates a texture.
        bool bucketOk = AcrylicBackdropMath.BucketDim(1) == 64 && AcrylicBackdropMath.BucketDim(64) == 64
            && AcrylicBackdropMath.BucketDim(65) == 128 && AcrylicBackdropMath.BucketDim(240) == 256
            && AcrylicBackdropMath.BucketDim(960) == 1024;
        Check("64n4. acrylic LayerPool buckets: next-pow2 (floor 64) so pooled RTs reuse across layers and frames",
            bucketOk,
            $"b(1)={AcrylicBackdropMath.BucketDim(1)} b(65)={AcrylicBackdropMath.BucketDim(65)} b(960)={AcrylicBackdropMath.BucketDim(960)}");

        // 64n5 — retained-backdrop cache decision (AcrylicBackdropMath.BackdropReusable): the §2.3 region-aware reuse
        // gate (headless half of the AcrylicCompositor pinned-RT cache). A stationary layer reuses its blurred snapshot
        // when nothing behind it moved; a geometry change OR a damage rect touching its snapshot region forces a re-blur.
        var stampA = AcrylicBackdropMath.Stamp(new RectF(100f, 80f, 300f, 200f), 30f, 1f, 1920, 1080);
        var stampSame = AcrylicBackdropMath.Stamp(new RectF(100f, 80f, 300f, 200f), 30f, 1f, 1920, 1080);
        var stampMoved = AcrylicBackdropMath.Stamp(new RectF(100f, 90f, 300f, 200f), 30f, 1f, 1920, 1080);   // rect moved 10 DIP
        var stampSource = AcrylicBackdropMath.Stamp(new RectF(100f, 80f, 300f, 200f), 30f, 1f, 1920, 1080,
            sourceId: 42, clipLeft: 90, clipTop: 70, clipRight: 410, clipBottom: 290);
        var stampOtherSource = AcrylicBackdropMath.Stamp(new RectF(100f, 80f, 300f, 200f), 30f, 1f, 1920, 1080,
            sourceId: 43, clipLeft: 90, clipTop: 70, clipRight: 410, clipBottom: 290);
        var stampOtherClip = AcrylicBackdropMath.Stamp(new RectF(100f, 80f, 300f, 200f), 30f, 1f, 1920, 1080,
            sourceId: 42, clipLeft: 100, clipTop: 70, clipRight: 410, clipBottom: 290);
        int down5 = AcrylicBackdropMath.DownsampleFactor(30f, 1f);
        int rTex5 = AcrylicBackdropMath.KernelRadiusTexels(AcrylicBackdropMath.EffectiveTexelSigma(30f, 1f, down5));
        AcrylicBackdropMath.SnapshotRegion(new RectF(100f, 80f, 300f, 200f), 1f, down5, rTex5, 1920, 1080, out int qx, out int qy, out int qw, out int qh);
        var region = new RectF(qx, qy, qw, qh);
        bool reuseNone = AcrylicBackdropMath.BackdropReusable(stampA, stampSame, region, default);                                 // nothing moved → reuse
        bool reuseFar  = AcrylicBackdropMath.BackdropReusable(stampA, stampSame, region, new RectF(1500f, 900f, 100f, 80f));       // damage elsewhere (e.g. bottom player bar) → reuse
        bool reblurHit = !AcrylicBackdropMath.BackdropReusable(stampA, stampSame, region, new RectF(150f, 120f, 40f, 40f));        // damage inside the snapshot region → re-blur
        bool reblurGeo = !AcrylicBackdropMath.BackdropReusable(stampA, stampMoved, region, default);                               // geometry changed → re-blur
        bool reblurSource = !AcrylicBackdropMath.BackdropReusable(stampSource, stampOtherSource, region, default);
        bool reblurClip = !AcrylicBackdropMath.BackdropReusable(stampSource, stampOtherClip, region, default);
        Check("64n5. acrylic retained-backdrop cache invalidates on geometry, damage, source-target, or clip changes",
            reuseNone && reuseFar && reblurHit && reblurGeo && reblurSource && reblurClip,
            $"reuse(none)={reuseNone} reuse(far)={reuseFar} hit={reblurHit} geo={reblurGeo} source={reblurSource} clip={reblurClip}");

        // gate.acrylic.stampSubPixelJitterHits (E7): the stamp rect + scale are QUANTIZED into the cache key, so a
        // presence-spring settle's sub-pixel rect wobble (<0.5 device px) + a 1-ULP fractional-DPI scale wobble land in
        // the SAME grid cell/scale bucket ⇒ the stamps compare equal ⇒ the cached blur is reused (no permanent per-frame
        // re-blur). Composite position stays exact (it reads L.DeviceRect, not the stamp).
        var jA = AcrylicBackdropMath.Stamp(new RectF(100f, 80f, 300f, 200f), 30f, 1f, 1920, 1080);
        var jB = AcrylicBackdropMath.Stamp(new RectF(100.3f, 80.2f, 300.1f, 199.9f), 30f, 1f + 1e-6f, 1920, 1080);
        var jC = AcrylicBackdropMath.Stamp(new RectF(99.7f, 79.8f, 300.3f, 200.4f), 30f, 1f - 1e-6f, 1920, 1080);
        bool jitterHits = jA.Equals(jB) && jA.Equals(jC)
            && AcrylicBackdropMath.BackdropReusable(jA, jB, new RectF(0, 0, 100, 100), default);
        Check("gate.acrylic.stampSubPixelJitterHits: sub-0.5px rect wobble + 1-ULP scale wobble quantize to the same stamp (reusable)",
            jitterHits, $"AB={jA.Equals(jB)} AC={jA.Equals(jC)}");

        // gate.acrylic.stampWholePixelMisses (E7): a ≥1 device-px move crosses a grid cell ⇒ the stamps differ ⇒ re-blur.
        // Verified at 100% DPI (1 DIP = 1 device px) AND at 200% DPI (0.6 DIP = 1.2 device px) — a fractional-DPI-safe move.
        var wA = AcrylicBackdropMath.Stamp(new RectF(100f, 80f, 300f, 200f), 30f, 1f, 1920, 1080);
        var wB = AcrylicBackdropMath.Stamp(new RectF(101.6f, 80f, 300f, 200f), 30f, 1f, 1920, 1080);   // +1.6 device px
        var wC0 = AcrylicBackdropMath.Stamp(new RectF(100f, 80f, 300f, 200f), 30f, 2f, 3840, 2160);
        var wC1 = AcrylicBackdropMath.Stamp(new RectF(100.6f, 80f, 300f, 200f), 30f, 2f, 3840, 2160); // +1.2 device px @2x
        bool wholeMisses = !wA.Equals(wB) && !wC0.Equals(wC1);
        Check("gate.acrylic.stampWholePixelMisses: a >=1 device-px move changes the quantized stamp (re-blur) at 100% and 200% DPI",
            wholeMisses, $"move1x={!wA.Equals(wB)} move2x={!wC0.Equals(wC1)}");

        // gate.acrylic.tightDamageRegion (E8): reuse tests damage against the TIGHT rect+8, not the kernel-inflated
        // snapshot region. A damage rect inside the ±KernelRadius·down halo but outside rect+8 ⇒ reusable; one overlapping
        // the rect ⇒ re-blur. Layer rect (200,160,200,120): tight = (192,152,216,136); inflated pad @/4 = 88 ⇒ 112..488.
        var tStamp = AcrylicBackdropMath.Stamp(new RectF(200f, 160f, 200f, 120f), 30f, 1f, 1920, 1080);
        AcrylicBackdropMath.SnapshotRegionTight(new RectF(200f, 160f, 200f, 120f), 1f, 1920, 1080, out int ttx, out int tty, out int ttw, out int tth);
        var tightR = new RectF(ttx, tty, ttw, tth);
        bool haloReuse = AcrylicBackdropMath.BackdropReusable(tStamp, tStamp, tightR, new RectF(130f, 160f, 20f, 20f)); // in halo (112..), left of tight 192 → reuse
        bool rectReblur = !AcrylicBackdropMath.BackdropReusable(tStamp, tStamp, tightR, new RectF(210f, 170f, 20f, 20f)); // inside rect → re-blur
        bool tightBox = ttx == 192 && tty == 152 && ttw == 216 && tth == 136;
        Check("gate.acrylic.tightDamageRegion: damage in the blur halo but outside rect+8 reuses; damage on the rect re-blurs",
            haloReuse && rectReblur && tightBox, $"halo={haloReuse} rect={rectReblur} tight=({ttx},{tty},{ttw},{tth})");

        // gate.acrylic.ownSubtreeDamageCarvedOut (E9): damage entries emitted by the layer's OWN subtree (the contiguous
        // range [push,pop)) draw ON TOP of its snapshot ⇒ can never invalidate it ⇒ excluded from the reuse test; an entry
        // OUTSIDE the range that overlaps the tight region still forces a re-blur; DamageOverflow ⇒ the whole-frame union
        // is used (no carve-out — the safe fallback).
        ReadOnlySpan<RectF> ownOnly = new[] { new RectF(1500f, 900f, 50f, 50f), new RectF(210f, 170f, 20f, 20f), new RectF(230f, 190f, 20f, 20f) };
        bool ownCarved = AcrylicBackdropMath.OwnSubtreeReusable(tStamp, tStamp, tightR, ownOnly, 3, 1, 3, false, default); // idx1,2 own (inside tight) carved; idx0 far → reuse
        ReadOnlySpan<RectF> withExternal = new[] { new RectF(210f, 170f, 20f, 20f), new RectF(300f, 200f, 10f, 10f) };
        bool externalBlocks = !AcrylicBackdropMath.OwnSubtreeReusable(tStamp, tStamp, tightR, withExternal, 2, 1, 2, false, default); // idx0 external inside tight → re-blur
        bool overflowUnion = !AcrylicBackdropMath.OwnSubtreeReusable(tStamp, tStamp, tightR, ownOnly, 3, 0, 3, true, new RectF(210f, 170f, 20f, 20f)); // overflow → union inside tight → re-blur
        Check("gate.acrylic.ownSubtreeDamageCarvedOut: own-subtree entries excluded; an external entry on the tight region re-blurs; overflow falls back to the union",
            ownCarved && externalBlocks && overflowUnion, $"carved={ownCarved} external={externalBlocks} overflow={overflowUnion}");

        KawaseChainChecks();
    }

    // ── Wave B: the LIVE-BACKDROP acrylic blur is a dual-Kawase downsample/upsample chain (ARM SIGGRAPH 2015 dual filter;
    // AcrylicKawaseMath). These gate the PORTABLE σ→(iterations,offset) mapping + the snapshot pad that the D3D12 leaf
    // consumes, so the chain math is headless-verifiable while the HLSL stays render-thread-confined. The self-blur path
    // (OpacityLayerCompositor) keeps the separable AcrylicBackdropMath pipeline, gated above.
    static void KawaseChainChecks()
    {
        // gate.kawase.sigmaMapping: σ14/20/30 (WinUI acrylic band) map to the expected (iterations, offset) with the
        // offset in the sane [1,2] range and 3–4 iterations, and the chain's effective sigma round-trips to the input σ
        // within tolerance (in-band ⇒ exact). Calibrated K = SigmaPerLevel = 1.25 (validated by the visual A/B).
        AcrylicKawaseMath.SelectChain(14f, 1f, out int i14, out float o14);
        AcrylicKawaseMath.SelectChain(20f, 1f, out int i20, out float o20);
        AcrylicKawaseMath.SelectChain(30f, 1f, out int i30, out float o30);
        bool mapOk =
            i14 == 3 && MathF.Abs(o14 - 1.4f) < 1e-4f &&
            i20 == 3 && MathF.Abs(o20 - 2.0f) < 1e-4f &&
            i30 == 4 && MathF.Abs(o30 - 1.5f) < 1e-4f;
        bool roundTrip =
            MathF.Abs(AcrylicKawaseMath.EffectiveSigma(i14, o14) - 14f) < 0.5f &&
            MathF.Abs(AcrylicKawaseMath.EffectiveSigma(i20, o20) - 20f) < 0.5f &&
            MathF.Abs(AcrylicKawaseMath.EffectiveSigma(i30, o30) - 30f) < 0.5f;
        // every mapped chain stays within the pyramid depth and the sane offset band
        bool bounded = true;
        for (float s = 1f; s <= 40f; s += 0.37f)
        {
            AcrylicKawaseMath.SelectChain(s, 1f, out int it, out float of);
            if (it < 1 || it > AcrylicKawaseMath.MaxIterations || of < AcrylicKawaseMath.OffsetMin - 1e-4f || of > AcrylicKawaseMath.OffsetMax + 1e-4f) bounded = false;
        }
        Check("gate.kawase.sigmaMapping: σ14/20/30 → (3,1.4)/(3,2.0)/(4,1.5), offset∈[1,2], iters∈[3,4], effective σ round-trips",
            mapOk && roundTrip && bounded,
            $"σ14=({i14},{o14:0.00}) σ20=({i20},{o20:0.00}) σ30=({i30},{o30:0.00}) rt={roundTrip} bounded={bounded}");

        // gate.kawase.padCoversSupport: at each iteration count the snapshot pad (PadPx at the max offset) covers the
        // chain's blur support, AND SnapshotRegion inflated by that pad actually contains the ±support halo on every side
        // (mirrors 64n3: unclamped rect grows by 2·pad). down = 1 ⇒ the pad passes straight through as kernelRadius·1.
        bool padOk = true, regionOk = true;
        for (int it = 1; it <= AcrylicKawaseMath.MaxIterations; it++)
        {
            float support = AcrylicKawaseMath.SupportPx(it, AcrylicKawaseMath.OffsetMax);
            int pad = AcrylicKawaseMath.PadPx(it, AcrylicKawaseMath.OffsetMax);
            if (pad < support) padOk = false;
            AcrylicBackdropMath.SnapshotRegion(new RectF(400f, 300f, 200f, 120f), 1f, 1, pad, 4000, 4000,
                out int rx, out int ry, out int rw, out int rh);
            // unclamped (region well inside a 4000² canvas): width = rect + 2·pad, origin = rect − pad
            if (rx != 400 - pad || ry != 300 - pad || rw != 200 + 2 * pad || rh != 120 + 2 * pad) regionOk = false;
        }
        Check("gate.kawase.padCoversSupport: snapshot pad ≥ chain support at every iteration count and inflates the region by ±pad",
            padOk && regionOk, $"padOk={padOk} regionOk={regionOk} pad@4={AcrylicKawaseMath.PadPx(4, 2f)}");
    }

    static void ContentDialogChromeChecks(StringTable strings)
    {
        using var app = new HeadlessPlatformApp();
        var window = new HeadlessWindow(new WindowDesc("dialogchrome", new Size2(760, 520), 1f));
        window.Show();
        var device = new HeadlessGpuDevice();
        var fonts = new HeadlessFontSystem(strings);
        using var host = new AppHost(app, window, device, fonts, strings, new ContentDialogProbe());

        for (int i = 0; i < 24; i++) host.RunFrame();   // open + settle the modal scale/fade

        var title = FindTextNode(host.Scene, strings, host.Scene.Root, "Save your work?");
        NodeHandle outer = title;
        while (!outer.IsNull)
        {
            ref var p = ref host.Scene.Paint(outer);
            if (Near(p.BorderWidth, 1f, 0.01f) && ColorClose(p.BorderColor, Tok.StrokeSurfaceDefault, 0.02f))
                break;
            outer = host.Scene.Parent(outer);
        }

        var top = outer.IsNull ? NodeHandle.Null : Child(host.Scene, outer, 0);
        var sep = outer.IsNull ? NodeHandle.Null : Child(host.Scene, outer, 1);
        var command = outer.IsNull ? NodeHandle.Null : Child(host.Scene, outer, 2);

        bool realOuterBorder = !outer.IsNull
            && ColorClose(host.Scene.Paint(outer).Fill, Tok.FillSolidBase, 0.02f)
            && ColorClose(host.Scene.Paint(outer).BorderColor, Tok.StrokeSurfaceDefault, 0.02f)
            && Near(host.Scene.Paint(outer).BorderWidth, 1f, 0.01f)
            && Near(host.Scene.Paint(outer).Corners.TopLeft, Radii.Overlay, 0.01f)
            && (host.Scene.Flags(outer) & NodeFlags.ClipsToBounds) != 0;
        bool topOverlay = !top.IsNull && ColorClose(host.Scene.Paint(top).Fill, Tok.FillLayerAlt, 0.02f)
            && Near(host.Scene.Layout(top).Padding.Left, 24f, 0.01f)
            && Near(host.Scene.Paint(top).Corners.TopLeft, 0f, 0.01f)
            && Near(host.Scene.Paint(top).Corners.BottomLeft, 0f, 0.01f);
        bool separator = !sep.IsNull && Near(host.Scene.Bounds(sep).H, 1f, 0.01f)
            && ColorClose(host.Scene.Paint(sep).Fill, Tok.StrokeCardDefault, 0.02f);
        bool commandRow = !command.IsNull && ColorClose(host.Scene.Paint(command).Fill, Tok.FillSolidBase, 0.02f)
            && Near(host.Scene.Layout(command).Padding.Left, 24f, 0.01f)
            && Near(host.Scene.Layout(command).Gap, 8f, 0.01f)
            && Near(host.Scene.Paint(command).Corners.TopLeft, 0f, 0.01f)
            && Near(host.Scene.Paint(command).Corners.BottomLeft, 0f, 0.01f);

        Check("64g. ContentDialog chrome: real outer border; square internal content/command layers",
            realOuterBorder && topOverlay && separator && commandRow,
            $"outer={realOuterBorder} top={topOverlay} sep={separator} cmd={commandRow}");
    }

